const ANKI_DATA = {"cirugia":{"1":{"num":1,"name":"INTRODUCCION A CIRUGIA","cards":[{"front":"¿Cuál es el tiempo máximo de evolución que suele definir a un abdomen agudo no traumático?","back":"Generalmente menos de 48 horas, pudiendo extenderse hasta 6 días."},{"front":"¿Cómo se define el abdomen agudo no traumático en cuanto a la repercusión del paciente?","back":"Como un síndrome clínico con repercusión del estado general que requiere diagnóstico rápido por posible cirugía urgente."},{"front":"Menciona tres signos frecuentes de peritonismo en el abdomen agudo.","back":"Rigidez abdominal, incremento de la sensibilidad (con o sin rebote) y defensa o resistencia involuntaria."},{"front":"¿Qué porcentaje de precisión diagnóstica ofrece la laparoscopía en el abdomen agudo?","back":"Aproximadamente un 95%."},{"front":"¿Cuál es el propósito de una laparoscopía diagnóstica pura?","back":"Permitir descartar o confirmar una patología sin realizar una intervención terapéutica adicional."},{"front":"¿Para qué se utiliza la cirugía asistida por laparoscopía?","back":"Para determinar la mejor técnica quirúrgica y planear una laparotomía más dirigida."},{"front":"¿Qué define a la cirugía laparoscópica pura?","back":"Es aquella donde se trata completamente la patología identificada sin necesidad de conversión a cirugía abierta."},{"front":"Menciona tres causas gastrointestinales de abdomen agudo por perforación.","back":"Úlcera péptica perforada, diverticulitis y cáncer."},{"front":"Menciona las tres principales causas gineco-obstétricas de abdomen agudo no traumático.","back":"Embarazo ectópico roto, enfermedad pélvica inflamatoria y torsión de quiste ovárico."},{"front":"¿Qué estado hemodinámico se requiere para realizar una laparoscopía diagnóstica?","back":"Estabilidad hemodinámica (ausencia de choque hipovolémico o séptico)."},{"front":"Menciona una contraindicación absoluta para la laparoscopía en abdomen agudo.","back":"Trastornos severos de la coagulación no corregidos."},{"front":"¿Cuál es el estudio de imagen auxiliar de elección para un paciente con dolor abdominal?","back":"Tomografía Axial Computarizada (TAC)."},{"front":"Definición de herida quirúrgica 'Limpia'.","back":"Incisión en tejido sin abrir vísceras o cavidades que contienen flora bacteriana."},{"front":"¿Cuál es la tasa de infección esperada en una herida limpia?","back":"Menor al 2%."},{"front":"Definición de herida quirúrgica 'Limpia-Contaminada'.","back":"Procedimiento donde se accede de forma controlada a cavidades con flora bacteriana normal sin contaminación excesiva."},{"front":"¿Cuál es la tasa de infección en heridas limpias-contaminadas?","back":"Alrededor del 3-10%."},{"front":"Definición de herida quirúrgica 'Contaminada'.","back":"Herida con contaminación significativa o inflamación aguda sin pus, incluyendo roturas accidentales de la técnica aséptica."},{"front":"¿Cuál es la tasa de infección en heridas contaminadas?","back":"Aproximadamente del 10-20%."},{"front":"Definición de herida quirúrgica 'Sucia o Infectada'.","back":"Herida con infección clínica establecida, presencia de pus o tejidos necróticos."},{"front":"¿Cuál es la tasa de infección en heridas sucias o infectadas?","back":"Mayor al 20%."},{"front":"Menciona un ejemplo de cirugía que genera una herida limpia.","back":"Cirugías ortopédicas o neuroquirúrgicas sin entrada al tracto gastrointestinal."},{"front":"Menciona un ejemplo de cirugía que genera una herida limpia-contaminada.","back":"Apendicectomía en estadios tempranos o cirugía electiva de reflujo gastroesofágico."},{"front":"Menciona un ejemplo de situación que resulta en una herida contaminada.","back":"Cirugía de emergencia por perforación intestinal reciente con derrame importante de contenido."},{"front":"Menciona un ejemplo de cirugía para una herida sucia.","back":"Tratamiento de abscesos intraabdominales o perforaciones intestinales tardías."},{"front":"Característica del dolor en el abdomen agudo de tipo inflamatorio.","back":"Dolor constante, progresivo y localizado de forma inicial, acompañado de SIRS."},{"front":"Tríada diagnóstica del abdomen agudo obstructivo.","back":"Ausencia de evacuaciones/gases, ruidos intestinales aumentados y náuseas/vómitos."},{"front":"Descripción del dolor típico en el abdomen agudo perforativo.","back":"Dolor súbito, intenso, descrito como \"en puñalada\"."},{"front":"Signo clínico cardinal del abdomen agudo de origen vascular.","back":"Dolor abdominal desproporcionado a los hallazgos de la exploración física."},{"front":"Signos característicos del abdomen agudo hemorrágico.","back":"Inicio súbito, distensión abdominal y datos de choque hipovolémico."},{"front":"¿Cuál es el cuadro clínico típico de la colecistitis?","back":"Mujer >40 años, obesidad, dolor en hipocondrio derecho irradiado en hemicinturón y Murphy positivo."},{"front":"¿Cómo se describe la irradiación del dolor en la pancreatitis aguda?","back":"Irradiación transficticia (hacia la espalda)."},{"front":"¿Cuál es el patrón de migración del dolor en la apendicitis aguda?","back":"Dolor periumbilical que migra a la fosa ilíaca derecha."},{"front":"¿Cuál es el perfil típico de un paciente con diverticulitis?","back":"Paciente >60 años, bajo consumo de fibra, estreñimiento y dolor en fosa ilíaca izquierda."},{"front":"¿Cuál es la causa más frecuente de obstrucción de intestino delgado en pacientes con antecedentes quirúrgicos?","back":"Bridas o adherencias."},{"front":"¿Cuál es la causa más frecuente de obstrucción de intestino delgado en pacientes sin antecedentes quirúrgicos?","back":"Hernias."},{"front":"¿Qué signo radiológico es característico del vólvulo de sigmoides?","back":"Imagen en \"grano de café\" y ausencia de gas rectal."},{"front":"Perfil típico del paciente con vólvulo de sigmoides.","back":"Masculino >60 años con estreñimiento crónico y pérdida de peso."},{"front":"Perfil típico del paciente con vólvulo de ciego.","back":"Masculino >60 años con inicio agudo y brusco de síntomas obstructivos."},{"front":"\"¿Qué diagnóstico sugiere un dolor súbito \"\"en puñalada\"\"?\"","back":"Úlcera péptica perforada (UPP)."},{"front":"¿Qué patologías presentan dolor de tipo intermitente?","back":"Obstrucción intestinal y cólico biliar."},{"front":"Menciona tres diagnósticos diferenciales para dolor en el hipocondrio derecho.","back":"Patología biliar, hepatitis y absceso hepático."},{"front":"Menciona tres diagnósticos diferenciales para dolor en la fosa ilíaca derecha.","back":"Apendicitis, vólvulo cecal y embarazo ectópico."},{"front":"¿Qué síntoma ginecológico puede acompañar al dolor en fosa ilíaca por embarazo ectópico?","back":"Sangrado transvaginal."},{"front":"El dolor en fosa ilíaca izquierda es característico de la _____.","back":"Diverticulitis."},{"front":"\"En el vólvulo de ciego","back":"el antecedente quirúrgico-obstétrico suele verse en mujeres de _____ años.\""},{"front":"El signo de _____ positivo es característico de la colecistitis.","back":"Murphy."},{"front":"Las heridas en las que se cierran primariamente tras abrir el tracto gastrointestinal de forma controlada se clasifican como _____.","back":"Limpia-contaminadas."},{"front":"El dolor abdominal que es desproporcionado a la exploración física sugiere _____.","back":"Isquemia Mesentérica Aguda (IMA)."},{"front":"Concepto: Ruidos metálicos.","back":"Signo auscultatorio indicativo de obstrucción intestinal mecánica (hiperperistaltismo)."},{"front":"Concepto: Vómito fecaloide.","back":"Signo avanzado de obstrucción intestinal baja, común en casos de vólvulos o bridas graves."},{"front":"Concepto: Reacciones de peritonismo.","back":"Respuesta inflamatoria del peritoneo que causa rigidez, dolor al rebote y defensa abdominal ante la palpación."},{"front":"\"En el abdomen agudo vascular","back":"el antecedente clínico relevante suele ser _____.\""},{"front":"¿Qué patología se asocia a dolor en epigastrio irradiado a hipocondrios en forma de cinturón?","back":"Colecistitis."},{"front":"Causa principal del síndrome hemorrágico por aneurisma.","back":"Aneurisma de aorta abdominal."},{"front":"¿Qué tipo de herida quirúrgica requiere desbridamiento frecuente?","back":"Herida sucia o infectada."}]},"10":{"num":10,"name":"PATOLOGIA INFLAMATORIA INTESTINAL","cards":[{"front":"¿Cómo se define el Síndrome de Intestino Irritable (SII)?","back":"Afectación con dolor o molestia abdominal crónico asociado a alteraciones en el hábito intestinal sin causa orgánica."},{"front":"Para diagnosticar SII, ¿durante cuántos días al mes deben presentarse los síntomas en los últimos 3 meses?","back":"Al menos 3 días por mes."},{"front":"¿Cuál es el trastorno funcional gastrointestinal más común según el material?","back":"Síndrome de Intestino Irritable (SII)."},{"front":"¿A qué edad y en qué sexo se observa el pico de presentación del SII?","back":"Entre los 30 y 50 años en mujeres."},{"front":"¿Cuáles son los tres pilares de la etiología multifactorial del SII?","back":"Factores genéticos, factores psicosociales y alteración de la microbiota."},{"front":"¿Qué criterios se utilizan para clasificar los síntomas gastrointestinales en el SII?","back":"Criterios de Roma III."},{"front":"¿Qué herramienta se utiliza para evaluar la consistencia y forma de las heces en el SII?","back":"Escala de Bristol."},{"front":"Mencione los tres tipos de presentación clínica del SII.","back":"SII con constipación, SII con diarrea y SII mixto."},{"front":"¿Cuánto tiempo antes del diagnóstico deben haber comenzado los síntomas del SII?","back":"Al menos 6 meses antes."},{"front":"En el SII, el dolor o molestia abdominal se asocia con la mejoría tras la _____.","back":"Defecación"},{"front":"¿Cuál es la recomendación dietética principal para reducir la producción de gas en el SII?","back":"Dieta baja en FODMAPs (oligosacáridos, disacáridos, monosacáridos y polioles fermentables)."},{"front":"¿Qué tipo de fibra se recomienda específicamente para el tratamiento del SII?","back":"Fibra soluble, como el Psyllium plantago."},{"front":"Mencione tres alimentos o sustancias irritantes que deben evitarse en el SII.","back":"Café, alcohol y alimentos picantes."},{"front":"¿Cuál es el objetivo de la Terapia Cognitivo-Conductual (TCC) en el SII?","back":"Modificar patrones de pensamiento que exacerban la percepción del dolor y la ansiedad asociada."},{"front":"Mencione tres fármacos antiespasmódicos indicados para el SII.","back":"Bromuro de pinaverio, trimebutina y pargeverina."},{"front":"¿Qué fármaco antidiarreico se menciona, aclarando que no debe usarse en monoterapia?","back":"Loperamida."},{"front":"En pacientes con SII-Diarrea y comorbilidad psiquiátrica, ¿qué grupo de antidepresivos se prefiere por su efecto anticolinérgico?","back":"Antidepresivos tricíclicos."},{"front":"En pacientes con SII-Constipación o Mixto, ¿qué antidepresivos se utilizan para reducir el dolor visceral?","back":"Inhibidores Selectivos de la Recaptura de Serotonina (ISRS) como fluoxetina o paroxetina."},{"front":"¿En qué situación clínica se recomienda el uso de Rifaximina en el SII?","back":"Persistencia de diarrea y sospecha de sobrecrecimiento bacteriano."},{"front":"¿Qué escala permite clasificar la gravedad del SII en un rango de 0 a 500 puntos?","back":"IBS Severity Score (Cuestionario de Gravedad del SII)."},{"front":"Definición: Colitis Ulcerativa Crónica Idiopática (CUCI)","back":"Enfermedad inflamatoria crónica que afecta fundamentalmente la mucosa del colon de forma continua y difusa."},{"front":"¿Qué genes se asocian a una respuesta inmune desregulada en la Colitis Ulcerativa?","back":"HLA-BW35 y HLA-DR2."},{"front":"A nivel microscópico, ¿qué característica glandular presentan las criptas en la CUCI?","back":"Aspecto pseudovelloso."},{"front":"¿Qué hallazgo microscópico patognomónico se observa en las criptas de la mucosa con CUCI?","back":"Microabscesos crípticos."},{"front":"¿Cómo se describe la extensión de las lesiones en la colonoscopía de un paciente con CUCI?","back":"Lesiones continuas que comienzan en el recto y se extienden proximalmente."},{"front":"¿Qué porcentaje de los casos de CUCI se presenta como pancolitis?","back":"33%."},{"front":"¿Qué escala se utiliza para clasificar la actividad clínica de la Colitis Ulcerativa?","back":"Escala de Truelove."},{"front":"¿Cuál es la tríada clínica clásica de las deposiciones en la Colitis Ulcerativa?","back":"Diarrea sanguinolenta, pus y moco."},{"front":"Mencione dos afectaciones extraintestinales frecuentes en la Colitis Ulcerativa.","back":"Colangitis esclerosante y pioderma gangrenoso."},{"front":"¿Cuál es la complicación más frecuente y grave de la Colitis Ulcerativa mencionada?","back":"Megacolon tóxico."},{"front":"¿Qué signo radiológico característico se observa en la radiografía de abdomen de un paciente con CUCI crónica?","back":"Imagen en tubería de plomo."},{"front":"¿Qué anticuerpos son característicamente positivos en la Colitis Ulcerativa?","back":"pANCA positivo."},{"front":"¿Qué tratamiento de primera elección se utiliza para la CUCI leve a moderada?","back":"Mesalazina y otros aminosalicilatos (5-ASA)."},{"front":"¿Qué fármaco inmunosupresor se utiliza en fases más severas de la CUCI?","back":"Azatioprina."},{"front":"¿Cuál es el anticuerpo monoclonal indicado para casos severos tanto de CUCI como de Crohn?","back":"Infliximab."},{"front":"¿En qué consiste el tratamiento definitivo de la Colitis Ulcerativa?","back":"Cirugía (colectomía)."},{"front":"Definición: Enfermedad de Crohn","back":"Trastorno inflamatorio crónico transmural que puede involucrar cualquier parte del tracto gastrointestinal."},{"front":"¿Cuál es la complicación más frecuente de la Enfermedad de Crohn?","back":"Oclusión intestinal."},{"front":"¿Qué gen ubicado en el cromosoma 16 se asocia con la Enfermedad de Crohn?","back":"NOD2/CAR15."},{"front":"¿Qué característica microscópica se encuentra en el 50% de los pacientes con Crohn y es clave para el diagnóstico?","back":"Granulomas no caseificantes."},{"front":"A diferencia de la CUCI, la inflamación en la Enfermedad de Crohn es de tipo _____.","back":"Transmural"},{"front":"¿Cómo se describe el aspecto macroscópico de la mucosa en la Enfermedad de Crohn?","back":"Aspecto en empedrado."},{"front":"¿Qué tipo de distribución tienen las lesiones en la Enfermedad de Crohn?","back":"Segmentaria (lesiones a saltos)."},{"front":"¿Qué porcentaje de los casos de Enfermedad de Crohn respeta el recto?","back":"50%."},{"front":"¿Qué criterios se utilizan para determinar la presencia de la Enfermedad de Crohn?","back":"Criterios de Lennard-Jones."},{"front":"¿Qué escala clasifica la variedad de la Enfermedad de Crohn?","back":"Escala de Montreal."},{"front":"¿Qué índices se ocupan para determinar el grado de actividad en Crohn?","back":"CDAI y Harvey."},{"front":"¿Cuál es el dato clínico pivote de la Enfermedad de Crohn mencionado para el ENARM?","back":"Masa palpable."},{"front":"¿Cuál es la lesión cutánea más frecuente asociada a la Enfermedad de Crohn?","back":"Eritema nodoso."},{"front":"¿Qué signo radiológico es característico de la Enfermedad de Crohn?","back":"Imagen en manguera de jardín (signo de la cuerda)."},{"front":"¿Qué anticuerpos son característicos de la Enfermedad de Crohn?","back":"ASCA positivo."},{"front":"¿Cuál es el estudio confirmatorio para la Enfermedad de Crohn?","back":"Ileo-colonoscopía."},{"front":"¿Qué esteroide se utiliza para la inducción a la remisión en Crohn leve-moderada?","back":"Budesonida."},{"front":"En la Enfermedad de Crohn refractaria, ¿qué biológicos se recomiendan?","back":"Infliximab o Adalimumab."},{"front":"En ambas enfermedades inflamatorias intestinales, ¿qué infección debe descartarse siempre?","back":"Infección por Clostridium difficile."},{"front":"Definición: Esprúe Tropical","back":"Síndrome malabsortivo asociado a sobrecrecimiento bacteriano que ocurre en zonas tropicales."},{"front":"¿Cuál es el principal microorganismo asociado al Esprúe Tropical?","back":"Escherichia coli (E. coli)."},{"front":"¿Qué deficiencias vitamínicas son características del Esprúe Tropical?","back":"Deficiencia de vitamina B₁₂ y vitamina B₉ (ácido fólico)."},{"front":"¿Cuáles son los síntomas avanzados del Esprúe Tropical relacionados con las deficiencias vitamínicas?","back":"Queilitis y glositis."},{"front":"¿Cuál es el diagnóstico de elección para confirmar el Esprúe Tropical?","back":"Biopsia intestinal."},{"front":"¿Qué hallazgos se observan en la biopsia de un paciente con Esprúe Tropical?","back":"Atrofia de la mucosa, cambios en las vellosidades e infiltración de la lámina propia."},{"front":"¿Cuál es el tratamiento de elección para el Esprúe Tropical?","back":"Reposición de carencias nutricionales y, en algunos casos, tetraciclinas."},{"front":"¿Cómo afecta el tabaquismo a la CUCI en comparación con la Enfermedad de Crohn?","back":"Es un factor protector en CUCI, pero empeora la Enfermedad de Crohn."},{"front":"Mencione tres datos de alarma en el SII que obligan a realizar colonoscopía.","back":"Sangrado rectal, pérdida de peso inexplicable e inicio de síntomas después de los 50 años."},{"front":"¿Qué marcador de inflamación fecal se menciona como auxiliar diagnóstico en Crohn?","back":"Calprotectina fecal."},{"front":"¿Qué fármaco se añade al tratamiento de Crohn en caso de perforación?","back":"Metronidazol."},{"front":"En la CUCI, ¿con qué frecuencia se recomienda realizar una endoscopía de seguimiento?","back":"Cada 10 años."},{"front":"¿Qué combinación de laxantes se indica para el SII con constipación?","back":"Psyllium plantago + polietilenglicol (PEG)."},{"front":"A diferencia de la CUCI, en la Enfermedad de Crohn los abscesos crípticos son _____.","back":"Raros"},{"front":"¿Qué fármaco de mantenimiento se menciona específicamente para la CUCI?","back":"Sulfasalazina."},{"front":"Concepto: Pseudopólipos","back":"Hallazgo macroscópico característico de la Colitis Ulcerativa debido a la inflamación crónica de la mucosa."},{"front":"¿Qué zona del tracto digestivo se ve afectada con mayor frecuencia en la Enfermedad de Crohn?","back":"Íleon, ciego y colon."},{"front":"¿Qué síntoma nocturno se considera un dato de alarma en pacientes con sospecha de SII?","back":"Dolor abdominal nocturno."},{"front":"¿Qué técnica psicológica se menciona además de la TCC para el manejo del SII?","back":"Hipnoterapia."},{"front":"¿Qué efecto tienen los agentes serotoninérgicos en el intestino?","back":"Aumentan la motilidad intestinal, la sensibilidad y la secreción."}]},"11":{"num":11,"name":"HERNIAS","cards":[{"front":"¿Cómo se define una hernia en términos anatómicos generales?","back":"Es la protrusión a través de una debilidad u orificio anormal en una capa envolvente."},{"front":"¿Cuál es la cirugía electiva más frecuente realizada por el cirujano general?","back":"La hernioplastía (reparación de hernias)."},{"front":"Definición: Hernia que no se puede reducir, es blanda y dolorosa, pero no presenta compromiso vascular.","back":"Hernia incarcerada."},{"front":"Una hernia incarcerada que presenta compromiso vascular del contenido herniado se denomina hernia _____.","back":"Estrangulada"},{"front":"¿Cuáles son las características clínicas de una hernia estrangulada?","back":"Es dolorosa, a tensión y presenta una coloración violácea."},{"front":"Definición: Hernia que, después de reducirse manualmente, no vuelve a salir espontáneamente.","back":"Hernia coercible."},{"front":"Definición: Hernia que vuelve a salir de forma inmediata después de haber sido reducida.","back":"Hernia incoercible."},{"front":"¿Qué caracteriza a una hernia por deslizamiento?","back":"Una porción del saco herniario está formada por la pared de una víscera (como el ciego o sigmoides)."},{"front":"¿Cuál es el tipo de hernia más frecuente en la población general?","back":"La hernia inguinal."},{"front":"¿Qué tipo de hernia inguinal es más común en los hombres?","back":"La hernia inguinal indirecta."},{"front":"En la población de adultos mayores, ¿qué tipo de hernia inguinal se presenta con mayor frecuencia?","back":"La hernia inguinal directa."},{"front":"¿En qué sexo son más frecuentes las hernias femorales (crurales)?","back":"En las mujeres."},{"front":"¿Qué lugar ocupan las hernias femorales como causa de obstrucción del intestino delgado?","back":"Segunda causa."},{"front":"Mencione tres factores de riesgo para el desarrollo de hernias inguinales.","back":"Antecedentes genéticos, tabaquismo y problemas pulmonares crónicos."},{"front":"¿Qué hallazgo clínico suele observarse inicialmente en una hernia inguinal no complicada?","back":"Un bulto en la región inguinal que no es doloroso."},{"front":"¿Qué síntoma adicional a la masa dolorosa sugiere una hernia incarcerada?","back":"Un cuadro obstructivo intestinal."},{"front":"¿A través de qué canal atraviesa una hernia crural o femoral?","back":"Atraviesa el canal formado por el ligamento lacunar, la vena femoral y el ligamento inguinal."},{"front":"Las hernias indirectas salen de la cavidad abdominal laterales a los vasos _____.","back":"Epigástricos"},{"front":"¿Cuál es el sitio de protrusión anatómico de una hernia inguinal directa?","back":"El triángulo de Hesselbach."},{"front":"¿Qué tipo de hernia inguinal tiene la capacidad de descender hasta el escroto?","back":"La hernia inguinal indirecta."},{"front":"¿Cuál es el método principal para realizar el diagnóstico de una hernia inguinal?","back":"La exploración física y la clínica."},{"front":"¿Cuál es el estudio de imagen inicial indicado ante una duda diagnóstica de hernia?","back":"Ultrasonido (USG)."},{"front":"Si el ultrasonido no es concluyente para el diagnóstico de hernia, ¿qué estudio se debe realizar a continuación?","back":"Resonancia Magnética (RM)."},{"front":"¿Cuál es el estándar de oro (Gold Standard) para el diagnóstico de hernias de difícil detección?","back":"La herniografía."},{"front":"¿Cuál es la conducta terapéutica ante una hernia inguinal asintomática?","back":"Vigilancia y programación de cirugía electiva."},{"front":"La técnica de elección (estándar de oro) para el tratamiento quirúrgico es la hernioplastía abierta con _____.","back":"Material protésico (malla)"},{"front":"¿Qué técnica quirúrgica sin tensión utiliza una malla plana y tiene el menor índice de recurrencia?","back":"La técnica de Lichtenstein."},{"front":"¿En qué situación se utiliza la técnica de Shouldice (con tensión)?","back":"Cuando existe ausencia de material protésico o en hernias complicadas."},{"front":"¿Cuál es la complicación postquirúrgica más frecuente tras una hernioplastía inguinal?","back":"Retención urinaria."},{"front":"¿Cuál es el analgésico antiinflamatorio (AINE) de elección en el postquirúrgico de hernia?","back":"Ketorolaco."},{"front":"¿Qué tipo de mallas se recomiendan específicamente para la reparación de una hernia femoral?","back":"Mallas preperitoneales (como Stoppa o Wantz)."},{"front":"¿Cuál es el manejo quirúrgico de una hernia estrangulada respecto al uso de malla?","back":"Se realiza reducción o resección del contenido y plastía convencional sin malla."},{"front":"En la clasificación de Nyhus, ¿qué caracteriza al Tipo I?","back":"Hernia indirecta con anillo inguinal interno de diámetro normal."},{"front":"En la clasificación de Nyhus, ¿qué caracteriza al Tipo II?","back":"Hernia indirecta con anillo inguinal interno dilatado y pared posterior intacta."},{"front":"Según Nyhus, ¿qué tipo de hernia se clasifica como IIIa?","back":"Hernia inguinal directa."},{"front":"Según Nyhus, ¿qué tipo de hernia se clasifica como IIIc?","back":"Hernia femoral."},{"front":"¿Qué categoría de Nyhus corresponde a las hernias recurrentes?","back":"Tipo IV."},{"front":"¿Cómo se clasifican las hernias ventrales mediales localizadas a menos de 3 cm por debajo del xifoides?","back":"M1 (Subxifoideas)."},{"front":"¿Qué zona delimita a las hernias ventrales umbilicales (M3) según su localización?","back":"Zona que va de 3 cm por arriba a 3 cm por debajo del ombligo."},{"front":"¿Cómo se llaman las hernias ventrales que ocurren después de un procedimiento quirúrgico?","back":"Postincisionales."},{"front":"¿Cómo se define el tamaño de una hernia ventral 'grande'?","back":"> 10 cm."},{"front":"¿Cuál es la técnica de elección para la colocación de malla retro-aponeurótica en hernias ventrales?","back":"Técnica de Rives."},{"front":"¿Cuál es la relación de frecuencia de hernia umbilical entre mujeres y hombres?","back":"2:1 (más frecuente en mujeres)."},{"front":"Mencione dos síndromes asociados a la presencia de hernia umbilical.","back":"Síndrome de Down y Síndrome de Ehlers-Danlos."},{"front":"¿A qué edad se debe considerar la reparación quirúrgica de una hernia umbilical pediátrica persistente?","back":"Después de los 2 años de edad."},{"front":"¿Cuál es la indicación de tamaño para operar una hernia umbilical pediátrica a cualquier edad?","back":"Defecto herniario mayor de 1.5 cm."},{"front":"¿Cuál es la técnica de primera elección para la reparación de hernia umbilical en adultos sin malla?","back":"Técnica de Mayo."},{"front":"¿A partir de qué diámetro de defecto se recomienda el uso de malla en hernias umbilicales de adultos?","back":"> 3 cm."},{"front":"¿Qué contiene el saco herniario en una hernia de Litre?","back":"Un divertículo de Meckel."},{"front":"Definición: Herniación de una porción de la pared antimesentérica del intestino delgado.","back":"Hernia de Richter."},{"front":"¿En qué localización anatómica surge la hernia de Spiegel?","back":"En la unión del borde lateral del recto abdominal con la línea semilunar de Spiegel."},{"front":"Definición: Hernia que contiene una apendicitis aguda dentro de su saco.","back":"Hernia de Amyand."},{"front":"¿Qué complicación grave puede ocurrir en una hernia con pérdida de domicilio debido al volumen excesivo?","back":"Síndrome compartimental abdominal."},{"front":"¿Cuál es el abordaje quirúrgico de elección para una esplenectomía si el bazo mide menos de 20 cm?","back":"Abordaje laparoscópico."},{"front":"¿Cuál es la indicación de abordaje por laparotomía en una esplenectomía?","back":"Bazo mayor de 20 cm o trauma esplénico."},{"front":"Mencione dos enfermedades hematológicas que son indicaciones frecuentes de esplenectomía.","back":"Esferocitosis hereditaria y Talasemia mayor."},{"front":"¿Qué vacuna es obligatoria antes de una esplenectomía, además de la de Neumococo y Meningococo?","back":"Haemophilus influenzae tipo B."},{"front":"Durante la exploración física, si el saco choca con la punta del dedo, se sospecha de una hernia inguinal _____.","back":"Indirecta"},{"front":"Durante la exploración física, si el saco choca con la parte lateral del dedo, se sospecha de una hernia inguinal _____.","back":"Directa"},{"front":"¿Qué estudio radiológico se debe solicitar en caso de sospecha de oclusión intestinal por hernia?","back":"Radiografía de tórax."},{"front":"¿Cuál es el síntoma cardinal de las hernias de Spiegel?","back":"Dolor con masa palpable."},{"front":"¿Cuál es el porcentaje de recidiva de una hernia cuando no se utiliza material protésico?","back":"Mayor al 50%."},{"front":"¿Cuál es el esquema de seguimiento anual recomendado para un paciente post-hernioplastía?","back":"Seguimiento anual hasta cumplir 5 años."}]},"12":{"num":12,"name":"PATOLOGIA HEPATICA","cards":[{"front":"¿Qué porcentaje de infiltración grasa macrovesicular en los hepatocitos define al hígado graso no alcohólico?","back":"Más del 5%."},{"front":"¿Qué hallazgos histopatológicos distinguen a la esteatohepatitis no alcohólica de la esteatosis simple?","back":"Necroinflamación, balonización hepatocelular y fibrosis."},{"front":"¿Cuál es la enfermedad hepática crónica más frecuente en pacientes en la cuarta década de la vida?","back":"Enfermedad hepática grasa no alcohólica (75%)."},{"front":"Mencione el punto de corte del Índice de Masa Corporal (IMC) considerado factor de riesgo para EHGNA.","back":"IMC > 25."},{"front":"¿Cuál es el estudio de imagen de primera elección para el diagnóstico de hígado graso no alcohólico?","back":"Ultrasonido de hígado y vías biliares."},{"front":"¿Cuál es el estándar de oro para el diagnóstico de la enfermedad hepática grasa no alcohólica?","back":"Biopsia hepática."},{"front":"¿Qué cuerpos de inclusión histológicos se encuentran característicamente en la biopsia de EHGNA?","back":"Cuerpos de Mallory."},{"front":"En las pruebas de funcionamiento hepático de un paciente con EHGNA, ¿qué transaminasa suele estar más elevada?","back":"AST mayor que ALT."},{"front":"¿Qué nivel de ferritina es sugestivo de enfermedad hepática grasa no alcohólica?","back":"Ferritina > 1.5."},{"front":"¿Cuál es el porcentaje de reducción de peso necesario para reducir la enfermedad hepática en un 97%?","back":"Reducción del 10%."},{"front":"¿Cuál es el tratamiento farmacológico de elección para la esteatohepatitis en pacientes diabéticos?","back":"Pioglitazona (30 mg por día)."},{"front":"¿Cuál es el medicamento de primera línea en pacientes no diabéticos con esteatohepatitis no alcohólica?","back":"Vitamina E (Alfa-tocoferol) 800 UI al día."},{"front":"¿Cuál es el principal riesgo sistémico aumentado en pacientes con EHGNA?","back":"Riesgo cardiovascular."},{"front":"El síndrome caracterizado por hígado negruzo e ictericia persistente se conoce como _____.","back":"Síndrome de Dubin-Johnson"},{"front":"¿Cuál es la principal causa de ictericia metabólica constitucional?","back":"Síndrome de Gilbert."},{"front":"¿Cuál es el tratamiento definitivo para la hepatitis alcohólica con un puntaje MELD > 15?","back":"Trasplante hepático."},{"front":"¿Qué fármacos son responsables del 90% de los casos de hepatitis autoinmune?","back":"Minociclina y Nitrofurantoína."},{"front":"¿Cuál es la principal patología asociada a la hepatitis autoinmune?","back":"Hipotiroidismo."},{"front":"¿Con qué alelos del sistema HLA se relaciona la hepatitis autoinmune?","back":"HLA DR3 y DR4."},{"front":"Mencione los autoanticuerpos característicos de la hepatitis autoinmune tipo I.","back":"ANA (Antinucleares) y ASMA (Músculo liso) positivos."},{"front":"¿Cuál es el hallazgo histológico definitivo en la fase crónica de la hepatitis autoinmune?","back":"Hepatitis de interfase."},{"front":"¿Qué tipo de células predominan en la fase aguda de una hepatitis autoinmune según la biopsia?","back":"Células plasmáticas."},{"front":"¿Cuál es el esquema de tratamiento de elección para la hepatitis autoinmune?","back":"Prednisona asociada a Azatioprina."},{"front":"¿Cuál es la vía de transmisión más común para el absceso hepático piógeno?","back":"Conducto biliar (colangitis ascendente)."},{"front":"¿Qué microorganismos son las causas más frecuentes del absceso hepático piógeno?","back":"E. coli y Klebsiella."},{"front":"¿Cuál es el cuadro clínico clásico del absceso hepático piógeno?","back":"Fiebre en picos, dolor en hipocondrio derecho y hepatomegalia."},{"front":"¿Cuál es el tratamiento estándar para un absceso hepático piógeno mayor a 6 cm?","back":"Antibiótico de amplio espectro más drenaje percutáneo."},{"front":"¿Cuál es el agente etiológico del absceso hepático amebiano?","back":"Entamoeba histolytica."},{"front":"Describa el aspecto macroscópico característico del pus en un absceso amebiano.","back":"Pus estéril en pasta de anchoas."},{"front":"¿Cuál es la localización más frecuente del absceso hepático amebiano?","back":"Lóbulo derecho (80% de los casos)."},{"front":"¿Cuál es el esquema farmacológico de elección para el absceso hepático amebiano?","back":"Metronidazol seguido de un amebicida intraluminal (como Paromomicina)."},{"front":"Mencione tres criterios para realizar punción percutánea en un absceso amebiano.","back":"Falla al tratamiento tras 72 horas, absceso en lóbulo izquierdo o volumen > 500 ml."},{"front":"¿Cuál es la complicación más frecuente del absceso hepático amebiano?","back":"Lesión pleuropulmonar."},{"front":"¿Cuál es la causa más común de hepatitis viral en el mundo y específicamente en niños?","back":"Hepatitis A."},{"front":"¿Cuál es el período de incubación promedio de la hepatitis A?","back":"28 días."},{"front":"Para inactivar el virus de la hepatitis A en alimentos, estos deben cocinarse a una temperatura mayor a _____.","back":"85°C"},{"front":"¿Qué marcador serológico confirma una infección aguda por hepatitis A?","back":"IgM anti-VHA positivo."},{"front":"¿Qué fármaco debe evitarse en la hepatitis A por riesgo de desencadenar falla hepática?","back":"Paracetamol."},{"front":"¿En qué población la hepatitis E tiene un riesgo del 20% de evolucionar a hepatitis fulminante?","back":"Mujeres embarazadas."},{"front":"¿Cuál es el período de incubación de la hepatitis E?","back":"5 a 6 semanas."},{"front":"¿Qué tipo de virus (familia y genoma) es la hepatitis B?","back":"Virus de ADN."},{"front":"¿Cuál es el riesgo de cronicidad de la hepatitis B en neonatos infectados?","back":"Aproximadamente el 90%."},{"front":"¿Cuál es el genotipo de Hepatitis B más común en México?","back":"Genotipo H."},{"front":"¿Qué fármaco es la elección para tratar Hepatitis B en pacientes con coinfección por VIH?","back":"Tenofovir."},{"front":"¿Cuál es el marcador serológico que indica infección activa por Hepatitis B?","back":"HBsAg (Antígeno de superficie)."},{"front":"¿Qué marcador indica una alta replicación y capacidad de transmisión en Hepatitis B?","back":"HBeAg (Antígeno e)."},{"front":"La persistencia del HBsAg por más de _____ meses define la cronicidad de la infección.","back":"6 meses"},{"front":"¿Qué anticuerpo indica inmunidad contra Hepatitis B (por vacuna o curación)?","back":"HBsAb (Anti-HBs)."},{"front":"¿Qué marcador distingue una infección aguda de una crónica en Hepatitis B cuando el HBsAg es positivo?","back":"IgM anti-HBc (aguda) vs IgG anti-HBc (crónica)."},{"front":"¿Qué serología presenta un paciente vacunado contra la Hepatitis B?","back":"HBsAb positivo únicamente."},{"front":"¿Qué serología presenta un paciente curado de una infección previa por Hepatitis B?","back":"HBsAb positivo e IgG anti-HBc positivo."},{"front":"¿Cuál es el manejo para un recién nacido de madre HBsAg positiva?","back":"Vacuna contra VHB e inmunoglobulina (IGHB) en las primeras 12 horas."},{"front":"¿Cuál es el riesgo de cronicidad en la infección por Hepatitis C?","back":"80%."},{"front":"¿Cuál es el genotipo de Hepatitis C más común y asociado a mayor cronicidad en México?","back":"Genotipo 1b."},{"front":"¿Cuál es el estudio de tamizaje inicial para Hepatitis C?","back":"ELISA para anticuerpos anti-VHC."},{"front":"¿Cuál es el estudio confirmatorio para la infección por Hepatitis C?","back":"PCR para RNA del VHC."},{"front":"¿Cuál es el tratamiento actual de elección para la Hepatitis C según la GPC (y opciones directas)?","back":"Antivirales de acción directa (como Sofosbuvir)."},{"front":"¿Qué marcador debe solicitarse para el tamizaje de hepatocarcinoma en pacientes con cirrosis por VHC?","back":"Alfafetoproteína."},{"front":"¿Qué condición es indispensable para que el virus de la Hepatitis D pueda infectar una célula?","back":"Presencia del HBsAg (Hepatitis B)."},{"front":"¿Cuál es el único tratamiento recomendado para la Hepatitis D?","back":"Interferón alfa."},{"front":"Diferencie entre coinfección y sobreinfección por VHD en términos de cronicidad.","back":"La coinfección tiene bajo riesgo, mientras que la sobreinfección llega al 100% de cronicidad."},{"front":"¿Qué manifestación extrahepática de la Hepatitis C se asocia a vasculitis y daño renal?","back":"Crioglobulinemia tipo II."},{"front":"Mencione el riesgo de transmisión por pinchazo accidental para VIH, VHC y VHB.","back":"VIH 0.3%, VHC 3% y VHB 30%."}]},"13":{"num":13,"name":"CIRROSIS","cards":[{"front":"En la clasificación de Child-Pugh, ¿qué nivel de bilirrubina asigna 3 puntos?","back":"Mayor a 3 mg/dL."},{"front":"Parámetro de Child-Pugh: Una albúmina sérica de 2.8 a 3.5 g/dL otorga _____ puntos.","back":"2"},{"front":"¿Qué puntaje total en la escala de Child-Pugh define la Clase B?","back":"De 7 a 9 puntos."},{"front":"Concepto: Child-Pugh Clase C","back":"Puntaje de 10 a 15, indicando una cirrosis descompensada con una sobrevida al primer año del 45%."},{"front":"¿Cuál es la sobrevida estimada al segundo año para un paciente Child-Pugh Clase A?","back":"85\\%."},{"front":"En la escala de Child-Pugh, ¿qué grado de encefalopatía suma 3 puntos?","back":"Grado 3 o 4."},{"front":"¿Qué valor de INR se considera para asignar 1 punto en la escala de Child-Pugh?","back":"Menor a 1.7."},{"front":"Definición patológica de cirrosis: Proceso difuso de fibrosis y conversión de la arquitectura normal en _____.","back":"Nódulos estructuralmente anormales."},{"front":"¿Cuál es el límite de consumo diario de alcohol en mujeres para considerar riesgo de cirrosis?","back":"Más de 20 gramos al día."},{"front":"¿Qué fármaco se menciona específicamente como causa de cirrosis en el material?","back":"Metotrexato."},{"front":"En la cirrosis compensada, ¿cómo suele presentarse la analítica hepática?","back":"Sin ninguna alteración."},{"front":"¿Qué complicaciones definen clínicamente a la cirrosis descompensada?","back":"Hemorragia variceal (STDA), ictericia, ascitis y encefalopatía."},{"front":"¿Cuál es el estándar de oro (Gold Standard) para el diagnóstico de cirrosis?","back":"Biopsia hepática."},{"front":"¿Cada cuánto tiempo se debe realizar una endoscopia de seguimiento si no se encuentran várices en el diagnóstico inicial?","back":"Cada 2 años."},{"front":"En caso de encontrar una lesión mayor a 1 cm en el ultrasonido de un cirrótico, ¿qué estudio sigue?","back":"Tomografía Computarizada (TAC)."},{"front":"¿Qué porcentaje de pacientes con cirrosis son asintomáticos?","back":"40\\%."},{"front":"¿Cuál es la recomendación de consumo de sodio diario en el tratamiento de la cirrosis?","back":"De 1 a 2 gramos al día."},{"front":"¿Por qué se deben evitar los AINES en pacientes con cirrosis?","back":"Porque pueden inducir falla renal."},{"front":"¿Qué tipo de dieta se recomienda para un paciente con cirrosis?","back":"Hiperproteica de origen vegetal."},{"front":"¿Cuándo se define que la Hipertensión Portal es clínicamente significativa?","back":"Cuando la presión es mayor o igual a 10 mmHg."},{"front":"¿Cuál es el nivel normal de presión en el sistema portal?","back":"De 1 a 5 mmHg."},{"front":"¿A partir de qué gradiente de presión portosistémica aumenta significativamente el riesgo de sangrado variceal?","back":"Mayor a 12 mmHg."},{"front":"Causa de Hipertensión Portal: La trombosis de la vena porta es un ejemplo de causa _____.","back":"Prehepática."},{"front":"¿Qué síndrome se clasifica como una causa posthepática de Hipertensión Portal?","back":"Síndrome de Budd-Chiari."},{"front":"¿Cuál es la complicación letal más común de la cirrosis?","back":"Várices esofágicas."},{"front":"Clasificación de várices: Se consideran várices grandes cuando su tamaño es _____.","back":"Igual o mayor a 5 mm."},{"front":"En la endoscopia, ¿qué hallazgo se describe como \"mucosa en piel de serpiente\"?","back":"Gastropatía hipertensiva portal (o mucosa en mosaico)."},{"front":"Mencione una contraindicación para realizar una endoscopia en un paciente cirrótico.","back":"Trombocitopenia menor a 50.000."},{"front":"¿Cuál es el mecanismo de acción de los betabloqueadores en la profilaxis de várices?","back":"Disminuyen la presión portal al reducir el flujo esplácnico."},{"front":"¿En qué pacientes Child A está indicada la profilaxis primaria con betabloqueadores?","back":"En aquellos con várices mayores a 5 mm."},{"front":"¿Qué combinación de tratamiento se debe usar de por vida en la profilaxis secundaria de várices?","back":"Betabloqueadores combinados con técnica de erradicación endoscópica (ligadura o escleroterapia)."},{"front":"¿Cuál es el fármaco de elección en el manejo inicial de una hemorragia variceal aguda?","back":"Terlipresina."},{"front":"En una hemorragia aguda, ¿en qué ventana de tiempo se debe realizar el tratamiento endoscópico?","back":"Durante las primeras 24 horas."},{"front":"¿Cuál es la técnica endoscópica preferida para várices mayores a 5 mm en fase aguda?","back":"Ligadura variceal."},{"front":"¿Qué sonda se debe colocar si no se cuenta con endoscopia durante un sangrado activo?","back":"Sonda de Sengstaken-Blakemore o sonda de Linton."},{"front":"¿Cuál es la duración total del tratamiento con Terlipresina o Somatostatina en hemorragia aguda?","back":"5 días."},{"front":"¿Qué porcentaje de pacientes con cirrosis y ascitis morirán en un plazo de dos años?","back":"50\\%."},{"front":"¿Cuál es el síntoma más frecuente de la ascitis?","back":"Aumento del perímetro abdominal."},{"front":"Exploración física de ascitis: La presencia del signo de la ola indica un volumen de al menos _____ litros.","back":"10"},{"front":"¿Cuál es el mejor método diagnóstico para detectar ascitis leve (desde 100 ml)?","back":"Ultrasonido abdominal."},{"front":"Grados de ascitis: La ascitis detectable solo por ultrasonido se clasifica como Grado _____.","back":"I"},{"front":"¿Qué indica un Gradiente de Albúmina Sérica/Ascítica (GASA) mayor a 1.1 g/dL?","back":"Hipertensión portal."},{"front":"¿Cuál es el tratamiento farmacológico inicial para la ascitis moderada?","back":"Espironolactona 100 mg y Furosemida 40 mg vía oral."},{"front":"¿Cuál es la dosis máxima de Espironolactona recomendada en el tratamiento de la ascitis?","back":"400 mg."},{"front":"En pacientes con ascitis y edema, ¿cuál es la pérdida de peso diaria esperada con el tratamiento?","back":"1 kg por día."},{"front":"¿Qué fármaco sustituye a la Furosemida en caso de intolerancia?","back":"Amilorida."},{"front":"Paracentesis: Si se extraen más de 5 litros de líquido, se debe reponer albúmina a una dosis de _____ por litro extraído.","back":"8 a 10 gramos."},{"front":"¿Qué volumen de Dextrán se administra por cada litro extraído si la paracentesis es menor a 5 litros?","back":"125 ml."},{"front":"Criterio diagnóstico de Peritonitis Bacteriana Espontánea: Presencia de más de _____ polimorfonucleares (PMN) por mm³.","back":"250"},{"front":"¿Cuál es el agente etiológico más común en la ascitis infecciosa espontánea?","back":"Escherichia coli."},{"front":"¿Cuál es el tratamiento antibiótico de elección para la Peritonitis Bacteriana Espontánea?","back":"Cefotaxima u Ofloxacino."},{"front":"¿A qué se debe principalmente la Encefalopatía Hepática según la fisiopatología?","back":"Aumento de amonio que altera la actividad de dopamina y serotonina."},{"front":"¿Qué factores son los principales desencadenantes de la Encefalopatía Hepática?","back":"Estreñimiento y fármacos."},{"front":"En caso de duda diagnóstica en encefalopatía, ¿qué hallazgo se busca en el electroencefalograma?","back":"Ondas trifásicas."},{"front":"Tratamiento de Encefalopatía Hepática: El fármaco de primera línea para disminuir el amonio es la _____.","back":"Lactulosa (o lactitol)."},{"front":"¿Qué antibiótico no absorbible es el más usado para tratar la encefalopatía hepática?","back":"Rifaximina."},{"front":"¿Cuál es el antídoto indicado si la encefalopatía es desencadenada por benzodiazepinas?","back":"Flumazenil."},{"front":"Criterios de West-Haven: El Grado II se caracteriza por la presencia de _____.","back":"Asterixis franca."},{"front":"¿Qué grado de West-Haven presenta inversión del patrón de sueño y euforia?","back":"Grado I."},{"front":"Enfermedad de Wilson: ¿Cuál es el signo ocular característico?","back":"Anillos de Kayser-Fleischer."},{"front":"¿Cuál es el tratamiento farmacológico de elección para la Enfermedad de Wilson?","back":"D-penicilamina y piridoxina (B6)."},{"front":"¿Qué parámetros utiliza el sistema MELD para priorizar el trasplante hepático?","back":"Bilirrubina sérica, INR y creatinina sérica."},{"front":"Trasplante hepático: Se pone en lista de espera a pacientes con cirrosis descompensada y un MELD mayor a _____.","back":"10"},{"front":"¿Cuál es la indicación más frecuente de trasplante hepático en la población pediátrica?","back":"Atresia de vías biliares."},{"front":"¿Qué tipo de compatibilidad NO es necesaria para un trasplante hepático?","back":"Compatibilidad HLA."},{"front":"Tipos de rechazo: El rechazo que ocurre entre el día 4 y 14 posoperatorio se denomina _____.","back":"Agudo celular o reversible."},{"front":"¿Qué tipo de rechazo de trasplante hepático solo responde al retrasplante?","back":"Rechazo hiperagudo o fulminante."},{"front":"¿Cuál es la supervivencia estimada a los 5 años después de un trasplante hepático?","back":"60 a 75\\%."},{"front":"Esprúe Tropical: ¿Cuál es el antecedente epidemiológico clave para el diagnóstico?","back":"Viaje reciente a zonas tropicales."},{"front":"¿Qué deficiencias vitamínicas suele causar el Esprúe Tropical?","back":"Vitamina B12 y B9 (Ácido fólico)."},{"front":"¿Qué hallazgo se espera encontrar en la biopsia de un paciente con Esprúe Tropical?","back":"Atrofia de la mucosa, cambios en vellosidades e infiltración de la lámina propia."},{"front":"¿Cuál es el tratamiento de elección para el Esprúe Tropical?","back":"Reposición de carencias nutricionales y tetraciclinas."},{"front":"¿Qué porcentaje de pacientes cirróticos Child C presentan várices esofágicas?","back":"85\\%."},{"front":"Etiología de HTP: ¿Qué porcentaje de los casos se debe a causas intrahepáticas (cirrosis)?","back":"95\\%."},{"front":"¿Cuál es la profilaxis recomendada para la Peritonitis Bacteriana Espontánea?","back":"TMP/SMZ (Trimetroprim/Sulfametoxazol)."}]},"14":{"num":14,"name":"PATOLOGIA ARTERIAL Y VENOSA","cards":[{"front":"¿Cuáles son las tres causas principales de la insuficiencia arterial aguda?","back":"Embolismo, trombosis o trauma vascular."},{"front":"¿Cuál es el origen más frecuente de un embolismo en la insuficiencia arterial aguda?","back":"Cardíaco (80% de los casos)."},{"front":"¿Cuál es la causa subyacente más común de la insuficiencia arterial de origen trombótico?","back":"Aterosclerosis."},{"front":"¿Cuál es la arteria que se ve afectada con mayor frecuencia en la insuficiencia arterial aguda?","back":"La arteria femoral."},{"front":"¿Cuál es la probabilidad de salvar una extremidad si la isquemia arterial aguda supera las 6 horas?","back":"Pocas probabilidades."},{"front":"¿Qué complicación sistémica puede ocurrir tras la reperfusión de una extremidad isquémica?","back":"Falla orgánica múltiple y colapso cardiovascular."},{"front":"Mencione las 6 \"P\" de la clínica de insuficiencia arterial aguda.","back":"Pain (dolor), Palidez, Parestesias, Parálisis, Pérdida de temperatura y Pulsos ausentes."},{"front":"¿Cuál es el estudio de diagnóstico de elección para la insuficiencia arterial aguda?","back":"Angiografía."},{"front":"Según la clasificación de Rutherford, ¿qué caracteriza al Grado I (viable)?","back":"Extremidad viable con presencia de señal Doppler."},{"front":"Según Rutherford, ¿qué déficit diferencia al Grado IIB del Grado IIA?","back":"El Grado IIB presenta déficit motor, además del sensitivo."},{"front":"Según Rutherford, ¿cuál es el manejo indicado para una extremidad Grado III (no viable)?","back":"Amputación."},{"front":"¿Qué procedimiento quirúrgico está indicado en un paciente con Rutherford IIB por riesgo de síndrome compartimental?","back":"Fasciotomía."},{"front":"¿Cuál es una contraindicación absoluta para la trombólisis relacionada con antecedentes neurológicos?","back":"Antecedentes de EVC hemorrágico o neoplasia intracraneal."},{"front":"¿Cuál es el manejo inicial de la rabdomiólisis secundaria a isquemia si aún no hay daño renal?","back":"Administración de líquidos, manitol y bicarbonato (HCO₃)."},{"front":"¿Cuál es el síntoma más frecuente de la Enfermedad Arterial Periférica (EAP)?","back":"Claudicación intermitente."},{"front":"¿Qué fenómeno clínico se caracteriza por dolor en piernas durante la deambulación que alivia con el reposo?","back":"Claudicación intermitente."},{"front":"¿Qué nombre recibe la manifestación clásica de la EAP donde hay isquemia digital pero los pulsos pedios están normales?","back":"Síndrome del dedo azul."},{"front":"¿Qué porcentaje de pacientes con Enfermedad Arterial Periférica son asintomáticos?","back":"20%."},{"front":"¿Cuál es la localización anatómica más frecuente de la Enfermedad Arterial Periférica?","back":"Femoro-poplítea (43%)."},{"front":"¿Cuál es la causa más frecuente de muerte en pacientes con Enfermedad Arterial Periférica?","back":"Enfermedad cardiovascular."},{"front":"¿Cómo se calcula el Índice Tobillo-Brazo (ITB)?","back":"Dividiendo la presión sistólica del tobillo entre la presión sistólica braquial."},{"front":"¿Cuál es el rango considerado normal para el Índice Tobillo-Brazo en reposo?","back":"1.00 a 1.40."},{"front":"¿Qué valor de Índice Tobillo-Brazo se considera diagnóstico de EAP (anormal)?","back":"Menor a 0.90."},{"front":"¿Qué estudio se debe realizar si el ITB de un paciente es limítrofe (0.91 a 0.99)?","back":"ITB con ejercicio (prueba de banda sin fin)."},{"front":"¿Cuál es el estudio de imagen no invasivo que confirma el diagnóstico de EAP?","back":"Ecografía Doppler Dúplex."},{"front":"¿Cuál es el tratamiento farmacológico de elección para mejorar la distancia de caminata en estadios II de EAP?","back":"Cilostazol."},{"front":"¿Cuál es la principal contraindicación para el uso de Cilostazol?","back":"Falla cardíaca."},{"front":"¿En qué caso específico de EAP está indicada la Pentoxifilina?","back":"Únicamente en presencia de úlcera activa."},{"front":"¿Qué tipo de revascularización se prefiere para arterias proximales suprapoplíteas?","back":"Reparación endovascular (tromboembolectomía)."},{"front":"¿Cómo se define fisiopatológicamente la insuficiencia venosa crónica (IVC)?","back":"Incapacidad funcional del retorno sanguíneo por anomalías de la pared venosa o valvular."},{"front":"¿A qué se debe específicamente la formación de várices en la IVC?","back":"A una insuficiencia valvular de las venas perforantes."},{"front":"¿Cuántas horas de bipedestación prolongada se consideran factor de riesgo para IVC?","back":"Más de 5 horas."},{"front":"¿Cuál suele ser el primer síntoma de la insuficiencia venosa crónica?","back":"Sensación de pesadez o aumento de peso en las piernas."},{"front":"¿Qué hallazgo en la medición de los muslos es sugestivo de insuficiencia venosa crónica?","back":"Una diferencia de circunferencia mayor a 1 cm."},{"front":"¿En qué sitio anatómico específico aparecen típicamente las úlceras venosas?","back":"En el maléolo interno."},{"front":"En la clasificación CEAP, ¿a qué hallazgo corresponde la Clase 2?","back":"Venas varicosas."},{"front":"En la clasificación CEAP, ¿a qué hallazgo corresponde la Clase 3?","back":"Edema."},{"front":"En la clasificación CEAP, ¿qué diferencia a la Clase 6 de la Clase 5?","back":"La Clase 6 tiene úlcera activa y la Clase 5 tiene úlcera cicatrizada."},{"front":"¿Qué evalúa específicamente la prueba de Trendelenburg?","back":"El reflujo a través de las venas perforantes o superficiales."},{"front":"¿Qué sistema venoso valora la maniobra de Perthes?","back":"El sistema venoso profundo."},{"front":"¿Cuál es el Gold Standard diagnóstico para la IVC cuando no hay Doppler disponible?","back":"Pletismografía."},{"front":"¿Cuál es la recomendación de altura de tacón para pacientes con IVC?","back":"Menor a 3 cm."},{"front":"¿Qué presión de medias de compresión se recomienda para personal con riesgo profesional alto?","back":"22 a 29 mmHg."},{"front":"¿Para qué tamaño de venas está indicada la escleroterapia en IVC?","back":"Venas menores a 5 mm."},{"front":"¿Cuál es el sitio más frecuente de formación de trombos en la Trombosis Venosa Profunda (TVP)?","back":"El plexo venoso a nivel del sóleo."},{"front":"¿Qué signo clínico de TVP consiste en dolor a la palpación del cordón venoso en la zona poplítea?","back":"Signo de Olow."},{"front":"¿Qué es el signo de Homans?","back":"Dolor en la pantorrilla al realizar flexión dorsal del pie."},{"front":"¿Qué signo de TVP se define por la presencia de 3 venas pretibiales dilatadas que persisten al elevar la pierna?","back":"Signo de Pratt."},{"front":"Según la escala de Wells, ¿qué estudio se solicita ante una baja probabilidad de TVP?","back":"Dímero D."},{"front":"¿Qué utilidad clínica principal tiene el Dímero D en la sospecha de TVP o TEP?","back":"Su elevado valor predictivo negativo (sirve para excluir la enfermedad)."},{"front":"¿Cuál es el objetivo terapéutico de INR durante la anticoagulación con dicumarínicos en TVP?","back":"Entre 2 y 3."},{"front":"¿Qué componentes integran la Tríada de Virchow?","back":"Lesión endotelial, estasis sanguínea y estado de hipercoagulabilidad."},{"front":"¿De dónde proviene el émbolo que origina el Tromboembolismo Pulmonar (TEP) en el 90-95% de los casos?","back":"De una trombosis venosa profunda de los miembros inferiores."},{"front":"¿Cuál es el estado de hipercoagulabilidad hereditario más frecuente en pacientes con TEP?","back":"Resistencia a la proteína C activada (Factor V de Leiden)."},{"front":"¿Cuáles son los síntomas más frecuentes del embolismo pulmonar?","back":"Disnea y dolor pleurítico."},{"front":"¿Cuáles son los signos clínicos más constantes en el TEP?","back":"Taquicardia y taquipnea."},{"front":"¿Cómo se define un TEP masivo según la clínica?","back":"Aquel que se presenta con hipotensión o shock."},{"front":"¿Qué hallazgo define a un TEP como moderado/grave?","back":"Ausencia de shock, pero con signos ecocardiográficos de sobrecarga del ventrículo derecho."},{"front":"¿Cuál es la técnica de imagen de elección ante la sospecha de TEP?","back":"TC helicoidal con contraste (Angio-TC)."},{"front":"¿Cuál es el Gold Standard para el diagnóstico de Tromboembolismo Pulmonar?","back":"Angiografía pulmonar."},{"front":"¿En qué tipo de TEP está indicada la Heparina no fraccionada junto con fibrinolíticos?","back":"En el TEP masivo con compromiso hemodinámico."},{"front":"¿Cuál es la duración recomendada del tratamiento anticoagulante tras un primer episodio de TEP con factores de riesgo reversibles?","back":"3 a 6 meses."},{"front":"¿En qué situación está indicado un filtro de vena cava inferior?","back":"Contraindicación para anticoagulación o progresión del cuadro a pesar del tratamiento."},{"front":"¿Bajo qué condiciones se debe mantener la anticoagulación de por vida tras una TVP?","back":"Si la causa no es reversible o si el cuadro es recurrente."}]},"15":{"num":15,"name":"COLOPROCTO","cards":[{"front":"¿Cómo se define fisiopatológicamente la enfermedad hemorroidal?","back":"Como el prolapso de las estructuras vasculares del canal anal por rotura de sus mecanismos de sujeción."},{"front":"¿Cuáles son las tres localizaciones principales de los cojinetes hemorroidales?","back":"Lateral izquierdo, anterolateral derecho y posterolateral derecho."},{"front":"¿Cuál es el pico de incidencia por edad y sexo de la enfermedad hemorroidal?","back":"Hombres de 45 a 65 años."},{"front":"¿Cuál es la causa más frecuente de rectorragia en atención primaria?","back":"La enfermedad hemorroidal."},{"front":"Mencione tres factores de riesgo principales para el desarrollo de hemorroides.","back":"Aumento de presión intraabdominal, embarazo y estreñimiento."},{"front":"¿Dónde se localizan las hemorroides externas respecto a la línea dentada?","back":"Por debajo de la línea dentada (tercio inferior del canal anal)."},{"front":"¿De qué tipo de epitelio están cubiertas las hemorroides internas?","back":"Epitelio columnar o de transición."},{"front":"¿Cuál es la manifestación clínica más común de las hemorroides internas?","back":"Sangrado rectal (rectorragia)."},{"front":"¿Qué complicación suele indicar la presencia de dolor en las hemorroides externas?","back":"Trombosis hemorroidal."},{"front":"¿Cuál es la tríada clínica de las hemorroides externas?","back":"Dolor, prurito anal y tumoración."},{"front":"¿En qué posiciones se recomienda colocar al paciente para la exploración física proctológica?","back":"Posición genupectoral lateral izquierda o posición de Sims."},{"front":"¿Qué estudio diagnóstico se indica en caso de duda tras la historia clínica y el examen físico de hemorroides?","back":"Anuscopía."},{"front":"¿En qué situaciones se debe realizar una colonoscopia en un paciente con sospecha de hemorroides?","back":"Ante la sospecha de cáncer de colon o enfermedad de Crohn."},{"front":"Definición de hemorroides internas Grado I.","back":"No existe prolapso de los paquetes hemorroidales."},{"front":"Definición de hemorroides internas Grado II.","back":"Prolapso con maniobra de Valsalva que presenta reducción espontánea."},{"front":"Definición de hemorroides internas Grado III.","back":"Prolapso con maniobra de Valsalva que requiere reducción manual."},{"front":"Definición de hemorroides internas Grado IV.","back":"Prolapso crónico que no puede reducirse manualmente."},{"front":"¿Cuál es el pilar del tratamiento conservador inicial para hemorroides grado I y II?","back":"Dieta rica en fibra, líquidos, baños de asiento y evitar el sedentarismo."},{"front":"¿Cuál es el tiempo máximo recomendado para el uso de anestésicos tópicos en hemorroides?","back":"< 7 días."},{"front":"¿Qué fármacos venotónicos están contraindicados en el embarazo para el manejo de hemorroides?","back":"Flavonoides."},{"front":"¿Cuál es el tratamiento de elección para hemorroides grado II que fracasan al manejo conservador?","back":"Ligadura con banda elástica."},{"front":"¿Cuál es el tratamiento quirúrgico definitivo para hemorroides grado III y IV?","back":"Hemorroidectomía."},{"front":"¿Qué técnica quirúrgica tiene menor sintomatología postoperatoria pero mayor índice de recidiva en hemorroides?","back":"Hemorroidopexia."},{"front":"¿Cuál es el tratamiento para una trombosis hemorroidal externa si el paciente no tolera el dolor?","back":"Hemorroidectomía."},{"front":"¿Cómo se define un absceso anal?","back":"Colección de pus en los espacios perianales por obstrucción de una glándula anal con estasis bacteriana."},{"front":"¿Cuál es el pico de edad de incidencia para los abscesos anales?","back":"Entre 20 y 60 años (media de 40 años)."},{"front":"¿Cuál es el microorganismo más frecuentemente aislado en un absceso anorectal?","back":"E. coli."},{"front":"¿Cuál es la complicación más frecuente de un absceso anal?","back":"Fístula perianal."},{"front":"¿Cuál es la causa más común de abscesos anales?","back":"Infección criptoglandular."},{"front":"¿Cuál es la localización más frecuente de los abscesos anales (60%)?","back":"Perianal."},{"front":"¿Qué nombre recibe la colección en herradura que se extiende por la fosa isquioanal?","back":"Absceso isquiorrectal."},{"front":"¿Qué tipo de absceso anal se caracteriza por dolor intenso al tacto rectal?","back":"Absceso intraesfintérico."},{"front":"¿Cuál es la tríada clínica típica del absceso anorectal?","back":"Dolor intenso a la defecación, tumefacción eritematosa y signos de infección (fiebre)."},{"front":"¿Qué estudio de imagen es útil para encontrar la cripta de origen del absceso?","back":"Ultrasonido endoanal."},{"front":"¿Cuál es el 'Gold Standard' diagnóstico para abscesos supraelevadores o asociados a enfermedad de Crohn?","back":"Resonancia Magnética (RM)."},{"front":"¿Cuándo se reserva la Tomografía Axial Computarizada (TAC) en el diagnóstico de abscesos?","back":"Ante sospecha de abscesos supraesfinterianos o pélvicos."},{"front":"¿Cuál es el tratamiento primario de un absceso anal?","back":"Incisión y drenaje amplio."},{"front":"Mencione dos grupos de pacientes que requieren antibióticos tras el drenaje de un absceso.","back":"Inmunodeprimidos, diabéticos, cardiópatas con prótesis o pacientes en sepsis."},{"front":"¿Cuál es el esquema antibiótico de elección para abscesos anorectales?","back":"Metronidazol más Ciprofloxacino."},{"front":"¿Cuál es el manejo de un absceso anal en niños menores de dos años?","back":"Tratamiento conservador con Amoxicilina/Clavulanato."},{"front":"¿Qué porcentaje de abscesos anales desarrollan una fístula perianal?","back":"50%."},{"front":"¿Cómo se define una fístula perianal?","back":"Trayecto inflamatorio crónico que comunica la mucosa del recto con la piel perianal."},{"front":"¿Qué diferencia al orificio interno del orificio externo en una fístula?","back":"El interno está en la mucosa rectal y el externo en la piel perianal."},{"front":"¿Cuál es el tipo de fístula más común según la clasificación de Parks?","back":"Fístula interesfinteriana."},{"front":"¿Qué criterio define a una fístula como compleja respecto al esfínter externo?","back":"Cuando el trayecto compromete más del 30 - 50% del esfínter externo."},{"front":"¿Cuál es el síntoma cardinal de la fístula perianal?","back":"Supuración crónica de material purulento que mancha la ropa interior."},{"front":"¿Cuál es el estudio de primera línea ante la sospecha de una fístula compleja?","back":"Ultrasonido endoanal."},{"front":"¿Qué utilidad tiene la fistulografía?","back":"Es útil específicamente en las fístulas extraesfinterianas."},{"front":"¿Cuál es el tratamiento de elección para una fístula simple?","back":"Fistulotomía más marsupialización."},{"front":"¿Cuál es el manejo quirúrgico de una fístula compleja sin incontinencia?","back":"Colocación de Setón más fistulotomía en intervalos."},{"front":"¿Cuál es la complicación más grave de la cirugía de fístula anal?","back":"Incontinencia fecal."},{"front":"¿Qué escala se utiliza para evaluar la incontinencia fecal postoperatoria?","back":"Escala de Wexner."},{"front":"¿Qué fármaco biológico se indica en fístulas perineales complejas asociadas a Crohn?","back":"Infliximab."},{"front":"¿Cómo se define una fisura anal aguda?","back":"Desgarro superficial del anodermo con una evolución menor a 6 semanas."},{"front":"¿Cuál es la localización más frecuente de la fisura anal (90%)?","back":"Línea media posterior."},{"front":"¿A qué se asocia frecuentemente una fisura anal de localización anterior?","back":"Trauma obstétrico."},{"front":"¿Cuáles son los dos principales factores de riesgo para la fisura anal?","back":"Enfermedad hemorroidal y estreñimiento."},{"front":"¿Cuál es el síntoma cardinal de la fisura anal?","back":"Dolor anal intenso, ardoroso y quemante trans y posdefecatorio."},{"front":"¿Qué elementos componen la Tríada de Brodie en la fisura anal crónica?","back":"Papila anal hipertrófica, colgajo centinela y base de la fisura con fibras del esfínter interno expuestas."},{"front":"¿Cuál es el tratamiento médico de primera línea para la fisura anal crónica?","back":"Diltiazem tópico al 2% por 6 a 8 semanas."},{"front":"¿Cuál es el siguiente paso terapéutico en una fisura crónica que no responde a Diltiazem?","back":"Aplicación de Toxina Botulínica (20-25 U)."},{"front":"¿Cuál es el tratamiento quirúrgico de elección para la fisura anal crónica con hipertonía?","back":"Esfinterotomía lateral interna."},{"front":"¿Qué efecto secundario se asocia frecuentemente al uso de Diltiazem tópico?","back":"Prurito anal."},{"front":"¿Qué es el quiste pilonidal?","back":"Inflamación crónica de los folículos pilosos en la región sacro-coccígea (surco natal)."},{"front":"¿Cuál es el sitio anatómico específico donde se localiza el quiste pilonidal?","back":"Foseta glabelar."},{"front":"¿Cuál es el tratamiento estándar para el quiste pilonidal?","back":"Resección, legrado y cierre primario."},{"front":"¿Cuál es la complicación más frecuente tras la cirugía de quiste pilonidal?","back":"Infección de la herida (9%)."},{"front":"¿Cuántos gramos de fibra dietética se recomienda consumir al día para prevenir patología perianal?","back":"20 a 30 gramos."}]},"16":{"num":16,"name":"UROLOGIA PARTE 1","cards":[{"front":"¿Cuál es el principal microorganismo causal de la infección de vías urinarias (IVU)?","back":"Escherichia coli."},{"front":"Los microorganismos del tracto urinario se adquieren principalmente por la vía _____.","back":"Ascendente."},{"front":"¿Por qué la recurrencia de IVU es más común en el sexo femenino?","back":"Por la corta longitud de la uretra y la proximidad al ano y vagina."},{"front":"¿Cuántos urocultivos consecutivos se requieren para diagnosticar bacteriuria asintomática en mujeres?","back":"Dos urocultivos."},{"front":"¿Cuántos urocultivos se requieren para diagnosticar bacteriuria asintomática en hombres?","back":"Un solo urocultivo."},{"front":"¿Cuál es el recuento bacteriano necesario para definir bacteriuria asintomática?","back":"≥ 10⁵ UFC/ml."},{"front":"¿Cómo se define una infección del tracto urinario (ITU) recurrente?","back":"Tres o más episodios al año o dos en los últimos seis meses."},{"front":"¿A qué grupo poblacional se limita la definición de ITU no complicada?","back":"Mujeres no embarazadas sin anomalías anatómicas o funcionales."},{"front":"¿Qué condición clasifica automáticamente a un hombre con ITU como una \"ITU complicada\"?","back":"El simple hecho de ser varón."},{"front":"¿En qué período de tiempo se considera que una ITU está asociada a sonda vesical tras su retiro?","back":"En las primeras 72 horas."},{"front":"En una tira reactiva, ¿cuál es el dato de mayor importancia por su especificidad para IVU?","back":"Nitritos."},{"front":"En una tira reactiva, ¿cuál es el parámetro con mayor sensibilidad para detectar infección?","back":"Esterasa leucocitaria."},{"front":"¿Qué síntomas permiten descartar patologías ginecológicas durante el diagnóstico de una IVU?","back":"Ausencia de síntomas vaginales, flujo, ardor o prurito."},{"front":"¿Cuál es el estándar de oro para el diagnóstico de una infección de vías urinarias?","back":"Urocultivo."},{"front":"¿Por qué se recomiendan los esquemas cortos de 3 a 5 días para el tratamiento de la IVU?","back":"Presentan menos efectos adversos gastrointestinales."},{"front":"¿En qué pacientes se pueden considerar los AINEs como tratamiento de primera línea para síntomas leves de IVU?","back":"Pacientes menores de 65 años."},{"front":"¿Qué fármaco se sugiere específicamente para el control del dolor y síntomas irritativos urinarios?","back":"Fenazopiridina."},{"front":"¿Cuál es la recomendación de consumo de líquidos para prevenir infecciones urinarias?","back":"Mayor a 1.5 litros de agua al día."},{"front":"¿Qué remedios o hábitos se recomienda evitar para no interferir con la salud urinaria?","back":"Jugo de arándano, alcalinizantes de orina y duchas vaginales."},{"front":"¿Cuál es la infección hospitalaria más frecuente?","back":"Infección del tracto urinario."},{"front":"¿En qué caso se debe tratar la bacteriuria asintomática en un paciente con sonda vesical?","back":"Si la bacteriuria persiste 3 días después del retiro de la sonda."},{"front":"Definición: Pielonefritis aguda.","back":"Inflamación del parénquima y sistema colector por un proceso infeccioso con urocultivo positivo."},{"front":"¿Cuál es el recuento de unidades formadoras de colonias necesario para diagnosticar pielonefritis?","back":"Al menos 100.000 UFC/mm³."},{"front":"Además de E. coli, ¿cuáles son los otros dos patógenos más frecuentes en la pielonefritis?","back":"Proteus y Klebsiella."},{"front":"¿Qué característica clínica permite diferenciar una pielonefritis de una ITU baja?","back":"Presencia de síntomas sistémicos como fiebre, escalofríos y dolor en flanco."},{"front":"¿Cuándo se indica realizar un ultrasonido de tracto urinario en pacientes con pielonefritis?","back":"Si los síntomas persisten después de 72 horas de tratamiento."},{"front":"¿Cuál es el tratamiento antibiótico ambulatorio de elección para pielonefritis leve-moderada?","back":"Ciprofloxacino 1g o Levofloxacino 750mg."},{"front":"¿Cuál es la duración del tratamiento para pielonefritis en el sexo masculino?","back":"14 días."},{"front":"¿Qué manifestación clínica obliga a cambiar el manejo de la pielonefritis a vía intravenosa y hospitalaria?","back":"Intolerancia a la vía oral como náuseas y vómitos."},{"front":"¿Cuál es el agente causal asociado a la pielonefritis granulomatosa?","back":"Proteus."},{"front":"¿Qué microorganismo es el agente causal más frecuente del absceso perirrenal?","back":"Staphylococcus aureus."},{"front":"¿Cuál es el tratamiento recomendado para un absceso renal causado por E. coli?","back":"Ceftriaxona más drenaje percutáneo."},{"front":"¿Qué estudio de imagen es el de elección para diagnosticar abscesos renales o pielonefritis enfisematosa?","back":"Tomografía Axial Computarizada (TAC)."},{"front":"¿Cuál es el tratamiento definitivo para la pielonefritis enfisematosa?","back":"Nefrostomía y drenaje."},{"front":"¿Cuál es el segundo sitio más común de infección extrapulmonar por tuberculosis?","back":"Tuberculosis genitourinaria."},{"front":"¿Qué vía de transmisión utiliza Mycobacterium tuberculosis para llegar al tracto urinario?","back":"Vía hematógena."},{"front":"¿Qué elementos componen la tríada de Colombino en la tuberculosis genitourinaria?","back":"Orina ácida, piuria y orina aséptica."},{"front":"¿Cuál es el diagnóstico de elección (cultivo) para la tuberculosis genitourinaria?","back":"Cultivo de Löwenstein."},{"front":"¿Qué hallazgo en la urografía es característico de la tuberculosis genitourinaria?","back":"Mordisqueo de cálices."},{"front":"¿Cómo se define la retención urinaria aguda?","back":"Incapacidad súbita de vaciamiento de la vejiga a pesar de tener una vejiga llena."},{"front":"¿Cuál es la principal etiología de retención urinaria en los hombres?","back":"Hiperplasia prostática."},{"front":"¿Cuál es la causa más frecuente de retención urinaria en las mujeres?","back":"Prolapso pélvico."},{"front":"¿A partir de qué volumen urinario es posible detectar matidez a la percusión vesical?","back":"150 ml."},{"front":"¿Qué volumen de orina en la vejiga permite su detección mediante la palpación?","back":"200 ml."},{"front":"¿Cuál es el manejo inicial de elección para un paciente con retención aguda de orina?","back":"Cateterización vesical con sonda Foley."},{"front":"¿Cómo debe realizarse el vaciamiento vesical seguro tras la cateterización por retención aguda?","back":"En bloques de 400 ml con descansos de 15 minutos entre cada uno."},{"front":"¿En qué situación se indica la punción suprapúbica en un caso de retención urinaria?","back":"En caso de fracaso con la sonda Foley."},{"front":"Concepto: Varicocele.","back":"Tortuosidad y dilatación anormal del plexo pampiniforme por reflujo venoso."},{"front":"¿Cuál es la principal causa de infertilidad masculina en el mundo?","back":"Varicocele."},{"front":"¿Qué porcentaje de los casos de varicocele afectan al testículo izquierdo?","back":"78-93%."},{"front":"¿Cuál es el signo clínico clásico del varicocele a la inspección/palpación?","back":"Bolsa testicular con \"aspecto de gusano\"."},{"front":"¿Cuál es el método diagnóstico de elección para confirmar un varicocele?","back":"Ultrasonido Doppler."},{"front":"¿Qué estudio es considerado el estándar de oro para el diagnóstico de varicocele?","back":"Venografía."},{"front":"¿Qué caracteriza al grado I de varicocele según la clasificación de Dubin y Amelar?","back":"Palpable únicamente con maniobra de Valsalva."},{"front":"¿Qué caracteriza al grado II de varicocele según la clasificación de Dubin y Amelar?","back":"Palpable en reposo."},{"front":"¿Qué caracteriza al grado III de varicocele según la clasificación de Dubin y Amelar?","back":"Visible en reposo."},{"front":"¿Cuál es el tratamiento quirúrgico de elección para el varicocele?","back":"Cirugía abierta con ligadura de Marmar."},{"front":"¿Cuáles son los criterios del qSOFA que sugieren sospecha de urosepsis?","back":"qSOFA >2."},{"front":"¿Qué complicación obstétrica se asocia con la pielonefritis en el 75% de las embarazadas?","back":"Parto prematuro."},{"front":"¿En qué período de tiempo se debe reevaluar a una paciente hospitalizada por IVU si no hay mejoría inmediata?","back":"En 48 a 72 horas."}]},"17":{"num":17,"name":"UROLOGIA PARTE 2","cards":[{"front":"¿Cómo se define fisiopatológicamente la litiasis renal?","back":"Es la agregación de cristales en la orina, principalmente compuestos de oxalato de calcio."},{"front":"¿Cuál es la causa secundaria más común de los litos de oxalato de calcio?","back":"La hipercalciuria."},{"front":"¿Qué hormona es la encargada de la resorción del calcio a nivel renal?","back":"La hormona paratiroidea (PTH)."},{"front":"¿Cuál es el componente más frecuente de los litos renales y qué porcentaje representa?","back":"Oxalato de calcio, representando el 65% de los casos."},{"front":"¿Qué porcentaje de la etiología de la litiasis renal corresponde al ácido úrico?","back":"Entre el 5 y el 10%."},{"front":"¿Qué porcentaje de la etiología de la litiasis renal corresponde al fosfato cálcico?","back":"El 15%."},{"front":"¿Cuál es el tipo de lito menos frecuente (1-3% de los casos)?","back":"Los litos de cistina."},{"front":"Menciona tres factores de riesgo relacionados con el estilo de vida y metabolismo para desarrollar litiasis.","back":"Baja ingesta de agua (flujo urinario bajo), obesidad e hiperparatiroidismo."},{"front":"¿En qué sexo es más prevalente la litiasis renal según la epidemiología?","back":"En varones (10-20%) comparado con mujeres (3-5%)."},{"front":"¿En qué década de la vida suele aparecer con mayor frecuencia la litiasis renal?","back":"En la tercera década de la vida."},{"front":"¿Cuál es la tasa de recurrencia de la enfermedad litiásica?","back":"Aproximadamente el 40% de los casos."},{"front":"En pacientes con recurrencia, ¿cada cuánto tiempo suele aparecer un nuevo lito en promedio?","back":"Cada 2 a 3 años."},{"front":"¿Cuál es la probabilidad de expulsión espontánea de un lito localizado en el uréter distal?","back":"Del 71%."},{"front":"¿Cuál es la probabilidad de expulsión espontánea de un lito localizado en el uréter proximal?","back":"Del 22%."},{"front":"¿Cuál es el síntoma más común de la urolitiasis?","back":"El dolor (cólico renal)."},{"front":"¿Cuál es la duración típica de los paroxismos de dolor en un cólico renal?","back":"De 20 a 60 minutos."},{"front":"¿Hacia qué zonas se irradia típicamente el dolor severo localizado en el flanco?","back":"Hacia la parte inferior del abdomen, ingle o genitales."},{"front":"¿Qué signo de la exploración física resulta positivo en el cólico renal?","back":"El signo de Giordano (puñopercusión renal)."},{"front":"¿Qué síntomas vegetativos acompañan frecuentemente al cólico renal?","back":"Náusea y vómito."},{"front":"¿En qué porcentaje de los casos de litiasis se presenta hematuria macroscópica?","back":"En hasta el 90% de los casos."},{"front":"¿Cuál es el estudio de imagen inicial ante la sospecha de litiasis renal?","back":"La ultrasonografía."},{"front":"¿Qué hallazgo obstructivo permite identificar la ultrasonografía en pacientes con litiasis?","back":"La hidronefrosis."},{"front":"¿Cuál es el tamaño mínimo de un lito para ser identificado mediante ultrasonido?","back":"Litos mayores de 5 mm."},{"front":"¿Cuál es el estudio de elección para el diagnóstico de litiasis en niños y embarazadas?","back":"La ultrasonografía."},{"front":"¿Cuál es el estudio de diagnóstico de elección (estándar de oro) para litiasis renal?","back":"TAC no contrastada (UroTAC)."},{"front":"¿Cuál es la sensibilidad reportada de la TAC no contrastada para detectar litiasis?","back":"98-100%."},{"front":"¿Cuál es el tamaño mínimo de lito que puede identificar una TAC no contrastada?","back":"Litos menores de 3 mm."},{"front":"¿Bajo qué condiciones la radiografía de abdomen permite identificar un lito?","back":"Cuando el lito es radiopaco y mide más de 5 mm."},{"front":"En el examen general de orina (EGO), ¿qué parámetros ayudan a descartar una infección concomitante?","back":"La presencia de piuria y leucocitos."},{"front":"¿Cuáles son los fármacos de primera línea para el manejo del dolor en un cólico renal?","back":"Diclofenaco 75 mg IV o Metamizol 2 g IV."},{"front":"¿Qué fármaco se utiliza como terapia de rescate para el dolor en el cólico renal?","back":"Clonixinato de lisina 100 mg IV."},{"front":"¿Cuál es el analgésico de elección para el cólico renal en pacientes embarazadas?","back":"Paracetamol."},{"front":"¿Qué medicamento es superior a la morfina en rapidez y eficacia analgésica para el cólico renoureteral?","back":"El diclofenaco."},{"front":"¿Cuál es el antiemético de elección para el manejo del vómito en litiasis (no embarazadas)?","back":"Ondansetrón 4 mg IV."},{"front":"¿Qué antiemético se prefiere en pacientes embarazadas con cólico renal?","back":"Metoclopramida."},{"front":"¿Qué antibióticos se recomiendan en caso de sobreinfección y cuál es su duración?","back":"Ciprofloxacino (400 mg IV c/12h) o Levofloxacino (750 mg IV c/24h) por 7 a 14 días."},{"front":"Menciona tres criterios de referencia a segundo o tercer nivel por litiasis renal.","back":"Urosepsis, insuficiencia renal aguda o dolor persistente a pesar del tratamiento."},{"front":"¿A partir de qué tamaño de lito se indica la referencia?","back":"Litos mayores de 10 mm."},{"front":"¿Cuál es el tratamiento de elección para litos pielocaliciales pequeños a medianos (hasta 20 mm o 3 cc)?","back":"Litotripsia extracorpórea por ondas de choque (LEOC)."},{"front":"Menciona dos contraindicaciones absolutas para realizar una LEOC.","back":"Embarazo e infección activa."},{"front":"¿Cuál es la complicación más frecuente de la litotripsia extracorpórea (LEOC)?","back":"La hematuria."},{"front":"¿Cuándo se indica la ureteroscopía con litotricia endoscópica?","back":"En litos inaccesibles (uréter distal) o que no se fragmentan con LEOC."},{"front":"¿Cuál es el tratamiento de elección para litos grandes (20-70 mm o 3-7 cc)?","back":"Cirugía renal percutánea (nefrolitotomía percutánea)."},{"front":"¿Qué tipo de litos, caracterizados por dilatar la vía urinaria de forma crónica, requieren cirugía percutánea?","back":"Litos coraliformes."},{"front":"Menciona una indicación para realizar cirugía abierta en litiasis renal.","back":"Pacientes con alteraciones morfológicas funcionales y falla en tratamientos previos."},{"front":"¿Qué fármaco se utiliza para facilitar la expulsión de litos de 5-10 mm?","back":"Tamsulosina 0.4 mg al día (bloqueador alfa)."},{"front":"¿Cuál es el mecanismo de acción de la tamsulosina en la litiasis renal?","back":"Inhibe el tono basal uretral."},{"front":"Concepto: Sales de oxalato cálcico.","back":"Etiología: Hipercalciuria. Radiología: Radiopacos. Manejo: Tiazidas y citrato."},{"front":"¿Qué medicamento se indica específicamente para la hiperoxaluria primaria?","back":"Piridoxina."},{"front":"¿Cuál es el pH urinario asociado a los litos de fosfato de calcio?","back":"pH alcalino."},{"front":"¿Qué gérmenes productores de ureasa se asocian a la formación de litos de estruvita?","back":"Proteus o Klebsiella."},{"front":"¿Cuál es el sexo en el que predominan los litos de estruvita?","back":"En mujeres."},{"front":"¿Cuál es la morfología microscópica característica de los cristales de estruvita?","back":"Formas prismáticas polimórficas conocidas como 'cristales en ataúd'."},{"front":"¿Qué inhibidores de la ureasa se pueden utilizar en el tratamiento de litos de estruvita?","back":"Ácido propiónico y ácido acetohidroxámico."},{"front":"¿Cuál es el manejo para modificar el pH urinario en pacientes con litos de estruvita?","back":"Acidificar la orina con cloruro de amonio."},{"front":"¿Cuál es la apariencia radiológica característica de los litos de ácido úrico?","back":"Radiotransparentes (radiolúcidos)."},{"front":"¿Qué condición metabólica se asocia al 50% de los casos de litiasis por ácido úrico?","back":"La gota."},{"front":"¿Cómo se debe modificar el pH urinario para tratar los litos de ácido úrico?","back":"Alcalinizando la orina."},{"front":"¿En qué caso se añade alopurinol al tratamiento de litos de ácido úrico?","back":"Cuando el paciente presenta hiperuricemia."},{"front":"¿Cuál es la morfología microscópica de los cristales de cistina?","back":"Cristales hexagonales en prismas o láminas."},{"front":"¿Qué prueba diagnóstica resulta positiva en la litiasis por cistina?","back":"Test de Brand positivo."},{"front":"¿A qué nivel se debe elevar el pH urinario para tratar la cistinuria?","back":"A más de 7.5."},{"front":"¿Qué fármaco se utiliza en la cistinuria si no hay respuesta a la ingesta hídrica y alcalinización?","back":"D-penicilamina."},{"front":"¿Cuál es el pH urinario asociado a los litos de ácido úrico y cistina?","back":"pH ácido."}]},"18":{"num":18,"name":"PATOLOGIA PROSTATICA","cards":[{"front":"¿Qué hormona es la principal responsable del origen de la hiperplasia prostática benigna?","back":"Dihidrotestosterona (DHT)."},{"front":"¿Qué enzima convierte la testosterona en dihidrotestosterona (DHT) en el tejido prostático?","back":"La enzima 5-α-reductasa tipo 2."},{"front":"Mencione uno de los tres criterios que definen la hiperplasia prostática benigna.","back":"Detección microscópica de hiperplasia."},{"front":"¿A partir de qué edad suele presentarse la sintomatología de la HPB?","back":"Entre los 60 y 65 años."},{"front":"¿Cuál es el tumor más frecuente en hombres mayores de 50 años en México?","back":"Hiperplasia prostática benigna."},{"front":"¿Cuál es la causa más frecuente de hematuria en hombres mayores de 50 años?","back":"Hiperplasia prostática benigna."},{"front":"¿En qué zona de la próstata se desarrolla predominantemente el carcinoma prostático?","back":"Zona periférica."},{"front":"¿En qué zona de la próstata se produce el crecimiento característico de la HPB?","back":"Zona transicional."},{"front":"Mencione los tres factores de riesgo principales para desarrollar HPB.","back":"Edad mayor a 55 años, síndrome metabólico y raza negra."},{"front":"Categoría de síntomas de la HPB que incluye disminución del flujo, intermitencia y goteo terminal.","back":"Síntomas de vaciamiento (obstructivos)."},{"front":"Categoría de síntomas de la HPB que incluye urgencia, nicturia y polaquiuria.","back":"Síntomas irritativos (de almacenamiento)."},{"front":"¿Cuáles son los dos síntomas de HPB más comúnmente reportados por los pacientes?","back":"Nicturia y disminución del chorro urinario."},{"front":"¿Cuál es el estudio clínico inicial para evaluar el tamaño y consistencia de la próstata?","back":"Tacto rectal."},{"front":"¿Qué consistencia suele tener la próstata al tacto rectal en un paciente con HPB?","back":"Consistencia de goma (gomosa)."},{"front":"¿Cuál es el valor considerado normal para el Antígeno Prostático Específico (APE)?","back":"Menor a 4  ng/ml."},{"front":"¿En qué rango de niveles de APE se debe solicitar la medición de APE libre?","back":"Entre 4 y 10  ng/ml."},{"front":"¿Qué estudio es el estándar de oro para confirmar el diagnóstico de HPB?","back":"Biopsia transrectal de próstata."},{"front":"¿Para qué se utiliza el ultrasonido vesical en el protocolo de estudio de la HPB?","back":"Para medir la orina residual y el tamaño prostático."},{"front":"¿Cuál es la conducta recomendada para un paciente con un puntaje de IPSS menor a 8?","back":"Realizar modificaciones higiénico-dietéticas."},{"front":"¿Qué rango de puntaje en la escala IPSS define una sintomatología moderada?","back":"Entre 8 y 19 puntos."},{"front":"¿Qué rango de puntaje en la escala IPSS define una sintomatología severa?","back":"Entre 20 y 35 puntos."},{"front":"¿Cuál es el fármaco de elección para pacientes con IPSS de 8-19 puntos y próstata menor a 40  ml?","back":"Bloqueadores α-1 (ej. Tamsulosina)."},{"front":"¿Cuál es el efecto adverso más característico de la tamsulosina?","back":"Eyaculación retrógrada."},{"front":"¿Cuánto tiempo tardan los bloqueadores alfa en reducir el IPSS en un 30-40%?","back":"Desde el primer mes de tratamiento."},{"front":"¿Cuál es el efecto de los bloqueadores alfa sobre el tamaño de la próstata?","back":"No reducen el tamaño de la próstata."},{"front":"¿Bajo qué condición de tamaño prostático se debe añadir finasteride al tratamiento con bloqueadores alfa?","back":"Cuando la próstata mide más de 40  g o ml."},{"front":"¿Cuánto tiempo de uso de finasteride se requiere para observar una reducción del 20% en el tamaño prostático?","back":"Seis meses de uso continuo."},{"front":"Mencione dos efectos adversos del uso de finasteride.","back":"Reducción de la libido y del volumen de eyaculación."},{"front":"¿Qué fármaco para la HPB tiene el beneficio adicional de reducir el riesgo de cáncer de próstata?","back":"Finasteride."},{"front":"¿Cuál es el estándar de oro quirúrgico para próstatas con un volumen de 30 a 80  ml?","back":"Resección Transuretral Prostática (RTUP)."},{"front":"¿Qué procedimiento endoscópico se recomienda para próstatas menores a 30  cc en pacientes que desean preservar la eyaculación?","back":"Incisión Transuretral (ITUP)."},{"front":"¿Cuál es la indicación principal de volumen prostático para realizar una prostatectomía abierta?","back":"Próstatas mayores a 80  ml."},{"front":"Mencione un criterio absoluto para el tratamiento quirúrgico de la HPB.","back":"Retención urinaria reiterada."},{"front":"¿Cuál es la complicación más común después de una cirugía de próstata?","back":"Eyaculación retrógrada (65-70%)."},{"front":"¿Cuál es la complicación más grave reportada tras la cirugía de próstata?","back":"Disfunción eréctil."},{"front":"¿Qué clase de fármacos psiquiátricos están contraindicados en pacientes con HPB?","back":"Antidepresivos tricíclicos."},{"front":"¿Cuál es el agente etiológico más frecuente en la prostatitis aguda?","back":"E.  coli."},{"front":"¿Qué porcentaje de los casos de prostatitis aguda se asocia a manipulación del tracto urinario (como biopsia)?","back":"30% de los casos."},{"front":"¿Por qué debe suspenderse el tacto rectal en un paciente con sospecha de prostatitis si presenta dolor intenso?","back":"Para evitar el riesgo de sepsis y retención urinaria."},{"front":"¿Por qué no se recomienda medir el APE durante la fase aguda de una prostatitis?","back":"Porque estará elevado y tardará hasta 3 meses en normalizarse."},{"front":"¿Cuál es el esquema antibiótico de elección para la prostatitis aguda?","back":"Aminoglucósidos combinados con cefalosporinas de amplio espectro o ampicilina."},{"front":"¿Cuál es la duración recomendada del tratamiento antibiótico en la prostatitis aguda?","back":"Hasta por 4 semanas."},{"front":"¿Qué hallazgo en el líquido prostático define a la prostatitis crónica?","back":"Más de 10 leucocitos por campo."},{"front":"¿Cómo se denomina a la condición donde el paciente tiene síntomas perineales pero los estudios diagnósticos son normales?","back":"Prostatodinia."},{"front":"¿Qué estudio de imagen está indicado específicamente en pacientes con prostatitis que no responden al manejo médico inicial?","back":"Ultrasonido transrectal o TAC (para buscar abscesos)."},{"front":"Mencione una indicación para hospitalizar a un paciente con prostatitis.","back":"Diabetes o inmunosupresión (pacientes de alto riesgo)."},{"front":"¿Qué síntoma postmiccional se caracteriza por la sensación de no haber vaciado la vejiga por completo?","back":"Tenesmo vesical."},{"front":"¿A qué se debe el goteo terminal en la sintomatología de la HPB?","back":"A la obstrucción del flujo de orina por el crecimiento prostático."},{"front":"¿Cuál es el valor de APE a partir del cual se debe derivar a urología para biopsia de forma directa?","back":"Mayor a 10  ng/ml."},{"front":"¿Bajo qué circunstancia se utiliza el ultrasonido transrectal de próstata según la guía?","back":"Únicamente cuando se va a realizar una biopsia."},{"front":"¿Qué complicación renal justifica el tratamiento quirúrgico absoluto de la HPB?","back":"Hidronefrosis retrógrada."},{"front":"¿Qué hallazgo físico en la prostatitis aguda se considera un signo de alarma durante el tacto?","back":"Crepitación o aumento de temperatura local."},{"front":"¿Cuál es la utilidad de los alfa-bloqueadores en el contexto de una prostatitis?","back":"Reducir el riesgo de retención urinaria y facilitar la micción."},{"front":"¿Cuál es el síntoma principal reportado en la prostatitis crónica?","back":"Dolor perineal (sensación de incomodidad prolongada al estar sentado)."},{"front":"¿Qué factor de riesgo para HPB se asocia con un estado de inflamación crónica y resistencia a la insulina?","back":"Síndrome metabólico."}]},"19":{"num":19,"name":"ETS","cards":[{"front":"¿Cuál es el agente etiológico de la sífilis?","back":"Treponema pallidum."},{"front":"En la patogenia de la sífilis, ¿cuáles son las lesiones infectantes por contacto sexual?","back":"Chancro, mucosa, erupción cutánea y condiloma plano."},{"front":"¿Qué tipo de pruebas se utilizan para el cribado de sífilis debido a su alta sensibilidad?","back":"Pruebas no treponémicas."},{"front":"¿En qué anticuerpos se basan las pruebas VDRL y RPR para el diagnóstico de sífilis?","back":"Anticuerpos anti-cardiolipina-lecitina-colesterol."},{"front":"¿Cuál es la función principal de las pruebas treponémicas como el FTA-ABS y TP-PA?","back":"Confirmar el diagnóstico por su alta especificidad."},{"front":"En la microscopía de campo oscuro para sífilis, ¿cuál es la morfología característica del microorganismo?","back":"En sacacorchos."},{"front":"¿Cómo se describe la lesión típica de la sífilis primaria?","back":"Úlcera (chancro) indoloro, único, limpio y con bordes elevados."},{"front":"¿Qué tipo de lesiones aparecen típicamente en la sífilis secundaria?","back":"Lesiones blancas elevadas y grandes, generalmente cercanas al chancro."},{"front":"Mencione tres síntomas sistémicos que pueden acompañar a la sífilis secundaria.","back":"Fiebre, cefalea y malestar general."},{"front":"¿Cuáles son las manifestaciones características de la sífilis terciaria?","back":"Neurosífilis, sífilis meningovascular, parenquimatosa y gomas en piel y huesos."},{"front":"La _____ se define como una prueba de VDRL positiva sin datos clínicos presentes.","back":"sífilis latente"},{"front":"¿Cuál es el tratamiento de elección para la sífilis?","back":"Penicilina G benzatínica 2.4  M UI IM en dosis única."},{"front":"¿Cuál es la alternativa de tratamiento para la sífilis en pacientes alérgicos a la penicilina?","back":"Doxiciclina 100  mg VO cada 12  horas por 14  días."},{"front":"¿Cuántas dosis de penicilina se requieren para tratar la sífilis latente?","back":"3  dosis."},{"front":"¿Qué agente causa el linfogranuloma venéreo, también conocido como enfermedad de Durand-Nicolas?","back":"Chlamydia trachomatis."},{"front":"¿Cómo se presenta la lesión inicial típica en el linfogranuloma venéreo?","back":"Úlcera única o pápula no dolorosa."},{"front":"¿Cuál es la característica de la linfadenopatía en el linfogranuloma venéreo?","back":"Unilateral inguinal y purulenta debido a que fistuliza."},{"front":"¿Cuál es el esquema de tratamiento de elección para el linfogranuloma venéreo?","back":"Doxiciclina 100  mg cada 12  horas por 21  días."},{"front":"¿Qué alternativa de tratamiento existe para el linfogranuloma venéreo si no se puede usar doxiciclina?","back":"Eritromicina 500  mg cada 6  horas por 21  días."},{"front":"¿Cuál es el agente etiológico del chancroide?","back":"Haemophilus ducreyi."},{"front":"¿Qué características definen a la úlcera genital en el chancroide?","back":"Dolorosa, única, sucia, necrótica, purulenta y de bordes mal delimitados."},{"front":"¿Qué sucede típicamente al contacto con la lesión del chancroide?","back":"Sangra fácilmente."},{"front":"¿Cuál es el tratamiento de elección para el chancroide en dosis única?","back":"Azitromicina 1  g VO."},{"front":"¿Qué alternativas intramusculares existen para el tratamiento del chancroide?","back":"Ceftriaxona 250  mg IM en dosis única."},{"front":"¿Cuál es la etiología del granuloma inguinal?","back":"Klebsiella granulomatis."},{"front":"¿Qué hallazgo microscópico confirma el diagnóstico de granuloma inguinal mediante tinción de Wright-Giemsa?","back":"Cuerpos de Donovan."},{"front":"¿Cómo se describen los pseudo-bubones en el cuadro clínico del granuloma inguinal?","back":"Adenopatías inguinales que se ulceran, son indoloras y con fondo eritematoso sangrante."},{"front":"¿Cuál es el esquema de tratamiento de elección para el granuloma inguinal?","back":"Azitromicina 1  g VO semanal por 3  semanas."},{"front":"¿Cuál es el tratamiento alternativo para el granuloma inguinal con ciprofloxacino?","back":"Ciprofloxacino 500  mg VO cada 12  horas por 3  semanas."},{"front":"¿Qué virus es responsable de aproximadamente el 80% de los casos de herpes genital?","back":"Herpes Simple tipo 2 (o tipo 1)."},{"front":"¿En qué sitio anatómico se aloja el virus del herpes de forma latente tras la remisión?","back":"Ganglios nerviosos sensoriales."},{"front":"¿Cuál es la presentación clínica de las lesiones en el herpes genital?","back":"Múltiples úlceras con vesículas ardorosas y pruriginosas."},{"front":"¿Qué hallazgo en la tinción de Tzanck sugiere sospecha diagnóstica de herpes genital?","back":"Células gigantes multinucleadas."},{"front":"¿Qué estudio se considera confirmatorio para herpes genital?","back":"PCR de las lesiones o cultivo viral."},{"front":"¿Cuál es el tratamiento de elección para un episodio de herpes genital?","back":"Aciclovir 400  mg cada 8  horas por 5  días."},{"front":"¿Cuál es la conducta recomendada para el parto en pacientes embarazadas con lesiones activas de herpes genital?","back":"Realizar cesárea."},{"front":"¿Qué es el hidrosalpinx?","back":"Inflamación crónica de la tuba uterina que causa edema y obstrucción."},{"front":"¿Cuál es el principal factor de riesgo para desarrollar hidrosalpinx?","back":"Enfermedad Pélvica Inflamatoria (EPI) crónica."},{"front":"¿Qué agente bacteriano está frecuentemente implicado en el hidrosalpinx?","back":"Neisseria gonorrhoeae."},{"front":"¿Cuál es el estudio de elección para evaluar la permeabilidad de la trompa en casos de infertilidad?","back":"Histerosalpingografía."},{"front":"¿Qué hallazgo ecográfico sugiere un hidrosalpinx?","back":"Signo de rueda dentada o imagen serpiginosa."},{"front":"¿Cuál es el estándar de oro (Gold Standard) para el diagnóstico de hidrosalpinx?","back":"Laparoscopia."},{"front":"¿Cuál es el tratamiento quirúrgico indicado para el hidrosalpinx en pacientes con paridad satisfecha?","back":"Salpingectomía."},{"front":"¿Qué procedimiento se prefiere en hidrosalpinx si la paciente tiene paridad no satisfecha?","back":"Salpingostomía."},{"front":"¿Qué lugar ocupan las ETS entre los motivos de consulta en el primer nivel de atención?","back":"Se sitúan entre los 5 primeros motivos de consulta."},{"front":"¿Cuántos condones mensuales debe proveer la clínica según las recomendaciones mencionadas?","back":"12  a  15  condones."},{"front":"¿Cuál es el principal beneficio del uso del condón en ETS ulcerosas?","back":"Minimiza el riesgo de transmisión."},{"front":"La reacción de _____ se caracteriza por fiebre, taquicardia y mialgias tras el tratamiento de la sífilis.","back":"Jarisch-Herxheimer"},{"front":"¿Qué hallazgos hemodinámicos y respiratorios acompañan a la reacción de Jarisch-Herxheimer?","back":"Taquicardia, taquipnea y vasodilatación."},{"front":"¿Cuál es el agente causal del linfogranuloma venéreo según la clasificación de Durand-Nicolas?","back":"Chlamydia trachomatis."},{"front":"Concepto: Úlcera en chancroide","back":"Definición: Lesión dolorosa, sucia y necrótica causada por Haemophilus ducreyi."},{"front":"¿Qué tratamiento alternativo para sífilis se administra cada 12  horas?","back":"Doxiciclina 100  mg VO cada 12  horas por 14  días."},{"front":"En el contexto de ETS, ¿qué significa que una úlcera sea 'sucia'?","back":"Que presenta fondo necrótico y purulento."},{"front":"¿Cuál es la duración del tratamiento con valaciclovir para herpes genital?","back":"3  días (500  mg cada 24  horas)."},{"front":"¿Qué microorganismo se describe clásicamente con movimiento 'en sacacorchos'?","back":"Treponema pallidum."}]},"2":{"num":2,"name":"PATOLOGIA ESOFAGICA","cards":[{"front":"¿Cuál es la característica fisiopatológica distintiva de la acalasia?","back":"Deficiente relajación del esfínter esofágico inferior y pérdida de la peristalsis esofágica."},{"front":"La acalasia se debe principalmente a la degeneración de qué estructura anatómica?","back":"Plexo muscular de Auerbach."},{"front":"¿A qué enfermedades infecciosas o sistémicas se puede asociar la acalasia?","back":"Enfermedad de Chagas y esclerodermia."},{"front":"¿Cuál es la principal complicación anatómica de la acalasia no tratada?","back":"Megaesófago."},{"front":"¿Cómo progresa típicamente la disfagia en un paciente con acalasia?","back":"De forma progresiva, de sólidos a líquidos."},{"front":"¿Qué hallazgo radiológico es característico de la acalasia en un esofagograma baritado?","back":"Imagen en \"pico de pájaro\" o \"cola de ratón\"."},{"front":"¿Cuál es el estándar de oro para el diagnóstico de la acalasia?","back":"Manometría esofágica."},{"front":"¿Qué estudio diagnóstico es obligatorio en todos los pacientes con acalasia que serán sometidos a cirugía?","back":"Manometría esofágica."},{"front":"¿Cuál es el tratamiento quirúrgico inicial de elección para la acalasia?","back":"Miotomía de Heller más funduplicatura parcial (tipo Toupet o Dor)."},{"front":"¿Qué escala se utiliza para evaluar la efectividad clínica del tratamiento en la acalasia?","back":"Escala de Eckardt."},{"front":"¿Cuál es la conducta a seguir si falla la miotomía de Heller inicial en un paciente con acalasia?","back":"Realizar una miotomía contralateral."},{"front":"\"En pacientes con acalasia y alto riesgo quirúrgico","back":"¿qué tratamiento farmacológico local se recomienda?\""},{"front":"¿Cuál es la principal contraindicación para el uso de toxina botulínica en acalasia?","back":"Alergia al huevo."},{"front":"¿Qué fármacos se consideran de última elección (paliativos) para el tratamiento de la acalasia?","back":"Nifedipino o isosorbide sublingual."},{"front":"¿Por qué se recomienda realizar un esofagograma anual en pacientes con acalasia?","back":"Debido al riesgo elevado de desarrollar carcinoma epidermoide."},{"front":"¿Qué define al espasmo esofágico difuso en términos de motilidad?","back":"Múltiples contracciones masivas, incoordinadas y no propulsivas."},{"front":"¿Cuál es el hallazgo clásico en la serie esófago-gastroduodenal de un paciente con espasmo esofágico difuso?","back":"Imagen en \"sacacorchos\"."},{"front":"¿Cuál es el tratamiento farmacológico de primera elección para el espasmo esofágico difuso?","back":"Bloqueadores de canales de calcio (nifedipino) o nitratos sublinguales (isosorbide)."},{"front":"El espasmo esofágico difuso se considera un precursor de qué otra patología motora (específicamente el tipo III)?","back":"Acalasia."},{"front":"¿Cómo se define la enfermedad por reflujo gastroesofágico (ERGE)?","back":"Ascenso del contenido gástrico por arriba de la unión gastroesofágica que causa síntomas o lesiones."},{"front":"¿Cuál es el rango de presión normal del esfínter esofágico inferior?","back":"10 a 26 mmHg."},{"front":"¿Qué alteración genética se asocia a la predisposición de padecer ERGE y hernia hiatal?","back":"Mutación en el gen del colágeno tipo 3."},{"front":"\"Según la clasificación de Montreal","back":"¿cuál es el síntoma esofágico más frecuente del ERGE?\""},{"front":"¿Cuáles son los síntomas extraesofágicos típicos asociados al ERGE?","back":"Tos crónica, asma, laringitis crónica y erosiones dentarias."},{"front":"¿En qué consiste la prueba terapéutica inicial para el diagnóstico de ERGE?","back":"Administración de IBP durante 2 semanas para evaluar la mejoría clínica."},{"front":"¿Cuál es el estándar de oro para el diagnóstico definitivo de ERGE?","back":"pH-metría con impedancia de 24 horas."},{"front":"¿En qué situaciones está indicada una endoscopia diagnóstica en un paciente con sospecha de ERGE?","back":"Falla a la prueba terapéutica, presencia de datos de alarma o pacientes mayores de 55 años."},{"front":"¿Cuál es el tratamiento quirúrgico de elección (estándar de oro) para el ERGE?","back":"Funduplicatura de Nissen."},{"front":"Concepto: Gas Bloating","back":"Definición: Complicación postquirúrgica de la funduplicatura caracterizada por la incapacidad de eructar y distensión abdominal."},{"front":"¿Qué fármaco se recomienda específicamente para el tratamiento del reflujo alcalino?","back":"Hidróxido de aluminio."},{"front":"¿Cuál es la complicación más frecuente de la esofagitis?","back":"Úlcera esofágica."},{"front":"¿Qué sistemas de clasificación se utilizan para estadificar la esofagitis por endoscopia?","back":"Clasificación de Los Ángeles y Savary-Miller."},{"front":"\"En la clasificación de Los Ángeles","back":"¿qué define a la esofagitis Grado C?\""},{"front":"¿Qué cambio histológico define al esófago de Barrett?","back":"Metaplasia de la mucosa esofágica a epitelio columnar de tipo intestinal."},{"front":"¿Cuál es el principal riesgo de malignidad asociado al esófago de Barrett?","back":"Adenocarcinoma de esófago."},{"front":"¿Qué sistema de clasificación endoscópica se utiliza para describir la extensión del esófago de Barrett?","back":"Clasificación de Praga."},{"front":"¿Cuál es el tratamiento endoscópico de elección para el esófago de Barrett con displasia?","back":"Resección mucosa y ablación con radiofrecuencia."},{"front":"¿Dónde se localiza anatómicamente el divertículo de Zenker?","back":"En la parte posterior, entre los músculos cricofaríngeo y constrictor inferior (triángulo de Killian)."},{"front":"¿Cuál es el cuadro clínico clásico de un paciente con divertículo de Zenker?","back":"Disfagia, halitosis y regurgitación de alimentos no digeridos de días anteriores."},{"front":"¿Cuál es el estudio de elección para confirmar la presencia de un divertículo de Zenker?","back":"Esofagogramas baritados."},{"front":"¿Qué tratamiento quirúrgico se indica si el divertículo de Zenker mide más de 3 cm?","back":"Miotomía más diverticulotomía con grapa."},{"front":"¿Qué tratamiento quirúrgico se indica si el divertículo de Zenker mide menos de 3 cm?","back":"Miotomía cricofaríngea aislada."},{"front":"¿Cuántos eosinófilos por campo se requieren para diagnosticar esofagitis eosinofílica?","back":"Más de 15 eosinófilos por campo."},{"front":"¿Cuál es la causa más frecuente de impacto alimentario en pacientes jóvenes (20-30 años)?","back":"Esofagitis eosinofílica."},{"front":"¿Qué hallazgo endoscópico es característico de la esofagitis eosinofílica?","back":"Esófago en anillo, ondulado o \"felino\"."},{"front":"¿Cuál es el pilar del tratamiento farmacológico tópico para la esofagitis eosinofílica?","back":"Glucocorticoides tópicos (budesonida o fluticasona)."},{"front":"¿Cómo se define la hernia hiatal tipo I o deslizante?","back":"Desplazamiento de la unión gastroesofágica por encima del hiato diafragmático."},{"front":"¿Cuál es la característica de la hernia hiatal tipo II o paraesofágica?","back":"El fondo gástrico se hernia a través del hiato mientras la unión gastroesofágica permanece en su sitio."},{"front":"¿Qué estudio se utiliza inicialmente para evaluar una hernia hiatal?","back":"Serie esófago-gastroduodenal."},{"front":"¿Cuál es el tratamiento definitivo para una hernia hiatal sintomática?","back":"Cirugía laparoscópica con técnica de Nissen."},{"front":"¿Bajo qué condición se debe colocar una malla durante la reparación de una hernia hiatal?","back":"En defectos del hiato mayores a 5 mm."},{"front":"¿Qué trastorno psicológico se asocia frecuentemente al espasmo esofágico difuso?","back":"Ansiedad, estrés o depresión."},{"front":"¿Cuál es la complicación más frecuente tras la inyección de toxina botulínica en el EEI?","back":"Dolor torácico."},{"front":"¿Qué porcentaje de efectividad tiene la toxina botulínica para la acalasia al cabo de un año?","back":"30%."},{"front":"\"En el contexto de ERGE","back":"¿cuándo se considera que una esofagitis es grave según Los Ángeles?\""},{"front":"¿Qué fármaco ayuda a reducir la frecuencia de relajaciones transitorias del esfínter esofágico inferior?","back":"Baclofeno."},{"front":"¿Cuál es la conducta recomendada para megaesófago en fase terminal?","back":"Esofagectomía."},{"front":"\"En la escala de Eckardt","back":"¿a partir de cuántos puntos se considera falla al tratamiento?\""},{"front":"¿Cuál es el principal factor de riesgo genético para ERGE?","back":"Alteración del gen del colágeno tipo 3."},{"front":"¿Qué estudio se solicita ante la recurrencia de síntomas después de una cirugía antirreflujo?","back":"Serie esófago-gastroduodenal."},{"front":"¿Cuál es la incidencia de progresión de esófago de Barrett a adenocarcinoma?","back":"0.5% anual."},{"front":"\"¿Qué tipo de hernia hiatal se conoce como \"\"invertida\"\" e implica la herniación de otros órganos?\"","back":"Hernia hiatal tipo IV."},{"front":"¿A qué edad es más común la presentación del divertículo de Zenker?","back":"Adultos mayores."},{"front":"¿Cuál es el tratamiento quirúrgico definitivo para el espasmo esofágico difuso?","back":"Miotomía de la capa muscular del esófago o dilatación con balón."},{"front":"¿Qué fármaco de la familia de los IBP se asocia con una mejor tasa de cicatrización en esofagitis?","back":"Esomeprazol."}]},"20":{"num":20,"name":"ATLS PARTE 1","cards":[{"front":"¿Cuál es la causa número uno de muerte en la población de 1 a 44 años?","back":"El trauma."},{"front":"En la población general, el trauma es la _____ causa de muerte después de enfermedades cardiovasculares y cáncer.","back":"Tercera"},{"front":"¿Cuál es la causa principal de muerte en el grupo de 1 a 25 años en USA?","back":"Armas de fuego."},{"front":"¿Cuál es la causa número uno de muerte mundial en el grupo de 5 a 29 años?","back":"Accidentes de tránsito."},{"front":"¿Cuál es la causa más común de shock en el paciente con trauma?","back":"Hemorragia (shock hemorrágico)."},{"front":"¿Cuál es la principal causa de muerte prevenible en el trauma de adultos?","back":"Hemorragia."},{"front":"¿Cuáles son las principales causas de discapacidad permanente a nivel mundial tras un trauma?","back":"Lesión cerebral traumática (TCE) y lesión medular."},{"front":"¿Cuál es la causa más común de muerte prevenible en niños con trauma?","back":"Fallo en vía aérea o ventilación (hipoxia)."},{"front":"¿Cuál es el mecanismo de lesión número uno en pacientes geriátricos (>65 años)?","back":"Caídas a nivel de piso."},{"front":"Criterio de Triage (Signos vitales): ¿Qué puntaje en la Escala de Coma de Glasgow indica necesidad de traslado a centro de trauma?","back":"GCS ≤ 13."},{"front":"Criterio de Triage (Signos vitales): ¿Qué cifra de Presión Arterial Sistólica se considera crítica?","back":"< 90 mmHg."},{"front":"Criterio de Triage (Signos vitales): ¿Cuál es el rango de Frecuencia Respiratoria que indica prioridad?","back":"< 10 o > 29 rpm."},{"front":"En menores de 1 año, una Frecuencia Respiratoria menor a _____ rpm es un criterio de triage.","back":"20"},{"front":"Criterio de Triage (Anatomía): ¿A partir de qué localización se consideran críticas las lesiones penetrantes en extremidades?","back":"Proximales al codo o rodilla."},{"front":"Criterio de Triage (Anatomía): ¿A partir de qué localización una amputación se considera de alta prioridad?","back":"Proximal a la muñeca o tobillo."},{"front":"¿Qué significa la mnemotecnia S-XABCDE-BAR para el traspaso de pacientes?","back":"Situación, Exanguinación, revisión primaria (A-B-C-D-E), Background, Assessment, Recomendación."},{"front":"¿Cuál es el principal cambio de la 11ava edición de ATLS en la revisión primaria?","back":"El control de la hemorragia exanguinante externa (X) antes de la vía aérea."},{"front":"En el manejo de la vía aérea (A), ¿qué maniobra manual se prefiere si hay sospecha de lesión cervical?","back":"Tracción mandibular (sin extensión del cuello)."},{"front":"¿Cuál es la meta de saturación de oxígeno (SpO₂) en la revisión primaria?","back":"> 95%."},{"front":"En la evaluación de la circulación (C), ¿cuáles son las 5 fuentes de hemorragia oculta?","back":"Tórax, abdomen, pelvis, retroperitoneo y huesos largos."},{"front":"¿Cuál es el bolo inicial de cristaloides isotónicos recomendado para un adulto en shock?","back":"1 litro (tibio)."},{"front":"¿Cuál es la dosis de líquidos inicial para un paciente pediátrico en shock?","back":"20 ml/kg."},{"front":"¿A qué nivel anatómico se debe colocar la faja pélvica ante sospecha de fractura de pelvis?","back":"A la altura de los trocánteres mayores."},{"front":"En la evaluación de déficit neurológico (D), ¿qué parámetro de la escala de Glasgow se relaciona más con el pronóstico?","back":"La respuesta motora."},{"front":"¿Cuál es el objetivo principal de la exposición y control del ambiente (E)?","back":"Identificar todas las lesiones y prevenir la hipotermia."},{"front":"¿Qué sugiere la presencia de Actividad Eléctrica Sin Pulso (AESP) en un paciente con trauma torácico?","back":"Taponamiento cardíaco o neumotórax a tensión."},{"front":"¿Cuál es el estándar de oro para confirmar que un tubo endotraqueal está en la tráquea?","back":"Capnografía (detección de CO₂ exhalado)."},{"front":"¿En qué situación está contraindicada la colocación de una sonda Foley?","back":"Sospecha de lesión uretral (sangre en meato o próstata flotante)."},{"front":"¿Qué tipo de sonda gástrica debe usarse si se sospecha fractura de base de cráneo?","back":"Sonda orogástrica."},{"front":"En una paciente embarazada con hipotensión, ¿cómo se debe desplazar el útero para descomprimir la vena cava inferior?","back":"Manualmente hacia la izquierda."},{"front":"¿Cuándo inicia formalmente la evaluación secundaria?","back":"Después de completar la revisión primaria y lograr estabilidad fisiológica."},{"front":"Mnemotecnia AMPLE: ¿Qué significa la letra 'L'?","back":"Libaciones o última comida (importante por riesgo de aspiración)."},{"front":"¿Cuál es el tiempo ideal para intentar convertir un torniquete a vendaje compresivo para salvar la extremidad?","back":"Menos de 2 horas (máximo 6 horas)."},{"front":"¿A qué distancia proximal del sitio de sangrado se debe aplicar un torniquete?","back":"De 2 a 3 pulgadas (directo sobre la piel)."},{"front":"¿Cuál es el estándar de oro para evaluar trauma en un paciente hemodinámicamente estable?","back":"Tomografía Computarizada (TAC)."},{"front":"Concepto: Vía aérea definitiva.","back":"Tubo en la tráquea con balón inflado bajo las cuerdas vocales, conectado a oxígeno y ventilación."},{"front":"¿Por qué está contraindicada la intubación nasotraqueal en fracturas de base de cráneo?","back":"Riesgo de paso del tubo hacia la cavidad intracraneal."},{"front":"¿Cuál es el punto de corte de la escala de Glasgow para indicar intubación?","back":"8 puntos o menos."},{"front":"¿Qué hallazgo en la voz sugiere una obstrucción inminente de la vía aérea por trauma laríngeo?","back":"Estridor o voz de \"papa caliente\" (disfonía)."},{"front":"¿Qué tres factores componen la evaluación de vía aérea difícil actualmente?","back":"Anatomía, lesión y fisiología (hipoxia/hipotensión)."},{"front":"¿Cuál es el objetivo principal de la Intubación de Secuencia Rápida (ISR)?","back":"Lograr la intubación sin ventilar con bolsa-mascarilla para evitar aspiración."},{"front":"¿Por qué es peligroso inducir con sedantes a un paciente hipovolémico antes de estabilizarlo?","back":"Puede causar colapso cardiovascular y paro cardíaco."},{"front":"Sedante de elección en trauma por mantener la presión arterial y ser broncodilatador:","back":"Ketamina (1-2 mg/kg)."},{"front":"¿Cuál es el relajante neuromuscular de elección para la secuencia de intubación rápida?","back":"Succinilcolina (1-2 mg/kg)."},{"front":"La Maniobra de Sellick consiste en aplicar _____.","back":"Presión cricoidea."},{"front":"¿En qué pacientes está contraindicada la cricotiroidotomía quirúrgica?","back":"Niños menores de 12 años."},{"front":"¿Cuál es el tratamiento puente para la vía aérea en niños menores de 12 años si la intubación falla?","back":"Cricotiroidotomía con aguja (jet ventilation)."},{"front":"¿Cuál es la complicación principal de la cricotiroidotomía con aguja si se usa más de 45 minutos?","back":"Hipercapnia progresiva (ventila mal)."},{"front":"¿Cómo se define fisiopatológicamente el choque?","back":"Anormalidad circulatoria que produce perfusión tisular inadecuada e hipoxia celular."},{"front":"¿Cuál es el signo clínico más temprano del estado de choque?","back":"Taquicardia (y vasoconstricción cutánea)."},{"front":"¿Qué porcentaje de pérdida de volumen sanguíneo se requiere usualmente para que aparezca la hipotensión?","back":"Aproximadamente el 30% (Grado III)."},{"front":"¿Cómo se calcula el Índice de Choque y cuál es su valor normal?","back":"FC / PAS; Normal: 0.5 - 0.7."},{"front":"¿Qué indica un Índice de Choque mayor a 1?","back":"Choque significativo y probable necesidad de transfusión masiva."},{"front":"En el choque hemorrágico, ¿qué grado corresponde a una pérdida del 31% al 40% de volemia?","back":"Grado III."},{"front":"¿Qué grado de hemorragia se caracteriza por una FC >140, hipotensión franca y estado letárgico?","back":"Grado IV."},{"front":"¿Cuál es la meta de Presión Arterial Sistólica en un paciente con trauma (sin TCE) para evitar resucitación excesiva?","back":"80 - 90 mmHg (presencia de pulso radial)."},{"front":"En pacientes con Trauma Craneoencefálico (TCE), ¿cuál es la meta de PAS para asegurar perfusión cerebral?","back":"> 100 - 110 mmHg."},{"front":"¿Cuál es el esquema de administración del Ácido Tranexámico (TXA)?","back":"1g en 10 min seguido de 1g en 8 horas."},{"front":"¿Cuál es el tiempo límite tras el trauma para administrar Ácido Tranexámico?","back":"Dentro de las primeras 3 horas."},{"front":"¿Qué componentes forman la \"Tríada de la Muerte\"?","back":"Acidosis, Hipotermia y Coagulopatía."},{"front":"En la transfusión masiva, ¿cuál es la relación recomendada de hemoderivados?","back":"1:1:1 (Glóbulos rojos : Plasma : Plaquetas)."},{"front":"¿Cuál es la causa más común de choque obstructivo en el paciente con trauma?","back":"Neumotórax a tensión."},{"front":"¿Cuál es la tríada clínica clásica del Neumotórax a Tensión?","back":"Ausencia de ruidos respiratorios, hiperresonancia y choque (hipotensión)."},{"front":"¿Cuál es el tratamiento inicial de urgencia para un neumotórax a tensión?","back":"Descompresión con aguja en el 5.º espacio intercostal, línea axilar media."},{"front":"¿En qué consiste la Tríada de Beck para el taponamiento cardíaco?","back":"Hipotensión, ruidos cardíacos apagados e ingurgitación yugular."},{"front":"¿Cuál es el método de elección para diagnosticar taponamiento cardíaco en urgencias?","back":"FAST (ventana pericárdica ecográfica)."},{"front":"¿Cuál es el manejo inicial de un Neumotórax Abierto?","back":"Parche oclusivo fijado por 3 bordes (válvula unidireccional)."},{"front":"Se define Hemotórax Masivo como la acumulación de más de _____ ml de sangre en la cavidad torácica.","back":"1,500 ml."},{"front":"En el Hemotórax Masivo, ¿qué hallazgo a la percusión lo diferencia del neumotórax?","back":"Matidez (en lugar de hiperresonancia)."},{"front":"Criterio para Toracotomía de urgencia: Drenaje inicial de hemotórax mayor a _____ ml.","back":"1,500"},{"front":"Criterio para Toracotomía de urgencia: Sangrado continuo de _____ ml/hora por 2-4 horas.","back":"200"},{"front":"¿Qué lesión se debe sospechar ante un neumotórax que no expande tras colocar un tubo y presenta fuga masiva de aire?","back":"Lesión traqueobronquial."},{"front":"¿Cuál es el estándar de oro para diagnosticar una lesión traqueobronquial?","back":"Broncoscopía."},{"front":"¿En qué período de tiempo suele ocurrir el pico de gravedad de una contusión pulmonar?","back":"Entre las 24 y 72 horas."},{"front":"¿Cuál es la medida de tratamiento más importante (piedra angular) en la contusión pulmonar?","back":"Analgesia (para permitir ventilación y tos)."},{"front":"¿Qué tríada clínica caracteriza a la fractura laríngea?","back":"Disfonía, enfisema subcutáneo y fractura palpable."},{"front":"¿Cuál es la diferencia clave entre Neumotórax Simple y Neumotórax a Tensión?","back":"En el simple no hay desplazamiento del mediastino ni compromiso hemodinámico (choque)."},{"front":"¿Cuál es el calibre recomendado del tubo torácico para drenar un hemotórax y evitar que se tape?","back":"28 - 32 Fr."},{"front":"¿Qué complicación tardía se busca evitar drenando completamente un hemotórax simple?","back":"Empiema o hemotórax coagulado (pulmón atrapado)."},{"front":"Concepto: Signo de Kussmaul en trauma.","back":"Aumento de la presión venosa yugular al inspirar, asociado a taponamiento cardíaco."}]},"21":{"num":21,"name":"ATLS PARTE 2","cards":[{"front":"¿Cuál es la arteria que se lesiona con mayor frecuencia en un hematoma epidural?","back":"La arteria meníngea media."},{"front":"¿En qué espacio anatómico se sitúan las arterias meníngeas?","back":"Entre la duramadre y la superficie interna del cráneo."},{"front":"¿Qué establece la Doctrina de Monro-Kellie sobre el volumen intracraneal?","back":"El volumen total de los contenidos intracraneales (cerebro, sangre y LCR) debe ser constante."},{"front":"¿Cuál es el rango normal de la presión intracraneal (PIC)?","back":"7 a 15 mmHg."},{"front":"¿A partir de qué valor de presión intracraneal (PIC) se considera un mal pronóstico?","back":"> 22 mmHg."},{"front":"¿Cuál es el rango meta de saturación de oxígeno (SpO₂) en el manejo de un TCE?","back":"94% - 98%."},{"front":"¿Cuál es el rango objetivo de PaCO₂ (ventilación) en un paciente con TCE?","back":"35 - 45 mmHg."},{"front":"¿Cuál es la meta de glucosa sérica en la reanimación de un paciente con TCE?","back":"80 - 180 mg/dL."},{"front":"¿Cuál es el rango de temperatura corporal objetivo en un paciente con TCE?","back":"36°C - 38°C."},{"front":"¿Cuál es la meta de sodio sérico en pacientes con traumatismo craneoencefálico?","back":"135 - 145 mEq/L."},{"front":"¿Cuál es el valor objetivo de INR en la reanimación de un TCE?","back":"≤ 1.4."},{"front":"¿Qué presión arterial sistólica (PAS) se debe mantener en pacientes con TCE de 50 a 69 años?","back":"≥ 100 mmHg."},{"front":"¿Qué presión arterial sistólica (PAS) se debe mantener en pacientes con TCE de 15 a 49 años o mayores de 70 años?","back":"≥ 110 mmHg."},{"front":"¿En qué casos de TCE es obligatoria la realización de una TAC de cráneo de urgencia según el nivel de Glasgow?","back":"En todo TCE moderado o severo (GCS < 13)."},{"front":"En un TCE leve (GCS 13-15), ¿cuál es el criterio de tiempo para indicar TAC si el paciente no recupera un GCS de 15?","back":"A las 2 horas de la lesión."},{"front":"Mencione tres signos clínicos de sospecha de fractura de base de cráneo.","back":"Ojos de mapache, signo de Battle y otorraquia/rinorraquia."},{"front":"¿Cuántos episodios de vómito en un TCE leve justifican la realización de una TAC?","back":"2 o más episodios."},{"front":"¿A partir de qué edad se considera un factor de riesgo para TAC en un paciente con TCE leve?","back":"> 65 años."},{"front":"¿Cuál es el tiempo de pérdida de conciencia que justifica una TAC en un TCE leve?","back":"> 5 minutos."},{"front":"¿Qué fármaco se debe utilizar en caso de convulsiones agudas tras un TCE?","back":"Benzodiacepinas (como Diazepam o Lorazepam)."},{"front":"¿Qué estudio se debe realizar si un paciente con TCE presenta hipotensión inexplicable?","back":"FAST (Focused Assessment with Sonography for Trauma)."},{"front":"¿Cuál es el criterio de tiempo para considerar amnesia retrógrada como riesgo medio en TCE leve?","back":"> 30 minutos."},{"front":"¿Qué soluciones intravenosas se deben evitar en el TCE para no aumentar el edema cerebral?","back":"Soluciones hipotónicas o glucosadas."},{"front":"¿Por qué se debe evitar la hiperventilación profiláctica en el TCE?","back":"Porque el bajo CO₂ causa vasoconstricción y puede aumentar la isquemia cerebral."},{"front":"¿En qué situación clínica específica se permite el uso breve de hiperventilación?","back":"En pacientes con signos de herniación inminente (ej. pupila dilatada, descerebración)."},{"front":"¿Cuál es la dosis inicial de Manitol al 20% para tratar la herniación en un paciente normovolémico?","back":"1 g/kg en bolo."},{"front":"¿Cuál es la contraindicación principal para el uso de Manitol en el control de la PIC?","back":"La hipotensión del paciente."},{"front":"¿Qué tratamiento osmótico es preferible para reducir el edema cerebral si el paciente está hipotenso?","back":"Solución salina hipertónica (3% a 23.4%)."},{"front":"¿Cuándo se indica el uso de barbitúricos en el manejo del TCE?","back":"En casos de hipertensión intracraneal (PIC) refractaria."},{"front":"¿Cuál es el objetivo del uso de fenitoína o levetiracetam en los primeros 7 días tras un TCE?","back":"Prevenir convulsiones tempranas."},{"front":"¿Qué tipo de pacientes tienen mayor riesgo de convulsiones postraumáticas y requieren profilaxis?","back":"Pacientes con Glasgow < 8 o con lesiones penetrantes."},{"front":"¿Qué porcentaje de los casos de TCE moderado se deterioran clínicamente hasta caer en coma?","back":"10% al 20%."},{"front":"¿Cuál es la conducta a seguir respecto a la TAC en un paciente con TCE moderado (GCS 9-12)?","back":"La TAC de cráneo es obligatoria en todos los casos."},{"front":"¿Cuál es la prioridad de manejo en la vía aérea (A) de un paciente con TCE severo (GCS 3-8)?","back":"Intubación endotraqueal inmediata."},{"front":"¿En qué ventana de tiempo se debe administrar el Ácido Tranexámico en un TCE moderado/severo?","back":"En las primeras 3 horas tras el trauma."},{"front":"¿Cuál es el esquema de administración del Ácido Tranexámico en el TCE?","back":"1 g en 10 min seguido de 1 g para 8 horas."},{"front":"¿Qué hallazgo clínico indica una fractura de la fosa craneal anterior (hueso frontal)?","back":"Ojos de mapache (equimosis periorbitaria)."},{"front":"¿Qué indica el signo de Battle (equimosis retroauricular sobre la mastoides)?","back":"Fractura de la fosa media (hueso temporal)."},{"front":"¿Qué par craneal se lesiona comúnmente en las fracturas de base de cráneo?","back":"El nervio facial (VII) o el auditivo (VIII)."},{"front":"En caso de fractura de base de cráneo, ¿qué vía se prefiere para colocar una sonda gástrica?","back":"Vía orogástrica (nunca nasogástrica)."},{"front":"¿Cuál es la imagen clásica de un hematoma epidural en la TAC?","back":"Imagen biconvexa o lenticular (forma de limón o balón de fútbol americano)."},{"front":"¿Cómo se comporta el hematoma epidural respecto a las líneas de sutura craneales?","back":"No cruza las líneas de sutura."},{"front":"Describa la presentación clínica del \"intervalo lúcido\" en el hematoma epidural.","back":"Pérdida inicial de conciencia, período de lucidez aparente y posterior deterioro neurológico súbito."},{"front":"¿Cuál es el origen vascular más común del hematoma subdural?","back":"Ruptura de las venas puente (corticales)."},{"front":"¿Cuál es la imagen clásica de un hematoma subdural en la TAC?","back":"Imagen en forma de semiluna (forma de plátano)."},{"front":"¿Cruza el hematoma subdural las líneas de sutura craneales?","back":"Sí, puede extenderse por todo el hemisferio."},{"front":"¿Qué población tiene mayor riesgo de hematoma subdural debido a la atrofia cerebral?","back":"Ancianos y alcohólicos."},{"front":"¿Qué diagnóstico debe sospecharse ante un hematoma subdural en un bebé?","back":"Maltrato infantil (Síndrome del niño sacudido)."},{"front":"¿Qué patrón radiológico en la TAC caracteriza a las contusiones cerebrales?","back":"Imagen de \"sal y pimienta\" (sangre mezclada con edema)."},{"front":"¿Qué mecanismo produce la Lesión Axonal Difusa (LAD)?","back":"Aceleración/desaceleración rápida o rotación (cizallamiento)."},{"front":"¿Cuál es el hallazgo típico de la Lesión Axonal Difusa en una TAC?","back":"Puede ser normal o mostrar hemorragias puntiformes en el cuerpo calloso o la unión gris-blanca."},{"front":"¿Cuál es la causa más común de una Hemorragia Subaracnoidea (HSA) no traumática?","back":"Ruptura de un aneurisma."},{"front":"¿Qué fármaco se utiliza para prevenir el vasoespasmo en la HSA aneurismática?","back":"Nimodipino."},{"front":"¿Cuál es el estándar de oro para confirmar el diagnóstico de muerte cerebral?","back":"Angiografía cerebral de 4 vasos (ausencia de flujo)."},{"front":"¿Qué temperatura mínima debe tener un paciente para ser evaluado por muerte cerebral?","back":"≥ 32°C."},{"front":"¿Cuál es el valor del Glasgow en un paciente con muerte cerebral?","back":"3 puntos."},{"front":"¿En qué consiste la prueba de apnea para muerte cerebral?","back":"Ausencia de esfuerzo ventilatorio espontáneo al dejar subir la PaCO₂."},{"front":"¿Cuál es la zona más vulnerable de la columna vertebral en un trauma?","back":"La columna cervical (específicamente C3-C7)."},{"front":"¿A qué nivel de lesión medular suele ocurrir el choque neurogénico?","back":"Lesiones por encima de T6."},{"front":"¿Cuál es la tríada clínica característica del choque neurogénico?","back":"Hipotensión, bradicardia y piel caliente/rosa."},{"front":"¿Qué fármaco se utiliza para manejar la bradicardia en el choque neurogénico?","back":"Atropina."},{"front":"¿Cuál es el mecanismo de lesión de la Fractura de Jefferson (C1)?","back":"Carga axial o estallido (ej. clavado en piscina poco profunda)."},{"front":"¿Qué mecanismo produce la Fractura del Ahorcado (C2)?","back":"Hiperextensión y distracción."},{"front":"¿Qué mecanismo caracteriza a la Fractura de Chance (T10-L2)?","back":"Flexión con distracción (típica por cinturón de seguridad de dos puntos)."},{"front":"¿Qué caracteriza al Síndrome Medular Central?","back":"Debilidad motora desproporcionada en extremidades superiores mayor que en las inferiores."},{"front":"¿Cuál es el mecanismo típico del Síndrome Medular Central?","back":"Hiperextensión del cuello en ancianos con estenosis cervical."},{"front":"¿Qué funciones se preservan en el Síndrome Medular Anterior?","back":"Propiocepción, vibración y tacto fino (columnas posteriores)."},{"front":"¿Cuál es el síndrome medular de peor pronóstico funcional?","back":"Síndrome Medular Anterior."},{"front":"¿Qué hallazgos clínicos definen el Síndrome de Brown-Séquard?","back":"Pérdida motora ipsilateral y pérdida de dolor/temperatura contralateral."},{"front":"¿Cuál es el síndrome medular con mejor pronóstico para la recuperación motora?","back":"Síndrome de Brown-Séquard."},{"front":"¿Cuál es la meta de PaCO₂ en pacientes con TCE?","back":"Normocapnia (35 a 45 mmHg)."},{"front":"¿Qué escala se utiliza para evaluar el riesgo de vasoespasmo en la hemorragia subaracnoidea?","back":"Escala de Fisher."},{"front":"¿Qué escala evalúa el pronóstico clínico de la hemorragia subaracnoidea aneurismática?","back":"Escala de Hunt y Hess."},{"front":"¿Cuál es la indicación de TAC en un paciente con TCE y uso de anticoagulantes?","back":"La TAC es obligatoria independientemente del Glasgow."}]},"22":{"num":22,"name":"ATLS PARTE 3","cards":[{"front":"¿Cuál es el órgano lesionado con mayor frecuencia en el trauma abdominal cerrado?","back":"El bazo (40-55\\%)."},{"front":"¿Cuál es el órgano más frecuentemente afectado en el trauma por arma blanca?","back":"El hígado (40\\%)."},{"front":"¿Qué órgano se lesiona con mayor frecuencia en heridas por arma de fuego?","back":"El intestino delgado (50\\%)."},{"front":"En el trauma abdominal cerrado, ¿cuál es el segundo órgano más afectado después del bazo?","back":"El hígado (35-45\\%)."},{"front":"¿Qué porcentaje de incidencia tiene el hematoma retroperitoneal en pacientes sometidos a laparotomía por trauma?","back":"15\\%."},{"front":"Las lesiones penetrantes en la región glútea se asocian a un _____ de probabilidad de lesiones intraabdominales significativas.","back":"50\\%."},{"front":"¿Qué porcentaje de las heridas por arma de fuego abdominales causan una lesión intraperitoneal?","back":"98\\%."},{"front":"¿Cuál es el porcentaje de lesión intraperitoneal en heridas abdominales por arma blanca?","back":"30\\%."},{"front":"¿Cuál es la conducta inmediata ante un paciente con herida abdominal por arma de fuego?","back":"Laparotomía inmediata."},{"front":"Menciona dos indicaciones clínicas directas de laparotomía tras un trauma abdominal.","back":"Irritación peritoneal y evisceración."},{"front":"¿Qué cantidad de sangre aspirada inicialmente hace que un Lavado Peritoneal Diagnóstico (LPD) se considere positivo?","back":"10 cc."},{"front":"¿Cuál es el recuento de eritrocitos por mm³ necesario para considerar positivo un LPD tras infundir un litro de suero?","back":"100,000 eritrocitos/mm³."},{"front":"¿Cuál es el recuento de leucocitos por mm³ necesario para considerar positivo un LPD?","back":"500 leucocitos/mm³."},{"front":"En un paciente inestable con trauma cerrado, ¿qué estudios de imagen son de elección inicial?","back":"USG FAST o LPD."},{"front":"¿Cuál es el estudio de imagen de elección para evaluar el retroperitoneo en un paciente estable?","back":"Tomografía Axial Computarizada (TAC)."},{"front":"¿Cuáles son las 4 regiones que evalúa el examen USG FAST?","back":"Subxifoidea, fosa hepatorrenal (Morison), fosa esplenorrenal y pelvis (saco de Douglas)."},{"front":"Menciona tres signos físicos que contraindican la colocación de una sonda uretral sin antes realizar un uretrograma retrógrado.","back":"Sangre en el meato, hematoma escrotal y equimosis perineal."},{"front":"En caso de sospecha de lesión uretral donde no se puede colocar sonda, ¿cuál es el procedimiento a seguir?","back":"Insertar una sonda suprapúbica."},{"front":"¿Qué mecanismo de fractura pélvica es conocido como \"libro abierto\"?","back":"Compresión anteroposterior."},{"front":"¿Cuál es el mecanismo de fractura pélvica más grave y asociado a mayor mortalidad?","back":"Compresión anteroposterior (Libro abierto)."},{"front":"¿A partir de qué altura de caída se suele producir una lesión por cizallamiento vertical de la pelvis?","back":"Más de 12 pies (3.66 metros)."},{"front":"¿Cuál es el mecanismo de fractura pélvica más común?","back":"Compresión lateral (cerrada)."},{"front":"¿Cuál es el método de elección para el control del sangrado arterial en fracturas de pelvis?","back":"Embolización por angiografía."},{"front":"Menciona una medida de estabilización mecánica temporal para una pelvis inestable en urgencias.","back":"Uso de una sábana o inmovilizador pélvico."},{"front":"¿Qué hallazgo en el examen físico de extremidades sugiere una fractura de pelvis en ausencia de fracturas de fémur?","back":"Diferencia en el largo de las extremidades o rotación de la pierna."},{"front":"¿Cuál es la arteria más frecuentemente lesionada en el trauma periférico?","back":"Arteria femoral superior."},{"front":"¿Cuál es la arteria más frecuentemente lesionada en el trauma de miembro superior?","back":"Arteria braquial (20-30\\%)."},{"front":"¿Cuáles son los \"signos duros\" de lesión vascular que indican exploración quirúrgica inmediata?","back":"Hemorragia pulsátil, ausencia de pulsos, hematoma en expansión, frémito o soplo."},{"front":"Menciona tres \"signos blandos\" de lesión vascular periférica.","back":"Reducción de pulsos, lesión cercana a trayecto vascular y alteración nerviosa."},{"front":"Nombra las 6 \"P\" indicativas de insuficiencia vascular periférica.","back":"Pain, Palidez, Parestesias, Parálisis, Pulselessness y Pérdida de temperatura."},{"front":"¿Qué valor del índice Tobillo-Brazo (ITB) se considera indicativo de una lesión arterial muy grave?","back":"Menor a 0.5."},{"front":"¿Cuál es el estándar de oro para el diagnóstico de trauma vascular?","back":"Arteriografía."},{"front":"¿Cuál es el método de elección para trauma vascular ante la baja disponibilidad de arteriografía?","back":"Angiotomografía (AngioTAC)."},{"front":"¿Cuál es el tiempo recomendado de observación para un paciente con trauma vascular?","back":"24 a 48 horas."},{"front":"¿Cuál es la causa principal de muerte fetal en el trauma obstétrico?","back":"Shock y muerte de la madre."},{"front":"¿Cuál es la segunda causa de muerte fetal tras un traumatismo abdominal?","back":"Desprendimiento prematuro de placenta."},{"front":"¿Cómo debe posicionarse a la paciente embarazada para evitar la compresión de la vena cava inferior?","back":"Desplazar el útero hacia la izquierda (15°-30°) o elevar el lado derecho 10-15 cm."},{"front":"¿Cuál es el orden correcto de las revisiones (primaria/secundaria) en la paciente embarazada traumatizada?","back":"Revisión primaria materna, revisión primaria fetal y revisión secundaria materna."},{"front":"¿Cuánta sangre puede perder una paciente embarazada antes de mostrar signos de hipovolemia?","back":"Entre 1,200 a 1,500 mL."},{"front":"¿Cuánto tiempo de monitoreo fetal continuo se requiere en pacientes con factores de riesgo para desprendimiento de placenta?","back":"24 horas."},{"front":"¿Qué complicación se debe sospechar si el líquido amniótico pasa al espacio intravascular materno?","back":"Embolismo de líquido amniótico."},{"front":"¿A partir de qué cifra de tensión arterial sistólica se define hipotensión en el paciente geriátrico?","back":"Menor a 110 mmHg."},{"front":"¿Cuál es la causa más común de trauma en el paciente geriátrico?","back":"Caídas (asociadas a polifarmacia)."},{"front":"¿Cuál es el mayor predictor de maltrato infantil en el contexto de trauma?","back":"Lesiones cubiertas por la ropa."},{"front":"En pediatría, ¿cuál es la altura de caída mínima considerada indicación de TAC en lactantes menores de un año?","back":"Más de 90 cm."},{"front":"¿Qué es el Signo de Kehr y qué indica?","back":"Dolor referido al hombro izquierdo por irritación diafragmática tras una ruptura esplénica."},{"front":"¿Qué hallazgo radiológico sugiere un desgarro del diafragma?","back":"Elevación diafragmática, apariencia borrosa o sombra de gas que oscurece la placa."},{"front":"¿Qué estudio diagnóstico es de elección para la sospecha de lesión duodenal?","back":"TAC con doble contraste."},{"front":"¿Qué mecanismo de lesión sugiere específicamente una lesión duodenal?","back":"Impacto frontal sin cinturón o golpe directo con manubrio de bicicleta."},{"front":"En mujeres inconscientes menstruando que sufren trauma, ¿por qué es vital retirar tampones vaginales?","back":"Para evitar sepsis tardía."},{"front":"¿Cuál es la conducta ante una AngioTAC dudosa en sospecha de trauma vascular?","back":"Realizar arteriografía."},{"front":"Ante rabdomiólisis por trauma vascular, ¿cuál es la meta del tratamiento además de la reanimación hídrica?","back":"Administrar bicarbonato (HCO₃) y mantener diuresis para evitar lesión renal."},{"front":"¿Cuál es la causa más frecuente de quemaduras en la población general según el texto?","back":"Escaldaduras."},{"front":"¿Qué lado del diafragma se lesiona con mayor frecuencia en un traumatismo?","back":"El lado izquierdo."},{"front":"¿Qué indica el hallazgo de fibras vegetales en el aspirado de un LPD?","back":"Positividad inmediata para laparotomía (sugiere perforación intestinal)."}]},"23":{"num":23,"name":"TOXINDROMES","cards":[{"front":"¿Cuál es el mecanismo de acción del síndrome anticolinérgico?","back":"Bloqueo competitivo de la acetilcolina en las sinapsis parasimpáticas."},{"front":"Menciona tres clases de fármacos que pueden causar un síndrome anticolinérgico.","back":"Antihistamínicos, neurolépticos y antidepresivos tricíclicos."},{"front":"¿Qué hallazgo pupilar es característico del síndrome anticolinérgico?","back":"Midriasis."},{"front":"¿Cómo se describe clásicamente el estado de la piel y mucosas en el síndrome anticolinérgico?","back":"Paciente \"seco\" (piel seca y rubicunda)."},{"front":"¿Cuál es el tratamiento específico (antídoto) para el síndrome anticolinérgico?","back":"Fisostigmina."},{"front":"¿Cuál es el mecanismo fisiopatológico del síndrome simpaticomimético?","back":"Exceso de aminas en el SNC por aumento de liberación, disminución de recaptación o impedimento de su metabolismo."},{"front":"¿Qué hallazgo en la piel diferencia al síndrome simpaticomimético del anticolinérgico?","back":"La presencia de diaforesis (sudoración) en el simpaticomimético."},{"front":"En el síndrome simpaticomimético por cocaína, ¿cuál es el tratamiento de elección para el control de la agitación?","back":"Benzodiacepinas."},{"front":"¿Qué fármaco se recomienda para el manejo de una crisis hipertensiva en un síndrome simpaticomimético?","back":"Nicardipino."},{"front":"Menciona tres causas farmacológicas del síndrome serotoninérgico.","back":"Sertralina, fluoxetina y ondansetrón."},{"front":"¿Qué síntomas gastrointestinales y neuromusculares distinguen al síndrome serotoninérgico?","back":"Diarrea, mioclonías y rigidez."},{"front":"¿Cuál es el tratamiento específico inicial para el síndrome serotoninérgico?","back":"Benzodiacepinas."},{"front":"El síndrome colinérgico es el resultado de la hiperestimulación de los receptores _____ de la acetilcolina.","back":"Muscarínicos."},{"front":"¿Cuáles son las manifestaciones muscarínicas clásicas del síndrome colinérgico?","back":"Miosis, broncorrea, bradicardia, sialorrea y lagrimación."},{"front":"¿Qué síntomas caracterizan la fase nicotínica del síndrome colinérgico?","back":"Taquicardia, midriasis, temblor y parálisis craneal."},{"front":"¿En qué período de tiempo se presenta el síndrome intermedio tras una exposición a organofosforados?","back":"De 1 a 4 días."},{"front":"¿Cuál es el tratamiento específico inicial para las manifestaciones muscarínicas del síndrome colinérgico?","back":"Atropina (1-2 mg cada 5 minutos)."},{"front":"¿Qué fármacos son la elección para reactivar la acetilcolinesterasa en una intoxicación por organofosforados?","back":"Oximas (ej. obidoxima)."},{"front":"¿Cómo se realiza el diagnóstico confirmatorio de intoxicación por organofosforados?","back":"Estimación de la actividad de la colinesterasa plasmática y eritrocitaria."},{"front":"¿Cuál es la principal causa de muerte en el síndrome colinérgico severo?","back":"Paro respiratorio secundario a parálisis o broncorrea severa."},{"front":"¿Qué neurotransmisor inhibidor es el responsable de la sintomatología en el síndrome hipnótico-sedante?","back":"GABA (ácido gamma aminobutírico)."},{"front":"Menciona tres signos clínicos del síndrome hipnótico-sedante.","back":"Bradilalia, nistagmo e hiporreflexia."},{"front":"¿Cuál es el antídoto específico para la intoxicación por benzodiacepinas?","back":"Flumazenil (0.1-0.3 mg IV)."},{"front":"En un paciente con sospecha de intoxicación por benzodiacepinas y prueba de orina negativa, ¿qué fármaco se debe administrar?","back":"Naloxona."},{"front":"¿Por qué se recomienda la retirada gradual de los barbitúricos en pacientes adictos?","back":"Porque la abstinencia a barbitúricos conlleva una alta mortalidad."},{"front":"¿Cuál es la tríada clínica clásica de la intoxicación por opiáceos?","back":"Miosis, alteración del nivel de conciencia y depresión respiratoria."},{"front":"Además de la miosis, ¿qué efectos sobre la motilidad y la piel producen los opiáceos?","back":"Reducción de motilidad intestinal (estreñimiento) y prurito."},{"front":"¿Cuál es el antídoto de elección para revertir la depresión respiratoria por opiáceos?","back":"Naloxona (0.4-2 mg IV)."},{"front":"Concepto: Cóctel toxicológico","back":"Combinación de glucosa, oxígeno, naloxona y tiamina para pacientes con déficit neurológico de causa desconocida."},{"front":"¿Qué enzima es la encargada de convertir el etanol en acetaldehído?","back":"Alcohol deshidrogenasa."},{"front":"¿Por qué no se recomienda el lavado gástrico en la intoxicación por etanol?","back":"Debido a la rápida absorción del alcohol en la mucosa (30% estómago, 70% intestino delgado)."},{"front":"¿Qué hallazgo pupilar se presenta en la intoxicación grave por etanol?","back":"Midriasis."},{"front":"¿Cuál es el tratamiento específico para prevenir complicaciones neurológicas en la intoxicación por etanol?","back":"Tiamina (1 o 2 ámpulas)."},{"front":"¿Qué fármaco se utiliza para el manejo del paciente agresivo por intoxicación etílica?","back":"Haloperidol."},{"front":"Antídoto para intoxicación por Paracetamol:","back":"N-acetilcisteína."},{"front":"Antídoto para intoxicación por Beta-bloqueadores:","back":"Glucagón."},{"front":"Antídoto para intoxicación por Calcio antagonistas:","back":"Calcio, glucagón e insulina."},{"front":"Antídoto para intoxicación por Monóxido de Carbono:","back":"Oxígeno."},{"front":"Antídoto para intoxicación por Heparina:","back":"Protamina."},{"front":"Antídoto para intoxicación por Isoniazida:","back":"Piridoxina."},{"front":"Antídoto para intoxicación por Metahemoglobina:","back":"Azul de metileno."},{"front":"Antídoto para intoxicación por Metanol:","back":"Etanol."},{"front":"Antídoto para intoxicación por Plomo y Mercurio:","back":"Penicilamina."},{"front":"Antídoto para intoxicación por Plomo (alternativa a penicilamina):","back":"EDTA o Succímero."},{"front":"En el contexto de intoxicación por antidepresivos tricíclicos, ¿qué sustancia se utiliza como parte del manejo de base?","back":"Bicarbonato de sodio."},{"front":"¿Qué estado de la República Mexicana presenta el mayor número de casos reportados de intoxicación colinérgica?","back":"Jalisco."},{"front":"¿Qué estado de la República Mexicana tiene la mayor incidencia de intoxicación colinérgica?","back":"Nayarit."},{"front":"¿Cuál es la mortalidad reportada en casos de intoxicación colinérgica severa?","back":"47%."},{"front":"¿Qué síntomas caracterizan a la intoxicación leve por etanol?","back":"Labilidad emocional, ataxia, somnolencia y alteración de reflejos."},{"front":"¿Qué síntomas caracterizan a la intoxicación moderada por etanol?","back":"Lenguaje incoherente, agresividad y letargia."},{"front":"En pediatría, ¿cuáles son las causas comunes de intoxicación accidental por alcohol?","back":"Ingesta o baños de alcohol."},{"front":"¿Qué receptor opiáceo es el principal responsable de la sintomatología clínica tras la activación?","back":"Receptor Mu (μ)."},{"front":"¿Cuál es el mecanismo de acción de la Naloxona?","back":"Bloquea la inhibición de los receptores GABA mediada por opioides."},{"front":"¿Qué toxíndrome se caracteriza por agresividad, hipertensión y diaforesis?","back":"Simpaticomimético."},{"front":"¿Cuál es la principal causa de intoxicación por drogas en adultos?","back":"Abuso de ingestión de alcohol."},{"front":"¿Qué alteración visual es común en el síndrome hipnótico-sedante?","back":"Nistagmo."},{"front":"¿Cuál es el síntoma neuromuscular que define al síndrome serotoninérgico según los \"Puntos Madre Mía\"?","back":"Mioclonías y rigidez."},{"front":"En el síndrome colinérgico, ¿qué efecto tiene la atropina sobre los receptores nicotínicos?","back":"Nula respuesta (la atropina solo actúa sobre receptores muscarínicos)."},{"front":"¿Qué toxíndrome suele presentarse en trabajadores del campo?","back":"Colinérgico (por organofosforados)."},{"front":"¿Cuál es el manejo de base inicial para casi todos los toxíndromes según el material?","back":"Descontaminación y ABCDE."}]},"24":{"num":24,"name":"MORDEDURAS Y PICADURAS","cards":[{"front":"¿Cuál es el agente etiológico del loxoscelismo, comúnmente conocida como araña violinista o parda?","back":"Loxosceles reclusa."},{"front":"¿Qué característica morfológica en el dorso permite identificar a la araña Loxosceles?","back":"Una mancha en forma de violín invertido."},{"front":"¿Cuál es la toxina principal del veneno de Loxosceles reclusa responsable de la lisis de eritrocitos?","back":"Esfingomielinasa-D."},{"front":"En el loxoscelismo cutáneo, ¿cómo se describe el dolor característico inicial?","back":"Dolor tipo ardoroso con sensación de \"quemadura de cigarro\"."},{"front":"¿Cómo se denomina a la lesión cutánea clásica del loxoscelismo que presenta un patrón de piel pálida rodeando una vesícula hemorrágica?","back":"Placa livedoide."},{"front":"El loxoscelismo sistémico o cutáneo-visceral suele ocurrir en un período de _____ a _____ horas después de la mordedura.","back":"24 a 48"},{"front":"¿Cuál es la tríada clínica característica del loxoscelismo cutáneo-visceral?","back":"Anemia hemolítica, hemoglobinuria y oliguria."},{"front":"¿Cuáles son las dos principales causas de muerte en pacientes con loxoscelismo sistémico?","back":"Falla renal y Coagulación Intravascular Diseminada (CID)."},{"front":"¿Qué fármaco se utiliza específicamente en el tratamiento del loxoscelismo cutáneo, junto con el hielo local?","back":"Dapsona."},{"front":"¿Cuál es el tratamiento de elección para el loxoscelismo en pacientes embarazadas?","back":"Prednisona."},{"front":"¿Para qué se solicita una radiografía AP y lateral de la extremidad afectada en una mordedura de araña?","back":"Para descartar la presencia de aire en tejidos blandos."},{"front":"¿Cuál es el nombre científico de la araña conocida como \"viuda negra\" o \"capulina\"?","back":"Latrodectus mactans."},{"front":"¿Qué marca distintiva presenta la hembra de Latrodectus mactans en su abdomen?","back":"Una cutícula roja en forma de reloj de arena."},{"front":"¿Cuál es el mecanismo de acción de las alfa-latrotoxinas en el latrodectismo?","back":"Causan la liberación masiva de neurotransmisores presinápticos."},{"front":"¿En qué rango de tiempo suele presentarse la toxicidad sistémica tras una mordedura de viuda negra?","back":"De 30 minutos a 2 horas."},{"front":"Menciona una de las principales manifestaciones neuromusculares del latrodectismo.","back":"Fasciculaciones."},{"front":"¿Cuál es el tratamiento específico inicial para el latrodectismo?","back":"Un vial de 2.5 ml de anti-arácnido diluido en solución salina."},{"front":"¿Bajo qué condición se debe repetir la dosis de faboterápico en el latrodectismo?","back":"Si los síntomas persisten por más de 24 horas."},{"front":"¿Cuál es la toxina del veneno de alacrán que afecta principalmente los canales de K^+, Na^+ y Ca²⁺?","back":"Escorpaminas."},{"front":"¿Qué función tiene la hialuronidasa en el veneno de alacrán?","back":"Aumenta la permeabilidad capilar para facilitar la absorción del veneno."},{"front":"¿Cuáles son los tres grupos de población con mayor riesgo ante una picadura de alacrán?","back":"Menores de 5 años, mayores de 60 años y pacientes con comorbilidades."},{"front":"¿Qué género de alacrán es el más frecuente y de importancia médica en México?","back":"Centruroides."},{"front":"¿Qué especie de alacrán es considerada la más tóxica en México y en qué estado se localiza?","back":"Centruroides noxius en Nayarit."},{"front":"Como medida de prevención en zonas endémicas, la cama debe estar separada de la pared al menos _____ cm.","back":"10"},{"front":"¿Qué síntoma define el grado leve (grado 1) de la picadura de alacrán?","back":"Dolor y parestesias locales."},{"front":"Paciente con picadura de alacrán que presenta prurito nasal, faríngeo y sialorrea. ¿Qué grado de severidad presenta?","back":"Grado 2 (Moderado)."},{"front":"Menciona dos datos de alarma que indican una picadura de alacrán grado 3 (severo).","back":"Nistagmo y fasciculaciones linguales."},{"front":"¿Cuántas ámpulas de faboterápico se administran inicialmente a un adulto sano con alacranismo leve?","back":"1 ámpula IV."},{"front":"¿Cuál es la dosis inicial de faboterápico para un niño de 3 años con alacranismo moderado?","back":"4 ámpulas IV."},{"front":"¿Cuántas ámpulas IV requiere un paciente mayor de 60 años con alacranismo severo?","back":"6 ámpulas IV."},{"front":"Tras aplicar el faboterápico por picadura de alacrán, ¿cuánto tiempo debe observarse al paciente antes de decidir aplicar otra dosis?","back":"20 minutos."},{"front":"¿Cuál es el sitio anatómico donde ocurre el 72% de las mordeduras de serpiente?","back":"Pies y tobillos."},{"front":"En América, la familia de serpientes _____ representa más del 90% de los accidentes ofídicos.","back":"Viperidae."},{"front":"Concepto: Mordedura fría","back":"Definición: Mordedura de serpiente en la que no se inocula veneno (ocurre en el 20% de los casos)."},{"front":"¿Qué tipo de toxinas en el veneno de serpiente interfieren con los factores de coagulación V, VIII, X y XIII?","back":"Hemotoxinas."},{"front":"En el accidente ofídico, ¿por qué está contraindicado el uso de torniquetes?","back":"Porque complican la circulación linfática y favorecen la necrosis y fibrinólisis."},{"front":"¿Cuál es la conducta a seguir si un paciente llega con un torniquete tras una mordedura de serpiente?","back":"Aplicar el antídoto antes de retirar el torniquete."},{"front":"¿Qué presión deben tener las bandas de presión utilizadas en el miembro afectado por mordedura de serpiente?","back":"De 50 a 70 mmHg."},{"front":"¿Cada cuánto tiempo se debe evaluar la circunferencia del miembro afectado en un accidente ofídico?","back":"Cada 15 a 20 minutos."},{"front":"¿Por qué se recomiendan opioides en lugar de AINES para el dolor en mordeduras por Viperidae?","back":"Para evitar el riesgo de exacerbar coagulopatías."},{"front":"¿Qué escala se utiliza para clasificar la gravedad del envenenamiento por la familia Viperidae?","back":"Clasificación de Christopher-Rodning."},{"front":"Según Christopher-Rodning, ¿qué grado se caracteriza por edema de 10 cm circunscrito al área de la lesión?","back":"Grado I (Leve)."},{"front":"Paciente con mordedura de cascabel que presenta náuseas y edema de 18 cm. ¿Cuántos viales de faboterápico deben aplicarse?","back":"5 viales IV."},{"front":"En el grado III de Christopher-Rodning, ¿cuál es la extensión del edema en el miembro afectado?","back":"Edema en todo el miembro."},{"front":"¿Cuántos viales de faboterápico se administran en un envenenamiento Grado IV por Viperidae?","back":"25 viales IV."},{"front":"¿Cuál es el volumen de dilución estándar de solución salina para los viales de faboterápico en mordedura por Viperidae?","back":"100 a 250 ml."},{"front":"¿Cuáles son los síntomas característicos de un envenenamiento moderado por serpiente coral (Elapidae)?","back":"Astenia, adinamia, ptosis palpebral y visión borrosa."},{"front":"¿Cuál es el tratamiento para una mordedura grave por serpiente coral que presenta parálisis flácida?","back":"8 frascos de faboterápico."},{"front":"¿Qué complicación renal es común tanto en el loxoscelismo como en el accidente ofídico grave?","back":"Insuficiencia Renal Aguda."},{"front":"¿Bajo qué condición se considera una mordedura de Viperidae como Grado 0?","back":"Presencia de huellas puntiformes sin signos de envenenamiento."},{"front":"La aplicación de hielo local en mordeduras de serpiente debe ser de forma intermitente cada _____ minutos.","back":"20"},{"front":"Para la picadura de alacrán, ¿qué medida de prevención se recomienda para las patas de las camas?","back":"Sumergirlas en recipientes con agua."},{"front":"¿Cuál es la vida media aproximada del veneno de alacrán en el cuerpo humano?","back":"36 horas."},{"front":"Menciona una de las causas de muerte específica en el latrodectismo debida a la hiperestimulación autonómica.","back":"Crisis convulsivas o fallo respiratorio (por debilidad muscular)."},{"front":"En mordeduras por coralillo, ¿cuántos frascos de faboterápico se indican en el grado leve?","back":"2 a 3 frascos."},{"front":"¿Cuál es el primer paso del manejo inicial en cualquier accidente ofídico?","back":"Reposo e inmovilización de la parte lesionada y traslado inmediato."},{"front":"Menciona dos estudios de laboratorio esenciales para vigilar complicaciones en mordedura de serpiente.","back":"Tiempos de coagulación (TP, TTP) y Creatinina."},{"front":"¿Qué efecto tiene el veneno de alacrán sobre el sistema nervioso autónomo?","back":"Produce estimulación simpática y parasimpática."},{"front":"En el contexto de mordedura de serpiente en niños, ¿cuáles son las tres complicaciones más temidas?","back":"Necrosis tisular, CID y síndrome compartimental."},{"front":"¿Qué hallazgo en el examen general de orina sugiere loxoscelismo sistémico?","back":"Hemoglobinuria."}]},"25":{"num":25,"name":"QUEMADURAS","cards":[{"front":"¿Cuál es el principal proceso fisiopatológico que define a las quemaduras?","back":"Deshidratación súbita del tejido con desnaturalización proteica y destrucción celular."},{"front":"¿Cuál es la principal causa de muerte inmediata en un paciente con quemaduras?","back":"Choque hipovolémico."},{"front":"¿Cuáles son las causas predominantes de muerte en las complicaciones tardías de una quemadura?","back":"Problemas respiratorios o sobreinfecciones."},{"front":"¿Qué porcentaje de las quemaduras son de origen térmico?","back":"90%."},{"front":"¿Cuál es el grupo de edad más afectado por las quemaduras térmicas?","back":"Menores de 5 años."},{"front":"¿Cuál es el mecanismo específico que constituye la principal causa de quemaduras térmicas?","back":"Escaldaduras."},{"front":"¿En qué lugares específicos del hogar ocurren el 67% de las quemaduras?","back":"Cocina y baño."},{"front":"Dentro del manejo inicial, ¿cuál es el primer paso obligatorio?","back":"Detener el proceso de la quemadura."},{"front":"¿Qué acción se debe evitar con la ropa adherida a la piel durante el manejo inicial?","back":"Arrancar la ropa adherida."},{"front":"¿Cuál es la medida inmediata para evitar la hipotermia una vez detenida la quemadura?","back":"Cubrir al paciente con cobertores limpios."},{"front":"¿Qué porcentaje de superficie corporal quemada es una indicación directa para intubación?","back":"Mayor al 40%."},{"front":"Mencione dos signos físicos de obstrucción de la vía aérea que indican intubación en el quemado.","back":"Estridor y uso de músculos accesorios."},{"front":"¿En qué caso se debe descartar específicamente una lesión de la vía aérea inferior?","back":"Inhalación de líquidos calientes o gases inflamables."},{"front":"¿Cuál es el criterio de hospitalización por SCQ en pacientes menores de 10 años con quemaduras de segundo grado?","back":"Más del 10% de superficie corporal."},{"front":"¿Cuál es el criterio de hospitalización por SCQ en adultos de 18 a 49 años con quemaduras de segundo grado?","back":"Más del 20% de superficie corporal."},{"front":"Mencione tres localizaciones anatómicas donde una quemadura grave siempre requiere hospitalización.","back":"Genitales, periné y articulaciones."},{"front":"¿Qué grado de quemadura se caracteriza típicamente por ser causada por el sol?","back":"Primer grado."},{"front":"¿Cuál es el nombre de la escala utilizada para clasificar los grados de las quemaduras?","back":"Escala de Smith."},{"front":"¿Hasta qué nivel anatómico de la piel llega una quemadura de segundo grado superficial?","back":"Dermis papilar."},{"front":"Las quemaduras de segundo grado superficial suelen ser causadas por escaldadura por _____.","back":"Salpicadura o derrame."},{"front":"¿Cómo se comporta el llenado capilar a la presión en una quemadura de segundo grado superficial?","back":"Blanquea con la presión."},{"front":"¿Hasta qué profundidad llega una quemadura de segundo grado profundo?","back":"Dermis reticular."},{"front":"¿Por qué las quemaduras de segundo grado profundo se consideran indoloras?","back":"Por la destrucción de las terminaciones nerviosas."},{"front":"¿Qué aspecto clínico caracteriza a una quemadura de tercer grado?","back":"Aspecto gris o negro carbonizado, seco y sin elasticidad."},{"front":"¿Qué regla se utiliza para calcular la superficie corporal quemada en pacientes mayores de 15 años?","back":"Regla de los 9 de Wallace."},{"front":"¿Qué esquema se prefiere para cuantificar la superficie corporal quemada en pediatría?","back":"Esquema de Lund and Browder."},{"front":"¿Cuál es la fórmula de Parkland para la reanimación hídrica?","back":"2-4 ml × superficie corporal quemada × kg de peso."},{"front":"¿Qué solución cristaloide es la de elección según la fórmula de Parkland?","back":"Ringer Lactato."},{"front":"¿Cómo se distribuye la administración de líquidos en las primeras 24 horas según Parkland?","back":"El 50% en las primeras 8 horas y el resto en las siguientes 16 horas."},{"front":"¿Cuál es el tiempo recomendado de irrigación con agua para quemaduras químicas?","back":"30 minutos."},{"front":"¿Cuál es la meta de uresis horaria en un paciente adulto quemado?","back":"0.5 ml/kg/hora."},{"front":"¿Cuál es la meta de uresis horaria en un paciente pediátrico quemado?","back":"1 ml/kg/hora."},{"front":"¿Por qué se prefieren los antibióticos tópicos sobre los sistémicos en quemaduras profundas?","back":"Los sistémicos tienen poca efectividad debido a la pérdida de vascularidad en la zona."},{"front":"¿Qué agente tópico es el estándar de oro mencionado para el cuidado de la quemadura?","back":"Sulfadiazina de plata."},{"front":"¿Qué medida de inmunización es obligatoria en todo paciente quemado?","back":"Inmunización contra el tétanos."},{"front":"¿Cuál es el puntaje en el Índice de Gravedad necesario para clasificar a un paciente como 'Gran Quemado'?","back":"Mayor a 70 puntos."},{"front":"¿A partir de qué porcentaje de SCQ de tipo AB o B se considera 'Gran Quemado' a un paciente de 40 años?","back":"Más del 20%."},{"front":"¿Qué tipo de quemadura eléctrica clasifica automáticamente al paciente como 'Gran Quemado'?","back":"Quemadura eléctrica por alta tensión."},{"front":"¿Qué nombre recibe también la quemadura por frío?","back":"Frostbite."},{"front":"¿Cuál es el mecanismo de daño tisular en el Frostbite?","back":"Formación de cristales de hielo intracelulares con oclusión microvascular."},{"front":"¿Qué grado de Frostbite presenta hiperemia y edema sin evidencia de necrosis cutánea?","back":"Primer grado."},{"front":"¿Qué hallazgo clínico distingue al Frostbite de tercer grado?","back":"Formación de vesículas hemorrágicas con necrosis de espesor completo."},{"front":"¿Qué estructuras están involucradas en el Frostbite de cuarto grado además de la piel?","back":"Músculo y hueso."},{"front":"¿Qué término describe la lesión por inmersión al frío sin congelación?","back":"Pie de trinchera."},{"front":"¿Cuál es el rango de temperatura ambiental que produce el pie de trinchera?","back":"1.6 °C a 10 °C (35 °F a 50 °F)."},{"front":"¿A qué temperatura se debe aplicar el agua para el recalentamiento en lesiones por frío?","back":"40 °C."},{"front":"¿Qué complicación electrolítica se debe vigilar durante el recalentamiento por riesgo de síndrome de reperfusión?","back":"Hipercalemia."},{"front":"¿Qué temperatura corporal central define el golpe de calor según los criterios de Bouchama?","back":"≥ 40 °C (104 °F)."},{"front":"Mencione dos manifestaciones de compromiso del SNC en el golpe de calor.","back":"Desorientación y convulsiones (o coma)."},{"front":"¿Cuál es la alteración eléctrica más frecuente en el electrocardiograma por hipertermia?","back":"Prolongación del intervalo QT."},{"front":"¿Qué tipo de golpe de calor ocurre típicamente en ancianos durante olas de calor sin actividad física?","back":"Golpe de calor clásico."},{"front":"¿Qué distingue al agotamiento por calor del golpe de calor respecto a la función mental?","back":"En el agotamiento por calor la función mental está esencialmente intacta."},{"front":"¿Cuál es el objetivo de temperatura central al iniciar el tratamiento del golpe de calor?","back":"Disminuir la temperatura a menos de 39 °C."},{"front":"¿Cuál es el método de enfriamiento preferido para atletas jóvenes con golpe de calor?","back":"Inmersión en agua helada."},{"front":"¿A qué se debe la rabdomiólisis en pacientes con quemaduras eléctricas?","back":"A que las lesiones internas son más graves de lo que aparentan superficialmente."},{"front":"En el agotamiento por calor, ¿cuál es la temperatura central habitual?","back":"Generalmente menor de 39 °C (102.2 °F)."}]},"26":{"num":26,"name":"ONCOLOGIA PARTE 1","cards":[{"front":"¿Cuál es la forma de presentación más frecuente del cáncer de esófago?","back":"Metastásica (40%)."},{"front":"¿Cuál es el sitio de metástasis más común en el cáncer de esófago?","back":"Pulmón."},{"front":"¿Qué estirpe histológica de cáncer de esófago predomina en Occidente?","back":"Adenocarcinoma."},{"front":"¿Cuál es la sobrevida promedio del cáncer de esófago sin tratamiento?","back":"3-4 meses."},{"front":"¿Qué factor de riesgo se asocia específicamente al carcinoma epidermoide de esófago?","back":"Alcoholismo."},{"front":"En el esófago de Barrett con displasia de alto grado, ¿cuál es el riesgo anual de progresión a cáncer?","back":"7%."},{"front":"¿En qué tercio del esófago se localiza habitualmente el adenocarcinoma?","back":"Tercio distal."},{"front":"¿En qué tercio del esófago se localiza habitualmente el carcinoma epidermoide?","back":"Tercio medio."},{"front":"¿Cuál es el síndrome paraneoplásico caracterizado por hipercalcemia en el cáncer de esófago?","back":"Elevación de PTH."},{"front":"¿Cuál es el Gold Standard diagnóstico para el cáncer de esófago?","back":"Esofagoscopia con toma de biopsia."},{"front":"¿Qué estudio de imagen se utiliza para valorar la extensión del tumor esofágico?","back":"Tomografía Computarizada (TAC)."},{"front":"¿Qué estudio es de elección para valorar la invasión de la pared y la enfermedad ganglionar en cáncer esofágico?","back":"Ultrasonido (USG) endoscópico."},{"front":"¿Cuál es el tratamiento de elección para el cáncer de esófago en estadios I y IIA?","back":"Cirugía."},{"front":"¿Qué abordaje quirúrgico se prefiere para tumores de esófago torácico mayores a 3 cm?","back":"Abordaje de McKeown."},{"front":"¿Qué abordaje quirúrgico se prefiere para tumores de esófago torácico menores a 3 cm?","back":"Abordaje transhiatal."},{"front":"¿Qué agente quimioterapéutico se utiliza específicamente para el adenocarcinoma de esófago?","back":"5-Fluorouracilo."},{"front":"¿Cuál es el segundo tumor gastrointestinal más frecuente en México?","back":"Cáncer gástrico."},{"front":"¿En qué porcentaje se encuentran las mutaciones de E-cadherina en el cáncer gástrico?","back":"75-85%."},{"front":"¿Qué grupo sanguíneo se asocia con un mayor riesgo de cáncer gástrico?","back":"Grupo A."},{"front":"¿Qué variante histológica de cáncer gástrico tiene el peor pronóstico?","back":"Difuso (Células en anillo de sello)."},{"front":"¿Cuál es el tumor benigno más frecuente del estómago?","back":"Leiomioma."},{"front":"Concepto: Ganglio de Virchow","back":"Definición: Linfadenopatía supraclavicular izquierda que sugiere metástasis de cáncer gástrico."},{"front":"¿Qué nombre recibe la metástasis ovárica del cáncer gástrico?","back":"Tumor de Krukenberg."},{"front":"¿Cuál es la localización del ganglio de la Hermana María José?","back":"Cicatriz umbilical."},{"front":"¿Cuál es el estudio de elección para el diagnóstico de cáncer gástrico?","back":"Endoscopia flexible con toma de al menos 3 biopsias."},{"front":"¿Cuál es el tratamiento de elección para el cáncer gástrico Etapa 0 o IA?","back":"Mucosectomía endoscópica."},{"front":"¿Qué escala se utiliza para decidir una gastrectomía profiláctica en familias de alto riesgo?","back":"Criterios de Ámsterdam."},{"front":"¿Cuál es el tratamiento quirúrgico para el cáncer gástrico distal resecable?","back":"Gastrectomía subtotal."},{"front":"¿Qué esquema de quimioterapia se indica para el cáncer gástrico irresecable?","back":"Fluorouracilo + Leucovorina."},{"front":"¿Cuál es la localización más frecuente del cáncer de páncreas?","back":"Cabeza del páncreas."},{"front":"¿Cuál es la estirpe histológica más común del cáncer de páncreas?","back":"Adenocarcinoma ductal (80-90%)."},{"front":"¿Qué gen presenta mutaciones en el 90% de los casos de cáncer pancreático?","back":"KRAS."},{"front":"¿Cuál es la tríada clínica frecuente en tumores de la cabeza del páncreas?","back":"Pérdida de peso, ictericia y dolor abdominal."},{"front":"¿Cuál es la mejor prueba de imagen inicial para el diagnóstico y etapificación del cáncer de páncreas?","back":"Tomografía Computarizada (TAC)."},{"front":"¿Qué estudio posee la mayor especificidad para el cáncer de páncreas?","back":"Ultrasonido endoscópico con aguja fina."},{"front":"¿Cuál es la técnica quirúrgica de elección para tumores en la cabeza del páncreas?","back":"Duodenopancreatectomía cefálica (Operación de Whipple)."},{"front":"¿Qué cirugía se realiza en tumores de cuerpo y cola del páncreas?","back":"Pancreatectomía distal o procedimiento de RAMPS."},{"front":"¿Qué fármacos se utilizan en la quimioterapia paliativa del cáncer pancreático?","back":"Gemcitabina y Erlotinib."},{"front":"¿Qué hallazgo anatómico define la irresecabilidad de un tumor de la cola del páncreas?","back":"Invasión a la columna o costillas."},{"front":"¿Cuál es la estirpe histológica que representa el 90% de los casos de cáncer de colon?","back":"Adenocarcinoma."},{"front":"¿Qué mutaciones genéticas son las más frecuentemente involucradas en el cáncer de colon?","back":"MLH1 y MSH2."},{"front":"¿Cómo se define el 'Riesgo Medio' para cáncer de colon?","back":"Presencia de pólipos adenomatosos o enfermedad inflamatoria de 10 años de evolución."},{"front":"¿Qué síntomas son característicos del cáncer de colon derecho?","back":"Hemorragia oculta y síndrome constitucional."},{"front":"¿Cuáles son los síntomas predominantes en el cáncer de colon izquierdo?","back":"Estreñimiento y rectorragia."},{"front":"¿Cuál es el sitio anatómico más común del cáncer colorrectal?","back":"Recto."},{"front":"¿Cuál es el sitio de metástasis más frecuente en el cáncer de colon?","back":"Hígado."},{"front":"¿Qué tipo de pólipo adenomatoso tiene mayor potencial de malignización?","back":"Pólipo velloso."},{"front":"¿Cuál es el estudio inicial de tamizaje para cáncer de colon en la población general a partir de los 50 años?","back":"Sangre oculta en heces (Guayaco)."},{"front":"¿Qué estudio es el Gold Standard para el diagnóstico de cáncer de colon?","back":"Colonoscopia con toma de biopsia."},{"front":"¿Qué imagen es característica en el colon por enema con doble contraste en presencia de cáncer?","back":"Imagen en corazón de manzana (manzana mordida)."},{"front":"¿A partir de qué estadio se indica quimioterapia adyuvante en el cáncer de colon?","back":"Estadio III."},{"front":"¿Cuál es el tipo de cáncer de hígado primario más frecuente?","back":"Hepatocarcinoma (90%)."},{"front":"¿Cuál es el principal factor de riesgo para desarrollar hepatocarcinoma?","back":"Cirrosis hepática (VHB, VHC o alcoholismo)."},{"front":"¿Qué factores dietéticos se consideran protectores para el hepatocarcinoma?","back":"Consumo de carne blanca y Omega 3."},{"front":"¿Cada cuánto tiempo se debe realizar el tamizaje con USG en pacientes cirróticos?","back":"Cada 6 meses."},{"front":"¿Qué fenómeno vascular es diagnóstico de hepatocarcinoma en la TAC?","back":"Fenómeno de Wash Out."},{"front":"¿Qué nivel de Alfa-fetoproteína se considera diagnóstico para hepatocarcinoma?","back":"Niveles mayores de 400 ng/mL."},{"front":"¿Qué sistema de estadificación se utiliza para el tratamiento del hepatocarcinoma?","back":"Barcelona Clinic Liver Cancer (BCLC)."},{"front":"¿Cuál es el tratamiento de elección para el Estadio B del BCLC?","back":"Quimioembolización."},{"front":"¿Qué fármaco sistémico es de elección para el Estadio C del BCLC?","back":"Sorafenib."},{"front":"¿Qué tratamiento se indica para un hepatocarcinoma Child-Pugh A con nódulo único < 2 cm?","back":"Resección hepática parcial."},{"front":"¿Qué es el Síndrome de Lynch?","back":"Trastorno autosómico dominante con predisposición a cáncer colorrectal no polipósico."},{"front":"¿Qué localización intestinal predomina en los tumores del Síndrome de Lynch?","back":"Colon derecho."},{"front":"¿Cuál es el cáncer extra-colónico más frecuente en mujeres con Síndrome de Lynch?","back":"Cáncer de endometrio."},{"front":"¿A partir de qué edad debe iniciar el tamizaje con colonoscopia en pacientes con Síndrome de Lynch?","back":"18 años."},{"front":"¿Cuál es el tratamiento quirúrgico profiláctico de elección en el Síndrome de Lynch?","back":"Colectomía total con anastomosis ileorrectal."},{"front":"¿Qué frecuencia recomendada de la biopsia uterina de tamizaje en mujeres con Lynch?","back":"Anual, a partir de los 30 años."},{"front":"¿Qué mutaciones definen el diagnóstico definitivo del Síndrome de Lynch?","back":"MSH2, MLH1, MSH6 y PMS2."},{"front":"¿En qué tercio del esófago es más común la presentación de disfagia por carcinoma epidermoide?","back":"Tercio medio."},{"front":"¿Qué complicación quirúrgica del esófago presenta una mortalidad del 22%?","back":"Abscesos o fístulas post-esofaguectomía."},{"front":"¿Qué utilidad tiene la clasificación de Ámsterdam II y Bethesda?","back":"Identificar familias con alta sospecha de Síndrome de Lynch."},{"front":"¿Cuál es el estudio más sensible para la detección de sangre oculta en heces?","back":"Fecaltest."},{"front":"¿Qué conducta se sigue ante una dispepsia no complicada que no mejora tras 6 meses en mayores de 55 años?","back":"Endoscopia flexible con toma de biopsia."},{"front":"En cáncer gástrico, el estadio IV recibe tratamiento tipo _____.","back":"Paliativo."},{"front":"¿Qué mutación se asocia con el 74% de los cánceres de páncreas?","back":"P53."},{"front":"¿Bajo qué condiciones se indica una derivación biliodigestiva en cáncer de páncreas?","back":"Pacientes con ictericia irresecable y expectativa de vida > 6 meses."},{"front":"¿Cuál es la frecuencia de la colonoscopia para tamizaje en pacientes de Riesgo Alto?","back":"Cada 2 años."},{"front":"¿Cuál es el tumor primario de hígado con menor tasa de curación?","back":"Hepatocarcinoma."},{"front":"¿Qué porcentaje de los pacientes con cáncer de páncreas presentan enfermedad avanzada al diagnóstico?","back":"70%."},{"front":"¿Qué hallazgo ecográfico en el hígado sugiere hepatocarcinoma en un cirrótico?","back":"Nódulo hipoecoico con neovascularización."},{"front":"¿Qué síntoma constitucional es casi universal en el cáncer de cuerpo y cola de páncreas?","back":"Pérdida de peso (100%)."},{"front":"En el cáncer de esófago cervical, ¿a qué distancia del cricofaríngeo se decide entre tratamiento QT/RT o QT preoperatoria?","back":"5 cm."},{"front":"¿Qué síndrome se caracteriza por pólipos hamartomatosos y riesgo de cáncer gástrico?","back":"Síndrome de Peutz-Jeghers."},{"front":"¿Cuál es el tratamiento para el Estadio D del BCLC en hepatocarcinoma?","back":"Tratamiento paliativo."},{"front":"En pacientes geriátricos, ¿cuál es la causa más frecuente de sangrado de tubo digestivo bajo?","back":"Cáncer de colon."}]},"27":{"num":27,"name":"ONCOLOGIA PARTE 2","cards":[{"front":"¿Cuál es el tumor maligno más frecuente del aparato genital masculino?","back":"Cáncer de próstata."},{"front":"Tipo histológico que constituye el 95% de los carcinomas prostáticos:","back":"Adenocarcinoma."},{"front":"¿En qué zona de la próstata se originan la mayoría de los adenocarcinomas?","back":"Zona periférica."},{"front":"¿Cuál es la edad promedio al momento del diagnóstico de cáncer de próstata?","back":"66 años."},{"front":"Menciona tres factores de riesgo principales para el desarrollo de cáncer de próstata:","back":"Raza afroamericana, familiar de primer grado con diagnóstico antes de los 60 años y obesidad."},{"front":"Mutaciones genéticas asociadas con un mayor riesgo de cáncer de próstata:","back":"BRCA 1 y BRCA 2."},{"front":"Factor protector que reduce el riesgo de cáncer de próstata según la frecuencia mensual:","back":"Eyacular más de 21 veces al mes."},{"front":"¿Por qué el cáncer de próstata suele ser asintomático en etapas iniciales?","back":"Debido a que se presenta predominantemente en la zona periférica."},{"front":"Porcentaje de pacientes que presentan metástasis al momento del diagnóstico de cáncer de próstata:","back":"25%."},{"front":"Sitio anatómico que representa el principal lugar de metástasis ósea en cáncer de próstata:","back":"Región lumbar."},{"front":"Edad recomendada para realizar la primera determinación basal de Antígeno Prostático Específico (APE):","back":"Entre los 40 y 50 años."},{"front":"Conducta a seguir ante un APE > 4.0 ng/ml:","back":"Solicitar APE libre y realizar un nuevo control en un año."},{"front":"Indicación diagnóstica inmediata ante un APE > 10 ng/ml:","back":"Realizar biopsia de próstata."},{"front":"Porcentaje de APE libre que indica la necesidad de realizar una biopsia prostática:","back":"Menor al 15%."},{"front":"¿A qué grupo de pacientes se les debe realizar tacto rectal independientemente de su edad?","back":"A aquellos con sintomatología urinaria baja."},{"front":"Características físicas del carcinoma prostático al tacto rectal:","back":"Duro, nodular e irregular."},{"front":"Estudio de imagen inicial para el abordaje de cáncer de próstata:","back":"Ultrasonido (USG) rectal."},{"front":"Hallazgo ultrasonográfico típico del cáncer de próstata:","back":"Nódulos hipoecogénicos."},{"front":"Marcador bioquímico que indica extensión extraprostática en el cáncer de próstata:","back":"Fosfatasa ácida prostática."},{"front":"Criterios para solicitar una gammagrafía ósea en la estadificación del cáncer de próstata:","back":"Escala de Gleason mayor a 8 o un APE mayor a 20 ng/ml."},{"front":"¿Cuál es el estándar de oro para el diagnóstico definitivo del cáncer de próstata?","back":"Biopsia (tomando 12 muestras)."},{"front":"Ejemplos de fármacos agonistas de GnRH o LHRH utilizados en el tratamiento:","back":"Leuprolida, goserelina y triptorelina."},{"front":"Criterios para clasificar el cáncer de próstata como de Bajo Riesgo:","back":"Estadio T1-T2a, APE < 10 ng/ml y Gleason ≤ 6."},{"front":"Criterios para clasificar el cáncer de próstata como de Riesgo Intermedio:","back":"Estadio T2b, APE de 10 a 20 ng/ml y Gleason de 7."},{"front":"Criterios para clasificar el cáncer de próstata como de Alto Riesgo:","back":"Estadio T2c-T3, APE > 20 ng/ml y Gleason de 8 a 10."},{"front":"Opciones de tratamiento para pacientes con cáncer de próstata de bajo riesgo:","back":"Vigilancia activa, prostatectomía radical, radioterapia externa o braquiterapia."},{"front":"Tratamiento quirúrgico indicado para el cáncer de próstata de alto riesgo:","back":"Prostatectomía radical con linfadenectomía pélvica extendida."},{"front":"Porcentaje que representa el cáncer renal dentro de todos los tumores malignos:","back":"Del 2% al 3%."},{"front":"¿En qué porcentaje de los casos se detecta el cáncer renal de forma incidental?","back":"50%."},{"front":"Sitio más común de diseminación metastásica del cáncer renal:","back":"Pulmón."},{"front":"Menciona dos enfermedades hereditarias asociadas al cáncer renal:","back":"Enfermedad de Von Hippel-Lindau y Síndrome de Birt-Hogg-Dubé."},{"front":"Cromosoma cuya mutación se asocia frecuentemente con el cáncer renal:","back":"Cromosoma 3."},{"front":"Componentes de la tríada clásica del cáncer renal:","back":"Dolor en fosa renal, hematuria macroscópica y masa abdominal palpable."},{"front":"¿Qué porcentaje de pacientes con cáncer renal presenta la tríada clásica?","back":"Del 6% al 10%."},{"front":"Síndrome paraneoplásico más frecuente en el cáncer renal:","back":"Síndrome anémico (88%)."},{"front":"¿En qué consiste el Síndrome de Stauffer en el contexto del cáncer renal?","back":"Disfunción hepática no metastásica asociada a carcinoma de células renales."},{"front":"Tipo histológico de cáncer renal más frecuente y su porcentaje de aparición:","back":"Cáncer de células claras (80% de los carcinomas de células renales)."},{"front":"Origen anatómico preciso del cáncer de células claras renales:","back":"Túbulos proximales."},{"front":"Característica distintiva del cáncer papilar renal:","back":"Es frecuentemente bilateral y multifocal."},{"front":"Tumor renal de carácter benigno mencionado en la clasificación histológica:","back":"Oncocitoma."},{"front":"En cáncer renal, un tumor confinado al riñón menor a 7 cm se clasifica como estadio:","back":"Estadio I (T1)."},{"front":"Tratamiento quirúrgico de elección para el cáncer renal Estadio I (T1):","back":"Nefrectomía parcial."},{"front":"Un tumor renal mayor a 7 cm confinado al riñón se clasifica como estadio:","back":"Estadio II (T2)."},{"front":"Tratamiento indicado para cáncer renal en estadios II (T2) y III (T3):","back":"Nefrectomía radical (abierta o laparoscópica)."},{"front":"Definición del estadio IV (T4) en cáncer renal:","back":"Invasión más allá de la fascia renal con afección de la glándula suprarrenal."},{"front":"Tratamiento quirúrgico indicado en el estadio IV del cáncer renal:","back":"Nefrectomía citorreductora."},{"front":"¿Por qué el estadio IV del cáncer renal tiene una supervivencia de solo el 10%?","back":"Debido a la resistencia a la quimioterapia."},{"front":"Estudio de elección para el diagnóstico y estadificación del cáncer renal:","back":"TAC abdominopélvica simple y contrastada."},{"front":"Indicación específica para realizar una biopsia renal en masas pequeñas:","back":"Masas renales menores a 3 cm."},{"front":"Utilidad de la Resonancia Magnética (RM) en el diagnóstico de cáncer renal:","back":"Determinar metástasis a vena cava o en pacientes con alergia al medio de contraste."},{"front":"Ejemplos de terapias dirigidas (blanco molecular) para el cáncer de células claras:","back":"Sunitinib, pazopanib y bevacizumab."},{"front":"¿Cuál es la única opción de tratamiento curativo para el cáncer renal?","back":"Tratamiento quirúrgico (nefrectomía parcial o total)."},{"front":"Factor de riesgo para tumores testiculares que aumenta el riesgo de 2 a 8 veces:","back":"Criptorquidia."},{"front":"Síndrome genético asociado a un mayor riesgo de tumores testiculares:","back":"Síndrome de Klinefelter."},{"front":"¿Cuál es la tasa de curación general de los tumores testiculares?","back":"90%."},{"front":"Tipo de tumor testicular más frecuente (95% de los casos):","back":"Tumores de células germinales."},{"front":"Menciona los tres tipos de seminomas:","back":"Típico, anaplásico y espermatocítico."},{"front":"¿Qué síntoma clínico suele acompañar a los tumores no seminomatosos?","back":"Ginecomastia."},{"front":"Hallazgo clínico considerado patognomónico de tumor de testículo:","back":"Masa testicular sólida sin dolor."},{"front":"Periodicidad y edad de inicio recomendada para la autoexploración testicular:","back":"Una vez al mes a partir de los 15 años."},{"front":"Marcadores tumorales esenciales para el abordaje de tumores testiculares:","back":"α-fetoproteína (AFP), β-HCG y deshidrogenasa láctica (DHL)."},{"front":"Estudio de imagen inicial ante la sospecha de un tumor testicular:","back":"USG Doppler testicular."},{"front":"Estudio utilizado para evaluar la extensión tumoral en cáncer de testículo:","back":"TAC toracoabdominal."},{"front":"¿Qué tumores testiculares germinales elevan la β-HCG?","back":"Coriocarcinoma y seminoma."},{"front":"¿Qué tumores testiculares germinales elevan la α-fetoproteína?","back":"Carcinoma embrionario y tumor del seno endodérmico."},{"front":"Definición del estadio II en tumores testiculares:","back":"Enfermedad extendida a los ganglios linfáticos retroperitoneales."},{"front":"¿Por qué la orquiectomía debe realizarse vía inguinal y no transescrotal?","back":"Porque el abordaje transescrotal tiene mayor riesgo de recurrencia."},{"front":"Esquema de quimioterapia estándar utilizado en cáncer de testículo:","back":"Bleomicina, etopósido y platino."},{"front":"Tratamiento para un tumor testicular Estadio I con lesión > 4 cm:","back":"Orquiectomía más inicio de radioterapia y quimioterapia."},{"front":"¿Qué indica el estadio III en el cáncer de testículo?","back":"Afectación de ganglios supradiafragmáticos u otros órganos."},{"front":"Tumor de células germinales no seminomatoso más frecuente en niños:","back":"Tumor de Yolk Sac (carcinoma embrionario)."},{"front":"Ejemplos de tumores estromales del testículo:","back":"Tumores de células de Leydig y tumores de células de Sertoli."},{"front":"Definición del estadio I en tumores testiculares:","back":"Enfermedad limitada al testículo y al cordón espermático."},{"front":"¿Cuál es la principal complicación clínica de las metástasis óseas por cáncer de próstata?","back":"Compresión medular."},{"front":"En el contexto de cáncer renal, ¿qué estudio identifica quistes simples inicialmente?","back":"Ultrasonido (USG) renal."}]},"28":{"num":28,"name":"INTRODUCCION OFTALMO Y PATOLOGIA DE ANEXOS","cards":[{"front":"¿Cuál es la causa más común de pérdida visual reversible según el material?","back":"Las ametropías (defectos de refracción)."},{"front":"Defecto de refracción caracterizado por la dificultad para ver claramente los objetos distantes:","back":"Miopía."},{"front":"Defecto de refracción caracterizado por la dificultad para ver claramente los objetos cercanos:","back":"Hipermetropía."},{"front":"¿Qué estructura ocular presenta una curvatura anormal en el astigmatismo?","back":"La córnea."},{"front":"¿Cuál es el factor de riesgo principal relacionado con el peso al nacer para el desarrollo de ametropías?","back":"Peso menor a 1.500 gramos."},{"front":"En la etapa preescolar, ¿cuál es la prevalencia del astigmatismo?","back":"28%."},{"front":"¿Cuál es el valor de agudeza visual que define la ceguera según la OMS?","back":"20/400."},{"front":"¿Cuál es la agudeza visual esperada en un recién nacido?","back":"3/200."},{"front":"¿Cuál es la agudeza visual esperada a los 3 meses de edad?","back":"20/200."},{"front":"¿A qué edad se espera que un niño alcance una agudeza visual de 20/100?","back":"Al año de edad."},{"front":"¿Cuál es el rango de agudeza visual normal para un niño de 3 a 4 años?","back":"20/50."},{"front":"¿Cuál es la agudeza visual esperada entre los 5 y 6 años de edad?","back":"20/20."},{"front":"En menores de un año, ¿cómo debe evaluarse la agudeza visual?","back":"Mediante el reflejo de fijación y seguimiento con oclusión alternante."},{"front":"¿Cómo es el tamaño del globo ocular en un paciente con miopía?","back":"Más largo de lo normal."},{"front":"¿Cómo es el tamaño del globo ocular en un paciente con hipermetropía?","back":"Más corto de lo normal."},{"front":"¿Cuál es el defecto de refracción más común?","back":"La miopía."},{"front":"¿Cuál es la indicación para el uso de lentes en el primer año de vida en un paciente miope?","back":"Miopía mayor a -5 dioptrías."},{"front":"¿Qué complicación retiniana tiene un riesgo elevado en pacientes con miopía moderada o grave?","back":"Desprendimiento de retina."},{"front":"Concepto: Astenopia","back":"Definición: Fatiga ocular, ardor y dolor causados por el esfuerzo acomodativo, común en la hipermetropía."},{"front":"¿Qué tipo de estrabismo se asocia frecuentemente a la hipermetropía para compensar el defecto?","back":"Estrabismo convergente (acomodativo)."},{"front":"¿Qué patología de los párpados puede coexistir con el astigmatismo debido a la compensación constante?","back":"Blefaritis."},{"front":"¿Cuál es el método de diagnóstico de primera elección para evaluar la agudeza visual?","back":"Cartilla de Snellen."},{"front":"¿A qué distancia (en pies y metros) se debe colocar la cartilla de Snellen?","back":"A 20 pies (6 metros)."},{"front":"¿Qué instrumento se utiliza cuando el paciente no lee las letras pequeñas para determinar si la causa es refractiva?","back":"Aparato (agujero) estenopeico."},{"front":"¿Cuántas dioptrías definen una ametropía severa?","back":"Más de 6 dioptrías."},{"front":"¿Qué tipo de lentes se utilizan para corregir la miopía?","back":"Lentes cóncavos, negativos o divergentes."},{"front":"¿Qué tipo de lentes se utilizan para corregir la hipermetropía?","back":"Lentes convexos, positivos o convergentes."},{"front":"¿Qué tipo de lentes son específicos para el tratamiento del astigmatismo?","back":"Lentes tóricos."},{"front":"¿Hasta cuántas dioptrías puede corregir la cirugía LASIK en un paciente miope?","back":"Hasta 7 dioptrías."},{"front":"¿Cuál es la complicación más frecuente de la cirugía LASIK?","back":"Ojo seco."},{"front":"Definición de Blefaritis:","back":"Inflamación crónica del borde palpebral, de origen multifactorial."},{"front":"¿Cuál es el factor de riesgo dermatológico más frecuente asociado a la blefaritis?","back":"Acné rosácea."},{"front":"¿Qué glándulas se afectan en la blefaritis anterior?","back":"Glándulas de Zeiss y de Moll."},{"front":"¿Qué glándulas se afectan en la blefaritis posterior?","back":"Glándulas de Meibomio."},{"front":"¿Cuál es el agente etiológico más común en la blefaritis anterior estafilocócica?","back":"Staphylococcus aureus."},{"front":"¿Qué hallazgo clínico es característico de la blefaritis anterior estafilocócica en las pestañas?","back":"Cilindros de fibrina en la base de la pestaña."},{"front":"¿Cuál es el pilar fundamental del tratamiento de la blefaritis y por cuánto tiempo mínimo?","back":"Higiene palpebral por 6 semanas."},{"front":"¿Cuál es el tratamiento antibiótico tópico de elección para la blefaritis?","back":"Sulfacetamida tópica."},{"front":"¿Qué antibióticos sistémicos se pueden emplear en la blefaritis posterior?","back":"Tetraciclina o Doxiciclina."},{"front":"Definición de Chalazión:","back":"Granuloma inflamatorio crónico de una glándula de Meibomio por obstrucción."},{"front":"¿Cuál es la característica principal que diferencia al chalazión del orzuelo en cuanto al dolor?","back":"El chalazión suele ser una lesión no dolorosa (estéril)."},{"front":"Definición de Orzuelo:","back":"Inflamación aguda, usualmente infecciosa, de las glándulas de los párpados."},{"front":"¿Qué agentes bacterianos causan el orzuelo con mayor frecuencia?","back":"S. aureus y S. epidermidis."},{"front":"¿Cuál es el tratamiento farmacológico tópico para un orzuelo?","back":"Cloranfenicol o Eritromicina tópica."},{"front":"¿En qué patología se debe sospechar ante un chalazión recidivante?","back":"Carcinoma de glándulas sebáceas."},{"front":"¿Cuál es el tumor maligno de párpado más frecuente?","back":"Carcinoma basocelular."},{"front":"¿Qué cambios produce el humo del cigarro en la película lagrimal?","back":"Cambios en la capa lipídica por peroxidación lipídica."},{"front":"En el síndrome de ojo seco moderado (Estadio II), ¿cuál es el tiempo de ruptura lagrimal esperado?","back":"≤ 10 segundos."},{"front":"¿Cuál es el tratamiento para el Estadio IV (severo incapacitante) del síndrome de ojo seco?","back":"AINEs sistémicos, acetilcisteína, goggles o cirugía."},{"front":"¿Qué hallazgo diferencia la celulitis orbitaria de la preseptal?","back":"La celulitis orbitaria presenta alteración de la motilidad ocular, proptosis y disminución de la agudeza visual."},{"front":"¿Cuál es el estudio de imagen confirmatorio para la celulitis orbitaria?","back":"Tomografía Axial Computarizada (TAC)."},{"front":"¿Cuál es el esquema antibiótico intravenoso para la celulitis orbitaria?","back":"Vancomicina + Ceftriaxona."},{"front":"¿Cuál es la causa de la dacriocistitis en el recién nacido?","back":"Imperforación del conducto lacrimonasal."},{"front":"¿Cuál es el tratamiento inicial para la dacriocistitis del recién nacido?","back":"Masajes en el saco lagrimal (el 90% resuelve espontáneamente)."},{"front":"¿Cuál es el síntoma principal de la dacriocistitis crónica en el adulto?","back":"Epífora (lagrimeo constante)."},{"front":"Definición de Dacrioadenitis:","back":"Inflamación de la glándula lagrimal principal."},{"front":"En el trauma ocular por químicos, ¿cuál es la medida inmediata de primer auxilio?","back":"Lavar con solución fisiológica durante 10 a 20 minutos."},{"front":"¿Qué indica el hallazgo de una 'córnea blanca' tras un trauma ocular?","back":"Quemadura por cáusticos."},{"front":"Concepto: Hiposfagma","back":"Definición: Hemorragia subconjuntival súbita e indolora, de color rojo brillante y bordes mal definidos."},{"front":"¿Cuánto tiempo tarda normalmente en remitir un hiposfagma sin tratamiento?","back":"De 2 a 3 semanas (período máximo de 10-38 días)."},{"front":"¿Qué es la presbicia y a qué edad suele iniciar?","back":"Disminución de la elasticidad del cristalino que impide enfocar de cerca; inicia a partir de los 40 años."},{"front":"¿Qué vitamina está deficiente en un paciente con ceguera nocturna y manchas de Bitot (xeroftalmia)?","back":"Vitamina A."},{"front":"¿Cuál es la causa número uno de ceguera irreversible a cualquier edad?","back":"Glaucoma."},{"front":"¿Cuál es la causa número uno de ceguera en personas menores de 65 años?","back":"Retinopatía diabética."},{"front":"¿Cuál es el tratamiento de elección para lesiones por chalazión menores de 4 mm?","back":"Triamcinolona tópica e higiene palpebral."},{"front":"En dacriocistitis aguda supurada del adulto, ¿qué antibiótico se recomienda?","back":"Dicloxacilina."},{"front":"¿Qué estudio de imagen es la elección para evaluar un trauma ocular y descartar cuerpos extraños o fracturas?","back":"Tomografía Axial Computarizada (TAC)."},{"front":"Según la norma de primer nivel, ¿qué no se debe aplicar nunca ante un trauma ocular antes de derivar?","back":"Medicamentos tópicos."},{"front":"La queratitis actínica es una lesión ocular causada típicamente por:","back":"Rayos UV (ej. soldadores sin protección)."},{"front":"El sangrado en la cámara anterior del ojo tras un trauma cerrado se denomina:","back":"Hipema."}]},"29":{"num":29,"name":"CAMARA ANTERIOR","cards":[{"front":"¿Qué agentes etiológicos causan la fiebre adeno-faringo-conjuntival?","back":"Los adenovirus serotipos 3, 4 y 7."},{"front":"¿Qué serotipos de adenovirus están asociados con la queratoconjuntivitis viral?","back":"Los serotipos del 8 al 19."},{"front":"¿Cuál es el tipo de secreción característica en una conjuntivitis de origen viral?","back":"Secreción acuosa o hialina."},{"front":"¿Cuál es el manejo inicial recomendado para la conjuntivitis viral?","back":"Fomentos fríos e hipromelosa."},{"front":"¿Qué fármacos están contraindicados de forma general en el tratamiento de la conjuntivitis viral?","back":"Antibióticos y esteroides."},{"front":"¿Cuáles son los cuatro agentes bacterianos más frecuentes en la conjuntivitis infecciosa?","back":"S. aureus, S. epidermidis, S. pneumoniae y H. influenzae."},{"front":"¿Qué tipo de secreción define a la conjuntivitis bacteriana?","back":"Secreción mucopurulenta."},{"front":"¿Cuál es el síntoma característico al despertar en pacientes con conjuntivitis bacteriana?","back":"Formación de lagañas que dificulta despegar los párpados."},{"front":"¿Cuál es el tratamiento de primera elección para la conjuntivitis bacteriana y su posología?","back":"Cloranfenicol cada 6 horas durante 6 días."},{"front":"¿Qué tipo de hipersensibilidad inmunológica media la conjuntivitis alérgica?","back":"Hipersensibilidad tipo I mediada por IgE."},{"front":"En la conjuntivitis alérgica, ¿qué fármaco se utiliza como estabilizador de mastocitos para el manejo crónico?","back":"Cromoglicato de sodio."},{"front":"¿Cuál es la característica clínica distintiva de la conjuntivitis vernal en la conjuntiva tarsal?","back":"Papilas con aspecto de empedrado."},{"front":"¿Qué agente etiológico y qué serotipos causan el tracoma?","back":"Chlamydia trachomatis serotipos A, B y C."},{"front":"¿Cuál es la principal causa de ceguera infecciosa a nivel mundial?","back":"El tracoma."},{"front":"¿En qué estado de la República Mexicana el tracoma se mantiene como una enfermedad endémica?","back":"Chiapas."},{"front":"¿Cuál es el vector biológico asociado a la transmisión del tracoma?","back":"La mosca Musca sorbens."},{"front":"¿Qué porcentaje de prevalencia de tracoma activo en niños justifica el tratamiento masivo a toda la comunidad?","back":"Una prevalencia mayor al 10%."},{"front":"¿Cuál es el tratamiento de elección para un adulto con tracoma?","back":"Azitromicina en dosis única de 1 g."},{"front":"¿Cuál es el tratamiento de elección para el tracoma en mujeres embarazadas o menores de 6 meses?","back":"Ungüento de tetraciclina al 1% dos veces al día por 6 semanas."},{"front":"¿Qué componentes integran la estrategia SAFE de la OMS para el control del tracoma?","back":"Cirugía para triquiasis, antibióticos, limpieza facial y mejora del ambiente."},{"front":"Según la clasificación de la OMS, ¿qué define al Tracoma Folicular (TF)?","back":"Presencia de al menos cinco folículos de un tamaño mínimo de 0,5 mm."},{"front":"En la clasificación del tracoma, ¿cuándo se considera que existe Tracoma Intenso (TI)?","back":"Cuando el engrosamiento inflamatorio obscurece más de la mitad de los vasos conjuntivales profundos."},{"front":"¿Qué hallazgo clínico define al Tracoma con Triquiasis (TT)?","back":"Al menos una pestaña hace contacto con la córnea."},{"front":"¿Cuál es el tiempo de incapacidad recomendado para un paciente con tracoma que presenta úlcera corneal?","back":"Dos semanas."},{"front":"¿Qué es una pingüécula?","back":"Un crecimiento amarillento y elevado en la conjuntiva que no invade la córnea."},{"front":"¿En qué lado de la conjuntiva se localiza usualmente la pingüécula?","back":"En el lado nasal."},{"front":"¿Qué proceso degenerativo subyace a la formación de la pingüécula?","back":"Degeneración de fibras elásticas subconjuntivales con depósito de sustancia hialina amorfa."},{"front":"¿Qué característica morfológica distingue al pterigión de la pingüécula?","back":"El pterigión tiene forma triangular e invade la córnea."},{"front":"¿Cuál es el principal factor desencadenante ambiental para la aparición del pterigión?","back":"Exposición a radiación ultravioleta (UV) de 240 a 400 nm."},{"front":"¿Qué nombre reciben las pequeñas opacidades en la membrana de Bowman que indican actividad en un pterigión?","back":"Islas de Fuchs."},{"front":"En caso de actividad inflamatoria en el pterigión, ¿cuál es el esquema inicial de prednisolona?","back":"Una gota cada 6-8 horas durante una semana."},{"front":"¿Qué fármaco coadyuvante se utiliza durante la resección quirúrgica del pterigión para evitar recurrencias?","back":"Mitomicina."},{"front":"¿Cuántos días de incapacidad se otorgan tras el tratamiento quirúrgico de un pterigión?","back":"28 días."},{"front":"¿Cuáles son los agentes bacterianos más frecuentemente involucrados en la queratitis infecciosa?","back":"S. aureus, S. pneumoniae y Pseudomonas."},{"front":"¿Qué hallazgos clínicos componen la presentación clásica de la queratitis bacteriana?","back":"Hipopión e hiperemia periquerática."},{"front":"¿Cuál es el tratamiento farmacológico de elección para la queratitis bacteriana?","back":"Colirios de vancomicina y ceftazidima."},{"front":"¿Qué porcentaje de los casos de queratitis herpética son causados por el virus herpes simple tipo 1 (VHS-1)?","back":"El 95% de los casos."},{"front":"¿Cuál es el hallazgo patognomónico de la queratitis herpética al utilizar tinción de fluoresceína?","back":"Úlcera dendrítica o arborescente."},{"front":"¿Qué fármaco tópico es el pilar del tratamiento en la queratitis herpética?","back":"Aciclovir tópico."},{"front":"¿Qué grupo poblacional se ve afectado con mayor frecuencia por la epiescleritis?","back":"Mujeres entre 30 y 40 años de edad."},{"front":"¿Cómo se comporta el ojo rojo de la epiescleritis ante la instilación de fenilefrina?","back":"El ojo rojo aclara con la fenilefrina."},{"front":"¿Cuál es la diferencia clínica en la agudeza visual entre la epiescleritis y la escleritis?","back":"La epiescleritis no suele afectar la visión, mientras que la escleritis disminuye la agudeza visual."},{"front":"¿Qué signo ecográfico es característico de la escleritis posterior?","back":"El signo de la T."},{"front":"¿Cuál es el síntoma principal que distingue a la abrasión corneal del trauma conjuntival?","back":"Dolor intenso que se agrava con el movimiento del párpado."},{"front":"¿Cómo se realiza el diagnóstico confirmatorio de una abrasión corneal?","back":"Tiñendo con fluoresceína y observando con luz azul de cobalto."},{"front":"¿Cuál es el manejo para una lesión corneal menor a 10 mm?","back":"Lente de contacto blando y ciprofloxacino en gotas 4 veces al día."},{"front":"¿Qué tratamiento antibiótico tópico en ungüento se recomienda para abrasiones corneales?","back":"Cloranfenicol ungüento cada 6 horas por 5 días."},{"front":"¿Qué hallazgos sugieren una ruptura escleral tras un trauma ocular?","back":"Hipotonía ocular, hifema, hemorragia vítrea y limitación de movimientos oculares."},{"front":"¿Qué caracteriza fisiopatológicamente al queratocono?","back":"Incremento progresivo de la curvatura corneal y adelgazamiento apical no inflamatorio."},{"front":"¿En qué consiste el signo de Munson?","back":"Deformación del párpado inferior en forma de V cuando el paciente mira hacia abajo."},{"front":"¿Qué procedimiento quirúrgico refractivo se asocia con la aparición iatrogénica de queratasia (queratocono)?","back":"Cirugía LASIK."},{"front":"¿Cuál es el estudio estándar para la estadificación y diagnóstico confirmatorio del queratocono?","back":"Topografía corneal de elevación."},{"front":"¿Cuál es el objetivo del tratamiento con cross-linking (entrecruzamiento de colágena) en el queratocono?","back":"Prevenir la progresión de la enfermedad, aunque no mejora la visión."},{"front":"¿Qué tipo de lentes se indican cuando las gafas aéreas ya no corrigen la visión en el queratocono?","back":"Lentes de contacto rígidos permeables al gas."},{"front":"¿Cuál es el tratamiento definitivo para el queratocono en casos severos con compromiso visual importante?","back":"Trasplante corneal."},{"front":"¿Cuál es la principal causa de oftalmoplejía internuclear mencionada en los puntos clave?","back":"Esclerosis múltiple."}]},"3":{"num":3,"name":"PATOLOGIA GASTRICA","cards":[{"front":"¿Cómo se define el síndrome de Mallory-Weiss?","back":"Desgarros longitudinales en el esófago distal y estómago proximal por aumento de presión intraabdominal."},{"front":"¿Cuál es la etiología más frecuente del síndrome de Mallory-Weiss en hombres?","back":"Alcoholismo (40-80%)."},{"front":"¿Cuál es la causa principal del síndrome de Mallory-Weiss en mujeres?","back":"Hiperemesis gravídica."},{"front":"¿En qué ventana de tiempo está indicada la endoscopia en el síndrome de Mallory-Weiss?","back":"Entre >6 horas y <24 horas del evento."},{"front":"¿Qué porcentaje de casos de Mallory-Weiss presentan remisión espontánea del sangrado?","back":"80%."},{"front":"¿Cuál es el fármaco con la tasa más efectiva de cicatrización en el síndrome de Mallory-Weiss?","back":"Esomeprazol."},{"front":"¿Qué enzima produce H. pylori para sobrevivir al ambiente ácido del estómago?","back":"Ureasa."},{"front":"¿Cuál es la principal proteína patógena de H. pylori?","back":"CagA."},{"front":"¿Cuál es el estudio inicial (screening) para el diagnóstico de H. pylori?","back":"Test de urea marcada con C13."},{"front":"¿Cuánto tiempo antes del test de urea se deben suspender los antibióticos?","back":"4 semanas."},{"front":"¿Cuánto tiempo antes del test de urea se deben suspender los inhibidores de bomba de protones (IBP)?","back":"2 semanas."},{"front":"¿Cuáles son los tres fármacos que componen el tratamiento de primera elección para la erradicación de H. pylori?","back":"Amoxicilina, Claritromicina y Omeprazol."},{"front":"¿Cuál es la duración recomendada del tratamiento de erradicación para H. pylori?","back":"14 días."},{"front":"¿Qué fármacos se añaden al esquema de segunda elección (cuádruple) para H. pylori además de un IBP?","back":"Tetraciclina, Metronidazol y Bismuto."},{"front":"¿Cuándo se debe realizar la prueba de aliento confirmatoria tras el tratamiento de erradicación de H. pylori?","back":"4 semanas después de finalizar el esquema."},{"front":"¿Qué profundidad anatómica debe alcanzar una lesión para considerarse úlcera péptica?","back":"Debe penetrar más allá de la muscular de la mucosa (>5 mm)."},{"front":"¿Cuál es la principal causa de Úlcera Péptica?","back":"Infección por H. pylori."},{"front":"¿Cuál es la principal causa de Sangrado de Tubo Digestivo Alto (STDA)?","back":"Consumo crónico de AINES."},{"front":"¿Cuál es el principal factor de riesgo para la refractariedad de una úlcera péptica?","back":"Tabaquismo."},{"front":"¿En qué pacientes con úlcera está indicada la endoscopia para descartar cáncer gástrico?","back":"Mayores de 55 años o con síntomas de alarma."},{"front":"¿Cuál es el síntoma más frecuente de la úlcera péptica?","back":"Dolor epigástrico ardoroso o quemante."},{"front":"¿Qué efecto tienen los alimentos sobre el dolor en la úlcera duodenal?","back":"El dolor se alivia con la ingesta de alimentos."},{"front":"¿Qué efecto tienen los alimentos sobre el dolor en la úlcera gástrica?","back":"El dolor aumenta al momento de comer."},{"front":"¿Cuál es la asociación porcentual de la úlcera duodenal con H. pylori?","back":"95%."},{"front":"¿Dónde se localizan el 95% de las úlceras duodenales?","back":"En la primera porción del duodeno."},{"front":"¿Cuál es el Gold Standard para el diagnóstico de H. pylori?","back":"Cultivo."},{"front":"¿Cuál es el tiempo de tratamiento con IBP recomendado para una úlcera duodenal tras la erradicación?","back":"8 semanas."},{"front":"¿Cuál es el sitio de localización más frecuente de las úlceras gástricas?","back":"Curvadura menor."},{"front":"¿Qué tipo de úlceras gástricas presentan mayor frecuencia de sangrado?","back":"Úlceras prepilóricas."},{"front":"¿Cuál es el tiempo de tratamiento con IBP recomendado para una úlcera gástrica?","back":"12 semanas."},{"front":"¿Cuál es la principal causa de muerte en pacientes con úlcera péptica complicada?","back":"Sangrado."},{"front":"\"En el manejo inicial de úlcera complicada","back":"¿cuál es la dosis de carga (bolo) de Omeprazol recomendada?\""},{"front":"Hallazgo endoscópico Forrest Ia:","back":"Hemorragia activa en chorro."},{"front":"Hallazgo endoscópico Forrest Ib:","back":"Hemorragia activa en babeo."},{"front":"Hallazgo endoscópico Forrest IIa:","back":"Vaso visible."},{"front":"Hallazgo endoscópico Forrest IIb:","back":"Coágulo adherido."},{"front":"Hallazgo endoscópico Forrest III:","back":"Base de fibrina (ausencia de signos de sangrado)."},{"front":"¿Qué escala se utiliza para predecir el riesgo de muerte y necesidad de hospitalización en úlcera péptica?","back":"Escala de Rockall."},{"front":"¿Qué escala indica la necesidad de una intervención endoscópica temprana?","back":"Escala de Blatchford."},{"front":"¿Cuál es la zona más frecuente de perforación en la úlcera péptica?","back":"Región prepilórica."},{"front":"¿Qué puntaje se utiliza para predecir la mortalidad perioperatoria en úlcera perforada?","back":"Puntaje de Boey."},{"front":"¿Cuál es el signo radiológico característico de una úlcera perforada en la RX de tórax?","back":"Signo de alas de gaviota (aire subdiafragmático)."},{"front":"¿Cuál es el tratamiento quirúrgico de elección para la úlcera perforada?","back":"Parche de epiplón (Parche de Graham)."},{"front":"¿Qué porcentaje de los días debe presentar síntomas un paciente para diagnosticar dispepsia funcional?","back":"25% de los días en las últimas 4 semanas."},{"front":"¿Qué criterios diagnósticos se utilizan para la dispepsia funcional?","back":"Criterios de Roma III."},{"front":"\"Tipo de gastritis caracterizada por atrofia en cuerpo y fundus","back":"asociada a anemia perniciosa:\""},{"front":"¿Cuál es el tratamiento único para la gastritis tipo A?","back":"Administración intramuscular de Vitamina B12."},{"front":"¿En qué parte del estómago se localiza inicialmente la gastritis por H. pylori en personas jóvenes?","back":"Antro."},{"front":"Úlcera gástrica asociada a patología del sistema nervioso central o aumento de presión intracraneal:","back":"Úlcera de Cushing."},{"front":"Úlcera gástrica asociada a pacientes con grandes quemaduras:","back":"Úlcera de Curling."},{"front":"¿Cuál es la causa patogénica de la enfermedad de Menétrier?","back":"Sobreexpresión de TGF-α que causa exceso de EGFR e hiperplasia foveolar."},{"front":"¿Cuál es el hallazgo histológico característico en la enfermedad de Menétrier?","back":"Hiperplasia foveolar con atrofia glandular."},{"front":"¿Cuál es el tratamiento farmacológico de elección para la enfermedad de Menétrier?","back":"Cetuximab (inhibidor de EGFR)."},{"front":"¿Dónde se localizan el 90% de los tumores en el Síndrome de Zollinger-Ellison?","back":"Triángulo de Passaro."},{"front":"¿Con qué neoplasia endocrina múltiple se asocia el Síndrome de Zollinger-Ellison en el 25% de los casos?","back":"MEN1."},{"front":"¿Cuál es la prueba diagnóstica de elección para confirmar el Síndrome de Zollinger-Ellison?","back":"Prueba de secretina IV."},{"front":"¿Cuál es el valor de gastrina sérica en ayunas considerado positivo para Zollinger-Ellison?","back":">1000 ng/L."},{"front":"¿Cuál es el tratamiento quirúrgico definitivo para el Síndrome de Zollinger-Ellison?","back":"Procedimiento de Whipple."},{"front":"Término: Dispepsia Funcional","back":"Definición: Dolor o malestar en epigastrio no explicado por causas orgánicas, con síntomas el 25% del tiempo en el último mes."},{"front":"El consumo a largo plazo de IBP se asocia con el desarrollo de _____.","back":"Osteoporosis."}]},"30":{"num":30,"name":"CAMARA POSTERIOR","cards":[{"front":"¿Qué es la catarata?","back":"La opacificación parcial o total del cristalino o su cápsula que disminuye la agudeza visual."},{"front":"¿Cuál es la principal causa de ceguera en el mundo según el material?","back":"La catarata, representando entre el 41% - 68% de los casos."},{"front":"¿Cuál es el factor de riesgo más frecuente para el desarrollo de cataratas?","back":"El envejecimiento (catarata senil nuclear)."},{"front":"¿Cuál es la principal causa metabólica de formación de cataratas?","back":"La diabetes mellitus."},{"front":"¿A partir de qué edad se recomienda la detección de cataratas en pacientes sin factores de riesgo?","back":"A partir de los 50 años."},{"front":"En la exploración de un paciente con catarata, el Gold Standard muestra una opacidad en el _____.","back":"Reflejo rojo"},{"front":"¿Cuál es el tratamiento quirúrgico de elección para la catarata?","back":"Facoemulsificación."},{"front":"¿Cuál es la complicación más frecuente después de una cirugía de catarata?","back":"Queratitis bullosa."},{"front":"¿Cuál es la complicación más grave de la cirugía de catarata?","back":"Endoftalmitis."},{"front":"¿Qué estudio se utiliza para valorar el cálculo del lente intraocular (LIO)?","back":"Ultrasonido (USG)."},{"front":"¿Cuál es la complicación más grave de la anestesia local retrobulbar en cirugía ocular?","back":"Perforación ocular."},{"front":"¿Qué define al glaucoma de ángulo abierto?","back":"Neuropatía óptica con cambios estructurales de la papila y déficit funcional en campos visuales."},{"front":"¿Cuál es el factor de riesgo más importante para el glaucoma?","back":"El incremento de la presión intraocular (PIO)."},{"front":"¿Qué cifra de presión intraocular (PIO) se considera indicativa de glaucoma?","back":">21 mmHg."},{"front":"Factores de riesgo para glaucoma de ángulo abierto: Edad >40 años, sexo femenino, diabetes, migraña y _____.","back":"Miopía"},{"front":"¿Cuál es el tratamiento de sostén de primera elección para el glaucoma de ángulo abierto?","back":"Análogos de prostaglandinas (como latanoprost)."},{"front":"¿Qué procedimiento quirúrgico se utiliza para disminuir la presión intraocular en glaucoma?","back":"Trabeculectomía."},{"front":"¿Qué hallazgo anatómico caracteriza al glaucoma de ángulo cerrado?","back":"Contacto iridotrabecular de al menos 180°."},{"front":"¿Qué error refractivo se asocia frecuentemente al glaucoma de ángulo cerrado?","back":"Hipermetropía."},{"front":"¿Cuál es la medida inicial para romper el bloqueo angular en un ataque agudo de glaucoma?","back":"Gonioscopía dinámica."},{"front":"¿Cuál es el fármaco de primera elección en el tratamiento farmacológico del ataque agudo de glaucoma?","back":"Acetazolamida (inhibidor de la anhidrasa carbónica)."},{"front":"¿En qué caso se indica el uso de manitol como tratamiento adjunto en glaucoma?","back":"Cuando la presión intraocular es mayor a 50 mmHg."},{"front":"¿Cuál es la medida profiláctica recomendada para el ojo contralateral en glaucoma de ángulo cerrado?","back":"Iridotomía con láser."},{"front":"¿Con qué marcador genético se asocia frecuentemente la uveítis anterior?","back":"HLA-B27."},{"front":"¿Qué tríada clínica compone el síndrome ciliar en la uveítis anterior?","back":"Dolor, fotofobia y blefaroespasmo."},{"front":"Fenómeno de Tyndall","back":"Presencia de células flotando en la cámara anterior del ojo, típico de la uveítis anterior."},{"front":"¿Cuál es el tratamiento de la uveítis anterior?","back":"Esteroides en gotas y midriáticos."},{"front":"¿Cuál es la causa infecciosa más común asociada a la uveítis posterior?","back":"Toxoplasmosis."},{"front":"¿Qué hallazgo en el examen de fondo de ojo es característico de la uveítis posterior por toxoplasma?","back":"Visión en faro de niebla con miodesopsias."},{"front":"¿Cuál es el esquema de tratamiento para la uveítis por toxoplasma?","back":"Sulfadiazina + Pirimetamina + esteroides."},{"front":"¿Cuál es el motivo más frecuente de pérdida de visión en la retinopatía diabética?","back":"El edema macular."},{"front":"¿Qué comorbilidad sistémica es un fuerte predictor de la presencia de retinopatía diabética?","back":"La enfermedad renal."},{"front":"¿Cuándo debe realizarse el primer tamizaje de fondo de ojo en un paciente con DM1?","back":"3 a 5 años después del diagnóstico."},{"front":"¿Cuándo debe realizarse el primer tamizaje de fondo de ojo en un paciente con DM2?","back":"Al momento del diagnóstico."},{"front":"¿Cuál es la meta de HbA1c para reducir el riesgo de retinopatía diabética?","back":"Menor a 6.5%."},{"front":"¿Cuál es el signo oftalmológico más temprano y típico de la retinopatía diabética?","back":"Los microaneurismas."},{"front":"¿En qué consiste el tratamiento de la retinopatía diabética proliferativa?","back":"Panfotocoagulación con láser e inhibidores del factor de crecimiento vascular endotelial (VEGF)."},{"front":"Retinopatía diabética no proliferativa leve","back":"Presencia única de microaneurismas en el fondo de ojo."},{"front":"¿Qué define a la retinopatía diabética como 'proliferativa'?","back":"La presencia de neovasos (en la papila o extrapapilares)."},{"front":"¿Cuál es el hallazgo característico del Grado I en la clasificación de Keith-Wagener?","back":"Arterias en hilos de cobre con signos de cruce mínimos."},{"front":"¿Qué hallazgo define al Grado IV de la retinopatía hipertensiva (Keith-Wagener)?","back":"Edema de papila."},{"front":"¿Qué representan los 'hilos de plata' en la retinopatía hipertensiva?","back":"Arteriolas blanquecinas por engrosamiento extremo de la íntima."},{"front":"Signos de Gunn","back":"Signos de cruce arteriovenoso donde la arteria comprime a la vénula, indicativo de aterosclerosis."},{"front":"¿Qué es el desprendimiento de retina?","back":"La separación de la retina neurosensorial del epitelio pigmentario."},{"front":"¿Cuál es el tipo de desprendimiento de retina más frecuente?","back":"Regmatógeno (causado por un agujero o desgarro)."},{"front":"¿Qué causa el desprendimiento de retina de tipo traccional?","back":"La formación de tractos fibrosos en el vítreo que jalan la retina."},{"front":"¿Qué tipo de desprendimiento de retina se asocia a hipertensión arterial o neoplasias?","back":"Desprendimiento exudativo."},{"front":"¿Cuál es el tratamiento quirúrgico para el desprendimiento de retina regmatógeno?","back":"Fotocoagulación con láser y colocación de banda de silicona."},{"front":"¿Qué fármaco se utiliza para tratar el desprendimiento de retina exudativo por inflamación?","back":"Prednisona (corticoesteroide oral) por 3 meses."},{"front":"¿Cuál es el tumor intraocular primario más común en la infancia?","back":"Retinoblastoma."},{"front":"¿Cuál es el gen mutado asociado al retinoblastoma?","back":"RB1."},{"front":"¿Cuál es el signo clínico cardinal del retinoblastoma?","back":"Leucocoria."},{"front":"¿Cuál es el síntoma inicial más frecuente de retinoblastoma en menores de 1 año?","back":"Estrabismo."},{"front":"¿Cuál es el estudio inicial para el diagnóstico de retinoblastoma?","back":"Ultrasonido (USG) ocular."},{"front":"¿Cuál es el hallazgo patognomónico del retinoblastoma en el ultrasonido?","back":"Masa intraocular con calcificaciones y sombra acústica."},{"front":"¿Cuál es el Gold Standard para evaluar la extensión del retinoblastoma a las órbitas?","back":"Resonancia Magnética (RM)."},{"front":"¿Qué tumor secundario tiene un riesgo del 30% de desarrollarse en pacientes con retinoblastoma?","back":"Osteosarcoma."},{"front":"¿Qué patrón de crecimiento del retinoblastoma se dirige desde las capas internas hacia el vítreo?","back":"Endofítico."},{"front":"Edema de Berlin","back":"Hallazgo oftalmológico que indica conmoción retiniana tras un traumatismo."},{"front":"¿Cuál es la meta de reducción de PIO en un paciente con glaucoma avanzado?","back":"Disminución del 30-40% (menos de 14 mmHg)."},{"front":"¿A qué se debe el glaucoma congénito?","back":"A la falta de desarrollo de la malla trabecular."},{"front":"¿Qué alteración visual causan típicamente los craneofaringiomas?","back":"Hemianopsia bitemporal heterónima."},{"front":"¿En qué pacientes se debe administrar anestesia general para cirugía ocular?","back":"Pacientes pediátricos, sordomudos o con trastornos psiquiátricos."},{"front":"¿Cuál es la primera causa de disminución de la agudeza visual en pacientes con retinopatía diabética proliferativa?","back":"Hemorragia vítrea."},{"front":"Ambliopía","back":"Padecimiento por falta de estímulo visual temprano secundario a estrabismo o cataratas."},{"front":"¿Qué seguimiento se le da a un paciente con PIO elevada pero sin daño al nervio óptico?","back":"Evaluación cada 18 meses."},{"front":"¿Cuándo debe realizarse la primera evaluación de fondo de ojo en una paciente diabética embarazada?","back":"Al inicio del embarazo."},{"front":"¿Cuál es el síntoma principal del desprendimiento de retina?","back":"Pérdida rápida de agudeza visual sin dolor."}]},"31":{"num":31,"name":"HIPOACUSIA Y VERTIGO","cards":[{"front":"¿Cuál es la principal causa de vértigo según el material de estudio?","back":"VPPB (Vértigo Posicional Paroxístico Benigno)."},{"front":"¿Cuál es la duración típica de las crisis de vértigo en el VPPB?","back":"Menores de 60 segundos."},{"front":"En el VPPB, el nistagmo se caracteriza por presentar una latencia corta y _____ con la repetición de la maniobra.","back":"fatiga"},{"front":"¿Qué depósitos minerales se desprenden de las máculas y entran al canal semicircular en el VPPB?","back":"Carbonato de calcio."},{"front":"¿Cuál es el canal semicircular afectado con mayor frecuencia (60-90%) en el VPPB?","back":"Canal semicircular posterior."},{"front":"Nombre de la maniobra diagnóstica considerada el estándar de oro para el VPPB.","back":"Maniobra de Dix-Hallpike."},{"front":"En el VPPB, si se sospecha afectación del canal horizontal, ¿qué prueba se debe realizar?","back":"Prueba de McClure."},{"front":"¿Qué maniobra de reposicionamiento es el tratamiento de elección para el VPPB del canal posterior?","back":"Maniobra de Epley."},{"front":"¿Qué maniobra se utiliza específicamente para el tratamiento del VPPB del canal horizontal?","back":"Maniobra de Barbecue."},{"front":"¿Cuál es el fármaco de elección a dosis de 40 a 120 mg diarios para la crisis aguda de VPPB?","back":"Cinarizina."},{"front":"Se recomienda el uso de _____ blando durante las primeras 48 horas tras el tratamiento del VPPB.","back":"collarín"},{"front":"¿Cuál es la segunda causa más común de vértigo periférico?","back":"Neuronitis vestibular."},{"front":"¿Qué estructura anatómica se inflama específicamente en la neuronitis vestibular?","back":"Rama vestibular del VIII par craneal."},{"front":"¿Cuál es la duración característica de los episodios de vértigo en la neuronitis vestibular?","back":"De horas a días."},{"front":"¿Con qué virus se ha relacionado frecuentemente la neuronitis vestibular a nivel ganglionar?","back":"Herpes virus tipo 1."},{"front":"¿Cuántos episodios de neuronitis vestibular suele presentar un paciente a lo largo de su vida?","back":"Solo uno (la mayor parte de las veces)."},{"front":"Estudio de imagen con contraste utilizado para confirmar el diagnóstico de neuronitis vestibular.","back":"Resonancia Magnética con gadolinio."},{"front":"¿Cuál es la tercera causa más frecuente de vértigo según el material?","back":"Enfermedad de Ménière."},{"front":"¿Qué nombre recibe el exceso de endolinfa (hidrops) de causa idiopática?","back":"Enfermedad de Ménière."},{"front":"¿Qué nombre recibe el hidrops endolinfático con causa identificable, como sífilis o trauma?","back":"Síndrome de Ménière."},{"front":"¿Cuál es la duración mínima de un episodio típico de vértigo para el diagnóstico de Ménière?","back":"20 minutos."},{"front":"Fenómeno en el cual la audición del paciente mejora justo al iniciar la crisis de vértigo en Ménière.","back":"Fenómeno de Lermoyez."},{"front":"Nombre de las crisis súbitas en Ménière donde el paciente puede caer al suelo sin perder la conciencia.","back":"Crisis de Tumarkin."},{"front":"En las pruebas vestibulares de Ménière, ¿hacia qué lado se lateraliza típicamente la prueba de Romberg?","back":"Hacia el lado sano."},{"front":"¿Cuál es el manejo dietético inicial recomendado para pacientes con enfermedad de Ménière?","back":"Dieta hiposódica (1-2 gramos)."},{"front":"Tratamiento farmacológico de primera elección para la enfermedad de Ménière.","back":"Gentamicina intratimpánica."},{"front":"Cirugía indicada en Ménière cuando el paciente tiene vértigo intratable y un nivel auditivo no útil.","back":"Laberintectomía."},{"front":"Definición de hipoacusia súbita: pérdida auditiva neurosensorial mayor a _____ en al menos tres frecuencias consecutivas.","back":"30 dB"},{"front":"¿En qué periodo de tiempo máximo debe instaurarse la pérdida auditiva para considerarse hipoacusia súbita?","back":"72 horas."},{"front":"¿Qué síntoma acompaña al vértigo y la hipoacusia en el 100% de los casos de hipoacusia súbita?","back":"Plenitud ótica y acúfenos."},{"front":"Fármaco y vía de administración de elección para el tratamiento de la hipoacusia súbita idiopática.","back":"Metilprednisolona intratimpánica."},{"front":"Dosis de Prednisona oral recomendada si el paciente con hipoacusia súbita no acepta la vía intratimpánica.","back":"60 mg/día."},{"front":"¿Cuál es la posición de reposo recomendada para pacientes con hipoacusia súbita?","back":"Semisentado entre 35° y 45°."},{"front":"¿Qué enfermedad se define como una remodelación ósea desordenada que causa fijación de los huesecillos?","back":"Otoesclerosis."},{"front":"¿Cuál es el principal factor de riesgo nutricional asociado a la otoesclerosis?","back":"Deficiencia de fluoruro de sodio."},{"front":"¿Cuál es el dato pivote epidemiológico clásico para la otoesclerosis en exámenes médicos?","back":"Mujer embarazada."},{"front":"¿En qué fase de la otoesclerosis se observa el Signo de Schwartze?","back":"Otoespongiosis."},{"front":"Componente de la Tríada de Holgrem que describe la piel del conducto auditivo externo.","back":"Sequedad con ausencia de cerumen."},{"front":"Nombre del hallazgo patognomónico en la audiometría de un paciente con otoesclerosis.","back":"Nicho de Carhart."},{"front":"¿Cuál es el tratamiento quirúrgico de elección en la otoesclerosis?","back":"Estapedectomía."},{"front":"La prueba de Rinné compara la conducción ósea contra la conducción _____.","back":"aérea"},{"front":"¿Cómo se define un Rinné Negativo?","back":"La conducción ósea es mejor que la aérea."},{"front":"¿Qué tipo de hipoacusia se asocia con un resultado de Rinné Negativo?","back":"Hipoacusia conductiva."},{"front":"En una hipoacusia neurosensorial, ¿hacia qué lado se lateraliza el sonido en la prueba de Weber?","back":"Hacia el lado sano."},{"front":"En una hipoacusia conductiva, ¿hacia qué lado se lateraliza el sonido en la prueba de Weber?","back":"Hacia el lado enfermo."},{"front":"¿Cuál es el manejo inicial de la mayoría de las perforaciones timpánicas traumáticas directas?","back":"Observación (suelen autolimitarse)."},{"front":"¿Qué nombre recibe el cerumen impactado en el conducto auditivo externo?","back":"Otocerosis."},{"front":"¿Cuál es el método de tratamiento recomendado para el cerumen impactado?","back":"Irrigación con aparato eléctrico."},{"front":"¿En qué situación está contraindicado el uso de cerumenolíticos como el peróxido de hidrógeno?","back":"Sospecha de perforación timpánica."},{"front":"Pérdida auditiva bilateral progresiva común en pacientes geriátricos con Rinné positivo bilateral.","back":"Presbiacusia."},{"front":"¿Cuál es el tratamiento principal para la presbiacusia?","back":"Prótesis auditiva."},{"front":"¿Qué maniobra terapéutica se utiliza para el VPPB del canal semicircular superior?","back":"Maniobra de Epley inversa."},{"front":"En la neuronitis vestibular, el nistagmo suele _____ con la fijación visual.","back":"inhibirse"},{"front":"Tratamiento quirúrgico para Ménière cuando se desea conservar la audición residual.","back":"Neurectomía vestibular."},{"front":"¿Qué porcentaje de pacientes con hipoacusia súbita presenta recuperación instantánea?","back":"65%"},{"front":"¿Cuál es la edad media de inicio de la otoesclerosis?","back":"15-45 años."},{"front":"Fármaco utilizado para evitar la progresión de la otoesclerosis en fases iniciales.","back":"Fluoruro de sodio."},{"front":"En la hipoacusia neurosensorial, el Rinné es de tipo _____.","back":"Positivo (aunque con pérdida auditiva)"},{"front":"¿Qué hallazgo se espera en una prueba de Weber normal?","back":"Weber central (el sonido se percibe igual en ambos oídos)."}]},"32":{"num":32,"name":"OTORRINO","cards":[{"front":"¿Qué tipo de reacción de hipersensibilidad caracteriza a la rinitis alérgica?","back":"Hipersensibilidad tipo I (mediada por IgE)."},{"front":"Porcentaje de pacientes con rinitis alérgica que desarrollan síntomas antes de los 20 años.","back":"80%."},{"front":"Factor de riesgo para rinitis alérgica relacionado con los niveles de IgE antes de los 6 años.","back":"IgE > 100 UI/ml."},{"front":"Hallazgo clásico en la exploración física de los cornetes en un paciente con rinitis alérgica.","back":"Inflamación azulada de los cornetes."},{"front":"Concepto: Línea alérgica","back":"Surco transversal en el puente nasal debido al frotamiento crónico de la nariz (saludo alérgico)."},{"front":"¿Qué son los pliegues de Dennie-Morgan?","back":"Líneas o pliegues cutáneos acentuados debajo del párpado inferior, asociados a rinitis alérgica."},{"front":"Estudio de primera elección para el diagnóstico de rinitis alérgica.","back":"Citología nasal."},{"front":"Criterio para establecer el diagnóstico definitivo de rinitis alérgica.","back":"Presencia de IgE específica contra alérgenos."},{"front":"¿Cuál es la tríada del tratamiento empírico inicial para la rinitis alérgica?","back":"Evitar alérgeno + antihistamínico (oral o nasal) + esteroide nasal."},{"front":"Tratamiento de elección para pacientes con rinitis alérgica de tipo persistente.","back":"Esteroides nasales (como furoato de mometasona)."},{"front":"Indicación específica para el uso de antagonistas de receptores de leucotrienos (Montelukast) en rinitis alérgica.","back":"Solo en casos que no responden a la primera línea de tratamiento."},{"front":"Conducta ante un paciente con azelastina crónica y síntomas persistentes moderados.","back":"Suspender el antihistamínico e iniciar esteroide nasal."},{"front":"Definición temporal de la rinosinusitis aguda.","back":"Proceso infeccioso e inflamatorio que persiste por más de 10 días y menos de 3 meses."},{"front":"¿Cuáles son los agentes bacterianos más frecuentes en la rinosinusitis aguda?","back":"S. pneumoniae, H. influenzae y M. catarrhalis."},{"front":"Senos paranasales más frecuentemente afectados por rinosinusitis en la población pediátrica.","back":"Maxilares y etmoidales."},{"front":"Mencione los síntomas mayores diagnósticos de rinosinusitis.","back":"Rinorrea purulenta, obstrucción nasal, dolor facial, hiposmia/anosmia y fiebre."},{"front":"Mencione los síntomas menores de la rinosinusitis aguda.","back":"Tos, halitosis y cefalea."},{"front":"Considerado el signo cardinal de la rinosinusitis bacteriana.","back":"Drenaje nasal o descarga purulenta."},{"front":"Estándar de oro para el diagnóstico de rinosinusitis.","back":"Cultivo de secreción de los senos paranasales."},{"front":"¿Qué proyección radiográfica es de mayor utilidad ante duda diagnóstica en rinosinusitis?","back":"Radiografía de Waters."},{"front":"Tratamiento antibiótico de primera elección para rinosinusitis bacteriana.","back":"Amoxicilina o Amoxicilina con Ácido Clavulánico."},{"front":"Dosis de amoxicilina/clavulanato recomendada en rinosinusitis aguda severa.","back":"80-90 mg/kg/día."},{"front":"Alternativa de tratamiento antibiótico en pacientes con rinosinusitis y alergia a la penicilina.","back":"Claritromicina, azitromicina o eritromicina."},{"front":"Indicación para el tratamiento quirúrgico (aspiración transnasal) en rinosinusitis.","back":"Fracaso al tratamiento de segunda línea, inmunocompromiso o complicaciones."},{"front":"Complicaciones graves de la rinosinusitis bacteriana aguda.","back":"Celulitis orbital, abscesos (subperióstico/orbital), infección intracraneal y trombosis del seno cavernoso."},{"front":"¿Cuál es el sitio de origen del 90% de los sangrados en la epistaxis anterior?","back":"Plexo de Kiesselbach (Área de Little)."},{"front":"Arteria responsable del sangrado en la epistaxis posterior.","back":"Arteria esfenopalatina."},{"front":"Tratamiento de primera elección ante un cuadro de epistaxis aguda.","back":"Presión nasal directa + vasoconstrictor local (ej. oximetazolina)."},{"front":"Opciones de segunda elección para el control de la epistaxis si la presión directa falla.","back":"Cauterización eléctrica o química con nitrato de plata."},{"front":"Método de taponamiento nasal utilizado en epistaxis graves cuando otros métodos fallan.","back":"Sonda Foley."},{"front":"Tratamiento quirúrgico ideal para la epistaxis posterior.","back":"Ligadura de la arteria esfenopalatina."},{"front":"Patología hematológica que debe descartarse siempre en primer lugar ante epistaxis recurrentes.","back":"Púrpura Trombocitopénica Idiopática."},{"front":"Definición de Parálisis de Bell.","back":"Disfunción del VII par craneal (facial) de etiología desconocida."},{"front":"Factores de riesgo asociados al desarrollo de Parálisis de Bell.","back":"Diabetes mellitus, hipertensión, embarazo, obesidad y preeclampsia."},{"front":"Fenómeno de Bell: Descripción.","back":"Movimiento ascendente del ojo al intentar cerrar los párpados."},{"front":"Componentes del Síndrome de Ramsay-Hunt.","back":"Parálisis facial + hipoacusia + vértigo (causado por Herpes Zóster)."},{"front":"¿Qué escala se utiliza para estadificar la severidad de la parálisis facial?","back":"Escala de House-Brackmann."},{"front":"Tratamiento farmacológico de primera elección en la Parálisis de Bell.","back":"Prednisona oral (1 mg/kg/día por 5 días)."},{"front":"Ventana de tiempo ideal para iniciar el tratamiento con esteroides en la Parálisis de Bell.","back":"Primeras 48-72 horas del cuadro clínico."},{"front":"Medidas generales esenciales para la protección ocular en la parálisis facial.","back":"Oclusión de ojo (parche), lágrimas artificiales y terapia física."},{"front":"¿Cuál es la prueba diagnóstica de elección para el Síndrome de Apnea Obstructiva del Sueño (SAOS)?","back":"Polisomnografía (PSG)."},{"front":"Predictor anatómico de riesgo para SAOS basado en la circunferencia del cuello.","back":">38 cm en mujeres y >40 cm en hombres."},{"front":"Mencione tres síntomas diurnos del SAOS en adultos.","back":"Somnolencia excesiva, cefalea matutina y fatiga crónica."},{"front":"Síntoma de SAOS en niños que involucra la pérdida de control de esfínteres durante la noche.","back":"Enuresis secundaria."},{"front":"Tratamiento de elección para SAOS en adultos sin alteraciones maxilofaciales.","back":"CPAP (Presión Positiva Continua en la Vía Aérea)."},{"front":"Alternativa de tratamiento en adultos que no toleran el CPAP.","back":"Dispositivos de avance mandibular."},{"front":"Tratamiento quirúrgico indicado en niños con SAOS e hipertrofia amigdalina.","back":"Amigdalectomía (Tratamiento quirúrgico de la vía aérea)."},{"front":"Sitio anatómico de la laringe donde se origina el cáncer con mayor frecuencia (59%).","back":"Glotis."},{"front":"Principal tipo histológico del cáncer de laringe.","back":"Carcinoma epidermoide."},{"front":"Principal factor de riesgo modificable para prevenir el cáncer de laringe.","back":"Tabaquismo."},{"front":"Síntoma temprano característico del cáncer de glotis.","back":"Disfonía."},{"front":"Estudio diagnóstico inmediato ante la presencia de una masa cervical o adenopatía sospechosa.","back":"Biopsia por Aspiración con Aguja Fina (BAAF)."},{"front":"Utilidad de la exploración endoscópica en el protocolo de estudio de cáncer de laringe.","back":"Identificar tumores primarios sincrónicos."},{"front":"Etiología más frecuente de la papilomatosis laríngea.","back":"Virus del Papiloma Humano (VPH) tipos 6 y 11."},{"front":"Mencione la tríada clásica de la papilomatosis laríngea.","back":"Disfonía, estridor y dificultad respiratoria."},{"front":"Grupo de edad más afectado por la papilomatosis laríngea juvenil.","back":"Niños menores de 5 años."},{"front":"Estudio diagnóstico inicial ante sospecha de papilomatosis laríngea.","back":"Nasofibrolaringoscopía flexible."},{"front":"Tratamientos adyuvantes farmacológicos utilizados en papilomatosis laríngea.","back":"Cidofovir y Bevacizumab."},{"front":"Método quirúrgico de elección para la resección de papilomas laríngeos.","back":"Láser CO₂ o microdebridación."}]},"33":{"num":33,"name":"TYO PARTE 1","cards":[{"front":"¿Cómo se define una fractura cerrada según la lesión tisular?","back":"Es aquella en la que no existe comunicación entre el foco de la fractura y el exterior."},{"front":"¿Qué caracteriza a una fractura abierta?","back":"La piel ha sufrido daño y el tejido óseo queda expuesto al exterior."},{"front":"En la clasificación por extensión, ¿qué estructuras se ven afectadas en una fractura completa?","back":"El trazo afecta tanto al hueso como al periostio."},{"front":"¿Qué define a una fractura incompleta?","back":"Es aquella en la que el trazo no afecta a todo el espesor del hueso."},{"front":"Fracturas de _____ energía: Requieren una cinemática alta para transmitir la fuerza al hueso y lesionarlo.","back":"alta"},{"front":"¿Qué tipos de fracturas se consideran de baja energía?","back":"Fracturas por estrés, fatiga, patológicas o por insuficiencia."},{"front":"¿Cuál es la diferencia entre un mecanismo de lesión directo e indirecto?","back":"El directo ocurre en el lugar del impacto y el indirecto se produce a distancia del mismo."},{"front":"¿En qué tres regiones anatómicas se localizan las fracturas según el texto?","back":"Epífisis (zona articular), metáfisis y diáfisis."},{"front":"Según la estabilidad, ¿qué tipo de trazo suelen tener las fracturas estables?","back":"Suelen ser transversas u oblicuas menores de 45°."},{"front":"¿Por qué las fracturas oblicuas mayores de 45° o espiroideas se consideran inestables?","back":"Porque tienden a desplazarse incluso después de haber sido reducidas."},{"front":"Mencione los 4 pilares necesarios para una restauración ósea adecuada.","back":"Células osteogénicas, osteoconductor, factores de crecimiento y estabilidad mecánica."},{"front":"¿Qué condición quirúrgica permite una consolidación directa o primaria?","back":"Reducción anatómica de fragmentos con ausencia completa de movimiento (ej. placa de osteosíntesis)."},{"front":"¿Cuál es una característica histológica ausente en la consolidación directa?","back":"No presenta tejido cartilaginoso ni formación de callo de fractura."},{"front":"¿Bajo qué condiciones de estabilidad ocurre la consolidación indirecta?","back":"Ocurre en fracturas no estabilizadas rígidamente donde hay movilidad interfragmentaria."},{"front":"¿Qué dispositivos quirúrgicos favorecen típicamente la consolidación indirecta?","back":"Clavos intramedulares o fijadores externos."},{"front":"En la fase inicial de consolidación, ¿cuál es la función del hematoma?","back":"Actúa como fuente de moléculas de señalización para iniciar la cascada de reparación."},{"front":"Mencione dos citocinas (interleucinas) que participan en la formación del hematoma de fractura.","back":"IL-1 e IL-6."},{"front":"Además de las interleucinas, ¿qué otros factores de crecimiento participan en la fase de impacto?","back":"TGF-β y PDGF."},{"front":"¿Qué proceso osteoclástico ocurre durante la fase de tejido de granulación?","back":"Reabsorción osteoclástica de los márgenes de la fractura."},{"front":"¿Qué tipo de proliferación celular inicia en la fase de tejido de granulación?","back":"Proliferación fibroblástica y condroblástica."},{"front":"¿Qué factor físico determina la diferenciación tisular durante la formación del callo primario?","back":"La tensión de oxígeno."},{"front":"¿En qué parte de la fractura se forma el callo duro?","back":"En la periferia y el periostio (zona con mayor tensión de oxígeno)."},{"front":"¿Qué tipo de colágeno predomina en el callo óseo duro?","back":"Colágeno tipo 1 (T1)."},{"front":"¿Por qué se forma el callo blando en la zona central de la fractura?","back":"Debido a la existencia de hipoxia (baja tensión de oxígeno)."},{"front":"¿Qué componentes celulares y de matriz caracterizan al callo blando?","back":"Condroblastos y colágeno tipo 2 (T2)."},{"front":"¿Qué célula domina la fase de osificación del callo aproximadamente a las 2 semanas?","back":"El condrocito hipertrófico."},{"front":"¿Cómo contribuyen los condrocitos hipertróficos a la calcificación del callo?","back":"Liberan vesículas de matriz con proteasas que aportan iones fosfato para el calcio."},{"front":"¿Cómo se denomina al hueso inicial, trabecular e irregular, antes de la remodelación?","back":"Hueso inmaduro o fibrilar."},{"front":"¿Cuánto tiempo puede durar la fase de remodelación ósea?","back":"De meses a años."},{"front":"¿Qué es el síndrome compartimental?","back":"Aumento de la presión tisular dentro de un compartimiento osteofascial que ocluye la circulación muscular."},{"front":"¿Con qué fracturas se asocia más frecuentemente el síndrome compartimental?","back":"Fracturas de tibia, antebrazo, codo y supracondíleas."},{"front":"¿Cuál es el síntoma clínico más desproporcionado y característico del síndrome compartimental?","back":"Dolor intenso que aumenta con el estiramiento pasivo."},{"front":"¿Cuál es el rango de presión intracompartimental diagnóstica según el texto?","back":"30-40 mmHg."},{"front":"¿Cuál es el tratamiento definitivo del síndrome compartimental?","back":"Fasciotomía."},{"front":"Mencione dos causas extrínsecas que pueden generar síndrome compartimental.","back":"Yesos o vendajes muy apretados."},{"front":"¿Qué complicación se define como la interrupción de la vascularización de fragmentos óseos?","back":"Necrosis isquémica o avascular."},{"front":"Mencione los cuatro huesos donde es más común la necrosis avascular postraumática.","back":"Escafoides, astrágalo, cabeza femoral y cabeza humeral."},{"front":"¿Cuáles son los hallazgos radiográficos típicos de la necrosis avascular?","back":"Aumento de la densidad ósea y fragmentación."},{"front":"¿Cuál es el tratamiento de elección para la necrosis avascular en fémur o húmero?","back":"Colocación de una prótesis."},{"front":"¿Qué opciones terapéuticas existen para la necrosis del astrágalo?","back":"Órtesis o artrodesis."},{"front":"¿Qué es el Síndrome de Dolor Regional Complejo (SDRC)?","back":"Hiperactividad del sistema simpático tras una lesión tisular, con dolor y alteraciones sensitivas."},{"front":"¿Cuál es la diferencia entre el SDRC tipo I y el tipo II?","back":"El tipo I no tiene lesión nerviosa identificable, mientras que el tipo II sí presenta lesión de un nervio."},{"front":"¿Cómo se describe el dolor en el SDRC?","back":"Dolor quemante que no corresponde a un dermatoma."},{"front":"¿Qué fractura distal del radio se asocia frecuentemente con SDRC?","back":"Fractura de Colles."},{"front":"¿Cuál es la causa más frecuente del síndrome de embolia grasa?","back":"Fractura de la diáfisis femoral."},{"front":"Además del fémur, ¿qué otras fracturas inestables se asocian a embolia grasa?","back":"Fracturas inestables de pelvis."},{"front":"¿Cuál es la tríada clínica del síndrome de embolia grasa?","back":"Rash petequial, deterioro mental e insuficiencia respiratoria progresiva."},{"front":"¿Qué nivel de hipoxemia se espera en la embolia grasa?","back":"PO₂ menor a 60 mmHg."},{"front":"¿Qué escala se utiliza para diagnosticar el síndrome de embolia grasa?","back":"Criterios de Gurd."},{"front":"¿Cuántos criterios de Gurd se requieren para el diagnóstico de embolia grasa?","back":"1 criterio mayor y 4 criterios menores."},{"front":"¿Cuál es el manejo terapéutico del síndrome de embolia grasa?","back":"Oxigenoterapia, corticoides en dosis altas, estabilización de fracturas y manejo en UCI."},{"front":"¿Qué define a una fractura en tallo verde?","back":"Una inflexión rompe la cortical de un lado y la contralateral solo se abomba (incompleta)."},{"front":"¿En qué población es más frecuente la fractura en tallo verde?","back":"En niños."},{"front":"¿Cuál es la localización más común de la fractura en tallo verde?","back":"Antebrazo (diáfisis de cúbito y radio)."},{"front":"¿Cuál es el estudio inicial y de elección para diagnosticar una fractura en tallo verde?","back":"Radiografía simple (Rx)."},{"front":"¿En qué consiste el tratamiento de la fractura en tallo verde?","back":"Reducción y vigilancia estrecha para detectar redesplazamientos."},{"front":"¿Qué proteína estructural predomina en la fase de callo duro?","back":"Colágeno tipo 1."},{"front":"¿En qué fase de la consolidación actúan principalmente los fibroblastos y condroblastos?","back":"Fase de tejido de granulación."},{"front":"¿Qué complicación ortopédica requiere desensibilización de la piel y bloqueos simpáticos?","back":"Síndrome de Dolor Regional Complejo (SDRC)."},{"front":"En el contexto de embolia grasa, el rash _____ es un signo clínico patognomónico.","back":"petequial"}]},"34":{"num":34,"name":"TYO PARTE 2","cards":[{"front":"¿Qué porcentaje de las fracturas corresponde a la fractura de húmero proximal","back":"frecuentemente asociada a osteoporosis?"},{"front":"En las fracturas de húmero proximal, ¿cuál es la relación de afectación por sexo entre mujeres y hombres?","back":"Relación de 3:1."},{"front":"¿Cuál es el mecanismo de lesión más común para la fractura de húmero proximal en pacientes de edad avanzada?","back":"Caída con apoyo en la mano y el brazo extendido desde posición de pie."},{"front":"¿Qué estudio de imagen se debe solicitar si existe duda sobre la fragmentación en una fractura de húmero proximal?","back":"Tomografía Axial Computarizada (TAC)."},{"front":"¿Qué clasificación divide las fracturas de húmero proximal en 6 grupos distintos?","back":"Clasificación de Neer."},{"front":"¿Cuál es el tratamiento de elección para una fractura de húmero proximal no desplazada?","back":"Tratamiento conservador."},{"front":"¿Qué procedimiento se indica en fracturas de húmero proximal con dos fragmentos o fractura-luxación?","back":"Reducción abierta y fijación interna."},{"front":"En el manejo postoperatorio de fracturas humerales, ¿qué analgésicos opioides se mencionan específicamente?","back":"Buprenorfina y nalbufina."},{"front":"¿Cuál es el esquema antibiótico profiláctico de elección para cirugías de fractura de húmero?","back":"Cefazolina 1-2 gr en la pre-inducción, seguido de 1 gr cada 8 horas por 24 horas."},{"front":"En pacientes alérgicos a la penicilina que requieren profilaxis antibiótica por fractura de húmero, ¿qué fármaco se utiliza?","back":"Clindamicina."},{"front":"¿Qué porcentaje de todas las fracturas constituyen las de la diáfisis del húmero?","back":"Del 1% al 3%."},{"front":"¿Qué complicación grave se debe descartar sistemáticamente en una fractura de diáfisis de húmero?","back":"Síndrome compartimental."},{"front":"En el contexto de una fractura de húmero, ¿qué beneficio se obtiene al iniciar el tratamiento antibiótico en las primeras 3 horas?","back":"Reduce el riesgo de infección en un 59%."},{"front":"¿Bajo qué clasificación se determina el tratamiento antibiótico en fracturas de húmero y antebrazo?","back":"Clasificación de Gustilo."},{"front":"¿Cuál es el tratamiento indicado para fracturas de húmero conminutas o expuestas grado IIIB y IIIC?","back":"Fijación externa."},{"front":"¿Qué porcentaje de todas las fracturas representan las lesiones de la diáfisis de radio y cúbito?","back":"Del 10% al 14%."},{"front":"¿Por qué las fracturas de radio y cúbito suelen asociarse a incongruencia articular?","back":"Porque el antebrazo es considerado una sola articulación funcional."},{"front":"¿Qué nervios deben valorarse tras una lesión traumática en el antebrazo?","back":"Nervio radial, mediano y ulnar."},{"front":"¿En qué casos de fractura de antebrazo se indica una angiografía?","back":"Cuando existe sospecha de lesiones vasculares."},{"front":"¿Cuál es el manejo inicial para fracturas de radio y cúbito no desplazadas con mínima inflamación?","back":"Inmovilización con férula o yeso con reducción cerrada."},{"front":"¿Cómo se denomina la fractura distal del radio con desplazamiento dorsal y radial del fragmento, conocida como deformidad \"en tenedor\"?","back":"Fractura de Pouteau-Colles."},{"front":"¿Cuál es el mecanismo de producción típico de la fractura de Colles?","back":"Hiperextensión de la muñeca."},{"front":"¿Cómo se denomina la fractura de radio distal con desplazamiento palmar del fragmento, conocida como deformidad \"en pala de jardinero\"?","back":"Fractura de Goyrand-Smith."},{"front":"¿Qué mecanismo de lesión produce la fractura de Smith?","back":"Hiperflexión de la muñeca."},{"front":"Definición: Fractura de Bennett","back":"Fractura oblicua intraarticular e inestable de la base del primer metacarpiano con desplazamiento proximal de la diáfisis."},{"front":"Definición: Fractura de Rolando","back":"Fractura intraarticular conminuta de la base del primer metacarpiano."},{"front":"¿Cuál es el tratamiento inicial recomendado para la fractura de Rolando?","back":"Tratamiento conservador y movilización precoz."},{"front":"¿En qué consiste la denominada \"Fractura del boxeador\"?","back":"Fractura del cuello del quinto metacarpiano, usualmente por dar un puñetazo."},{"front":"Concepto: Lesión de Galeazzi","back":"Fractura de la diáfisis radial distal asociada a luxación de la articulación radiocubital distal (cabeza del cúbito)."},{"front":"Concepto: Lesión de Monteggia","back":"Fractura de la diáfisis cubital proximal asociada a luxación de la articulación radiocubital proximal (cabeza del radio)."},{"front":"¿Cuál es el tipo más frecuente de la lesión de Monteggia según la clasificación de Bado?","back":"Tipo I (cabeza radial desplazada a anterior)."},{"front":"¿Cuáles son las dos maniobras clínicas utilizadas para diagnosticar el síndrome de pinzamiento del manguito rotador?","back":"Maniobra de Neer y maniobra de Hawkins."},{"front":"¿Qué signos clínicos son positivos en la sospecha de tendinitis bicipital?","back":"Signo de Speed y signo de Yergason."},{"front":"¿Cuál es la recomendación terapéutica inicial para el síndrome de hombro doloroso?","back":"Manejo fisioterapéutico para mantener arcos de movilidad."},{"front":"¿Cuántas infiltraciones subacromiales de cortisona se recomiendan como máximo para el control del dolor en el hombro?","back":"Dos a tres infiltraciones."},{"front":"¿En qué pacientes está contraindicado realizar fisioterapia de hombro?","back":"Pacientes con fracturas inestables, luxaciones agudas o inestabilidad."},{"front":"La tríada de músculos del manguito rotador incluye al supraespinoso, infraespinoso, redondo menor y _____.","back":"Subescapular."},{"front":"¿Cuál es la característica principal del dolor en el síndrome crónico del manguito rotador?","back":"Dolor nocturno en la cara anterior y lateral del hombro con irradiación al cuello."},{"front":"¿Qué rangos de abducción se ven limitados típicamente en la patología crónica del manguito rotador?","back":"De 30° a 60°."},{"front":"¿Cuál es el fármaco y dosis utilizados habitualmente para la infiltración intraarticular en patología de hombro?","back":"2 ml de corticoesteroide y 2 ml de lidocaína al 2% sin epinefrina."},{"front":"¿Cuál es la diferencia mecánica entre la ruptura crónica y la aguda del manguito rotador?","back":"La crónica es por uso excesivo progresivo, mientras la aguda es por caída sobre el brazo en extensión o movimientos bruscos."},{"front":"¿Qué tipo de luxación glenohumeral es la más frecuente, representando el 90% de los casos?","back":"Luxación anterior."},{"front":"¿En qué contexto clínico son frecuentes las luxaciones de hombro posteriores?","back":"Pacientes con descargas eléctricas o crisis convulsivas."},{"front":"¿Cuál es la apariencia física característica de un hombro con luxación glenohumeral anterior?","back":"Hombro en charretera."},{"front":"¿Qué nervio suele lesionarse en asociación con una luxación glenohumeral anterior?","back":"Nervio axilar."},{"front":"Concepto: Lesión de Bankart","back":"Daño al rodete glenoideo en su porción antero-inferior tras una luxación."},{"front":"Concepto: Lesión de Hill-Sachs","back":"Daño o fractura por impactación en la parte posterior de la cabeza humeral."},{"front":"¿Cuáles son las dos técnicas de reducción cerrada más comunes para la luxación de hombro?","back":"Técnica de Hipócrates y técnica de tracción-contracción."},{"front":"¿Qué estructura anatómica se subluxa en el llamado \"codo de niñera\"?","back":"La cabeza del radio fuera del ligamento anular."},{"front":"¿Cuál es la presentación clínica típica de un niño con codo de niñera?","back":"Codo en semiextensión, antebrazo en pronación y ausencia de movilidad activa."},{"front":"¿Qué estudio diagnóstico confirma el codo de niñera, dado que la radiografía suele ser normal?","back":"Ultrasonografía (USG)."},{"front":"¿Cuál es la maniobra de tratamiento para reducir el codo de niñera?","back":"Supinación forzada del antebrazo en extensión seguida de flexión."},{"front":"¿Qué signo clínico se utiliza para evaluar la anatomía normal del codo y se pierde en las luxaciones?","back":"Triángulo de Nélaton."},{"front":"En una luxación de codo, ¿qué nervios corren mayor riesgo de lesión?","back":"Nervio cubital y nervio mediano."},{"front":"¿Qué mecanismo lesional define al esguince cervical?","back":"Lesión combinada entre extensión y flexión de la columna (fenómeno de latigazo)."},{"front":"¿Cuál es el manejo no farmacológico del esguince cervical durante las primeras 48 horas?","back":"Crioterapia."},{"front":"En el tratamiento del esguince cervical grado I, ¿por qué se deben evitar los collarines?","back":"Porque no están indicados y el manejo debe ser con reposo relativo e higiene postural."},{"front":"¿Qué grado de esguince cervical se caracteriza por dolor cervical y espasmo muscular, pero sin signos físicos evidentes?","back":"Grado I."},{"front":"¿Qué grado de la clasificación de esguince cervical implica la presencia de síntomas, signos y clínica neurológica?","back":"Grado III."},{"front":"¿Cuál es el estudio de imagen indicado para un esguince cervical grado III?","back":"TAC, RM, mielografía o discografía."},{"front":"¿En qué consiste la prueba del \"paso de cuerda floja\" para evaluar el esguince cervical?","back":"El paciente camina despacio por 3 metros sobre una línea recta."},{"front":"¿Qué meta se busca alcanzar en la Fase 1 (1-4 días) del tratamiento del esguince cervical?","back":"Reducir el dolor y disminuir las cargas."},{"front":"¿Qué fármacos de primera línea se recomiendan para el manejo del dolor en el esguince cervical?","back":"AINES combinados con Inhibidores de la Bomba de Protones (IBP)."},{"front":"En la fractura de diáfisis de radio y cúbito en adultos, ¿cuándo se considera candidato a tratamiento quirúrgico?","back":"En fracturas de Galeazzi, Monteggia, expuestas o asociadas a síndrome compartimental."},{"front":"¿Cuál es el tiempo estimado de recuperación para una fractura de diáfisis de húmero?","back":"De 8 a 16 semanas."}]},"35":{"num":35,"name":"TYO PARTE 3","cards":[{"front":"¿Cuál es la complicación más frecuente en ancianos tras una cirugía de fractura de cadera?","back":"Delirium."},{"front":"¿Cuál es el principal factor de comorbilidad y mortalidad asociado a la fractura de cadera?","back":"Tromboembolismo venoso."},{"front":"En la fractura de cadera, ¿cuál es el porcentaje de mortalidad esperado al cabo de un año?","back":"30%."},{"front":"¿Qué músculo es responsable de la rotación externa clínica en una fractura de cadera?","back":"Psoas ilíaco."},{"front":"¿Por qué se produce el acortamiento del miembro en una fractura de cadera?","back":"Por el ascenso del segmento femoral debido a la contractura de los pelvitrocantéreos."},{"front":"¿Cuál es el estudio de imagen indicado cuando existe sospecha clínica de fractura de cadera pero la radiografía es normal?","back":"Resonancia Magnética Nuclear (RMN)."},{"front":"Tratamiento de elección para fracturas de cadera desplazadas en pacientes jóvenes:","back":"Osteosíntesis con tornillos canulados."},{"front":"Tratamiento de elección para fracturas de cadera desplazadas en pacientes de edad avanzada:","back":"Artroplastia."},{"front":"¿Cuál es la posición clásica del miembro inferior en una luxación de cadera posterior?","back":"Acortado, en rotación interna, aproximación (aducción) y flexión."},{"front":"¿Qué estructura nerviosa se lesiona con mayor frecuencia en una luxación posterior de cadera?","back":"Nervio ciático."},{"front":"¿Cuál es la posición clásica del miembro inferior en una luxación de cadera anterior?","back":"Alargado, en rotación externa y discreta separación (abducción)."},{"front":"¿Qué porcentaje de las luxaciones de cadera corresponden al tipo posterior?","back":"90%."},{"front":"¿Cuál es la complicación a largo plazo más frecuente de una luxación de cadera?","back":"Coxartrosis postraumática."},{"front":"¿Cuál es la principal causa de embolia grasa en traumatología?","back":"Fractura de diáfisis femoral."},{"front":"En la fractura de diáfisis femoral, el tratamiento quirúrgico con clavos intramedulares debe realizarse preferentemente en las primeras _____ horas.","back":"24"},{"front":"¿Cuál es la principal complicación de las fracturas de tibia?","back":"Ausencia de consolidación."},{"front":"¿Qué herramienta clínica se utiliza para decidir la necesidad de radiografías en un traumatismo de tobillo?","back":"Reglas de Ottawa."},{"front":"¿Cuál es el ligamento que se lesiona con más frecuencia en un esguince de tobillo?","back":"Ligamento peroneo astragalino anterior."},{"front":"Grado de esguince de tobillo caracterizado por lesión completa del ligamento, edema severo y pérdida de la función:","back":"Grado 3."},{"front":"Tratamiento farmacológico de primera elección para un esguince de tobillo grado 1:","back":"Paracetamol."},{"front":"¿Cuál es la conducta recomendada respecto al uso de férulas de yeso en esguinces de tobillo grado 1 y 2?","back":"No se deben utilizar."},{"front":"¿Qué tipo de vendaje se recomienda cuando existe edema bimaleolar en un esguince de tobillo?","back":"Vendaje de Jones."},{"front":"¿Cuál es el agente etiológico más común de la artritis séptica?","back":"Staphylococcus aureus."},{"front":"¿Cuál es la vía de invasión más común de la artritis séptica en niños?","back":"Vía hematógena."},{"front":"¿Cuál es el estándar de oro (gold standard) para el diagnóstico de artritis séptica?","back":"Cultivo de líquido sinovial."},{"front":"¿Para qué es útil la ecografía en el contexto de una sospecha de artritis séptica en niños?","back":"Para detectar derrame articular, especialmente en la cadera."},{"front":"¿Cuál es la duración mínima recomendada del tratamiento antibiótico en artritis séptica?","back":"4 a 6 semanas."},{"front":"Definición de osteomielitis:","back":"Infección del hueso que afecta la cavidad medular, el periostio y el tejido óseo."},{"front":"¿Qué patógeno se debe sospechar en casos de osteomielitis con cultivos negativos?","back":"Kingella kingae."},{"front":"¿Qué síntoma clínico característico sugiere osteomielitis (conocido como 'one finger pain')?","back":"Dolor óseo localizado."},{"front":"En la osteomielitis, ¿a partir de cuántos días se vuelven positivos los hallazgos radiológicos?","back":"7 a 10 días."},{"front":"¿Cuál es el estudio con mayor sensibilidad y especificidad para el diagnóstico de osteomielitis crónica?","back":"Cintigrama óseo con Tc⁹⁹."},{"front":"Tratamiento antibiótico de elección para osteomielitis en menores de 5 años:","back":"Cefuroxima o Penicilina G."},{"front":"Definición de la enfermedad de Legg-Calvé-Perthes:","back":"Isquemia de la extremidad proximal del fémur en crecimiento que condiciona osteonecrosis parcial."},{"front":"¿Cuál es el perfil epidemiológico típico del paciente con necrosis avascular de la cabeza femoral (Perthes)?","back":"Niño varón de 4 a 8 años."},{"front":"Menciona las cuatro etapas de la enfermedad de Perthes:","back":"Necrosis, resorción/fragmentación, reosificación y remodelación."},{"front":"¿Cuál es la proyección radiográfica inicial necesaria para el diagnóstico de Perthes?","back":"Posición de Lowenstein (rana)."},{"front":"Signo radiológico característico de la enfermedad de Perthes avanzada:","back":"Pérdida de esfericidad del fémur o signo del 'tope de vagón'."},{"front":"¿Cuál es la característica clínica del dolor en la lumbalgia de tipo inflamatorio?","back":"Inicio insidioso, dura más de 3 meses, mejora con el ejercicio y aumenta con el reposo."},{"front":"¿Qué ejercicios de rehabilitación están indicados para el manejo de la lumbalgia?","back":"Ejercicios de Williams (flexión)."},{"front":"¿Cuál es la duración máxima recomendada para el tratamiento combinado de paracetamol y AINES en lumbalgia crónica?","back":"4 semanas."},{"front":"¿Cuál es la causa más frecuente de hombro doloroso?","back":"Tendinitis del supraespinoso."},{"front":"La formación de depósitos de calcio en los tendones del manguito rotador se denomina:","back":"Tendinitis calcificante."},{"front":"Nombre clínico de la epicondilitis lateral:","back":"Codo de tenista."},{"front":"Nombre clínico de la epitrocleítis:","back":"Codo de golfista."},{"front":"¿Qué musculatura se ve afectada en la epitrocleítis?","back":"Musculatura flexora-pronadora del antebrazo."},{"front":"Definición de la Tenosinovitis de Quervain:","back":"Inflamación de la vaina de los tendones del extensor corto y abductor largo del pulgar."},{"front":"¿Qué maniobra clínica (descrita por sus síntomas) confirma la Tenosinovitis de Quervain?","back":"Desviación cubital de la muñeca con el primer dedo sujeto en la palma."},{"front":"Nombre común de la bursitis prerrotuliana:","back":"Rodilla de beata."},{"front":"¿Qué tendones conforman la 'pata de ganso' (anserina)?","back":"Sartorio, semitendinoso y grácil."},{"front":"¿Cuál es el hueso del carpo que se fractura con mayor frecuencia?","back":"Escafoides."},{"front":"¿Cuál es el hueso del carpo que se luxa con mayor frecuencia?","back":"Semilunar."},{"front":"En las fracturas de la diáfisis humeral, ¿qué nervio corre mayor riesgo de lesión?","back":"Nervio radial."},{"front":"En las fracturas del húmero proximal, ¿qué nervio puede verse afectado?","back":"Nervio axilar (circunflejo)."},{"front":"La neuropatía por compresión más frecuente es:","back":"Síndrome del túnel del carpo."},{"front":"¿En qué parte de la clavícula ocurren la mayoría de las fracturas?","back":"Tercio medio."},{"front":"¿Cuál es el tumor óseo benigno más frecuente?","back":"Osteocondroma."},{"front":"Localización típica del Sarcoma de Ewing en el hueso:","back":"Diáfisis."},{"front":"¿Qué tipo de tumor óseo es el más frecuente en pacientes mayores de 50 años?","back":"Metástasis."},{"front":"¿Por qué debe evitarse el uso de nalbufina en el postoperatorio de ancianos?","back":"Porque es el opiáceo que con mayor frecuencia se asocia al desarrollo de delirium."},{"front":"La maniobra de exploración que indica laxitud ligamentaria en el tobillo se llama:","back":"Prueba del bostezo articular."},{"front":"¿Cuál es la principal causa de lesión traumática en el niño?","back":"Fractura supracondílea."},{"front":"En la fractura-luxación de Monteggia, ¿qué nervio suele lesionarse?","back":"Nervio interóseo posterior (rama del nervio radial)."},{"front":"¿Qué nervio se afecta típicamente en las fracturas del radio distal?","back":"Nervio mediano."},{"front":"Diferencia clínica principal entre esguince grado 1 y grado 2:","back":"El grado 2 presenta equimosis leve/moderada y discapacidad funcional moderada."}]},"36":{"num":36,"name":"EPIDEMIOLOGIA","cards":[{"front":"Definición: Sensibilidad","back":"Probabilidad de que la prueba sea positiva entre los enfermos."},{"front":"Definición: Especificidad","back":"Probabilidad de obtener un resultado negativo entre los individuos sanos."},{"front":"Definición: Valor Predictivo Positivo (VPP)","back":"Probabilidad de estar enfermo si el resultado de la prueba es positivo."},{"front":"Definición: Valor Predictivo Negativo (VPN)","back":"Probabilidad de estar sano si el resultado de la prueba es negativo."},{"front":"Cuando una prueba diagnóstica tiene una sensibilidad muy alta, su principal utilidad es _____ la enfermedad.","back":"descartar"},{"front":"Cuando una prueba diagnóstica tiene una especificidad muy alta, su principal utilidad es _____ la enfermedad.","back":"confirmar"},{"front":"¿Cómo se comporta el Valor Predictivo Positivo (VPP) ante un aumento en la prevalencia de la enfermedad?","back":"El VPP aumenta."},{"front":"¿Cómo se comporta el Valor Predictivo Negativo (VPN) ante una disminución en la prevalencia de la enfermedad?","back":"El VPN mejora (aumenta)."},{"front":"¿Cuál es el diseño de estudio que selecciona individuos sanos y los clasifica según su exposición para medir la incidencia?","back":"Estudio de cohorte."},{"front":"¿Qué medida de asociación se utiliza típicamente en los estudios de cohorte?","back":"Riesgo Relativo (RR)."},{"front":"¿Cuál es el rasgo distintivo principal de un estudio de cohorte respecto a la temporalidad?","back":"Posee una secuencia temporal clara de exposición hacia el evento."},{"front":"¿Qué diseño de estudio parte de sujetos con la enfermedad y reconstruye su historia de exposición de forma retrospectiva?","back":"Casos y controles."},{"front":"¿Qué medida de asociación se emplea en un estudio de casos y controles?","back":"Odds Ratio (OR)."},{"front":"¿Para qué tipo de enfermedades es especialmente eficiente el diseño de casos y controles?","back":"Enfermedades raras o con períodos de latencia largos."},{"front":"¿Qué diseño de estudio mide simultáneamente la exposición y el resultado, funcionando como una \"fotografía\"?","back":"Estudio transversal."},{"front":"¿Qué parámetro epidemiológico estima principalmente un estudio transversal?","back":"Prevalencia."},{"front":"¿Por qué un estudio transversal no puede establecer causalidad?","back":"Debido a que mide exposición y resultado simultáneamente, careciendo de secuencia temporal."},{"front":"¿Qué diseño de estudio asigna al azar la intervención y permite el mayor control de sesgos?","back":"Ensayo Clínico Aleatorizado (ECA)."},{"front":"¿Cuál es la medida de asociación típica utilizada en un Ensayo Clínico Aleatorizado (ECA)?","back":"Reducción Absoluta del Riesgo (RAR)."},{"front":"Definición: Alerta epidemiológica","back":"Comunicado de un evento epidemiológico que representa un daño inminente a la salud de la población."},{"front":"Definición: Asociación epidemiológica","back":"Situación en que dos o más casos comparten características de tiempo, lugar y persona."},{"front":"En vigilancia epidemiológica, ¿qué constituye un \"brote\" además de la ocurrencia de dos casos asociados?","back":"La existencia de un caso único en un área donde no existía el padecimiento."},{"front":"Definición: Caso confirmado","back":"Caso corroborado por estudios auxiliares o asociado epidemiológicamente a otro caso confirmado por laboratorio."},{"front":"Definición: Caso sospechoso","back":"Individuo susceptible que presenta algunos síntomas o signos compatibles con el evento bajo vigilancia."},{"front":"Definición: Caso probable","back":"Persona que presenta signos o síntomas sugerentes de la enfermedad bajo vigilancia."},{"front":"En el sarampión, ¿qué síntomas acompañan a la fiebre y al exantema maculopapular en un caso probable?","back":"Tos, coriza, conjuntivitis o adenomegalias."},{"front":"Para confirmar un caso probable de sarampión sin muestras de laboratorio, se requiere que esté _____ a otro caso confirmado.","back":"asociado epidemiológicamente"},{"front":"¿Cuál es el criterio de edad para un caso probable de rubéola, excepto en situaciones de brote?","back":"Ser menor de 15 años."},{"front":"¿Qué hallazgo de laboratorio confirma un caso de rubéola?","back":"Serología positiva para anticuerpos IgM específicos o aislamiento del virus."},{"front":"En la fiebre tifoidea, ¿cómo se describe típicamente el patrón de la fiebre en un caso probable?","back":"Fiebre continua en agujas de predominio vespertino."},{"front":"¿En qué muestras biológicas se debe aislar Salmonella typhi después de la segunda semana para confirmar fiebre tifoidea?","back":"Orina y heces fecales."},{"front":"¿Cuál es el síntoma pivote que define a un caso sospechoso de intoxicación alimentaria estafilocócica?","back":"Vómitos sin causa aparente después de comer."},{"front":"¿Cuánto tiempo después de ingerir alimentos suelen aparecer los síntomas en la intoxicación alimentaria estafilocócica?","back":"Después de 2 horas."},{"front":"¿Qué tipo de alimentos se asocian preferentemente a la intoxicación alimentaria estafilocócica?","back":"Lácteos (quesos, flanes) y cárnicos."},{"front":"En la giardiasis, ¿cuántos días de duración debe tener la diarrea para considerarse caso probable?","back":"Más de 14 días (diarrea crónica)."},{"front":"Mencione dos características de las evacuaciones en un caso probable de giardiasis.","back":"Esteatorrea (heces grasosas) y pálidas."},{"front":"¿Qué formas parasitarias deben identificarse en el coproparasitoscópico para confirmar giardiasis?","back":"Quistes o trofozoítos."},{"front":"¿Cuánto tiempo después del contacto sexual aparece el chancro en un caso probable de sífilis?","back":"Tres semanas."},{"front":"¿Cuáles son las tres características clínicas del chancro sifilítico primario?","back":"Úlcera indolora, indurada y con exudado seroso."},{"front":"En la sífilis, un caso sospechoso se define clínicamente por la presencia de chancro y un resultado positivo en la prueba de _____.","back":"VDRL"},{"front":"¿Qué técnica de laboratorio se considera estándar de oro o definitiva para confirmar un caso de sífilis?","back":"Anticuerpos fluorescentes directos (DFA-TP)."},{"front":"¿Qué zoonosis requiere notificación inmediata, semanal y cuenta con un sistema de vigilancia especial?","back":"Leptospirosis."},{"front":"Nombre las tres entidades bajo vigilancia sindromática que requieren notificación inmediata.","back":"Enfermedad Febril Exantemática, Parálisis Flácida Aguda y Síndrome Coqueluchoide."},{"front":"¿Cuál es la frecuencia de notificación para la Difteria y la Tosferina?","back":"Notificación inmediata."},{"front":"¿Qué enfermedad infecciosa del aparato digestivo requiere notificación inmediata, diaria, semanal y sistema especial?","back":"Cólera."},{"front":"Mencione tres enfermedades transmitidas por vectores que requieren notificación inmediata.","back":"Fiebre amarilla, Peste y Dengue hemorrágico."},{"front":"¿Qué tipos de paludismo requieren notificación inmediata según el agente causal?","back":"Paludismo por Plasmodium falciparum."},{"front":"¿Cuál es la frecuencia de notificación para el Dengue clásico (fiebre por dengue)?","back":"No tiene notificación inmediata."},{"front":"¿Qué enfermedad transmitida por vectores, además del Dengue clásico, no requiere notificación inmediata?","back":"Paludismo por Plasmodium vivax."},{"front":"En el contexto de la fiebre tifoidea, ¿en qué periodo es más probable aislar el patógeno en sangre?","back":"Durante la primera y segunda semana de la enfermedad."},{"front":"Para el diagnóstico de sarampión, ¿qué institución debe reconocer las técnicas de laboratorio utilizadas?","back":"El InDRE."},{"front":"¿Qué síntoma prodrómico diferencia al sarampión de la rubéola en la definición de caso probable?","back":"La coriza y la tos (más características del sarampión)."},{"front":"¿Cuál es el rasgo distintivo de la postración en la intoxicación estafilocócica según la definición de caso?","back":"Postración acompañada de hipotermia intensa y diaforesis."},{"front":"¿Qué criterio de tiempo descarta un caso de intoxicación alimentaria estafilocócica?","back":"No haber ingerido alimentos en más de 8 horas antes del inicio de síntomas."}]},"4":{"num":4,"name":"PATOLOGIA BILIAR","cards":[{"front":"¿Cuál es la principal fuente de irrigación de la vesícula biliar?","back":"La arteria cística."},{"front":"¿De qué estructura arterial se origina generalmente la arteria cística?","back":"De la arteria hepática derecha."},{"front":"¿En qué sistema venoso desembocan las venas císticas?","back":"En el sistema porta."},{"front":"¿Qué nervio proporciona la inervación parasimpática para la motilidad vesicular?","back":"El nervio vago."},{"front":"¿De dónde provienen las fibras simpáticas que se distribuyen hacia la vesícula biliar?","back":"Del plexo celíaco y los ganglios prevertebrales."},{"front":"Componente que representa el 80% de la composición de los litos biliares:","back":"Colesterol."},{"front":"¿Qué factor suele asociarse a la formación de litos pigmentarios marrones?","back":"Infecciones en la vesícula biliar."},{"front":"¿Qué patologías se asocian a la formación de litos pigmentarios negros?","back":"Hepatopatías y hemólisis."},{"front":"¿Cuáles son los 4 factores de riesgo clásicos (las 4 F) para colelitiasis?","back":"Female (mujer), Forty (cuarenta años), Fertility (fértil), Fat (obesidad)."},{"front":"¿A partir de qué dosis de estrógenos diarios aumenta el riesgo de colelitiasis?","back":"Mayor a 50 mcg/día."},{"front":"¿Cuál es el estudio de imagen de primera elección para el diagnóstico de colelitiasis?","back":"Ultrasonido (USG) de hígado y vías biliares."},{"front":"¿Qué estudio de segunda elección muestra el 'signo de Rim' (aumento de radiactividad)?","back":"Gammagrafía biliar con Tc-HIDA."},{"front":"Tratamiento farmacológico de la colelitiasis indicado por 1 a 2 años:","back":"Ácido ursodesoxicólico."},{"front":"¿Qué características debe tener un lito para ser candidato a litotricia extracorpórea?","back":"Lito único, no calcificado y no mayor a 20 mm."},{"front":"¿Cuál es el momento ideal para realizar una colecistectomía en una paciente embarazada?","back":"Durante el segundo trimestre."},{"front":"¿Cuál es la manifestación clínica principal de la colelitiasis sintomática?","back":"El cólico biliar."},{"front":"¿En qué momento del día aparece con mayor frecuencia el cólico biliar tras la ingesta de alimentos?","back":"De 1 a 5 horas después, sobre todo en las noches."},{"front":"¿Cuál es el manejo inicial para un paciente con colelitiasis asintomática?","back":"No requieren tratamiento."},{"front":"¿Qué fármaco y dosis se indica para el manejo del cólico biliar?","back":"Diclofenaco 75 mg IM."},{"front":"¿A partir de qué tamaño un lito es indicación de cirugía aunque sea asintomático?","back":"Litos mayores a 2.5-3 cm."},{"front":"¿Qué hallazgo en la pared vesicular es indicación de colecistectomía profiláctica por riesgo de cáncer?","back":"Vesícula en porcelana."},{"front":"¿Cuál es la complicación más frecuente tras una cirugía de vesícula?","back":"Infección de la herida quirúrgica."},{"front":"¿Cuál es la complicación más grave de una colecistectomía?","back":"Lesión a la vía biliar."},{"front":"¿Cómo se define la colecistitis aguda?","back":"Inflamación de la pared vesicular secundaria a litos o barro biliar."},{"front":"Porcentaje de casos de colecistitis que se presentan sin la presencia de litos (alitiásica):","back":"10%."},{"front":"¿Qué complicación es más frecuente en la colecistitis alitiásica en comparación con la litiásica?","back":"Mayor riesgo de perforación."},{"front":"¿En qué consiste el signo de Murphy positivo?","back":"Cese de la inspiración a la palpación profunda del hipocondrio derecho."},{"front":"¿Qué nombre recibe la masa palpable en CSD en el contexto de una colecistitis complicada?","back":"Signo de Courvoisier."},{"front":"¿Hacia qué región se irradia típicamente el dolor de la colecistitis aguda?","back":"Hacia la región infraescapular (en hemicinturón)."},{"front":"Hallazgo en el ultrasonido de la pared vesicular sugestivo de colecistitis aguda:","back":"Engrosamiento de la pared mayor a 5 mm."},{"front":"¿Qué dimensiones vesiculares en el USG (axial y diametral) sugieren colecistitis?","back":"8 cm de largo (axial) y 4 cm de ancho (diametral)."},{"front":"Hallazgo ultrasonográfico que consiste en la visualización de capas en la pared vesicular:","back":"Imagen en doble riel."},{"front":"¿Cuál es la técnica diagnóstica más específica para colecistitis aguda?","back":"Gammagrafía biliar."},{"front":"Criterio laboratorial de inflamación sistémica según las Guías de Tokio para colecistitis:","back":"Leucocitosis >10,000/μL o PCR elevada."},{"front":"¿Qué define a la Colecistitis Aguda Grado I (Leve)?","back":"Paciente sin datos de disfunción orgánica y solo cambios inflamatorios leves."},{"front":"¿Qué hallazgos clínicos/laboratoriales definen la Colecistitis Grado II (Moderada)?","back":"Leucocitos >18,000, masa palpable en CSD o cuadro de >72 horas."},{"front":"¿Qué caracteriza a la Colecistitis Aguda Grado III (Grave)?","back":"Presencia de datos de disfunción orgánica (cardiovascular, neurológica, renal, etc.)."},{"front":"Antibiótico de elección para Colecistitis Grado I:","back":"Fluoroquinolonas (Levofloxacino o Ciprofloxacino) o Cefalosporinas orales."},{"front":"Esquema antibiótico recomendado para Colecistitis Grado II:","back":"Piperacilina/Tazobactam o Cefalosporinas de segunda generación."},{"front":"Tratamiento quirúrgico estándar para Colecistitis Grado I y II:","back":"Colecistectomía temprana por laparoscopía (1 a 7 días tras el ataque)."},{"front":"¿Cuál es el manejo inicial y quirúrgico para la Colecistitis Grado III?","back":"Manejo de falla orgánica en UCI y colecistectomía tardía (2 a 3 meses después)."},{"front":"¿Qué es el Síndrome de Mirizzi?","back":"Impactación de un lito en el infundíbulo de la vesícula que comprime el conducto hepático común."},{"front":"¿Qué antibiótico tiene mayor riesgo de inducir la formación de litos biliares?","back":"Ceftriaxona."},{"front":"¿Cómo se define la coledocolitiasis?","back":"Presencia de litos en el colédoco, ya sean primarios o secundarios."},{"front":"¿Qué porcentaje de pacientes con colelitiasis asintomática presentan coledocolitiasis?","back":"10 a 15%."},{"front":"\"Conjunto de síntomas compuesto por ictericia","back":"coluria y acolia:\""},{"front":"¿Cuál es el tratamiento de elección para la coledocolitiasis?","back":"CPRE (Colangiopancreatografía Retrógrada Endoscópica) seguida de colecistectomía laparoscópica."},{"front":"¿Cuál es el diámetro normal del colédoco por ultrasonido?","back":"Menor a 6 mm."},{"front":"¿Qué estudio se indica si el diámetro del colédoco está entre 6 y 8 mm?","back":"Colangio-Resonancia Magnética (Colangio-RM)."},{"front":"¿Qué estudio se considera el Gold Standard cuando el colédoco mide más de 8 mm?","back":"CPRE."},{"front":"¿Cuál es la principal causa de la colangitis?","back":"Infección de la vía biliar secundaria a coledocolitiasis."},{"front":"Microorganismo gramnegativo más frecuentemente aislado en colangitis:","back":"E. coli."},{"front":"Anaerobio más común en infecciones de la vía biliar:","back":"Bacteroides fragilis."},{"front":"¿Qué elementos componen la Tríada de Charcot?","back":"Fiebre, ictericia y dolor en hipocondrio derecho."},{"front":"¿Qué elementos componen la Pentada de Reynolds?","back":"Fiebre, ictericia, dolor en hipocondrio derecho, choque y alteración del estado de alerta."},{"front":"¿Cuál es el procedimiento de elección para el diagnóstico y drenaje en colangitis?","back":"CPRE."},{"front":"¿Cómo se define la Colangitis Biliar Primaria?","back":"Enfermedad autoinmunitaria donde los conductos biliares se inflaman y destruyen lentamente."},{"front":"¿Qué anticuerpos son característicos de la Colangitis Biliar Primaria?","back":"Antimitocondriales (AMA) y Antinucleares (ANA)."},{"front":"¿Cuál es el estándar de oro para el diagnóstico de Colangitis Biliar Primaria?","back":"Biopsia hepática."},{"front":"¿Qué es el íleo biliar?","back":"Obstrucción mecánica intestinal por un cálculo biliar impactado, usualmente en el íleon terminal."},{"front":"¿Qué componentes forman la Tríada de Rigler en el íleo biliar?","back":"Obstrucción intestinal, aerobilia y cálculo biliar en localización aberrante."},{"front":"¿Cuál es el tratamiento quirúrgico de elección para el íleo biliar?","back":"Enterolitotomía."},{"front":"¿Qué hallazgo radiológico es clave para sospechar una fístula bilioentérica en íleo biliar?","back":"Aerobilia (aire en las vías biliares)."},{"front":"¿Qué patologías gastrointestinales crónicas aumentan el riesgo de colelitiasis?","back":"Enfermedad de Crohn y cirrosis hepática."},{"front":"¿Qué microorganismos se asocian a la colecistitis enfisematosa?","back":"Microorganismos productores de gas."},{"front":"¿A qué se debe la sospecha de coledocolitiasis residual?","back":"Colangitis o ictericia en un paciente previamente colecistectomizado."},{"front":"\"En pacientes con SIDA","back":"¿qué agentes pueden causar colangitis?\""}]},"5":{"num":5,"name":"PANCREATITIS","cards":[{"front":"¿Cuál es la principal etiología de la pancreatitis aguda a nivel mundial?","back":"Litiasis biliar (49-66% de los casos)."},{"front":"¿Qué porcentaje de los casos de pancreatitis aguda se clasifican como graves?","back":"El 20% de los casos."},{"front":"¿Cuál es el nivel de triglicéridos séricos necesario para considerar la hipertrigliceridemia como causa de pancreatitis?","back":"Niveles mayores a 1000 mg/dL."},{"front":"¿Cuál es la causa principal de la pancreatitis aguda recurrente?","back":"Microlitiasis."},{"front":"¿En qué regiones abdominales se localiza típicamente el dolor de la pancreatitis aguda?","back":"Región epigástrica e hipocondrio izquierdo."},{"front":"¿Qué posición suele adoptar el paciente para aliviar el dolor transficticio de la pancreatitis?","back":"Posición fetal."},{"front":"¿En qué sexo es más frecuente la pancreatitis de etiología alcohólica?","back":"En hombres."},{"front":"Definición: Signo de Cullen","back":"Presencia de equimosis en la región periumbilical."},{"front":"Definición: Signo de Gray-Turner","back":"Presencia de equimosis en los flancos."},{"front":"Definición: Signo de Fox","back":"Presencia de equimosis en el ligamento inguinal."},{"front":"¿Cuántos criterios diagnósticos deben cumplirse para confirmar una pancreatitis aguda?","back":"Al menos 2 de los 3 criterios establecidos."},{"front":"¿Qué nivel de elevación de lipasa o amilasa se requiere para el diagnóstico de pancreatitis aguda?","back":"Más de 3 veces el límite superior normal."},{"front":"¿Qué enzima pancreática posee mayor especificidad para el diagnóstico?","back":"La lipasa."},{"front":"¿Cuál es el puntaje de APACHE II que indica un mal pronóstico en el paciente?","back":"Una puntuación mayor a 7."},{"front":"\"¿Qué valor de Proteína C Reactiva (PCR) es considerado el \"\"estándar de oro\"\" para predecir mal pronóstico?\"","back":"Un valor mayor a 150 mg/dL."},{"front":"¿Cuál es el punto de corte en la escala de Ranson para determinar un mal pronóstico?","back":"Una puntuación mayor a 3."},{"front":"¿Cómo se clasifica la severidad de una pancreatitis que presenta falla orgánica por más de 48 horas?","back":"Pancreatitis aguda grave."},{"front":"¿Qué nivel de calcio sérico es predictor de gravedad en la pancreatitis aguda?","back":"Niveles menores a 1.9 mg/dL."},{"front":"¿Cuál es el estudio de imagen inicial que se debe realizar ante la sospecha de pancreatitis aguda?","back":"Ultrasonido abdominal."},{"front":"¿Cuál es el tiempo ideal para solicitar una TAC con contraste para detectar necrosis pancreática?","back":"Entre las 72 y 96 horas del inicio del cuadro."},{"front":"¿Qué estudio de imagen se prefiere en situaciones particulares como el embarazo por su especificidad?","back":"Resonancia Magnética (RM)."},{"front":"¿Cuál es el fluido de elección para la reanimación hídrica (piedra angular) en pancreatitis aguda?","back":"Solución de Hartmann (Ringer Lactato)."},{"front":"¿Cuál es la meta de Presión Arterial Media (PAM) durante el manejo hemodinámico?","back":"Entre 65 y 85 mmHg."},{"front":"¿Cuál es el rango de diuresis horaria objetivo en la reanimación hídrica?","back":"0.5-1 mL/kg/hora."},{"front":"¿Bajo qué condición se justifica el uso de antibióticos en la pancreatitis aguda?","back":"Solo ante sospecha o confirmación de infección o necrosis."},{"front":"¿Dentro de qué ventana de tiempo se recomienda iniciar la alimentación en pacientes estables?","back":"En las primeras 24-48 horas."},{"front":"¿Cuál es el aporte calórico diario recomendado para un paciente con pancreatitis?","back":"25-35 kcal/kg/día."},{"front":"¿Por qué se prefiere la nutrición enteral sobre la parenteral en estos pacientes?","back":"Debido al menor riesgo de infecciones asociado a la vía enteral."},{"front":"¿Cuál es el tratamiento de elección definitivo para la pancreatitis de etiología biliar?","back":"CPRE más colecistectomía (una vez que el paciente esté estable)."},{"front":"¿Qué porcentaje de necrosis tisular justifica la realización de una necrosectomía?","back":"Necrosis que involucre más del 50% del tejido."},{"front":"\"En caso de necrosis infectada","back":"¿cuánto tiempo se debe demorar idealmente el tratamiento quirúrgico?\""},{"front":"¿Cómo se denominan las colecciones líquidas que aparecen antes de las 4 semanas de evolución?","back":"Colección necrótica aguda o colección líquida peripancreática."},{"front":"¿Cuál es la complicación local crónica más frecuente de la pancreatitis aguda?","back":"Pseudoquiste pancreático."},{"front":"¿Qué característica distingue al pseudoquiste pancreático de una colección aguda?","back":"Posee una pared bien definida y aparece después de las 4 semanas."},{"front":"Definición: Necrosis Amurallada (WON)","back":"Colección encapsulada madura de necrosis pancreática con pared bien definida."},{"front":"¿Cuál es la causa sistémica de hasta el 75% de las muertes en pancreatitis?","back":"Insuficiencia circulatoria (falla orgánica)."},{"front":"¿Cuál es el signo clínico más frecuente encontrado a la exploración física?","back":"Resistencia muscular."},{"front":"¿En qué casos está contraindicada la vía oral/enteral en la pancreatitis?","back":"En presencia de íleo o durante el uso de opioides potentes como analgesia."},{"front":"¿Cuáles son los componentes de la tríada clásica de la pancreatitis crónica?","back":"Calcificaciones pancreáticas, esteatorrea y diabetes."},{"front":"¿Qué porcentaje de pérdida de la función exocrina es necesario para que aparezca la esteatorrea?","back":"Una pérdida mayor al 90%."},{"front":"¿Cuál es el principal factor etiológico de la pancreatitis crónica en adultos?","back":"Alcoholismo."},{"front":"\"¿Cuál es el \"\"estándar de oro\"\" para el diagnóstico de pancreatitis crónica?\"","back":"Colangiopancreatografía Retrógrada Endoscópica (CPRE)."},{"front":"¿Qué prueba de función pancreática es la más sensible para detectar daño tisular mayor al 60%?","back":"Examen de secreción pancreática tras estimulación con secretina."},{"front":"¿Cómo suelen encontrarse los niveles de amilasa y lipasa en la pancreatitis crónica?","back":"Niveles normales."},{"front":"¿Qué parámetro de laboratorio se encuentra generalmente alterado en la pancreatitis crónica debido a la pérdida de función endocrina?","back":"La glucosa (hiperglucemia)."},{"front":"¿Cuál es el tratamiento farmacológico para la insuficiencia pancreática exocrina?","back":"Enzimas pancreáticas más ocreótida."},{"front":"¿Qué complicación vascular puede producir cualquier proceso que dañe crónicamente el páncreas?","back":"Trombosis de la vena esplénica."},{"front":"¿Cuál es el tratamiento de elección para la pancreatitis crónica de origen autoinmune?","back":"Corticoides."},{"front":"¿Qué escala se utiliza para el manejo escalonado del dolor en pancreatitis?","back":"La escala analgésica de la OMS."},{"front":"Concepto: Pancreatitis Crónica","back":"Proceso inflamatorio persistente e irreversible que provoca cambios morfológicos y funcionales permanentes en el páncreas."},{"front":"\"En el manejo del dolor","back":"¿en qué escalón de la OMS se sitúa el uso de AINEs como el Metamizol?\""},{"front":"¿Cuál es el principal riesgo de la alimentación parenteral en pacientes con pancreatitis?","back":"Mayor riesgo de infecciones."},{"front":"\"¿Qué marcador inflamatorio","back":"además de la PCR"},{"front":"¿Qué intervención se recomienda para el manejo de pseudoquistes que causan síntomas obstructivos?","back":"Drenaje percutáneo o endoscópico."},{"front":"¿Cómo se describe el dolor típico de la pancreatitis en relación a su irradiación?","back":"Dolor en \"cinturón\" que se irradia hacia la espalda."},{"front":"¿Cuál es el rango de mortalidad en casos graves de pancreatitis aguda?","back":"Entre el 20% y el 40%."},{"front":"¿Qué hallazgo en la TAC caracteriza a la colección líquida peripancreática aguda?","back":"Pared mal definida con contenido líquido homogéneo sin necrosis sólida."},{"front":"¿Qué vitamina liposoluble puede dejar de absorberse debido a la insuficiencia exocrina en la pancreatitis crónica?","back":"Cualquiera de las vitaminas A, D, E, K."},{"front":"¿A partir de qué tiempo de consumo de alcohol (50-80 g/día) se incrementa el riesgo de pancreatitis crónica?","back":"Después de 5 años de consumo."},{"front":"¿Cuál es la indicación quirúrgica en pancreatitis crónica cuando el dolor no cede con mórficos?","back":"Cirugía por dolor persistente intratable."}]},"6":{"num":6,"name":"APENDICITIS","cards":[{"front":"¿Cuál es la definición de apendicitis aguda?","back":"Es la inflamación del apéndice cecal o vermiforme."},{"front":"¿Cuál es la urgencia quirúrgica abdominal más común en la población general?","back":"La apendicitis aguda."},{"front":"¿En qué rango de edad se presenta el pico máximo de incidencia de la apendicitis?","back":"Entre los 15 y 35 años de edad."},{"front":"Menciona el evento fisiopatológico inicial que desencadena la apendicitis aguda.","back":"La obstrucción de la luz apendicular."},{"front":"¿Qué porcentaje de los cuadros sugestivos de apendicitis resultan ser realmente una infección de vías urinarias (IVU)?","back":"El 10%."},{"front":"¿Cuáles son los dos microorganismos más frecuentemente relacionados con la apendicitis?","back":"E. coli y B. fragilis."},{"front":"¿Cuál es la posición anatómica más frecuente del apéndice cecal?","back":"Retrocecal (74%)."},{"front":"La arteria apendicular es una rama directa de la arteria _____.","back":"Ileocólica."},{"front":"¿Cuál es la causa (etiología) más común de apendicitis en el paciente adulto?","back":"Fecalitos."},{"front":"¿Cuál es la causa más común de apendicitis en pacientes pediátricos?","back":"Hiperplasia de los folículos linfoides."},{"front":"Menciona las 4 fases evolutivas de la apendicitis aguda en orden cronológico.","back":"1. Congestiva, 2. Supurativa, 3. Gangrenosa y 4. Perforada."},{"front":"¿Cuál es la característica macroscópica principal de la fase catarral o congestiva?","back":"Inflamación submucosa con apariencia macroscópicamente normal."},{"front":"La presencia de exudado purulento en la luz y región periapendicular define a la fase _____.","back":"Flemonosa, fibrosa o supurativa."},{"front":"¿Qué hallazgo define la fase gangrenosa de la apendicitis?","back":"Necrosis y ulceración de la mucosa."},{"front":"¿Cuál es el parásito que se asocia con mayor frecuencia a la apendicitis?","back":"Ascaris."},{"front":"¿Cómo afecta la apendicectomía el riesgo de padecer Colitis Ulcerativa Crónica Idiopática (CUCI)?","back":"Reduce el riesgo de padecerla."},{"front":"¿Cuál es la complicación temprana más frecuente tras una intervención quirúrgica por apendicitis?","back":"Infección de la herida quirúrgica."},{"front":"¿Cuál es la complicación tardía más frecuente después de una apendicectomía?","back":"Absceso residual."},{"front":"Describe la migración clásica del dolor en la apendicitis aguda.","back":"Inicia en la región periumbilical y migra hacia el cuadrante inferior derecho."},{"front":"¿Qué elementos integran la Tríada de Murphy en la apendicitis?","back":"Náusea, fiebre y dolor."},{"front":"¿Cuál es el primer signo clínico que suele presentarse en la apendicitis aguda?","back":"Hiperalgesia cutánea."},{"front":"¿Qué hallazgo define al Signo de McBurney?","back":"Dolor a la palpación y descompresión en el cuadrante inferior derecho."},{"front":"¿Qué indica la presencia del Signo de Blumberg?","back":"Irritación peritoneal manifestada por sensibilidad de rebote pasajera."},{"front":"¿En qué consiste el Signo de Rovsing?","back":"Dolor en el punto de McBurney al comprimir la fosa ilíaca izquierda."},{"front":"¿A qué variante anatómica de apendicitis se asocia el Signo del Psoas?","back":"Apéndice o absceso retrocecal."},{"front":"¿En qué consiste el Signo del Obturador?","back":"Dolor al realizar flexión y rotación interna del muslo derecho."},{"front":"¿Qué maniobra desencadena el Signo de Dunphy?","back":"Aumento de dolor en la fosa ilíaca derecha provocado por la tos."},{"front":"\"En la escala de Alvarado","back":"¿qué parámetros otorgan 2 puntos cada uno?\""},{"front":"¿Qué conducta se sugiere si un paciente obtiene 5 o 6 puntos en la escala de Alvarado?","back":"Se considera posible apendicitis y requiere mayor observación."},{"front":"¿Qué rango de puntuación en la escala de Alvarado indica una alta probabilidad de apendicitis?","back":"7 a 8 puntos."},{"front":"\"¿Cuál es el estudio de imagen inicial recomendado para niños","back":"adultos y embarazadas?\""},{"front":"¿Cuál es el estándar de oro (gold standard) para el diagnóstico de apendicitis aguda?","back":"Tomografía Computarizada (TAC)."},{"front":"¿Cuál es el tratamiento quirúrgico de elección para la apendicitis aguda?","back":"Apendicectomía laparoscópica."},{"front":"¿Qué fármaco se recomienda como profilaxis antibiótica pre-operatoria?","back":"Cefoxitina 2 g IV."},{"front":"\"En pacientes alérgicos a betalactámicos","back":"¿qué antibiótico se utiliza como alternativa?\""},{"front":"Menciona una contraindicación para realizar cirugía laparoscópica en apendicitis.","back":"Insuficiencia cardíaca congestiva o hipertensión pulmonar severa."},{"front":"¿En qué rango de edad pediátrica se observa la mayor incidencia de apendicitis?","back":"Entre los 6 y 10 años de vida."},{"front":"¿Cuál es la tasa de perforación apendicular estimada en lactantes menores de un año?","back":"Puede ser de hasta el 100%."},{"front":"¿Cuál es el orden típico de presentación de los síntomas en el paciente pediátrico?","back":"Dolor abdominal, seguido de náusea/vómito y finalmente fiebre."},{"front":"¿Cuál suele ser el síntoma inicial de apendicitis en lactantes?","back":"Diarrea."},{"front":"¿Qué parámetros componen la 'prueba triple' diagnóstica en pediatría?","back":"PCR >8 mcg/ml, Leucocitosis >11,000/mm³ y Neutrofilia >8,000."},{"front":"¿Cuál es el abordaje quirúrgico recomendado para un niño con apendicitis menor de 5 años?","back":"Apendicectomía abierta."},{"front":"¿Cuál es el padecimiento quirúrgico no obstétrico más común durante el embarazo?","back":"Apendicitis aguda."},{"front":"¿En qué trimestre del embarazo es más frecuente la aparición de apendicitis?","back":"Segundo trimestre."},{"front":"¿En qué trimestre del embarazo tiene la apendicitis un peor pronóstico?","back":"Tercer trimestre."},{"front":"¿Cuál es el síntoma más frecuente de apendicitis en la mujer embarazada?","back":"Dolor abdominal en fosa ilíaca derecha."},{"front":"¿Cuál es el principal diagnóstico diferencial de apendicitis en el primer trimestre del embarazo?","back":"Embarazo ectópico."},{"front":"¿Cuántos centímetros puede desplazarse el apéndice hacia arriba de su posición normal por el crecimiento uterino?","back":"De 3 a 4 cm."},{"front":"¿Cuál es el estudio de imagen de elección en embarazadas con más de 20 semanas de gestación si el USG no es concluyente?","back":"Resonancia Magnética (RM)."},{"front":"¿Cuál es la postura actual sobre el uso de la TAC en el embarazo?","back":"Se deja como último recurso y solo después de la semana 20."},{"front":"¿Cómo suele ser la evolución clínica de la apendicitis en el adulto mayor?","back":"Subaguda, con una atención médica más tardía."},{"front":"¿Cuál es el estudio diagnóstico inicial recomendado para el adulto mayor con sospecha de apendicitis?","back":"Tomografía Computarizada (TAC)."},{"front":"¿Qué técnica quirúrgica se prefiere en un adulto mayor de 60 años con comorbilidades?","back":"Apendicectomía abierta."},{"front":"Menciona el síntoma más frecuente de apendicitis en el paciente adulto mayor.","back":"Dolor abdominal difuso de larga evolución."},{"front":"¿En qué zona específica del apéndice suele ocurrir la perforación?","back":"En el tercio distal, a nivel del borde antimesentérico."},{"front":"¿En cuánto tiempo puede ocurrir la perforación apendicular en los extremos de la vida?","back":"En las primeras 12 horas del inicio del cuadro."},{"front":"¿Cuál es el tiempo estimado de reincorporación laboral tras una apendicectomía abierta?","back":"De 2 a 3 semanas."},{"front":"¿Cuál es el tiempo estimado de reincorporación laboral tras una apendicectomía laparoscópica?","back":"De 1 a 2 semanas."},{"front":"Concepto: Signo de Summer","back":"Definición: Defensa involuntaria de los músculos abdominales por irritación peritoneal."},{"front":"¿Por qué las peritonitis en niños suelen ser más severas que en adultos?","back":"Debido a la inmadurez anatómica del epiplón."},{"front":"¿Qué porcentaje de riesgo de pérdida fetal existe en una apendicitis perforada?","back":"Hasta un 20%."},{"front":"¿Qué hallazgo en la biometría hemática de la embarazada sugiere un alto valor predictivo positivo para apendicitis?","back":"Leucocitosis entre 15,000 y 20,000/mm³."},{"front":"\"Si una paciente en edad reproductiva presenta dolor en fosa ilíaca derecha","back":"¿qué prueba debe solicitarse siempre?\""}]},"7":{"num":7,"name":"PATOLOGIA DIVERTICULAR","cards":[{"front":"¿Qué es la diverticulosis?","back":"La presencia de divertículos en el colon sin manifestaciones clínicas (asintomáticos)."},{"front":"¿Cómo se define la enfermedad diverticular?","back":"La aparición de signos y síntomas secundarios a la presencia de diverticulosis."},{"front":"¿Qué caracteriza a la diverticulitis?","back":"La presencia de datos de inflamación e infección en los divertículos."},{"front":"¿En qué segmento del colon se localiza el 95% de los divertículos?","back":"En el colon sigmoides."},{"front":"¿Qué porcentaje de los pacientes con diverticulosis desarrollará diverticulitis?","back":"Entre el 10% y el 20%."},{"front":"¿Cuál es el principal factor de riesgo para el desarrollo de diverticulosis?","back":"El estreñimiento crónico."},{"front":"¿Cuál es la prevalencia de la patología diverticular en personas mayores de 80 años?","back":"El 65%."},{"front":"¿Cuál es la causa más frecuente de sangrado de tubo digestivo bajo en mayores de 60 años?","back":"La patología diverticular."},{"front":"En pacientes con diverticulosis, ¿qué tipo de dieta se recomienda como medida preventiva?","back":"Dieta rica en fibra (20-35 g/día) y baja en grasas y carne roja."},{"front":"¿Qué fármacos se asocian frecuentemente con el sangrado en la enfermedad diverticular?","back":"Aspirina (ASA) y antiinflamatorios no esteroideos (AINES)."},{"front":"¿Cuál es la localización típica del dolor crónico en la enfermedad diverticular?","back":"Fosa ilíaca izquierda."},{"front":"¿Qué hallazgo hematológico inusual se menciona asociado a la enfermedad diverticular crónica?","back":"Leucopenia."},{"front":"¿Cuál es el estudio de imagen ideal para la enfermedad diverticular, aunque actualmente esté en desuso?","back":"Enema opaco."},{"front":"Si la enfermedad diverticular se asocia a colitis, ¿qué estudio debe realizarse para descartar otras entidades?","back":"Colonoscopía."},{"front":"¿Cuál es la dosis y esquema de la rifaximina en el tratamiento de la enfermedad diverticular?","back":"400 mg cada 12 horas por 7 días, una vez al mes."},{"front":"Si no hay mejoría con rifaximina, ¿qué fármacos se pueden agregar al tratamiento?","back":"Mesalazina (5-ASA) más probióticos."},{"front":"¿A qué edad promedio suele aparecer la diverticulitis?","back":"A los 62 años."},{"front":"¿Qué término clínico se utiliza para describir la diverticulitis debido a su similitud diagnóstica?","back":"Apendicitis izquierda."},{"front":"¿Cuál es el síntoma sistémico que diferencia a la diverticulitis de la diverticulosis?","back":"La presencia de fiebre."},{"front":"¿Qué porcentaje de pacientes con diverticulitis en fase aguda presenta hemorragia?","back":"El 25%."},{"front":"¿Cuál es el estudio de elección para el diagnóstico de diverticulitis?","back":"Tomografía Axial Computarizada (TAC) de abdomen y pelvis."},{"front":"¿Qué valor de Proteína C Reactiva (PCR) es sugestivo de diverticulitis?","back":"Mayor a 50 mg/L."},{"front":"¿Por qué están contraindicados el enema opaco y la colonoscopía en la fase aguda de la diverticulitis?","back":"Por el elevado riesgo de perforación colónica."},{"front":"Mencione tres complicaciones posibles de la diverticulitis.","back":"Abscesos, peritonitis, fístulas u obstrucción."},{"front":"¿A qué corresponde el Estadio 0 de la clasificación de Hinchey?","back":"Diverticulitis leve."},{"front":"¿A qué corresponde el Estadio Ia de la clasificación de Hinchey?","back":"Inflamación pericólica y flemón."},{"front":"¿A qué corresponde el Estadio Ib de la clasificación de Hinchey?","back":"Absceso menor a 5 cm en la proximidad del proceso inflamatorio primario."},{"front":"¿A qué corresponde el Estadio II de la clasificación de Hinchey?","back":"Absceso intraabdominal, pélvico o retroperitoneal distante al sitio primario."},{"front":"¿A qué corresponde el Estadio III de la clasificación de Hinchey?","back":"Peritonitis purulenta generalizada."},{"front":"¿A qué corresponde el Estadio IV de la clasificación de Hinchey?","back":"Peritonitis fecal."},{"front":"¿Cuál es el manejo inicial para un Hinchey Estadio 0?","back":"Manejo conservador y ambulatorio con reposo intestinal, líquidos y fibra."},{"front":"¿Cuál es el esquema antibiótico de elección para el manejo hospitalario de la diverticulitis?","back":"Ciprofloxacino o Ceftriaxona más Metronidazol por 7 a 10 días."},{"front":"¿Cuál es la indicación de primera elección para abscesos mayores a 5 cm (Estadio II)?","back":"Drenaje percutáneo."},{"front":"¿Cuál es el tratamiento quirúrgico para los Estadios III y IV de Hinchey?","back":"Laparotomía exploratoria con resección del segmento afectado, anastomosis primaria e ileostomía derivativa."},{"front":"¿Qué técnica quirúrgica electiva se prefiere para la diverticulitis complicada?","back":"Sigmoidectomía laparoscópica."},{"front":"¿Cuál es el estatus actual del procedimiento de Hartmann en el tratamiento de la diverticulitis?","back":"Se encuentra actualmente en desuso."},{"front":"Fisiopatológicamente, ¿por qué se forman los divertículos?","back":"Por un aumento de la presión intraluminal sumado a una debilidad de la musculatura colónica."},{"front":"¿Cuánto tiempo se debe esperar para realizar una cirugía electiva tras un episodio de diverticulitis controlada?","back":"De 6 a 8 semanas."},{"front":"En el contexto de diverticulosis, existe un aumento de la actividad _____ y una disminución de la actividad no colinérgica.","back":"colinérgica"},{"front":"¿A partir de qué volumen de pérdida hemática se hace presente la melena?","back":"Mayor a 100 ml."},{"front":"¿Qué patología debe descartarse primero en un paciente joven con sangrado de tubo digestivo bajo y anemia?","back":"Patología diverticular."},{"front":"Concepto: Flemón (en Hinchey Ia)","back":"Masa de tejido blando inflamado sin una cavidad de pus definida."},{"front":"¿Qué hallazgo en la exploración física sugiere irritación peritoneal en diverticulitis?","back":"Resistencia o dolor a la descompresión en la fosa ilíaca izquierda."},{"front":"El 95% de los _____ afectan al colon sigmoides, al igual que los divertículos.","back":"vólvulos"},{"front":"¿Qué porcentaje de personas mayores de 45 años padece diverticulosis?","back":"El 35%."},{"front":"En la enfermedad diverticular, no debe haber datos de _____, a diferencia de la diverticulitis.","back":"SRIS (Síndrome de Respuesta Inflamatoria Sistémica)"},{"front":"¿Cuál es la función del consumo alto de fibra en relación con la diverticulosis?","back":"Actúa como un factor protector."},{"front":"Si no se dispone de TAC para evaluar una diverticulitis, ¿cuál es el estudio de imagen alternativo?","back":"Ultrasonografía (USG)."},{"front":"La tríada clínica clásica de la diverticulitis incluye dolor en FII, fiebre y _____.","back":"leucocitosis"},{"front":"¿Qué síntoma gastrointestinal puede acompañar a la colitis asociada a divertículos?","back":"Diarrea y rectorragia."}]},"8":{"num":8,"name":"ABDOMEN AGUDO OBSTRUCTIVO","cards":[{"front":"¿Qué hallazgo clínico define la interrupción del tránsito intestinal en el abdomen agudo obstructivo?","back":"La incapacidad de expulsar gases y heces por el recto."},{"front":"¿Cuál es la causa principal de obstrucción de intestino delgado en pacientes con antecedentes de cirugía previa?","back":"Bridas o adherencias postquirúrgicas."},{"front":"En ausencia de antecedentes quirúrgicos, ¿cuál es la etiología más frecuente de la obstrucción de intestino delgado?","back":"Hernias."},{"front":"¿Qué tipo de ruidos peristálticos son característicos de una obstrucción intestinal mecánica?","back":"Ruidos metálicos (hiperperistaltismo)."},{"front":"¿Cómo se clasifica el contenido del vómito en una obstrucción intestinal proximal?","back":"Gastroalimentario."},{"front":"¿Qué característica presenta el vómito cuando la obstrucción de intestino delgado es de localización distal?","back":"Vómito fecaloide."},{"front":"Ante la presencia de fiebre, dolor continuo y rigidez muscular en una obstrucción intestinal, ¿qué complicación se debe sospechar?","back":"Estrangulación intestinal."},{"front":"¿Cuál es el estudio de imagen inicial para el diagnóstico de obstrucción intestinal?","back":"Radiografía de abdomen AP en bipedestación."},{"front":"¿A partir de qué diámetro se considera que existe dilatación de las asas de intestino delgado en una radiografía?","back":"> 3 cm."},{"front":"¿Qué nombre recibe el signo radiológico de asas delgadas dispuestas una sobre otra en la obstrucción intestinal?","back":"Imagen en pila de monedas."},{"front":"¿Qué hallazgo en la radiografía de abdomen indica la presencia de aire y líquido atrapados en las asas intestinales?","back":"Niveles hidroaéreos."},{"front":"¿Cuál es el estándar de oro (gold standard) para el diagnóstico de la obstrucción intestinal?","back":"Tomografía Axial Computarizada (TAC)."},{"front":"¿Cuál es el primer paso en el tratamiento de una obstrucción intestinal mecánica no complicada?","back":"Colocación de sonda nasogástrica (SNG) y reposición hidroelectrolítica."},{"front":"¿Cuál es el período máximo recomendado para mantener el manejo conservador en una oclusión por adherencias antes de considerar cirugía?","back":"De 48 a 72 horas."},{"front":"¿Cuál es la causa más frecuente de obstrucción en el intestino grueso?","back":"Cáncer (tumores colorrectales)."},{"front":"¿En qué región anatómica se localiza con mayor frecuencia el cáncer que causa obstrucción colónica?","back":"Recto-sigmoides."},{"front":"¿Cuál es el sitio con mayor riesgo de perforación en una obstrucción de colon con válvula ileocecal competente?","back":"El ciego."},{"front":"¿Qué hallazgo a la exploración física es indicativo de gran distensión gaseosa en la obstrucción de colon?","back":"Timpanismo abdominal."},{"front":"¿Cómo suele ser la instauración de la obstrucción intestinal debida a un proceso neoplásico?","back":"De forma lenta e insidiosa."},{"front":"¿Cuál es el volumen de drenaje por sonda nasogástrica que se considera un predictor de falla al tratamiento conservador?","back":"> 500 ml."},{"front":"¿Qué nivel de Proteína C Reactiva (PCR) sugiere la necesidad de intervención quirúrgica en una oclusión intestinal?","back":"> 75 mg/L (o UI/L según fuente)."},{"front":"¿Qué valor de Creatina Fosfoquinasa (CPK) se asocia a un fallo en el manejo médico de la obstrucción?","back":"> 130 UI/L."},{"front":"¿Cuál es el nombre técnico de la intervención quirúrgica para liberar adherencias intestinales?","back":"Adhesiolisis."},{"front":"¿Qué es un vólvulo de sigmoides?","back":"La torsión axial del sigmoides sobre su pedículo vascular."},{"front":"¿Qué porcentaje de los vólvulos colónicos corresponden a la localización sigmoidea?","back":"75%."},{"front":"¿Cuál es la causa principal de obstrucción intestinal durante el embarazo?","back":"Vólvulo de sigmoides."},{"front":"Mencione dos factores de riesgo para el desarrollo de vólvulo de sigmoides relacionados con el estilo de vida o edad.","back":"Edad mayor de 60 años y estreñimiento crónico."},{"front":"¿Qué enfermedad infecciosa crónica se asocia frecuentemente con el desarrollo de megacolon y vólvulo de sigmoides?","back":"Enfermedad de Chagas."},{"front":"¿Qué signo clínico se caracteriza por palpar una fosa ilíaca derecha vacía en el vólvulo?","back":"Signo de Dance."},{"front":"¿Cuál es el hallazgo radiológico más frecuente (90%) en un vólvulo de sigmoides?","back":"Ausencia de gas rectal."},{"front":"¿Cuál es el signo radiológico más sensible para el diagnóstico de vólvulo de sigmoides?","back":"Imagen en grano de café."},{"front":"¿Qué signo se observa en el enema de bario ante un vólvulo de sigmoides?","back":"Signo del as de espadas (o pico de pájaro)."},{"front":"¿Qué hallazgo es patognomónico del vólvulo de sigmoides en una TAC?","back":"Signo del remolino (o grano de café)."},{"front":"¿Cuál es el tratamiento inicial de elección para un paciente estable con vólvulo de sigmoides?","back":"Colonoscopía descompresiva (destorsión endoscópica)."},{"front":"Tras una descompresión exitosa de vólvulo de sigmoides, ¿qué porcentaje de recidiva se espera?","back":"30%."},{"front":"¿Cuál es la cirugía de urgencia indicada en un paciente inestable con vólvulo de sigmoides?","back":"Procedimiento de Hartmann."},{"front":"¿En qué consiste el vólvulo de ciego?","back":"En la torsión del ciego sobre el eje mesentérico."},{"front":"¿Cuál es el perfil epidemiológico típico del vólvulo de ciego?","back":"Mujeres de edad media con antecedentes de cirugías previas."},{"front":"¿Qué patrón radiológico se observa característicamente en el vólvulo de ciego?","back":"Asa desproporcionadamente dilatada más un patrón de oclusión de intestino delgado distal."},{"front":"¿Cuál es el tratamiento quirúrgico de elección para el vólvulo de ciego?","back":"Hemicolectomía derecha con anastomosis primaria."},{"front":"En pacientes con vólvulo de ciego y alto riesgo quirúrgico, ¿qué alternativa quirúrgica se puede realizar?","back":"Cecopexia."},{"front":"Ante un hombre de 25-40 años con vómito gastroalimentario y cicatrices abdominales, ¿cuál es el diagnóstico más probable?","back":"Obstrucción de intestino delgado por bridas."},{"front":"Ante un paciente masculino mayor de 60 años con pérdida de peso y estreñimiento crónico, ¿cuál es la sospecha principal de obstrucción?","back":"Cáncer colorrectal."},{"front":"¿Qué grupo de pacientes institucionalizados presenta un riesgo aumentado de vólvulos de colon?","back":"Pacientes con enfermedades neuropsiquiátricas (ej. Parkinson, retraso mental) o inmovilidad prolongada."},{"front":"¿Qué indicación quirúrgica absoluta existe si un paciente presenta edema del mesenterio y líquido intraperitoneal en la TAC?","back":"Falla al tratamiento conservador o sospecha de compromiso vascular."},{"front":"¿Qué condición clínica se sospecha en una mujer de 25-40 años con vómito fecaloide y antecedentes obstétricos?","back":"Vólvulo del ciego."},{"front":"La tríada clínica clásica de la obstrucción intestinal incluye dolor abdominal, distensión y _____.","back":"Vómitos."},{"front":"¿Qué complicación mecánica debe descartarse ante una hernia con dolor intenso y cambios de coloración cutánea?","back":"Hernia estrangulada."},{"front":"¿Cuál es el manejo definitivo programado tras una descompresión endoscópica exitosa de sigmoides?","back":"Resección de sigmoides y anastomosis primaria (cirugía electiva)."},{"front":"En el contexto de obstrucción intestinal, ¿cuándo se considera que el íleo meconial es un criterio quirúrgico?","back":"Cuando persiste por más de 3 días."},{"front":"El signo de la 'U' invertida en una radiografía de abdomen es característico de _____.","back":"Vólvulo de sigmoides."},{"front":"¿Cuál es el tratamiento definitivo mencionado para el vólvulo de sigmoides?","back":"Megasigmoidoplastía."},{"front":"¿Qué porcentaje de los casos de vólvulo corresponden al vólvulo de ciego?","back":"20%."},{"front":"¿Cuál es la principal causa de obstrucción de colon en pacientes con enfermedad inflamatoria intestinal (EII)?","back":"Estenosis o inflamación aguda (aunque el cáncer sigue siendo la causa general más común)."},{"front":"En la exploración física de un vólvulo, ¿qué porcentaje de pacientes presenta hipersensibilidad abdominal?","back":"81%."}]},"9":{"num":9,"name":"PATOLOGIA ISQUEMICA INTESTINAL","cards":[{"front":"¿Con qué otro nombre se conoce clínicamente a la isquemia mesentérica crónica?","back":"Angina intestinal"},{"front":"Etiología más frecuente de la isquemia mesentérica crónica","back":"Arteroesclerosis de las arterias mesentéricas"},{"front":"¿Qué vasos sanguíneos se ven afectados con mayor frecuencia en la isquemia mesentérica crónica?","back":"Tronco celíaco y arteria mesentérica superior"},{"front":"¿En qué sexo es más prevalente la isquemia mesentérica crónica?","back":"Mujeres"},{"front":"Características del dolor abdominal en la isquemia mesentérica crónica","back":"Sordo, de tipo cólico, localizado en el periumbilical o hipogastrio"},{"front":"¿Cuánto tiempo después de las comidas suele aparecer el dolor en la angina intestinal?","back":"15 a 30 minutos"},{"front":"¿Cuál es la causa de la pérdida de peso en pacientes con isquemia mesentérica crónica?","back":"Miedo a comer (sitofobia)"},{"front":"Hallazgo exploratorio presente en la mitad de los pacientes con isquemia crónica","back":"Soplo abdominal sistólico"},{"front":"Estándar de oro para el diagnóstico de isquemia mesentérica crónica","back":"Arteriografía"},{"front":"Tratamiento definitivo de elección para la isquemia mesentérica crónica","back":"Revascularización quirúrgica (bypass o endarterectomía)"},{"front":"Mortalidad estimada de la isquemia mesentérica crónica","back":"Menor al 10%"},{"front":"Definición de isquemia mesentérica aguda","back":"Disminución del flujo sanguíneo que compromete los requerimientos metabólicos intestinales"},{"front":"¿Cuál es la arteria más afectada en la isquemia mesentérica aguda?","back":"Arteria mesentérica superior"},{"front":"Causa más frecuente de isquemia mesentérica aguda","back":"Embólica"},{"front":"Antecedente cardíaco más importante relacionado con la etiología embólica","back":"Fibrilación auricular"},{"front":"Característica principal del dolor en la fase inicial de la embolia mesentérica","back":"Dolor intenso (10/10) que no guarda proporción con los hallazgos en la exploración física"},{"front":"Antecedente clínico característico en pacientes con isquemia mesentérica aguda de origen trombótico","back":"Enfermedad vascular previa o angina intestinal"},{"front":"¿Qué porcentaje de pacientes con angina intestinal evoluciona a una isquemia aguda por oclusión total?","back":"50%"},{"front":"Factores desencadenantes de la isquemia mesentérica no oclusiva","back":"Estados de bajo gasto cardíaco o uso de vasoconstrictores"},{"front":"Sustancias que pueden provocar vasoconstricción mesentérica no oclusiva","back":"Cocaína o descongestivos nasales"},{"front":"Factores de riesgo para desarrollar trombosis venosa mesentérica","back":"Hipertensión portal, sepsis o estados de hipercoagulabilidad"},{"front":"Tipo de dolor abdominal asociado a la trombosis venosa mesentérica","back":"Dolor abdominal sordo y menos intenso que el arterial"},{"front":"Signo clínico que puede presentarse en las evacuaciones durante una isquemia aguda","back":"Evacuaciones en jalea de grosella"},{"front":"¿Qué parámetro bioquímico suele elevarse antes de que la isquemia intestinal sea irreversible?","back":"Fosfato sérico"},{"front":"Nivel de dímero D sugerente de isquemia mesentérica aguda","back":"Mayor a 500 mcg"},{"front":"Significado clínico de la acidosis láctica en el contexto de isquemia intestinal","back":"Presencia de necrosis transmural"},{"front":"Estudio de imagen inicial para descartar perforación intestinal","back":"Radiografía de abdomen"},{"front":"Estudio de imagen de elección para el diagnóstico de isquemia mesentérica aguda","back":"Tomografía de abdomen contrastada"},{"front":"Estándar de oro para el diagnóstico definitivo de isquemia mesentérica aguda","back":"Arteriografía (angiografía)"},{"front":"Hallazgos tomográficos de isquemia mesentérica avanzada","back":"Neumatosis intestinal, gas en vena porta o engrosamiento de pared"},{"front":"Meta terapéutica de TPT para la anticoagulación en isquemia mesentérica","back":"2.5"},{"front":"Manejo de la isquemia embólica sin peritonitis y sin contraindicación para trombólisis","back":"Aspiración más trombólisis"},{"front":"Manejo quirúrgico de la isquemia embólica con contraindicación para trombólisis","back":"Embolectomía abierta"},{"front":"Tratamiento de elección para la isquemia mesentérica aguda trombótica sin peritonitis","back":"Colocación de stent"},{"front":"Indicación terapéutica para la isquemia mesentérica aguda con datos de peritonitis","back":"Laparotomía exploratoria"},{"front":"Tratamiento farmacológico de elección para la isquemia mesentérica no oclusiva","back":"Inyección de vasodilatadores (Papaverina)"},{"front":"Estrategia de manejo para la trombosis venosa mesentérica no complicada","back":"Anticoagulación precoz y mantenida de por vida"},{"front":"Contraindicaciones neurológicas absolutas para la trombólisis en isquemia mesentérica","back":"EVC hemorrágico, aneurisma intracraneal o EVC isquémico menor a 3 meses"},{"front":"Definición de colitis isquémica","back":"Insuficiencia circulatoria de la microvascularización del colon"},{"front":"¿Cuál es la forma más común de isquemia intestinal?","back":"Colitis isquémica"},{"front":"Región anatómica del colon afectada con mayor frecuencia en la colitis isquémica","back":"Ángulo esplénico (Punto de Griffith)"},{"front":"Factores de riesgo demográficos para la colitis isquémica","back":"Varones ancianos con enfermedades cardiovasculares, diabetes o insuficiencia renal"},{"front":"Síntomas clínicos característicos de la colitis isquémica inicial","back":"Dolor tipo cólico de inicio súbito y rectorragia"},{"front":"Estudio diagnóstico definitivo para la colitis isquémica","back":"Colonoscopía"},{"front":"Signo radiológico clásico observado en el enema opaco por colitis isquémica","back":"Imagen de impresiones digitales"},{"front":"Tratamiento inicial para la colitis isquémica transitoria","back":"Reposo alimentario, fluidos y antibióticos profilácticos"},{"front":"Indicación quirúrgica en colitis isquémica gangrenosa","back":"Resección segmentaria con o sin anastomosis"},{"front":"Territorios arteriales que irrigan el área esplácnica","back":"Mesentérica superior, mesentérica inferior y tronco celíaco"},{"front":"Mortalidad de la isquemia mesentérica aguda si se diagnostica de forma temprana","back":"Menor al 50%"},{"front":"¿Qué hallazgo bioquímico sugiere isquemia no oclusiva sensible a tratamiento médico?","back":"Mejoría del dolor tras el uso de vasodilatadores"},{"front":"Significado de la neumatosis intestinal en la tomografía","back":"Presencia de gas dentro de la pared intestinal, indicativo de isquemia grave"},{"front":"¿En qué fase de la isquemia mesentérica aguda el dolor no corresponde con la clínica exploratoria?","back":"Fase aguda"},{"front":"Hallazgo hematológico común en la isquemia mesentérica aguda","back":"Leucocitosis con desviación a la izquierda"},{"front":"Enzimas que suelen elevarse en el perfil bioquímico de un infarto intestinal","back":"DHL, fosfatasa alcalina y amilasa"},{"front":"Manejo quirúrgico para un émbolo mesentérico con necrosis establecida","back":"Embolectomía abierta más cirugía de control de daños"},{"front":"Efecto de la analgesia común sobre el dolor de la isquemia mesentérica aguda","back":"El dolor no se modifica con analgésicos convencionales"},{"front":"La colitis isquémica suele afectar preferentemente al colon izquierdo.","back":"Izquierdo"},{"front":"Duración habitual del dolor en la angina intestinal posprandial","back":"Varias horas"},{"front":"Factor etiológico no oclusivo relacionado con medicamentos de venta libre","back":"Descongestivos nasales"},{"front":"Relación entre la isquemia mesentérica aguda y la cirugía de control de daños","back":"Se utiliza tras realizar revascularización y resección de tejido necrótico con peritonitis"},{"front":"Principal diferencia diagnóstica entre isquemia aguda y crónica respecto a la urgencia","back":"La crónica permite diagnóstico precoz para prevenir el infarto, la aguda es una emergencia con alta mortalidad"},{"front":"Hallazgo en el enema opaco que desaconseja su uso rutinario en colitis aguda","back":"El riesgo de perforación y la baja especificidad frente a la colonoscopía"},{"front":"Manejo de la isquemia no oclusiva con datos de necrosis","back":"Cirugía"},{"front":"¿Qué condición médica previa hace más probable una isquemia trombótica frente a una embólica?","back":"Antecedente de angina intestinal o claudicación abdominal"},{"front":"Proporción de mortalidad general de la isquemia mesentérica aguda sin diagnóstico temprano","back":"60% a 90%"}]}},"gineco":{"1":{"num":1,"name":"INTRODUCCION A GINECOLOGIA","cards":[{"front":"¿Qué hormona libera el hipotálamo para regular el ciclo genital femenino?","back":"Hormona liberadora de gonadotropinas (GnRH)."},{"front":"¿Qué efecto tienen los pulsos rápidos de GnRH en la hipófisis?","back":"Estimulan la liberación de hormona luteinizante (LH)."},{"front":"¿Qué efecto tienen los pulsos lentos de GnRH en la hipófisis?","back":"Estimulan la liberación de hormona foliculoestimulante (FSH)."},{"front":"¿A qué capa del folículo ovárico estimula la FSH?","back":"A la capa de la granulosa."},{"front":"¿Cuál es la función principal de la FSH en el ovario?","back":"Inducir el crecimiento folicular."},{"front":"¿A qué capa del folículo ovárico estimula la LH?","back":"A la capa de la teca."},{"front":"¿Qué evento fisiológico es inducido por el pico de LH?","back":"La ovulación."},{"front":"¿Qué tipo de hormonas produce la capa de la teca bajo estímulo de la LH?","back":"Andrógenos."},{"front":"¿Qué enzima convierte los andrógenos en estrógenos en la granulosa?","back":"Aromatasa."},{"front":"¿Qué estructura produce la progesterona tras la ovulación?","back":"El cuerpo lúteo."},{"front":"¿Qué efecto tiene la progesterona sobre la temperatura corporal basal?","back":"Aumenta la temperatura aproximadamente 1°C."},{"front":"¿Cuál es el rango de duración normal de un ciclo menstrual según el material?","back":"Entre 24 y 38 días."},{"front":"¿Cuál es el volumen normal de hemorragia en un ciclo menstrual?","back":"Entre 5 y 80 ml."},{"front":"¿Cuál es el estrógeno predominante en la mujer en etapa reproductiva?","back":"Estradiol."},{"front":"¿Cuál es el estrógeno predominante durante el embarazo?","back":"Estriol."},{"front":"¿Cuál es el estrógeno predominante en la postmenopausia y en el SOP?","back":"Estrona."},{"front":"¿Qué norma oficial mexicana regula los servicios de planificación familiar?","back":"NOM 005."},{"front":"¿Qué mide el índice de Pearl en anticoncepción?","back":"El número de embarazos no planeados por cada 100 mujeres al año."},{"front":"¿Qué define la 'categoría 4' en los criterios de elegibilidad de la OMS?","back":"Riesgo inaceptable o contraindicación absoluta para el uso del método."},{"front":"¿Cuál es el mecanismo de acción principal del DIU de cobre?","back":"Produce un ambiente uterino hostil e inflamatorio que interfiere con la movilidad espermática."},{"front":"¿En qué pacientes se indica preferentemente el DIU de cobre según el texto?","back":"Mujeres mayores de 20 años nulíparas o con antecedentes de TVP, DM u obesidad."},{"front":"¿Cuál es el método anticonceptivo de emergencia de elección?","back":"El DIU de cobre."},{"front":"¿Cuál es el límite de tiempo para colocar el DIU de cobre como anticoncepción de emergencia?","back":"Dentro de las primeras 120 horas postcoitales."},{"front":"¿Cuál es el efecto secundario más común del DIU de cobre?","back":"Incremento del sangrado menstrual y dismenorrea."},{"front":"¿Qué patología metabólica es una contraindicación específica para el DIU de cobre?","back":"Enfermedad de Wilson."},{"front":"¿Cuál es la indicación principal del DIU de levonorgestrel además de la anticoncepción?","back":"Tratamiento de sangrados uterinos anormales (SUA)."},{"front":"¿Qué efecto secundario es frecuente tras el uso prolongado del DIU de levonorgestrel?","back":"Amenorrea."},{"front":"¿Cuál es el tiempo máximo para retirar un DIU en caso de embarazo?","back":"Hasta las 12 semanas de gestación (SDG)."},{"front":"¿Qué sustancia activa contiene el implante subdérmico?","back":"Levonorgestrel o Etonogestrel."},{"front":"¿Cuál es el mecanismo de acción del implante subdérmico?","back":"Inhibición de la ovulación y cambios en la consistencia del moco cervical."},{"front":"¿Cuál es el método anticonceptivo reversible más eficaz disponible?","back":"El implante subdérmico."},{"front":"¿Cuánto tiempo tarda en retornar la fertilidad tras retirar el implante subdérmico?","back":"Aproximadamente 3 meses."},{"front":"¿Cada cuánto tiempo se aplica la inyección de medroxiprogesterona de 150 mg?","back":"Cada 3 meses (12 semanas)."},{"front":"¿Qué efecto sobre la densidad ósea tiene el uso prolongado del inyectable trimestral?","back":"Produce una reducción de la densidad ósea que revierte al suspender el uso."},{"front":"¿Cuál es el mecanismo de acción de los anticonceptivos orales combinados (ACOS)?","back":"Inhiben la ovulación mediante la supresión de las gonadotropinas hipofisarias."},{"front":"¿En qué periodo del ciclo menstrual se recomienda iniciar los ACOS?","back":"Dentro de los primeros 5 días del ciclo."},{"front":"¿Por qué no se deben usar ACOS en los primeros 6 meses del postparto?","back":"Debido a que los estrógenos pueden disminuir la producción de leche materna."},{"front":"¿Qué conducta se debe seguir si una paciente vomita dentro de las 2 horas tras tomar un ACO?","back":"Debe tomar otra tableta lo más pronto posible."},{"front":"¿Qué método anticonceptivo es la elección durante la lactancia y el puerperio inmediato?","back":"Pastillas de progestágeno (minipíldora)."},{"front":"¿Cuál es la eficacia típica de los condones masculinos en el primer año de uso?","back":"Entre 15 y 21 embarazos por cada 100 mujeres."},{"front":"¿Cuántos condones por mes debe proveer la clínica según los puntos clave?","back":"Entre 12 y 15 condones."},{"front":"¿Cuál es la ventana de tiempo ideal para la pastilla de emergencia de levonorgestrel?","back":"Primeras 72 horas (aunque se menciona eficacia decreciente hasta las 120 h)."},{"front":"¿Cómo afecta un IMC > 25 a la eficacia de la pastilla de emergencia de levonorgestrel?","back":"Disminuye significativamente su eficacia."},{"front":"¿Cuál es el método definitivo con mayor efectividad global?","back":"La vasectomía."},{"front":"¿Qué técnicas se utilizan para realizar una vasectomía?","back":"Schmidt (convencional) y Li Shunqiang (sin bisturí)."},{"front":"¿Cuánto tiempo debe usarse un método de respaldo tras una vasectomía?","back":"Durante los primeros 3 meses o tras 20 a 25 eyaculaciones."},{"front":"¿Qué resultado en el espermograma post-vasectomía confirma el éxito del procedimiento?","back":"Azoospermia o menos de 100,000 espermatozoides inmóviles por campo."},{"front":"¿Cuál es la técnica de Oclusión Tubaria Bilateral (OTB) más utilizada?","back":"Técnica de Pomeroy."},{"front":"¿Bajo qué condiciones se puede realizar la reversión de la OTB?","back":"Pacientes menores de 37 años, sin daño tubárico y longitud de salpinge > 4 cm."},{"front":"¿Qué define a la infertilidad según el material proporcionado?","back":"Incapacidad para concebir tras un año de relaciones sexuales regulares sin anticonceptivos."},{"front":"¿A partir de qué edad de la mujer se reduce a 6 meses el tiempo para diagnosticar esterilidad?","back":"Mayores de 35 años."},{"front":"¿Cuál es el porcentaje de causa de infertilidad atribuido exclusivamente al factor femenino?","back":"Aproximadamente 37%."},{"front":"¿Qué nivel de progesterona en fase lútea confirma una ovulación correcta?","back":"Valores mayores a 10 ng/ml."},{"front":"¿Qué valor de progesterona sugiere anovulación en el estudio de infertilidad?","back":"Valores menores a 3 a 5 ng/ml."},{"front":"¿Cuál es la prueba de elección inicial para evaluar la permeabilidad tubárica?","back":"Histerosonosalpingografía."},{"front":"¿Cuál es el estándar de oro para diagnosticar anomalías uterinas?","back":"Histeroscopia."},{"front":"¿Qué procedimiento se prefiere si se sospecha de endometriosis como causa de infertilidad?","back":"Laparoscopia."},{"front":"¿Qué estudio se debe solicitar si se detecta azoospermia u oligozoospermia severa?","back":"Cariotipo."},{"front":"¿A partir de qué concentración espermática se define oligozoospermia?","back":"Menos de 20 millones de espermatozoides por ml."},{"front":"¿Qué término define la movilidad espermática reducida en un análisis de semen?","back":"Astenozoospermia."},{"front":"¿Cuál es el fármaco de primera elección para inducir la ovulación en casos de infertilidad?","back":"Citrato de clomifeno."},{"front":"¿Cuál es el mecanismo de acción del citrato de clomifeno?","back":"Inhibe los receptores estrogénicos a nivel hipotalámico."},{"front":"¿Qué fármaco se utiliza en pacientes con SOP para ayudar a inducir la ovulación?","back":"Metformina."},{"front":"¿En qué consiste la técnica de alta complejidad ICSI?","back":"Inyección intracitoplasmática de espermatozoides."},{"front":"¿Qué caracteriza al Síndrome de Hiperestimulación Ovárica (SHO)?","back":"Agrandamiento ovárico y aumento de permeabilidad capilar con acumulación de líquidos."},{"front":"¿Qué nivel de estradiol se considera un factor de riesgo para el SHO?","back":"Niveles mayores a 3,000 pg/ml."},{"front":"¿Cuál es el hallazgo clínico clave del SHO severo?","back":"Ascitis marcada y derrame pleural."},{"front":"¿Qué alteración de laboratorio define la severidad en el SHO?","back":"Hemoconcentración con hematocrito > 45%."},{"front":"¿Cuál es el tratamiento para el SHO leve o moderado?","back":"Manejo ambulatorio, hidratación adecuada y control de peso."},{"front":"¿Qué medida terapéutica es vital en el SHO severo para la reposición de líquidos?","back":"Administración de albúmina humana intravenosa."},{"front":"¿Qué función cumple la inhibina producida en la granulosa?","back":"Realiza una retroalimentación negativa sobre la liberación de FSH."},{"front":"¿En qué día del ciclo ocurre la ovulación en mujeres con ciclos regulares?","back":"En el día 14 del ciclo."},{"front":"¿Cuándo ocurre la ovulación en mujeres con ciclos irregulares?","back":"Dos semanas antes del inicio del sangrado menstrual."},{"front":"¿Cuál es el periodo de incapacidad tras una laparoscopia diagnóstica?","back":"7 días."},{"front":"¿Cuál es el periodo de incapacidad tras una laparotomía?","back":"14 días."},{"front":"¿En qué consiste el método MELA de planificación familiar?","back":"Ausencia de menstruación por el efecto fisiológico de la lactancia materna."},{"front":"¿Cuál es el tiempo máximo de efectividad del método MELA?","back":"Los primeros 6 meses postparto."},{"front":"¿Qué indicador sugiere éxito tras el uso de anticoncepción de emergencia?","back":"La presencia de sangrado a los 21 días del uso."},{"front":"¿Cuál es la técnica de salpingectomía parcial postparto más efectiva?","back":"Salpingectomía parcial (Pomeroy modificado)."},{"front":"¿Qué técnica de esterilización tubárica se considera la menos efectiva?","back":"Clips de resorte."},{"front":"¿Cuál es el rango de IMC asociado con dificultad para lograr el embarazo?","back":"Menor a 19 o mayor a 29."},{"front":"¿Qué antibióticos se recomiendan como profilaxis en pacientes jóvenes tras un DIU de emergencia?","back":"Doxiciclina más Azitromicina en dosis única."},{"front":"¿Qué estructura alcanza su pico funcional en el día 22 del ciclo genital?","back":"El cuerpo lúteo."},{"front":"¿Qué hormona inhibe el cuerpo lúteo para prevenir contracciones uterinas?","back":"Prostaglandina F2."},{"front":"¿Cuál es el seguimiento recomendado tras la inserción de un DIU?","back":"Revisión a las 3 y 6 semanas, y posteriormente de forma anual."}]},"10":{"num":10,"name":"PATOLOGIA INFECCIOSA CERVICAL","cards":[{"front":"¿Cuál es el mecanismo fisiopatológico básico de la Enfermedad Pélvica Inflamatoria (EPI)?","back":"Infección ascendente de gérmenes procedentes del cérvix."},{"front":"¿Qué porcentaje de los casos de EPI se considera de etiología polimicrobiana?","back":"75% de los casos."},{"front":"Agente etiológico de la EPI que es el principal según la Guía de Práctica Clínica (GPC):","back":"Neisseria gonorrhoeae."},{"front":"Agente etiológico de la EPI más frecuente a nivel mundial:","back":"Chlamydia trachomatis."},{"front":"¿Qué patógeno se asocia a EPI en usuarias de DIU durante las primeras 3 semanas tras su colocación?","back":"Actinomyces israelii."},{"front":"Menciona dos asociaciones o secuelas reproductivas graves de la EPI:","back":"Embarazos ectópicos e infertilidad."},{"front":"¿Cuál es el factor protector mencionado para la Enfermedad Pélvica Inflamatoria?","back":"Uso de anticonceptivos hormonales orales."},{"front":"¿Qué síntoma clínico está presente en el 90% de las pacientes con EPI?","back":"Dolor abdominal bajo."},{"front":"¿Cuál es el 'dato pivote' durante el examen bimanual en una sospecha de EPI?","back":"Dolor a la movilización cervical."},{"front":"¿Qué hallazgo en la exploración física sugiere la presencia de un absceso en pacientes con EPI?","back":"Presencia de una masa anexial."},{"front":"Según la clasificación de Monif, ¿qué caracteriza al Grado I?","back":"EPI sin masa anexial ni datos de irritación peritoneal."},{"front":"Según la clasificación de Monif, ¿qué define al Grado II?","back":"EPI con masa anexial o abscesos, con o sin signos de irritación peritoneal."},{"front":"Según la clasificación de Monif, ¿cuál es el hallazgo distintivo del Grado III?","back":"Absceso tubo-ovárico roto o datos de irritación peritoneal generalizada."},{"front":"¿Qué añade el Grado IV a la clasificación de Monif en EPI?","back":"Datos de respuesta inflamatoria sistémica."},{"front":"¿Cuál es el método diagnóstico de primera elección (imagen) para la EPI?","back":"Ultrasonido transvaginal."},{"front":"¿Cuál es el estándar de oro (Gold Standard) para el diagnóstico de EPI?","back":"Laparoscopía."},{"front":"¿En qué situación específica se indica realizar una laparoscopía en EPI?","back":"En caso de duda diagnóstica para diferenciar de apendicitis o embarazo ectópico."},{"front":"Prueba específica para confirmar Neisseria gonorrhoeae en pacientes con EPI:","back":"Frotis con tinción de Gram."},{"front":"Prueba específica para confirmar Chlamydia trachomatis en pacientes con EPI:","back":"Inmunofluorescencia."},{"front":"¿Qué marcadores inflamatorios inespecíficos se encuentran aumentados en la EPI?","back":"Proteína C Reactiva (PCR) y Velocidad de Sedimentación Globular (VSG)."},{"front":"Tratamiento ambulatorio de elección para EPI leve o moderada según la disponibilidad en el sector salud:","back":"Levofloxacino más Metronidazol."},{"front":"¿En qué plazo se debe citar a una paciente con EPI ambulatoria para evaluar la respuesta al tratamiento?","back":"A las 72 horas."},{"front":"Menciona tres criterios absolutos para el tratamiento hospitalario de la EPI:","back":"Casos graves (Monif III-IV), embarazadas y falla al tratamiento ambulatorio."},{"front":"Esquema de tratamiento hospitalario para EPI que utiliza Ceftriaxona:","back":"Ceftriaxona 250 mg IM + Doxiciclina 100 mg c/12h + Metronidazol 400 mg c/12h."},{"front":"¿Por cuánto tiempo se debe completar el tratamiento antibiótico total en EPI?","back":"14 días."},{"front":"Antibiótico alternativo en EPI hospitalaria en caso de alergia a cefalosporinas:","back":"Azitromicina."},{"front":"¿Cuál es el tiempo de incapacidad recomendado para una paciente con EPI leve a moderada?","back":"De 3 a 5 días."},{"front":"¿Cuál es la secuela más frecuente de la Enfermedad Pélvica Inflamatoria?","back":"Dolor pélvico crónico."},{"front":"En una tinción de Gram para Gonorrea, ¿qué hallazgo se reporta específicamente?","back":"Diplococos Gram negativos intracelulares."},{"front":"Definición del Síndrome de Fitz-Hugh-Curtis:","back":"Perihepatitis de la cara anterior derecha secundaria al ascenso de Chlamydia."},{"front":"¿Cuál es el dato patognomónico visualizado en la laparoscopía del Síndrome de Fitz-Hugh-Curtis?","back":"Adherencias perihepáticas en 'cuerda de violín'."},{"front":"Tratamiento quirúrgico indicado para el Síndrome de Fitz-Hugh-Curtis:","back":"Adhesiólisis laparoscópica."},{"front":"¿Cuál es el Gold Standard diagnóstico para la Endocervicitis?","back":"Pruebas de Amplificación de Ácidos Nucleicos (NAAT)."},{"front":"Tratamiento de dosis única para la infección por Chlamydia en endocervicitis:","back":"Azitromicina 1 g vía oral."},{"front":"¿Cuál es la causa número uno de vaginitis?","back":"Vaginosis Bacteriana."},{"front":"Agente etiológico principal de la Vaginosis Bacteriana:","back":"Gardnerella vaginalis."},{"front":"Características típicas de la leucorrea en la Vaginosis Bacteriana:","back":"Grisácea, con olor a pescado y sin prurito."},{"front":"¿Cuál es el valor del pH vaginal en la Vaginosis Bacteriana?","back":"pH > 4.5."},{"front":"En el diagnóstico de Vaginosis Bacteriana, ¿cuál es el dato más específico al microscopio?","back":"Presencia de células clave (clue cells)."},{"front":"Menciona los cuatro criterios de Amsel para el diagnóstico de Vaginosis Bacteriana:","back":"pH > 4.5, olor a pescado (KOH+), células clave y leucorrea característica."},{"front":"Tratamiento de elección para la Vaginosis Bacteriana:","back":"Metronidazol 500 mg cada 12 horas por 7 días."},{"front":"Clasificación utilizada para evaluar la flora vaginal (Grados I, II y III):","back":"Clasificación de Hay/Ison."},{"front":"¿A qué grupo de pacientes con Vaginosis Bacteriana se les DEBE dar tratamiento aunque sean asintomáticas?","back":"Mujeres embarazadas o pacientes que serán sometidas a procedimientos quirúrgicos."},{"front":"¿Cuál es el manejo de la pareja sexual en casos de Vaginosis Bacteriana?","back":"No se requiere tratar a la pareja."},{"front":"Causa número uno de cervicovaginitis sintomática:","back":"Candidiasis vaginal."},{"front":"¿Qué patógeno causa el 90% de los casos de Candidiasis vaginal?","back":"Candida albicans."},{"front":"Descripción macroscópica clásica del flujo en la Candidiasis:","back":"Blanquecino con grumos (aspecto de queso cottage)."},{"front":"¿Cuál es la principal característica clínica subjetiva de la Candidiasis vaginal?","back":"Prurito vulvar intenso."},{"front":"¿Cómo se encuentra el pH vaginal en una infección por Candida?","back":"Normal (4.0 - 4.5)."},{"front":"Menciona tres factores de riesgo para Candidiasis vaginal recurrente:","back":"Diabetes mellitus, obesidad y uso de antibióticos de amplio espectro."},{"front":"Estudio de elección inicial para confirmar Candidiasis vaginal:","back":"Frotis en fresco (observación de levaduras o hifas)."},{"front":"Tratamiento local de primera línea para Candidiasis vaginal en pacientes gestantes:","back":"Clotrimazol."},{"front":"Tratamiento de primera línea para Candidiasis vaginal no complicada (vía oral):","back":"Fluconazol dosis única."},{"front":"¿Qué esquema de mantenimiento se recomienda para Candidiasis recurrente por C. glabrata?","back":"Fluconazol 150 mg una vez por semana durante 6 meses."},{"front":"¿Qué tipo de microorganismo es Trichomonas vaginalis?","back":"Protozoo flagelado."},{"front":"Única cervicovaginitis del grupo considerada estrictamente una Enfermedad de Transmisión Sexual (ETS):","back":"Tricomoniasis."},{"front":"Hallazgo colposcópico característico ('patognomónico') de la Tricomoniasis:","back":"Eritema cervical o 'cérvix en fresa'."},{"front":"Descripción del flujo vaginal en la Tricomoniasis:","back":"Amarillo-verdoso, espumoso y fétido."},{"front":"Gold Standard para el diagnóstico de Tricomoniasis:","back":"Cultivo vaginal en medio Diamond."},{"front":"Manejo esencial respecto a los contactos sexuales en la Tricomoniasis:","back":"Tratar a la paciente y a todas sus parejas de los últimos 6 meses."},{"front":"Tratamiento de elección para Tricomoniasis (tanto en embarazadas como no embarazadas):","back":"Metronidazol (2 g dosis única o 500 mg c/12h por 7 días)."},{"front":"¿Qué sospecha diagnóstica debe tenerse ante casos recurrentes de Tricomoniasis?","back":"Infección por VIH."},{"front":"Definición de Bartholinitis:","back":"Infección e inflamación de la glándula de Bartolino, en la cara interna del labio mayor."},{"front":"¿En qué grupo de edad predomina la Bartholinitis?","back":"Mujeres en edad reproductiva (20 a 40 años)."},{"front":"¿Cuál es la ubicación anatómica exacta de la tumefacción en la Bartholinitis?","back":"Región posterior de los labios mayores."},{"front":"Tratamiento inicial para un absceso de la glándula de Bartolino:","back":"Incisión y drenaje."},{"front":"Procedimiento quirúrgico indicado en Bartholinitis ante recurrencias:","back":"Marsupialización."},{"front":"¿Qué agentes infecciosos se asocian con mayor frecuencia a la Bartholinitis?","back":"E. coli y Neisseria gonorrhoeae."},{"front":"¿Cuál es la conducta recomendada ante una paciente con EPI que tiene un DIU colocado?","back":"No se debe retirar el DIU."},{"front":"Criterio de envío a segundo nivel en casos de cervicovaginitis:","back":"Falla al tratamiento de primera línea o infecciones por especies distintas a C. albicans."},{"front":"¿Qué efecto tienen los azoles tópicos sobre los métodos de barrera?","back":"Dañan los condones y diafragmas de látex."},{"front":"Características de la secreción vaginal normal:","back":"Inodora, clara, viscosa, pH < 4.5 y ausencia de neutrófilos."},{"front":"¿Qué diagnóstico sugiere un dolor en cuadrante superior derecho irradiado a hombro con antecedente de EPI?","back":"Síndrome de Fitz-Hugh-Curtis."},{"front":"¿A qué glándulas invade la Trichomonas vaginalis en el 90% de los casos?","back":"Glándulas parauretrales."},{"front":"¿Cuál es el síntoma predominante de la Vaginosis Bacteriana?","back":"Leucorrea fétida (olor a pescado)."},{"front":"¿Qué otro microorganismo, además de los clásicos, puede causar Vaginosis Bacteriana?","back":"Mycoplasma hominis."},{"front":"¿Qué complicación obstétrica se asocia a la Vaginosis Bacteriana?","back":"Parto prematuro y ruptura prematura de membranas."},{"front":"Definición de Candidiasis recurrente:","back":"Más de 4 episodios documentados por año."},{"front":"Tratamiento de segunda línea para Vaginosis o Tricomoniasis en caso de falla o alternativa al Metronidazol:","back":"Tinidazol."},{"front":"Antibiótico indicado para pacientes con Vaginosis Bacteriana alérgicas al Metronidazol:","back":"Clindamicina."}]},"11":{"num":11,"name":"CONTROL PRENATAL PARTE 1","cards":[{"front":"¿En qué sitio anatómico ocurre frecuentemente la fecundación durante el primer día posovulación?","back":"Ámpula (ampolla de la trompa de Falopio)."},{"front":"¿Qué estructura resulta de la unión del óvulo y el espermatozoide antes de dividirse en mórula?","back":"Cigoto."},{"front":"¿En qué días tras la ovulación ocurre típicamente la implantación del blastocisto?","back":"Día 6 o 7."},{"front":"Dentro de la estructura del blastocisto, ¿qué parte dará origen a la placenta?","back":"Trofoblasto."},{"front":"Dentro de la estructura del blastocisto, ¿qué parte dará origen al feto?","back":"Masa celular interna."},{"front":"¿A partir de qué mes de gestación la placenta alcanza su estructura definitiva con división en cotiledones?","back":"Quinto mes."},{"front":"¿Cuál es la principal función de la placenta como barrera mecánica?","back":"Evitar la comunicación directa entre la circulación materna y la fetal."},{"front":"¿Qué hormona es producida por el trofoblasto desde etapas tempranas del embarazo?","back":"β-HCG (Hormona Gonadotropina Coriónica Humana)."},{"front":"¿Qué estructura produce la progesterona antes de la semana 6 de gestación?","back":"Cuerpo lúteo."},{"front":"¿Cuál es el precursor bioquímico necesario para la producción de progesterona en el embarazo?","back":"Colesterol."},{"front":"¿A través de qué mecanismo de transporte pasan el O₂ y el CO₂ por la placenta?","back":"Difusión simple."},{"front":"¿A través de qué mecanismo de transporte se intercambia la glucosa en la placenta?","back":"Difusión facilitada."},{"front":"¿Qué sustancias utilizan el transporte activo para cruzar la barrera placentaria?","back":"Hierro, aminoácidos y vitaminas hidrosolubles."},{"front":"¿Qué tipo de anticuerpos maternos pueden cruzar la placenta mediante pinocitosis?","back":"IgG."},{"front":"¿Qué inmunoglobulina no puede atravesar la barrera placentaria debido a su peso molecular?","back":"IgM."},{"front":"¿En qué porcentaje aproximado aumenta el volumen vascular total durante la gestación?","back":"40%."},{"front":"¿En qué semanas de gestación se alcanza el pico máximo del aumento del volumen vascular?","back":"Semanas 28 a 32."},{"front":"¿Qué tipo de soplo cardiaco puede considerarse funcional (no patológico) durante el embarazo?","back":"Soplo sistólico funcional."},{"front":"¿Cuál es el comportamiento fisiológico de la presión arterial durante los dos primeros trimestres del embarazo?","back":"Disminuye progresivamente."},{"front":"¿Qué cambios se observan frecuentemente en el eje eléctrico del ECG de una embarazada?","back":"Desviación del eje a la izquierda."},{"front":"¿Cuál es el incremento porcentual esperado de la frecuencia cardiaca durante el embarazo?","back":"15% a 20%."},{"front":"Mencione tres factores de coagulación dependientes de vitamina K que aumentan en el embarazo.","back":"Factores VII, IX y X."},{"front":"¿Cuál es el peso aproximado del útero al final de la gestación en comparación con su peso basal?","back":"1100 g (frente a 70 g normales)."},{"front":"¿Qué cantidad total de agua acumula aproximadamente una mujer durante el embarazo?","back":"6.5 L."},{"front":"¿Cuál es la tríada metabólica característica de los carbohidratos en la fisiología del embarazo?","back":"Hipoglicemia leve en ayunas, hiperglucemia posprandial e hiperinsulinemia."},{"front":"¿A partir de qué semana aparece la hidronefrosis fisiológica en la embarazada?","back":"Semana 6."},{"front":"¿Qué porcentaje de aumento experimenta el flujo plasmático renal durante el embarazo?","back":"50%."},{"front":"¿Cómo afecta la progesterona a la musculatura lisa intestinal?","back":"Produce relajación, disminuyendo la motilidad intestinal."},{"front":"¿A qué complicaciones gastrointestinales predispone la hipotonía vesicular por progesterona?","back":"Litiasis biliar."},{"front":"¿Qué cambio ocurre en los islotes de células beta del páncreas materno?","back":"Hipertrofia e hiperplasia."},{"front":"¿En qué medida cambia el nivel de cortisol sérico durante la gestación?","back":"Se duplica."},{"front":"¿A partir de qué semana la madre suele percibir los movimientos fetales?","back":"Semanas 14 a 16."},{"front":"¿Cuántas consultas prenatales mínimas establece la NOM para un embarazo normal?","back":"5 consultas."},{"front":"¿Cuál es el número ideal de consultas prenatales según la GPC 2022?","back":"10 a 12 consultas."},{"front":"¿En qué periodo se recomienda realizar la primera consulta prenatal según la NOM?","back":"Entre las semanas 6 y 8."},{"front":"¿Cuál es la dosis recomendada de ácido fólico para una paciente sin factores de riesgo?","back":"0.4 mg (o 400 μg) diarios."},{"front":"¿En qué casos se debe prescribir una dosis de 5 mg de ácido fólico?","back":"Antecedentes de DTN, DM descontrolada, uso de anticonvulsivos o tabaquismo activo/pasivo."},{"front":"¿Qué cantidad de hierro suplementario se recomienda a partir de la semana 20?","back":"30 a 60 mg diarios."},{"front":"¿Cuál es el límite máximo recomendado de cafeína al día para una embarazada?","back":"Menos de 200 mg (2 tazas de café)."},{"front":"¿Qué manejo dietético se sugiere para una paciente con náuseas y vómitos sin desequilibrio hidroelectrolítico?","back":"Dieta blanda o seca, fraccionada en 5-6 tomas al día."},{"front":"¿Cuál es el parámetro ecográfico más preciso para datar la edad gestacional en el primer trimestre?","back":"Longitud cráneo-caudal (LCC)."},{"front":"¿Qué hallazgo ultrasonográfico es indicativo de un embarazo gemelar bicorial?","back":"Signo de Lambda."},{"front":"¿Qué hallazgo ultrasonográfico es indicativo de un embarazo gemelar monocorial?","back":"Signo de T."},{"front":"¿En qué rango de semanas se realiza el ultrasonido estructural para valorar malformaciones?","back":"Semanas 18 a 22."},{"front":"¿A partir de qué nivel de β-HCG debería ser visible el saco gestacional por ultrasonido?","back":"Mayor a 1500 mUI/ml."},{"front":"¿Qué tipo de vacunas están estrictamente contraindicadas durante el embarazo?","back":"Vacunas de virus vivos atenuados."},{"front":"¿En qué periodo gestacional se debe aplicar la vacuna Tdpa si la paciente tiene esquema completo de Td?","back":"Semanas 28 a 36."},{"front":"¿Qué define al Signo de Chadwick?","back":"Coloración azulada de la vulva y vagina por aumento de la vascularidad."},{"front":"¿En qué semana es detectable la β-HCG en sangre materna?","back":"Tercera semana."},{"front":"¿Cuál es la fórmula de Naegele para calcular la fecha probable de parto (FPP)?","back":"FUM + 7 días - 3 meses + 1 año."},{"front":"¿Qué sugiere una altura de fondo uterino mayor a la esperada por edad gestacional?","back":"Diabetes gestacional o embarazo molar."},{"front":"¿Cuál es el rango de ganancia de peso total recomendado para una paciente con IMC normal (19.9-24.8)?","back":"11 a 16.5 kg."},{"front":"¿En qué trimestre del embarazo ocurre la ganancia de peso más rápida?","back":"Segundo trimestre."},{"front":"Concepto: Situación Fetal","back":"Relación entre el eje longitudinal del feto y el eje longitudinal de la madre (longitudinal, transversa u oblicua)."},{"front":"Concepto: Actitud Fetal","back":"Relación que guardan entre sí las distintas partes que constituyen el feto."},{"front":"¿Qué evalúa la primera maniobra de Leopold?","back":"La altura del fondo uterino y la situación fetal."},{"front":"¿Qué evalúa la segunda maniobra de Leopold?","back":"La posición fetal (dorso derecho o izquierdo)."},{"front":"¿Qué evalúa la tercera maniobra de Leopold?","back":"La presentación fetal (cefalica o podálica)."},{"front":"¿Qué evalúa la cuarta maniobra de Leopold?","back":"El grado de encajamiento de la presentación en la pelvis."},{"front":"¿Cuál es la causa quirúrgica no obstétrica más común durante el embarazo?","back":"Apendicitis."},{"front":"¿Cuántas calorías adicionales se deben agregar a la dieta diaria durante el embarazo?","back":"300 a 400 kcal."},{"front":"¿Cuál es el número mínimo de movimientos fetales que se deben percibir en un periodo de 2 horas?","back":"10 movimientos."},{"front":"¿Cuál es la duración del efecto protector de una dosis de inmunoglobulina Anti-D?","back":"6 semanas."},{"front":"¿Qué método clínico se utiliza para establecer el peso fetal estimado?","back":"Método de Johnson."},{"front":"¿Cuál es el tratamiento de primera línea para el reflujo gastroesofágico en el embarazo?","back":"Carbonato de magnesio o hidróxido de aluminio con simeticona."},{"front":"¿Qué fármacos se recomiendan para el manejo de la hiperémesis gravídica?","back":"Piridoxina-doxilamina, prometazina o metoclopramida."},{"front":"¿A qué complicaciones se asocia la exposición materna a calor extremo?","back":"Defectos del tubo neural y abortos."},{"front":"¿Cuál es el rango de presión de las contracciones de Braxton Hicks?","back":"5 a 25 mmHg."},{"front":"¿En qué semana de gestación se suele solicitar el segundo tamiz de glucosa?","back":"Semanas 24 a 28."},{"front":"Si una paciente no tiene antecedentes de vacunación contra el tétanos, ¿cuántas dosis de Td/Tdpa debe recibir?","back":"3 dosis (inicial, a las 4-8 semanas y a los 6-12 meses)."}]},"12":{"num":12,"name":"CONTROL PRENATAL PARTE 2","cards":[{"front":"¿Qué porcentaje de mujeres embarazadas padece enfermedad periodontal?","back":"El 30% de las pacientes."},{"front":"La enfermedad periodontal durante el embarazo se asocia principalmente a parto pretérmino y _____.","back":"Ruptura prematura de membranas (RPM)"},{"front":"¿Cuál es la concentración recomendada del enjuague bucal con clorhexidina para la salud bucal prenatal?","back":"Al 0.12%."},{"front":"Para evitar la compresión de la vena cava en el sillón dental, se debe elevar la cadera derecha de la paciente entre _____ cm.","back":"10 a 12 cm"},{"front":"¿En qué posición inclinada debe colocarse la paciente en el sillón dental si no se eleva la cadera derecha?","back":"Sobre el lado izquierdo de 5 a 15 grados."},{"front":"¿En qué consulta se debe determinar obligatoriamente el grupo sanguíneo y el factor Rh?","back":"En la primera consulta de control prenatal."},{"front":"¿Qué prueba se solicita si una paciente embarazada tiene un grupo Rh negativo?","back":"Test de Coombs indirecto."},{"front":"La prueba que detecta anticuerpos circulantes contra eritrocitos en la madre se denomina Test de _____.","back":"Coombs Indirecto"},{"front":"¿Qué detecta el Test de Coombs directo realizado en el neonato?","back":"Anticuerpos fijados a eritrocitos hemolizados."},{"front":"Si una paciente Rh negativo recibe su primera dosis de inmunoglobulina en el primer trimestre, ¿cuándo debe recibir la segunda?","back":"A las 28 semanas de gestación."},{"front":"Si la primera dosis de inmunoglobulina anti-D se administra entre las semanas 13 y 20, ¿cuándo se aplica la segunda?","back":"A las 34 semanas de gestación."},{"front":"¿Cuál es el tiempo límite para administrar la inmunoglobulina anti-D tras el parto si la madre es Rh negativa?","back":"Dentro de las primeras 72 horas postparto."},{"front":"Ante una paciente embarazada Rh negativo con pareja Rh positivo y Coombs indirecto positivo, ¿cuál es la conducta a seguir?","back":"Referir a segundo nivel para recibir tratamiento por sensibilización."},{"front":"¿Qué tipo de inmunoglobulina media la incompatibilidad al Rh y es capaz de atravesar la placenta?","back":"La inmunoglobulina G (IgG)."},{"front":"La incompatibilidad del grupo ABO está mediada por la inmunoglobulina _____, la cual no atraviesa la placenta.","back":"IgM"},{"front":"¿Cuál es la dosis estándar de inmunoglobulina humana anti-D para neutralizar hasta 30 ml de sangre fetal?","back":"300 μ g (1500 UI)."},{"front":"¿Qué dosis de inmunoglobulina anti-D se recomienda en sangrados ocurridos antes de las 12 semanas de gestación?","back":"150 μ g (750 UI)."},{"front":"¿Cuál es la cantidad mínima de sangre fetal necesaria para causar sensibilización materna?","back":"0.1 ml."},{"front":"¿Cuál es el periodo de tiempo en que puede presentarse la depresión posparto?","back":"Desde el parto hasta los 12 meses del nacimiento."},{"front":"En México, la prevalencia de la depresión prenatal y posparto oscila entre el _____.","back":"9% y el 13%."},{"front":"¿Cuál es el estándar de oro para el diagnóstico de depresión en el embarazo?","back":"Entrevista diagnóstica con criterios del DSM-V."},{"front":"¿Con qué escala se realiza el tamizaje de depresión posparto?","back":"Escala de Edimburgo."},{"front":"¿A partir de cuántos puntos en la Escala de Edimburgo se debe iniciar tratamiento cognitivo-conductual?","back":"Más de 10 puntos."},{"front":"El tratamiento de primera línea para la depresión prenatal es la _____.","back":"Terapia cognitivo-conductual"},{"front":"¿Cuáles son los dos antidepresivos de elección si falla el tratamiento no farmacológico en la depresión posparto?","back":"Sertralina o paroxetina."},{"front":"¿Qué categoría de riesgo se le asigna al uso de paroxetina durante el embarazo?","back":"Riesgo D."},{"front":"¿Cuál es el principal agente bacteriano causante de infecciones de vías urinarias en el embarazo?","back":"Escherichia coli."},{"front":"¿Qué estudio es la elección para el tamizaje obligatorio de bacteriuria asintomática en la primera consulta?","back":"Urocultivo."},{"front":"Tratamiento de primera elección para infecciones de vías urinarias bajas en el embarazo:","back":"Fosfomicina 3 g en dosis única."},{"front":"¿Cuál es el esquema de administración de nitrofurantoína para el tratamiento de IVU bajas?","back":"100 mg cada 12 horas por 5 días."},{"front":"¿En qué trimestres del embarazo se debe evitar el uso de nitrofurantoína?","back":"En el primero y el tercer trimestre."},{"front":"Se define bacteriuria asintomática como la presencia de bacterias en orina mayor a _____ UFC.","back":"100,000 UFC"},{"front":"¿En qué porcentaje incrementa la bacteriuria asintomática el riesgo de pielonefritis?","back":"En un 20% a 30%."},{"front":"¿Por qué la bacteriuria asintomática aumenta el riesgo de parto pretérmino?","back":"Por el aumento de ácido araquidónico, fosfolipasa A2 y prostaglandinas."},{"front":"Durante el primer trimestre, el aumento de la _____ puede causar un falso hipertiroidismo.","back":"Gonadotropina coriónica humana (hCG)"},{"front":"¿Cuál es el fármaco de elección para tratar la enfermedad de Graves en el primer trimestre?","back":"Propiltiouracilo."},{"front":"¿Qué fármaco se utiliza para la enfermedad de Graves después del primer trimestre?","back":"Metimazol (o Carbimazol)."},{"front":"Si una paciente con Graves requiere tiroidectomía, ¿en qué trimestre se debe realizar preferentemente?","back":"En el segundo trimestre."},{"front":"¿Qué complicación fetal puede resultar del uso excesivo de tionamidas por parte de la madre?","back":"Hipotiroidismo fetal o defectos congénitos."},{"front":"En mujeres con hipotiroidismo que desean embarazarse, se debe mantener una TSH menor a _____.","back":"2.5 mUI/L"},{"front":"¿A partir de qué valor de TSH se considera hipotiroidismo clínico independientemente de los niveles de T4L?","back":"Mayor a 10 mUI/L."},{"front":"Se define hipotiroidismo subclínico en el embarazo como una TSH mayor a 2.5 mUI/L con presencia de anticuerpos _____.","back":"Anti-TPO positivos"},{"front":"¿Cuál es la dosis inicial recomendada de levotiroxina durante el embarazo?","back":"1.2 μ g/kg/día."},{"front":"¿En qué porcentaje se debe aumentar la dosis de levotiroxina en una paciente con hipotiroidismo preexistente al embarazarse?","back":"Entre un 25% y un 30%."},{"front":"¿Cuál es la meta de TSH durante el primer trimestre del embarazo?","back":"0.1 a 2.5 mUI/L."},{"front":"¿Cuál es la meta de TSH durante el segundo trimestre del embarazo?","back":"0.2 a 3.0 mUI/L."},{"front":"¿A partir de qué semana de gestación se realiza el registro cardiotocográfico en embarazos de riesgo?","back":"A partir de la semana 28."},{"front":"¿Cuál es el rango normal de la frecuencia cardíaca fetal (FCF)?","back":"Entre 120 y 160 latidos por minuto."},{"front":"¿Qué condición materna se asocia frecuentemente con bradicardia fetal?","back":"Hipoglucemia materna."},{"front":"En el registro cardiotocográfico, las desaceleraciones que ocurren simultáneamente con la contracción se llaman _____.","back":"DIP I (o tempranas)"},{"front":"¿Qué significan las desaceleraciones tipo DIP II (o tardías)?","back":"Que las desaceleraciones no corresponden temporalmente con la contracción."},{"front":"¿Cuál es el rango de variabilidad normal en un registro cardiotocográfico?","back":"Entre 10 y 25 latidos."},{"front":"Un registro cardiotocográfico se considera positivo si presenta más del _____ de DIP II en 10 contracciones.","back":"30%"},{"front":"¿Cuál es el marcador ecográfico de mayor importancia para la detección de cromosomopatías en el primer trimestre?","back":"Translucencia nucal."},{"front":"¿Qué prueba de tamizaje sérico compone el 'Duo Test' del primer trimestre?","back":"bhCG y PAPP-A."},{"front":"¿Cuál es el marcador más sensible para cromosomopatías en el segundo trimestre?","back":"Hipoplasia nasal."},{"front":"Periodo de gestación recomendado para realizar una biopsia corial:","back":"Semana 9 a 13 de gestación."},{"front":"Periodo de gestación indicado para realizar una amniocentesis según la GPC:","back":"Semana 16 a 20 de gestación."},{"front":"¿A partir de qué semana de gestación se puede realizar una cordocentesis?","back":"A partir de la semana 20."},{"front":"Mencione una causa no estrogénica de trombosis durante el embarazo:","back":"Disminución de la actividad fibrinolítica."},{"front":"¿Qué sustancias, además de la insulina y la heparina, no atraviesan la placenta?","back":"Inmunoglobulina M (IgM)."},{"front":"¿Cuál es la complicación neonatal más importante en hijos de madres con lupus y anticuerpos Anti-Ro/Anti-La?","back":"Bloqueo auriculoventricular (AV)."}]},"13":{"num":13,"name":"HEMORRAGIAS DE PRIMER TRIMESTRE","cards":[{"front":"¿Cómo se define el aborto según la edad gestacional y el peso fetal?","back":"Es la interrupción del embarazo antes de las 22 SDG o antes de que el feto alcance los 500 gramos."},{"front":"¿A partir de qué semana se considera que un aborto es tardío?","back":"Después de las 14 SDG."},{"front":"¿Cuál es la definición de aborto recurrente?","back":"La presencia de 2 o más abortos consecutivos o 5 intercalados."},{"front":"¿Cuál es la causa número uno de los abortos tempranos (80% de los casos)?","back":"Las cromosomopatías (factores ovulares)."},{"front":"¿Cuál es la trisomía más frecuentemente asociada a abortos espontáneos?","back":"La Trisomía 16."},{"front":"¿Cuál es la causa principal de los abortos tardíos (20% de los casos)?","back":"La incompetencia ístmico-cervical."},{"front":"¿Qué hallazgo en la especuloscopía define a la amenaza de aborto frente a otros tipos de aborto?","back":"La ausencia de dilatación cervical (cérvix cerrado)."},{"front":"¿Cuál es el estudio de imagen de elección para el diagnóstico de aborto?","back":"El ultrasonido transvaginal."},{"front":"¿A partir de qué niveles de β-hCG se debe visualizar el saco gestacional mediante ultrasonido transvaginal?","back":"Niveles mayores a 1,500 UI."},{"front":"¿Qué frecuencia cardíaca fetal (bradicardia) se considera un marcador de predicción de aborto?","back":"Menos de 110 LPM."},{"front":"¿Cuál es el comportamiento normal de la β-hCG cada 2-3 días en un embarazo viable?","back":"Los niveles deben duplicarse."},{"front":"¿Qué niveles de progesterona sugieren muerte del producto?","back":"Niveles menores de 5 UI."},{"front":"¿Qué característica clínica distingue al aborto inevitable del aborto en evolución?","back":"La presencia de ruptura de membranas en el aborto inevitable."},{"front":"¿Cómo se define el aborto diferido?","back":"Es la muerte del producto sin que ocurra su expulsión espontánea."},{"front":"¿Qué complicación hematológica se debe vigilar en un aborto diferido por riesgo de coagulación intravascular diseminada (CID)?","back":"Los niveles de fibrinógeno."},{"front":"¿Qué antibióticos se recomiendan para el tratamiento del aborto séptico?","back":"Doxiciclina y Gentamicina."},{"front":"¿Cuál es el esquema de tratamiento médico para un aborto incompleto en pacientes con menos de 8 SDG?","back":"Mifepristona 600 mg más Misoprostol 800 mcg."},{"front":"En el tratamiento médico del aborto, ¿cuál es el tiempo máximo de espera para la expulsión antes de considerar falla?","back":"Hasta 72 horas (aunque suele ocurrir en las primeras 24 horas)."},{"front":"¿Cuáles son las condiciones de altura uterina y dilatación para realizar una Aspiración Manual Endouterina (AMEU)?","back":"Altura uterina menor a 11 cm y dilatación cervical menor a 1 cm."},{"front":"¿Cuáles son las condiciones de altura uterina y dilatación para realizar un Legrado Intrauterino (LIU)?","back":"Altura uterina mayor a 12 cm y dilatación cervical mayor a 1 cm."},{"front":"¿Qué antibiótico profiláctico se administra antes y después de un procedimiento quirúrgico de evacuación uterina?","back":"Doxiciclina (100 mg antes y 200 mg después)."},{"front":"¿Qué fármaco se administra para disminuir el sangrado durante un procedimiento quirúrgico de aborto?","back":"Oxitocina."},{"front":"En una amenaza de aborto, ¿cuál es la recomendación principal respecto a la actividad física?","back":"Reposo absoluto por 48 horas o hasta que cese el sangrado."},{"front":"¿Qué tratamiento hormonal se indica en una amenaza de aborto en pacientes con más de 12-14 SDG?","back":"17-hidroxiprogesterona."},{"front":"¿Cuál es la dosis de inmunoglobulina Anti-D en pacientes Rh negativas con menos de 13 SDG?","back":"150 mcg."},{"front":"¿Dónde ocurre la implantación en un embarazo ectópico?","back":"Fuera del endometrio de la cavidad uterina."},{"front":"¿Cuál es la localización anatómica más frecuente del embarazo ectópico tubárico (70-75%)?","back":"La región ampular."},{"front":"¿Cómo se denomina a la coexistencia de un embarazo ectópico y un embarazo intrauterino?","back":"Embarazo heterotópico."},{"front":"¿Cuál es la triada clínica clásica del embarazo ectópico?","back":"Sangrado transvaginal, dolor abdominal y amenorrea."},{"front":"¿Cuál es el principal factor de riesgo para desarrollar un embarazo ectópico (30-50% de los casos)?","back":"Enfermedad Pélvica Inflamatoria (EPI)."},{"front":"¿Qué hallazgo en el ultrasonido Doppler es característico del embarazo ectópico?","back":"El signo del 'anillo de fuego' o del látigo."},{"front":"¿Cuál es el diagnóstico de certeza para un embarazo ectópico según el USG y los niveles de β-hCG?","back":"Ultrasonido con masa anexial y β-hCG menor a 1,000 UI."},{"front":"¿Cómo se visualiza el útero en un embarazo cervical según el ultrasonido?","back":"En forma de 'reloj de arena'."},{"front":"¿Cuál es el tratamiento médico de primera elección para el embarazo ectópico?","back":"Metotrexato."},{"front":"¿Qué porcentaje de disminución de β-hCG se espera entre el día 4 y 7 para considerar éxito en el tratamiento con Metotrexato?","back":"Una disminución del 15%."},{"front":"¿Cuál es el abordaje quirúrgico de elección en un embarazo ectópico con inestabilidad hemodinámica?","back":"Laparotomía."},{"front":"¿Qué procedimiento quirúrgico se prefiere en mujeres con embarazo ectópico que desean conservar la fertilidad?","back":"Salpingostomía."},{"front":"¿Cuál es la indicación de salpingectomía en un embarazo ectópico?","back":"Embarazo mayor a 5 cm, hemorragia no controlada o paridad satisfecha."},{"front":"¿Qué es la enfermedad trofoblástica gestacional (ETG)?","back":"Una proliferación anormal (tumoral) del trofoblasto con capacidad de producir hormonas placentarias."},{"front":"¿Cuál es el síntoma clínico más frecuente en la enfermedad trofoblástica gestacional?","back":"Hemorragia uterina anormal."},{"front":"¿Qué hallazgo clínico es considerado patognomónico de la enfermedad trofoblástica?","back":"La expulsión de vesículas."},{"front":"¿Cuál es el 'Gold Standard' diagnóstico para la enfermedad trofoblástica gestacional?","back":"El estudio histopatológico."},{"front":"¿Qué patrón ecográfico es característico de la mola completa?","back":"Imagen en 'copos de nieve' o 'panal de abeja'."},{"front":"¿Qué imagen ecográfica se observa en la mola incompleta?","back":"Imagen en 'queso suizo'."},{"front":"¿Cuál es el genotipo más frecuente de la mola completa?","back":"46,XX."},{"front":"¿Cuál es el genotipo más frecuente de la mola incompleta?","back":"69,XXY."},{"front":"¿Por qué no se debe realizar inducción del trabajo de aborto con misoprostol en casos de mola?","back":"Por el riesgo de embolismo pulmonar o metástasis."},{"front":"¿Cuál es el tratamiento quirúrgico de elección para evacuar una mola en pacientes con paridad insatisfecha?","back":"Aspiración Manual Endouterina (AMEU)."},{"front":"¿Qué seguimiento se le debe dar a la β-hCG tras la evacuación de una mola?","back":"Medición semanal hasta negativizar y luego mensual hasta cumplir 6 meses."},{"front":"¿Qué es el coriocarcinoma?","back":"Un tumor maligno derivado del epitelio del trofoblasto (sincitio y citotrofoblasto)."},{"front":"¿Cuál es el esquema quimioterapéutico de elección para el coriocarcinoma de mal pronóstico?","back":"EMA-CO (Etopósido, Metotrexato, Actinomicina, Ciclofosfamida y Vincristina)."},{"front":"¿Qué es el fenómeno de Arias-Stella?","back":"Una modificación endometrial que ocurre en presencia de un embarazo extrauterino."},{"front":"¿Bajo qué condiciones de niveles de β-hCG sin saco gestacional se sospecha de embarazo ectópico según el ENARM?","back":"Niveles entre 1,100 a 2,000 UI."},{"front":"¿Qué estudio se utiliza específicamente para diagnosticar un embarazo ectópico intersticial (angular)?","back":"Resonancia Magnética (RM)."},{"front":"¿Qué marca la diferencia entre un aborto espontáneo y una pérdida gestacional recurrente en términos de tratamiento?","back":"El aborto recurrente puede requerir cerclaje cervical (retirado entre las 36-37 SDG)."},{"front":"¿Qué marcador de bienestar fetal es considerado el mejor según el material?","back":"El estriol."},{"front":"¿Qué signo ecográfico ayuda a diferenciar un aborto en evolución de un embarazo ectópico cervical?","back":"El signo de deslizamiento (presente en aborto, ausente en ectópico cervical)."},{"front":"¿Cuál es el rango de pérdida sanguínea que define el colapso hemodinámico en obstetricia?","back":"Entre el 35% y el 45%."},{"front":"¿Cuál es el tono basal normal del útero?","back":"De 8 a 12 mmHg."},{"front":"¿Qué microorganismo en un aborto séptico es indicación absoluta de histerectomía?","back":"Clostridium."}]},"14":{"num":14,"name":"HEMORRAGIAS DE TERCER TRIMESTRE","cards":[{"front":"¿Cómo se define la placenta previa?","back":"Implantación placentaria que cubre parcial o totalmente el orificio cervical interno."},{"front":"¿A qué distancia del orificio cervical interno (OCI) se encuentra una placenta de inserción baja?","back":"A menos de 2 cm del OCI sin llegar a cubrirlo."},{"front":"¿Cuál es la distancia normal entre la placenta y el orificio cervical interno?","back":"A más de 2 cm por encima del OCI."},{"front":"¿Cuál es el factor de riesgo más importante para el desarrollo de placenta previa?","back":"Fertilización in vitro."},{"front":"¿Cuál es el factor de riesgo más característico para presentar placenta previa?","back":"Cesáreas previas."},{"front":"Describa el color del sangrado característico en la placenta previa.","back":"Rojo rutilante."},{"front":"¿Cómo suele ser el inicio del sangrado en una paciente con placenta previa?","back":"Lento e insidioso."},{"front":"¿La placenta previa se presenta con dolor abdominal?","back":"No, es una hemorragia indolora."},{"front":"¿Cómo se encuentra el tono uterino en una paciente con placenta previa?","back":"Sin cambios (tono normal)."},{"front":"¿Cuál es el estudio diagnóstico inicial ante la sospecha de placenta previa?","back":"Especuloscopía más exploración física."},{"front":"¿Cuál es el método diagnóstico de elección para placenta previa?","back":"Ultrasonido transvaginal."},{"front":"¿Qué maniobra exploratoria está contraindicada en sospecha de placenta previa?","back":"Tacto vaginal."},{"front":"¿En qué semana de gestación se realiza el tamizaje de placenta previa mediante USG abdominal?","back":"Semana 20."},{"front":"¿En qué semana de gestación se debe confirmar el diagnóstico definitivo de placenta previa?","back":"Semana 32."},{"front":"¿Cuándo se programa el parto en una paciente con placenta previa sin episodios de sangrado?","back":"Entre las semanas 36 y 37."},{"front":"¿En qué momento se programa la cesárea si la paciente con placenta previa tuvo un episodio de sangrado previo?","back":"Entre las semanas 34 y 36."},{"front":"¿Cuál es la indicación de cesárea basada en la distancia de la placenta al OCI?","back":"Cuando la distancia es menor a 10 mm."},{"front":"¿Cuál es el manejo inicial de una paciente con sangrado por placenta previa menor a 34 SDG y estable?","back":"ABCDE, estabilización y esquema de maduración pulmonar."},{"front":"Mencione el esquema de administración de Betametasona para maduración pulmonar.","back":"12 mg cada 24 horas por 2 días."},{"front":"Mencione el esquema de administración de Dexametasona para maduración pulmonar.","back":"6 mg cada 12 horas por 2 días."},{"front":"¿Qué define al acretismo placentario?","back":"Invasión de la placenta al miometrio debido a una extensión anormal del trofoblasto."},{"front":"¿Qué porcentaje de pacientes con placenta previa presentan también acretismo placentario?","back":"10%."},{"front":"¿Cuál es la principal causa de sangrado en el tercer periodo del trabajo de parto?","back":"Acretismo placentario."},{"front":"¿Cuál es la profundidad de invasión en la placenta acreta?","back":"Alcanza el miometrio sin invadirlo profundamente (75% de los casos)."},{"front":"¿Qué caracteriza a la placenta increta?","back":"Invade directamente el miometrio (17% de los casos)."},{"front":"¿Qué caracteriza a la placenta percreta?","back":"Penetra el miometrio y puede alcanzar órganos vecinos (5% de los casos)."},{"front":"¿Qué síntoma clínico sugiere invasión vesical en una placenta percreta?","back":"Hematuria."},{"front":"¿Qué síntoma clínico sugiere invasión rectal en una placenta percreta?","back":"Rectorragia."},{"front":"¿Cuál es la sospecha clínica típica de acretismo durante el parto?","back":"Dificultad para la expulsión de la placenta o sangrado abundante post-expulsión."},{"front":"¿Cuál es el estudio de elección para el diagnóstico de acretismo placentario?","back":"Ultrasonido Doppler."},{"front":"En el contexto de acretismo, ¿a qué se refiere el hallazgo de 'queso Gruyere' en el USG?","back":"Presencia de espacios vasculares lacunares en el parénquima placentario."},{"front":"¿Cuál es el tratamiento de elección para el acretismo placentario programado?","back":"Cesárea clásica más histerectomía entre las semanas 34 y 36."},{"front":"¿Cuál es el manejo recomendado para la placenta durante la cesárea por acretismo?","back":"Dejar la placenta in situ y evitar intentar separarla de las paredes uterinas."},{"front":"¿Qué es el desprendimiento prematuro de placenta normoinserta (DPPNI)?","back":"Separación prematura de la placenta de su sitio de implantación antes del nacimiento."},{"front":"¿Cuál es el principal factor de riesgo para presentar un abruptio placentario (DPPNI)?","back":"Estados hipertensivos del embarazo (preeclampsia)."},{"front":"¿Cuál es la causa número uno de coagulación intravascular diseminada (CID) en el embarazo?","back":"Desprendimiento prematuro de placenta normoinserta (DPPNI)."},{"front":"Describa el color del sangrado en el DPPNI.","back":"Rojo oscuro."},{"front":"¿Qué hallazgo en el tono uterino es característico del DPPNI?","back":"Hipertonía uterina."},{"front":"Según la clasificación de Page, ¿qué porcentaje de desprendimiento define a la Clase II (Moderada)?","back":"25 - 50%."},{"front":"¿Qué nivel de desprendimiento en la clasificación de Page se asocia con choque grado IV y óbito fetal?","back":"Clase III (Severa), con desprendimiento mayor al 50%."},{"front":"¿Cuál es el hallazgo ultrasonográfico característico del DPPNI?","back":"Hematoma retroplacentario."},{"front":"¿Cuál es el tratamiento de elección definitivo para el DPPNI con feto vivo?","back":"Cesárea urgente."},{"front":"¿En qué caso se puede valorar el parto vaginal ante un DPPNI?","back":"Cuando existe muerte fetal y la madre está estable."},{"front":"¿Qué es el útero de Couvelaire?","back":"Extravasación de sangre hacia la musculatura uterina y debajo de la serosa por DPPNI."},{"front":"¿Qué maniobra quirúrgica se debe realizar ante un útero de Couvelaire?","back":"Histerectomía más cesárea."},{"front":"¿Cómo se define la ruptura uterina?","back":"Desgarro del miometrio con o sin exposición de partes fetales."},{"front":"¿Cuál es el antecedente quirúrgico más relacionado con la ruptura uterina?","back":"Dehiscencia de cicatriz uterina (dos o más cesáreas previas)."},{"front":"Mencione los tres elementos de la tríada clásica de ruptura uterina.","back":"Dolor abdominal súbito, sangrado transvaginal y anomalías en la FCF."},{"front":"¿Qué hallazgo a la exploración física es indicativo de ruptura uterina completa?","back":"Palpación de partes fetales y pérdida de la presentación fetal."},{"front":"¿Cuál es el diagnóstico confirmatorio de la ruptura uterina?","back":"Laparotomía."},{"front":"¿Cuál es el manejo inicial y definitivo de la ruptura uterina?","back":"Estabilización (ABCDE) seguida de laparotomía urgente con cesárea inmediata."},{"front":"¿Qué es la vasa previa?","back":"Vasos sanguíneos fetales que cruzan el orificio cervical interno sin protección de placenta o cordón."},{"front":"¿Cuál es el factor de riesgo principal para vasa previa?","back":"Inserción velamentosa del cordón umbilical."},{"front":"¿En qué momento ocurre típicamente el sangrado en la vasa previa?","back":"Al momento de la ruptura de membranas (amniorrexis)."},{"front":"En la vasa previa, ¿cómo se encuentra el estado hemodinámico materno frente al fetal durante el sangrado?","back":"Madre estable (sin dolor) y feto en alto riesgo (sufrimiento fetal súbito)."},{"front":"¿Cuál es el método para confirmar el diagnóstico de vasa previa entre las semanas 30 y 34?","back":"Ultrasonido Doppler."},{"front":"¿Cuál es el tratamiento de urgencia ante una hemorragia activa por vasa previa?","back":"Cesárea urgente."},{"front":"¿Qué patología hemorrágica del tercer trimestre se asocia con el uso de cocaína?","back":"Desprendimiento prematuro de placenta normoinserta (DPPNI)."},{"front":"¿Qué diferencia el dolor entre el DPPNI y la placenta previa?","back":"El DPPNI presenta dolor intenso, mientras que la placenta previa es indolora."},{"front":"La presencia de polisistolia ayuda a diferenciar el DPPNI de la ruptura uterina, ¿en cuál está ausente?","back":"En la ruptura uterina."},{"front":"¿Cuál es la mortalidad fetal estimada en casos de vasa previa?","back":"75%."},{"front":"Ante sospecha de acretismo placentario con invasión vesical, ¿qué estudio adicional se puede realizar?","back":"Cistoscopia."},{"front":"¿Cuál es el sitio más común de invasión en el acretismo placentario?","back":"Cara anterior del útero."},{"front":"¿Qué tipo de incisión quirúrgica se prefiere en una cesárea por acretismo placentario?","back":"Incisión media infraumbilical."},{"front":"Paciente con sangrado transvaginal oscuro y útero leñoso (hipertonía), ¿cuál es el diagnóstico más probable?","back":"Desprendimiento prematuro de placenta normoinserta (DPPNI)."}]},"15":{"num":15,"name":"ESTADOS HIPERTENSIVOS DEL EMBARAZO","cards":[{"front":"¿Cómo se define operativamente la hipertensión en el embarazo según el número de mediciones?","back":"Presión mayor a 140/90 mmHg con dos mediciones anormales con un intervalo de 4 a 6 horas entre ellas."},{"front":"¿Cuál es el criterio temporal para diagnosticar hipertensión arterial crónica en el embarazo?","back":"Presencia de hipertensión antes del embarazo o diagnóstico previo a la semana 20 de gestación."},{"front":"¿Cuál es el periodo de presentación característico de la hipertensión gestacional?","back":"Posterior a la semana 20 hasta la semana 12 posparto."},{"front":"Defina el hallazgo paraclínico que diferencia a la hipertensión gestacional de la preeclampsia.","back":"La ausencia de proteinuria en la hipertensión gestacional."},{"front":"¿Qué cantidad de proteinuria define a la preeclampsia sin datos de severidad en una recolección de 24 horas?","back":"Mayor a 300 mg (0.3 gramos)."},{"front":"¿Cuál es la cifra de presión arterial sistólica/diastólica que define por sí misma un dato de severidad en la preeclampsia?","back":"Presión arterial mayor o igual a 160/110 mmHg."},{"front":"¿A partir de qué cantidad de proteinuria en 24 horas se considera un dato de severidad?","back":"Mayor a 3 gramos."},{"front":"¿Cómo se define la eclampsia?","back":"Presencia de preeclampsia más convulsiones."},{"front":"¿Hasta qué día del posparto puede presentarse la eclampsia?","back":"Hasta el décimo día posparto."},{"front":"¿Qué componentes integran la tríada del síndrome de HELLP?","back":"Hemólisis, enzimas hepáticas elevadas y plaquetas bajas."},{"front":"¿A partir de qué momento se reclasifica la hipertensión del embarazo como crónica si persiste tras el parto?","back":"Después de la semana 12 del puerperio."},{"front":"¿Cuál es el punto de corte gestacional para clasificar la preeclampsia en temprana o tardía?","back":"La semana 34 de gestación."},{"front":"¿Por qué la preeclampsia temprana tiene peor pronóstico que la tardía?","back":"Porque está mediada por factores placentarios, mientras que la tardía es por factores maternos."},{"front":"¿Qué porcentaje de las muertes maternas son causadas por complicaciones hipertensivas?","back":"Entre el 15 y el 20% de las muertes maternas."},{"front":"¿Cuál es el factor de riesgo con el mayor riesgo relativo (RR = 9.72) para desarrollar preeclampsia?","back":"Enfermedades autoinmunes como el Lupus Eritematoso Sistémico o el Síndrome Antifosfolípidos."},{"front":"¿Cuál es el principal mecanismo fisiopatológico de los estados hipertensivos del embarazo?","back":"El daño endotelial."},{"front":"¿Qué parámetro ecográfico se utiliza entre las semanas 11 y 13.6 para el tamizaje de preeclampsia?","back":"El índice de pulsatilidad de la arteria uterina."},{"front":"¿Cuál es la dosis recomendada de calcio para profilaxis en pacientes con baja ingesta basal?","back":"1.5 gramos vía oral cada 24 horas."},{"front":"¿Qué riesgo fetal existe si se administra Ácido Acetilsalicílico (ASA) antes de la semana 12?","back":"Defectos de la pared abdominal."},{"front":"¿A qué complicación placentaria se asocia el uso de ASA después de la semana 16?","back":"Desprendimiento prematuro de placenta normoinserta (DPPNI)."},{"front":"¿En qué semana se debe suspender el ASA para evitar efectos en la coagulación neonatal?","back":"Antes de la semana 36."},{"front":"¿Cuál es el estándar de oro para el diagnóstico de proteinuria en el embarazo?","back":"La recolección de orina de 24 horas."},{"front":"¿Qué valor del cociente proteína/creatinina indica proteinuria significativa?","back":"Un cociente mayor a 0.28."},{"front":"En ausencia de proteinuria, ¿cuál es el nivel de creatinina sérica que sugiere preeclampsia?","back":"1.1 mg/dL o el doble de la concentración sérica previa."},{"front":"¿Qué nivel de plaquetas se considera un criterio diagnóstico de preeclampsia en ausencia de proteinuria?","back":"Menos de 100,000 plaquetas por μL."},{"front":"¿Cuál es el fármaco de primera línea para el tratamiento de la hipertensión gestacional y preeclampsia sin datos de severidad?","back":"Alfametildopa."},{"front":"¿Cuál es el efecto secundario neonatal característico del uso de Metoprolol en el embarazo?","back":"Bradicardia neonatal."},{"front":"¿Por qué el Nifedipino puede afectar la dinámica del parto?","back":"Porque puede provocar uteroinhibición al ser un bloqueador de canales de calcio."},{"front":"¿Cuál es la meta terapéutica de presión arterial en pacientes embarazadas sin comorbilidades?","back":"130-155 mmHg sistólica y 80-105 mmHg diastólica."},{"front":"En pacientes con preeclampsia y comorbilidades, ¿cuál es la meta de presión arterial sistólica?","back":"130-139 mmHg."},{"front":"¿Qué nivel de consciencia en la escala de Glasgow se considera un criterio de severidad?","back":"Un puntaje menor a 13."},{"front":"¿Cuál es el volumen urinario que define la oliguria en 24 horas como dato de severidad?","back":"Menor a 400 mL."},{"front":"¿Cuáles son los tres síntomas clásicos de vasoespasmo mencionados en la preeclampsia severa?","back":"Cefalea, fotopsias y tinnitus."},{"front":"¿Cuál es el fármaco antihipertensivo de elección vía intravenosa para crisis en preeclampsia severa?","back":"Labetalol."},{"front":"¿Cuál es el fármaco antihipertensivo oral de elección en México para preeclampsia con datos de severidad?","back":"Nifedipino."},{"front":"¿En qué consiste el esquema de Zuspan para la administración de Sulfato de Magnesio?","back":"Impregnación con 4 g IV para 30 minutos, seguido de mantenimiento de 1 g/h IV."},{"front":"¿Cuál es el antídoto para la intoxicación por Sulfato de Magnesio?","back":"Gluconato de calcio (1 ámpula)."},{"front":"¿Qué signo clínico indica la abolición del reflejo rotuliano por toxicidad de magnesio?","back":"Arreflexia o hiporreflexia rotuliana."},{"front":"¿Cuál es el tratamiento definitivo para la preeclampsia con datos de severidad?","back":"La finalización del embarazo."},{"front":"¿Qué criterios diagnósticos utiliza el sistema de Tennessee para el Síndrome de HELLP?","back":"AST > 70 UI/L, plaquetas < 100,000, bilirrubina total > 1.2 mg/dL y DHL > 600 UI/L."},{"front":"¿Cuál es el principal biomarcador de severidad en el síndrome de HELLP?","back":"El aumento de los niveles de Deshidrogenasa Láctica (DHL)."},{"front":"¿Cuál es la complicación materna no fetal más frecuente del síndrome de HELLP?","back":"Ruptura de hematoma hepático que causa hemoperitoneo."},{"front":"¿Qué nombre recibe el protocolo de manejo para el síndrome de HELLP que incluye corticosteroides?","back":"Protocolo de Mississippi."},{"front":"Según el protocolo de Mississippi, ¿qué dosis de dexametasona se administra anteparto?","back":"10 mg IV cada 12 horas."},{"front":"¿Cuál es el objetivo de presión arterial diastólica según el protocolo de Mississippi?","back":"80-100 mmHg."},{"front":"¿Qué síntoma es considerado el primer signo de alerta antes de la aparición de convulsiones en la eclampsia?","back":"Aumento excesivo de peso en el tercer trimestre."},{"front":"¿Cuál es el rango de dosis terapéutica óptima de magnesio en sangre?","back":"5 a 7 mg/dL."},{"front":"¿Cuánto tiempo debe mantenerse el sulfato de magnesio tras la última convulsión en eclampsia?","back":"Hasta 24 horas después."},{"front":"¿Qué fármaco se utiliza como segunda elección en caso de contraindicación al Sulfato de Magnesio?","back":"Fenitoína."},{"front":"¿Cuál es el flujo urinario mínimo que se debe vigilar en una paciente con tratamiento de magnesio?","back":"Mayor a 30 mL por hora."},{"front":"¿Cuál es la indicación de vía de resolución del embarazo en preeclampsia si hay buen control y sin severidad?","back":"Inducción del trabajo de parto por vía vaginal entre la semana 38 y 39.6."},{"front":"¿Qué grupos farmacológicos antihipertensivos están contraindicados en el embarazo por riesgo de malformaciones renales?","back":"IECAs y ARA II."},{"front":"¿Qué complicación fetal se asocia al uso de Prazosina en el embarazo?","back":"Óbito fetal."},{"front":"¿Qué relación existe entre la homocisteína y la preeclampsia?","back":"Niveles altos de homocisteína (asociados a baja ingesta de folatos) incrementan el riesgo de preeclampsia de 2 a 3 veces."},{"front":"¿En qué semana se recomienda iniciar las pruebas de bienestar fetal en pacientes con hipertensión controlada?","back":"A partir de las semanas 32-34."},{"front":"El signo de dolor en el cuadrante superior derecho es característico de HELLP, pero ¿en qué otras condiciones puede aparecer?","back":"En preeclampsia con datos de severidad o eclampsia."},{"front":"Si el cociente proteína/creatinina es indeterminado (0.15 a 0.28), ¿qué estudio se debe solicitar?","back":"Depuración de creatinina en orina de 24 horas."},{"front":"¿Qué fármacos se sugieren para el control de la presión arterial específicamente en el puerperio?","back":"Betabloqueadores combinados con diuréticos."},{"front":"¿Cuál es el valor de proteinuria en tira reactiva que se considera un criterio de severidad?","back":"+++ (tres cruces)."},{"front":"¿Qué complicación visual severa se asocia a la preeclampsia con datos de severidad?","back":"Ceguera cortical o desprendimiento de retina."}]},"16":{"num":16,"name":"PATOLOGIA EN EL EMBARAZO","cards":[{"front":"¿Cómo se define la diabetes gestacional según el material proporcionado?","back":"Intolerancia a los carbohidratos de severidad variable reconocida por primera vez durante el embarazo."},{"front":"¿Qué criterio define a la diabetes pregestacional?","back":"Diagnóstico previo al embarazo o realizado durante el primer trimestre de gestación."},{"front":"¿Cuál es la prevalencia de diabetes en el embarazo a nivel mundial?","back":"7% en todos los embarazos."},{"front":"¿Cuál es el rango de prevalencia de diabetes en el embarazo reportado para México?","back":"8-17%."},{"front":"Durante la primera mitad del embarazo, el estado metabólico se caracteriza por el _____.","back":"Anabolismo"},{"front":"Durante la segunda mitad del embarazo, el estado metabólico se caracteriza por el _____.","back":"Catabolismo"},{"front":"¿Cuál es considerada la hormona de mayor resistencia a la insulina durante el embarazo?","back":"Lactógeno placentario."},{"front":"¿En qué periodo del embarazo ocurre el pico de producción del lactógeno placentario?","back":"Entre las semanas 24 y 28."},{"front":"¿Cuál es la principal estrategia para evitar el nacimiento de productos macrosómicos?","back":"La detección oportuna de la diabetes."},{"front":"¿Qué nivel de HbA1c se asocia a un mayor riesgo de malformaciones y preeclampsia?","back":"Niveles mayores al 7%."},{"front":"¿Cuál es el riesgo a largo plazo para las pacientes que desarrollaron diabetes gestacional?","back":"Alto riesgo de desarrollar diabetes mellitus tipo 2 en los siguientes 10 años."},{"front":"Nombre una característica de una paciente de bajo riesgo para diabetes gestacional.","back":"Edad menor a 25 años."},{"front":"¿Qué antecedente reproductivo se considera un factor de riesgo alto para diabetes gestacional?","back":"Antecedente de productos macrosómicos."},{"front":"¿En qué momento se debe realizar el tamizaje de diabetes pregestacional?","back":"Antes de la semana 13 de gestación."},{"front":"¿Qué valor de glucosa en ayuno en el primer trimestre se considera negativo para diabetes?","back":"Menos de 92 mg/dl."},{"front":"¿Qué estudio se debe solicitar si la glucosa en ayuno en el primer trimestre resulta entre 92 y 125 mg/dl?","back":"Curva de tolerancia a la glucosa (75 g) de un paso."},{"front":"¿Qué valor de glucosa en ayuno en el primer trimestre establece el diagnóstico de diabetes pregestacional?","back":"126 mg/dl o más."},{"front":"¿Cómo se interpreta una glucosa al azar mayor a 200 mg/dl en el embarazo?","back":"Diagnóstico de diabetes pregestacional."},{"front":"¿Qué nivel de HbA1c es diagnóstico de diabetes pregestacional?","back":"Mayor a 6.5%."},{"front":"En la curva de tolerancia de 75 g (1 paso), ¿qué valor a la hora poscarga es diagnóstico?","back":"180 mg/dl o más."},{"front":"En la curva de tolerancia de 75 g (1 paso), ¿qué valor a las 2 horas poscarga es diagnóstico?","back":"153 mg/dl o más."},{"front":"¿Cuántos valores alterados se requieren en la curva de 75 g para diagnosticar diabetes?","back":"Un solo valor alterado."},{"front":"¿Qué hallazgo en un examen de orina rutinario puede indicar diabetes gestacional no diagnosticada?","back":"Glucosuria de 2+ en una ocasión o 1+ en dos o más ocasiones."},{"front":"¿En qué semanas de gestación se realiza el tamizaje universal para diabetes gestacional?","back":"Entre las semanas 24 y 28."},{"front":"¿En qué consiste el primer paso del tamizaje de dos pasos (O'Sullivan) en México?","back":"Carga de 50 g de glucosa sin necesidad de ayuno."},{"front":"¿Cuál es el valor de corte en el tamizaje de 50 g para proceder al segundo paso?","back":"140 mg/dl o más."},{"front":"¿Qué carga de glucosa se utiliza en el estudio confirmatorio de dos pasos?","back":"Carga de 100 g en ayuno."},{"front":"Según los criterios de Carpenter, ¿qué valor de glucosa en ayuno es anormal en la prueba de 100 g?","back":"Mayor a 95 mg/dl."},{"front":"Según los criterios de Carpenter, ¿qué valor a las 2 horas poscarga (100 g) es anormal?","back":"Mayor a 155 mg/dl."},{"front":"Según los criterios de Carpenter, ¿qué valor a las 3 horas poscarga (100 g) es anormal?","back":"Mayor a 140 mg/dl."},{"front":"¿Cuántos valores alterados se requieren tradicionalmente para el diagnóstico con los criterios de Carpenter?","back":"Dos de cuatro valores (2/4)."},{"front":"¿Cuál es la piedra angular del tratamiento de la diabetes gestacional?","back":"Cambios en el estilo de vida (dieta y ejercicio)."},{"front":"¿Qué porcentaje de pacientes logra metas terapéuticas solo con dieta y ejercicio?","back":"90%."},{"front":"¿Cuál es el tratamiento farmacológico de elección para la diabetes gestacional?","back":"Insulina NPH."},{"front":"¿Qué cantidad de glucosa metaboliza aproximadamente una unidad de insulina NPH?","back":"30-50 mg."},{"front":"¿Cuál es la dosis inicial recomendada de insulina NPH?","back":"0.2 UI por kg de peso actual."},{"front":"¿Cómo se debe distribuir la dosis diaria de insulina NPH?","back":"2/3 por la mañana y 1/3 vespertino."},{"front":"¿Por qué está contraindicada la insulina glargina según el texto?","back":"Es categoría C y se considera potencialmente teratogénica."},{"front":"¿Cuál es la conducta a seguir si una paciente con diabetes pregestacional ya utilizaba metformina?","back":"Se debe mantener el fármaco."},{"front":"¿Qué meta de glucosa en ayuno se establece para la diabetes gestacional?","back":"Menos de 95 mg/dl."},{"front":"¿Cuál es la meta de glucosa 1 hora posprandial durante el embarazo?","back":"Menos de 140 mg/dl."},{"front":"¿Cuál es la meta de glucosa 2 horas posprandiales durante el embarazo?","back":"Menos de 120 mg/dl."},{"front":"¿Qué meta de HbA1c se busca durante el embarazo?","back":"Menos de 6.0%."},{"front":"¿Cuál es el criterio de hospitalización por glucemia en ayuno?","back":"Mayor a 140 mg/dl."},{"front":"¿Cuál es el valor límite de hipoglucemia en ayuno para hospitalización?","back":"Menor a 60 mg/dl."},{"front":"¿Cuándo se recomienda la inducción del parto en una paciente controlada?","back":"Después de la semana 38."},{"front":"¿Cuál es la indicación de cesárea basada en el peso fetal estimado?","back":"Producto macrosómico (mayor a 4000 g)."},{"front":"¿Qué niveles de glucosa sérica se deben mantener durante la fase activa del trabajo de parto?","back":"Entre 70 y 90 mg/dl."},{"front":"¿En qué momento del día se recomienda realizar la cesárea programada?","back":"En las primeras horas de la mañana."},{"front":"¿A cuánto se debe aumentar la dosis de ácido fólico en pacientes con descontrol metabólico?","back":"5 mg."},{"front":"¿Cuál es la complicación más frecuente en el hijo de madre diabética?","back":"Macrosomía (50%)."},{"front":"¿Cuál es la malformación cardíaca más frecuente en hijos de madres diabéticas?","back":"Hipertrofia del tabique interventricular."},{"front":"¿Cuál es la malformación fetal más característica de la diabetes en el embarazo?","back":"Regresión caudal."},{"front":"¿Cuál es la manifestación patológica más frecuente en el recién nacido de madre diabética?","back":"Hipoglucemia."},{"front":"¿Cuándo se debe realizar la reclasificación de la paciente en el puerperio?","back":"Entre la semana 6 y 12 mediante una CTGO de un paso."},{"front":"¿Qué fármaco se recomienda iniciar antes de la semana 16 para evitar preeclampsia?","back":"Aspirina (ASA) 100 mg/día."},{"front":"¿Qué clasificación evalúa el daño vascular y el riesgo materno-fetal en diabetes?","back":"Clasificación de Freinkel."},{"front":"¿Cuál es la principal complicación del hígado graso agudo en el embarazo?","back":"Falla hepática aguda."},{"front":"¿En qué trimestre del embarazo aparece típicamente el hígado graso agudo?","back":"Último trimestre (generalmente después de la semana 35)."},{"front":"¿Cuál es el principal diagnóstico diferencial del hígado graso agudo del embarazo?","back":"Síndrome de HELLP."},{"front":"El síntoma clínico común en hígado graso agudo es el dolor en el _____.","back":"Cuadrante superior derecho"},{"front":"¿Cuál es el Gold Standard para el diagnóstico de hígado graso agudo del embarazo?","back":"Biopsia de tejido hepático."},{"front":"¿Qué se observa en la biopsia hepática en casos de hígado graso agudo del embarazo?","back":"Acumulación de grasa microvascular del hepatocito."},{"front":"¿Cuál es el tratamiento de elección para el hígado graso agudo del embarazo?","back":"Interrupción del embarazo."},{"front":"¿Cuál es el porcentaje de mortalidad materno-fetal asociado al hígado graso agudo?","back":"20%."},{"front":"¿Qué requerimiento calórico adicional se sugiere para pacientes diabéticas que están lactando?","back":"500 kcal al día."},{"front":"¿Cuál es el objetivo de glucosa antes de dormir y en la madrugada en el embarazo?","back":"60 mg/dl."},{"front":"¿Bajo qué condiciones se deben ajustar las metas a <80 mg/dl en ayuno y <110 mg/dl posprandial?","back":"Si el crecimiento fetal es igual o mayor al percentil 90."},{"front":"¿Cuál es el valor de corte para tamizaje de diabetes gestacional en pacientes de bajo riesgo (no mexicanas)?","back":"Glucosa en ayuno menor a 92 mg/dl."},{"front":"¿Qué contraindicación absoluta para el embarazo se menciona respecto a la HbA1c?","back":"Niveles mayores al 10%."}]},"17":{"num":17,"name":"TRABAJO DE PARTO","cards":[{"front":"Tipo de pelvis considerada ideal para el trabajo de parto, con una frecuencia del 50%.","back":"Pelvis ginecoide."},{"front":"Tipo de pelvis que presenta el peor pronóstico para el parto y es la segunda más frecuente.","back":"Pelvis androide."},{"front":"Pelvis menos común (5%) asociada históricamente a mujeres que caminaron antes de los 14 meses.","back":"Pelvis platipeloide."},{"front":"Límite anatómico del primer plano de Lee, correspondiente a una presentación móvil.","back":"Desde el promontorio hasta el borde superior de la sínfisis púbica (-4 cm)."},{"front":"Límite anatómico del segundo plano de Lee, donde la presentación se considera fija.","back":"Desde el borde inferior de la sínfisis púbica a la segunda vértebra sacra (-2 cm)."},{"front":"Nivel anatómico que define el tercer plano de Lee (presentación encajada o 0 cm).","back":"Nivel de las espinas iliácas."},{"front":"Límite anatómico del cuarto plano de Lee, correspondiente a una presentación profundamente encajada.","back":"Desde el vértice del sacro a la punta del cóccix (+4 cm)."},{"front":"Concepto: Situación fetal.","back":"Relación entre el eje mayor del feto y el eje vertical uterino."},{"front":"Indicación absoluta de cesárea en una situación transversa respecto a la posición del dorso.","back":"Dorso inferior."},{"front":"Concepto: Presentación fetal.","back":"Parte del cuerpo fetal que se encuentra más cercana al canal de parto."},{"front":"Variante de la presentación pélvica que conlleva un mayor riesgo de prolapso de cordón.","back":"Presentación pélvica incompleta."},{"front":"Diámetro cefálico fetal más importante para el parto, con una medida máxima de 9.5 cm.","back":"Suboccipitobregmático (biparietal)."},{"front":"Concepto: Posición fetal.","back":"Orientación de la presentación respecto a la pelvis materna."},{"front":"Variedad de posición más común en el trabajo de parto.","back":"Occipito anterior izquierda."},{"front":"Causa frecuente de parto prolongado relacionada con la rotación de la presentación.","back":"Posición posterior que rota a anterior."},{"front":"Concepto: Actitud fetal.","back":"Grado de flexión o extensión de la cabeza fetal."},{"front":"Posibles causas de una actitud fetal en extensión durante el parto.","back":"Hipotonía fetal o daño neurológico."},{"front":"Hito que marca el inicio del primer periodo del trabajo de parto (dilatación).","back":"Inicio de contracciones dolorosas y presencia de cambios cervicales."},{"front":"Criterios de dilatación y borramiento para definir la fase latente.","back":"Dilatación menor a 5 cm y borramiento menor al 50%."},{"front":"Duración normal de la fase latente en una paciente nulípara.","back":"12 a 18 horas."},{"front":"Duración normal de la fase latente en una paciente multípara.","back":"6 a 12 horas."},{"front":"Tiempo requerido para diagnosticar una fase latente prolongada en nulíparas.","back":"Más de 20 horas."},{"front":"Tiempo requerido para diagnosticar una fase latente prolongada en multíparas.","back":"Más de 14 horas."},{"front":"Criterios de dilatación y borramiento que definen el inicio de la fase activa.","back":"Más de 5 cm de dilatación y borramiento mayor al 50%."},{"front":"Duración promedio de la fase activa en pacientes nulíparas.","back":"8 a 18 horas."},{"front":"Duración promedio de la fase activa en pacientes multíparas.","back":"5 a 12 horas."},{"front":"Signo clínico que podría indicar un trabajo de parto detenido durante la fase activa.","back":"Más de 2 horas sin cambios cervicales."},{"front":"¿Por qué la OMS (2018) no recomienda el criterio de 1 cm/h para diagnosticar falta de progresión?","back":"Debido a la gran variabilidad reportada en la tasa de dilatación."},{"front":"Hitos que delimitan el segundo periodo del trabajo de parto (expulsión).","back":"Desde la dilatación completa hasta la expulsión del feto."},{"front":"Duración estándar del periodo expulsivo.","back":"60 minutos a 2 horas."},{"front":"Maniobra que consiste en ejercer presión sobre el mentón fetal y controlar la salida de la cabeza.","back":"Maniobra de Ritgen."},{"front":"Última maniobra mecánica que realiza el feto antes de su expulsión total.","back":"Rotación externa."},{"front":"Maniobra proscrita en el periodo expulsivo por riesgo de ruptura uterina.","back":"Maniobra de Kristeller."},{"front":"Hitos que delimitan el tercer periodo del trabajo de parto (alumbramiento).","back":"Desde el pinzamiento del cordón hasta la expulsión de la placenta."},{"front":"Tiempo recomendado para el pinzamiento tardío de cordón en recién nacidos sanos.","back":"30 a 60 segundos."},{"front":"Fármaco de elección para el manejo activo del tercer periodo y prevención de hemorragia posparto.","back":"Oxitocina."},{"front":"Condiciones maternas o fetales que obligan al pinzamiento inmediato del cordón umbilical.","back":"DPPNI, ruptura uterina, paro cardíaco materno o asfixia neonatal."},{"front":"Maniobra de expulsión placentaria que consiste en girar la placenta sobre su propio eje.","back":"Maniobra de Dublín."},{"front":"Maniobra de expulsión placentaria que combina presión suprapúbica con tracción del cordón.","back":"Maniobra de Brand-Andrews."},{"front":"Frecuencia recomendada para vigilar las contracciones uterinas durante la primera fase.","back":"Cada 30 minutos."},{"front":"Frecuencia recomendada para realizar el tacto vaginal durante la fase activa.","back":"Cada 4 horas (o más si es necesario)."},{"front":"Técnica de episiotomía considerada de primera elección.","back":"Técnica mediolateral."},{"front":"Antibióticos recomendados para el tratamiento de una episiotomía infectada.","back":"Cefalosporinas de 2da/3ra generación, eritromicina o clindamicina."},{"front":"Material de sutura preferido para la reparación de la episiotomía.","back":"Vicryl."},{"front":"Complicaciones tardías asociadas a la realización de una episiotomía.","back":"Dispareunia, adherencias y endometriosis."},{"front":"Acciones durante el segundo periodo que disminuyen el riesgo de desgarros y uso de episiotomía.","back":"Uso de compresas calientes y masaje perineal."},{"front":"Definición: Violencia obstétrica.","back":"Apropiación del cuerpo femenino y procesos reproductivos mediante trato deshumanizado y medicación abusiva."},{"front":"Tiempo recomendado para iniciar la lactancia materna tras el nacimiento.","back":"Durante la primera hora de vida."},{"front":"Intervención de rutina en el ingreso a labor que NO se recomienda según la evidencia actual.","back":"Realización de enemas evacuantes."},{"front":"Recomendación sobre la tricotomia en el trabajo de parto amigable.","back":"No realizar tricotomia de forma rutinaria."},{"front":"Norma Oficial Mexicana (NOM) que regula la atención del trabajo de parto.","back":"NOM-007."},{"front":"Posición materna recomendada para realizar el monitoreo fetal.","back":"Decúbito lateral izquierdo, sentada o media posición vertical."},{"front":"Sustancia de abuso cuyo consumo se asocia específicamente a bajo peso al nacimiento.","back":"Cocaína."},{"front":"Secuencia de los movimientos cardinales del parto (pasos 1 al 4).","back":"Encajamiento, descenso, flexión y rotación interna."},{"front":"Secuencia de los movimientos cardinales del parto (pasos 5 al 7).","back":"Extensión, rotación externa y expulsión."},{"front":"Punto toconómico en una presentación cefálica de vértice.","back":"Occipucio."},{"front":"Punto toconómico en una presentación pélvica.","back":"Sacro."},{"front":"Porcentaje de casos en los que la presentación fetal es cefálica.","back":"97%."},{"front":"La amniorrexis _____ no se recomienda para acelerar el parto de forma rutinaria.","back":"Inducida (artificial)."},{"front":"¿Bajo qué condiciones se recomienda el registro cardiotocográfico de rutina?","back":"No se recomienda de rutina en embarazos de bajo riesgo con trabajo de parto espontáneo."},{"front":"Frecuencia de vigilancia de la FCF con Doppler o Pinard durante las contracciones.","back":"Cada 15 a 30 minutos."},{"front":"Procedimiento prohibido durante el alumbramiento para evitar complicaciones.","back":"Revisión manual de la cavidad uterina."},{"front":"Acción recomendada al ingreso a sala de labor para evitar el uso de sondas.","back":"Favorecer la micción espontánea."},{"front":"Objetivo principal del manejo activo del tercer periodo del parto.","back":"Disminuir el riesgo de hemorragia posparto."},{"front":"En una incompatibilidad de grupo Rh, ¿qué extremo del cordón se debe pinzar inmediatamente?","back":"Solo el extremo fetal."}]},"18":{"num":18,"name":"PARTO PRETERMINO","cards":[{"front":"¿Cómo se define el parto pretérmino en cuanto a edad gestacional y peso?","back":"Parto entre la semana 22-36.6 o con peso ≥ 500 g con signos de vida."},{"front":"Según la clasificación GPC 2017, ¿qué semanas de gestación abarca un prematuro extremo?","back":"Menos de 28 semanas."},{"front":"Según la clasificación GPC 2017, ¿qué rango de semanas define a un recién nacido muy prematuro?","back":"Entre 28 y 31 semanas."},{"front":"Según la clasificación GPC 2017, ¿cuál es el rango de semanas para un prematuro moderado?","back":"Entre 32 y 33 semanas."},{"front":"Según la clasificación GPC 2017, ¿qué semanas corresponden al parto pretérmino tardío?","back":"Entre 34 y 36 semanas."},{"front":"¿Qué porcentaje de la mortalidad perinatal a nivel mundial se asocia al parto pretérmino?","back":"Hasta un 70%."},{"front":"¿Cuál es la frecuencia de contracciones para diagnosticar una amenaza de parto pretérmino (APP)?","back":"Menos de 4 contracciones en 20 minutos u 8 en 60 minutos."},{"front":"¿Cuáles son los criterios de dilatación y borramiento cervical en una amenaza de parto pretérmino (APP)?","back":"Dilatación ≤ 3 cm y borramiento < 50%."},{"front":"¿Cuál es la frecuencia de contracciones que indica que el trabajo de parto pretérmino ya se ha establecido?","back":"≥ 4 contracciones en 20 minutos o > 8 en 60 minutos."},{"front":"¿Qué cambios cervicales definen al parto pretérmino establecido frente a la amenaza?","back":"Dilatación > 3 cm y borramiento > 50%."},{"front":"¿Qué sistema se utiliza para valorar el nivel de riesgo de parto pretérmino en una paciente?","back":"Sistema de riesgo de Papiernik."},{"front":"¿Qué longitud cervical medida por USG entre las semanas 20-24 se considera un factor de riesgo anatómico?","back":"Menor a 25 mm."},{"front":"¿Qué longitud cervical medida por USG entre las semanas 14-15 se considera un factor de riesgo anatómico?","back":"Menor a 15 mm."},{"front":"¿En qué semanas se recomienda realizar el tamizaje de longitud cervical en pacientes de alto riesgo?","back":"Entre la semana 13 y 15."},{"front":"¿En qué semanas se realiza la medición de longitud cervical en pacientes con factores de riesgo generales?","back":"Entre la semana 20 y 24."},{"front":"¿Cuál es el tratamiento preventivo indicado para una paciente con longitud cervical < 15 mm en la semana 13-15?","back":"Cerclaje cervical (disponible hasta la semana 34)."},{"front":"¿Cuál es el tratamiento preventivo para una paciente con cérvix < 25 mm detectado entre las semanas 20-24?","back":"Progesterona vaginal."},{"front":"¿Hasta qué semana se recomienda mantener el tratamiento con progesterona vaginal en pacientes con cérvix corto?","back":"Hasta la semana 34-36."},{"front":"¿Qué conducta se debe seguir si el Índice tocolítico de Gruber-Baumgarten es ≥ 5?","back":"Se diagnostica parto pretérmino y se deja evolucionar el trabajo de parto."},{"front":"¿Bajo qué puntaje del Índice de Gruber se puede considerar la terapia tocolítica?","back":"Menor a 5 puntos."},{"front":"¿En qué rango de semanas de gestación es útil realizar la prueba de fibronectina?","back":"Entre la semana 24 y 34."},{"front":"¿Cuál es el valor predictivo negativo (VPN) de la prueba de fibronectina para parto pretérmino?","back":"Aproximadamente 95%."},{"front":"¿Cuál es el útero-inhibidor de primera elección en el manejo ambulatorio de la amenaza de parto pretérmino?","back":"Nifedipino (vía oral)."},{"front":"¿Por qué se contraindica la indometacina como tocolítico en gestaciones mayores a 32 semanas?","back":"Por el riesgo de cierre precoz del conducto arterioso fetal."},{"front":"¿En qué pacientes se indica la administración de corticoesteroides para maduración pulmonar?","back":"Pacientes < 34 semanas con riesgo de parto pretérmino o ruptura de membranas."},{"front":"¿Cuáles son las contraindicaciones absolutas para el uso de corticoesteroides en la maduración pulmonar?","back":"Diabetes mellitus descontrolada, tuberculosis activa o corioamnionitis."},{"front":"¿Cuál es la indicación para administrar sulfato de magnesio como neuroprotección fetal?","back":"Gestaciones menores a 32 semanas con riesgo de parto inminente."},{"front":"¿Qué condición define a la Ruptura Prematura de Membranas (RPM) como 'prolongada'?","back":"Cuando lleva más de 18 horas de evolución."},{"front":"¿Cuál es la causa principal de la Ruptura Prematura de Membranas (RPM)?","back":"Infecciones (como cervicovaginitis e IVUs)."},{"front":"¿Qué deficiencia de mineral y vitamina se asocia a la etiología de la RPM?","back":"Cobre y vitamina C."},{"front":"¿Cómo se define una RPM 'previable'?","back":"Ocurre antes de las 24 semanas de gestación."},{"front":"¿En qué consiste el signo de Tarnier observado durante la especuloscopía?","back":"Salida de líquido abundante por la vagina al realizar maniobras."},{"front":"¿Cuál es el 'Gold Standard' para el diagnóstico de Ruptura Prematura de Membranas?","back":"Antecedente clínico de salida de líquido (aunque se auxilia de pruebas)."},{"front":"En la prueba de Nitrazina, ¿qué pH indica la presencia de líquido amniótico?","back":"Un pH entre 7.1 y 7.3."},{"front":"¿Qué hallazgo microscópico confirma una prueba de cristalografía positiva para RPM?","back":"Formación de cristales en forma de 'helechos'."},{"front":"¿Cuál es la conducta terapéutica en una RPM con más de 34 semanas de gestación?","back":"Finalizar el embarazo."},{"front":"¿Qué esquema antibiótico profiláctico de primera elección se utiliza en RPM menor a 34 semanas?","back":"Ampicilina + Eritromicina IV por 2 días, seguido de Amoxicilina + Eritromicina VO por 5 días."},{"front":"¿Cuál es la vía de interrupción del embarazo preferida en RPM entre las semanas 27 y 32?","back":"Vía abdominal (cesárea)."},{"front":"¿Cuál es la definición clínica de corioamnionitis?","back":"Inflamación o infección de la placenta, corion y amnios."},{"front":"¿Cuál es el agente etiológico más frecuente (50%) de la corioamnionitis?","back":"\\textit{Ureaplasma}."},{"front":"¿Qué agente etiológico de la corioamnionitis se asocia específicamente a la realización de tactos vaginales repetidos?","back":"\\textit{Mycoplasma hominis} (30%)."},{"front":"Menciona tres de los Criterios de Gibbs para el diagnóstico de corioamnionitis.","back":"Fiebre > 38°C, taquicardia (fetal o materna) y líquido amniótico fétido."},{"front":"¿Cuál es el 'Gold Standard' para el diagnóstico de corioamnionitis?","back":"Estudio histológico de las membranas."},{"front":"¿Qué esquema antibiótico se elige para el tratamiento de la corioamnionitis antes de interrumpir el embarazo?","back":"Ampicilina + Gentamicina."},{"front":"¿Cuánto tiempo antes de la interrupción del embarazo debe administrarse la antibioticoterapia en caso de corioamnionitis?","back":"6 horas antes."},{"front":"¿Cómo se define el polihidramnios según el volumen de líquido amniótico?","back":"Acumulación de más de 2000 ml o el doble de lo normal para la edad gestacional."},{"front":"¿Qué valor del Índice de Phelan en el USG confirma el diagnóstico de polihidramnios?","back":"Mayor a 25 cm."},{"front":"¿Cuál es la etiología más frecuente del polihidramnios?","back":"Causa idiopática (60%)."},{"front":"¿Cuál es el tratamiento de primera elección para el polihidramnios agudo o grave?","back":"Amniocentesis evacuadora."},{"front":"¿Cómo se define el oligohidramnios según el volumen de líquido amniótico?","back":"Cantidad menor a 500 ml."},{"front":"¿Qué valor del Índice de Phelan define al oligohidramnios según los términos ENARM?","back":"Menor a 5 cm."},{"front":"¿Qué complicación pulmonar se asocia frecuentemente al oligohidramnios severo?","back":"Hipoplasia pulmonar."},{"front":"¿Cuál es el tratamiento indicado para el oligohidramnios?","back":"Amnioinfusión (500-600 ml de solución fisiológica)."},{"front":"¿Cuál es la intervención más eficaz para reducir la morbimortalidad neonatal en el parto pretérmino?","back":"Administración de corticoesteroides prenatales."},{"front":"¿Cuál es el periodo intergenésico ideal recomendado para prevenir el parto pretérmino?","back":"Entre 1.5 y 2 años."},{"front":"¿Qué efecto tiene la ingesta de Omega 3 durante el embarazo respecto al tiempo de gestación?","back":"Previene el parto pretérmino pero aumenta el riesgo de embarazo postérmino."},{"front":"¿Por qué se debe evitar realizar tactos vaginales en una sospecha de infección o RPM?","back":"Para no aumentar el riesgo de corioamnionitis y progresión de la infección."},{"front":"En pacientes con VIH y RPM, ¿cuál es el manejo profiláctico intraparto?","back":"Zidovudina IV."},{"front":"¿Qué prueba diagnóstica para RPM tiene el mayor Valor Predictivo Positivo (VPP)?","back":"Detección de microglobulina placentaria."},{"front":"¿Qué porcentaje de reducción de hemorragia intraventricular se logra con el uso de corticoesteroides prenatales?","back":"46%."}]},"19":{"num":19,"name":"PATOLOGIA DE TRABAJO DE PARTO","cards":[{"front":"¿En qué consiste la inducción del trabajo de parto?","back":"En desencadenar los fenómenos fisiológicos del parto después de la semana 22 de gestación."},{"front":"¿Cuál es la principal complicación de la inducción del trabajo de parto?","back":"La ruptura uterina."},{"front":"Indicación de inducción: ruptura prematura de membranas a término tras _____ horas del evento.","back":"24"},{"front":"¿A qué edad gestacional se debe ofrecer la inducción a mujeres con embarazo prolongado?","back":"Entre las semanas 41 y 42."},{"front":"Para realizar una inducción, ¿cuál es el requisito respecto a la presentación fetal?","back":"Debe ser presentación cefálica."},{"front":"¿Qué escala se utiliza para valorar si una paciente es candidata a inducción o requiere maduración cervical?","back":"El índice de Bishop."},{"front":"¿Cuál es el puntaje del índice de Bishop que indica una alta probabilidad de éxito para iniciar la inducción?","back":"> 6"},{"front":"¿Qué conducta se debe seguir si el índice de Bishop es < 6?","back":"Realizar maduración cervical."},{"front":"¿Cuál es el fármaco \"estándar de oro\" para la inducción del trabajo de parto con Bishop favorable?","back":"Oxitocina."},{"front":"¿Cuál es la dosis mínima de oxitocina recomendada para la inducción?","back":"1-2 mU/min."},{"front":"¿Cuál es el fármaco de elección (PGE2) para la maduración cervical?","back":"Dinoprostona."},{"front":"¿Qué fármaco (PGE1) es de elección para la maduración cervical en casos de muerte intrauterina?","back":"Misoprostol."},{"front":"¿Qué complicación uterina se asocia frecuentemente al uso de prostaglandinas?","back":"Taquisistolia."},{"front":"¿En qué consiste la maniobra de Hamilton?","back":"En despegar las membranas amnióticas de forma manual."},{"front":"En el índice de Bishop, ¿qué parámetro evalúa la posición del cérvix?","back":"Posición (Posterior, Medio o Anterior)."},{"front":"En el índice de Bishop, un borramiento del > 80 % otorga un puntaje de _____.","back":"3"},{"front":"¿A partir de qué edad gestacional se define el procedimiento de cesárea?","back":"Después de las 28 semanas de gestación."},{"front":"¿En qué periodo se debe derivar a segundo nivel a una paciente con antecedente de cesárea?","back":"Entre la semana 34 y 36."},{"front":"¿Cuál es el umbral de carga viral de VIH para indicar una cesárea absoluta?","back":"Mayor a 1,000 copias."},{"front":"Un peso fetal menor a _____ gramos es una indicación absoluta de cesárea.","back":"1,500"},{"front":"¿Qué tipo de indicación representa el producto macrosómico para la realización de cesárea?","back":"Indicación relativa."},{"front":"¿Cuál es el antibiótico de elección para la profilaxis general en una cesárea?","back":"Ampicilina."},{"front":"¿Qué tipo de incisión uterina es la más frecuente y permite un parto vaginal subsecuente?","back":"Segmentaria transversal tipo Kerr."},{"front":"¿Cuál es la principal desventaja de la incisión uterina clásica o corporal?","back":"No permite un parto vaginal subsecuente."},{"front":"¿Qué antibiótico se puede agregar a las cefalosporinas si hay alto riesgo de endometritis post-cesárea?","back":"Azitromicina."},{"front":"¿Cuál es una estrategia clave para disminuir la frecuencia de cesáreas respecto al ingreso hospitalario?","back":"Ingresar a la paciente únicamente en fase activa del trabajo de parto."},{"front":"¿Qué maniobra para distocia de hombros consiste en la abducción de cadera e hiperflexión de piernas maternas?","back":"Maniobra de McRoberts."},{"front":"¿Cuál es la eficacia aproximada de la maniobra de McRoberts en la distocia de hombros?","back":"90 %."},{"front":"¿En qué consiste la maniobra de Robin II-Woods?","back":"En interiorizar ambos hombros hacia el tórax del neonato."},{"front":"¿Qué maniobra de último recurso para distocia de hombros implica la fractura de clavícula y reintroducción del feto?","back":"Maniobra de Zavanelli."},{"front":"¿En qué consiste la maniobra de Gaskin?","back":"En colocar a la madre en posición de cuatro extremidades (pedio)."},{"front":"¿Qué plano de Hodge y dilatación se requieren para el uso de espátulas?","back":"Dilatación completa y 4to plano de Hodge."},{"front":"¿Qué tipo de fórceps está indicado específicamente para la presentación pélvica?","back":"Fórceps de Piper."},{"front":"¿Qué tipo de fórceps se utiliza cuando se requiere rotación cefálica?","back":"Fórceps de Kielland."},{"front":"¿Cuál es el requisito de plano de Hodge para la aplicación de ventosa (vacuoextractores)?","back":"2do plano de Hodge."},{"front":"¿Cuál es la incidencia aproximada del embarazo gemelar?","back":"1-3 %."},{"front":"En el embarazo gemelar, ¿qué signo ecográfico indica un embarazo bicorial?","back":"Signo de lambda (λ)."},{"front":"En el embarazo gemelar, ¿qué signo ecográfico indica un embarazo monocorial?","back":"Signo de la T."},{"front":"Los gemelos _____ provienen de la fecundación de un solo óvulo y un espermatozoide.","back":"monocigotos"},{"front":"¿Qué porcentaje de los embarazos gemelares son dicigotos?","back":"75 %."},{"front":"¿En qué semana se recomienda la interrupción de un embarazo gemelar monocorial no complicado?","back":"Semana 36."},{"front":"Si el primer feto en un embarazo gemelar no está en presentación cefálica, la vía de nacimiento debe ser _____.","back":"cesárea"},{"front":"¿Cuál es el tiempo límite para el nacimiento del segundo feto en un parto vaginal gemelar antes de indicar cesárea?","back":"30 minutos."},{"front":"¿En qué semanas se debe realizar la cesárea en un embarazo gemelar monoamniótico?","back":"Semana 32-34."},{"front":"¿Cuál es la complicación más frecuente en embarazos monocoriales debida a anastomosis vasculares?","back":"Síndrome de transfusión feto-feto."},{"front":"¿Qué características presenta el feto transfusor en el síndrome de transfusión feto-feto?","back":"Anemia y oligohidramnios."},{"front":"¿Qué características presenta el feto transfundido en el síndrome de transfusión feto-feto?","back":"Policitemia e insuficiencia cardiaca de alto gasto."},{"front":"¿Cuál es el tratamiento de elección para el síndrome de transfusión feto-feto?","back":"Coagulación láser de las anastomosis vasculares."},{"front":"Factor de riesgo para gemelaridad: la edad materna avanzada aumenta la secreción de la hormona _____.","back":"FSH"},{"front":"¿Qué tipo de fórceps se utiliza para la presentación occipito-posterior?","back":"Simpson o Tucker McLane."},{"front":"¿Qué complicación materna es la más común en el embarazo múltiple según el texto?","back":"Parto pretérmino."},{"front":"¿Cuál es la principal complicación materna de la maniobra de McRoberts?","back":"Hemorragia."},{"front":"Toda paciente con indicación de inducción debe ser valorada mediante el _____.","back":"Índice de Bishop"},{"front":"En el índice de Bishop, una dilatación de 0 cm otorga un puntaje de _____.","back":"0"},{"front":"En el índice de Bishop, una altura de presentación de 0 corresponde a un puntaje de _____.","back":"2"}]},"2":{"num":2,"name":"AMENORREAS PRIMARIAS Y SECUNDARIAS","cards":[{"front":"¿Cómo se define la amenorrea primaria en mujeres sin caracteres sexuales secundarios?","back":"Ausencia de menarca en mayores de 13 años."},{"front":"¿Cuál es la edad límite para definir amenorrea primaria en presencia de caracteres sexuales secundarios?","back":"Mayores de 15 años."},{"front":"¿Qué criterio de tiempo define la amenorrea secundaria en mujeres con ciclos regulares?","back":"Ausencia de menstruación por 90 días."},{"front":"En mujeres con ciclos irregulares, ¿cuántos meses de ausencia menstrual definen la amenorrea secundaria?","back":"6 meses."},{"front":"¿Cuáles son los cuatro estados que comprenden la amenorrea fisiológica?","back":"Embarazo, puerperio, climaterio y antes de la pubertad."},{"front":"El gen _____, ubicado en el cromosoma Y, actúa como interruptor para iniciar la formación de testículos.","back":"SRY"},{"front":"¿De qué factor depende el fenotipo sexual, independientemente del cariotipo?","back":"De la presencia o ausencia de andrógenos."},{"front":"¿Qué sucede con el desarrollo fenotípico en un individuo 46,XY con insensibilidad a los andrógenos?","back":"Desarrolla un fenotipo femenino."},{"front":"¿Cuál es el tumor hipotálamo-hipofisario más frecuentemente asociado a amenorreas centrales?","back":"Craneofaringioma."},{"front":"¿Qué hormonas se incrementan en la amenorrea deportiva alterando la descarga de GnRH?","back":"Andrógenos y prolactina."},{"front":"¿Cómo afecta la liberación de corticotropina por estrés a la producción de FSH y LH?","back":"Inhibe la secreción de gonadotropinas al activar el eje hipotálamo-hipófisis-adrenal."},{"front":"¿Qué hormona producida por la grasa corporal estimula la producción de GnRH?","back":"Leptina."},{"front":"¿Por qué disminuye la GnRH en pacientes con anorexia nerviosa?","back":"Debido a la disminución de la producción de leptina por falta de grasa corporal."},{"front":"El Síndrome de Kallmann se caracteriza por amenorrea e infantilismo sexual asociados a _____.","back":"Anosmia (o atrofia del bulbo olfatorio)."},{"front":"¿Qué gen está mutado en el Síndrome de Kallmann ligado al cromosoma X?","back":"Gen KAL1."},{"front":"Tríada clínica del Síndrome de Prader-Willi: hipotonía, obesidad e _____.","back":"Hipogonadismo"},{"front":"¿A qué alteración cromosómica se asocia el Síndrome de Prader-Willi?","back":"Cromosoma 15."},{"front":"¿Cuál es el tratamiento farmacológico mencionado para el Síndrome de Prader-Willi?","back":"Clomifeno."},{"front":"El Síndrome de Progeria, caracterizado por vejez prematura y alopecia, se asocia al cromosoma _____.","back":"1"},{"front":"¿Cuál es el perfil de LH/FSH y estrógenos en el hipogonadismo hipergonadotrópico?","back":"LH/FSH elevadas y estrógenos reducidos."},{"front":"¿Dónde se localiza el defecto primario en el hipogonadismo hipogonadotrópico?","back":"Hipotálamo o hipófisis."},{"front":"¿Cuál es el cariotipo típico del Síndrome de Turner?","back":"45,X."},{"front":"¿Cuál es la causa más frecuente de amenorrea primaria?","back":"Síndrome de Turner (disgenesia gonadal)."},{"front":"En el Síndrome de Turner, los ovarios son reemplazados por estructuras denominadas _____.","back":"Cintillas ováricas."},{"front":"¿Qué hallazgo ecográfico en el primer trimestre sugiere un diagnóstico prenatal de Síndrome de Turner?","back":"Higroma quístico."},{"front":"¿Cuál es el estándar de oro para el diagnóstico del Síndrome de Turner en la vida adulta?","back":"Cariotipo."},{"front":"¿Cuál es el dato clínico más frecuente del Síndrome de Turner durante la infancia?","back":"Linfedema."},{"front":"¿Qué alteración ungueal es característica del Síndrome de Turner en la adolescencia?","back":"Displasia ungueal."},{"front":"¿Cuál es la malformación cardíaca más frecuente en pacientes con Síndrome de Turner?","back":"Elongación del arco transverso."},{"front":"¿Qué patología aórtica es el Síndrome de Turner la causa principal?","back":"Coartación de la aorta."},{"front":"¿En qué consiste el tratamiento hormonal para el crecimiento en el Síndrome de Turner?","back":"Somatropina (hormona del crecimiento)."},{"front":"¿Cuál es el cariotipo característico del Síndrome de Swyer?","back":"46,XY (o mosaicismo 45,X/46,XY)."},{"front":"¿Cuál es la diferencia anatómica clave entre el Síndrome de Swyer y el Síndrome de Morris respecto al útero?","back":"En Swyer el útero está presente, en Morris está ausente."},{"front":"¿Qué neoplasia tiene un alto riesgo de desarrollarse en cintillas gonadales con presencia de cromosoma Y (ej. Swyer)?","back":"Gonadoblastoma."},{"front":"El Síndrome de Morris también es conocido médicamente como _____.","back":"Feminización testicular (o insensibilidad a los andrógenos)."},{"front":"¿Cómo se encuentran los niveles de testosterona en una paciente con Síndrome de Morris?","back":"Normales o elevados para un varón."},{"front":"¿Por qué no se desarrollan útero ni trompas en el Síndrome de Morris si el fenotipo es femenino?","back":"Por la actividad normal de la Hormona Antimülleriana (AMH)."},{"front":"¿Dónde se localizan habitualmente los testículos en el Síndrome de Morris?","back":"Intraabdominales o en el conducto inguinal."},{"front":"¿Cuál es la característica clínica distintiva del vello en el Síndrome de Morris?","back":"Ausencia de vello axilar y púbico."},{"front":"¿Qué tumor maligno se asocia con mayor frecuencia al Síndrome de Morris?","back":"Disgerminoma."},{"front":"¿Qué enzima es deficiente en la forma más común de Hiperplasia Suprarrenal Congénita?","back":"21-hidroxilasa."},{"front":"¿Cuál es el cariotipo de una paciente con Síndrome de Rokitansky?","back":"46,XX."},{"front":"¿Qué estructuras anatómicas están ausentes en el Síndrome de Rokitansky?","back":"Útero y los 2/3 superiores de la vagina."},{"front":"¿Cómo son los niveles hormonales en pacientes con Síndrome de Rokitansky?","back":"Normales."},{"front":"¿Cuál es el síntoma principal que acompaña a la amenorrea en el himen imperforado?","back":"Dolor abdominal cíclico por acumulación menstrual."},{"front":"¿Qué define al Síndrome de Asherman?","back":"Amenorrea secundaria por sinequias (adherencias) uterinas."},{"front":"¿Cuál es el principal factor de riesgo para desarrollar Síndrome de Asherman?","back":"Antecedentes de instrumentación ginecológica como legrados (curetaje)."},{"front":"¿Cuál es el dato clínico más importante, además de la amenorrea, en el Síndrome de Asherman?","back":"Infertilidad."},{"front":"¿Cuál es el estándar de oro para el diagnóstico y tratamiento del Síndrome de Asherman?","back":"Histeroscopía."},{"front":"¿Qué evento desencadena el Síndrome de Sheehan?","back":"Hemorragia posparto masiva que causa infarto hipofisario."},{"front":"¿Cuál es la principal causa de panhipopituiturismo post-parto?","back":"Síndrome de Sheehan."},{"front":"¿Cuál es el signo clínico más temprano y característico del Síndrome de Sheehan?","back":"Incapacidad para lactar (agalactia)."},{"front":"¿Qué hallazgo en el vello corporal sugiere Síndrome de Sheehan?","back":"Pérdida del vello púbico y axilar."},{"front":"El Síndrome de Netter se define como adherencias intrauterinas extensas causadas por _____.","back":"Endometritis tuberculosa."},{"front":"¿Qué elementos componen la tríada de la mujer deportista?","back":"Trastornos de la alimentación, de la menstruación y del sistema óseo."},{"front":"¿Cuál es el tratamiento definitivo para el Síndrome de Morris y Swyer para prevenir neoplasias?","back":"Gonadectomía."},{"front":"En el Síndrome de Rokitansky, la vagina termina en _____.","back":"Fondo de saco ciego."},{"front":"La presencia de útero y niveles elevados de FSH/LH con cariotipo 46,XY sugiere el diagnóstico de _____.","back":"Síndrome de Swyer"},{"front":"¿Qué hormonas deben solicitarse inicialmente ante una amenorrea primaria con útero presente?","back":"FSH, LH, TSH y estradiol."},{"front":"A diferencia del Síndrome de Turner, las pacientes con Síndrome de Swyer suelen tener una talla _____.","back":"Normal."}]},"20":{"num":20,"name":"PATOLOGIA PUERPERAL","cards":[{"front":"¿Cuál es la definición general de hemorragia puerperal según la pérdida de volumen sanguíneo?","back":"Pérdida de sangre mayor o igual a 1000 ml dentro de las 24 horas posteriores al parto."},{"front":"En un parto vaginal, ¿a partir de qué volumen de pérdida hemática se considera hemorragia puerperal?","back":"Mayor a 500 ml."},{"front":"En una cesárea, ¿a partir de qué volumen de pérdida hemática se considera hemorragia puerperal?","back":"Mayor a 1000 ml."},{"front":"¿Qué caracteriza a la hemorragia puerperal persistente?","back":"Pérdida de al menos 1000 ml dentro de las primeras 24 horas que es refractaria al tratamiento de primera línea."},{"front":"¿Cuál es la causa más frecuente de hemorragia puerperal?","back":"Atonía uterina."},{"front":"¿Qué grupo de edad presenta la mayor afectación por hemorragia puerperal en términos de mortalidad?","back":"Mujeres de 45 a 49 años."},{"front":"¿Qué porcentaje de la razón de mortalidad materna en México representa la hemorragia puerperal?","back":"20.4%."},{"front":"¿Cuál es la periodicidad recomendada para valorar los signos vitales en las primeras 2 horas del puerperio?","back":"Cada 15 minutos inicialmente, y posteriormente cada 30 minutos."},{"front":"¿En qué consiste el manejo activo del tercer periodo del trabajo de parto para prevenir la hemorragia?","back":"Aplicación de oxitocina, tracción controlada del cordón umbilical y masaje uterino."},{"front":"¿Cuál es la vida media de la oxitocina?","back":"5 minutos."},{"front":"Uterotónico de primera elección para el tratamiento de la hemorragia posparto si no se recibió profilaxis:","back":"Oxitocina."},{"front":"¿Cuál es la dosis máxima de oxitocina mencionada para el manejo activo del tercer periodo?","back":"40 UI."},{"front":"¿Por qué la ergonovina está contraindicada en pacientes con trastornos hipertensivos del embarazo?","back":"Debido a que puede provocar vasoespasmo grave."},{"front":"¿Cuál es la dosis y vía de administración de la carbetocina recomendada en cesáreas?","back":"100 microgramos vía intravenosa lenta."},{"front":"El uso de misoprostol para la hemorragia posparto debe reservarse únicamente para casos donde _____.","back":"No se cuente con ningún otro medicamento uterotónico."},{"front":"¿Cuál es la dosis estándar de ácido tranexámico recomendada en la hemorragia posparto?","back":"1 gramo vía intravenosa."},{"front":"¿Cuál es la ventana de tiempo ideal para administrar el ácido tranexámico tras el inicio de la hemorragia?","back":"Dentro de las primeras 3 horas."},{"front":"Mencione una medida de manejo hemostático mecánico inicial antes de recurrir a la vía quirúrgica:","back":"Compresión uterina bimanual."},{"front":"¿Para qué sirve el pantalón antichoque no neumático en el contexto de la hemorragia obstétrica?","back":"Como medida temporal de estabilización en caso de traslado de la paciente."},{"front":"¿Cuáles son las dos suturas uterinas hemostáticas más comunes en el manejo quirúrgico conservador?","back":"B-Lynch y Hayman."},{"front":"¿Cuál es el tratamiento quirúrgico definitivo para una hemorragia puerperal que no responde a otras medidas?","back":"Histerectomía."},{"front":"En la mnemotecnia de las 4T's de la hemorragia, ¿qué representa la 'T' de Tono?","back":"Atonía uterina."},{"front":"En la mnemotecnia de las 4T's de la hemorragia, ¿qué representa la 'T' de Trauma?","back":"Lesiones del canal de parto, como desgarros o ruptura uterina."},{"front":"En la mnemotecnia de las 4T's de la hemorragia, ¿qué representa la 'T' de Tejido?","back":"Retención de restos placentarios o coágulos."},{"front":"En la mnemotecnia de las 4T's de la hemorragia, ¿qué representa la 'T' de Trombina?","back":"Alteraciones de la coagulación (coagulopatías)."},{"front":"¿Qué porcentaje de las hemorragias posparto se deben a problemas de tono (atonía)?","back":"50 a 70%."},{"front":"¿Qué factores de riesgo causan sobredistensión uterina y predisponen a la atonía?","back":"Productos macrosómicos, gestación múltiple y polihidramnios."},{"front":"Según la clasificación de desgarros de Sultan, ¿qué estructuras se dañan en el Grado 2?","back":"La piel y los músculos perineales, sin afectar el esfínter anal."},{"front":"¿Qué define a un desgarro perineal de Grado 3?","back":"La afectación o daño del esfínter anal."},{"front":"¿Cuál es la diferencia entre un desgarro Grado 3a y uno 3b?","back":"El 3a afecta menos del 50% del esfínter, mientras que el 3b afecta más del 50%."},{"front":"¿Qué estructura se ve afectada específicamente en un desgarro Grado 4?","back":"La mucosa rectal."},{"front":"¿A partir de qué grado de desgarro perineal se debe administrar profilaxis antibiótica?","back":"Grado 3 y Grado 4."},{"front":"¿Qué es la placenta succenturiata?","back":"Una placenta que posee un lóbulo accesorio fuera del cuerpo placentario principal."},{"front":"¿Cuál es el manejo inicial ante la sospecha de retención de tejido placentario?","back":"Revisión manual de la cavidad bajo anestesia y legrado si es necesario."},{"front":"¿Qué causa suele provocar una inversión uterina aguda?","back":"Una tracción incorrecta o excesiva del cordón umbilical antes del desprendimiento placentario."},{"front":"¿Qué fármacos se utilizan para relajar el útero y facilitar la reposición en una inversión uterina?","back":"Tocolíticos."},{"front":"¿Cómo se define el choque hemorrágico en la paciente obstétrica según el volumen total perdido?","back":"Pérdida mayor o igual al 15% del volumen total de sangre."},{"front":"¿Cuál es el volumen sanguíneo estimado por kilogramo de peso en una mujer embarazada?","back":"100 ml/kg."},{"front":"Fórmula para calcular el Índice de Choque (IC):","back":"Frecuencia Cardíaca dividida entre la Tensión Arterial Sistólica."},{"front":"¿Qué valor del Índice de Choque se considera diagnóstico de un estado de choque en obstetricia?","back":"Mayor a 0.9."},{"front":"Mencione un dato de severidad del choque hemorrágico relacionado con la gasometría arterial:","back":"Déficit de base menor a -10 o lactato mayor a 4."},{"front":"¿Cuál es el valor del Índice de Choque que indica un estado de choque severo?","back":"Mayor a 1.7."},{"front":"¿Qué valor de gasto urinario indica hipoperfusión renal en la paciente en choque?","back":"Menor de 0.5 ml/kg/hora."},{"front":"¿Cuál es el objetivo de Tensión Arterial Media (PAM) durante la reanimación del choque obstétrico?","back":"Mantener una PAM mayor a 60 mmHg."},{"front":"¿Cuál es el volumen inicial de cristaloides recomendado para la reanimación hídrica inicial?","back":"30 ml/kg de solución Hartmann o fisiológica."},{"front":"¿Cuál es el umbral de hemoglobina recomendado para iniciar una transfusión de concentrados eritrocitarios?","back":"Menor a 7 g/dL."},{"front":"¿A partir de qué nivel de fibrinógeno se recomienda la reposición con crioprecipitados?","back":"Menor a 200 mg/dL."},{"front":"En una hemorragia activa, ¿cuál es el nivel de plaquetas por debajo del cual se debe transfundir?","back":"Menor a 50,000 /ml."},{"front":"¿Cuál es la relación de paquetes recomendada en un protocolo de transfusión masiva (Plaquetas:Plasma:Eritrocitos)?","back":"1:1:2."},{"front":"¿Cómo se define la sepsis materna?","back":"Disfunción orgánica potencialmente mortal causada por una respuesta incontrolable del huésped a la infección durante el embarazo o puerperio."},{"front":"¿Cuál es el factor de riesgo independiente más importante para desarrollar sepsis materna?","back":"Cesárea no programada de urgencia."},{"front":"Los tres microorganismos principales causantes de sepsis materna son: E. coli, S. aureus y _____.","back":"S. pyogenes."},{"front":"¿Cuál es la infección no relacionada con el embarazo más frecuente durante la gestación?","back":"Pielonefritis."},{"front":"¿Cuál es la infección relacionada con el embarazo más frecuente durante el mismo?","back":"Corioamnionitis."},{"front":"¿Qué herramienta se utiliza para el tamizaje de disfunción orgánica en sepsis materna?","back":"Criterios omSOFA."},{"front":"¿Cuál es el estudio de laboratorio más importante para el diagnóstico etiológico en sepsis materna?","back":"Hemocultivo."},{"front":"¿En qué plazo debe iniciarse el antibiótico empírico ante la sospecha de sepsis materna?","back":"En el plazo máximo de una hora."},{"front":"¿Cuál es el esquema antibiótico empírico inicial recomendado en sepsis materna?","back":"Ampicilina con Gentamicina."},{"front":"¿Cuál es el vasopresor de elección en caso de choque séptico persistente tras reanimación hídrica?","back":"Norepinefrina."},{"front":"Definición de endometritis puerperal:","back":"Infección del tracto genital ocurrida entre la ruptura de membranas y los 42 días posteriores al parto."},{"front":"¿Qué procedimiento obstétrico se asocia frecuentemente con el desarrollo de endometritis?","back":"Revisión de la cavidad uterina."},{"front":"Mencione dos datos clínicos característicos de la endometritis:","back":"Fiebre y flujo vaginal fétido (loquios fétidos)."},{"front":"¿Cuál es el esquema antibiótico de elección para endometritis según el cuadro básico?","back":"Amoxicilina con Ácido Clavulánico o Dicloxacilina."},{"front":"¿Cuál es el agente causal más común de la mastitis puerperal?","back":"S. aureus."},{"front":"En una paciente con choque hemorrágico, ¿cuál es la meta de gasto urinario para considerar una reanimación adecuada?","back":"1 a 2 ml/kg/hora."}]},"3":{"num":3,"name":"SANGRADOS UTERINOS ANORMALES","cards":[{"front":"¿Cómo se define el Sangrado Uterino Anormal (SUA)?","back":"Alteración del ciclo menstrual normal que afecta la frecuencia, duración y cantidad de flujo."},{"front":"Definición de Hemorragia Uterina Anormal (HUA)","back":"Sangrado uterino que presenta un aumento tanto en duración como en cantidad."},{"front":"¿Qué es la metrorragia?","back":"Pérdida sanguínea intermenstrual de origen uterino no atribuible a la menstruación."},{"front":"¿Qué criterio de duración define a la menorragia?","back":"Menstruación que dura más de 7 días."},{"front":"¿Qué es la menometrorragia?","back":"Sangrado intermenstrual que se presenta de forma abundante."},{"front":"¿Cuál es el rango de duración normal de la menstruación?","back":"3-8 días."},{"front":"¿Cuál es el volumen de pérdida hemática considerado normal en un ciclo?","back":"5-80 ml."},{"front":"¿Cuál es la frecuencia normal del ciclo menstrual en días?","back":"24-38 días."},{"front":"Capacidad de absorción estimada de un tampón","back":"5 ml."},{"front":"Capacidad de absorción estimada de una toalla sanitaria","back":"15 ml."},{"front":"¿Qué representan las siglas de la clasificación estructural PALM?","back":"Pólipo, Adenomiosis, Leiomioma y Malignidad."},{"front":"¿Qué representan las siglas de la clasificación no anatómica COEIN?","back":"Coagulopatía, Disfunción ovulatoria, Endometrial, Iatrogénica y No clasificado."},{"front":"¿Cuál es la causa más frecuente dentro de la clasificación COEIN?","back":"Disfunción ovulatoria."},{"front":"Definición de dismenorrea","back":"Dolor uterino asociado a la menstruación por aumento de contracciones debido a un desequilibrio hormonal."},{"front":"Factores hormonales involucrados en la fisiopatología de la dismenorrea","back":"Desequilibrio entre progesterona, vasopresina y prostaglandinas E2 y F2."},{"front":"¿Qué caracteriza a la dismenorrea primaria?","back":"Ausencia de patología orgánica asociada, iniciando usualmente en los primeros 6 meses tras la menarca."},{"front":"Localización y tipo de dolor típico en la dismenorrea primaria","back":"Dolor tipo cólico en región hipogástrica con irradiación lumbosacra o al muslo anterior."},{"front":"¿Cuál es la causa más común de dismenorrea secundaria?","back":"Endometriosis."},{"front":"Diferencia clínica del dolor en la dismenorrea secundaria respecto a la primaria","back":"El dolor es más persistente, severo y puede presentarse fuera del ciclo menstrual."},{"front":"Factores de riesgo para desarrollar dismenorrea","back":"IMC menor a 20, tabaquismo, consumo de alcohol/drogas y antecedentes heredofamiliares."},{"front":"Factores protectores contra la dismenorrea","back":"Uso de anticonceptivos orales, ejercicio, multiparidad e ingesta de pescado."},{"front":"Estudio de imagen de elección para la evaluación inicial de dismenorrea","back":"Ultrasonido pélvico o transvaginal."},{"front":"Estándar de oro para el diagnóstico de dismenorrea secundaria y dolor pélvico crónico","back":"Laparoscopia."},{"front":"Tratamiento farmacológico de primera elección para la dismenorrea","back":"AINES por un periodo de 3 meses."},{"front":"Tratamiento quirúrgico de última elección para dismenorrea refractaria","back":"Neurectomía pre-sacra."},{"front":"¿Qué es la endometriosis?","back":"Presencia de glándulas y estroma endometrial fuera del útero, siendo una patología benigna y estrógeno dependiente."},{"front":"¿En qué consiste la teoría de Sampson sobre la endometriosis?","back":"Menstruación retrógrada, donde el tejido endometrial regresa por las trompas y se implanta en la cavidad."},{"front":"¿En qué consiste la teoría de Meyer sobre la endometriosis?","back":"Metaplasia del epitelio celómico, donde células fuera del útero se transforman en tejido similar al endometrio."},{"front":"Localización anatómica más frecuente de la endometriosis","back":"Ovarios (frecuentemente el izquierdo)."},{"front":"Sitio más frecuente de recurrencia de la endometriosis","back":"Intestino."},{"front":"La tríada clásica de la endometriosis","back":"Dispareunia, infertilidad y dismenorrea."},{"front":"Síntoma más frecuente de la endometriosis en general","back":"Dolor pélvico crónico (presente en el 95% de los casos)."},{"front":"Manifestación clínica de la endometriosis torácica","back":"Hemoptisis catamenial, dolor torácico, tos y disnea."},{"front":"¿En qué momento del ciclo se recomienda realizar la exploración física en sospecha de endometriosis?","back":"Durante la menstruación."},{"front":"Estudio de imagen inicial para identificar endometriomas","back":"Ultrasonido transvaginal."},{"front":"Estándar de oro terapéutico en endometriosis","back":"Laparoscopia (especialmente ante endometriomas > 3 cm)."},{"front":"Tratamiento quirúrgico definitivo para pacientes con paridad satisfecha y endometriosis grave","back":"Histerectomía total abdominal más ooforectomía."},{"front":"¿Qué complicación obstétrica es común en pacientes con endometriosis en el primer trimestre?","back":"Aborto espontáneo o embarazo ectópico."},{"front":"¿Qué es el Síndrome de Ovario Poliquístico (SOP)?","back":"Endocrinopatía caracterizada por hiperandrogenismo, alteraciones menstruales y anovulación crónica."},{"front":"¿Cuál es el otro nombre del Síndrome de Ovario Poliquístico?","back":"Síndrome de Stein-Leventhal."},{"front":"Mecanismo fisiopatológico de la anovulación en el SOP","back":"Elevación de LH en meseta que evita el pico necesario para la ovulación."},{"front":"Relación hormonal típica LH/FSH en el SOP","back":"Relación LH/FSH > 2."},{"front":"Dato clínico más frecuente del hiperandrogenismo en SOP","back":"Hirsutismo (presente en el 60%)."},{"front":"¿Qué escala se utiliza para evaluar el hirsutismo y qué puntaje es diagnóstico?","back":"Escala de Ferriman-Gallwey, con un puntaje ≥ 8."},{"front":"Criterios de Rotterdam para SOP (mencione los 3 componentes)","back":"Oligo/Anovulación, hiperandrogenismo (clínico o bioquímico) y ovarios poliquísticos por ultrasonido."},{"front":"Hallazgo ultrasonográfico de ovario poliquístico según criterios de Rotterdam","back":"≥ 12 folículos de 2-9 mm o volumen ovárico > 10 ml."},{"front":"Valor de progesterona en fase lútea que confirma anovulación en el SUA","back":"Menor a 5 ng/ml."},{"front":"Estudio para descartar hiperplasia suprarrenal si la testosterona está muy elevada en SOP","back":"Prueba de 17-hidroxiprogesterona."},{"front":"Piedra angular del tratamiento del SOP","back":"Cambios en el estilo de vida (dieta y actividad física)."},{"front":"Tratamiento de primera línea para pacientes con SOP sin deseos de embarazo","back":"Anticonceptivos orales combinados (Etinilestradiol)."},{"front":"Tratamiento de primera elección para la infertilidad en SOP (México)","back":"Citrato de clomifeno."},{"front":"Indicación de la metformina en el tratamiento del SOP","back":"Manejo de la resistencia a la insulina y disminución de concentraciones de LH."},{"front":"Fármaco antiandrógeno preferido en SOP combinado con etinilestradiol","back":"Ciproterona."},{"front":"¿Con qué frecuencia se deben inducir hemorragias con progestágenos para prevenir cáncer de endometrio en SOP?","back":"Al menos cada tercer mes."},{"front":"Complicaciones a largo plazo del SOP","back":"Diabetes mellitus tipo 2, síndrome metabólico y cáncer de endometrio."},{"front":"¿Cuándo se debe sospechar de una coagulopatía como causa de SUA?","back":"Presencia de equimosis o epistaxis recurrentes (1-2 veces al mes) y gingivorragia frecuente."},{"front":"¿Qué deficiencia específica se debe investigar ante sospecha de coagulopatía en SUA?","back":"Deficiencia del factor de Von Willebrand."},{"front":"Complicación tardía más común tras tratamiento quirúrgico de endometriosis","back":"Recurrencia de síntomas en el 50% de los casos a los 5 años."},{"front":"Efecto de los AINES administrados a mitad del ciclo menstrual","back":"Pueden producir un efecto anovulatorio."},{"front":"Análogo de GnRH utilizado en endometriosis por menos de 6 meses","back":"Goserelina."},{"front":"¿Qué estudio se debe realizar si una paciente usa análogos de GnRH por más de 6 meses?","back":"Densitometría ósea (para vigilar hipoestrogenismo)."},{"front":"Indicación terapéutica del acetato de medroxiprogesterona en SOP","back":"Lograr sangrado menstrual en pacientes con oligomenorrea, al menos cada 3 meses."},{"front":"¿Qué determina el índice HOMA en pacientes con SOP?","back":"La presencia de resistencia a la insulina."},{"front":"Razón glucosa/insulina que sugiere resistencia a la insulina en SOP","back":"Mayor a 4.5."},{"front":"Principal causa de consulta estética en pacientes con SOP","back":"Acné."}]},"4":{"num":4,"name":"SANGRADO UTERINO DE ORIGEN ANATOMICO","cards":[{"front":"¿Cómo se define un pólipo endometrial según su morfología?","back":"Es una protrusión benigna sobre la superficie endometrial."},{"front":"Menciona tres factores de riesgo para el desarrollo de pólipos endometriales.","back":"Edad avanzada, obesidad y el uso de tamoxifeno."},{"front":"¿Qué métodos anticonceptivos actúan como factores protectores contra los pólipos?","back":"Los anticonceptivos orales (ACOS) y el DIU de levonorgestrel (LNG)."},{"front":"¿Cuál es el estudio de primera elección para el diagnóstico de pólipos endometriales?","back":"Ultrasonido (USG)."},{"front":"¿Cuál es el Gold Standard para el diagnóstico de pólipos endometriales?","back":"Histerosonografía."},{"front":"¿Cuál es la forma más frecuente de presentación clínica de los pólipos endometriales?","back":"Asintomática."},{"front":"¿Cómo se describe el sangrado intermenstrual característico de los pólipos?","back":"Sangrado \"en goteo\"."},{"front":"¿Qué procedimiento se debe realizar tras la extirpación quirúrgica de un pólipo?","back":"Estudio histológico para descartar malignidad."},{"front":"¿Qué es la adenomiosis?","back":"Es la extensión de glándulas y tejido endometrial hacia el miometrio."},{"front":"¿Cuál es el pico de incidencia de edad para la adenomiosis?","back":"Entre los 40 y 50 años."},{"front":"¿Cuál es el estudio inicial para el diagnóstico de adenomiosis?","back":"Ultrasonido transvaginal."},{"front":"En un USG transvaginal, ¿qué hallazgo es sugerente de adenomiosis?","back":"Presencia de lagunas quísticas en el miometrio."},{"front":"¿Cuál es el estudio de elección (más específico) para adenomiosis?","back":"Resonancia Magnética (RM)."},{"front":"¿Cuál es el Gold Standard para el diagnóstico de la adenomiosis?","back":"Biopsia o estudio histológico."},{"front":"Describe las características físicas del útero en la adenomiosis.","back":"Útero aumentado de tamaño, globular y simétrico (similar a 14 SDG)."},{"front":"¿En qué consiste el signo de Halban?","back":"Presencia de un útero blando y doloroso a la palpación bimanual."},{"front":"¿Cuál es el tratamiento definitivo para la adenomiosis?","back":"Histerectomía."},{"front":"Concepto: Leiomioma","back":"Tumor benigno de músculo liso (miometrio) que es hormonodependiente."},{"front":"¿Cuál es la neoplasia benigna ginecológica más común?","back":"Miomatosis uterina."},{"front":"¿Qué grupo étnico presenta el mayor riesgo de padecer miomatosis uterina?","back":"Pacientes afroamericanas."},{"front":"¿Qué sucede con el tamaño de los miomas durante la menopausia?","back":"Sufren regresión debido a su dependencia hormonal."},{"front":"¿Qué tipo de mioma se localiza por debajo del endometrio y es el más sintomático?","back":"Mioma submucoso."},{"front":"¿Qué porcentaje de los miomas son de localización intramural?","back":"55%."},{"front":"Define el mioma subseroso.","back":"Mioma localizado en la superficie uterina que deforma la serosa."},{"front":"¿Qué tipo de mioma se asocia con mayor frecuencia a la infertilidad por dificultad de implantación?","back":"Mioma submucoso."},{"front":"Según la clasificación por tamaño, ¿cuál es el diámetro de un mioma de medianos elementos?","back":"Entre 2.1 y 6 cm."},{"front":"Define la miomatosis gigante.","back":"Presencia de miomas con un diámetro mayor a 20 cm."},{"front":"¿Qué tipo de degeneración de los miomas es más frecuente durante el embarazo?","back":"Degeneración roja (por infarto muscular agudo)."},{"front":"¿Cuál es el síntoma clínico más frecuente de la miomatosis uterina?","back":"Menorragia (sangrado abundante)."},{"front":"¿Qué tipo de anemia es característica en pacientes con miomatosis sintomática?","back":"Anemia microcítica hipocrómica."},{"front":"¿Cuál es el estudio inicial para detectar miomas mayores a 5 cm?","back":"Exploración bimanual."},{"front":"¿A partir de qué tamaño un ultrasonido puede detectar miomas uterinos?","back":"Mayores a 3 cm."},{"front":"¿Cuál es el estudio de imagen con mayor sensibilidad y especificidad para miomatosis?","back":"Resonancia Magnética (RM)."},{"front":"¿Cuál es el estudio de elección para el diagnóstico de miomas submucosos?","back":"Histeroscopía."},{"front":"¿Qué tratamiento médico se indica prequirúrgicamente para reducir el tamaño de un mioma?","back":"Análogos de GnRH."},{"front":"¿En qué porcentaje reducen los análogos de GnRH el tamaño de los miomas?","back":"Entre un 35% y 60%."},{"front":"¿Cuál es la técnica quirúrgica de elección para miomas de medianos y grandes elementos?","back":"Laparotomía."},{"front":"¿Bajo qué condiciones se utiliza la miomectomía por laparoscopía?","back":"En miomas de pequeños elementos cuando son únicos."},{"front":"¿Cuál es la conducta a seguir ante una paciente asintomática con útero menor a 14 cm?","back":"Vigilancia clínica y por USG cada 6 a 12 meses."},{"front":"¿Cuándo se debe referir a una paciente con miomatosis a segundo nivel?","back":"Si es sintomática, el útero mide más de 14 cm o es de rápido crecimiento."},{"front":"De acuerdo al método de Higham, ¿cuál es el volumen de sangre que absorbe un tampón súper?","back":"8 ml."},{"front":"¿Qué volumen de pérdida sanguínea representa una toalla nocturna según el método de Higham?","back":"15 ml."},{"front":"Define torsión ovárica.","back":"Rotación del ovario y la trompa sobre su pedículo vascular, interrumpiendo el flujo sanguíneo."},{"front":"¿Cuál es el principal factor de riesgo para sufrir una torsión ovárica?","back":"Presencia de masas ováricas mayores a 5-6 cm."},{"front":"¿Por qué el ovario derecho se afecta más frecuentemente en una torsión?","back":"Porque el ligamento utero-ovárico derecho es más largo."},{"front":"Menciona la tríada clínica de la torsión ovárica.","back":"Dolor pélvico súbito unilateral, náuseas/vómitos y masa anexial palpable."},{"front":"¿Qué indica la presencia de fiebre en un cuadro de torsión ovárica?","back":"Necrosis del tejido afectado."},{"front":"¿Cuál es el estándar de oro para el diagnóstico de torsión ovárica?","back":"Laparoscopía diagnóstica."},{"front":"¿Cuál es el hallazgo ultrasonográfico típico en una torsión ovárica?","back":"Ovario aumentado de tamaño con folículos periféricos."},{"front":"¿Cuál es el tratamiento de elección para restaurar el flujo en la torsión ovárica?","back":"Destorsión por laparoscopía inmediata."},{"front":"¿En qué casos se indica una ooforectomía ante una torsión ovárica?","back":"Cuando el tejido está necrótico o en mujeres postmenopáusicas."},{"front":"¿Qué complicación es frecuente en pacientes sometidas a histerectomía?","back":"Tromboembolismo venoso."},{"front":"¿Qué fármaco se utiliza para el manejo del sangrado uterino anormal en pacientes con actividad sexual?","back":"DIU de levonorgestrel."},{"front":"¿Cuál es la causa más frecuente de histerectomía según el material?","back":"Miomatosis uterina."},{"front":"¿A qué edad es más común encontrar adenomiosis en lugar de miomatosis?","back":"En pacientes multíparas entre 35 y 50 años."}]},"5":{"num":5,"name":"PATOLOGIA DE MENOPAUSIA Y CLIMATERIO","cards":[{"front":"¿Cómo se define la menopausia fisiológica?","back":"Ausencia de menstruación por más de 12 meses en personas de 40 años o más."},{"front":"¿A qué edad se considera que el cese de la menstruación es una insuficiencia ovárica primaria?","back":"En personas menores de 40 años."},{"front":"¿Qué periodo comprende la posmenopausia temprana?","back":"Los primeros 5 años después del último periodo menstrual."},{"front":"¿Cuál es la definición de perimenopausia?","back":"Desde el inicio de alteraciones en el ciclo menstrual hasta un año después de la última menstruación."},{"front":"¿Qué es el síndrome climatérico?","back":"Conjunto de signos y síntomas que se presentan durante la perimenopausia."},{"front":"¿Cuál es la edad media de presentación de la menopausia en México?","back":"49 a 50 años."},{"front":"Menciona dos factores de riesgo no modificables para la patología de la menopausia.","back":"Raza negra y padecimientos crónicos."},{"front":"¿Cuál es la ingesta diaria recomendada de calcio para proteger la salud ósea en el climaterio?","back":"1000 a 1200 mg/día."},{"front":"¿Cuál es la dosis diaria recomendada de vitamina D en el periodo climatérico?","back":"800 a 1000 UI/día."},{"front":"¿A qué cambio hormonal se asocia el inicio de los síntomas climatéricos?","back":"A una disminución de los niveles de estrógenos."},{"front":"¿Por qué aumenta la FSH durante la transición a la menopausia?","back":"Por el descenso de la inhibina, lo que elimina la retroalimentación negativa."},{"front":"¿Cuál es el nivel de FSH característico en la premenopausia según el diagnóstico hormonal?","back":"Mayor a 25 UI/L."},{"front":"¿Cuál es el principal estrógeno presente en la posmenopausia?","back":"Estrona."},{"front":"En la posmenopausia, el nivel de FSH es mayor a 40 UI/L y el estradiol es menor a _____.","back":"20 pg/mL"},{"front":"¿Qué escala se utiliza para clasificar las etapas reproductivas de la mujer?","back":"Clasificación de STRAW."},{"front":"¿Qué síntomas caracterizan a la atrofia urogenital en la posmenopausia?","back":"Dispareunia, sequedad vaginal y urgencia miccional."},{"front":"¿Cuál es el porcentaje de densidad ósea que se puede perder a lo largo de la vida debido a la osteoporosis?","back":"70%."},{"front":"¿Qué estudios de gabinete e laboratorio integrales se deben realizar a pacientes en edad climatérica?","back":"Citología vaginal, perfil de lípidos, glucosa, TSH, densitometría, mastografía y USG pélvico."},{"front":"¿Cuál es el objetivo principal del tratamiento de primera elección en el síndrome climatérico?","back":"Reducir el 70% de los síntomas."},{"front":"¿Cuál es la indicación para iniciar terapia hormonal en una paciente climatérica?","back":"Afectación significativa en la calidad de vida."},{"front":"¿Qué esquema hormonal se utiliza en pacientes con útero intacto en etapa de premenopausia?","back":"Terapia secuencial combinada (estrógenos diarios + progestágenos 10-14 días)."},{"front":"¿Qué esquema hormonal se indica en pacientes con útero en etapa de posmenopausia?","back":"Combinado continuo (estrógenos y progestágenos)."},{"front":"¿Qué terapia hormonal se prescribe a pacientes con síndrome climatérico que no tienen útero?","back":"Terapia estrogénica simple o tibolona."},{"front":"¿Qué vía de administración de terapia hormonal es preferible en pacientes con hipertensión arterial o riesgo de trombosis?","back":"Parche transdérmico."},{"front":"¿Qué fármacos se consideran de segunda línea si hay contraindicación para hormonas en el climaterio?","back":"Inhibidores de la recaptura de serotonina y norepinefrina (como desvenlafaxina)."},{"front":"Menciona tres contraindicaciones absolutas para la terapia hormonal.","back":"Cáncer de mama, tromboembolismo venoso y enfermedad hepática activa."},{"front":"¿Qué planta medicinal es un ejemplo de fitoterapia (cumestanos) para el climaterio?","back":"Alfalfa."},{"front":"¿Cómo se define la osteoporosis?","back":"Disminución de masa ósea y deterioro de la microarquitectura con aumento de fragilidad y riesgo de fracturas."},{"front":"¿Cuál es la causa de la osteoporosis primaria tipo I?","back":"Deficiencia de estrógenos (postmenopáusica)."},{"front":"¿Qué caracteriza a la osteoporosis primaria tipo II?","back":"Pérdida de masa cortical debida a la edad (senil)."},{"front":"¿Cuál es el valor de T-score para diagnosticar osteopenia?","back":"Entre -1.0 y -2.5 desviaciones estándar."},{"front":"¿A partir de qué valor de T-score se diagnostica osteoporosis?","back":"Menor a -2.5 desviaciones estándar."},{"front":"¿Qué compara el índice Z en una densitometría ósea?","back":"La densidad de la paciente con adultos de su misma edad."},{"front":"¿Cuáles son los sitios más frecuentes de fractura por fragilidad?","back":"Columna (por compresión) y cadera."},{"front":"¿Cuál es la fractura por fragilidad más grave en términos de morbimortalidad?","back":"Fractura de cadera."},{"front":"¿Por qué se debe evitar el consumo excesivo de cafeína en la prevención de osteoporosis?","back":"Porque evita la absorción de calcio."},{"front":"¿Qué es una fractura de bajo impacto?","back":"Aquella que ocurre tras una caída de la propia altura o menor, o sin traumatismo evidente."},{"front":"¿Cuál es la conducta a seguir en una paciente mayor de 65 años sin antecedentes de fractura?","back":"Realizar densitometría ósea directamente."},{"front":"¿Qué herramienta estima el riesgo de fracturas osteoporóticas a 10 años basándose en factores clínicos?","back":"Índice FRAX."},{"front":"¿Cuál es el fármaco de elección para el tratamiento de osteoporosis con riesgo bajo o moderado?","back":"Bifosfonatos vía oral (como alendronato o risedronato)."},{"front":"¿Qué medicamento se indica en osteoporosis si hay intolerancia a bifosfonatos orales?","back":"Ácido zoledrónico intravenoso."},{"front":"¿Qué fármaco es una opción para osteoporosis en pacientes con riesgo de cáncer de mama?","back":"Raloxifeno."},{"front":"¿Qué anticuerpo monoclonal puede usarse para la osteoporosis en pacientes con insuficiencia renal?","back":"Denosumab."},{"front":"¿Cómo se define el éxito del tratamiento de la osteoporosis tras el primer año?","back":"Un incremento de la densidad ósea en un 3%."},{"front":"¿Qué es el prolapso de órganos pélvicos (POP)?","back":"El descenso de uno o más órganos pélvicos hacia la vagina."},{"front":"¿Cuál es el síntoma más específico del prolapso de órganos pélvicos?","back":"Sensación de cuerpo extraño en la vagina."},{"front":"En el estadio 0 del prolapso según la ICS, ¿dónde se ubican los puntos anteriores y posteriores?","back":"En -3 cm."},{"front":"¿Qué rango define el Estadio II de prolapso en la escala de Bump?","back":"El punto de mayor prolapso está entre -1 cm y +1 cm respecto al himen."},{"front":"¿Cuál es el tratamiento quirúrgico de elección para el prolapso de pared vaginal?","back":"Colporrafia (anterior o posterior)."},{"front":"¿Cómo se define la incontinencia urinaria de esfuerzo?","back":"Pérdida de orina durante actividades que aumentan la presión abdominal (tos, estornudo)."},{"front":"¿A qué se debe la incontinencia urinaria de urgencia?","back":"A contracciones involuntarias del músculo detrusor."},{"front":"¿Cuál es la maniobra física para sospechar incontinencia de esfuerzo?","back":"Maniobra de Valsalva positiva."},{"front":"¿Cuál es el tratamiento de primera línea para la incontinencia urinaria de esfuerzo?","back":"Ejercicios de piso pélvico (Ejercicios de Kegel)."},{"front":"¿Qué fármaco se utiliza específicamente para el tratamiento médico de la incontinencia de esfuerzo?","back":"Duloxetina."},{"front":"Menciona un ejemplo de fármaco antimuscarínico para la incontinencia de urgencia.","back":"Oxibutinina (o Tolterodina)."},{"front":"¿Cuáles son los criterios diagnósticos para insuficiencia ovárica primaria?","back":"Amenorrea antes de los 40 años (mínimo 4 meses) y FSH > 25-40 UI/L en dos tomas."},{"front":"¿Qué prueba se utiliza para diagnosticar la hipermovilidad uretral en la incontinencia de esfuerzo?","back":"Prueba de Q-tip."},{"front":"¿Para qué se utiliza la veralaprida en el síndrome climatérico?","back":"Para el manejo de crisis vasomotoras (reduce síntomas hasta un 80%)."}]},"6":{"num":6,"name":"ONCOLOGIA GINECOLOGICA","cards":[{"front":"¿Qué hallazgo clínico es característico del cáncer de endometrio en estadios tempranos?","back":"Sangrado transvaginal con aspecto de \"agua de lavar carne\" y crecimiento uterino."},{"front":"¿Cuál es la tríada clínica sugerente de cáncer de ovario en etapas avanzadas?","back":"Distensión o dolor abdominal, masa en flancos y presencia de ascitis."},{"front":"En el cáncer cervicouterino, el sangrado en \"agua de lavar carne\" y la leucorrea fétida suelen presentarse en estadios _____.","back":"Tardíos"},{"front":"¿Cuál es el estímulo hormonal principal que condiciona la hiperplasia endometrial?","back":"Un estímulo mantenido de estrógenos sin oposición de progestágenos."},{"front":"¿Por qué la hiperplasia endometrial se presenta frecuentemente en los extremos de la vida reproductiva?","back":"Debido a la presencia de ciclos de oligoovulación."},{"front":"Mencione tres factores de riesgo para hiperplasia endometrial asociados a hiperestrogenismo sostenido.","back":"SOP (Síndrome de Ovario Poliquístico), nuliparidad e infertilidad."},{"front":"¿A partir de qué edad se considera un factor de riesgo para el desarrollo de patología endometrial?","back":"Mayor a 45 años."},{"front":"¿Qué fármaco modulador de los receptores de estrógeno se asocia con un mayor riesgo de hiperplasia y cáncer de endometrio?","back":"Tamoxifeno"},{"front":"¿Cuál es el factor de progresión a malignidad más importante en la hiperplasia endometrial?","back":"La presencia de atipias celulares."},{"front":"Concepto: Hiperplasia simple","back":"Definición: Tipo de hiperplasia endometrial más frecuente, con un riesgo de malignización del 1-5%."},{"front":"¿Cuál es el riesgo de malignización de una hiperplasia endometrial compleja con atipia?","back":"Aproximadamente del 29-30%."},{"front":"¿Cuánto tiempo de uso de anticonceptivos orales combinados se requiere para considerarse un factor protector contra patología endometrial?","back":"Más de un año de uso continuo."},{"front":"¿Qué dispositivo intrauterino actúa como factor protector para la hiperplasia endometrial?","back":"DIU de levonorgestrel (DIU-LNG)."},{"front":"¿Cuál es el síntoma clínico más común de la hiperplasia endometrial?","back":"Hemorragia intermenstrual."},{"front":"¿Cuál es el estudio inicial para valorar el grosor endometrial en pacientes con sospecha de hiperplasia?","back":"Ultrasonido (USG) transvaginal."},{"front":"¿Cuál es el punto de corte del grosor endometrial por USG para solicitar biopsia en una mujer premenopáusica?","back":"Grosor de 12 mm o más."},{"front":"¿Cuál es el punto de corte del grosor endometrial por USG para solicitar biopsia en una mujer postmenopáusica?","back":"Grosor de 5 mm o más."},{"front":"¿Cuál es el estándar de oro para el diagnóstico de hiperplasia endometrial?","back":"Biopsia endometrial con estudio histopatológico."},{"front":"¿Qué alternativa técnica existe para la toma de biopsia endometrial además de la cánula de Pipelle?","back":"AMEU (Aspiración Manual Endouterina)."},{"front":"¿En qué tipo de hiperplasia endometrial está indicado el tratamiento farmacológico con progestágenos?","back":"En la hiperplasia sin atipia."},{"front":"¿Cuál es la indicación de tratamiento quirúrgico (histerectomía) en la hiperplasia endometrial?","back":"Presencia de hiperplasia con atipia o falla al tratamiento médico."},{"front":"¿Cuál es la estirpe histológica más frecuente del cáncer de endometrio?","back":"Adenocarcinoma endometrioide."},{"front":"¿Cuál es el lugar que ocupa el cáncer de endometrio entre los cánceres ginecológicos en México?","back":"Tercer lugar."},{"front":"¿Qué síndrome genético se asocia con un mayor riesgo hereditario de cáncer de endometrio, ovario y colorrectal?","back":"Síndrome de Lynch."},{"front":"¿Qué factor de riesgo metabólico es crítico para el cáncer de endometrio cuando el peso es mayor a 90 kg?","back":"Obesidad"},{"front":"A diferencia del tamoxifeno, el _____ no se asocia al desarrollo de cáncer de endometrio.","back":"Raloxifeno"},{"front":"El factor protector contra el cáncer de endometrio que suele ser contraproducente para otros sistemas es el _____.","back":"Tabaquismo"},{"front":"Concepto: Cáncer de endometrio Tipo I","back":"Definición: Neoplasia estrógeno-dependiente, asociada a obesidad e hiperplasia, de estirpe endometrioide y mejor pronóstico."},{"front":"Concepto: Cáncer de endometrio Tipo II","back":"Definición: Neoplasia estrógeno-independiente, agresiva, en pacientes delgadas de mayor edad, con invasión miometrial profunda."},{"front":"¿Qué estirpes histológicas se asocian al cáncer de endometrio Tipo II?","back":"Carcinoma seroso y de células claras."},{"front":"¿Cuál es el síntoma más común del cáncer de endometrio en la postmenopausia?","back":"Sangrado uterino anormal (80% de los casos)."},{"front":"¿Para qué se utiliza el marcador CA 125 en el cáncer de endometrio?","back":"Para monitorizar la respuesta clínica en casos de metástasis extrauterina."},{"front":"¿Qué porcentaje de citologías vaginales resultan anormales en pacientes con cáncer de endometrio?","back":"Aproximadamente el 50%."},{"front":"¿En qué consiste la cirugía estadificadora estándar para cáncer de endometrio?","back":"LAPE, lavado peritoneal, histerectomía extrafascial, salpingooforectomía bilateral y linfadenectomía pélvica y paraaórtica."},{"front":"¿En qué casos de cáncer de endometrio se debe realizar omentectomía y toma de biopsias de cúpula diafragmática?","back":"En estirpes de células claras, serosa-papilar o indiferenciados."},{"front":"FIGO Endometrio: ¿Qué define el Estadio IA?","back":"Invasión del miometrio menor al 50%."},{"front":"FIGO Endometrio: ¿Qué define el Estadio IB?","back":"Invasión del miometrio igual o mayor al 50%."},{"front":"FIGO Endometrio: ¿Qué define el Estadio II?","back":"Invasión del estroma cervical."},{"front":"¿Cuál es el tratamiento adyuvante para un Estadio IA, Grado 3 (G3) de cáncer de endometrio?","back":"Radioterapia"},{"front":"¿Qué medicamentos se utilizan en el tratamiento paliativo (quimioterapia) del cáncer de endometrio Estadio IV?","back":"Doxorrubicina y Cisplatino."},{"front":"¿Cuál es la principal causa de muerte por cáncer ginecológico?","back":"Cáncer de ovario."},{"front":"¿Qué porcentaje de los casos de cáncer de ovario se diagnostican en estadio IV?","back":"El 75%."},{"front":"¿Cuál es la teoría etiológica principal para el cáncer de ovario epitelial?","back":"Microtraumatismo secundario a la ovulación."},{"front":"¿Qué mutaciones genéticas incrementan significativamente el riesgo de cáncer de ovario?","back":"Mutaciones en los genes BRCA1 y BRCA2."},{"front":"¿Cuál es el tipo histológico más común de cáncer de ovario?","back":"Tumores epiteliales (60-85%)."},{"front":"Dentro de los tumores epiteliales de ovario, el tipo más frecuente es el _____.","back":"Seroso"},{"front":"Concepto: Cáncer de ovario mucinoso","back":"Definición: Tumor muy grande y multiloculado, asociado a pseudomixoma peritoneal y elevación de CA 19-9 o ACE."},{"front":"¿Qué hallazgo histológico en un tumor seroso de ovario indica que es bien diferenciado y tiene buen pronóstico?","back":"Cuerpos de Psamoma."},{"front":"¿A qué hallazgo físico se asocia el cáncer de ovario con diseminación linfática umbilical?","back":"Nódulo de la Hermana María José."},{"front":"¿Cuál es el estudio de imagen inicial para el diagnóstico de cáncer de ovario?","back":"Ultrasonido transvaginal con Doppler."},{"front":"¿Cuál es el marcador tumoral clásico para el seguimiento de tumores epiteliales de ovario?","back":"CA 125"},{"front":"FIGO Ovario: El Estadio III se define por la afección de ovarios, trompas y _____.","back":"Peritoneo y/o ganglios retroperitoneales."},{"front":"FIGO Ovario: ¿Qué hallazgo define el Estadio IV?","back":"Afección extraperitoneal, incluyendo cultivo positivo en derrame pleural."},{"front":"¿Cuál es el objetivo principal de la cirugía primaria en cáncer de ovario?","back":"Diagnóstico, estadificación y citorreducción máxima."},{"front":"¿Qué esquema de quimioterapia adyuvante es el estándar de elección para cáncer de ovario?","back":"Paclitaxel más Carboplatino (o Cisplatino)."},{"front":"Mencione dos criterios de irresecabilidad de Nelson para cáncer de ovario.","back":"Enfermedad >2 cm en mesenterio/diafragma y niveles de CA 125 > 1,000 U/ml."},{"front":"¿Qué marcadores tumorales se elevan característicamente en un teratoma de ovario?","back":"Alfafetoproteína (AFP) y CA 125."},{"front":"¿Cuál es el tumor germinal maligno más frecuente y a qué síndrome se asocia?","back":"Disgerminoma, asociado al Síndrome de Morris."},{"front":"¿Qué marcadores eleva el disgerminoma de ovario?","back":"CA 125 y β-HCG."},{"front":"Concepto: Tumor de la granulosa","back":"Definición: Tumor de cordones sexuales que secreta estrógenos, presenta cuerpos de Call-Exner y eleva inhibina A y B."},{"front":"Concepto: Síndrome de Meigs","back":"Definición: Tríada de tumor ovárico (frecuentemente tecoma), ascitis e hidrotórax."},{"front":"¿Qué hallazgo histológico es patognomónico de los tumores de células lipídicas (Sertoli-Leydig)?","back":"Cristaloides de Reinke."},{"front":"¿Cuál es el síntoma clínico predominante de un tumor de Sertoli-Leydig?","back":"Virilización (por secreción de andrógenos)."},{"front":"¿Cuál es la localización más frecuente del cáncer de vagina?","back":"Tercer superior de la vagina."},{"front":"¿Qué exposición intrauterina se asocia con el adenocarcinoma de células claras de vagina en adolescentes?","back":"Uso materno de dietilestilbestrol (DES)."},{"front":"¿Cuál es el tipo histológico más común de cáncer de vagina en adultas?","back":"Carcinoma epidermoide."},{"front":"¿Cuál es la técnica de biopsia recomendada para el diagnóstico definitivo de cáncer de vagina?","back":"Técnica de Tischler."},{"front":"¿Dónde se origina más frecuentemente el cáncer de vulva?","back":"En los labios mayores."},{"front":"El cáncer de vulva tipo II se asocia principalmente con la patología vulvar crónica denominada _____.","back":"Liquen escleroso"},{"front":"¿Cuál es el estudio inicial (test) para identificar áreas acetoblancas en la vulva?","back":"Test de Collins (ácido acético)."},{"front":"¿Cuál es el segundo tipo histológico más frecuente de cáncer de vulva?","back":"Melanoma vulvar."},{"front":"¿Qué síndrome se asocia con el gonadoblastoma de ovario?","back":"Síndrome de Swyer."},{"front":"¿A qué se refiere el término 'Tumor de Krukenberg'?","back":"Metástasis ovárica de un cáncer primario de origen gástrico."},{"front":"¿Cuál es el tiempo promedio de recurrencia del cáncer de ovario?","back":"15 meses."},{"front":"¿Qué índice se utiliza en el cáncer de ovario para medir el volumen tumoral peritoneal?","back":"Índice de Carcinomatosis Peritoneal (ICP)."}]},"7":{"num":7,"name":"LESIONES PRECURSORAS Y CACU","cards":[{"front":"¿Dónde se localiza generalmente la lesión intraepitelial precursora del cáncer de cuello uterino?","back":"En la zona de metaplasia escamosa (unión de los epitelios escamoso y cilíndrico)."},{"front":"¿Cómo se denomina a la célula epitelial que presenta cambios morfológicos indicativos de infección por VPH?","back":"Coilocito."},{"front":"¿Qué tipo de epitelio recubre el ectocérvix?","back":"Epitelio escamoso (plano estratificado no queratinizado)."},{"front":"¿Cuál es la infección de transmisión sexual (ITS) más frecuente según el material?","back":"Infección por el Virus del Papiloma Humano (VPH)."},{"front":"¿En qué porcentaje de los casos de cáncer cervicouterino se ha identificado la presencia de VPH?","back":"99.7%."},{"front":"¿Cuáles son los genotipos de VPH de bajo riesgo responsables de la mayoría de las verrugas anogenitales?","back":"6 y 11."},{"front":"¿Qué oncogenes del VPH son responsables de la pérdida del control de la proliferación celular al afectar a p53?","back":"E6 y E7."},{"front":"¿Qué serotipos de VPH cubre la vacuna bivalente Cervarix?","back":"16 y 18."},{"front":"¿Qué serotipos de VPH cubre la vacuna tetravalente Gardasil?","back":"6, 11, 16 y 18."},{"front":"Según los lineamientos de 2025, ¿cuál es la vacuna disponible en la campaña de vacunación en México?","back":"La vacuna nonavalente."},{"front":"En la campaña de 2025, ¿cuál es el esquema de vacunación para niñas de 5to grado de primaria o de 11 años no escolarizadas?","back":"Dosis única."},{"front":"¿Cuál es el esquema de vacunación contra el VPH para personas de 11 a 49 años que viven con VIH?","back":"Tres dosis (0, 2 y 6 meses)."},{"front":"¿Qué vía de administración y sitio anatómico se utiliza para la vacuna contra el VPH?","back":"Vía intramuscular (IM) en la región deltoidea del brazo no dominante."},{"front":"¿A qué edad debe iniciar el tamizaje con citología cervical convencional o base líquida?","back":"A los 25 años."},{"front":"¿Cuál es la prueba de elección para el tamizaje de cáncer cervicouterino en mujeres de 30 a 64 años?","back":"Detección molecular de VPH de alto riesgo (VPH-AR)."},{"front":"¿Cada cuántos años debe realizarse la prueba de VPH-AR si el resultado es negativo?","back":"Cada 5 años."},{"front":"¿Bajo qué condición se puede suspender el tamizaje de cáncer cervicouterino a los 64 años?","back":"Si existen resultados negativos consistentes en los últimos 10 años."},{"front":"Manejo ante un resultado de citología con ASC-US:","back":"Realizar prueba de VPH."},{"front":"Manejo ante un resultado de citología con LEIAG, ACG o ASC-H:","back":"Referencia directa a colposcopía y toma de biopsia."},{"front":"¿Qué conducta se sigue si una prueba de VPH-AR resulta positiva para los genotipos 16 o 18?","back":"Referir directamente a colposcopía."},{"front":"¿Qué significa la sigla ACG en un reporte de citología?","back":"Células glandulares atípicas."},{"front":"¿Qué significa la sigla ASC-H en un reporte de citología?","back":"Células escamosas atípicas donde no se pueden excluir lesiones de alto grado."},{"front":"¿Cuál es el estándar de oro para el diagnóstico definitivo de lesiones precursoras?","back":"Biopsia dirigida por colposcopía."},{"front":"¿Cuándo se considera el cono cervical como un tratamiento definitivo?","back":"En casos de cáncer microinvasor que cumplan con criterios específicos."},{"front":"¿Cuál es el tratamiento preferido para lesiones NIC 2+ o LEIAG?","back":"Escisión electroquirúrgica con asa (LEEP)."},{"front":"Term: Crioterapia (en CACU)","back":"Definition: Alternativa de tratamiento ablativo para lesiones pequeñas que no cubren más del 75% del ectocérvix ni se extienden al canal."},{"front":"¿En qué casos se debe suspender definitivamente el tamizaje de cáncer cervicouterino?","back":"En mujeres con histerectomía total no relacionada a cáncer."},{"front":"¿A qué edad inicia el tamizaje de VPH en pacientes con VIH?","back":"A los 25 años."},{"front":"¿Cuál es el intervalo de detección en pacientes con VIH y niveles de CD4 < 200 células/mm³?","back":"Cada 6 a 12 meses."},{"front":"¿Cuál es el factor de riesgo número uno para el desarrollo de cáncer cervicouterino?","back":"Persistencia de la infección por VPH 16 y 18."},{"front":"¿Cuál es la variedad histológica más frecuente del cáncer cervicouterino?","back":"Carcinoma escamoso o epidermoide (90%)."},{"front":"¿Cuál es el síntoma más precoz y característico del cáncer cervicouterino?","back":"Metrorragia."},{"front":"En etapas avanzadas, ¿qué característica tiene la leucorrea?","back":"Fétida y con apariencia de \"agua de lavar carne\"."},{"front":"¿Cuál es el principal sitio de metástasis a distancia en el cáncer cervicouterino?","back":"Ganglios paraaórticos."},{"front":"FIGO Estadio I: Definición general","back":"Carcinoma estrictamente confinado al cuello uterino."},{"front":"FIGO Estadio IA1: Definición de invasión","back":"Invasión al estroma menor a 3 mm de profundidad."},{"front":"FIGO Estadio IA2: Definición de invasión","back":"Invasión al estroma mayor a 3 mm y menor a 5 mm de profundidad."},{"front":"FIGO Estadio IB2: Definición","back":"Lesión clínica (macroscópica) mayor a 4 cm limitada al cuello uterino."},{"front":"FIGO Estadio IIB: Característica diagnóstica","back":"Invasión evidente de los parametrios (sin llegar a la pared pélvica)."},{"front":"FIGO Estadio IIIA: Extensión de la lesión","back":"Extensión al tercio inferior de la vagina sin afectar la pared pélvica."},{"front":"FIGO Estadio IIIB: Hallazgos clínicos","back":"Extensión a la pared pélvica y/o presencia de hidronefrosis o riñón excluido."},{"front":"FIGO Estadio IVA: Definición","back":"Invasión de la mucosa de la vejiga o del recto y/o extensión más allá de la pelvis verdadera."},{"front":"¿A partir de qué estadio clínico se considera que la lesión es irresecable y requiere quimiorradioterapia?","back":"Estadio IB2 (lesión > 4 cm)."},{"front":"¿Cuál es el tratamiento estándar para estadios localmente avanzados (IIB a IVA)?","back":"Quimiorradioterapia (basada en Cisplatino + Paclitaxel)."},{"front":"Tratamiento del Estadio IA1 en pacientes con deseo de preservar el embarazo:","back":"Cono terapéutico."},{"front":"Manejo del CACU en el segundo trimestre de embarazo con deseo de preservación:","back":"Quimioterapia neoadyuvante después de las 12 semanas y finalizar el embarazo al lograr madurez pulmonar."},{"front":"¿Cuál es el cáncer más común diagnosticado durante el embarazo?","back":"Cáncer cervicouterino (CACU)."},{"front":"¿Con qué frecuencia se debe realizar el seguimiento los primeros 2 años tras el alta por tratamiento de CACU?","back":"Cada 3 a 6 meses."},{"front":"¿A cuántos años de seguimiento sin evidencia de enfermedad se puede dar el alta definitiva en ginecología?","back":"A los 5 años."},{"front":"¿Qué genes del VPH son responsables de infectar la membrana basal y provocar condilomas?","back":"Genes tardíos L1 y L2."},{"front":"¿En qué porcentaje reduce la transmisión del VPH el uso correcto del condón?","back":"70%."},{"front":"La clasificación de Richart para colposcopía divide las lesiones en _____, _____ y _____.","back":"NIC 1, NIC 2 y NIC 3"},{"front":"Manejo de una paciente con VPH-AR positivo para genotipos no 16/18 y citología negativa:","back":"Repetir la prueba en 12 meses."},{"front":"¿Bajo qué circunstancia se debe referir a oncología en menos de 10 días?","back":"Diagnóstico confirmado de cáncer invasor o sospecha clínica de malignidad en colposcopía."},{"front":"El tratamiento de un NIC 2 no debe exceder los _____ días hábiles desde su diagnóstico.","back":"20"},{"front":"¿Qué complicación renal define el estadio IIIB en la clasificación FIGO?","back":"Hidronefrosis."},{"front":"¿Cuál es la principal vía de diseminación inicial del cáncer cervicouterino?","back":"Extensión directa (vagina y parametrios)."},{"front":"En pacientes con VIH y tratamiento antirretroviral efectivo con CD4 normales, ¿cada cuánto se realiza el tamizaje?","back":"Cada 3 a 5 años."},{"front":"La vacuna contra el VPH _____ (sí/no) está contraindicada durante el embarazo.","back":"no (aunque es preferible administrarla después)."},{"front":"Ante un caso de abuso sexual, ¿cuántas dosis de vacuna contra VPH se pueden aplicar?","back":"Hasta dos dosis (esquema 0-6 meses)."}]},"8":{"num":8,"name":"PATOLOGIA MAMARIA BENIGNA","cards":[{"front":"¿Cómo se define la patología mamaria benigna?","back":"Conjunto de alteraciones del tejido mamario sin capacidad de diseminarse."},{"front":"¿Qué factores influyen en la respuesta del tejido mamario a los mecanismos hormonales?","back":"Los hábitos nutricionales y el estilo de vida."},{"front":"El término médico correcto para referirse al dolor de mama es _____.","back":"Mastalgia"},{"front":"¿Qué clasificación se utiliza para describir la mastalgia?","back":"Clasificación de Cardiff."},{"front":"¿Con qué proceso fisiológico se relaciona la mastalgia cíclica?","back":"Con el ciclo menstrual."},{"front":"¿Cuál es la causa benigna más frecuente de mastalgia cíclica?","back":"Mastopatía fibroquística."},{"front":"¿Cuál es el origen habitual del dolor torácico en la zona mamaria?","back":"Muscular o costocondral."},{"front":"Identifique dos factores de riesgo para el desarrollo de patología mamaria benigna.","back":"Estados de hiperestrogenismo y tabaquismo."},{"front":"¿Qué hábitos dietéticos se asocian a un mayor riesgo de patología mamaria?","back":"Poca fibra y altas cantidades de grasa."},{"front":"¿A partir de qué edad presentarán una patología benigna mamaria aproximadamente el 50% de las mujeres?","back":"Después de los 20 años."},{"front":"¿Cuál es el tumor benigno más frecuente de la glándula mamaria?","back":"Fibroadenoma mamario."},{"front":"¿Cuál es el tumor benigno más frecuente en la mujer a nivel general?","back":"Miomatosis uterina."},{"front":"¿En qué zona anatómica de la mama suele originarse el cáncer (ductal o lobulillar)?","back":"En la unidad ducto-lobulillar o zona de transición."},{"front":"¿A qué edad recomienda la GPC iniciar la exploración mamaria clínica?","back":"A partir de los 19 años."},{"front":"¿A qué edad establece la NOM-041-SSA2-2011 el inicio de la exploración clínica mamaria?","back":"A partir de los 25 años."},{"front":"¿A qué edad deben iniciar la exploración clínica las mujeres portadoras de mutaciones BRCA?","back":"A partir de los 18-21 años."},{"front":"¿A partir de qué edad se recomienda iniciar la autoexploración mamaria?","back":"A partir de los 20 años."},{"front":"¿En qué días del ciclo menstrual se sugiere realizar la autoexploración mamaria?","back":"Del día 5 al 7 del ciclo."},{"front":"¿Qué riesgo de cáncer de mama presentan las lesiones proliferativas sin atipia?","back":"1.9"},{"front":"¿Qué riesgo de cáncer de mama presentan las lesiones proliferativas con atipia?","back":"5.3"},{"front":"La hiperplasia ductal atípica pertenece al grupo de lesiones proliferativas _____.","back":"Con atipia"},{"front":"¿Cuál es el agente causal del 90% de las mastitis puerperales?","back":"Staphylococcus aureus."},{"front":"¿Qué tipo de infección caracteriza a la mastitis no puerperal?","back":"Infección multibacteriana."},{"front":"¿Qué microorganismo es el agente causal del absceso de la glándula de Montgomery?","back":"Pseudomonas aeruginosa."},{"front":"Mencione el síntoma clínico de mastitis que se caracteriza por una masa palpable que se desplaza bajo presión.","back":"Masa fluctuante."},{"front":"¿Cuál es el analgésico antiinflamatorio de elección para el tratamiento de la mastitis?","back":"Ibuprofeno."},{"front":"¿Cuál es el tratamiento antibiótico de elección para la mastitis puerperal?","back":"Dicloxacilina, amoxicilina-clavulánico o cefalexina."},{"front":"Mencione un esquema antibiótico para la mastitis no puerperal.","back":"Ciprofloxacino o clindamicina."},{"front":"¿Cuál es la conducta recomendada respecto a la lactancia durante una mastitis?","back":"Continuar la lactancia (vaciamiento mamario)."},{"front":"¿Cuál es la principal complicación de la mastitis puerperal que requiere drenaje?","back":"Absceso mamario."},{"front":"¿Qué patología se debe descartar si una mastitis no mejora con antibióticos y no hay fiebre?","back":"Cáncer inflamatorio de mama."},{"front":"Defina mastopatía fibroquística.","back":"Enfermedad crónica benigna con proliferación del estroma y aparición de quistes."},{"front":"¿Cuál es la patología mamaria más frecuente en la práctica médica?","back":"Mastopatía fibroquística."},{"front":"¿Qué tratamiento de primera línea se indica para la mastalgia severa en mastopatía fibroquística?","back":"Linaza (25 g al día)."},{"front":"En mastopatía fibroquística, ¿qué fármaco de segunda línea requiere vigilancia especializada?","back":"Tamoxifeno."},{"front":"¿Qué estudio de imagen se prefiere para el diagnóstico en pacientes menores de 35 años?","back":"Ecografía (ultrasonido)."},{"front":"¿Qué estudio de imagen se prefiere para el diagnóstico en pacientes mayores de 35 años?","back":"Mastografía."},{"front":"¿Qué hallazgo ecográfico define a un quiste mamario simple?","back":"Nódulo anecoico con refuerzo acústico posterior."},{"front":"¿Cuál es el pico de incidencia de los quistes mamarios?","back":"40-50 años."},{"front":"¿En qué circunstancia se debe enviar el contenido de un quiste aspirado a estudio citológico?","back":"Si el contenido es sanguinolento."},{"front":"Concept: Galactocele","back":"Definition: Dilatación quística con contenido lechoso por obstrucción de un conducto lácteo durante o tras la lactancia."},{"front":"¿Cuál es el estudio de diagnóstico de primera elección para un galactocele?","back":"Ultrasonido."},{"front":"¿Cuál es el rango de edad más frecuente para la aparición de un fibroadenoma?","back":"Entre los 20 y 40 años."},{"front":"¿Cómo se describe la consistencia de un fibroadenoma a la palpación?","back":"Dura o elástica con bordes bien definidos."},{"front":"El fibroadenoma es un tumor mamario que suele crecer durante el _____ debido al hiperestrogenismo.","back":"Embarazo"},{"front":"¿Qué hallazgo en la mastografía es característico de un fibroadenoma antiguo?","back":"Calcificaciones en \"palomitas de maíz\"."},{"front":"¿A partir de qué tamaño se indica la exéresis de un fibroadenoma?","back":">2 cm."},{"front":"¿Cuál es la causa más frecuente de telorrea patológica?","back":"Papiloma intraductal solitario."},{"front":"¿Cuál es la clínica clásica del papiloma intraductal solitario?","back":"Telorrea sanguinolenta espontánea unilateral."},{"front":"¿Cómo se denomina la técnica quirúrgica para la escisión de conductos terminales en el papiloma intraductal?","back":"Operación de Addair."},{"front":"¿A qué hallazgo histológico se asocia frecuentemente el papiloma intraductal múltiple?","back":"Hiperplasia atípica."},{"front":"¿Cuál es el riesgo de asociación con cáncer de mama en el papiloma intraductal múltiple?","back":"Hasta el 40%."},{"front":"¿Qué gen se encuentra mutado en el síndrome de Li-Fraumeni, asociado al tumor phyllodes?","back":"TP53."},{"front":"¿Cuál es el tratamiento de elección para el tumor phyllodes?","back":"Resección quirúrgica amplia."},{"front":"Concept: Ectasia ductal","back":"Definition: Proceso inflamatorio no infeccioso por rotura de conductos terminales y cúmulo de secreciones."},{"front":"¿Qué patología se debe sospechar ante el antecedente de traumatismo mamario y una mastografía dudosa?","back":"Necrosis grasa."},{"front":"La enfermedad de Mondor se define fisiopatológicamente como una _____ de la pared torácica.","back":"Tromboflebitis superficial"},{"front":"¿Qué factor desencadenante se asocia a la enfermedad de Mondor?","back":"Ropa ajustada, ejercicio intenso o cirugía mamaria."},{"front":"¿Cuál es la segunda causa más frecuente de telorrea patológica?","back":"Ectasia ductal."},{"front":"¿Qué característica ecográfica distingue a un fibroadenoma de un quiste?","back":"El fibroadenoma es un nódulo sólido e hipoecoico."},{"front":"En mastopatía fibroquística, ¿en qué fase del ciclo se indican progestágenos?","back":"En la segunda fase del ciclo."},{"front":"¿Qué porcentaje de las mastalgias se resuelven espontáneamente o con medidas generales?","back":"Hasta el 70%."},{"front":"¿Qué conducta se debe seguir ante un nódulo mamario con microcalcificaciones BI-RADS 4?","back":"Realizar biopsia."},{"front":"¿Cómo se describe clínicamente el cordón en la enfermedad de Mondor?","back":"Cordón indurado y a menudo doloroso."},{"front":"¿Cuál es el manejo inicial recomendado para un galactocele?","back":"Manejo conservador."}]},"9":{"num":9,"name":"CANCER DE MAMA","cards":[{"front":"¿Cuál es la definición fisiopatológica del cáncer de mama?","back":"Crecimiento anormal de células del parénquima mamario por mecanismos genéticos, hormonales y mutaciones en genes supresores."},{"front":"¿Cuáles son los dos genes supresores de tumores cuya mutación se asocia frecuentemente al cáncer de mama?","back":"Los genes BRCA1 y BRCA2."},{"front":"¿Por qué el cáncer de mama se considera una enfermedad sistémica?","back":"Debido a su alta probabilidad de diseminación."},{"front":"¿Cuál es la neoplasia maligna más frecuente en la mujer a nivel mundial?","back":"El cáncer de mama (representa del 20 al 25%)."},{"front":"¿Cuál es la primera causa de mortalidad por tumor maligno en mujeres?","back":"El cáncer de mama."},{"front":"¿Cuál es la variedad histológica de cáncer de mama invasor más frecuente?","back":"El carcinoma ductal invasor."},{"front":"¿A qué edad se presenta el pico de incidencia máxima del cáncer de mama?","back":"Entre los 60 y 65 años."},{"front":"¿Cuál es el principal factor de riesgo para desarrollar cáncer de mama?","back":"El sexo femenino."},{"front":"¿Qué efecto tiene la lactancia materna sobre el riesgo de cáncer de mama?","back":"Reduce el riesgo en un 4% por cada 12 meses de lactancia."},{"front":"¿A partir de qué edad se considera un factor de riesgo para el cáncer de mama según la normativa?","back":"Edad mayor de 40 años."},{"front":"¿Cuál es el factor pronóstico más importante en el cáncer de mama?","back":"El número de ganglios linfáticos afectados."},{"front":"¿Qué alteración en los oncogenes se asocia a un mal pronóstico en el cáncer de mama?","back":"Alteraciones en ERB-B2 (HER2) y p53."},{"front":"¿Cuál es la localización anatómica más frecuente de los tumores mamarios?","back":"El cuadrante superoexterno de la mama."},{"front":"¿Cuál es la principal vía de diseminación del cáncer de mama?","back":"La vía linfática."},{"front":"¿Cuál es el sitio más frecuente de metástasis a distancia en el cáncer de mama?","back":"El pulmón (63%)."},{"front":"¿Qué tipo de cáncer de mama suele presentar metástasis en la serosa peritoneal?","back":"El carcinoma lobulillar infiltrante."},{"front":"¿Qué porcentaje de los carcinomas no invasores corresponde al carcinoma ductal in situ (CDIS)?","back":"Aproximadamente el 80%."},{"front":"¿Cuáles son las dos características clínicas principales del carcinoma lobulillar in situ (CLIS)?","back":"Es multicéntrico y frecuentemente bilateral (no simultáneo)."},{"front":"Subtipo molecular: Luminal A","back":"Definición: Buen pronóstico, receptores estrogénicos positivos, HER2 negativo y bajo índice de proliferación."},{"front":"¿Cuál es el subtipo molecular de cáncer de mama con el peor pronóstico?","back":"El subtipo triple negativo (sin receptores estrogénicos ni HER2)."},{"front":"¿Qué hallazgo cutáneo en la mama es sugestivo de edema linfático secundario a invasión tumoral?","back":"La apariencia de \"piel de naranja\"."},{"front":"¿A partir de qué edad recomienda la GPC realizar la autoexploración mamaria mensual?","back":"A partir de los 19 años."},{"front":"¿Cuál es la frecuencia recomendada de mastografía para mujeres asintomáticas de 40 a 49 años?","back":"Anual."},{"front":"¿Cada cuánto tiempo se recomienda la mastografía en mujeres de 40 a 69 años según la NOM-041-SSA2-2011?","back":"Cada 2 años."},{"front":"¿A qué edad debe iniciar el tamizaje anual en mujeres con mutación confirmada de BRCA1 o BRCA2?","back":"A los 30 años (pero no antes de los 25)."},{"front":"¿Cuál es el estándar de oro para la confirmación diagnóstica del cáncer de mama?","back":"La biopsia."},{"front":"¿Qué tipo de biopsia está indicada para el estudio citológico de ganglios axilares?","back":"Biopsia por aspiración con aguja fina (BAAF)."},{"front":"¿Qué tipo de biopsia es la de elección para obtener tejido y determinar el tipo histológico en lesiones palpables?","back":"Biopsia con aguja gruesa (Tru-cut)."},{"front":"¿Cuál es el método de imagen de elección para evaluar patología mamaria en menores de 35 años?","back":"El ultrasonido mamario."},{"front":"BI-RADS 0","back":"Significado: Evaluación incompleta; requiere pruebas de imagen adicionales o comparación con estudios previos."},{"front":"¿Cuál es el riesgo de malignidad asociado a una categoría BI-RADS 3?","back":"Menor al 2%."},{"front":"¿Cuál es la conducta a seguir tras un reporte BI-RADS 3?","back":"Seguimiento con mastografía unilateral a los 6 meses."},{"front":"¿Qué categoría BI-RADS indica hallazgos sospechosos de malignidad que requieren biopsia?","back":"BI-RADS 4."},{"front":"¿Cuál es el porcentaje de malignidad en la categoría BI-RADS 5?","back":"Mayor o igual al 95%."},{"front":"En el sistema TNM, un tumor de 3  cm se clasifica como _____.","back":"T2"},{"front":"¿Cómo se define la categoría T1 en la estadificación del cáncer de mama?","back":"Tumor con una dimensión máxima menor o igual a 2  cm."},{"front":"¿Qué clasificación TNM se otorga automáticamente al carcinoma inflamatorio de mama?","back":"T4d"},{"front":"¿En qué pacientes se debe emplear el Índice de Van Nuys para decidir el tratamiento?","back":"En pacientes con carcinoma ductal in situ (CDIS)."},{"front":"¿Cuál es la indicación quirúrgica para tumores mamarios menores de 3  cm?","back":"Cirugía conservadora."},{"front":"¿En qué caso es obligatoria la radioterapia tras el tratamiento quirúrgico?","back":"Cuando se realiza cirugía conservadora."},{"front":"¿Cuál es el esquema estándar de quimioterapia para el cáncer de mama?","back":"Esquema basado en antraciclinas más taxanos."},{"front":"¿Qué fármaco es la base de la hormonoterapia en pacientes premenopáusicas con receptores hormonales positivos?","back":"Tamoxifeno."},{"front":"¿Cuál es el tratamiento hormonal de elección en mujeres postmenopáusicas?","back":"Inhibidores de la aromatasa (como el letrozol)."},{"front":"¿Qué terapia dirigida se utiliza específicamente en pacientes con sobreexpresión de HER2/neu?","back":"Trastuzumab (anticuerpo monoclonal)."},{"front":"¿Cuál es la conducta inicial obligatoria ante un carcinoma inflamatorio antes de considerar cirugía?","back":"Administrar quimioterapia neoadyuvante."},{"front":"¿Cuál es el margen quirúrgico mínimo recomendado en la resección del tumor?","back":"Mayor a 2  mm."},{"front":"¿Qué efecto adverso grave se asocia al uso de Tamoxifeno por 5 años?","back":"Incremento del riesgo de cáncer de endometrio (1.2 veces)."},{"front":"¿Qué suplementos deben recibir las pacientes tratadas con inhibidores de la aromatasa?","back":"Ácido zoledrónico, calcio y vitamina D."},{"front":"¿Cuál es el signo clínico de sospecha de cáncer de mama en un hombre?","back":"Masa palpable, generalmente retroareolar, similar al manejo en mujeres."},{"front":"¿Cuál es la frecuencia de seguimiento clínico durante los primeros 3 años tras el diagnóstico?","back":"Cada 3 a 6 meses."},{"front":"¿A qué edad debe iniciar la exploración clínica mamaria en hombres con mutaciones BRCA1/2?","back":"A los 35 años."},{"front":"¿Qué fármacos están contraindicados específicamente en el tratamiento del cáncer de mama en hombres?","back":"Los inhibidores de la aromatasa."},{"front":"¿Cuál es la dosis de radiación estimada al feto durante una mastografía con protección abdominal?","back":"0.00004  Gy."},{"front":"¿Qué complicación cardiaca requiere vigilancia estrecha durante el uso de Trastuzumab?","back":"La cardiopatía dilatada."},{"front":"¿Qué patología se debe sospechar ante una telorrea en una mujer menor de 50 años sin masa palpable?","back":"Papiloma intraductal."},{"front":"¿Cuál es el tratamiento quirúrgico indicado en tumores mayores de 3  cm?","back":"Mastectomía radical."},{"front":"¿En qué trimestre del embarazo se debe evitar estrictamente la quimioterapia?","back":"Durante el primer trimestre."},{"front":"En el cáncer de mama invasor, si se detecta un ganglio positivo en la biopsia de ganglio centinela (BSGC), se debe administrar _____.","back":"Quimioterapia"},{"front":"¿Cuál es la definición de cáncer de mama asociado al embarazo?","back":"Aquel diagnosticado durante la gestación, la lactancia o el primer año tras el parto."},{"front":"¿A partir de qué nivel de atención se realiza el envío ante un reporte BI-RADS 4?","back":"Segundo nivel de atención."},{"front":"¿Qué estudio complementario se solicita en pacientes embarazadas con sospecha de metástasis hepática?","back":"Ultrasonido hepático."},{"front":"¿Qué hallazgo mamográfico se describe como \"nódulo espiculado o pérdida de la arquitectura\"?","back":"Criterio radiográfico de malignidad."},{"front":"¿Qué porcentaje de riesgo de malignizar tiene el carcinoma lobulillar in situ (CLIS)?","back":"Del 20 al 35%."},{"front":"¿A qué edad debe iniciar la mastografía anual en mujeres con antecedente de radiación de tórax recibida entre los 10 y 30 años?","back":"8 años después de la radioterapia (pero nunca antes de los 25)."},{"front":"¿A partir de qué categoría BI-RADS el envío debe ser a tercer nivel con atención inmediata?","back":"BI-RADS 5."},{"front":"La tríada de tratamiento para el cáncer inflamatorio es: _____, mastectomía radical modificada y radioterapia.","back":"Quimioterapia neoadyuvante"},{"front":"¿Qué factor reproductivo reduce el riesgo de cáncer de mama si ocurre antes de los 20 años?","back":"El primer embarazo a término."},{"front":"¿Cuál es la causa más frecuente de metástasis en el ojo?","back":"El cáncer de mama."},{"front":"¿Cuál es la utilidad del PET-CT en el diagnóstico de cáncer de mama?","back":"En tumores mayores de 2  cm o con sospecha de metástasis."},{"front":"En pacientes con alto riesgo y mamas densas, ¿qué estudio de imagen se prefiere si se cuenta con el recurso?","back":"Resonancia Magnética (RM)."},{"front":"¿Cuál es el diagnóstico diferencial principal de la telorrea en mujeres mayores de 50 años?","back":"Carcinoma ductal."},{"front":"¿A qué edad debe iniciar el examen clínico mamario anual según la NOM-041?","back":"A partir de los 25 años."},{"front":"¿Qué tipo de metástasis óseas son más frecuentes en el cáncer de mama?","back":"Metástasis blásticas (el cáncer de mama es la causa más frecuente de metástasis en hueso)."},{"front":"El carcinoma ductal in situ se considera una lesión de aspecto maligno que no ha atravesado la _____.","back":"membrana basal"},{"front":"¿Cuál es el periodo de seguimiento anual de la mastografía tras una cirugía conservadora?","back":"De por vida, en la mama remanente y en la contralateral."}]}},"pediatria":{"1":{"num":1,"name":"RN SANO","cards":[{"front":"¿Qué porcentaje de las muertes infantiles ocurren durante los primeros 28 días de vida?","back":"El 50% de las muertes infantiles."},{"front":"¿Cuál es la causa número uno de muerte neonatal en México según el material proporcionado?","back":"Asfixia e infecciones (51.3%)."},{"front":"En América Latina, ¿cuáles son las tres causas principales de muerte neonatal en orden de frecuencia?","back":"1. Infecciones, 2. asfixia y 3. prematurez."},{"front":"¿Cómo se clasifica a un recién nacido prematuro tardío según las semanas de gestación (SDG)?","back":"Entre 34 y 36 SDG."},{"front":"¿Qué rango de semanas de gestación define a un prematuro moderado?","back":"Entre 28 y 34 SDG."},{"front":"Un recién nacido con menos de 28 semanas de gestación se clasifica como prematuro _____.","back":"Extremo"},{"front":"¿Cuándo se deben realizar las citas de control tras el nacimiento?","back":"A los 7 días y a los 28 días."},{"front":"¿Cuánto tiempo se debe esperar para realizar un pinzamiento tardío del cordón umbilical?","back":"De 30 segundos a 1 minuto."},{"front":"Durante el pinzamiento tardío, ¿a qué distancia se debe dejar el cordón umbilical?","back":"A 15 cm."},{"front":"¿Cuál es el beneficio del pinzamiento tardío en recién nacidos a término?","back":"Mejor neurodesarrollo y menor posibilidad de anemia."},{"front":"¿Qué riesgos se asocian al pinzamiento tardío del cordón umbilical?","back":"Ictericia y policitemia."},{"front":"¿Cómo se define a un recién nacido con peso extremadamente bajo?","back":"Peso inferior a 1000 gramos."},{"front":"Un recién nacido con peso inferior a 1500 gramos se clasifica como peso _____.","back":"Muy bajo"},{"front":"¿Cuál es el rango de peso considerado adecuado para un recién nacido (P10-90)?","back":"Entre 2500 y 3999 gramos."},{"front":"¿Cuál es el mejor indicador antropométrico para evaluar la edad gestacional?","back":"El perímetro cefálico."},{"front":"¿Cuál es el promedio del perímetro cefálico al nacer?","back":"35 cm \\pm 2 cm."},{"front":"¿Qué porcentaje de peso se considera normal perder durante la primera semana de vida (periodo hebdomadario)?","back":"El 10% del peso (fisiológico)."},{"front":"¿A qué edad el lactante suele duplicar su peso del nacimiento?","back":"A los 5 meses."},{"front":"¿A qué edad el niño suele triplicar su peso del nacimiento?","back":"A los 12 meses (1 año)."},{"front":"¿En qué momento se espera que un niño duplique su talla al nacer?","back":"A los 4 años."},{"front":"¿Cómo se interpreta un puntaje de APGAR de 7 a 10 puntos?","back":"Normal."},{"front":"¿Qué estado clínico indica un puntaje de APGAR de 4 a 6 puntos?","back":"Depresión moderada."},{"front":"Un puntaje de APGAR menor a 3 puntos se interpreta como depresión _____.","back":"Severa"},{"front":"¿En qué minutos se debe evaluar la escala de APGAR de forma rutinaria?","back":"Al minuto 1 y al minuto 5."},{"front":"¿La escala de APGAR es útil para predecir daño neurológico a largo plazo?","back":"No, no predice daño neurológico."},{"front":"¿Qué evalúa la escala de Silverman-Anderson?","back":"La dificultad respiratoria del recién nacido."},{"front":"¿Cómo se interpreta un puntaje de 0 en la escala de Silverman-Anderson?","back":"Sin dificultad respiratoria."},{"front":"¿Cuál es la conducta a seguir ante un Silverman-Anderson mayor a 7 puntos?","back":"Intubación inmediata (dificultad respiratoria severa)."},{"front":"¿Para qué tipo de recién nacidos se utiliza la escala de Capurro para estimar la edad gestacional?","back":"En mayores de 34 SDG."},{"front":"¿En qué grupo de edad gestacional se prefiere el uso del test de Ballard modificado?","back":"En menores de 34 SDG."},{"front":"¿Cuál es el rango de temperatura considerado normotermia en el recién nacido?","back":"36 a 37.5 °C."},{"front":"¿En qué periodo de tiempo debe ocurrir la primera uresis (micción)?","back":"Dentro de las primeras 24 horas."},{"front":"¿En qué periodo de tiempo debe ocurrir la primera evacuación intestinal?","back":"Dentro de las primeras 48 horas."},{"front":"¿Qué patógenos busca prevenir la profilaxis oftálmica neonatal?","back":"Chlamydia y Gonococo."},{"front":"¿Cuál es el tiempo máximo que se puede retrasar la administración de la profilaxis oftálmica?","back":"4 horas."},{"front":"¿Cuál es la causa más frecuente de oftalmia neonatal?","back":"Chlamydia (serotipos D-K)."},{"front":"¿En qué periodo de tiempo suele aparecer la conjuntivitis gonocócica?","back":"Durante los primeros 4 días de vida."},{"front":"¿Cuál es la dosis de Vitamina K (fitomenadiona) para la profilaxis de hemorragia en un RN mayor de 34 SDG?","back":"1 mg IM dosis única."},{"front":"¿Cuál es la dosis de Vitamina K para un recién nacido menor de 34 SDG?","back":"0.5 mg IM."},{"front":"¿En qué momento se presenta típicamente la enfermedad hemorrágica clásica del recién nacido?","back":"Entre las 48 y 72 horas de vida."},{"front":"¿Cuál es la vía y el sitio de administración de la vacuna BCG?","back":"0.1 ml intradérmica (ID) en la región deltoidea derecha."},{"front":"¿Cuál es la contraindicación de peso para la aplicación de la vacuna BCG?","back":"Peso inferior a 2000 gramos."},{"front":"¿En qué periodo se debe aplicar la primera dosis de la vacuna contra Hepatitis B?","back":"Dentro de las primeras 12 horas de vida."},{"front":"¿Cuál es el requerimiento hídrico de un recién nacido en su primer día de vida?","back":"70 ml/kg/día."},{"front":"Fórmula para calcular la capacidad gástrica del recién nacido: _____.","back":"(\\text{Peso} \\times 10) - 3"},{"front":"¿Qué medida ha demostrado reducir la mortalidad neonatal y aumentar la lactancia a largo plazo?","back":"Contacto piel con piel en la primera hora de vida."},{"front":"¿Cuándo se debe realizar la primera exploración física del recién nacido?","back":"Al nacimiento."},{"front":"¿Cuál es la prueba inicial del tamiz auditivo?","back":"Emisiones otoacústicas (EOA)."},{"front":"¿Qué prueba se realiza si las emisiones otoacústicas son anormales por segunda vez?","back":"Potenciales evocados auditivos de tronco cerebral (PEATC)."},{"front":"¿En qué ventana de tiempo se debe realizar el tamiz cardiológico?","back":"Entre las 6 y 48 horas del nacimiento (idealmente a las 24 horas)."},{"front":"¿Qué resultado en el tamiz cardiológico se considera un \"positivo inmediato\"?","back":"SatO_2 < 90% en mano derecha o pie."},{"front":"¿Qué prueba diagnóstica se realiza en el tamiz oftalmológico antes de las 24 horas?","back":"Prueba del reflejo rojo."},{"front":"¿Qué hallazgo en el reflejo rojo es el dato más importante para sospechar retinoblastoma?","back":"Leucocoria (ausencia de reflejo rojo)."},{"front":"¿Cuál es la alteración cutánea más frecuente que aparece al 2^{\\circ} o 3^{\\circ} día y presenta eosinófilos en el frotis?","back":"Eritema tóxico del recién nacido."},{"front":"¿Qué células se observan en el frotis de una lesión de melanosis pustulosa?","back":"Neutrófilos."},{"front":"Las pápulas blanquecinas en mejillas, nariz y mentón se conocen como _____.","back":"Quistes de Milium"},{"front":"¿Dónde se localizan las perlas de Epstein?","back":"En el rafe palatino medio."},{"front":"¿Dónde se localizan las perlas de Bonn?","back":"En las crestas alveolares."},{"front":"¿Qué raíces nerviosas se afectan en la parálisis de Erb-Duchenne?","back":"C5-C7."},{"front":"¿Cuál es la posición característica del brazo en la parálisis de Erb-Duchenne?","back":"Propina de camarero."},{"front":"¿Qué raíces nerviosas se afectan en la parálisis de Dejerine-Klumpke?","back":"C8-T1."},{"front":"¿Qué síndrome puede complicar la parálisis de Dejerine-Klumpke si se afecta T1?","back":"Síndrome de Horner (ptosis, miosis, enoftalmos)."},{"front":"¿Cómo se diferencia el caput succedaneum del cefalohematoma respecto a las suturas craneales?","back":"El caput succedaneum atraviesa suturas y el cefalohematoma las respeta."},{"front":"¿Cuál es el tratamiento indicado para el cefalohematoma?","back":"Conservador (no se indica incisión ni drenaje)."},{"front":"¿Por qué mecanismos se produce la pérdida de calor después del nacimiento?","back":"Conducción, convección, evaporación y radiación."},{"front":"¿A partir de qué nivel de glucosa se considera hipoglucemia en el recién nacido?","back":"Menor de 47 mg/dL."},{"front":"¿Cuál es la principal causa de reingreso hospitalario en recién nacidos?","back":"Ictericia (51%)."},{"front":"¿Qué patología se debe sospechar ante una fontanela pequeña?","back":"Microcefalia, síndrome de Apert o enfermedad de Crouzon."},{"front":"¿Qué condiciones se asocian con una fontanela grande?","back":"Hipotiroidismo, Trisomías (13, 18, 21), acondroplasia u osteogénesis imperfecta."}]},"2":{"num":2,"name":"RENEO 2026","cards":[{"front":"¿Qué porcentaje de los recién nacidos requiere algún tipo de intervención para la transición a la vida extrauterina?","back":"El 10%."},{"front":"¿Cuál es el porcentaje de recién nacidos que requiere maniobras avanzadas de reanimación?","back":"El 1%."},{"front":"¿En qué momento ocurre el 85% de los casos de hipoxia neonatal?","back":"Durante el periodo intraparto."},{"front":"¿Cuál es la primera causa de muerte en el periodo neonatal según las estadísticas presentadas?","back":"La asfixia."},{"front":"¿Cuántas personas expertas deben estar presentes en un parto si existen factores de riesgo identificados?","back":"Mínimo 2 personas expertas."},{"front":"¿En qué rango de tiempo inician respiraciones espontáneas el 85% de los niños tras el nacimiento?","back":"Dentro de los primeros 10 a 30 segundos."},{"front":"Menciona tres factores de riesgo detectables antes del parto (prenatales).","back":"< 36 o > 41 SDG, preeclampsia/eclampsia y embarazo múltiple."},{"front":"¿Por qué el uso de magnesio en la madre se considera un factor de riesgo durante el parto?","back":"Porque puede deprimir el esfuerzo respiratorio del neonato."},{"front":"¿Cuál es el modo de acción del CPAP en la reanimación neonatal?","back":"Presión positiva constante."},{"front":"¿Qué requerimiento respiratorio debe cumplir el neonato para ser candidato a CPAP?","back":"Debe tener respiración espontánea."},{"front":"¿Cuál es la indicación principal para iniciar Ventilación con Presión Positiva (VPP)?","back":"Apnea o bradicardia."},{"front":"¿Qué intervención se prioriza para la estabilización en casos de dificultad respiratoria leve-moderada?","back":"El CPAP."},{"front":"¿Cuáles son las 3 preguntas de evaluación inicial inmediata al nacer?","back":"¿Nació a término?, ¿tiene buen tono muscular? y ¿respira o llora?"},{"front":"¿Cuál es el objetivo de los pasos iniciales (calentar, secar, estimular) en la reanimación?","back":"Identificar si el recién nacido necesita intervención inmediata."},{"front":"En un neonato no vigoroso, ¿en cuánto tiempo se debe evaluar la respuesta a los pasos iniciales?","back":"En no más de 30 segundos."},{"front":"¿Cuál es la acción más importante y efectiva durante la reanimación neonatal?","back":"La ventilación de los pulmones."},{"front":"¿Qué intervención se debe iniciar si el neonato presenta apnea o boqueo tras los pasos iniciales?","back":"Ventilación con Presión Positiva (VPP)."},{"front":"Si el neonato respira pero la frecuencia cardíaca es menor a 100 lpm, ¿qué acción procede?","back":"Iniciar Ventilación con Presión Positiva (VPP)."},{"front":"¿Por qué no se debe usar la cianosis como guía para el tratamiento con oxígeno?","back":"Porque no es un indicador fiable de la saturación de oxígeno; se debe usar oximetría preductal."},{"front":"En el contexto de líquido teñido por meconio, ¿cuándo se recomienda aspirar boca y nariz con perilla?","back":"Cuando el recién nacido está deprimido."},{"front":"¿Cuál es la frecuencia respiratoria recomendada durante la VPP?","back":"De 40 a 60 ventilaciones por minuto."},{"front":"¿Qué concentración de oxígeno se utiliza para iniciar VPP en recién nacidos \\ge 35 semanas de gestación?","back":"Oxígeno al 21%."},{"front":"¿Qué concentración de oxígeno se utiliza para iniciar VPP en recién nacidos < 35 semanas de gestación?","back":"Oxígeno al 21\\% - 30%."},{"front":"¿Qué mnemotecnia se utiliza para los pasos correctivos de la ventilación si la frecuencia cardíaca no aumenta?","back":"MR. SOPA."},{"front":"En MR. SOPA, ¿qué significan las siglas 'M' y 'R'?","back":"Ajustar Máscara y Reposicionar vía aérea."},{"front":"En MR. SOPA, ¿qué significan las siglas 'S' y 'O'?","back":"Succionar boca y nariz y Open mouth (Abrir la boca)."},{"front":"En MR. SOPA, ¿qué significan las siglas 'P' y 'A'?","back":"Aumentar Presión y Vía Aérea alternativa."},{"front":"¿Bajo qué condición única se deben iniciar las compresiones torácicas?","back":"Cuando la frecuencia cardíaca es < 60 lpm después de al menos 30 segundos de VPP efectiva."},{"front":"¿Cuál es la relación de compresión:ventilación en la reanimación neonatal?","back":"Relación 3:1."},{"front":"¿Cuántos eventos totales (compresiones y ventilaciones) se deben realizar en un minuto?","back":"120 eventos (90 compresiones y 30 ventilaciones)."},{"front":"¿Cuál es la profundidad recomendada para las compresiones torácicas en el neonato?","back":"Un tercio (1/3) del diámetro anteroposterior del tórax."},{"front":"¿Cuál es el objetivo de saturación preductal de SpO_2 al primer minuto de vida?","back":"60\\% - 65%."},{"front":"¿Cuál es el objetivo de saturación preductal de SpO_2 a los 10 minutos de vida?","back":"85\\% - 95%."},{"front":"¿Cuál es la dosis recomendada de adrenalina por vía intravenosa o intraósea?","back":"0.01 - 0.03 mg/kg (0.1 - 0.3 mL/kg)."},{"front":"¿Con qué frecuencia se puede repetir la dosis de adrenalina si la frecuencia cardíaca persiste < 60 lpm?","back":"Cada 3 a 5 minutos."},{"front":"¿Cuál es la dosis de adrenalina si se administra por vía endotraqueal?","back":"0.05 - 0.1 mg/kg (0.5 - 1 mL/kg)."},{"front":"¿Qué volumen de expansor (solución salina) se debe administrar en caso de choque o hemorragia?","back":"10 mL/kg cada 5 a 10 minutos."},{"front":"¿Qué medida se debe tomar para mantener la temperatura en recién nacidos < 32 semanas?","back":"Envolver en bolsa o envoltura de plástico de polietileno y usar colchón térmico."},{"front":"¿Cuál es el rango de temperatura corporal que se debe mantener en el recién nacido?","back":"36.5^{\\circ}C a 37.5^{\\circ}C."},{"front":"Ante un neonato con hernia diafragmática o atresia de coanas, ¿qué acción se exceptúa de la secuencia estándar?","back":"Se debe intubar de forma inmediata."},{"front":"¿Cómo se mejora la vía aérea en un recién nacido con secuencia de Pierre Robin?","back":"Colocando al bebé en decúbito prono."},{"front":"¿En qué posición se debe colocar a un neonato con gastrosquisis u onfalocele para optimizar la perfusión?","back":"Sobre el lado derecho."},{"front":"¿Cuál es el tamaño de tubo endotraqueal recomendado para un neonato de > 2 kg o > 34 SDG?","back":"3.5 mm."},{"front":"¿Cuál es el tamaño de tubo endotraqueal recomendado para un neonato de < 1 kg o < 28 SDG?","back":"2.5 mm."},{"front":"¿Cuál es el indicador principal de que la reanimación está siendo exitosa?","back":"El aumento de la frecuencia cardíaca."},{"front":"¿Qué enzima sirve para establecer un pronóstico en la lesión neurológica por hipoxia?","back":"La enolasa."},{"front":"¿Qué temperatura ambiental debe tener la habitación donde se reanima a un prematuro?","back":"Entre 23^{\\circ}C y 25^{\\circ}C."},{"front":"¿Cuál es el orden correcto para aspirar secreciones?","back":"Primero la boca y después la nariz."},{"front":"¿Cuándo se considera razonable evaluar la interrupción de los esfuerzos de reanimación si no hay frecuencia cardíaca?","back":"Alrededor de los 20 minutos después del nacimiento."},{"front":"Menciona las 4 preguntas que el equipo debe realizarse antes de todos los partos.","back":"Edad gestacional, líquido amniótico limpio, plan de manejo del cordón y factores de riesgo adicionales."},{"front":"¿Qué signo clínico sugiere un neumotórax durante la reanimación?","back":"Disminución de ruidos respiratorios y aumento de transiluminación del lado afectado."},{"front":"¿Cuál es el manejo inicial de un neonato vigoroso con líquido teñido de meconio?","back":"No requiere aspiración, solo limpiar boca y nariz con un paño."},{"front":"¿Qué intervención es 'la piedra angular' de la reanimación neonatal?","back":"La ventilación."},{"front":"¿Qué técnica de compresión torácica se prefiere en neonatología?","back":"La técnica de los dos pulgares en el esternón, debajo de la línea intermamilar."},{"front":"¿Cuál es el acceso vascular de elección en la reanimación neonatal de emergencia?","back":"La vena umbilical."}]},"3":{"num":3,"name":"PATOLOGIA INFECCIOSA","cards":[{"front":"¿Cómo se define la sepsis neonatal según el tiempo de vida del recién nacido?","back":"Síndrome clínico en un nacido de 28 días de vida o menos con signos sistémicos de infección."},{"front":"Punto de corte en días de vida para diferenciar entre sepsis neonatal temprana y tardía según la GPC.","back":"7 días de vida."},{"front":"Principal agente causal de sepsis neonatal temprana en México.","back":"E. coli."},{"front":"Principal agente causal de sepsis neonatal temprana a nivel mundial.","back":"S. agalactiae."},{"front":"Menciona los dos principales agentes causales de la sepsis neonatal tardía.","back":"S. epidermidis y S. aureus."},{"front":"¿Qué vía de transmisión caracteriza a la sepsis neonatal temprana?","back":"Transmisión vertical."},{"front":"¿Qué vía de transmisión caracteriza a la sepsis neonatal tardía?","back":"Transmisión horizontal."},{"front":"Lugar que ocupa la sepsis como causa de muerte neonatal.","back":"Tercera causa de muerte."},{"front":"¿Cuántos signos clínicos se requieren para justificar la toma de hemocultivos e inicio de antibiótico empírico?","back":"La presencia de 3 o más signos clínicos."},{"front":"Relación de neutrófilos inmaduros/totales (I/T) sugerente de sepsis neonatal.","back":"> 0.2."},{"front":"Valor de la Proteína C Reactiva (PCR) que se considera auxiliar en el diagnóstico de sepsis.","back":"> 10 mg/L."},{"front":"Valor de la procalcitonina que se considera indicador de sepsis en el neonato.","back":"> 3-5 ng/mL."},{"front":"¿Cuáles son las interleucinas involucradas como auxiliares diagnósticos en sepsis neonatal?","back":"Interleucinas 6 y 8."},{"front":"Estándar de oro para el diagnóstico de sepsis neonatal.","back":"Hemocultivo."},{"front":"Esquema antibiótico de primera línea para sepsis temprana.","back":"Ampicilina + Gentamicina."},{"front":"Esquema antibiótico de segunda línea para sepsis temprana.","back":"Cefotaxima / Amikacina."},{"front":"¿Por qué la ceftriaxona está contraindicada en neonatos?","back":"Por riesgo de hiperbilirrubinemia o si reciben calcio."},{"front":"Tratamiento de elección para sepsis neonatal por Candida.","back":"Anfotericina B."},{"front":"Esquema antibiótico para sepsis tardía con sospecha de infección por S. aureus.","back":"Dicloxacilina + Gentamicina."},{"front":"Antibiótico indicado en caso de resistencia a meticilina o sepsis asociada a dispositivos intravasculares.","back":"Vancomicina."},{"front":"Duración del tratamiento antibiótico en sepsis neonatal sin meningitis.","back":"7 a 10 días."},{"front":"Duración del tratamiento antibiótico en sepsis neonatal con meningitis.","back":"14 a 21 días."},{"front":"Criterio diagnóstico de choque séptico relacionado con el llenado capilar.","back":"> 3 segundos."},{"front":"Hallazgo laboratorial más común en el choque séptico neonatal.","back":"Acidosis metabólica con disminución de HCO_3 y aumento de lactato."},{"front":"Tipo de líquidos recomendados como primera línea en la terapia de fluidos del choque séptico.","back":"Cristaloides isotónicos (Solución salina 0.9% o Ringer Lactato)."},{"front":"Carga inicial de cristaloides recomendada en el algoritmo de choque neonatal.","back":"10 ml/kg por periodos de 15-20 minutos."},{"front":"Tratamiento farmacológico indicado en choque neonatal con datos de cardiopatía dependiente de conducto.","back":"Prostaglandina E1."},{"front":"Vasopresores de primera elección en choque refractario a líquidos en el neonato.","back":"Dopamina + Dobutamina."},{"front":"Principales agentes causales de meningitis en menores de 3 meses.","back":"E. coli y S. agalactiae."},{"front":"Agentes causales de meningitis si existe antecedente de válvula ventriculoperitoneal.","back":"S. aureus o S. epidermidis."},{"front":"Triada clásica de la meningitis.","back":"Fiebre, rigidez de cuello y alteraciones del estado mental."},{"front":"Signos físicos específicos de rigidez de nuca en meningitis.","back":"Signos de Kerning y Brudzinski."},{"front":"Sospecha diagnóstica ante un neonato con meningitis que presenta petequias o púrpura.","back":"Meningococo (Síndrome de Waterhouse-Friderichsen)."},{"front":"Estándar de oro para el diagnóstico de meningitis.","back":"Punción lumbar (con cultivos)."},{"front":"Tratamiento antibiótico para meningitis en menores de 3 meses.","back":"Ampicilina + Cefalosporina de 3era generación (Cefotaxima en < 1 mes)."},{"front":"Característica de la glucosa en el LCR de una meningitis bacteriana.","back":"< 40 mg/dL."},{"front":"Nivel de leucocitos en LCR típico de meningitis bacteriana.","back":"Más de 1000 cel/mm^3."},{"front":"Tipo de células predominantes en el LCR en meningitis viral.","back":"Mononucleares (linfocitos)."},{"front":"Tratamiento de elección para encefalitis por virus del herpes simple (VHS).","back":"Aciclovir."},{"front":"Principal agente causal de la onfalitis.","back":"S. aureus."},{"front":"Sospecha diagnóstica si el cordón umbilical no se desprende después de 2 semanas.","back":"Inmunodeficiencia."},{"front":"Tratamiento de onfalitis con eritema < 5 mm sin datos sistémicos.","back":"Neomicina o mupirocina tópica."},{"front":"Tratamiento de onfalitis con eritema > 5 mm.","back":"Tratamiento IV, referencia y drenaje en caso de absceso."},{"front":"Antiséptico ideal para la prevención de onfalitis si no se mantiene seco.","back":"Clorhexidina al 4%."},{"front":"Patología caracterizada por necrosis intestinal isquémica inflamatoria en el íleo distal.","back":"Enterocolitis Necrotizante (ENC)."},{"front":"Factor de riesgo más importante para desarrollar enterocolitis necrotizante.","back":"Prematuridad."},{"front":"Factor protector más importante contra la enterocolitis necrotizante.","back":"Lactancia materna (reduce hasta un 75% la posibilidad)."},{"front":"Estudio de imagen inicial recomendado cada 6 horas en sospecha de ENC.","back":"Radiografía de abdomen."},{"front":"Signo radiológico patognomónico de enterocolitis necrotizante.","back":"Neumatosis intestinal."},{"front":"Hallazgos en ultrasonido abdominal de 4 cuadrantes sugerentes de ENC.","back":"Gas en vena porta y neumatosis intestinal."},{"front":"Escala utilizada para la estadificación de la enterocolitis necrotizante.","back":"Criterios de Bell."},{"front":"Esquema antibiótico para el Estadio II (Definitivo) de la ENC.","back":"Ampicilina, Gentamicina y Metronidazol (o Piperacilina/Tazobactam)."},{"front":"Indicación de intervención quirúrgica en el Estadio IIIB de la ENC.","back":"Laparotomía exploradora por sospecha de perforación."},{"front":"Escala utilizada para el control del dolor/angustia en enterocolitis necrotizante.","back":"CONFORTNEO."},{"front":"Relación entre el uso prolongado de antibióticos y el riesgo de ENC.","back":"El uso de ATB por más de 4 días en ausencia de sepsis aumenta el riesgo."},{"front":"Periodo de aparición de la neumonía neonatal de inicio temprano.","back":"Primeros 7 días de vida (especialmente las primeras 72 horas)."},{"front":"Agentes causales frecuentes de neumonía neonatal de inicio tardío.","back":"S. aureus y bacilos gram negativos."},{"front":"Hallazgos radiográficos característicos de la neumonía neonatal.","back":"Infiltrados alveolares, bronconeumónicos y reticulogranulares."},{"front":"Diagnóstico probable en un neonato con dificultad respiratoria y antecedentes de infección materna.","back":"Sepsis temprana o neumonía neonatal."},{"front":"Diagnóstico probable en un neonato con distensión abdominal y sangre en heces.","back":"Enterocolitis necrotizante."},{"front":"Tratamiento preventivo para contactos de meningitis (quimioprofilaxis).","back":"Ceftriaxona."},{"front":"¿Cuál es la complicación más importante de la enterocolitis necrotizante?","back":"Perforación intestinal."},{"front":"Fármaco utilizado para tratar el edema cerebral en complicaciones de meningitis.","back":"Manitol 20%."},{"front":"Tratamiento farmacológico para crisis convulsivas en complicaciones del SNC.","back":"Fenitoína."}]},"4":{"num":4,"name":"PATOLOGIA RESPIRATORIA NEONATAL","cards":[{"front":"¿Qué tipo de células alveolares son las encargadas de la síntesis de factor surfactante?","back":"Los neumocitos tipo II."},{"front":"¿A partir de qué semana de edad gestacional empieza el neumocito tipo II a producir surfactante?","back":"A la semana 24-28."},{"front":"La madurez pulmonar total, en relación con el factor surfactante, se alcanza habitualmente a la semana _____.","back":"34"},{"front":"¿Cuál es la función fisiológica principal del factor surfactante en los alvéolos?","back":"Disminuir la tensión superficial para evitar el colapso alveolar."},{"front":"En recién nacidos menores de 28 semanas de edad gestacional, ¿cuál es la incidencia de la Enfermedad de Membrana Hialina (SDR 1)?","back":"Aproximadamente el 90%."},{"front":"¿Cuál es el principal factor de riesgo para desarrollar el Síndrome de Dificultad Respiratoria tipo 1?","back":"La prematurez."},{"front":"Concepto: Dipalmitoilfosfatidilcolina","back":"Definición: Es el componente fosfolipídico principal del factor surfactante."},{"front":"En la gasometría arterial de un paciente con EMH, ¿qué valor de PaO_{2} define la hipoxemia según el material?","back":"Menor a 50 mmHg."},{"front":"¿Qué valor de la relación lecitina-esfingomielina indica inmadurez pulmonar?","back":"Un valor menor a 2:1."},{"front":"¿Cuál es la utilidad diagnóstica de la prueba de aspirado gástrico en la etapa neonatal inmediata?","back":"Medir componentes del líquido pulmonar deglutido para evaluar madurez."},{"front":"¿Cómo se describe la imagen radiológica característica de la EMH en su grado leve?","back":"Imagen reticulogranular muy fina con transparencia pulmonar conservada."},{"front":"¿Qué hallazgo radiológico define el grado moderado de la EMH?","back":"Imagen reticulogranular en todo el campo pulmonar y broncograma que sobrepasa la silueta cardíaca."},{"front":"En la clasificación radiológica de EMH, la imagen en 'vidrio despulido' con ausencia de silueta cardíaca corresponde al grado _____.","back":"Muy grave (Grado IV)."},{"front":"¿Cuál es el tratamiento óptimo inicial para la EMH en menores de 1500 gramos?","back":"CPAP más administración temprana de surfactante mediante técnica LISA."},{"front":"¿Cuál es la dosis inicial recomendada de Poractant alfa para el tratamiento de la EMH?","back":"200 mg/kg."},{"front":"En el manejo de EMH, si no hay mejoría clínica tras la primera dosis de surfactante, ¿qué dosis se recomiendan para la segunda y tercera aplicación?","back":"100 mg/kg."},{"front":"¿Cuál es la complicación vascular más frecuente asociada a la Enfermedad de Membrana Hialina?","back":"Persistencia del conducto arterioso."},{"front":"La Taquipnea Transitoria del Recién Nacido (TTRN) se debe fisiopatológicamente a un retraso en la _____.","back":"Absorción del líquido pulmonar alveolar."},{"front":"¿En qué periodo de tiempo se autolimita típicamente la Taquipnea Transitoria del RN?","back":"Entre las 24 y 72 horas posteriores al nacimiento."},{"front":"¿Cuál es el trastorno del equilibrio ácido-base que suele presentarse en la TTRN?","back":"Alcalosis respiratoria."},{"front":"¿Qué hallazgo radiológico caracteriza al 'patrón húmedo' en la TTRN?","back":"Cisuritis, atrapamiento aéreo y congestión parahiliar simétrica."},{"front":"Según la técnica de alimentación en patología respiratoria, ¿qué conducta se sigue si la FR es de 60-80 rpm?","back":"Alimentación por sonda orogástrica."},{"front":"En un neonato con dificultad respiratoria, ¿cuál es el criterio de frecuencia respiratoria para indicar ayuno?","back":"Frecuencia respiratoria mayor a 80 rpm."},{"front":"¿Cuál es el rango de saturación de O_{2} meta para un paciente con TTRN?","back":"88%-95%."},{"front":"¿Cuál es el mecanismo de producción del Síndrome de Aspiración de Meconio (SAM) en las vías aéreas?","back":"Obstrucción de vías pequeñas creando un efecto de válvula e hiperinsuflación."},{"front":"¿En qué grupo de edad gestacional es más prevalente el Síndrome de Aspiración de Meconio?","back":"Recién nacidos a término o postérmino."},{"front":"¿Qué característica clínica del tórax es distintiva en un neonato con SAM?","back":"Tórax en tonel."},{"front":"Radiológicamente, el SAM se presenta con un patrón de infiltrados en parches conocido como _____.","back":"Imagen en 'sal y pimienta'."},{"front":"¿Cuál es la complicación más grave asociada al Síndrome de Aspiración de Meconio?","back":"Hipertensión pulmonar."},{"front":"¿Qué medida terapéutica NO se recomienda de forma rutinaria en un neonato con SAM que nace vigoroso?","back":"Aspiración de meconio en tráquea."},{"front":"La apnea del prematuro se define como el cese de la respiración por más de _____ segundos.","back":"20"},{"front":"¿Qué signos clínicos acompañantes permiten diagnosticar apnea aunque el cese respiratorio dure menos de 20 segundos?","back":"Cianosis o bradicardia."},{"front":"¿Cuál es el método diagnóstico de primera elección para la vigilancia de apnea en prematuros?","back":"Vigilancia continua por impedancia torácica."},{"front":"¿Cuál es el fármaco de elección para el tratamiento de la apnea del prematuro?","back":"Cafeína."},{"front":"¿Hasta qué edad corregida se suele mantener el tratamiento con cafeína en la apnea del prematuro?","back":"43-44 semanas de edad."},{"front":"¿Cómo se define cronológicamente la Displasia Broncopulmonar (DBP) en un menor de 32 semanas?","back":"Necesidad de oxígeno suplementario por más de 28 días."},{"front":"¿Qué patrón radiológico es característico de la Displasia Broncopulmonar?","back":"Patrón en esponja."},{"front":"Menciona dos fármacos diuréticos utilizados en el tratamiento de la Displasia Broncopulmonar.","back":"Furosemida y Espironolactona."},{"front":"¿Qué esteroide se utiliza en dosis de 0.2 mg/kg/día para el manejo de la DBP?","back":"Dexametasona."},{"front":"En pacientes con Displasia Broncopulmonar, ¿cuál es el rango de PaCO_{2} meta?","back":"40-55 mmHg."},{"front":"¿Cuál es el signo clínico cardinal de la Hipertensión Pulmonar Persistente neonatal?","back":"Cianosis a pesar de una saturación de oxígeno al 100%."},{"front":"¿Cuál es el 'gold estándar' para el diagnóstico de Hipertensión Pulmonar?","back":"Ecocardiograma."},{"front":"¿Qué hallazgo en el ecocardiograma confirma hipertensión pulmonar según los criterios de presión?","back":"Presión de la arteria pulmonar por arriba de 40 mmHg."},{"front":"¿Cuál es el tratamiento vasodilatador de elección para la Hipertensión Pulmonar Persistente?","back":"Óxido nítrico inhalado."},{"front":"El esquema de maduración pulmonar con Betametasona consiste en _____ dosis de 12 mg cada 24 horas.","back":"2"},{"front":"¿Cuál es el esquema posológico de la Dexametasona para la maduración pulmonar prenatal?","back":"4 dosis de 6 mg cada 12 horas."},{"front":"Para disminuir el riesgo de retinopatía del prematuro, ¿qué rango de PaO_{2} se recomienda mantener?","back":"50-70 mmHg."},{"front":"¿Qué fármaco se utiliza para la parálisis neuromuscular en neonatos con asistencia mecánica a la ventilación?","back":"Pancuronio."},{"front":"En la TTRN, la falta de absorción de líquido se asocia a la ausencia de estrés del trabajo de parto, que normalmente activa canales de _____.","back":"Sodio."},{"front":"¿Qué hallazgo radiológico del SAM indica atrapamiento aéreo?","back":"Horizontalización de arcos costales y sobredistensión pulmonar."},{"front":"¿Cuál es la mortalidad aproximada de la apnea en prematuros con peso menor a 2500 gramos?","back":"Hasta el 20%."},{"front":"En la DBP, el daño se produce por una interferencia con la _____ alveolar, resultando en alvéolos más grandes y menos funcionales.","back":"Septación."},{"front":"El factor surfactante está compuesto en un 80% por _____.","back":"Fosfolípidos."},{"front":"¿Qué porcentaje de los casos de dificultad respiratoria no infecciosa representa la TTRN?","back":"Entre el 35% y el 50%."}]},"5":{"num":5,"name":"PATOLOGIA NEONATO SNC","cards":[{"front":"¿Cómo se define la asfixia neonatal?","back":"Es la falta de oxígeno que genera hipoxia e isquemia debido a una alteración del intercambio gaseoso perinatal."},{"front":"En México, ¿qué lugar ocupa la asfixia como causa de muerte neonatal?","back":"Ocupa el primer lugar."},{"front":"¿Qué porcentaje de los eventos de hipoxia neonatal ocurren en la etapa intraparto?","back":"El 85% de los eventos."},{"front":"Mencione tres factores de riesgo maternos para asfixia neonatal.","back":"Hemorragias del tercer trimestre, infecciones e hipertensión inducida por el embarazo."},{"front":"Factores de riesgo útero-placentarios para asfixia: Placenta previa, desprendimiento placentario y _____.","back":"Prolapso de cordón umbilical (o nudos de cordón)."},{"front":"Mencione tres factores de riesgo fetales para asfixia neonatal.","back":"Retraso del crecimiento intrauterino, bajo peso y prematuridad."},{"front":"¿Cuál es un signo clínico de aparición temprana relacionado con el tono muscular en la asfixia?","back":"Depresión del tono muscular y de los reflejos."},{"front":"Mencione dos datos clínicos de aparición tardía en la asfixia neonatal.","back":"Sangrado de tubo digestivo y sangrado pulmonar."},{"front":"¿Qué alteraciones urinarias se observan en la fase de aparición tardía de la asfixia?","back":"Retraso en la primera micción, oligoanuria y poliuria."},{"front":"¿A partir de qué rango de déficit de base se presentan alteraciones neurológicas en el neonato?","back":"Entre 10 y 12."},{"front":"Criterio diagnóstico de asfixia: Acidosis metabólica con pH menor a _____ en sangre de cordón umbilical.","back":"7."},{"front":"Criterio diagnóstico de asfixia: Puntuación de Apgar menor o igual a _____ a los 5 minutos.","back":"3."},{"front":"¿Qué marcador sérico puede indicar la presencia de hipoxia tisular en el neonato?","back":"El lactato sérico."},{"front":"¿Qué vasos se evalúan mediante ultrasonido Doppler en embarazos de alto riesgo por sospecha de asfixia?","back":"Arteria uterina, umbilical y cerebral media del feto."},{"front":"¿Cuáles son los tres pilares del tratamiento inicial de la asfixia neonatal?","back":"Reanimación neonatal, asistencia ventilatoria y neuroprotección (hipotermia)."},{"front":"¿Cómo se define la Encefalopatía Hipóxico Isquémica (EHI)?","back":"Lesión encefálica por asfixia en recién nacidos con edad gestacional \\ge 35 semanas."},{"front":"¿Cuál es el principal factor de riesgo para desarrollar Encefalopatía Hipóxico Isquémica?","back":"La prematurez."},{"front":"¿Qué porcentaje de recién nacidos con EHI fallecen?","back":"El 60% de los recién nacidos."},{"front":"¿Qué porcentaje de sobrevivientes de EHI quedan con discapacidad significativa?","back":"El 25%."},{"front":"¿Cuál es la hemorragia intracraneana más común en la etapa neonatal?","back":"La hemorragia intraventricular."},{"front":"En la escala de Sarnat, ¿cómo se encuentra el estado de alerta en la Etapa 1?","back":"El paciente está hiperalerta e hiperactivo."},{"front":"En la escala de Sarnat, ¿cuál es la característica de las convulsiones en la Etapa 2?","back":"Son convulsiones frecuentes."},{"front":"En la escala de Sarnat, ¿cómo se describen los reflejos en la Etapa 3?","back":"Los reflejos están ausentes."},{"front":"En la escala de Sarnat, ¿qué hallazgo pupilar es característico de la Etapa 3?","back":"La anisocoria."},{"front":"En la escala de Sarnat, ¿cómo se encuentra el tono muscular en la Etapa 2?","back":"Presenta hipotonía leve."},{"front":"¿Qué escala clínica se utiliza para evaluar la gravedad y el pronóstico de la EHI?","back":"La escala de Sarnat."},{"front":"¿Cuándo se debe realizar el ultrasonido transfontanelar tras un evento de asfixia?","back":"Después de las primeras 24 horas posteriores al evento."},{"front":"¿En qué ventana de tiempo debe realizarse el EEGa (amplitud integrada) como predictor de EHI?","back":"En las primeras 6 horas."},{"front":"¿Cuál es el Gold Standard para evaluar la gravedad de la EHI y en qué tiempo debe realizarse?","back":"EEG convencional realizado en las primeras 24 horas."},{"front":"Criterio de inclusión para hipotermia terapéutica: Recién nacido menor de _____ semanas de gestación.","back":"36 semanas."},{"front":"Criterio de inclusión para hipotermia terapéutica: Peso menor de _____ gramos.","back":"1800 gramos."},{"front":"¿Cuál es el tiempo límite de vida para iniciar la hipotermia terapéutica?","back":"Menos de 6 horas de vida."},{"front":"¿Durante cuánto tiempo se debe mantener la hipotermia terapéutica?","back":"Durante 72 horas."},{"front":"Mencione una contraindicación para realizar hipotermia terapéutica.","back":"Malformaciones congénitas que requieran ventilación o cromosomopatías."},{"front":"¿Cuál es el anticonvulsivo de primera elección en EHI?","back":"Fenobarbital."},{"front":"Mencione dos opciones de anticonvulsivos de segunda elección para crisis convulsivas en EHI.","back":"Lorazepam o Midazolam."},{"front":"¿Qué estructura recubre el sistema ventricular y participa en la formación de neuronas?","back":"La matriz germinal."},{"front":"¿En qué semana de gestación completa su regresión la matriz germinal?","back":"A la semana 32."},{"front":"¿Cuál es la zona más afectada en la hemorragia de la matriz germinal?","back":"La matriz germinal subependimaria en el núcleo caudado."},{"front":"Mencione los factores de riesgo principales para hemorragia de la matriz germinal.","back":"Prematurez (menor de 32 SDG), peso menor a 1500 g y síndrome de dificultad respiratoria."},{"front":"¿Cuáles son las dos principales complicaciones de la hemorragia de la matriz germinal?","back":"Infarto hemorrágico ventricular e hidrocefalia posthemorrágica."},{"front":"¿Qué clasificación se utiliza para valorar la extensión de la hemorragia de la matriz germinal por USG?","back":"Clasificación de Papile y Volpe."},{"front":"Papile y Volpe Grado I: Extensión de la hemorragia menor del _____.","back":"10%."},{"front":"Papile y Volpe Grado II: Extensión de la hemorragia entre el _____.","back":"10 y 50%."},{"front":"Papile y Volpe Grado III: Extensión de la hemorragia de más del _____.","back":"50%."},{"front":"¿Qué fármacos sirven para la prevención de la hemorragia de la matriz germinal?","back":"Betametasona y Sulfato de Magnesio."},{"front":"¿Cuál es la única indicación para el uso de anticonvulsivos en el neonato asfixiado?","back":"El tratamiento de crisis convulsivas frecuentes."},{"front":"¿Cuál es la utilidad principal de la puntuación de Apgar según los puntos clave ENARM?","back":"Conocer cómo fue la transición de la etapa fetal a la neonatal."},{"front":"¿Verdadero o falso?: La puntuación de Apgar por sí sola predice el daño neurológico tardío.","back":"Falso."},{"front":"¿En qué etapa es más frecuente la aparición de hipoxia?","back":"Durante el parto."},{"front":"¿Qué porcentaje de eventos de asfixia ocurren aproximadamente antes del inicio del trabajo de parto?","back":"Aproximadamente el 5%."},{"front":"¿Cuándo ocurren el 90% de las hemorragias cerebrales neonatales?","back":"Entre las 72 horas y los primeros 7 días de edad."},{"front":"En recién nacidos a término, ¿cuál es la causa más común de hemorragia de plexos coroideos?","back":"La asfixia perinatal."},{"front":"¿Qué puntaje se considera normal en el perfil biofísico utilizado por obstetras?","back":"Un puntaje de 8/10."},{"front":"¿Qué puntaje de perfil biofísico se considera anormal e identifica recién nacidos de alto riesgo?","back":"Una puntuación de 6/10 o menos."},{"front":"En neonatos prematuros, ¿qué tipo de hemorragia representa el 90% de los casos?","back":"Hemorragia de matriz germinal."},{"front":"¿En qué pacientes se recomienda realizar ultrasonido transfontanelar de forma rutinaria los primeros 7 días?","back":"Menores de 32 SDG y menores de 1500 gr."},{"front":"Factores maternos de asfixia: ¿Qué tipo de anemia es factor de riesgo?","back":"La anemia (sin especificar tipo en el texto)."},{"front":"Procesos clínicos: ¿A qué se debe el retraso en la micción en la asfixia?","back":"A una falla renal por hipoxia (falla multisistémica)."},{"front":"Sarnat Etapa 2: ¿Cómo se describe el estado de conciencia?","back":"Letárgicos u obnubilados."},{"front":"Sarnat Etapa 3: ¿Cómo se describe el estado de conciencia?","back":"Estuporosos."},{"front":"Sarnat Etapa 3: ¿Cuál es la característica del tono muscular?","back":"Están flácidos."},{"front":"Sarnat Etapa 1: ¿Cómo se encuentran las convulsiones?","back":"No presenta convulsiones (Sin convulsiones)."},{"front":"¿Qué estudio es el predictor más temprano (primeras 6h) en EHI?","back":"EEGa (EEG de amplitud integrada)."},{"front":"Epidemiología: ¿Qué lugar ocupa la asfixia como causa de muerte en el mundo?","back":"Tercer lugar."},{"front":"Riesgo Fetal: ¿Qué alteración de la frecuencia cardíaca es factor de riesgo para asfixia?","back":"Alteraciones de la frecuencia cardíaca fetal."},{"front":"Riesgo placentario: ¿Qué alteración del cordón puede causar asfixia?","back":"Circulares del cordón."},{"front":"Clínica temprana: ¿Qué alteración hemodinámica se presenta?","back":"Alteraciones de la perfusión."},{"front":"¿Cuáles son los 5 síntomas más importantes (tempranos o tardíos) de asfixia?","back":"Alteración del estado de alerta, crisis convulsivas, intolerancia a la vía oral, hipotensión y alteración del ritmo cardíaco."},{"front":"Diagnóstico de EHI: Requiere pH < 7 en muestra de sangre _____ de cordón.","back":"Arterial."},{"front":"En el contexto de EHI, ¿qué evalúa específicamente la Escala de Sarnat?","back":"Evalúa la gravedad y el pronóstico."},{"front":"Prevención: ¿Para qué se solicita USG transfontanelar en las primeras 24 horas ante sospecha de un evento?","back":"Para tamizaje y detección temprana de lesiones (como hemorragia)."},{"front":"EHI: ¿Cuál es el rango de edad gestacional para el diagnóstico?","back":"\\ge 35 semanas de gestación."},{"front":"Hemorragia Matriz Germinal: ¿Qué grado de Papile y Volpe corresponde a una extensión del 40%?","back":"Grado II."},{"front":"Hemorragia Matriz Germinal: ¿Qué grado de Papile y Volpe corresponde a una extensión del 5%?","back":"Grado I."}]},"6":{"num":6,"name":"PATOLOGIA INFECCIOSA CONGENITA","cards":[{"front":"¿Cuál es la causa más común de infección congénita en México?","back":"Citomegalovirus (CMV), afectando al 0.6% de los recién nacidos."},{"front":"¿Cuál es la principal causa de hipoacusia y sordera neurosensorial infantil de origen infeccioso?","back":"La infección congénita por Citomegalovirus."},{"front":"En el recién nacido, la principal fuente de infección por CMV adquirida es a través de _____.","back":"La leche materna."},{"front":"¿En qué trimestre del embarazo es más grave la infección por CMV?","back":"En el primer trimestre."},{"front":"¿Cuál es la técnica diagnóstica más utilizada en el recién nacido para CMV por su rapidez?","back":"PCR en orina (resultados en 24-48 horas)."},{"front":"¿Qué tipo de calcificaciones intracraneales son características del Citomegalovirus?","back":"Calcificaciones periventriculares."},{"front":"¿Cuál es el hallazgo oftalmológico característico del CMV descrito como \"lesiones en salsa de catsup\"?","back":"Coriorretinitis (condensaciones vítreas)."},{"front":"¿Cuál es el tratamiento de elección para la infección congénita por CMV?","back":"Ganciclovir IV (12\\ mg/kg/día por 6 semanas) y cambio posterior a Valganciclovir."},{"front":"¿Cuál es el principal efecto adverso del Ganciclovir en el tratamiento de CMV?","back":"Neutropenia."},{"front":"Concepto: Toxoplasma gondii","back":"Definición: Protozoo intracelular obligado cuyo huésped definitivo es el gato."},{"front":"¿Cómo se adquiere típicamente la toxoplasmosis durante el embarazo?","back":"Por ingesta de carne poco cocinada o contacto con ooquistes en heces de gato."},{"front":"¿Qué porcentaje de los recién nacidos con toxoplasmosis congénita son asintomáticos al nacer?","back":"Aproximadamente el 80%."},{"front":"¿Cuáles son los componentes de la Tétrada clásica de Sabin en toxoplasmosis?","back":"Coriorretinitis, hidrocefalia obstructiva, calcificaciones intracerebrales difusas y convulsiones."},{"front":"¿Cuál es la secuela más frecuente de la toxoplasmosis congénita?","back":"Coriorretinitis."},{"front":"¿Cuál es el dato clínico más frecuente en la toxoplasmosis congénita?","back":"Esplenomegalia."},{"front":"¿A partir de qué semana de gestación se recomienda realizar la amniocentesis para detectar toxoplasmosis fetal?","back":"Después de las semanas 18-20 de gestación."},{"front":"¿Cuál es el tratamiento para la toxoplasmosis congénita en el recién nacido?","back":"Pirimetamina + Sulfadiazina + Ácido folínico por un año."},{"front":"¿Qué fármaco se utiliza para profilaxis si se confirma toxoplasmosis fetal antes de las 18 semanas de gestación?","back":"Espiramicina."},{"front":"¿Cuál es el tratamiento para toxoplasmosis fetal si el diagnóstico se confirma después de las 18 semanas de gestación?","back":"Pirimetamina + Sulfadiazina + Ácido folínico + Espiramicina por 4 semanas."},{"front":"La tríada de Gregg es característica de la infección por _____.","back":"Rubéola congénita."},{"front":"¿Cuáles son los tres componentes de la tríada de Gregg?","back":"Sordera neurosensorial, cardiopatía congénita y alteraciones oculares (cataratas o glaucoma)."},{"front":"¿Cuál es la cardiopatía congénita más frecuente asociada al Síndrome de Rubéola Congénita?","back":"Persistencia del conducto arterioso (PCA)."},{"front":"¿Cuál es el riesgo de contagio de rubéola al feto si la madre se infecta antes de la semana 11?","back":"Un 90%."},{"front":"Si la infección por rubéola ocurre después de la semana _____ de gestación, el riesgo de daño orgánico múltiple es nulo.","back":"16."},{"front":"¿Cuál es la prueba diagnóstica confirmatoria de rubéola congénita en el recién nacido?","back":"Detección de RNA viral del recién nacido."},{"front":"¿Cómo se transmite predominantemente el Virus del Herpes Simple (HSV) al recién nacido?","back":"Durante el paso por el canal del parto."},{"front":"¿Qué tipo de HSV provoca el 90% de los casos de herpes neonatal?","back":"HSV tipo 2 (Genital)."},{"front":"¿Qué factor de riesgo aumenta significativamente la transmisión de HSV de madre a hijo?","back":"Presencia de lesiones visibles en la madre al momento del parto o ruptura prolongada de membranas."},{"front":"¿Cómo se describen las lesiones cutáneas clásicas del herpes neonatal local?","back":"Lesiones cutáneas coalescentes sobre base eritematosa o \"gotas de rocío\"."},{"front":"¿Cuál es la dosis de Aciclovir recomendada para el recién nacido con infección por herpes?","back":"30\\ mg/kg/día durante 14-20 días."},{"front":"¿En qué casos de herpes materno se indica el nacimiento por cesárea?","back":"Cuando existen lesiones activas al momento del parto."},{"front":"¿Cuál es el agente causal de la sífilis?","back":"Treponema pallidum."},{"front":"La sífilis _____ se manifiesta en los primeros 2 años de vida, frecuentemente con rinitis hemorrágica y pénfigo ampolloso.","back":"Temprana (o reciente)."},{"front":"¿En qué localización se presenta típicamente el pénfigo sifilítico en el recién nacido?","back":"En palmas y plantas."},{"front":"Concepto: Signo de Wimberger","back":"Definición: Destrucción ósea de la porción medial de la metáfisis tibial proximal, característica de la sífilis congénita."},{"front":"¿Qué es el signo de Higoumenakis en la sífilis congénita?","back":"Engrosamiento proximal de la clavícula."},{"front":"¿Cuáles son los componentes de la tríada de Hutchinson (sífilis tardía)?","back":"Queratitis intersticial, sordera neurosensorial e incisivos en forma de pala."},{"front":"¿Qué hallazgo dental en molares es característico de la sífilis tardía (> 2 años)?","back":"Molares en forma de mora."},{"front":"¿Con qué pruebas se realiza inicialmente el tamizaje de sífilis en la embarazada?","back":"Pruebas no treponémicas cuantitativas (VDRL o RPR)."},{"front":"¿Qué prueba confirma el diagnóstico de sífilis por su alta especificidad?","back":"Pruebas treponémicas (como FTA-ABS o TP-PA)."},{"front":"¿Cuál es el tratamiento de elección para la sífilis congénita en recién nacidos menores de 1 mes?","back":"Penicilina G cristalina 50,000\\ UI cada 12 horas IV por 7 días, luego cada 8 horas hasta completar 10 o 14 días."},{"front":"En sífilis congénita, se considera curado al paciente si la serología es negativa a los _____ meses.","back":"6."},{"front":"¿Cuál es el riesgo de varicela congénita si la madre se infecta antes de la semana 20?","back":"2%."},{"front":"¿Cuáles son las manifestaciones clínicas de la varicela congénita?","back":"Cicatrices cutáneas en patrón dermatomal, hipoplasia de extremidades y microcefalia."},{"front":"¿Cuándo debe aplicarse la vacuna contra varicela a una mujer que planea embarazarse?","back":"28 días antes del embarazo."},{"front":"¿Qué medida se debe tomar en una madre expuesta a varicela para prevenir la infección fetal?","back":"Aplicar inmunoglobulina específica en las primeras 96 horas."},{"front":"¿Qué hallazgo en el ultrasonido fetal sugiere varicela congénita?","back":"Identificación de anomalías estructurales (como hipoplasia de extremidades)."},{"front":"Comparación: Calcificaciones en CMV vs. Toxoplasmosis","back":"CMV: Periventriculares; Toxoplasmosis: Difusas."},{"front":"Comparación: Tamaño de la cabeza en CMV vs. Toxoplasmosis","back":"CMV: Microcefalia; Toxoplasmosis: Macrocefalia (por hidrocefalia)."},{"front":"¿Cuál es la complicación fetal grave de la varicela en el período perinatal (5 días antes a 2 días después del parto)?","back":"Varicela neonatal grave que puede provocar la muerte fetal."},{"front":"¿Qué característica clínica en el recién nacido se conoce como \"Blueberry muffin baby\"?","back":"Púrpura trombocitopénica con hematopoyesis extramedular, común en CMV y Rubéola."},{"front":"La rinitis hemorrágica al nacer es un signo altamente sugestivo de _____.","back":"Sífilis congénita."},{"front":"¿A qué edad aparecen típicamente los síntomas de la sífilis tardía?","back":"Después de los 2 años de edad."},{"front":"¿Cuál es el seguimiento serológico recomendado para un niño con sospecha de sífilis congénita?","back":"Cada 2 meses hasta que los niveles de VDRL sean negativos."},{"front":"Concepto: Pseudoparálisis de Parrot","back":"Definición: Limitación del movimiento de una extremidad debido al dolor por osteocondritis en la sífilis congénita."},{"front":"¿Qué estudio complementario se solicita para evaluar microcalcificaciones y arterias estriadas en CMV?","back":"TAC de cráneo."},{"front":"¿Qué parásito es el responsable de la toxoplasmosis congénita?","back":"Toxoplasma gondii."},{"front":"¿Qué fármaco se añade al tratamiento de toxoplasmosis para prevenir la toxicidad de la pirimetamina?","back":"Ácido folínico."},{"front":"En la sífilis primaria materna, la probabilidad de transmisión vertical es del _____.","back":"70-100%."},{"front":"En el Síndrome de Rubéola Congénita, las secreciones faríngeas pueden ser contagiosas hasta por _____ meses.","back":"27."},{"front":"¿Cuál es el hallazgo de laboratorio hepático común en CMV congénito?","back":"Hiperbilirrubinemia conjugada y transaminasas elevadas."},{"front":"Antes de las 28 semanas de gestación, no existe transferencia placentaria de _____.","back":"Inmunoglobulinas."},{"front":"¿Qué acción inactiva el CMV en la leche materna?","back":"La congelación a -20^{\\circ}C."},{"front":"La tríada de Sabin es diagnóstica de _____, mientras que la de Gregg lo es de _____.","back":"Toxoplasmosis / Rubéola."},{"front":"¿Qué síntoma del SNC es común en la extensión sistémica del herpes neonatal?","back":"Encefalitis con letargia e hipotonía."},{"front":"¿Cuál es la mortalidad aproximada de la varicela congénita?","back":"30%."}]},"7":{"num":7,"name":"ESTENOSIS HIPERTROFICA DEL PILORO","cards":[{"front":"¿Qué cambios histopatológicos caracterizan a la estenosis hipertrófica del píloro?","back":"Hipertrofia e hiperplasia de la capa muscular del estómago en la porción antropilórica."},{"front":"¿Hacia qué dirección viajan las ondas peristálticas en el \"signo de la pelota de golf\"?","back":"De izquierda a derecha tras la alimentación."},{"front":"¿Cuál es la causa de cirugía abdominal más frecuente en lactantes menores de 2 meses?","back":"Estenosis hipertrófica del píloro."},{"front":"¿Qué antibióticos macrólidos se asocian al desarrollo de estenosis pilórica si se ingieren en las primeras dos semanas de vida?","back":"Azitromicina y eritromicina."},{"front":"¿Cuál es la relación de predominio por sexo (hombre:mujer) en la estenosis hipertrófica del píloro?","back":"Proporción de 5:1."},{"front":"¿En qué orden de nacimiento es más frecuente encontrar esta patología?","back":"En el primogénito."},{"front":"¿Cuál es el rango de edad más frecuente para la presentación clínica de la estenosis pilórica?","back":"De las 2 a las 8 semanas de vida."},{"front":"¿Cuál es la característica principal del contenido del vómito en la estenosis hipertrófica del píloro?","back":"Es de contenido no biliar."},{"front":"¿Cómo se describe la fuerza del vómito en un paciente con estenosis pilórica?","back":"Vómito en proyectil."},{"front":"¿Cuál es el signo patognomónico de la estenosis hipertrófica del píloro?","back":"La oliva pilórica."},{"front":"¿En qué cuadrante abdominal se palpa la oliva pilórica?","back":"Cuadrante superior derecho."},{"front":"¿En qué momento es más fácil realizar la palpación de la oliva pilórica?","back":"Después de un episodio de vómito."},{"front":"¿Qué alteración ácido-base metabólica es característica de esta patología?","back":"Alcalosis metabólica hipoclorémica e hipokalémica."},{"front":"¿Cuál es el estudio de imagen considerado el estándar de oro para el diagnóstico de EHP?","back":"Ultrasonido abdominal."},{"front":"¿Qué grosor del músculo pilórico en el ultrasonido es indicativo de estenosis?","back":"> 3-4 mm."},{"front":"¿Qué longitud del canal pilórico en el ultrasonido sugiere el diagnóstico de EHP?","back":"> 17 mm."},{"front":"¿Cuál es el diámetro pilórico total considerado diagnóstico en el ultrasonido?","back":"15-18 mm."},{"front":"¿A qué se debe la imagen de \"doble riel\" observada en los estudios de imagen del píloro?","back":"Al estrechamiento severo de la luz intestinal."},{"front":"¿Qué signo radiológico en la serie esofago-gastro-duodenal indica un canal pilórico muy estrecho?","back":"Signo de la cuerda."},{"front":"¿Qué hallazgo en la serie gastroduodenal se conoce como \"imagen en hombro\"?","back":"El abultamiento del músculo pilórico hacia el antro gástrico."},{"front":"¿Cuál es el primer paso en el tratamiento de un paciente con diagnóstico de estenosis pilórica?","back":"Corrección hidroelectrolítica, ayuno y soluciones parenterales."},{"front":"¿Cómo se denomina la intervención quirúrgica definitiva para la estenosis hipertrófica del píloro?","back":"Piloromiotomía de Fredet-Ramstedt."},{"front":"¿Cuál es la complicación transoperatoria más frecuente durante la piloromiotomía?","back":"Perforación de la mucosa."},{"front":"¿Cuánto tiempo después de la cirugía se recomienda iniciar la alimentación si no hay complicaciones?","back":"De 4 a 8 horas después de la recuperación anestésica."},{"front":"¿Cuál es la dosis recomendada de paracetamol para la analgesia postoperatoria?","back":"15 mg/kg/dosis cada 4 a 6 horas."},{"front":"Un recién nacido con vómito biliar e imagen de \"doble burbuja\" en las primeras 24 horas probablemente tiene:","back":"Atresia duodenal."},{"front":"Un recién nacido con vómito gastroalimentario e imagen de \"burbuja única\" en las primeras 24 horas sugiere:","back":"Atresia pilórica."},{"front":"¿Qué patología se debe sospechar ante un íleo meconial y antecedentes de neumonías de repetición?","back":"Fibrosis quística."},{"front":"¿Qué enfermedad se asocia a íleo meconial y estreñimiento crónico que se agrava con el tiempo?","back":"Enfermedad de Hirschsprung."},{"front":"¿A qué se debe la mortalidad en casos de estenosis hipertrófica del píloro no tratados?","back":"Casi siempre al choque por deshidratación."},{"front":"¿Qué porcentaje de pacientes con EHP tienen padres que también padecieron la patología?","back":"7 %."},{"front":"¿Cuál es la causa principal de alcalosis metabólica en el periodo pediátrico?","back":"Estenosis hipertrófica del píloro."},{"front":"¿En qué etapa de la vida es más frecuente la presentación inicial de la EHP?","back":"En los primeros 20 días de vida."},{"front":"¿Cuál es la incidencia reportada de EHP por cada 1000 nacidos vivos?","back":"De 1.5 a 4 casos."},{"front":"¿Qué raza se identifica como un factor de riesgo para la estenosis pilórica?","back":"Raza blanca."},{"front":"¿Cómo se encuentra el apetito del paciente tras los episodios de vómito en la EHP?","back":"Presenta gran avidez por la alimentación (hambre voraz)."},{"front":"Concepto: Gastromegalia","back":"Definición: Agrandamiento anormal del estómago observado como dato radiológico en la estenosis pilórica."},{"front":"¿Cuál es la última opción diagnóstica si los estudios de imagen no son concluyentes?","back":"Endoscopia de tubo digestivo alto."},{"front":"¿Qué signo clínico se observa en el abdomen debido a la lucha gástrica contra la obstrucción?","back":"Signo de la pelota de golf."},{"front":"¿Qué fórmula o índice numérico se menciona como criterio ecográfico adicional?","back":"3.1517 (PI + 1)."},{"front":"¿Cuál es el componente hidroelectrolítico que más se pierde y causa la alcalosis en la EHP?","back":"El cloro (causando hipocloremia)."},{"front":"¿Bajo qué condiciones se asocia el uso de macrólidos con la estenosis pilórica?","back":"Ingestión durante las primeras dos semanas de vida."},{"front":"¿Qué estudio se realiza para confirmar el estado metabólico y de gases en el paciente?","back":"Gasometría."},{"front":"¿Cómo se describe la progresión del vómito en la estenosis pilórica?","back":"Es de carácter progresivo (aumenta en frecuencia y fuerza)."},{"front":"¿Cuál es la localización anatómica precisa de la obstrucción en la EHP?","back":"La luz intestinal a nivel del píloro (segmento antropilórico)."},{"front":"¿Cuál es el diagnóstico diferencial de un paciente con distensión abdominal y falta de evacuación en las primeras 72 horas?","back":"Íleo meconial."},{"front":"¿Qué signo radiológico se asocia al retraso del vaciamiento gástrico en la serie baritada?","back":"Signo de la cuerda o del doble riel."},{"front":"¿Qué hallazgo físico indica deshidratación en un lactante con vómitos persistentes?","back":"Datos de deshidratación (como fontanela hundida o mucosas secas)."},{"front":"¿Cuál es la frecuencia de administración del paracetamol postoperatorio?","back":"Cada 4 a 6 horas."},{"front":"¿Qué factor genético/hereditario aumenta el riesgo de padecer esta condición?","back":"Tener antecedentes familiares de estenosis pilórica."},{"front":"¿Cuál es el hallazgo típico en la serie gastroduodenal respecto al tamaño del estómago?","back":"Gastro/gastromegalia."},{"front":"¿Qué tipo de alcalosis se produce por la pérdida de ácido clorhídrico en el vómito?","back":"Alcalosis hipoclorémica."}]},"8":{"num":8,"name":"ICTERICIA NEONATAL","cards":[{"front":"¿De qué proceso es producto la bilirrubina?","back":"Del catabolismo del grupo hemo."},{"front":"¿Qué porcentaje de la bilirrubina proviene de la degradación de la hemoglobina de los eritrocitos?","back":"Aproximadamente del 80-90%."},{"front":"¿Qué porcentaje de la bilirrubina se produce por la descomposición de proteínas distintas a la hemoglobina?","back":"Entre el 10-20%."},{"front":"Durante la absorción hepática, la bilirrubina se transporta al hígado unida a la _____.","back":"Albúmina"},{"front":"¿Cuál es la principal ventaja de la bilirrubina conjugada en comparación con la no conjugada?","back":"Es más soluble y puede ser excretada por la bilis."},{"front":"¿A través de qué transportadores ocurre la excreción biliar de la bilirrubina?","back":"Transportadores canaliculares."},{"front":"Definición: Ictericia neonatal","back":"Coloración amarilla de la piel y escleróticas por el aumento de la bilirrubina circulante."},{"front":"¿A qué se debe la reducción de la vida media de los eritrocitos en el período neonatal?","back":"A la inmadurez del complejo glucuroniltransferasa."},{"front":"¿Qué cifra de bilirrubina total (BT) define la ictericia en un recién nacido?","back":"> 5\\text{ mg/dL}."},{"front":"¿Qué porcentaje de recién nacidos a término desarrollan ictericia?","back":"El 60%."},{"front":"¿Qué porcentaje de recién nacidos prematuros desarrollan ictericia?","back":"El 80%."},{"front":"¿Cuál es la patología más común causante de readmisión hospitalaria en neonatos?","back":"La ictericia neonatal."},{"front":"¿Cuál es la edad gestacional considerada como factor de riesgo para ictericia neonatal?","back":"Menos de 38 semanas de gestación (SDG)."},{"front":"¿Qué causas de ictericia deben sospecharse si aparece en las primeras 24 horas de vida?","back":"Hemólisis o infecciones."},{"front":"¿Qué etiologías son comunes para la ictericia que aparece entre el 2^{\\circ} y 3^{\\circ} día de vida?","back":"Fisiológica, anemias hemolíticas o sepsis."},{"front":"¿Qué causas de ictericia se asocian con el periodo entre el 4^{\\circ} y 7^{\\circ} día de vida?","back":"Sepsis, TORCH o lactancia materna."},{"front":"¿Qué patologías se sospechan en una ictericia que persiste más de 1 mes?","back":"Galactosemia o hipotiroidismo."},{"front":"¿Cuál es la duración típica de la ictericia fisiológica?","back":"Menos de 10 días."},{"front":"¿En qué momento suele aparecer la ictericia asociada a la leche materna?","back":"Entre el 5^{\\circ} y 7^{\\circ} día de vida."},{"front":"¿Qué tipo de bilirrubina predomina en la ictericia fisiológica?","back":"Bilirrubina indirecta."},{"front":"¿Qué tipo de bilirrubina puede estar elevada en la ictericia no fisiológica?","back":"Bilirrubina directa o indirecta."},{"front":"¿Cuál es el estándar de oro para determinar el grado de hiperbilirrubinemia?","back":"Determinación de bilirrubinas séricas."},{"front":"¿En qué plazo se deben medir las bilirrubinas si se detecta ictericia visible después de las 24 horas?","back":"Dentro de las siguientes 6 horas."},{"front":"¿A partir de qué percentil se considera formalmente hiperbilirrubinemia?","back":"Percentil mayor a 95%."},{"front":"¿Qué rango de bilirrubina total se considera hiperbilirrubinemia severa?","back":"Entre 20-24\\text{ mg/dL}."},{"front":"¿Cuál es la utilidad principal de la Escala de Kramer?","back":"Determinar la presencia o ausencia de ictericia visualmente."},{"front":"Según la Escala de Kramer, ¿qué nivel de bilirrubina total se asocia a la Zona 1 (cabeza y cuello)?","back":"5.8\\text{ mg/dL}."},{"front":"Según la Escala de Kramer, ¿qué zona anatómica corresponde a un nivel de 14.7\\text{ mg/dL}?","back":"Zona 4 (brazos y piernas)."},{"front":"En la Escala de Kramer, la Zona 5 (palmas y plantas) indica niveles de bilirrubina superiores a _____.","back":"14.7\\text{ mg/dL}"},{"front":"¿Cuál es el espectro de luz utilizado en la fototerapia?","back":"Entre 460 a 490\\text{ nm} (luz azul)."},{"front":"¿Qué disminución horaria de bilirrubina se espera en las primeras 4-8 horas de fototerapia?","back":"0.5\\text{ mg/dL} por hora."},{"front":"¿En qué momento se alcanza la respuesta máxima a la fototerapia?","back":"Entre las 2 y 6 horas de inicio."},{"front":"¿Qué medida de protección es obligatoria para el neonato durante la fototerapia?","back":"Cubrir los ojos."},{"front":"¿A qué niveles de bilirrubina total se recomienda suspender la fototerapia?","back":"Al alcanzar 13-14\\text{ mg/dL}."},{"front":"Mencione tres efectos secundarios de la fototerapia en neonatos.","back":"Diarrea, rash y deshidratación."},{"front":"¿Cada cuánto tiempo se deben medir las bilirrubinas después de iniciar la fototerapia?","back":"Cada 4-6 horas."},{"front":"¿Cuál es la siguiente opción terapéutica si fallan dos ciclos de fototerapia?","back":"Exanguinotransfusión."},{"front":"¿En qué nivel de bilirrubinas no conjugadas se indica realizar exanguinotransfusión?","back":"Cuando superen los 300\\text{ \\mu mol/L}."},{"front":"¿Qué electrolito se debe medir al finalizar una exanguinotransfusión?","back":"Calcio."},{"front":"Mencione una complicación grave de la exanguinotransfusión relacionada con el sistema gastrointestinal.","back":"Enterocolitis necrotizante."},{"front":"¿Cuál es la fórmula de volumen para exanguinotransfusión en un recién nacido a término?","back":"80\\text{ mL/kg} \\times 2."},{"front":"¿A qué se debe la ictericia fisiológica del recién nacido?","back":"Inmadurez del complejo glucuroniltransferasa y menor vida media de eritrocitos."},{"front":"¿Por qué la ictericia por lactancia materna se asocia con un aumento de la circulación enterohepática?","back":"Debido a un tránsito intestinal lento."},{"front":"¿Constituye la ictericia por lactancia materna una contraindicación para amamantar?","back":"No, no contraindica la lactancia materna."},{"front":"Prueba diagnóstica: Ictericia por lactancia materna","back":"Interrupción de la lactancia por 48 horas para demostrar la disminución de la ictericia."},{"front":"¿Cuál es la causa más frecuente de las ictericias metabólicas constitucionales?","back":"Síndrome de Gilbert."},{"front":"¿Qué mutación genética caracteriza al Síndrome de Gilbert?","back":"Mutación del gen UGT1A1."},{"front":"¿Cuál es la prueba diagnóstica de elección para el Síndrome de Gilbert?","back":"Prueba de ayuno (2 días con dieta de 200\\text{ kcal})."},{"front":"¿Qué caracteriza al Síndrome de Crigler-Najjar Tipo I?","back":"Ausencia completa de la actividad de la glucuroniltransferasa."},{"front":"¿Cuál es el riesgo principal de muerte en el primer año de vida para pacientes con Crigler-Najjar Tipo I?","back":"Kernicterus."},{"front":"¿Cuál es el tratamiento definitivo para el Síndrome de Crigler-Najjar Tipo I?","back":"Trasplante hepático."},{"front":"¿Qué diferencia al Síndrome de Crigler-Najjar Tipo II del Tipo I?","back":"El Tipo II presenta una deficiencia parcial de la actividad enzimática, no total."},{"front":"¿Cuál es el rango típico de bilirrubina indirecta en el Síndrome de Crigler-Najjar Tipo II?","back":"Entre 6-20\\text{ mg/dL}."},{"front":"¿Cuál es el tipo de incompatibilidad sanguínea más frecuente en neonatos?","back":"Incompatibilidad de grupo ABO."},{"front":"¿Qué combinación de grupos sanguíneos madre-hijo es típica en la incompatibilidad ABO?","back":"Madre O y recién nacido A, B o AB."},{"front":"¿Es necesaria la sensibilización previa para que ocurra la incompatibilidad ABO?","back":"No, no se requiere sensibilización previa."},{"front":"¿Cuál es la isoinmunización más frecuente dentro de la incompatibilidad Rh?","back":"Isoinmunización anti-D."},{"front":"¿Qué cantidad mínima de eritrocitos Rh positivos es suficiente para generar anticuerpos en la madre?","back":"0.1\\text{ mL}."},{"front":"¿Qué prueba se solicita para descartar inmunización en la incompatibilidad Rh?","back":"Coombs indirecto."},{"front":"Definición: Atresia de vías biliares","back":"Colangiopatía fibro-esclerosante inflamatoria progresiva que causa la obliteración del tracto biliar."},{"front":"¿Cuál es el tipo más frecuente de atresia de vías biliares (80%)?","back":"Tipo III: Afecta a toda la vía biliar extrahepática."},{"front":"¿Qué hallazgos clínicos destacan en las etapas tardías de la atresia de vías biliares?","back":"Cirrosis, ascitis y hepatosplenomegalia."},{"front":"¿Cuál es el estudio de elección inicial para el diagnóstico de atresia de vías biliares?","back":"Ultrasonido (USG)."},{"front":"¿Qué signo ecográfico es característico de la atresia de vías biliares?","back":"Signo de la cuerda triangular."},{"front":"¿Cuál es el estándar de oro para el diagnóstico de atresia de vías biliares?","back":"Biopsia."},{"front":"¿En qué consiste la cirugía paliativa de Kasai para atresia biliar?","back":"Hepato-entero-estomía (hepatoportoenterostomía)."},{"front":"Si una ictericia presenta bilirrubina indirecta aumentada y la prueba de Coombs directo es positiva, se sospecha de _____.","back":"Incompatibilidad de grupo ABO o Rh"},{"front":"¿Qué patología se debe sospechar ante un patrón colestásico, acolia y coluria después de los 15 días de vida?","back":"Atresia de vías biliares."},{"front":"¿Cuánta bilirrubina produce el catabolismo de 1\\text{ g} de hemoglobina?","back":"35\\text{ mg}."},{"front":"¿Qué fármaco se menciona como tratamiento para las convulsiones en el contexto de ictericia neonatal?","back":"Fenobarbital."},{"front":"¿Cuál es la causa de ictericia no inmune por defectos de la membrana del eritrocito?","back":"Esferocitosis hereditaria."}]},"9":{"num":9,"name":"MALFORMACIONES CONGENITAS","cards":[{"front":"¿Cuál es la definición de onfalocele?","back":"Es un defecto congénito con eventración de vísceras cubiertas por amnios y peritoneo."},{"front":"¿Cuál es la definición de gastrosquisis?","back":"Es un defecto en la línea paraumbilical derecha sin saco protector de las vísceras."},{"front":"¿Qué cromosopatías presentan una alta asociación con el onfalocele?","back":"Trisomías 13, 18 y 21."},{"front":"En el onfalocele, ¿cuándo se considera que la presencia de hígado es indicación de cesárea?","back":"Cuando el defecto es mayor a 5 cm."},{"front":"¿Qué síndrome genético se asocia frecuentemente con el onfalocele?","back":"Síndrome de Beckwith-Wiedemann."},{"front":"¿Cuál es la incidencia estimada de la gastrosquisis?","back":"1 de cada 2,000 recién nacidos."},{"front":"¿Qué porcentaje de pacientes con gastrosquisis presenta prematurez asociada?","back":"Entre el 50% y el 60%."},{"front":"¿Qué parámetro es necesario medir en pacientes con defectos de pared abdominal para evitar un síndrome compartimental?","back":"La presión intraabdominal."},{"front":"¿Qué hallazgo por ultrasonido prenatal antes de la semana 25 sugiere un defecto de pared abdominal?","back":"Polihidramnios y ausencia de burbuja gástrica intraabdominal."},{"front":"¿Cuál es el manejo preoperatorio específico para cubrir el defecto en una gastrosquisis?","back":"Cubrir con material estéril y transparente, como una bolsa de polietileno."},{"front":"¿Cuál es el tratamiento quirúrgico de elección para una gastrosquisis?","back":"Colocación de un silo."},{"front":"¿Qué técnica quirúrgica se utiliza en un onfalocele con defecto roto?","back":"Cierre por etapas con silo (Técnica de Schuster)."},{"front":"¿Cuál es la fisiopatología principal de la hernia diafragmática congénita?","back":"Hipoplasia pulmonar secundaria a la herniación del contenido abdominal al tórax."},{"front":"¿Cuál es la localización más frecuente de la hernia de Bochdalek?","back":"Posterior y del lado izquierdo (95% de los casos)."},{"front":"¿Cuál es la localización característica de la hernia de Morgagni?","back":"Anterior y derecha (5% de los casos)."},{"front":"¿Qué hallazgos se esperan en la exploración física de un neonato con hernia de Bochdalek?","back":"Abdomen en batea, ruidos intestinales en tórax y ausencia de murmullo vesicular."},{"front":"¿A qué se debe el origen embriológico de la hernia de Bochdalek?","back":"Falta de cierre del canal pleuroperitoneal en la semana 8."},{"front":"¿Cuál es el estudio confirmatorio para el diagnóstico de hernia diafragmática?","back":"Radiografía de tórax."},{"front":"¿Cuál es el manejo inicial inmediato de un recién nacido con hernia diafragmática?","back":"Intubación y colocación de sonda nasogástrica."},{"front":"¿Cuál es el tipo de atresia esofágica más frecuente?","back":"Tipo III (Atresia proximal y fístula distal)."},{"front":"¿Cuál es la tríada clínica clásica de la atresia esofágica en el neonato?","back":"Sialorrea, imposibilidad para pasar sonda nasogástrica y cianosis/atragantamiento en tomas."},{"front":"En la atresia esofágica, ¿qué hallazgo en la radiografía confirma el diagnóstico?","back":"Sonda enrollada en el esófago o ausencia de cámara gástrica."},{"front":"¿Cuál es el Estándar de Oro para diagnosticar atresia esofágica?","back":"Radiografía abdominal con contraste hidrosoluble."},{"front":"¿Por qué se contraindica la intubación en el manejo inicial de la atresia esofágica?","back":"Por el riesgo de perforación gástrica debido al flujo de aire al estómago por la fístula."},{"front":"¿Cuál es la complicación postquirúrgica más frecuente tras la reparación de una atresia esofágica?","back":"Reflujo gastroesofágico."},{"front":"¿Qué tipo de atresia esofágica se asocia con neumonías recurrentes?","back":"Tipo V (Fístula sin atresia)."},{"front":"¿Cuál es la característica clínica cardinal de la atresia de coanas?","back":"Cianosis que desaparece cuando el recién nacido llora."},{"front":"¿Cuál es el estudio de elección para el diagnóstico de atresia de coanas?","back":"TAC simple."},{"front":"¿Qué componentes integran el síndrome de CHARGE?","back":"Coloboma, Heart (cardiopatía), Atresia de coanas, Retraso del crecimiento, Genitourinarias y Ear (sordera)."},{"front":"¿Cuál es la localización más frecuente de la atresia intestinal congénita?","back":"Duodenal (específicamente la 2^{a} o 3^{a} porción)."},{"front":"¿Qué signo radiográfico es característico de la atresia duodenal?","back":"Signo de la \"doble burbuja\"."},{"front":"¿Qué signo radiográfico se observa en la atresia pilórica?","back":"Burbuja gástrica única."},{"front":"¿Cuál es el tratamiento quirúrgico de elección para la atresia duodenal?","back":"Anastomosis duodeno-duodenal lateral (Técnica de Kimura)."},{"front":"Si un neonato presenta vómito claro y sin bilis, ¿cuál es el sitio probable de la obstrucción?","back":"Esófago o estómago."},{"front":"Un vómito de color verde en un recién nacido sugiere una obstrucción a nivel de _____.","back":"Yeyuno o íleon."},{"front":"¿Qué patología se asocia con el hallazgo radiográfico de \"vidrio esmerilado\" o pequeñas burbujas?","back":"Íleo meconial."},{"front":"¿Cuál es la deficiencia enzimática en la Mucopolisacaridosis 1 (Síndrome de Hurler)?","back":"Deficiencia de alfa-L-iduronidasa."},{"front":"¿Cuáles son las características clínicas faciales de un paciente con Síndrome de Hurler?","back":"Fascies toscas y macrocefalia con protuberancia."},{"front":"¿Cuál es el estudio confirmatorio para el diagnóstico de Mucopolisacaridosis 1?","back":"Estudio molecular."},{"front":"¿A qué se debe el 75% de los casos de espina bífida?","back":"A una deficiencia importante de ácido fólico durante la gestación."},{"front":"¿En qué días de la gestación ocurre normalmente el cierre del tubo neural?","back":"Cefálico a los 38 días y caudal a los 40 días."},{"front":"¿Qué fármaco consumido durante el embarazo es el principal factor de riesgo para defectos del tubo neural?","back":"Ácido valproico."},{"front":"¿Cuál es la diferencia clínica entre meningocele y mielomeningocele?","back":"El meningocele no contiene tejido neuronal, mientras que el mielomeningocele sí."},{"front":"¿Qué signo ultrasonográfico prenatal indica espina bífida entre las semanas 13 y 24?","back":"Signo del limón."},{"front":"¿Cuál es el tiempo ideal para realizar la cirugía definitiva en un paciente con espina bífida abierta?","back":"Entre 48 y 72 horas tras el nacimiento."},{"front":"¿Cuál es la manifestación clínica de la persistencia del uraco?","back":"Presencia de orina o líquido ácido en la cicatriz umbilical."},{"front":"¿Cuál es la complicación maligna más frecuente de la persistencia del uraco?","back":"Degeneración a adenocarcinoma."},{"front":"¿Cuál es el tratamiento de elección para el remanente uracal?","back":"Exéresis completa del remanente más tratamiento antibiótico."},{"front":"¿Qué porcentaje de malformaciones anorrectales se asocia con anomalías urinarias?","back":"67% de los casos."},{"front":"¿Cuál es el tratamiento quirúrgico de elección para las malformaciones anorrectales?","back":"Anoplastía."},{"front":"¿Cuál es la sospecha clínica inicial ante cualquier recién nacido con vómito bilioso?","back":"Malrotación intestinal."},{"front":"¿Qué hallazgo en la serie esófago-gastroduodenal es diagnóstico de malrotación intestinal?","back":"Imagen en sacacorchos."},{"front":"¿En qué consiste el tratamiento quirúrgico de la malrotación intestinal?","back":"Operación de Ladd (distorsión del vólvulo) más ampliación del mesenterio."},{"front":"¿Cuál es el patrón de herencia del Síndrome de Peutz-Jeghers?","back":"Autosómica dominante."},{"front":"¿Qué mutaciones genéticas condicionan el Síndrome de Peutz-Jeghers?","back":"Mutaciones en los genes LKB1 y STK11."},{"front":"¿Cuáles son las dos características clínicas principales del Síndrome de Peutz-Jeghers?","back":"Pólipos hamartomatosos en el tubo digestivo y lesiones cutáneas hiperpigmentadas."},{"front":"¿Cuál es el tratamiento para los pólipos en el Síndrome de Peutz-Jeghers?","back":"Polipectomía endoscópica."},{"front":"¿Cuál es la causa embriológica del labio y paladar hendido?","back":"Falta de migración del mesodermo del proceso nasomedial con los procesos nasolateral y maxilar."},{"front":"¿A qué edad se recomienda realizar la queiloplastía en pacientes con labio hendido?","back":"Después de los 3 meses de edad."},{"front":"¿A qué edad se recomienda realizar la palatoplastía?","back":"A los 18 meses de edad."},{"front":"Concepto: Atresia Tipo I de esófago.","back":"Definición: Atresia esofágica sin fístula, presente en el 8% de los casos."},{"front":"En el diagnóstico de onfalocele, ¿qué significa la ausencia de burbuja gástrica?","back":"Sugiere que el estómago está desplazado fuera de la cavidad abdominal."},{"front":"¿Cuál es el manejo inicial de un granuloma umbilical con secreción mucopurulenta?","back":"Descartar un granuloma inguinal."}]},"10":{"num":10,"name":"CRECIMIENTO Y DESARROLLO PARTE 1","cards":[{"front":"¿Cómo se define el 'crecimiento' en pediatría?","back":"Es el aumento de peso y talla debido a hipertrofia e hiperplasia celular."},{"front":"¿Qué término describe el perfeccionamiento y maduración de las funciones en el niño?","back":"Desarrollo"},{"front":"En la clasificación por edad, ¿qué periodo comprende el 'lactante menor'?","back":"De 1 a 12 meses de edad."},{"front":"¿A qué edad se considera que un niño deja de ser preescolar para ser escolar?","back":"A los 6 años."},{"front":"¿Cuál es la hormona principal que modula el crecimiento durante la vida intrauterina?","back":"Insulina"},{"front":"¿Qué hormonas son fundamentales para el crecimiento desde el nacimiento hasta la etapa preescolar?","back":"Hormonas tiroideas"},{"front":"En la etapa escolar, la hormona que predomina en la modulación del crecimiento es la _____.","back":"Hormona del crecimiento"},{"front":"¿Cuáles son las 4 áreas que evalúa el Test de Denver?","back":"Motor grueso, motor fino, aspectos personales (social/emocional) y lenguaje."},{"front":"En niños prematuros, ¿hasta qué edad se debe restar el tiempo de prematuridad al evaluar el desarrollo?","back":"Hasta los 2 años."},{"front":"Dato de alarma a los 3 meses: No fijar la mirada es sugerente de _____.","back":"Daño neurológico"},{"front":"¿Qué implica un resultado 'Rojo' en la Prueba de Evaluación del Desarrollo Infantil (EDI)?","back":"Riesgo de retraso en el desarrollo y necesidad de referir a segundo nivel."},{"front":"¿A qué edades es obligatoria la aplicación de la prueba EDI en México?","back":"1, 6, 18 y 30 meses."},{"front":"¿En qué mes de vida el lactante suele levantar la cabeza en posición prona y presentar sonrisa social?","back":"A los 2 meses."},{"front":"¿A qué edad se espera que un niño logre la sedestación por sí solo (sentarse solo)?","back":"Entre los 6 y 8 meses."},{"front":"¿A qué edad aparece típicamente la 'pinza fina' y el inicio de la bipedestación?","back":"A los 9-10 meses."},{"front":"¿Cuántas palabras (además de mamá y papá) se espera que use un niño de 12 meses?","back":"2 palabras."},{"front":"¿A qué edad se espera que un niño sea capaz de pedalear un triciclo?","back":"A los 3 años."},{"front":"¿Cuántos cubos debe ser capaz de apilar un niño de 2 años en una torre?","back":"6 cubos."},{"front":"¿A qué edad desaparece normalmente el reflejo de Moro?","back":"A los 6 meses."},{"front":"¿En qué rango de edad desaparece el reflejo de prensión palmar?","back":"A los 3-4 meses."},{"front":"La desaparición de los reflejos arcaicos se asocia fisiológicamente a la _____.","back":"Madurez cortical"},{"front":"¿Cuántas consultas médicas se recomiendan para un neonato (menor de 30 días)?","back":"2 consultas."},{"front":"¿Con qué frecuencia se deben realizar las consultas de seguimiento en niños de 1 a 4 años?","back":"Cada 6 meses."},{"front":"¿Qué cantidad de Vitamina D se debe administrar a un lactante de 0 a 6 meses?","back":"400 UI."},{"front":"¿En qué semanas de vida se debe realizar la primera evaluación del reflejo pupilar?","back":"Semana 1 y 4."},{"front":"¿A qué edad se espera que la dentición esté completa?","back":"A los 2 años."},{"front":"¿En qué mes cierra típicamente la fontanela anterior?","back":"A los 18 meses."},{"front":"¿En qué rango de meses ocurre el cierre de la fontanela posterior?","back":"Entre los 4 y 5 meses."},{"front":"¿Cuál es la recomendación de tiempo frente a pantallas para niños menores de dos años?","back":"Cero pantallas."},{"front":"¿A partir de qué edad se inicia la desparasitación rutinaria?","back":"A partir de los 2 años."},{"front":"¿Hasta qué mes se recomienda la lactancia materna exclusiva?","back":"Hasta los 6 meses."},{"front":"¿Qué porcentaje de la ingesta calórica debe representar la lactancia materna a los 2 años de edad?","back":"50%."},{"front":"¿Qué inmunoglobulina es característica del calostro (secretado los primeros 5 días)?","back":"IgA"},{"front":"La leche materna madura se establece a partir de los _____ días postparto.","back":"15 días."},{"front":"¿Cuál es la principal causa de abandono de la lactancia materna?","back":"Falta de producción láctea."},{"front":"Para disminuir la regurgitación, un niño hipotónico debe alimentarse en posición _____.","back":"Cruzada o de balón de futbol."},{"front":"¿Cuál es la regla de oro sobre el acercamiento durante la lactancia?","back":"El bebé alcanza el pecho y no el pecho al bebé."},{"front":"¿Qué signos indican que la deglución del bebé es efectiva durante la succión?","back":"Las mejillas se redondean y la deglución es visible y audible."},{"front":"¿Cuál es la capacidad gástrica aproximada de un recién nacido en su primer día de vida?","back":"5 a 7 ml (tamaño de una cereza)."},{"front":"¿Qué porcentaje de peso puede perder un bebé sano en la primera semana de vida?","back":"Hasta el 10% de su peso al nacimiento."},{"front":"¿Cuánto tiempo puede conservarse la leche materna extraída a temperatura ambiente?","back":"De 3 a 4 horas."},{"front":"¿Por cuánto tiempo es segura la leche materna congelada entre -4 y -20 ^\\circ C?","back":"Al menos 6 meses."},{"front":"¿Cuál es el método recomendado para descongelar la leche materna?","back":"A baño María."},{"front":"¿Qué material está contraindicado para los recipientes de almacenamiento de leche materna?","back":"Acero o polietileno."},{"front":"¿Cuál es la contraindicación absoluta de lactancia materna relacionada con el estado del pezón?","back":"Lesiones herpéticas activas en la mama."},{"front":"¿Bajo qué condición diagnóstica materna se puede dar lactancia directa en caso de tuberculosis?","back":"Si existen dos baciloscopias negativas."},{"front":"¿Qué antibióticos se mencionan como contraindicados durante la lactancia?","back":"Tetraciclinas, cloranfenicol y clindamicina."},{"front":"¿A qué edad se debe iniciar la ablactación o alimentación complementaria?","back":"A los 6 meses."},{"front":"¿Con qué frecuencia se debe introducir un alimento nuevo durante la ablactación?","back":"Cada 3 a 4 días."},{"front":"¿Por qué no se recomiendan las espinacas, acelgas y remolacha antes del primer año?","back":"Por el riesgo de metahemoglobinemia."},{"front":"¿Cuál es la textura recomendada para los alimentos de un lactante de 6 a 7 meses?","back":"Papillas o puré."},{"front":"¿A qué edad se recomienda introducir los trozos (dieta familiar) en la alimentación?","back":"A partir del primer año de vida."},{"front":"¿Cuál es el factor de riesgo más importante para el Síndrome de Muerte Súbita del Lactante (SMSL)?","back":"Tabaquismo durante y después del embarazo."},{"front":"¿Qué posición al dormir es la principal medida de prevención para el SMSL?","back":"Decúbito supino (boca arriba)."},{"front":"¿Qué hallazgo es el más frecuente en las autopsias por SMSL?","back":"Hemorragia petequial (68-95%)."},{"front":"El maltrato infantil físico se define como la agresión en menores de _____ años.","back":"18 años."},{"front":"¿Cuál es el tipo de abuso infantil más frecuente?","back":"Abuso físico."},{"front":"Menciona los tres componentes de la tríada clásica del Síndrome del Niño Sacudido.","back":"Hematoma subdural, hemorragia retiniana y edema cerebral (encefalopatía)."},{"front":"¿Qué se debe priorizar ante el caso de un niño víctima de maltrato infantil?","back":"Las lesiones que ponen en peligro la vida."},{"front":"¿Qué escala se utiliza para evaluar el riesgo de retraso psicomotor si hay 2 áreas afectadas?","back":"Prueba de Denver."},{"front":"¿Cuál es la meta de lactancia materna exclusiva de acuerdo a la OMS?","back":"50%."},{"front":"¿Qué fármaco se administra para tratar la falta de producción láctea (causa principal de abandono)?","back":"Domperidona"},{"front":"El orden de inducción recomendado en la ablactación es: vegetales, frutas y _____.","back":"Carne"},{"front":"¿Qué hallazgo clínico a los 6 meses es un dato de alarma del desarrollo?","back":"Persistencia de reflejos arcaicos."},{"front":"¿Cuál es el estándar de oro para el diagnóstico del Síndrome del Niño Sacudido?","back":"Historia clínica y exploración física detallada."}]},"11":{"num":11,"name":"CRECIMIENTO Y DESARROLLO PARTE 2","cards":[{"front":"¿Cuál es la causa primaria de la desnutrición según la fuente?","back":"La ingesta insuficiente de nutrientes."},{"front":"¿A qué se debe la causa secundaria de la desnutrición?","back":"A una enfermedad orgánica, como infecciones crónicas o patologías digestivas."},{"front":"Defina el término 'desmedro'.","back":"Es una estatura muy baja con respecto a la edad del paciente."},{"front":"Defina el término 'emaciación'.","back":"Es un peso muy bajo con respecto a la altura del paciente."},{"front":"¿Cuál es el rango de edad que representa el pico de incidencia de desnutrición?","back":"De 6 a 36 meses."},{"front":"¿Cuál es el tipo de desnutrición más común en México?","back":"La desnutrición crónica."},{"front":"¿Qué indicador epidemiológico es el más apropiado para evaluar la desnutrición crónica?","back":"La talla para la edad."},{"front":"¿Qué indicador epidemiológico es el más apropiado para evaluar la desnutrición aguda?","back":"El peso para la talla."},{"front":"¿Cuál es el hallazgo laboratorial más frecuente en niños desnutridos?","back":"Anemia microcítica hipocrómica."},{"front":"¿Qué parámetro evalúa la clasificación de Federico Gómez para valorar la severidad?","back":"El peso para la edad."},{"front":"¿Cuál es el tratamiento antibiótico indicado en caso de infección detectada en desnutrición?","back":"Ampicilina más Gentamicina."},{"front":"Concepto: Kwashiorkor","back":"Definición: Desnutrición aguda por ingesta inadecuada de proteínas, caracterizada por edema."},{"front":"¿A partir de qué nivel de albúmina suele comenzar el edema en el Kwashiorkor?","back":"< 2.8 g/100 mL."},{"front":"En el Kwashiorkor, ¿a qué se debe la presencia de un abdomen protuberante?","back":"A la debilidad de los músculos y a la hepatomegalia (esteatosis)."},{"front":"¿En qué consiste el 'signo de la bandera' en la desnutrición aguda?","back":"Es la decoloración del cabello debido a la hipoalbuminemia."},{"front":"Concepto: Marasmo","back":"Definición: Desnutrición crónica energético-calórica que afecta tanto el peso como la talla."},{"front":"¿Qué hallazgo físico se conoce como el 'signo del pantalón' en el marasmo?","back":"La emaciación de los pliegues glúteos."},{"front":"En el tratamiento de la desnutrición, ¿cuál es el tiempo estimado para la rehidratación?","back":"24 - 48 horas."},{"front":"¿Qué indicador utiliza la clasificación de Waterloo para valorar procesos agudos?","back":"El peso para la talla."},{"front":"Según el Z-score, ¿qué valor define una desnutrición severa?","back":"< -3 DS."},{"front":"¿Qué síntomas produce la deficiencia de Vitamina A?","back":"Ceguera nocturna, xeroftalmia y sequedad de epitelios."},{"front":"¿Cuál es la consecuencia clínica de la deficiencia de Vitamina B2 (Riboflavina)?","back":"Lesiones cutaneomucosas, oculares y nerviosas."},{"front":"¿Qué patología resulta de la deficiencia de Vitamina B1 (Tiamina)?","back":"Beriberi."},{"front":"¿Cómo se realiza el diagnóstico laboratorial del Beriberi?","back":"Mediante la prueba enzimática de la transcetolasa."},{"front":"Nombre la triada clásica de la Pelagra (deficiencia de B3).","back":"Diarrea, dermatitis y demencia."},{"front":"¿Cuál es el precursor endógeno de la Niacina (Vitamina B3)?","back":"El triptófano."},{"front":"¿Qué deficiencia vitamínica causa el Escorbuto?","back":"Deficiencia de Vitamina C (ácido ascórbico)."},{"front":"¿Qué hallazgo radiográfico en huesos largos sugiere Raquitismo?","back":"Metáfisis en copa de champán."},{"front":"¿Cómo se define clínicamente el sobrepeso en niños de 2 a 18 años?","back":"IMC entre el percentil 85 y 95 para la edad y el sexo."},{"front":"¿A partir de qué percentil de IMC se diagnostica obesidad en niños mayores de 2 años?","back":"Percentil > 95."},{"front":"¿Cuál es el tiempo máximo recomendado frente a pantallas para prevenir obesidad?","back":"2 horas diarias (evitar en menores de 2 años)."},{"front":"¿Cuál es el tratamiento farmacológico a largo plazo (más de 3 meses) para la obesidad infantil?","back":"Orlistat."},{"front":"¿Cuáles son los criterios para cirugía bariátrica (Bypass gástrico) en adolescentes?","back":"IMC > 40 o IMC > 35 con comorbilidad y madurez puberal."},{"front":"¿Cuándo se considera que la talla es baja con respecto a la población?","back":"Cuando se encuentra por debajo del percentil 3 o por debajo de -2 desviaciones estándar."},{"front":"¿Qué caracteriza a la talla baja familiar?","back":"Hipocrecimiento evolutivo postnatal con edad ósea normal y pronóstico de talla adulta baja."},{"front":"¿Qué zona anatómica se utiliza para valorar la edad ósea en menores de 2 años?","back":"Pie y tobillo (tibia izquierda)."},{"front":"¿Qué zona anatómica se utiliza para valorar la edad ósea en mayores de 2 años?","back":"Muñeca de la mano no dominante."},{"front":"¿Cuál es la fórmula para calcular la Talla Blanco Familiar en niños?","back":"(\\text{Talla materna} + \\text{Talla paterna}) / 2 + 6.5."},{"front":"¿Cuál es la fórmula para calcular la Talla Blanco Familiar en niñas?","back":"(\\text{Talla materna} + \\text{Talla paterna}) / 2 - 6.5."},{"front":"¿Cuál es el primer signo físico de la pubertad en las mujeres?","back":"El botón mamario (telarquia)."},{"front":"¿Cuánto tiempo después de la telarquia suele presentarse la menarquia?","back":"18 - 24 meses después."},{"front":"¿Cuál es el primer signo de pubertad en los hombres?","back":"Crecimiento del volumen testicular mayor a 4 mL."},{"front":"¿En qué estadio de Tanner se produce la máxima velocidad de crecimiento?","back":"Estadio III."},{"front":"¿A partir de qué edad se considera pubertad precoz en niñas?","back":"Antes de los 8 años de edad."},{"front":"¿A partir de qué edad se considera pubertad precoz en niños?","back":"Antes de los 9 años de edad."},{"front":"¿Qué es la telarquia precoz?","back":"Aumento uni o bilateral de la glándula mamaria sin otros signos de desarrollo puberal."},{"front":"¿Cómo se define la menarquia prematura aislada?","back":"Sangrado vaginal en niñas entre 1 y 9 años sin otros signos de desarrollo puberal."},{"front":"¿Qué marcador antropométrico es el mejor para determinar la edad gestacional?","back":"El perímetro cefálico."},{"front":"¿Cuál es el parámetro más importante para valorar el crecimiento de un niño?","back":"La velocidad de crecimiento."},{"front":"¿A qué proceso de adaptación fisiológica por baja ingesta calórica se le conoce como 'homeorrexis'?","back":"A la movilización y almacenamiento de energía para mantener funciones vitales."},{"front":"¿Qué clasificación distingue específicamente entre Marasmo y Kwashiorkor?","back":"La clasificación de Wellcome."},{"front":"¿Qué hormona es la encargada de inhibir la hormona del crecimiento?","back":"La somatostatina."},{"front":"¿Cada cuánto tiempo se debe registrar la talla en pacientes que reciben glucocorticoides sistémicos?","back":"Cada 4 - 6 meses."},{"front":"¿Para qué diagnóstico se utiliza específicamente la 'prueba de la galleta'?","back":"Para el diagnóstico de la lesión del plexo braquial."},{"front":"¿Qué déficit vitamínico produce dermatitis seborreica y anemia?","back":"Deficiencia de Vitamina B6 (Piridoxina)."},{"front":"¿Qué consecuencia tiene la deficiencia de Vitamina E?","back":"Distrofia muscular progresiva, abortos y atrofia testicular."},{"front":"En el contexto de talla baja, ¿qué sugiere una edad ósea avanzada?","back":"Pubertad precoz."},{"front":"En el contexto de talla baja, ¿qué sugieren enfermedades crónicas respecto a la edad ósea?","back":"Edad ósea disminuida."},{"front":"¿Qué dosis de Vitamina D2 se recomienda para el tratamiento del raquitismo?","back":"2000 UI por 3 meses."},{"front":"¿Qué factor de riesgo para obesidad se relaciona con un peso al nacer elevado?","back":"Productos macrosómicos."},{"front":"¿Cuál es el tratamiento inicial recomendado para la obesidad?","back":"Cambios en el estilo de vida (ejercicio 30 minutos, 10 de ellos intensos)."},{"front":"En el marasmo, ¿qué sucede con la piel del paciente?","back":"Se vuelve seca y pegadiza, pareciendo que 'retrata a los huesos'."},{"front":"¿Qué hallazgo cutáneo es clásico del Kwashiorkor?","back":"Descamación cutánea rojo-marrón y difusa (signo de esmalte descascarillado)."},{"front":"La suplementación diaria con _____ y _____ ha demostrado reducir la incidencia de desnutrición.","back":"Vitamina A; Zinc"},{"front":"El indicador de _____ utiliza el peso para la talla para valorar procesos agudos y talla para la edad para crónicos.","back":"Waterloo"}]},"12":{"num":12,"name":"TAMIZ METABOLICO","cards":[{"front":"¿En qué periodo de días después del nacimiento debe realizarse el tamiz metabólico neonatal?","back":"Entre el tercer y quinto día de vida."},{"front":"¿Cuántos días se debe esperar para realizar el tamiz si el recién nacido recibió una transfusión sanguínea?","back":"Se deben esperar 14 días."},{"front":"¿Cuál es la localización anatómica preferida para la toma de muestra del tamiz metabólico?","back":"En el talón del recién nacido."},{"front":"¿Cuál es el defecto más común causante de hipotiroidismo congénito primario?","back":"La disgenesia tiroidea, presente en el 85% de los casos."},{"front":"¿Cuál es la recomendación de la OMS para la ingesta diaria de yodo en mujeres embarazadas y en lactancia?","back":"200 \\mu g/día."},{"front":"Según la clasificación del hipotiroidismo congénito, ¿qué caracteriza a la ectopia tiroidea?","back":"Es tejido funcional fuera de su sitio habitual, siendo la sublingual la más frecuente."},{"front":"¿Cuál es la manifestación clínica más frecuente en el hipotiroidismo congénito?","back":"La hernia umbilical."},{"front":"¿Cuál es el segundo signo clínico más frecuente en el hipotiroidismo congénito?","back":"La ictericia."},{"front":"En el diagnóstico de hipotiroidismo congénito, ¿qué estudio es considerado el estándar de oro para establecer la variedad anatómica?","back":"El gamagrama con I^{123} o Tecnecio ^{99}."},{"front":"¿Cuál es el rango de dosis inicial de levotiroxina para el tratamiento del hipotiroidismo congénito?","back":"10-15 \\mu g/kg/día."},{"front":"¿Cuál es la meta de niveles de TSH al primer mes de tratamiento en hipotiroidismo congénito?","back":"Una TSH menor a 5 mU/ml."},{"front":"En el hipotiroidismo congénito, ¿qué hallazgo radiológico se conoce como el 'signo de rodilla vacía'?","back":"La ausencia del centro de osificación de la epífisis distal femoral."},{"front":"¿Cuál es la causa más común de retraso mental prevenible en el recién nacido?","back":"El hipotiroidismo congénito."},{"front":"¿Qué gen y en qué cromosoma se encuentra mutado en la fibrosis quística?","back":"El gen CFTR en el cromosoma 7."},{"front":"¿Cuál es el principal marcador detectado en el tamiz neonatal para la sospecha de fibrosis quística?","back":"El tripsinógeno inmunoreactivo (TIR)."},{"front":"¿Qué valor de cloro en sudor se considera confirmatorio para el diagnóstico de fibrosis quística?","back":"Un nivel mayor a 60 mmol/L en dos determinaciones."},{"front":"¿Cuál es la principal causa de muerte en pacientes con fibrosis quística?","back":"Las infecciones respiratorias."},{"front":"¿Qué microorganismo se asocia frecuentemente a infecciones pulmonares de repetición en fibrosis quística?","back":"Pseudomonas aeruginosa."},{"front":"¿Cuál es el tratamiento antibiótico de elección para infecciones por Pseudomonas en fibrosis quística?","back":"Ceftazidima más amikacina."},{"front":"¿Cuál es la deficiencia enzimática más común en la hiperplasia suprarrenal congénita?","back":"Deficiencia de la enzima 21-hidroxilasa."},{"front":"¿Qué sustrato se encuentra elevado en sangre y se utiliza para el tamiz de hiperplasia suprarrenal congénita?","back":"La 17-hidroxiprogesterona (17-OHP)."},{"front":"¿Qué niveles de 17-hidroxiprogesterona confirman el diagnóstico de hiperplasia suprarrenal congénita?","back":"Niveles mayores a 20 ng/mL."},{"front":"¿Cuáles son las dos formas clínicas principales de la hiperplasia suprarrenal congénita clásica?","back":"La perdedora de sal (67%) y la virilizante simple (33%)."},{"front":"¿Qué desequilibrio electrolítico caracteriza a la forma perdedora de sal en la hiperplasia suprarrenal congénita?","back":"Hiponatremia e hiperkalemia."},{"front":"¿Qué fármaco se utiliza para el mantenimiento electrolítico en pacientes con hiperplasia suprarrenal congénita perdedora de sal?","back":"Fludrocortisona."},{"front":"¿Cuál es la deficiencia enzimática en la galactosemia clásica (Tipo 1)?","back":"Deficiencia de galactosa-1-fosfatouridiltransferasa (GALT)."},{"front":"¿Cuál es el principal signo clínico observado en la galactosemia?","back":"La ictericia."},{"front":"¿Qué complicación ocular es característica de la galactosemia no tratada?","back":"Cataratas."},{"front":"¿Cuál es la contraindicación absoluta en la dieta de un recién nacido con galactosemia?","back":"La lactancia materna."},{"front":"¿Qué tipo de fórmula se debe utilizar en pacientes diagnosticados con galactosemia?","back":"Fórmula con base en proteína aislada de soya."},{"front":"¿Cuál es la deficiencia enzimática causal de la fenilcetonuria?","back":"Deficiencia de la enzima fenilalanina hidroxilasa."},{"front":"¿Qué olor característico presentan los pacientes con fenilcetonuria?","back":"Olor a humedad (ratón o paja mojada)."},{"front":"¿Qué características fenotípicas de hipopigmentación se asocian a la fenilcetonuria?","back":"Pelo rubio y ojos azules."},{"front":"¿Qué metabolito se puede encontrar en la orina de pacientes con fenilcetonuria?","back":"Fenilpiruvato."},{"front":"¿Qué vitamina es la biotina?","back":"Vitamina B7."},{"front":"¿Cuál es el tratamiento farmacológico para la deficiencia de biotinidasa?","back":"Biotina en dosis de 10 mg/día."},{"front":"¿Qué alimento debe evitarse en la deficiencia de biotinidasa por su alto nivel de avidina?","back":"La clara de huevo cruda."},{"front":"¿Cuál es el patrón de herencia de la enfermedad de Fabry?","back":"Herencia ligada al cromosoma X."},{"front":"¿Qué enzima se encuentra deficiente en la enfermedad de Fabry?","back":"La enzima \\alpha-galactosidasa A (A-GAL A)."},{"front":"¿Cuáles son las lesiones cutáneas características de la enfermedad de Fabry?","back":"Angioqueratomas (lesiones rojo-violáceas en región umbilical e ingle)."},{"front":"¿Cuál es la principal causa de muerte en pacientes con enfermedad de Fabry?","back":"La insuficiencia renal."},{"front":"¿En qué consiste el tratamiento específico para la enfermedad de Fabry?","back":"Terapia de reemplazo enzimático con agalsidasa alfa o beta."},{"front":"En el tamiz de hipotiroidismo, ¿qué conducta se sigue si la TSH se encuentra entre 10 y 20 mU/l?","back":"Se debe repetir el tamiz neonatal."},{"front":"¿Cuál es el objetivo de los niveles de T4 en el tratamiento del hipotiroidismo congénito?","back":"Mantener la T4 en la mitad superior de lo normal."},{"front":"¿Cuál es la dosis de levotiroxina recomendada para pacientes con atirosis?","back":"15 \\mu g/kg/día."},{"front":"¿Qué fármacos de consumo materno son factores de riesgo para hipotiroidismo congénito?","back":"Amiodarona, fenitoína, litio y aspirina (AAS)."},{"front":"¿Cuál es el principal factor pronóstico en un niño con hipotiroidismo congénito si el tratamiento inicia antes de los 28 días?","back":"La severidad de la enfermedad."},{"front":"¿Cuánto tiempo mínimo debe transcurrir entre la administración de levotiroxina y el consumo de fibra o soya?","back":"Como mínimo 2 horas."},{"front":"En fibrosis quística, ¿qué estudio se debe solicitar si los niveles de TIR están en rango dudoso (40-60)?","back":"Análisis del gen CFTR."},{"front":"¿A qué edad se debe iniciar la ablactación en pacientes con fenilcetonuria?","back":"A los 6 meses de edad."},{"front":"Concepto: Acroparestesias en enfermedad de Fabry.","back":"Definición: Dolor neuropático crónico en extremidades que empeora con el ejercicio o calor."},{"front":"¿Qué hallazgo oftalmológico se detecta con lámpara de hendidura en la enfermedad de Fabry?","back":"Opacidades corneales (cornea verticillata)."},{"front":"¿Cuál es el método de diagnóstico definitivo para galactosemia?","back":"Medición de GALT y GALT-1P en plasma por reacción enzimática."},{"front":"En el hipotiroidismo, ¿qué caracteriza al hipotiroidismo secundario?","back":"Una deficiencia a nivel hipofisario donde no se libera TSH."},{"front":"¿Cuál es la causa más común de elevación de TSH en pacientes ya diagnosticados y en tratamiento?","back":"La no adherencia al tratamiento."},{"front":"¿Cuál es la incidencia de hipotiroidismo congénito por cada 10,000 recién nacidos vivos?","back":"4.12 casos."},{"front":"¿Qué complicación gastrointestinal neonatal sugiere el diagnóstico de fibrosis quística?","back":"Íleo meconial."},{"front":"La tríada de hiponatremia, hiperkalemia y deshidratación en un neonato con genitales ambiguos sugiere _____.","back":"Hiperplasia suprarrenal congénita perdedora de sal."},{"front":"¿Cuál es el objetivo primordial del tamiz para hiperplasia suprarrenal congénita?","back":"Prevenir crisis adrenales y asignaciones sexuales erróneas."},{"front":"¿Qué tipo de herencia presentan todas las patologías del tamiz metabólico excepto el hipotiroidismo?","back":"Herencia autosómica recesiva."},{"front":"¿Qué porcentaje de los casos de hipotiroidismo congénito primario son permanentes debido a disgenesia?","back":"85%."},{"front":"¿Cuál es el requerimiento diario de yodo para niños de 6 a 12 años?","back":"120 \\mu g/día."},{"front":"¿A qué edad gestacional de la madre aumenta el riesgo de hipotiroidismo congénito?","back":"Menores de 16 años y mayores de 38 años."},{"front":"¿Qué cardiopatías se asocian frecuentemente al hipotiroidismo congénito?","back":"Persistencia del conducto arterioso (PCA) y comunicación interauricular (CIA)."},{"front":"¿Cuál es el síntoma inmunológico característico de la deficiencia de biotinidasa?","back":"Infecciones recurrentes."}]},"13":{"num":13,"name":"PATOLOGIA DIGESTIVA","cards":[{"front":"¿Cuál es el mecanismo fisiopatológico del Reflujo Gastroesofágico (RGE) funcional?","back":"Se debe a una relajación transitoria del esfínter esofágico inferior."},{"front":"¿Cuál es la tríada de síntomas característicos del RGE funcional?","back":"Regurgitación, irritabilidad y, ocasionalmente, vómito."},{"front":"En el RGE funcional, los pacientes presentan regurgitación sin presentar falla de medro ni _____.","back":"manifestaciones extraesofágicas"},{"front":"¿A qué edad se presenta el pico máximo de incidencia del reflujo fisiológico en lactantes?","back":"A los 4 meses de edad."},{"front":"¿En qué porcentaje se soluciona el reflujo fisiológico al año de vida?","back":"En el 90% de los casos."},{"front":"Definición clínica de RGE: Dos o más episodios de regurgitación al día por al menos _____.","back":"3 semanas"},{"front":"¿Cuál es la manifestación clínica más común de la Enfermedad por Reflujo Gastroesofágico (ERGE)?","back":"La regurgitación."},{"front":"¿Qué nombre recibe la extensión del cuello como síntoma sistémico de la ERGE?","back":"Síndrome de Sandifer."},{"front":"Enumere tres síntomas respiratorios asociados a la ERGE pediátrica.","back":"Apnea, sibilancias y tos crónica."},{"front":"¿Cuál es el estándar de oro (gold-standard) para el diagnóstico de ERGE?","back":"La pH-metría."},{"front":"¿En qué situación se indica realizar una Serie Esofagogastroduodenal (SEGD) en sospecha de ERGE?","back":"Cuando se sospechan alteraciones anatómicas del tubo digestivo alto."},{"front":"¿Cuál es la medida postural recomendada para el tratamiento del reflujo funcional?","back":"Decúbito lateral izquierdo."},{"front":"Para el reflujo funcional, ¿con qué sustancia se recomienda espesar las fórmulas lácteas?","back":"Con agua de cereal de arroz."},{"front":"¿Cuál es la posición recomendada para lactantes con ERGE para evitar la muerte súbita del lactante?","back":"Decúbito supino."},{"front":"¿Cuánto tiempo dura la prueba terapéutica inicial con inhibidores de la bomba de protones (IBP) en ERGE?","back":"De 2 a 4 semanas."},{"front":"Si los síntomas de ERGE mejoran tras la prueba con IBP, ¿por cuánto tiempo total se debe mantener el tratamiento?","back":"Por 3 meses."},{"front":"¿Qué fármaco para el manejo de ERGE está contraindicado por el riesgo de causar trombocitopenia?","back":"La ranitidina."},{"front":"¿Cuál es el procedimiento quirúrgico de elección para el tratamiento de la ERGE refractaria?","back":"Funduplicatura de Nissen."},{"front":"Definición de Invaginación Intestinal:","back":"Es la introducción de una asa proximal de intestino dentro de un segmento distal."},{"front":"¿Cuál es la causa más frecuente de obstrucción intestinal en pacientes de 3 meses a 6 años?","back":"La invaginación intestinal."},{"front":"¿Qué infección previa se asocia comúnmente con la aparición de invaginación intestinal?","back":"Gastroenteritis viral."},{"front":"¿Cuál es la localización anatómica más común de la invaginación intestinal?","back":"La zona ileocólica."},{"front":"Mencione los tres elementos de la tríada clásica de la invaginación intestinal.","back":"Tumor palpable, vómitos y evacuaciones en jalea de grosella."},{"front":"¿Cómo se describe el signo de la 'morcilla o salchicha' en la invaginación intestinal?","back":"Como una masa palpable en el hipocondrio derecho."},{"front":"¿En qué consiste el signo de Dance en la exploración abdominal de una invaginación?","back":"En la percepción de un vacío en la fosa ilíaca derecha."},{"front":"¿Cuál es el estudio de imagen inicial y de elección para diagnosticar invaginación intestinal?","back":"Ultrasonido abdominal."},{"front":"¿Qué hallazgo ultrasonográfico es característico de la invaginación intestinal?","back":"El signo de la diana."},{"front":"¿Cuál es el tratamiento de elección no quirúrgico para la invaginación intestinal?","back":"Hidroenema (o enema neumático)."},{"front":"¿En qué caso se indica tratamiento quirúrgico inmediato para la invaginación intestinal?","back":"Si han transcurrido más de 48 horas desde el inicio del cuadro clínico."},{"front":"El Divertículo de Meckel es un remanente del conducto embrionario _____.","back":"vitelino (u onfalomesentérico)"},{"front":"¿Cuál es la anomalía congénita más frecuente del tubo digestivo?","back":"Divertículo de Meckel."},{"front":"Según la 'Regla de los 2', ¿a qué distancia de la válvula ileocecal se localiza el Divertículo de Meckel?","back":"A 2 pies (60\\text{ cm})."},{"front":"¿Qué tipo de tejidos ectópicos puede contener el Divertículo de Meckel?","back":"Tejido gástrico o pancreático."},{"front":"¿Cuál es la manifestación clínica más común del Divertículo de Meckel en lactantes?","back":"Rectorragia (sangrado gastrointestinal) asintomática."},{"front":"¿Cuál es el estudio diagnóstico confirmatorio para el Divertículo de Meckel?","back":"Gammagrafía con Tecnecio 99."},{"front":"¿Cuál es el estándar de oro para el diagnóstico del Divertículo de Meckel?","back":"Laparoscopía."},{"front":"¿Cuál es el tratamiento definitivo para el Divertículo de Meckel?","back":"Resección quirúrgica del divertículo con anastomosis término-terminal."},{"front":"¿Cuál es la causa más frecuente de obstrucción intestinal inferior en el neonato?","back":"Enfermedad de Hirschsprung."},{"front":"¿Cuál es el defecto histológico básico en la Enfermedad de Hirschsprung?","back":"Ausencia de células ganglionares (agangliosis) en el plexo mientérico."},{"front":"¿Qué zona del colon se ve afectada con mayor frecuencia en la Enfermedad de Hirschsprung?","back":"El recto-sigmoides."},{"front":"Mencione la tríada clásica de la Enfermedad de Hirschsprung en neonatos.","back":"Distensión abdominal, ausencia de meconio en 24-48 horas y vómito bilioso."},{"front":"¿Cuál es el estándar de oro para diagnosticar la Enfermedad de Hirschsprung?","back":"Biopsia rectal (que demuestra ausencia de células ganglionares)."},{"front":"¿Cuál es la principal complicación de la Enfermedad de Hirschsprung?","back":"Sobrecrecimiento bacteriano (enterocolitis)."},{"front":"¿Qué malformación cromosómica se asocia frecuentemente con la Enfermedad de Hirschsprung?","back":"Síndrome de Down."},{"front":"Para diagnosticar estreñimiento funcional en menores de 4 años, ¿cuántas defecaciones por semana definen el criterio?","back":"Menos de 2 defecaciones por semana."},{"front":"¿Qué criterios se utilizan para el diagnóstico del estreñimiento funcional pediátrico?","back":"Criterios de Roma IV."},{"front":"¿Cuál es el tratamiento farmacológico inicial para la desimpactación en el estreñimiento funcional?","back":"Polietilenglicol (PEG) por 2 a 7 días."},{"front":"¿Cuál es la ingesta diaria recomendada de fibra para el mantenimiento en estreñimiento funcional?","back":"De 5 a 30 gramos al día."},{"front":"¿Cuál es el diagnóstico de la inflamación de los ganglios linfáticos mesentéricos en pacientes de 3 a 15 años?","back":"Adenitis mesentérica."},{"front":"¿Cuál es la segunda causa más frecuente de dolor en la fosa ilíaca derecha en pediatría?","back":"Adenitis mesentérica."},{"front":"¿Qué antecedente infeccioso suele preceder al cuadro de adenitis mesentérica?","back":"Infección respiratoria."},{"front":"¿Qué hallazgo se observa en el ultrasonido abdominal en casos de adenitis mesentérica?","back":"Nódulos mesentéricos hipoecoicos con apéndice normal."},{"front":"¿Cuál es la principal complicación de la adenitis mesentérica?","back":"Necrosis de los ganglios linfáticos."}]},"14":{"num":14,"name":"VACUNAS","cards":[{"front":"¿Cuál es el objetivo de cobertura de vacunación para la población general en México para el año 2025?","back":"Mantener vacunada al 95% de la población."},{"front":"¿Qué porcentaje de vacunación con esquema completo se busca alcanzar en menores de un año para 2025?","back":"Alcanzar el 90% de vacunación."},{"front":"¿En qué año se consolidó el Programa de Vacunación Universal en México?","back":"En 1991."},{"front":"Las vacunas donde los agentes pierden su patogenicidad pero se pueden seguir replicando se denominan vacunas _____.","back":"Vivas atenuadas"},{"front":"¿Qué componente de las vacunas inactivas o muertas es el encargado de generar inmunidad?","back":"El epítopo."},{"front":"¿Cuál es el tiempo máximo de uso de un frasco multidosis de vacuna viva atenuada una vez abierto?","back":"Hasta 6 horas."},{"front":"¿Cuánto tiempo puede durar abierto un frasco de la cepa Tokio para la vacuna BCG?","back":"Máximo 4 horas."},{"front":"Los frascos multidosis de vacunas inactivadas pueden usarse hasta _____ días después de abiertos si se conservan adecuadamente.","back":"28 días"},{"front":"¿Cuál es el rango de temperatura estándar para la refrigeración de vacunas?","back":"+2^{\\circ}C a +8^{\\circ}C."},{"front":"¿A qué temperatura se deben encontrar las vacunas congeladas (como la de Varicela)?","back":"-18^{\\circ}C a -25^{\\circ}C."},{"front":"¿Cuál es el rango de temperatura para la ultracongelación de vacunas?","back":"-60^{\\circ}C a -90^{\\circ}C."},{"front":"¿Qué distancia debe existir entre dos sitios de vacunación cuando las aplicaciones son simultáneas en la misma zona?","back":"De 2.5 cm a 5 cm."},{"front":"¿Cuánto tiempo debe estar abierto, como máximo, un frasco de vacuna liofilizada?","back":"6 horas."},{"front":"¿Qué intervalo de tiempo se debe esperar entre la administración de dos vacunas vivas atenuadas?","back":"4 semanas."},{"front":"¿Qué tipo de agente biológico contiene la vacuna BCG?","back":"Bacterias vivas atenuadas (Mycobacterium bovis)."},{"front":"¿Contra qué formas graves de tuberculosis protege principalmente la vacuna BCG?","back":"Miliar y meníngea."},{"front":"¿Cuál es la dosis y vía de administración de la vacuna BCG?","back":"0.1 ml por vía intradérmica."},{"front":"¿En qué sitio anatómico se aplica específicamente la vacuna BCG?","back":"Región deltoidea del brazo derecho."},{"front":"¿Cuál es la contraindicación de peso para la aplicación de BCG en un recién nacido?","back":"Peso menor a 2 kg."},{"front":"¿Bajo qué condición de CD4 se puede aplicar la BCG en pacientes con VIH?","back":"Con un conteo de CD4 mayor a 25%."},{"front":"El crecimiento de un ganglio ipsilateral tras la aplicación de BCG se conoce como _____.","back":"BCGitis"},{"front":"¿Cuál es el tratamiento para casos graves de BCGosis diseminada?","back":"Esquema RIPE (Rifampicina, Isoniazida, Pirazinamida, Etambutol)."},{"front":"¿Cuál es el orden cronológico de la evolución de la cicatriz de BCG?","back":"Pápula, mácula, nódulo, úlcera, costra y cicatriz."},{"front":"¿Qué antígeno compone la vacuna contra la Hepatitis B?","back":"Antígeno de superficie (AgSHB) recombinante."},{"front":"¿Cuál es el tiempo ideal para aplicar la dosis de nacimiento de Hepatitis B?","back":"En las primeras 24 horas de vida."},{"front":"¿En qué sitio anatómico se aplica la vacuna de Hepatitis B en recién nacidos?","back":"Muslo izquierdo (intramuscular)."},{"front":"¿Qué sustancia en la vacuna de Hepatitis B es la principal causa de contraindicación por alergia?","back":"Timerosal (mercurio)."},{"front":"¿Qué acción se debe tomar si el recién nacido pesa < 2000 g y la madre tiene AgSHB positivo?","back":"Aplicar vacuna más inmunoglobulina específica."},{"front":"¿A partir de qué nivel de anticuerpos anti-HBs se considera protegido a un paciente?","back":"> 10 mUI/mL."},{"front":"¿Qué componentes integran la vacuna Hexavalente acelular?","back":"H. influenzae B, Difteria, Tos ferina, Tétanos, Poliomielitis y Hepatitis B."},{"front":"¿Cuál es el esquema de vacunación para la vacuna Hexavalente?","back":"A los 2, 4, 6 y 18 meses de edad."},{"front":"¿En qué sitio se aplica la vacuna Hexavalente en menores de 18 meses?","back":"Muslo derecho (intramuscular)."},{"front":"¿Cuál es el intervalo de tiempo que debe esperar para vacunarse con Hexavalente un paciente que recibió inmunoglobulina?","back":"3 meses."},{"front":"¿Qué tipo de vacuna es la Anti-rotavirus?","back":"Virus vivos atenuados."},{"front":"¿Cuál es el esquema de la vacuna monovalent de Rotavirus?","back":"2 dosis: a los 2 y 4 meses."},{"front":"¿Cuál es el esquema de la vacuna pentavalente de Rotavirus?","back":"3 dosis: a los 2, 4 y 6 meses."},{"front":"¿Cuál es la edad máxima permitida para aplicar la última dosis de la vacuna contra Rotavirus?","back":"8 meses."},{"front":"Una contraindicación específica de la vacuna de Rotavirus es el antecedente de _____ intestinal.","back":"Intususcepción"},{"front":"¿Cuál es el esquema de la vacuna Neumocócica Conjugada (PCV13) en niños?","back":"3 dosis: a los 2, 4 y 12 meses."},{"front":"¿A qué edad se inicia la vacunación neumocócica en adultos sin factores de riesgo?","back":"A partir de los 60 años."},{"front":"¿Cuál es el esquema inicial de la vacuna Anti-influenza en niños?","back":"2 dosis: a los 6 y 7 meses de edad."},{"front":"¿Cuál es la principal contraindicación de la vacuna contra Influenza debido a su proceso de producción?","back":"Hipersensibilidad grave al huevo."},{"front":"¿En qué periodo estacional se aplica típicamente la vacuna contra la Influenza?","back":"Octubre a Marzo."},{"front":"¿Qué enfermedades previene la vacuna SRP?","back":"Sarampión, Rubéola y Parotiditis."},{"front":"¿Cuál es la vía y ángulo de aplicación de la vacuna SRP?","back":"Subcutánea a 45 grados."},{"front":"¿Cuál es el esquema de SRP para niños nacidos a partir de julio de 2020?","back":"A los 12 y 18 meses de edad."},{"front":"¿Qué efecto adverso articular se asocia específicamente al componente de Rubéola de la SRP?","back":"Artritis."},{"front":"¿A qué edad se aplica el refuerzo de la vacuna DPT?","back":"A los 4 años de edad."},{"front":"¿Cuál es el límite de edad superior para aplicar la vacuna DPT?","back":"Menores de 7 años (6 años 11 meses)."},{"front":"¿Qué componente de la vacuna DPT se asocia frecuentemente con el riesgo de encefalopatía?","back":"Pertussis (tos ferina)."},{"front":"¿Cada cuánto tiempo se recomienda el refuerzo de la vacuna Td en adultos con esquema completo?","back":"Cada 10 años."},{"front":"¿Cuál es la conducta ante una herida sucia en un paciente con esquema de Td desconocido?","back":"Vacunar y aplicar inmunoglobulina antitetánica."},{"front":"¿Cuál es la dosis de inmunoglobulina antitetánica recomendada para niños?","back":"250 UI."},{"front":"¿Qué población masculina se incluyó recientemente (actualización 2026) para recibir la vacuna VPH?","back":"Niños de 5to grado de primaria o 11 años no escolarizados."},{"front":"¿En qué periodo del embarazo se prefiere administrar la vacuna Tdpa?","back":"Entre las semanas 27 a 36 de gestación."},{"front":"¿Cuál es la vía de administración de la vacuna Sabin (Polio oral)?","back":"Vía oral."},{"front":"¿A qué edad se aplica la dosis única de la vacuna Anti-hepatitis A según la actualización 2026?","back":"A los 18 meses de edad."},{"front":"¿Cuál es la vía de administración de la vacuna contra la Varicela?","back":"Subcutánea."},{"front":"¿Qué medicamento se debe evitar durante las 6 semanas posteriores a la vacunación contra Varicela?","back":"Salicilatos (Aspirina)."},{"front":"¿Cuál es el tiempo de espera recomendado para buscar un embarazo después de recibir la vacuna contra Varicela?","back":"3 meses."},{"front":"¿En qué periodo de la gestación se incorpora la inmunización contra VSR para proteger al lactante?","back":"Entre las semanas 32 a 36 de gestación."},{"front":"¿Cuál es el plazo para notificar un ESAVI no grave?","back":"Hasta 48 horas posteriores a su detección."},{"front":"¿En cuánto tiempo se debe reportar un ESAVI grave?","back":"De forma inmediata (primeras 24 horas)."},{"front":"¿Cuál es el volumen estándar de la mayoría de las jeringas utilizadas para vacunar?","back":"0.5 ml."},{"front":"¿Cuál es el esquema de vacunación contra COVID-19 para adultos \\ge 60 años?","back":"Una sola dosis cada 12 meses después de la última dosis."},{"front":"¿Qué vacuna se asocia con el riesgo de Síndrome de Guillain-Barré como efecto adverso?","back":"Influenza (o Td)."}]},"15":{"num":15,"name":"DIARREA AGUDA Y CRONICA","cards":[{"front":"¿Cómo se define operacionalmente la diarrea aguda?","back":"Aumento súbito en la emisión de heces (más de tres en 24 horas) y disminución de su consistencia."},{"front":"¿Cuál es la duración máxima habitual de un cuadro de diarrea aguda para no considerarse persistente?","back":"14 días."},{"front":"En lactantes, ¿cuáles son los dos parámetros principales para guiar el diagnóstico de diarrea?","back":"La disminución de la consistencia de las evacuaciones y la presencia de vómito."},{"front":"¿Qué proceso fisiopatológico explica la disminución de la consistencia de las heces en la diarrea?","back":"Inhibición en la absorción por los enterocitos."},{"front":"¿A qué se debe el aumento en la cantidad de evacuaciones durante una reacción inflamatoria intestinal?","back":"Hipercreción digestiva y exudación."},{"front":"Según la OMS, ¿cuáles son los tres tipos clínicos de enfermedades diarreicas?","back":"Diarrea acuosa, diarrea disentérica y diarrea persistente."},{"front":"¿Cuál es la duración promedio de la diarrea acuosa?","back":"De uno a tres días."},{"front":"¿Qué microorganismos son los principales implicados en la diarrea acuosa?","back":"Vibrio cholerae, Escherichia coli enterotoxigénica, Rotavirus y Norovirus."},{"front":"¿Cuál es el signo clínico cardinal de la diarrea disentérica?","back":"Presencia de sangre en las heces."},{"front":"¿Cuál es la fisiopatología de la diarrea disentérica a nivel del colon?","back":"Inflamación e invasión de los enterocitos."},{"front":"¿Qué microorganismos se asocian principalmente a la diarrea disentérica?","back":"Shigella spp, Escherichia coli enteroinvasiva (ECEI) y Entamoeba histolytica."},{"front":"¿Qué rango de tiempo define a la diarrea persistente?","back":"Más de dos semanas pero menos de cuatro."},{"front":"¿Cuál es la causa infecciosa más frecuente de la diarrea persistente?","back":"Parasitosis."},{"front":"¿Cuál es la segunda causa de muerte en menores de 5 años a nivel mundial?","back":"Infecciones intestinales (enfermedades diarreicas)."},{"front":"¿En qué estación del año predominan los agentes bacterianos causantes de diarrea en México?","back":"Finales de primavera y verano."},{"front":"El _____ es responsable del 80% de los casos de diarrea viral en niños de 3 a 5 años.","back":"Rotavirus"},{"front":"¿Cuál es la medida preventiva de mayor impacto para reducir la morbimortalidad por diarrea?","back":"Lactancia materna."},{"front":"¿Cuántas veces disminuye el riesgo de diarrea aguda la estrategia de lavado de manos?","back":"2.3 veces."},{"front":"¿Cuál se considera la \"primera vacuna natural\" del niño para evitar muertes por diarrea?","back":"Lactancia materna."},{"front":"¿Qué intervención de prevención específica protege contra la diarrea grave y hospitalización en infantes?","back":"Vacuna contra el Rotavirus."},{"front":"¿Cuál es el método recomendado por la GPC para evaluar y clasificar la deshidratación?","back":"Método Dhaka."},{"front":"¿Cuál es el estándar de oro (gold standard) para evaluar el grado de deshidratación?","back":"Pérdida de peso del paciente."},{"front":"¿Qué porcentaje de pérdida de peso define una deshidratación grave?","back":"Mayor al 9%."},{"front":"¿Qué puntaje en la Escala de Evaluación Clínica (ECD) indica deshidratación moderada a grave?","back":"De 5 a 8 puntos."},{"front":"¿Qué característica del pulso radial se observa en un paciente adulto con deshidratación grave (Plan C)?","back":"Ausente o incontable."},{"front":"En el Método Dhaka, ¿qué característica del llenado capilar indica choque hipovolémico?","back":"Mayor a 2 segundos."},{"front":"¿Cuándo se deben solicitar estudios de laboratorio auxiliares en diarrea aguda?","back":"Sospecha de alteraciones hidroelectrolíticas, desnutrición grave o fracaso en la terapia de rehidratación."},{"front":"¿Cuál es la osmolaridad total del Vida Suero Oral (VSO) recomendado por la OMS (2002)?","back":"245 mOsm/L (hipoosmolar)."},{"front":"Concepto: Racecadotrilo","back":"Inhibidor de la encefalinasa que reduce la secreción intestinal de agua y electrolitos."},{"front":"¿Cuál es la dosis recomendada de Racecadotrilo en pediatría?","back":"1.5 mg/kg, tres veces al día."},{"front":"¿Qué suplemento ha demostrado reducir la duración de la diarrea?","back":"Zinc (suplementación de 5-10 mg/día)."},{"front":"¿Qué medicamento antiemético puede administrarse en dosis única para mejorar la tolerancia a la rehidratación oral?","back":"Ondansetrón."},{"front":"Mencione dos criterios clínicos para el uso de antibióticos en diarrea aguda.","back":"Disentería y fiebre mayor a 39^{\\circ}C con datos de sepsis."},{"front":"¿A partir de qué edad se considera un criterio de hospitalización la diarrea aguda por riesgo de deshidratación rápida?","back":"Menores de 6 meses."},{"front":"¿Qué cantidad de evacuaciones en 24 horas es criterio de hospitalización?","back":"Más de 8 evacuaciones."},{"front":"¿En qué consiste el Plan A de rehidratación (Regla ABC)?","back":"Alimentación habitual, Bebidas abundantes/VSO y Consulta oportuna (datos de alarma)."},{"front":"En el Plan A, ¿qué dosis de VSO se da tras cada evacuación a menores de un año?","back":"75 ml (media taza)."},{"front":"En el Plan A, ¿qué dosis de VSO se da tras cada evacuación a mayores de un año?","back":"150 ml (una taza)."},{"front":"¿Cuál es el volumen de VSO a administrar en el Plan B si se conoce el peso del paciente?","back":"50-100 ml/kg en 4 horas, fraccionados cada 30 minutos."},{"front":"En el Plan B pediátrico, si no se conoce el peso, ¿cuánto VSO se da a un niño de 2 a 5 años?","back":"800 a 1400 ml."},{"front":"¿Cuál es el esquema de hidratación parenteral (Plan C) en la primera hora para pediatría?","back":"50 ml/kg."},{"front":"¿Qué solución intravenosa se prefiere para el Plan C de rehidratación?","back":"Solución salina al 0.9% o Ringer Lactato."},{"front":"En adultos con deshidratación leve-moderada, ¿qué volumen de VSO se recomienda en las primeras 4 horas?","back":"2200 a 4000 ml."},{"front":"¿Cuál es el agente principal de diarrea grave en la infancia según los puntos ENARM?","back":"Rotavirus."},{"front":"En Planes A y B, ante intolerancia a la vía oral, ¿qué alternativa se debe preferir antes que la vía IV?","back":"Sonda nasogástrica."},{"front":"¿Qué microorganismo se asocia clásicamente al consumo de pollo mal cocido?","back":"Campylobacter."},{"front":"¿Con qué animal se asocia frecuentemente la transmisión de Salmonella?","back":"Tortugas."},{"front":"¿Por qué no se deben administrar bebidas carbonatadas en pacientes con diarrea?","back":"Están contraindicadas (pueden aumentar la carga osmótica)."},{"front":"¿Qué factores aumentan el riesgo de muerte por diarrea en pediatría?","back":"Edad menor de 3 años, edema en miembros inferiores, sexo femenino y diarrea invasora."},{"front":"En casos de desnutrición severa, ¿cuál es la solución de rehidratación oral de elección?","back":"ReSoMal."},{"front":"¿Cuál es la principal complicación de la infección por Salmonella?","back":"Sangrado gastrointestinal."},{"front":"¿En qué pacientes se recomiendan los probióticos según los puntos de adultos?","back":"Únicamente en diarrea asociada al uso de antimicrobianos."},{"front":"¿Qué efecto puede tener la Loperamida en pacientes con diarrea sanguinolenta e inflamatoria?","back":"Prolongación de la enfermedad."},{"front":"¿Cuáles son las causas principales de intoxicación alimentaria mencionadas en el texto?","back":"S. aureus (ensaladas, mayonesas) y Bacillus cereus (arroz frito)."},{"front":"¿Qué vacuna se recomienda aplicar en epidemias de fiebre tifoidea a personas de 2 a 19 años?","back":"Vacuna ViPCS."},{"front":"Si un paciente pediátrico tiene 1-4 puntos en la ECD, ¿qué grado de deshidratación presenta?","back":"Deshidratación leve."},{"front":"¿Bajo qué condiciones se debe sospechar de Shigella?","back":"Cuando exista la presencia de pus en las heces."},{"front":"En el Plan C para adultos, ¿cuál es el volumen total de líquidos recomendado para las primeras 24 horas?","back":"200 ml/kg."},{"front":"¿Qué fármaco se menciona que puede reducir el número de evacuaciones, aunque su beneficio es modesto?","back":"Subsalicilato de bismuto."},{"front":"¿Cuál es el objetivo del tratamiento de mantenimiento tras la rehidratación inicial?","back":"Reemplazar las pérdidas hasta que disminuya la diarrea o el vómito."},{"front":"¿Qué signo en los ojos sugiere deshidratación moderada (Plan B)?","back":"Ojos hundidos y sin lágrimas."},{"front":"¿Cuál es la conducta a seguir si un niño no mejora tras dos horas adicionales en Plan B?","back":"Trasladar al siguiente nivel de atención."},{"front":"En pacientes desnutridos, ¿por qué se prefiere el ReSoMal sobre el VSO estándar?","back":"Tiene menor contenido de sodio y mayor aporte de potasio y glucosa."},{"front":"¿Cuál es el componente del tratamiento coadyuvante que reduce la severidad de la diarrea?","back":"Probióticos (Saccharomyces boulardii) y consumo de plátano verde cocido."},{"front":"¿Qué factor materno aumenta el riesgo de hospitalización del niño por diarrea?","back":"Embarazo adolescente (madre menor de 18 años)."},{"front":"En la diarrea persistente, ¿a qué entidad rara de herencia autosómica recesiva se puede asociar?","back":"Intolerancia a la lactosa congénita."},{"front":"¿Qué manejo se sugiere para niños con dolor abdominal recurrente por estrés que presentan diarrea?","back":"Apoyo psicológico."},{"front":"¿Cuándo se considera que un paciente está listo para el alta tras observación en Plan B?","back":"Cuando tolera el VSO por dos horas."},{"front":"¿Qué porcentaje de muertes atribuibles a infecciones intestinales en menores de 5 años ocurrió en 2022?","back":"Dos millones de muertes."},{"front":"Diarrea en el adulto: ¿en qué tiempo se debe realizar la revaloración tras iniciar tratamiento sintomático?","back":"En 48 horas."}]},"16":{"num":16,"name":"PARASITOSIS","cards":[{"front":"¿Cuál es el protozoo entérico más frecuente en el ser humano y los animales domésticos?","back":"Giardia lamblia"},{"front":"¿Cuál es la cantidad mínima de quistes de Giardia lamblia necesarios para causar una infección?","back":"10 quistes"},{"front":"¿Cuál es el síntoma más frecuente en un paciente con giardiasis?","back":"Dolor abdominal"},{"front":"En la giardiasis crónica, ¿a qué síndrome clínico se asocian frecuentemente los cuadros enterales?","back":"Síndrome de malabsorción intestinal"},{"front":"¿Qué deficiencias vitamínicas son características en la infección por Giardia lamblia?","back":"Vitaminas A, D, E y K"},{"front":"¿Cuál es el estudio diagnóstico de elección para identificar Giardia lamblia?","back":"Coproparasitoscópico en serie de 3"},{"front":"¿Qué estudio diagnóstico se debe realizar en giardiasis si el coproparasitoscópico resulta negativo?","back":"Antígeno fecal"},{"front":"¿Cuál es el tratamiento de primera elección para la giardiasis?","back":"Metronidazol"},{"front":"¿Qué complicación visual específica se puede presentar en niños con giardiasis?","back":"Lesión en retina \"en sal y pimienta\""},{"front":"¿Qué condición secundaria debe vigilarse durante 2 a 3 semanas después del tratamiento de la giardiasis?","back":"Intolerancia a la lactosa"},{"front":"En el contexto de la amebiasis, ¿cuál es la forma infectante del parásito?","back":"Quiste"},{"front":"En el ciclo de Entamoeba histolytica, ¿cuál es la forma invasora?","back":"Trofozoíto"},{"front":"¿Cuál es la segunda causa de muerte por enfermedad parasitaria en el mundo?","back":"Amebiasis"},{"front":"¿Qué mediador inmunológico hace que la población mexicana sea más susceptible al absceso hepático amebiano?","back":"HLA-DR3"},{"front":"¿Cómo se denominan los tumores en el ciego producidos por Entamoeba histolytica?","back":"Amebomas"},{"front":"¿Cuál es el estándar de oro para el diagnóstico de amebiasis?","back":"PCR (Reacción en Cadena de la Polimerasa)"},{"front":"¿Qué tipo de fármaco se debe administrar en pacientes portadores asintomáticos de Entamoeba histolytica?","back":"Amebicida luminal"},{"front":"¿Cuál es el helminto que causa la infección más frecuente a nivel mundial?","back":"Ascaris lumbricoides"},{"front":"En la ascariasis, ¿en qué órgano se albergan las larvas antes de ser deglutidas hacia la bucofaringe?","back":"Alvéolos pulmonares"},{"front":"¿Qué síndrome se caracteriza por neumonitis con eosinofilia progresiva tras la ingesta de huevos de Ascaris?","back":"Síndrome de Löffler"},{"front":"¿Cuál es el hallazgo radiológico típico en el Síndrome de Löffler?","back":"Infiltrados alveolares bilaterales migratorios"},{"front":"¿Cuál es el tratamiento de elección para Ascaris lumbricoides?","back":"Albendazol"},{"front":"¿Qué fármaco es la opción de tratamiento para ascariasis en pacientes embarazadas?","back":"Pamoato de pirantel"},{"front":"¿Cuál es el hospedero intermediario de Taenia solium?","back":"El cerdo"},{"front":"¿Cuál es el hospedero intermediario de Taenia saginata?","back":"El ganado vacuno"},{"front":"¿Qué estructura parasitaria aparece en las heces permitiendo el diagnóstico de teniasis?","back":"Proglótides"},{"front":"¿Cómo se adquiere específicamente la cisticercosis por Taenia solium?","back":"Ingesta de huevos en heces humanas"},{"front":"¿Cuál es el principal estado de México afectado por la cisticercosis según el material?","back":"Sonora"},{"front":"¿Qué hallazgo es característico en la TAC de un paciente con neurocisticercosis?","back":"Lesiones con realce de contraste en anillo"},{"front":"¿Cuál es el esquema de tratamiento farmacológico para la neurocisticercosis?","back":"Albendazol por 7 a 14 días"},{"front":"¿Para qué se utilizan los esteroides en el tratamiento de la neurocisticercosis?","back":"Para evitar crisis convulsivas por la respuesta inflamatoria."},{"front":"¿Cuál es el síntoma clínico patognomónico de la enterobiasis (oxiuriasis)?","back":"Prurito de predominio vespertino o nocturno en región perianal"},{"front":"¿En qué consiste el Test de Graham para el diagnóstico de Enterobius vermicularis?","back":"Uso de cinta de celofán en la región perianal antes de levantarse."},{"front":"¿Qué hábito común en niños es un factor de riesgo para la oxiuriasis?","back":"Succión del pulgar"},{"front":"¿Cuál es el vector transmisor de Wuchereria bancrofti?","back":"Mosquito Culex quinquefasciatus"},{"front":"¿En qué horario es máxima la concentración sanguínea de microfilarias de Wuchereria bancrofti?","back":"De 10 PM a 2 AM"},{"front":"¿Qué manifestación crónica grave produce la obstrucción linfática por filariasis?","back":"Elefantiasis"},{"front":"¿Cuál es el mecanismo de transmisión de Strongyloides stercoralis?","back":"Penetración de larvas filariformes a través de la piel."},{"front":"¿Cómo se describe la lesión cutánea característica de la estrongiloidosis?","back":"Infección serpiginosa con migración rápida"},{"front":"¿Cuál es el método diagnóstico más sensible para Strongyloides stercoralis?","back":"Siembra de heces en placa de agar"},{"front":"¿Cuál es el tratamiento de elección para la estrongiloidosis?","back":"Ivermectina"},{"front":"¿Cuál es el céstodo más frecuente y de menor tamaño que infecta al ser humano?","back":"Hymenolepis nana"},{"front":"¿Qué animal actúa frecuentemente como reservorio de Hymenolepis nana?","back":"Roedores"},{"front":"¿Cuál es el tratamiento de primera opción para la himenolepiasis?","back":"Praziquantel"},{"front":"¿Qué tipo de reacción de hipersensibilidad media el prurito severo en la escabiosis?","back":"Hipersensibilidad retardada tipo IV"},{"front":"¿En qué época del año es más frecuente la infestación por Sarcoptes scabiei?","back":"Invierno"},{"front":"¿Qué áreas del cuerpo suele respetar la escabiosis clásica?","back":"Cabeza, cuello y pies"},{"front":"¿Qué nombre reciben las líneas de pápulas en hombros y detrás de las rodillas en la escabiosis?","back":"Líneas de Hebra"},{"front":"¿Cuál es el tratamiento tópico de elección para Sarcoptes scabiei?","back":"Permetrina en crema al 5%"},{"front":"¿Cuánto tiempo puede sobrevivir el ácaro Sarcoptes scabiei fuera del cuerpo humano?","back":"72 horas"},{"front":"En pacientes con SIDA, ¿qué forma clínica grave de escabiosis se presenta?","back":"Escabiosis noruega"},{"front":"¿Cuál es el síntoma más frecuente de la giardiasis que suele preguntarse en exámenes médicos?","back":"Dolor abdominal"},{"front":"Un paciente con prurito anal nocturno y bruxismo probablemente está infectado por _____.","back":"Enterobius vermicularis"},{"front":"La dosis estándar de albendazol para el tratamiento de ascariasis es de _____ mg en dosis única.","back":"400 mg"},{"front":"La triada de tos seca, disnea e infiltrados pulmonares migratorios por parásitos se conoce como _____.","back":"Síndrome de Löffler"}]},"17":{"num":17,"name":"PATOLOGIA RESPIRATORIA DEL PEDIATRICO","cards":[{"front":"¿Cuál es el principal agente etiológico de la bronquiolitis?","back":"Virus Sincitial Respiratorio (VSR)."},{"front":"¿Cuál es el rango de edad más afectado por la bronquiolitis?","back":"Lactantes de 3 a 6 meses de edad."},{"front":"La bronquiolitis se presenta casi exclusivamente en niños menores de _____ años.","back":"2"},{"front":"¿En qué meses del año hay una mayor prevalencia de bronquiolitis?","back":"De noviembre a marzo."},{"front":"¿Qué síntomas caracterizan los días 1 a 3 de la evolución de la bronquiolitis?","back":"Febrícula, rinorrea y tos."},{"front":"¿Qué signos clínicos aparecen típicamente entre los días 4 y 6 en la bronquiolitis?","back":"Taquipnea, hipoxia, sibilancias espiratorias y cianosis."},{"front":"¿Cuál es el hallazgo característico en la exploración física de un lactante con bronquiolitis?","back":"Prolongación de la fase espiratoria."},{"front":"¿Cuál es la duración promedio del cuadro clínico de la bronquiolitis?","back":"12 días."},{"front":"Fisiopatológicamente, ¿qué causa la obstrucción de la luz bronquiolar en la bronquiolitis?","back":"Edema, moco, broncoespasmo y necrosis de las células epiteliales."},{"front":"¿Cómo se realiza el diagnóstico inicial de la bronquiolitis?","back":"Es meramente clínico."},{"front":"¿Bajo qué circunstancia se debe solicitar una radiografía de tórax en bronquiolitis?","back":"Solo en caso de duda diagnóstica."},{"front":"¿Cuáles son los hallazgos radiográficos de atrapamiento de aire en bronquiolitis?","back":"Hiperinsuflación, radiolucidez y atelectasias."},{"front":"¿Cuál es el pilar del tratamiento para la bronquiolitis?","back":"Tratamiento sintomático y de soporte."},{"front":"¿Qué tipo de nebulización se recomienda en el manejo de la bronquiolitis?","back":"Nebulización con NaCl al 3% (solución hipertónica)."},{"front":"¿A partir de qué nivel de saturación de oxígeno se indica oxigenoterapia en bronquiolitis?","back":"Cuando la saturación es menor al 90%."},{"front":"¿En qué caso se recomienda administrar una dosis de salbutamol en un paciente con bronquiolitis?","back":"Cuando hay antecedente de atopia, asma o alergia."},{"front":"¿Cuáles son los factores de riesgo principales para desarrollar bronquiolitis?","back":"Prematurez, tabaquismo pasivo, contaminación y cardiopatías congénitas."},{"front":"¿Qué escala se utiliza para clasificar la gravedad de la bronquiolitis?","back":"Escala de Wood-Downes."},{"front":"¿Qué fármaco se utiliza para la prevención de bronquiolitis en pacientes de alto riesgo?","back":"Palivizumab."},{"front":"¿Cuál es el agente etiológico de la tos ferina?","back":"Bordetella pertussis."},{"front":"¿Qué tipo de bacteria es Bordetella pertussis según la tinción de Gram?","back":"Bacteria Gram negativa."},{"front":"¿Qué grupo de edad es el más afectado por la tos ferina?","back":"Niños de 6 meses a 3 años de edad."},{"front":"¿Cuál es la duración característica de la fase catarral en la tos ferina?","back":"2 semanas."},{"front":"¿En qué fase de la tos ferina el paciente presenta el mayor grado de contagiosidad?","back":"Fase catarral."},{"front":"¿Qué síntomas definen la fase paroxística de la tos ferina?","back":"Accesos de tos cianosante, estridor inspiratorio y tos quintosa."},{"front":"¿Qué se entiende por 'tos quintosa' en el contexto de la tos ferina?","back":"Presencia de más de 5 accesos de tos seguidos."},{"front":"¿Cuál es la manifestación clínica típica de la tos ferina en niños muy pequeños?","back":"Apneas."},{"front":"¿Qué hallazgo en la biometría hemática sugiere el diagnóstico de tos ferina?","back":"Linfocitosis."},{"front":"¿Cuál es el 'gold estándar' para el diagnóstico de tos ferina?","back":"Cultivo nasofaríngeo."},{"front":"¿Cuál es el tratamiento antibiótico de elección en la fase catarral de la tos ferina?","back":"Eritromicina por 14 días."},{"front":"¿Qué alternativa antibiótica se indica en tos ferina en caso de alergia a macrólidos?","back":"Trimetoprima con sulfametoxazol (TMP-SMX)."},{"front":"¿Qué profilaxis se debe administrar a los contactos estrechos de un paciente con tos ferina?","back":"Eritromicina por 14 días."},{"front":"¿A qué edad y en qué población se aplica la vacuna Tdpa según el material?","back":"Niños mayores de 7 años y embarazadas entre las 27 y 36 SDG."},{"front":"En la tos ferina, ¿qué toxina bacteriana es responsable de la parálisis de los cilios respiratorios?","back":"Toxina dermonecrótica."},{"front":"¿Qué efecto produce la toxina pertussis en el paciente?","back":"Sensibilidad a la histamina, lo que desencadena la tos."},{"front":"¿Cuál es la definición de tos ferina según la OMS?","back":"Más de 21 días con tos asociada a criterios epidemiológicos o confirmación de laboratorio."},{"front":"¿Cuál es el agente etiológico más común de la laringotraqueítis (crup)?","back":"Virus Parainfluenza tipo 1."},{"front":"¿En qué rango de edad es más frecuente la laringotraqueítis?","back":"De 6 meses a 3 años de edad."},{"front":"¿Cuál es la tríada clínica característica del crup?","back":"Tos traqueal (perruna), estridor laríngeo inspiratorio y disfonía."},{"front":"¿Cómo se describe el signo radiológico clásico en una proyección AP de cuello en el crup?","back":"Signo de la punta de lápiz (o de la torre/aguja)."},{"front":"¿Cuál es la piedra angular del tratamiento farmacológico de la laringotraqueítis?","back":"Corticosteroides (Dexametasona)."},{"front":"¿Cuál es la dosis recomendada de dexametasona vía oral para el crup?","back":"0.6 mg/kg en dosis única."},{"front":"¿Qué fármaco se añade al tratamiento en casos de laringotraqueítis grave?","back":"Epinefrina racémica o L-epinefrina nebulizada."},{"front":"¿Cuál es la meta de saturación de oxígeno en un paciente con laringotraqueítis?","back":"Mantener una saturación mayor al 92%."},{"front":"¿Qué procedimiento de enfermería está contraindicado en la laringotraqueítis?","back":"Aspiración nasofaríngea."},{"front":"¿Cuál es el principal agente etiológico de la epiglotitis según el ENARM?","back":"Haemophilus influenzae."},{"front":"¿Qué posición adopta típicamente un niño con epiglotitis para facilitar la respiración?","back":"Posición en trípode (sentado, cuello en hiperextensión y boca abierta)."},{"front":"¿Cuáles son las '4 D's' clínicas de la epiglotitis?","back":"Disnea, Disfagia, Disfonía y Drooling (sialorrea)."},{"front":"¿Cuál es el estudio de imagen inicial que se debe solicitar en epiglotitis tras estabilizar al paciente?","back":"Radiografía lateral de cuello."},{"front":"¿Cuál es el signo radiológico patognomónico de la epiglotitis en la placa lateral?","back":"Signo del pulgar."},{"front":"¿Cuál es el estándar de oro (diagnóstico definitivo) para la epiglotitis?","back":"Nasofibroscopia o laringoscopia directa."},{"front":"¿Cuál es la prioridad absoluta en el tratamiento de la epiglotitis?","back":"Asegurar la permeabilidad de la vía aérea (intubación si es necesario)."},{"front":"¿Cuáles son los antibióticos de elección para el tratamiento de la epiglotitis?","back":"Cefotaxima o Ceftriaxona."},{"front":"¿Qué fármacos NO se deben utilizar en el manejo de la epiglotitis?","back":"Epinefrina y corticoesteroides."},{"front":"¿Qué medicamento se utiliza como profilaxis para los contactos de un paciente con epiglotitis?","back":"Rifampicina."},{"front":"¿Qué patología se caracteriza por ronquera progresiva y pérdida de voz en un preescolar con cuadro de resfriado?","back":"Laringitis catarral."},{"front":"¿Cuál es la causa probable de sibilancias y cianosis en un lactante de 1 a 3 meses con antecedente de aspiración de leche?","back":"Neumonitis por aspiración."},{"front":"¿Qué complicación bacteriana presenta fiebre y estridor mixto con pobre respuesta a epinefrina tras un cuadro de crup vírico?","back":"Traqueítis bacteriana."},{"front":"En el diagnóstico diferencial, ¿cuál es la principal diferencia clínica entre el inicio de la bronquiolitis y la epiglotitis?","back":"La bronquiolitis tiene un inicio insidioso (días previos de resfriado) y la epiglotitis es de inicio brusco y fulminante."},{"front":"¿Qué hallazgo clínico diferencia primordialmente a la laringotraqueítis de la epiglotitis?","back":"La presencia de tos traqueal (perruna) en el crup vs. sialorrea y ausencia de tos en la epiglotitis."},{"front":"¿Qué define a un caso de crup leve según el algoritmo?","back":"Ausencia de estridor en reposo y dificultad respiratoria leve."},{"front":"¿Qué define a un caso de crup grave según el algoritmo?","back":"Estridor y dificultad respiratoria grave con agitación o letargia."},{"front":"¿Cuál es la mortalidad asociada a la neumonitis por aspiración según el texto?","back":"25%."},{"front":"¿En qué fase de la tos ferina se presentan las complicaciones como encefalopatía o convulsiones?","back":"Fase de convalecencia."},{"front":"Concepto: Tos quintosa","back":"Definición: Accesos paroxísticos de tos (más de 5 en una sola espiración) seguidos de un estridor inspiratorio."},{"front":"¿Qué componente de Bordetella pertussis se utiliza para el diseño de vacunas?","back":"Hemaglutinina."},{"front":"¿Cuál es la conducta a seguir ante un crup moderado que no mejora tras 4 horas de administración de dexametasona?","back":"Hospitalizar y administrar epinefrina nebulizada."}]},"18":{"num":18,"name":"PLANES DE REHIDRATACION","cards":[{"front":"¿Cómo se define la diarrea aguda según la frecuencia y consistencia de las evacuaciones?","back":"Es la disminución de la consistencia (líquidas o semilíquidas) o el incremento de la frecuencia (>3 en 24 horas)."},{"front":"¿Cuál es la duración máxima de una diarrea para ser considerada aguda?","back":"Menos de 14 días."},{"front":"¿Qué porcentaje de incidencia reduce el lavado de manos en casos de diarrea?","back":"30%."},{"front":"¿Cuál es el agente causal más frecuente de diarrea en la población pediátrica?","back":"Rotavirus."},{"front":"¿Qué patógeno es la causa principal de la llamada 'diarrea del viajero'?","back":"Escherichia coli."},{"front":"¿Con qué agente infeccioso se asocia el contacto con tortugas?","back":"Salmonella."},{"front":"¿Qué bacteria se asocia típicamente al consumo de pollo mal cocido?","back":"Campylobacter."},{"front":"¿Para qué sirve el Método Dhaka en el manejo de la diarrea?","back":"Ayuda a elegir el plan de rehidratación adecuado."},{"front":"¿En qué casos se indica realizar un estudio coprológico?","back":"Fiebre, evacuaciones con sangre y moco, o diarrea de más de 7 días."},{"front":"¿Cuántos leucocitos por campo en heces definen una diarrea como inflamatoria?","back":"Más de 10 leucocitos por campo."},{"front":"¿Cuál es el tratamiento sintomático de elección para las náuseas y vómitos en diarreas no inflamatorias?","back":"Antieméticos como el ondansetrón."},{"front":"¿Bajo qué condiciones se reserva el uso de antibióticos en la diarrea aguda?","back":"Solo en casos seleccionados como disentería o diarrea inflamatoria."},{"front":"¿Cuál es el escenario epidemiológico típico de los brotes por Norovirus?","back":"Espacios cerrados como cruceros, asilos, guarderías y hospitales."},{"front":"¿Qué suplemento se debe administrar junto a la hidratación en niños con rotavirus?","back":"Zinc (10-20 mg/día por 10-14 días)."},{"front":"¿Cuál es el tiempo de inicio de los síntomas tras la ingesta de toxinas preformadas de S. aureus?","back":"Inicio rápido en menos de 6 horas."},{"front":"¿Qué alimento se asocia frecuentemente con la intoxicación por la toxina cereulida de Bacillus cereus?","back":"Arroz frito recalentado."},{"front":"¿Cómo se describe clásicamente el aspecto de las evacuaciones por Vibrio cholerae?","back":"Diarrea en 'agua de arroz' con olor a pescado."},{"front":"¿Cuál es el tratamiento de primera elección (antibiótico) para el cólera en adultos?","back":"Doxiciclina (300 mg en dosis única)."},{"front":"¿Qué antibiótico es de elección para el tratamiento del cólera en niños?","back":"Azitromicina."},{"front":"¿Cuál es el antecedente farmacológico clave para sospechar de colitis por Clostridium difficile?","back":"Uso previo de antibióticos (como clindamicina, cefalosporinas o quinolonas)."},{"front":"¿Qué hallazgo macroscópico en colonoscopia es característico de C. difficile?","back":"Presencia de pseudomembranas (placas amarillo-blanquecinas)."},{"front":"¿Cuál es el tratamiento antibiótico de elección para C. difficile por vía oral?","back":"Vancomicina (125 mg cada 6 horas por 10 días)."},{"front":"¿Qué antibiótico se recomienda para el tratamiento de Shigella según la guía de práctica clínica?","back":"Ciprofloxacino (500 mg cada 12 horas por 3-5 días)."},{"front":"¿Qué células intestinales invade inicialmente Salmonella no typhi?","back":"Células M del íleon."},{"front":"¿Qué cuadro clínico extraintestinal puede asociarse a la infección por Campylobacter jejuni?","back":"Síndrome de Guillain-Barré."},{"front":"¿Por qué la infección por Yersinia puede confundirse con una apendicitis?","back":"Porque causa adenitis mesentérica con dolor en la fosa ilíaca derecha."},{"front":"¿Cuál es la tríada clínica clásica de la fiebre tifoidea (S. typhi)?","back":"Fiebre en escalera, bradicardia relativa y leucopenia."},{"front":"¿Cuál es el hallazgo hematológico más común en la fiebre tifoidea?","back":"Eosinopenia (80%) y leucopenia."},{"front":"¿Cuál es el estándar de oro (Gold Standard) para el diagnóstico de fiebre tifoidea?","back":"Mielocultivo."},{"front":"¿Cuál es el antibiótico de primera línea para el tratamiento de la fiebre tifoidea?","back":"Ceftriaxona (2 g IV cada 24 horas por 10-14 días)."},{"front":"¿Qué fármacos están estrictamente prohibidos en la infección por E. coli enterohemorrágica (EHEC)?","back":"Antibióticos y loperamida."},{"front":"¿Por qué están prohibidos los antibióticos en la infección por EHEC?","back":"Porque incrementan el riesgo de desarrollar Síndrome Urémico Hemolítico (SHU)."},{"front":"¿Cuáles son los tres componentes del Síndrome Urémico Hemolítico?","back":"Anemia hemolítica, trombocitopenia e insuficiencia renal aguda."},{"front":"¿Cuál es la duración mínima de la diarrea para ser clasificada como crónica?","back":"Más de 2 semanas."},{"front":"¿Cuál es el mecanismo inmunológico de la enfermedad celíaca?","back":"Intolerancia a la gliadina del gluten que causa atrofia de las vellosidades intestinales."},{"front":"¿Qué haplotipos HLA se asocian a la enfermedad celíaca en el 95% de los casos?","back":"HLA DQ2 y HLA DQ8."},{"front":"¿Qué manifestación cutánea se presenta en el 10% de los pacientes con enfermedad celíaca?","back":"Dermatitis herpetiformis."},{"front":"¿Qué hallazgo se observa en la biopsia de intestino delgado (estudio de elección) en enfermedad celíaca?","back":"Ausencia de vellosidades e hiperplasia de las criptas."},{"front":"¿Cuál es el tratamiento definitivo para la enfermedad celíaca?","back":"Dieta estricta sin gluten de por vida."},{"front":"¿Cuál es el estudio de elección para el diagnóstico de intolerancia a la lactosa?","back":"Prueba de hidrógeno espirado."},{"front":"¿Qué valor de pH fecal sugiere intolerancia a la lactosa?","back":"pH menor a 5.5."},{"front":"¿En qué consiste el tratamiento de la intolerancia a la lactosa secundaria?","back":"Disminución temporal de alimentos con lactosa mientras se trata la patología orgánica base."},{"front":"¿Qué tipo de reacción de hipersensibilidad es la alergia a la proteína de leche de vaca (APLV) mediada por IgE?","back":"Hipersensibilidad Tipo 1."},{"front":"¿Cuáles son las tres proteínas principales involucradas en la APLV?","back":"Caseína, lactoalbúmina y lactoglobulina."},{"front":"¿Cuál es el estándar de oro para el diagnóstico de APLV?","back":"Prueba oral de doble ciego (suprimir y reintroducir el alérgeno)."},{"front":"¿Qué tipo de fórmula se indica en el tratamiento de la APLV grave?","back":"Fórmula a base de aminoácidos (Damira)."},{"front":"¿Bajo qué condición única se recomiendan los probióticos según los Puntos ENARM?","back":"Únicamente en diarrea asociada al uso de antimicrobianos."},{"front":"¿Qué síntoma cardinal obliga a sospechar de Shigella?","back":"Presencia de pus en las evacuaciones."},{"front":"¿Cuál es la principal complicación de la infección por Salmonella?","back":"Sangrado gastrointestinal."},{"front":"¿Cuál es la dosis de Zinc recomendada en pediatría para el manejo de la diarrea?","back":"10-20 mg/día."},{"front":"En el contexto de diarrea por toxinas preformadas, ¿cuál es el manejo indicado?","back":"Únicamente tratamiento sintomático y rehidratación (autolimitado en <24-48 h)."},{"front":"¿Qué mecanismo utiliza Vibrio cholerae para causar diarrea masiva?","back":"Aumento de cAMP por enterotoxina colérica, alterando el transporte de agua y electrolitos."},{"front":"¿Qué antibiótico se utiliza como alternativa oral para la fiebre tifoidea?","back":"Azitromicina (500 mg cada 24 horas por 7 días)."},{"front":"¿Cuál es el fármaco de elección para la diarrea por Campylobacter jejuni?","back":"Azitromicina (500 mg al día por 3 días)."},{"front":"¿Qué complicación se debe vigilar estrechamente en un paciente con E. coli enterohemorrágica?","back":"Síndrome Urémico Hemolítico (SHU)."},{"front":"En la enfermedad celíaca, ¿en cuánto tiempo suelen resolverse los síntomas tras iniciar la dieta sin gluten?","back":"1-2 semanas."},{"front":"¿Cuál es el tratamiento farmacológico inicial para las náuseas en Norovirus?","back":"Ondansetrón (4-8 mg)."},{"front":"¿A qué edad suelen debutar los niños con enfermedad celíaca?","back":"A los 2 años, tras la introducción de gluten en la dieta."},{"front":"¿Qué nutriente suele presentar deficiencia en la enfermedad celíaca debido a la malabsorción?","back":"Hierro."},{"front":"¿Qué prueba se solicita a partir de la segunda semana para el diagnóstico de fiebre tifoidea?","back":"Reacciones febriles (Prueba de Widal)."},{"front":"¿Cuál es la dosis de dexametasona sugerida en caso de complicaciones por fiebre tifoidea?","back":"3 mg/kg/día por 3 días."},{"front":"¿Qué vacuna se recomienda para viajeros a zonas endémicas de fiebre tifoidea?","back":"Vacuna ViPCS."},{"front":"¿Qué hallazgo clínico diferencia la APLV de la intolerancia a la lactosa?","back":"La APLV involucra al sistema inmunológico y puede tener manifestaciones cutáneas o respiratorias."},{"front":"¿Cuál es el antibiótico de elección para E. coli enterotoxigénica (ETEC) en casos moderados?","back":"Rifaximina (200 mg cada 8 horas por 3 días)."},{"front":"¿Qué bacteria se asocia a la 'fiebre en puré de guisantes'?","back":"Salmonella typhi."},{"front":"¿Cuál es la dosis infecciosa de Shigella?","back":"Muy baja (10-100 bacterias)."},{"front":"¿Cuál es el tratamiento de elección para Yersinia en casos graves?","back":"Ciprofloxacino o Ceftriaxona."},{"front":"¿Qué gas se mide en la prueba de aliento para diagnosticar intolerancia a la lactosa?","back":"Hidrógeno."},{"front":"¿Qué síntoma es el más frecuente en la intolerancia a la lactosa?","back":"Dolor abdominal."},{"front":"Concepto: Plan Dhaka","back":"Definición: Estrategia para clasificar el estado de hidratación y seleccionar el tratamiento hídrico en pacientes con diarrea."}]},"19":{"num":19,"name":"NEUMONIAS","cards":[{"front":"¿Cómo se define la Neumonía Adquirida en la Comunidad (NAC) respecto al tiempo de hospitalización?","back":"Es una infección aguda del parénquima pulmonar en pacientes no hospitalizados en los últimos 7 días."},{"front":"¿Cuál es la principal causa de muerte infecciosa infantil a nivel mundial en menores de 5 años?","back":"Neumonía adquirida en la comunidad."},{"front":"¿Qué complicación de la NAC se considera la más frecuente?","back":"Derrame pleural."},{"front":"¿Qué complicación de la NAC se considera la más grave?","back":"Abscesos pulmonares."},{"front":"¿Cuál es el agente bacteriano más frecuente en adultos con NAC (39% de los casos)?","back":"Streptococcus pneumoniae."},{"front":"En pacientes adultos con EPOC, ¿qué agente bacteriano se debe sospechar específicamente?","back":"Haemophilus influenzae."},{"front":"¿Cuál es el agente etiológico viral más frecuente en pediatría para neumonía?","back":"Virus Sincitial Respiratorio (VSR)."},{"front":"¿Qué síntoma se considera el más frecuente en el cuadro clínico de la NAC?","back":"Tos."},{"front":"¿Cuál es el signo clínico con mayor valor predictivo positivo para neumonía en menores de 2 años?","back":"Taquipnea."},{"front":"¿Qué hallazgo radiológico es característico de una neumonía bacteriana típica?","back":"Infiltrado alveolar homogéneo o consolidación lobar."},{"front":"¿Qué patrón radiológico sugiere una etiología viral o atípica?","back":"Infiltrado intersticial difuso bilateral."},{"front":"¿Qué nivel de Proteína C Reactiva (PCR) indica una alta probabilidad de etiología bacteriana y necesidad de antibióticos?","back":"Mayor de 100 mg/dL."},{"front":"¿A partir de qué nivel de PCR aumenta significativamente el riesgo de muerte en el paciente?","back":"Mayor de 75 mg/dL."},{"front":"¿Qué valor de procalcitonina sugiere una sobreinfección bacteriana?","back":"Mayor a 0.8 ng/mL."},{"front":"En el diagnóstico de NAC severa, ¿cuándo es obligatorio realizar una tinción de Gram y cultivo?","back":"En pacientes intubados mediante aspirado endotraqueal o broncoscopia."},{"front":"¿Cuál es la saturación de oxígeno (SpO_2) que define hipoxemia en un paciente con NAC?","back":"Menor al 92%."},{"front":"¿Qué característica diferencia el inicio de síntomas entre la neumonía bacteriana típica y la atípica en adultos?","back":"La típica es hiperaguda (menor a 24 h) y la atípica es subaguda (días a semanas)."},{"front":"¿Qué síntoma extrapulmonar es característico de la infección por Legionella?","back":"Diarrea."},{"front":"¿Qué hallazgo en la auscultación es típico de la neumonía bacteriana localizada?","back":"Crepitantes localizados y matidez."},{"front":"¿Cómo se describe el estado general de un niño con neumonía atípica (neumonía del caminador)?","back":"Estado general conservado."},{"front":"¿Qué escala es la más utilizada para decidir el sitio de tratamiento (ambulatorio vs hospitalario) en adultos?","back":"CURB-65."},{"front":"En la escala CURB-65, ¿qué nivel de nitrógeno ureico en sangre otorga 1 punto?","back":"Mayor a 19 mg/dL."},{"front":"¿Cuál es el punto de corte de la frecuencia respiratoria en el CURB-65?","back":"\\ge 30 respiraciones por minuto."},{"front":"¿Qué valores de presión arterial otorgan un punto en la escala CURB-65?","back":"Sistólica < 90 mmHg o diastólica < 60 mmHg."},{"front":"Según el CURB-65, ¿qué conducta se debe seguir con un paciente que suma 2 puntos?","back":"Hospitalización corta o tratamiento en casa con supervisión estricta."},{"front":"¿Qué puntaje en la escala CRB-65 (sin urea) indica envío inmediato a segundo nivel?","back":"A partir de 1 punto."},{"front":"¿Cuál es el tratamiento de primera línea para NAC leve en adultos sin alergias?","back":"Amoxicilina vía oral por 5 días."},{"front":"¿Qué antibiótico se recomienda para adultos con NAC moderada-grave?","back":"Levofloxacino (quinolona) o cefalosporina de 3^{ra} generación."},{"front":"¿Cuál es el esquema antibiótico de elección para un paciente con NAC en la UCI?","back":"Betalactámico intravenoso más macrólido o quinolona."},{"front":"¿Por qué se debe evitar el uso de Inhibidores de la Bomba de Protones (IBP) en pacientes con riesgo de neumonía?","back":"Porque incrementan el riesgo de desarrollar neumonía en el adulto."},{"front":"¿Cuál es la dosis de amoxicilina recomendada como primera línea en pediatría para NAC?","back":"90 mg/kg/dia."},{"front":"¿Qué fármacos están contraindicados en el manejo de la neumonía pediátrica?","back":"Corticoides, antitusivos y antihistamínicos."},{"front":"¿Cuál es el principal factor de riesgo para desarrollar neumonía complicada por Staphylococcus aureus?","back":"Infección previa por Influenza."},{"front":"¿Cuál es la medida más efectiva para la prevención de la Influenza?","back":"Vacunación."},{"front":"¿Qué fármaco antiviral y dosis se indica para el tratamiento de Influenza?","back":"Oseltamivir 75 mg cada 12 horas por 5 días."},{"front":"¿En qué plazo se debe administrar la quimioprofilaxis con oseltamivir a los contactos de un caso de Influenza?","back":"En las primeras 48 horas."},{"front":"¿Qué síntoma es el síntoma más frecuente (90%) en la clínica de Influenza?","back":"Tos."},{"front":"¿Cuál es el estándar de oro (Gold Standard) para el diagnóstico de COVID-19?","back":"PCR-RT por hisopado nasofaríngeo."},{"front":"¿Qué hallazgo tomográfico es patognomónico de la neumonía por COVID-19?","back":"Patrón en vidrio despulido con empedrado y distribución periférica."},{"front":"¿Bajo qué condición de saturación de oxígeno se indica el uso de dexametasona en pacientes hospitalizados por COVID-19?","back":"Saturación menor al 90% al aire ambiente."},{"front":"¿Qué efecto tiene el uso de dexametasona en pacientes con COVID-19 que no requieren oxígeno?","back":"Aumenta la mortalidad en un 20%."},{"front":"¿Cuál es el tratamiento antiviral de elección para pacientes ambulatorios con COVID-19 y alto riesgo de complicaciones?","back":"Paxlovid (Nirmatrelvir + Ritonavir)."},{"front":"¿Cómo se define el Síndrome de Insuficiencia Respiratoria Aguda (SIRA) grave según la relación PaO_2/FiO_2?","back":"Relación PaO_2/FiO_2 < 100 mmHg con PEEP > 5 cmH_2O."},{"front":"¿Cuál es la piedra angular del tratamiento en el SIRA?","back":"Ventilación mecánica protectora."},{"front":"¿Qué posición del paciente mejora la oxigenación en cuadros de SIRA grave?","back":"Decúbito prono."},{"front":"¿A partir de cuántas horas de estancia hospitalaria se considera Neumonía Intrahospitalaria (NIH)?","back":"Después de 48 horas del ingreso."},{"front":"¿Qué microorganismo es el agente más común en la NIH temprana (menor a 5 días)?","back":"Streptococcus pneumoniae o Staphylococcus aureus meticilino sensible."},{"front":"¿Qué agentes se sospechan en una NIH tardía (mayor a 5 días)?","back":"Pseudomonas aeruginosa, MRSA o Acinetobacter."},{"front":"¿Cuál es el tratamiento empírico inicial para NIH con bajo riesgo de multirresistencia?","back":"Ceftriaxona."},{"front":"¿Qué medida preventiva reduce la aspiración de secreciones en pacientes hospitalizados?","back":"Mantener la cabecera entre 30-45^{\\circ}."},{"front":"¿Qué manifestación extrapulmonar sugiere infección por Mycoplasma pneumoniae?","back":"Anemia hemolítica (por crioaglutininas positivas)."},{"front":"¿Cuál es el tratamiento de elección para neumonía por Mycoplasma pneumoniae?","back":"Azitromicina o Claritromicina (macrólidos)."},{"front":"En pediatría, ¿qué hallazgo auscultatorio diferencia la neumonía viral de la bacteriana?","back":"La viral presenta sibilancias y crepitantes bilaterales; la bacteriana solo crepitantes localizados."},{"front":"¿Qué puntaje en la escala PSI (Pneumonia Severity Index) corresponde a la Clase IV?","back":"Entre 91-130 puntos."}]},"20":{"num":20,"name":"ASMA","cards":[{"front":"¿Cómo se define el asma desde el punto de vista fisiopatológico?","back":"Enfermedad inflamatoria crónica de las vías respiratorias con hiperreactividad y obstrucción del flujo aéreo."},{"front":"¿Qué característica tiene la obstrucción del flujo aéreo en el paciente asmático?","back":"Es total o parcialmente reversible."},{"front":"¿Cuál es la enfermedad crónica más frecuente en la infancia y la adolescencia?","back":"Asma."},{"front":"¿Cuál es la prevalencia reportada de asma en México?","back":"11.7 %."},{"front":"Mencione las cuatro células principales involucradas en el proceso inflamatorio del asma.","back":"Mastocitos, eosinófilos, linfocitos T e interleucinas (IL-2, IL-5)."},{"front":"¿Cuáles son los tres ejes principales para la clasificación del asma?","back":"Control de síntomas, nivel de gravedad y fenotipos."},{"front":"Factores de riesgo para exacerbación: ¿En qué estaciones del año suele iniciar la temporada de crisis?","back":"Otoño e invierno."},{"front":"¿Qué cantidad de síntomas definen a un paciente pediátrico como 'bien controlado'?","back":"Ningún síntoma."},{"front":"¿Cuántos síntomas presenta un paciente pediátrico con asma 'no controlada'?","back":"Tres o cuatro síntomas."},{"front":"¿Cómo se clasifica el control de un paciente que presenta uno o dos síntomas de asma?","back":"Parcialmente controlada."},{"front":"¿Qué nivel de tratamiento y VEF_1 definen el asma leve?","back":"Control con paso 1, 2 o 3 y VEF_1 > 70 %."},{"front":"¿Qué valor de VEF_1 es característico del asma grave?","back":"Menor del 60 %."},{"front":"En niños > 5 años, ¿cuántos síntomas diurnos a la semana sugieren falta de control?","back":"\\ge 2 veces por semana."},{"front":"En niños < 5 años, ¿cuántos despertares nocturnos al mes se consideran un criterio de falta de control?","back":"\\ge 1 vez al mes."},{"front":"¿Qué fenotipo de asma se caracteriza por antecedentes alérgicos personales y familiares?","back":"Asma alérgica o de inicio temprano."},{"front":"¿Qué caracteriza al fenotipo de asma con limitación fija al flujo de aire?","back":"Remodelación de la vía aérea o falta de reversibilidad tras años de padecer la enfermedad."},{"front":"¿Cuál es el síntoma más común del asma, usualmente seco y paroxístico?","back":"Tos (con predominio nocturno)."},{"front":"¿Cuántos síntomas clave se requieren para realizar el diagnóstico clínico de asma?","back":"Presencia de 2 o más síntomas."},{"front":"Mencione los tres criterios mayores para el diagnóstico de asma en niños < 3 años.","back":"Historia de padre(s) con asma, dermatitis atópica diagnosticada y sensibilización alérgica a \\ge 1 aeroalérgeno."},{"front":"¿Cuál es el punto de corte de eosinofilia periférica considerado como criterio menor en niños < 3 años?","back":"\\ge 4 %."},{"front":"¿Cuál es el estudio estándar para confirmar el diagnóstico de asma?","back":"Espirometría con prueba de reversibilidad con broncodilatador."},{"front":"¿Qué valor de la relación VEF_1/FVC indica un patrón obstructivo?","back":"< 0.7."},{"front":"¿Qué incremento en el VEF_1 se considera una prueba de reversibilidad positiva?","back":"Incremento de \\ge 12 % o \\ge 200 ml."},{"front":"¿Qué alternativa diagnóstica se debe considerar si no se puede realizar una espirometría?","back":"Medición del flujo espiratorio pico (FEP)."},{"front":"¿Qué tipo de inflamación refleja la Fracción Espiratoria de Óxido Nítrico (FENO)?","back":"Inflamación eosinofílica tipo 2 en la vía aérea."},{"front":"En niños \\ge 6 años, ¿qué valor de FENO se asocia a un diagnóstico de asma?","back":"\\ge 35 ppb."},{"front":"¿Cuál es el rango de SpO_2 en una crisis asmática leve a moderada?","back":"90 % a 95 %."},{"front":"¿Cómo es el lenguaje de un paciente pediátrico durante una crisis asmática grave?","back":"Habla entrecortada en palabras."},{"front":"¿Qué frecuencia cardíaca indica una crisis asmática grave en pediatría?","back":"120 a 140 LPM."},{"front":"¿Cuáles son los signos clínicos de un paro respiratorio inminente por asma?","back":"Confusión o letargo, silencio auscultatorio, bradicardia o arritmias."},{"front":"¿Cuál es el tratamiento de primera elección para el rescate en crisis asmáticas?","back":"SABA inhalado (Salbutamol)."},{"front":"¿Cuál es la dosis máxima de inhalaciones de Salbutamol recomendada cada 20 min en una crisis?","back":"10 inhalaciones."},{"front":"¿En qué caso se debe añadir Bromuro de Ipratropio al tratamiento de crisis?","back":"En crisis moderada sin respuesta o en crisis grave."},{"front":"En niños \\ge 4 años sin mantenimiento previo, ¿con qué tratamiento se inicia según el esquema de prevención?","back":"Mantenimiento (Paso 2-4 según gravedad) y SABA a demanda."},{"front":"¿En qué consiste el Paso 2 del tratamiento de control simple?","back":"Corticoesteroide inhalado (CEI) a dosis baja."},{"front":"¿Cuál es el tratamiento de primera línea en el Paso 3 para niños pediátricos?","back":"CEI dosis baja + LABA."},{"front":"¿A partir de qué paso del tratamiento de control se debe enviar al paciente con un especialista?","back":"Paso 4."},{"front":"¿Qué fármaco biológico (anti-IgE) se puede usar en el Paso 5 a partir de los 6 años?","back":"Omalizumab."},{"front":"¿Por qué no se deben usar los LABA como monoterapia de rescate?","back":"Aumentan el riesgo de crisis."},{"front":"Mencione tres medidas de tratamiento no farmacológico en asma.","back":"Evitar tabaquismo, limitar contaminación intradomiciliaria y evitar exposición a alérgenos animales."},{"front":"¿Cuál es el objetivo de saturación de oxígeno durante el manejo de una exacerbación aguda?","back":"> 94 %."},{"front":"En adultos, ¿cómo se clasifica el asma con síntomas nocturnos \\le 2 veces al mes y sin limitación de actividad?","back":"Asma intermitente."},{"front":"¿Qué valor de VEF_1 define al asma moderada persistente en el adulto?","back":"60 - 80 %."},{"front":"En el adulto, ¿qué nivel de persistencia presenta síntomas diurnos más de una vez al día y VEF_1 < 60 %?","back":"Grave persistente."},{"front":"¿Cómo es el habla de un paciente adulto en una crisis moderada?","back":"Frases."},{"front":"¿Qué frecuencia respiratoria indica una crisis grave en el paciente adulto?","back":"> 25 respiraciones por minuto."},{"front":"¿Qué hallazgo en la auscultación es característico de una crisis vital de asma?","back":"Silencio respiratorio."},{"front":"¿Cuál es el manejo ambulatorio inicial para una crisis leve en adultos?","back":"SABA."},{"front":"Tratamiento de crisis severa en adultos: SABA + SAMA + Corticoides + _____.","back":"Sulfato de Magnesio."},{"front":"¿Qué criterio gasométrico de PaCO_2 indica insuficiencia respiratoria hipercápnica en una crisis vital?","back":"> 45 mmHg."},{"front":"¿Cuál es el fármaco de elección para el mantenimiento en el Paso 2 si no se toleran los CEI?","back":"Antileucotrienos."},{"front":"¿Qué combinación de fármacos en un solo inhalador se sugiere en el Paso 3?","back":"Budesonida + Formoterol o Fluticasona + Salmeterol."},{"front":"¿Cuál es la frecuencia cardíaca en una crisis leve-moderada pediátrica?","back":"< 120 LPM."},{"front":"En la clasificación de adultos, ¿qué SaO_2 define una crisis grave?","back":"< 90 %."},{"front":"¿Qué fármaco se prefiere como rescate en mayores de 12 años según el resumen del tratamiento?","back":"SABA / Formoterol."},{"front":"¿Cuál es el síntoma guía para el diagnóstico en niños < 3 años según el Índice Predictivo de Asma?","back":"Historia de > 4 episodios de sibilancias en el último año."},{"front":"¿A partir de qué edad se puede utilizar el FENO como apoyo diagnóstico?","back":"\\ge 6 años."},{"front":"La tríada clínica clásica de una crisis de asma incluye: disnea, tos y _____.","back":"Sibilancias."},{"front":"¿Qué maniobra terapéutica se añade en el Paso 4 de tratamiento de control?","back":"Tiotropio."},{"front":"En adultos, ¿qué PaO_2 se asocia a una crisis moderada?","back":"\\ge 61 a 80 mmHg."}]},"21":{"num":21,"name":"IRAS Y CONVULSIONES","cards":[{"front":"¿Cuál es el principal agente causal del resfriado común en el 80-90% de los casos?","back":"Rhinovirus"},{"front":"El resfriado común se autolimita típicamente en un periodo de _____ días.","back":"5 a 14"},{"front":"¿Cuál es la maniobra más efectiva como factor protector contra el resfriado común?","back":"Lavado de manos"},{"front":"En el resfriado común, se debe sospechar de rinosinusitis si la clínica persiste después de _____ días.","back":"10-14"},{"front":"¿Cuál es el fármaco de elección para el control de la fiebre en el resfriado común y su dosis pediátrica?","back":"Paracetamol a 10\\text{ mg/kg}"},{"front":"¿Qué efecto tienen los antibióticos sobre la evolución natural del resfriado común?","back":"No modifican la evolución natural."},{"front":"Menciona los dos picos de incidencia estacional para el resfriado común.","back":"Otoño y Primavera"},{"front":"¿Cuál es la segunda causa viral más frecuente del resfriado común?","back":"Coronavirus"},{"front":"Definición clínica de faringoamigdalitis: infección de faringe y amígdalas con garganta roja de más de _____ días de duración.","back":"Cinco"},{"front":"¿Qué porcentaje de los episodios de faringoamigdalitis son de origen viral?","back":"80-90%"},{"front":"¿Cuál es la bacteria responsable del 15% de los casos de faringoamigdalitis?","back":"Streptococcus betahemolítico del grupo A (S. pyogenes)"},{"front":"¿Qué hallazgo en la orofaringe sugiere una etiología viral en lugar de bacteriana?","back":"Presencia de vesículas"},{"front":"¿Cuál es el estándar de oro para el diagnóstico de faringoamigdalitis recurrente?","back":"Cultivo faríngeo en agar sangre"},{"front":"Según los criterios de Centor, ¿cuál es la conducta a seguir con un puntaje de 0 a 2 puntos?","back":"Tratamiento sintomático únicamente."},{"front":"Según los criterios de Centor, ¿qué acción se indica ante un puntaje de 3 puntos?","back":"Realizar prueba rápida de antígeno o cultivo (dar antibiótico solo si es positiva)."},{"front":"En los criterios de Centor, ¿cuántos puntos se asignan a la ausencia de tos?","back":"1 punto"},{"front":"¿Cuál es el tratamiento antibiótico de elección para faringoamigdalitis en niños con peso menor a 27\\text{ kg}?","back":"Penicilina G benzatínica 600,000 UI en dosis única intramuscular."},{"front":"¿Cuál es el tratamiento antibiótico de elección para faringoamigdalitis en pacientes con peso mayor a 27\\text{ kg}?","back":"Penicilina G benzatínica 1,200,000 UI en dosis única intramuscular."},{"front":"¿Qué grupo de antibióticos se indica en pacientes con faringoamigdalitis y alergia a la penicilina?","back":"Macrólidos (Eritromicina o Azitromicina)"},{"front":"¿Cuál es la complicación supurativa más frecuente de la faringoamigdalitis?","back":"Absceso periamigdalino"},{"front":"¿Cuál es la complicación no supurativa más frecuente de la infección por S. pyogenes?","back":"Fiebre reumática"},{"front":"¿Cuál es la complicación no supurativa más grave tras una faringoamigdalitis estreptocócica?","back":"Glomerulonefritis postestreptocócica"},{"front":"Triada clásica del absceso periamigdalino: odinofagia severa unilateral, voz en papa y _____.","back":"Trismus (signo patognomónico)"},{"front":"¿Hacia qué lado se desplaza la úvula en la exploración física de un absceso periamigdalino?","back":"Hacia el lado contralateral"},{"front":"¿Cuál es el estándar de oro para el diagnóstico del absceso periamigdalino?","back":"TAC con contraste"},{"front":"¿Qué calibre de aguja se utiliza para el drenaje por aspiración de un absceso periamigdalino?","back":"Aguja de 18 G"},{"front":"¿Cuál es el agente causal de la mononucleosis infecciosa?","back":"Virus de Epstein-Barr (EBV o Herpes virus 4)"},{"front":"Triada clásica de la mononucleosis: fiebre, linfadenopatía y _____.","back":"Faringitis"},{"front":"¿Qué fenómeno cutáneo ocurre en el 80-100% de los pacientes con mononucleosis tras recibir ampicilina o amoxicilina?","back":"Desarrollan un exantema (rash)."},{"front":"En el diagnóstico de mononucleosis, ¿qué hallazgo en el frotis de sangre es característico?","back":"Presencia de linfocitos atípicos (>10%)."},{"front":"¿Cuál es la prueba confirmatoria (serológica) para mononucleosis infecciosa?","back":"Prueba de Paul-Bunnell"},{"front":"¿Por qué se deben evitar los deportes de contacto durante al menos 1 mes en la mononucleosis?","back":"Por el riesgo de ruptura esplénica debido a la esplenomegalia."},{"front":"Agente etiológico de la difteria:","back":"Corynebacterium diphtheriae (Gram +)"},{"front":"¿Cuál es la complicación más grave y principal causa de muerte en la difteria?","back":"Miocarditis"},{"front":"Hallazgo clínico característico de difteria en la orofaringe:","back":"Membranas grisáceas sangrantes adheridas a las mucosas."},{"front":"¿Cuál es el medio de cultivo específico para diagnosticar difteria?","back":"Cultivo de Loeffler"},{"front":"Diagnóstico diferencial: niño con inicio brusco, ataque al estado general y crepitantes localizados.","back":"Neumonía bacteriana"},{"front":"Definición de estado epiléptico: crisis que dura más de _____ minutos o recurrencia sin recuperación de conciencia.","back":"5 minutos"},{"front":"¿Cuál es el tipo de crisis convulsiva más común en niños menores de 5 años?","back":"Crisis febriles"},{"front":"¿Qué fases componen cronológicamente una crisis tónico-clónica?","back":"Fase prodrómica, fase tónica, fase clónica y periodo postictal."},{"front":"¿En qué rango de edad son más frecuentes las crisis febriles?","back":"6 meses a 5 años"},{"front":"¿Cuál es la duración máxima de una crisis febril típica?","back":"Menos de 15 minutos (según criterios clínicos habituales, el material indica 5 min para la distinción de manejo)."},{"front":"¿Cuál es el riesgo de desarrollar epilepsia en un niño con crisis febriles típicas?","back":"Igual al de la población general."},{"front":"¿Cuál es el estudio de elección para el abordaje etiológico de las convulsiones?","back":"Electroencefalograma (EEG)"},{"front":"¿Qué fármaco es la primera línea de tratamiento para una crisis que dura más de 5 minutos?","back":"Benzodiacepinas (Lorazepam IV o Diazepam IV)"},{"front":"En el tratamiento de crisis febriles, ¿cuál es la vía de administración de midazolam si no hay acceso venoso?","back":"Intranasal o intramuscular"},{"front":"¿Cuál es el tratamiento de elección para las crisis de ausencia en México ante la falta de etosuximida?","back":"Valproato"},{"front":"Hallazgo característico en el EEG de las crisis de ausencia:","back":"Puntas de ondas lentas (punta-onda) a 3 ciclos por segundo (3 Hz)."},{"front":"Triada clásica del Síndrome de West:","back":"Espasmos musculares, retraso del desarrollo y electroencefalograma con hipsarritmia."},{"front":"¿Cuál es el tratamiento de primera elección para el Síndrome de West?","back":"Vigabatrina"},{"front":"¿Qué síndrome epiléptico se caracteriza por un patrón de punta-onda lenta (<2.5\\text{ Hz}) y tiene como antecedente el Sx de West?","back":"Síndrome de Lennox-Gastaut"},{"front":"¿Qué mutación genética se asocia al Síndrome de Dravet?","back":"Mutación del canal de sodio (gen SCN1A)."},{"front":"¿En qué momento del día ocurren característicamente las crisis mioclónicas en la Enfermedad de Janz?","back":"Al despertarse"},{"front":"Localización de las puntas en el EEG de la epilepsia Rolandica:","back":"Región temporal (foco rolándico)."},{"front":"Fármaco de elección para el tratamiento de la epilepsia Rolandica:","back":"Carbamazepina"},{"front":"¿Cuál es la principal etiología del Síndrome de Ohtahara?","back":"Malformaciones estructurales"},{"front":"Criterio de hospitalización por trismus en absceso: apertura bucal menor a _____.","back":"2\\text{ cm}"},{"front":"¿Qué fármacos se deben evitar en el tratamiento del resfriado común según la guía?","back":"Vitamina C, antitusígenos y descongestionantes."},{"front":"¿Cuál es la principal causa de enfermedad en México según el material?","back":"Resfriado común"},{"front":"¿Cómo se define la epilepsia?","back":"Más de 2 crisis convulsivas sin asociación a otra patología, separadas por más de 24 horas."}]},"22":{"num":22,"name":"ENFERMEDADES EXANTEMATICAS","cards":[{"front":"¿A qué familia de virus pertenece el agente causal del sarampión?","back":"Paramyxovirus"},{"front":"¿Cuál es el periodo de incubación típico del sarampión?","back":"10 días"},{"front":"¿En qué periodo es contagioso un paciente con sarampión?","back":"Desde 3 días antes del exantema hasta 5 días después de su aparición."},{"front":"¿Cómo se denominan las lesiones blancas en la cara interna de los carrillos patognomónicas del sarampión?","back":"Manchas de Koplik"},{"front":"¿Qué nombre reciben los puntos grisáceos en faringe o amígdalas observados en el sarampión?","back":"Manchas de Herman"},{"front":"¿En qué consiste el signo de Stimson en el sarampión?","back":"Hiperemia en la conjuntiva palpebral."},{"front":"¿Cuál es la dosis de vitamina A para un niño mayor de 1 año con sarampión?","back":"200,000 UI por dos días."},{"front":"¿Cuál es la dosis de vitamina A para un niño menor de 1 año con sarampión?","back":"100,000 UI por dos días."},{"front":"¿Cuál es la complicación más frecuente del sarampión?","back":"Otitis media aguda"},{"front":"¿Cuál es la complicación más grave del sarampión que causa más muertes?","back":"Neumonía"},{"front":"¿A qué familia pertenece el virus de la rubéola?","back":"Togavirus (Matonavirus)"},{"front":"¿Cómo se describen las manchas de Forchheimer en la rubéola?","back":"Lesiones petequiales en el paladar blando."},{"front":"¿Qué hallazgo clínico define el signo de Teodor en la rubéola?","back":"Adenopatías retroauriculares dolorosas."},{"front":"¿Cuál es la complicación más frecuente de la rubéola en niños?","back":"Artritis"},{"front":"¿Cuál es el periodo de incubación de la rubéola?","back":"De 12 a 23 días."},{"front":"¿En qué momento es más infecciosa la rubéola?","back":"Durante la erupción cutánea."},{"front":"¿Qué virus es el principal responsable de la roséola (sexta enfermedad)?","back":"Herpes virus humano 6 (HHV-6)"},{"front":"¿Cuál es la característica clave de la fiebre en la roséola?","back":"Desaparece súbitamente cuando aparece el exantema."},{"front":"¿Qué son las manchas de Nagayama en la roséola?","back":"Pápulas eritematosas en el paladar blando y la úvula."},{"front":"¿En qué consiste el signo de Berliner observado en la roséola?","back":"Edema palpebral y periorbitario."},{"front":"¿Cuál es la complicación más frecuente de la roséola durante la fase febril?","back":"Crisis convulsivas"},{"front":"¿Cuál es el agente causal de la escarlatina?","back":"Estreptococo beta hemolítico del grupo A (S. pyogenes)."},{"front":"¿Cómo evoluciona la lengua en un paciente con escarlatina?","back":"Inicia con una capa blanquecina y papilas hipertrofiadas, tornándose luego roja como fresa."},{"front":"¿Cómo se describe la textura del exantema en la escarlatina?","back":"Exantema en lija o piel de gallina."},{"front":"¿Qué hallazgo clínico define el signo de Pastia en la escarlatina?","back":"Petequias longitudinales en los pliegues de flexión."},{"front":"¿Qué es el triángulo nasogeniano de Filatov en la escarlatina?","back":"Palidez perioral característica."},{"front":"¿Cuál es el estándar de oro para el diagnóstico de la escarlatina?","back":"Cultivo de exudado faríngeo"},{"front":"¿Cuál es el tratamiento de primera elección para la escarlatina?","back":"Penicilina V (fenoximetilpenicilina) vía oral por 10 días."},{"front":"¿Cuál es la complicación no supurativa más frecuente de la escarlatina?","back":"Glomerulonefritis"},{"front":"¿Cuál es el periodo de contagio de la escarlatina si el paciente recibe tratamiento?","back":"3 días con tratamiento."},{"front":"¿A qué familia pertenece el agente causal de la varicela?","back":"Alfa herpes virus"},{"front":"¿Cómo se describe la progresión de las lesiones en la varicela?","back":"Evolucionan de pápula a vesícula (gota de lluvia), luego a pústula y finalmente a costra."},{"front":"¿Qué término se usa para describir la presencia de lesiones en diferentes estadios en la varicela?","back":"Cielo estrellado"},{"front":"¿Cuál es la complicación más frecuente de la varicela?","back":"Infección de las heridas por cocos Gram positivos (impetiginización)."},{"front":"¿Qué estudio citológico confirma el diagnóstico de varicela al observar células gigantes multinucleadas?","back":"Tinción de Tzanck"},{"front":"¿Qué otro nombre recibe el eritema infeccioso?","back":"Quinta enfermedad"},{"front":"¿Cuál es el agente causal de la quinta enfermedad?","back":"Parvovirus humano B19 (PVB19)."},{"front":"¿Cuál es el hallazgo clínico inicial característico en la cara de un niño con quinta enfermedad?","back":"Signo de la mejilla abofeteada"},{"front":"¿Cómo se describe el exantema en la segunda etapa de la quinta enfermedad?","back":"Exantema papular distal y simétrico con apariencia de encaje."},{"front":"¿Cuál es la complicación más grave de la quinta enfermedad en mujeres embarazadas?","back":"Anemia aplásica e hidropesía fetal."},{"front":"¿Qué es la enfermedad de Kawasaki?","back":"Una vasculitis multisistémica aguda e inmunitaria que afecta vasos de mediano calibre."},{"front":"¿Cuál es el tratamiento de primera elección para la enfermedad de Kawasaki?","back":"Inmunoglobulina intravenosa (2 g/kg) y ácido acetilsalicílico."},{"front":"¿Cuál es la complicación cardíaca más grave de la enfermedad de Kawasaki?","back":"Aneurismas coronarios"},{"front":"¿Cuál es el agente causal más común de la enfermedad mano-boca-pie?","back":"Virus Coxsackie A16"},{"front":"¿Dónde se localizan típicamente las vesículas en la enfermedad mano-boca-pie?","back":"Dorso de los dedos, zona palmar, zona plantar y mucosa oral."},{"front":"¿Cuál es el agente causal principal de la herpangina?","back":"Virus Coxsackie A6"},{"front":"¿Cuál es la localización principal de las lesiones ulcerosas en la herpangina?","back":"Pilares amigdalinos y paladar blando."},{"front":"¿Cuál es el principal diagnóstico diferencial de la herpangina?","back":"Estomatitis herpética (donde las vesículas aparecen en las encías)."},{"front":"¿Qué exantemas presentan característicamente afectación en palmas y plantas?","back":"Enfermedad mano-boca-pie y enfermedad de Kawasaki."},{"front":"¿Qué enfermedades exantemáticas se asocian con la presencia de lengua en frambuesa?","back":"Escarlatina y enfermedad de Kawasaki."},{"front":"¿Qué tipo de transmisión es común en la enfermedad mano-boca-pie?","back":"Fecal-oral u oral-oral."},{"front":"¿Cuál es la duración del periodo de incubación de la escarlatina?","back":"De 1 a 7 días."},{"front":"¿Qué estudio se solicita en caso de duda diagnóstica en mano-boca-pie o herpangina en pacientes inmunocomprometidos?","back":"PCR"},{"front":"¿Cuál es la complicación más grave de la rubéola en adultos?","back":"Encefalitis"},{"front":"¿Cuál es el tratamiento de elección para el diagnóstico de sarampión por laboratorio?","back":"Detección de anticuerpos IgM por medio de ELISA."},{"front":"¿Qué antibiótico se recomienda en pacientes con escarlatina alérgicos a la penicilina?","back":"Cefalosporinas, clindamicina o azitromicina."},{"front":"¿Cuál es el rango de temperatura típico en la fase febril de la escarlatina?","back":"39-40 ^{\\circ}C"},{"front":"¿A qué edad es más común la incidencia de rubéola en niños no vacunados?","back":"Escolares de 8 años."},{"front":"¿Qué exantema viral se caracteriza por ser muy pruriginoso y umbilicarse antes de formar costras?","back":"Varicela"},{"front":"¿Qué enfermedad se asocia con descamación periungueal?","back":"Enfermedad de Kawasaki"}]},"23":{"num":23,"name":"URGENCIAS","cards":[{"front":"¿Cuál es el rango de edad con mayor morbimortalidad por aspiración o ingesta de cuerpos extraños?","back":"Niños de 2 a 12 años de edad."},{"front":"Menciona tres de los cuerpos extraños más comunes encontrados en pediatría.","back":"Cacahuates, cereales y granos de maíz."},{"front":"¿Cuál es el factor de riesgo de edad más frecuente para la aspiración de cuerpo extraño?","back":"Edad entre 6 meses y 5 años."},{"front":"¿Cuál es la relación por sexo (hombres:mujeres) en los factores de riesgo de aspiración?","back":"2:1."},{"front":"La tríada clásica de aspiración de cuerpo extraño incluye sibilancias, tos y _____.","back":"Disminución de ruidos respiratorios."},{"front":"¿Cuál es el sitio anatómico de localización más frecuente por aspiración (34%)?","back":"Bronquio principal derecho."},{"front":"¿En qué parte del esófago se localizan con mayor frecuencia (60-75%) los cuerpos extraños ingeridos?","back":"Esfínter esofágico superior."},{"front":"¿Cuál es el estudio de imagen inicial ante la sospecha de aspiración de cuerpo extraño?","back":"Radiografía de tórax en 2 posiciones."},{"front":"¿Cuál es el hallazgo radiológico más común (42%) en una aspiración de cuerpo extraño?","back":"Hiperclaridad distal de la zona de obstrucción."},{"front":"¿Cuál es el Gold Standard para el diagnóstico de aspiración de cuerpo extraño?","back":"Broncoscopia rígida."},{"front":"¿Cuál es el tratamiento de elección para la remoción de un objeto aspirado?","back":"Broncoscopia rígida."},{"front":"¿Qué medida inmediata se debe tomar ante la ingestión de una pila de botón de hidróxido de sodio?","back":"Extraer de forma inmediata."},{"front":"¿Cuál es la vía de exposición más frecuente en las intoxicaciones pediátricas?","back":"Vía digestiva (oral)."},{"front":"¿Cuál es la principal causa de muerte por intoxicación inhalatoria en niños?","back":"Monóxido de carbono."},{"front":"¿Cuál es la vía principal de excreción para la mayoría de los tóxicos?","back":"Riñones (orina)."},{"front":"¿Cuáles son los tres componentes del Triángulo de Valoración Pediátrica?","back":"Apariencia, trabajo respiratorio y circulación."},{"front":"¿Dentro de qué periodo de tiempo es efectivo realizar un lavado gástrico tras la ingesta?","back":"Dentro de la primera hora."},{"front":"¿Qué sustancia produce la mayor cantidad de intoxicaciones según los puntos ENARM?","back":"Etanol."},{"front":"¿Cuál es el medicamento que más se asocia a intoxicaciones en la práctica clínica?","back":"Paracetamol."},{"front":"¿Qué elementos componen el \"cóctel toxicológico\" para pacientes con déficit neurológico desconocido?","back":"Glucosa, oxígeno, naloxona y tiamina."},{"front":"¿Cuál es el metabolito altamente reactivo y hepatotóxico del paracetamol?","back":"N-acetil-para-benzoquinoneimina (NAPQI)."},{"front":"¿Cuál es la dosis terapéutica de paracetamol en pediatría?","back":"10-15 \\text{ mg/kg} cada 6 a 8 horas."},{"front":"¿A partir de qué dosis total se considera una ingesta letal de paracetamol?","back":"Más de 20 gramos."},{"front":"¿Qué síntomas caracterizan la Fase 2 (24-48 horas) de la intoxicación por paracetamol?","back":"Dolor en hipocondrio derecho (CSD), náusea, vómito y aumento de transaminasas."},{"front":"¿Qué herramienta clínica se utiliza para predecir la necesidad de tratamiento con N-acetilcisteína tras una ingesta aguda?","back":"Normograma de Rumack-Matthew."},{"front":"¿A partir de cuántas horas tras la ingesta se deben medir los niveles séricos para usar el normograma de Rumack-Matthew?","back":"4 horas."},{"front":"¿Qué valor de AST indica hepatotoxicidad establecida en el contexto de intoxicación por paracetamol?","back":">1000."},{"front":"¿Cuál es el antídoto específico para la intoxicación por paracetamol?","back":"N-acetilcisteína (NAC)."},{"front":"¿Cuál es la dosis de carga de N-acetilcisteína por vía oral?","back":"140 \\text{ mg/kg}."},{"front":"¿Cuál es la dosis de mantenimiento de N-acetilcisteína vía oral y cada cuánto se administra?","back":"70 \\text{ mg/kg} cada 4 horas."},{"front":"¿Cuál es la dosis de intoxicación aguda por Ácido Acetilsalicílico (AAS)?","back":"150 \\text{ mg/kg}."},{"front":"La intoxicación por salicilatos típicamente causa una acidosis metabólica con anion gap aumentado y una _____.","back":"Alcalosis respiratoria."},{"front":"¿Qué normograma se utiliza para evaluar la severidad de la intoxicación por salicilatos?","back":"Normograma de Done."},{"front":"¿Cuál es la prueba confirmatoria en orina para intoxicación por salicilatos?","back":"Prueba de cloruro férrico (Reactivo de Trinder)."},{"front":"¿Cuál es el objetivo de la administración de bicarbonato de sodio en la intoxicación por salicilatos?","back":"Alcalinización urinaria para aumentar la excreción del tóxico."},{"front":"¿Qué tipo de necrosis producen los agentes corrosivos ácidos?","back":"Necrosis por coagulación."},{"front":"¿Qué tipo de necrosis producen los agentes corrosivos álcalis?","back":"Necrosis por licuefacción."},{"front":"Entre ácidos y álcalis, ¿cuál produce una lesión local más profunda debido a la ausencia de una barrera protectora?","back":"Álcalis."},{"front":"¿Cuál es el Gold Standard diagnóstico para evaluar la extensión del daño por corrosivos?","back":"Endoscopia."},{"front":"¿Qué clasificación endoscópica se utiliza para estadificar las lesiones por cáusticos?","back":"Clasificación de Zargar."},{"front":"¿En qué ventana de tiempo se recomienda realizar la endoscopia tras la ingesta de un corrosivo?","back":"Entre las 6 y las 48 horas."},{"front":"¿Qué grado de la escala de Zargar se caracteriza por úlceras circunscritas, profundas o circunferenciales?","back":"Grado IIb."},{"front":"¿A partir de qué estadio de Zargar se observa necrosis?","back":"Estadio III (IIIa o IIIb)."},{"front":"¿Cuál es la complicación más frecuente a largo plazo de la intoxicación por corrosivos?","back":"Estenosis esofágica."},{"front":"¿Cuál es el nombre alternativo de la intoxicación por plomo?","back":"Saturnismo."},{"front":"¿Cómo se llama el signo clínico consistente en una coloración oscura en las encías por intoxicación por plomo?","back":"Ribete de Burton."},{"front":"¿Cuál es el tratamiento de elección (antídoto) para la intoxicación por plomo?","back":"Penicilamina."},{"front":"¿Qué intoxicación por metales pesados se asocia con diarrea en \"agua de arroz\" y líneas de Mees?","back":"Arsénico."},{"front":"¿Cuál es el antídoto de primera línea para la intoxicación por arsénico y mercurio?","back":"DMSA o DMPS (Succimer)."},{"front":"¿En qué metal pesado se presenta el Ribete de Gilbert como parte del cuadro clínico?","back":"Mercurio."},{"front":"¿Cuál es el antídoto específico para la intoxicación por hierro?","back":"Deferroxamina."},{"front":"¿Qué característica peculiar tiene el aliento de un paciente con intoxicación por cianuro?","back":"Olor a almendras."},{"front":"¿Cuál es el órgano más sensible al daño por intoxicación por plomo?","back":"El Sistema Nervioso Central (SNC)."},{"front":"¿Cuál es el mecanismo de acción principal del plomo en el organismo?","back":"Compite con metales esenciales como el calcio y el zinc."},{"front":"¿Qué riesgo oncológico aumenta 20 años después de una intoxicación por agentes corrosivos?","back":"Carcinoma epidermoide."},{"front":"Menciona una contraindicación absoluta del manejo inicial en intoxicación por corrosivos.","back":"Inducir el vómito (también lavado gástrico y carbón activado)."},{"front":"¿Qué metal pesado se utiliza principalmente para el cromado de automóviles y produce lesiones por contacto?","back":"Cromo."},{"front":"En la intoxicación por paracetamol, ¿qué valor de INR indica falla hepática fulminante?","back":">6.5."},{"front":"¿Cuál es la dosis recomendada de carbón activado en intoxicaciones?","back":"1 \\text{ g/kg}."},{"front":"Según los puntos ENARM, ¿cuál es la droga (no medicamento) que produce mayor cantidad de intoxicaciones?","back":"Etanol."}]},"24":{"num":24,"name":"UROPEDIA","cards":[{"front":"¿Cómo se define la Infección de Vías Urinarias (IVU) en pediatría?","back":"Crecimiento de microorganismos en el tracto urinario asociado a sintomatología clínica compatible."},{"front":"¿Cuál es la principal vía de adquisición de las IVU en el paciente pediátrico?","back":"Vía ascendente."},{"front":"¿Qué criterio define una IVU atípica respecto a la respuesta al tratamiento?","back":"Síntomas persistentes después de 48 horas de haber iniciado el tratamiento."},{"front":"Mencione dos datos de gravedad que caracterizan a una IVU atípica.","back":"Elevación de la creatinina o presencia de masa abdominal."},{"front":"¿Cuál es el agente etiológico responsable del 90% de las IVU pediátricas?","back":"Escherichia coli."},{"front":"¿Qué porcentaje de los recién nacidos prematuros desarrollan ictericia en la primera semana de vida?","back":"El 80%."},{"front":"¿Cuál es el factor de riesgo anatómico masculino relacionado con la IVU?","back":"Fimosis fisiológica."},{"front":"¿Cómo se clasifica una IVU que presenta inflamación de la mucosa vesical, disuria y dolor suprapúbico?","back":"Infección del tracto urinario baja o no complicada (Cistitis)."},{"front":"Definición de Pielonefritis aguda:","back":"Infección piógena difusa de la pelvis y parénquima renal con síntomas sistémicos como fiebre (>38^{\\circ}C)."},{"front":"¿Qué término describe una IVU causada por la reaparición de bacterias en un sitio dentro del tracto urinario?","back":"Infección persistente."},{"front":"¿Cuál es la diferencia entre infección recurrente por mismo patógeno vs. reinfección?","back":"La recurrente es por el mismo patógeno y la reinfección es provocada por otro patógeno."},{"front":"¿Qué condición clasifica automáticamente una IVU como complicada independientemente de otros factores?","back":"La presencia de Pielonefritis."},{"front":"¿Cuáles son los síntomas más frecuentes de IVU en lactantes menores de 3 meses?","back":"Fiebre, vómito, letargia e irritabilidad."},{"front":"¿Qué síntomas de IVU son más frecuentes en niños mayores de 3 meses?","back":"Fiebre, polaquiuria y disuria."},{"front":"¿Cuál es el estándar de oro para el diagnóstico definitivo de IVU?","back":"Urocultivo."},{"front":"¿Qué hallazgos en la tira reactiva sugieren un diagnóstico presuntivo de IVU?","back":"Nitritos positivos y/o esterasa leucocitaria positiva."},{"front":"¿Cuál es el recuento de colonias significativo para diagnóstico de IVU mediante punción suprapúbica?","back":">10,000 UFC/ml."},{"front":"¿Cuál es el recuento de colonias significativo para diagnóstico de IVU mediante cateterismo vesical transuretral?","back":">100,000 UFC/ml."},{"front":"¿Por qué no se debe utilizar la bolsa urinaria para la recolección de urocultivo?","back":"Por el alto riesgo de contaminación de la muestra."},{"front":"¿En qué pacientes pediátricos está indicado el ultrasonido renal como primer estudio de imagen?","back":"En menores de 2 años con su primera IVU o en casos de IVU atípica."},{"front":"¿Cuál es la indicación principal para realizar una Cistouretrografía Miccional (CUGM)?","back":"Pacientes con IVU recurrente, resistencia al tratamiento o anomalías detectadas en USG."},{"front":"¿Qué estudio es el más sensible para detectar cicatrices renales?","back":"Gramagrama renal con Tc-99 (DMSA)."},{"front":"¿Cuál es el tratamiento antibiótico empírico de elección para lactantes menores de 3 meses con IVU?","back":"Hospitalización con Aminoglucósido + Ampicilina."},{"front":"En IVU no complicada en niños de 3 meses a 2 años, ¿cuál es el fármaco de primera elección?","back":"Trimetoprim-Sulfametoxazol (TMP-SMX)."},{"front":"¿Cuál es el tratamiento ambulatorio de elección para una Pielonefritis?","back":"Cefalosporina de tercera generación (Cefixima)."},{"front":"En zonas de alto riesgo de resistencia, ¿qué antibiótico se prefiere para niños menores de 6 años?","back":"Cefalosporinas de segunda generación (Cefalexina) o Amoxicilina."},{"front":"En zonas de alto riesgo de resistencia, ¿qué antibiótico se indica para niños mayores de 6 años?","back":"Fosfomicina."},{"front":"¿Cuándo se debe solicitar un urocultivo de control tras iniciar el tratamiento?","back":"En caso de fiebre persistente o mala evolución clínica a las 48 horas."},{"front":"¿Qué fármacos se utilizan para el tratamiento profiláctico de IVU recurrentes?","back":"Nitrofurantoína, TMP-SMX o Cefalexina por 10-24 semanas."},{"front":"¿Qué define al Reflujo Vesicoureteral (RVU)?","back":"Flujo retrógrado de orina desde la vejiga hacia el tracto urinario superior."},{"front":"¿Cuál es el estudio más específico para el diagnóstico de Reflujo Vesicoureteral?","back":"Cistouretrografía o Cistografía miccional."},{"front":"¿Qué fármaco se asocia a malformaciones del tracto urinario como el mielomeningocele si es ingerido por la madre?","back":"Metotrexato."},{"front":"¿Cómo se define la Criptorquidia?","back":"Entidad caracterizada por la falta de descenso testicular hacia la bolsa escrotal."},{"front":"¿A qué edad gestacional inicia normalmente el descenso testicular?","back":"A las 26 semanas de gestación."},{"front":"¿Cuál es el estándar de oro para el diagnóstico de testículos no palpables?","back":"Laparoscopia."},{"front":"¿Cuál es el rango de edad ideal para realizar una orquidopexia en caso de criptorquidia?","back":"Entre los 6 y 12 meses de edad."},{"front":"¿Qué tipo de hidrocele cambia de tamaño con la actividad y se puede reducir?","back":"Hidrocele comunicante."},{"front":"¿Cuál es la causa más frecuente de escroto agudo en pacientes menores de 12 años?","back":"Torsión del apéndice testicular."},{"front":"¿Qué signo clínico es característico de la torsión del apéndice testicular?","back":"Signo de Fistol (punto azul en el polo superior)."},{"front":"¿Cómo se encuentra el reflejo cremastérico en la torsión del apéndice testicular?","back":"Presente."},{"front":"Definición de Torsión Testicular:","back":"Torsión del cordón espermático que compromete la circulación de sangre."},{"front":"¿Cuál es el signo de Ger en la torsión testicular?","back":"Umbilicación o hoyuelo en el escroto ipsilateral."},{"front":"¿Cómo se encuentra el reflejo cremastérico en la torsión testicular?","back":"Ausente."},{"front":"¿Cuál es el tiempo límite para realizar una destorsión quirúrgica y conservar el testículo en un 80%?","back":"Primeras 5 horas."},{"front":"Concepto: Signo de Angell","back":"Inserción alta de la túnica vaginal en el cordón espermático."},{"front":"¿Qué patología escrotal mejora el dolor al elevar el testículo (Signo de Prehn positivo)?","back":"Epididimitis."},{"front":"¿Cuál es el agente causal más común de la epididimitis en pediatría?","back":"Escherichia coli."},{"front":"¿Qué antibióticos se deben usar en caso de bacterias productoras de betalactamasas de espectro extendido (BLEE)?","back":"Carbapenémicos."},{"front":"¿Cuál es el requisito de Tasa de Filtración Glomerular para poder usar Nitrofurantoína?","back":">45 ml/min."},{"front":"¿Cuál es la duración estándar del tratamiento para una Cistitis?","back":"3 días."},{"front":"¿Cuál es la duración recomendada del tratamiento para una Pielonefritis?","back":"De 7 a 14 días."},{"front":"En el contexto de escroto agudo, ¿cuál es el estudio de imagen estándar de oro?","back":"Ultrasonido Doppler."},{"front":"¿Qué conducta se sigue ante un testículo no descendido unilateral no palpable en un recién nacido?","back":"Cirugía entre los 6 a 12 meses de edad."},{"front":"La tríada de fiebre, vómito e irritabilidad en un lactante <3 meses obliga a descartar:","back":"Infección de vías urinarias."},{"front":"¿Qué factor de riesgo de IVU es específico para niños varones?","back":"Fimosis fisiológica."}]},"25":{"num":25,"name":"CARDIOPEDIA","cards":[{"front":"¿Cómo se define una cardiopatía congénita?","back":"Malformaciones cardíacas o de los grandes vasos presentes desde el nacimiento que se originan en las primeras semanas de gestación."},{"front":"¿Cuál es la cardiopatía congénita más frecuente a nivel mundial?","back":"Comunicación interventricular (CIV)."},{"front":"¿Cuál es la cardiopatía congénita más frecuente en México?","back":"Persistencia del conducto arterioso (PCA)."},{"front":"¿En qué porcentaje aumenta el riesgo de cardiopatía en pacientes con cromosomopatías?","back":"Aumenta en un 30 %."},{"front":"¿En qué rango de tiempo ocurre el cierre fisiológico del conducto arterioso tras el nacimiento?","back":"12 a 72 horas."},{"front":"¿A qué edad ocurre el cierre anatómico del conducto arterioso?","back":"De 15 días a 2 meses."},{"front":"¿A qué edad ocurre el cierre del foramen oval?","back":"3 meses."},{"front":"¿Qué estructura se origina del conducto onfalomesentérico?","back":"Divertículo de Meckel."},{"front":"¿Hacia dónde se dirige el cortocircuito en las cardiopatías acianógenas?","back":"De izquierda a derecha."},{"front":"Mencione tres ejemplos de cardiopatías acianógenas con flujo pulmonar aumentado.","back":"Comunicación interauricular (CIA), comunicación interventricular (CIV) y persistencia del conducto arterioso (PCA)."},{"front":"Mencione dos ejemplos de cardiopatías acianógenas con flujo pulmonar normal.","back":"Coartación aórtica y estenosis pulmonar."},{"front":"¿Cuál es el estudio de diagnóstico inicial para las cardiopatías acianógenas?","back":"Radiografía de tórax."},{"front":"¿Cuál es el estudio de diagnóstico confirmatorio (estándar de oro) para las cardiopatías acianógenas?","back":"Ecocardiograma."},{"front":"En una cardiopatía acianógena, un defecto pequeño se asocia clínicamente con un soplo _____.","back":"Audible."},{"front":"En una cardiopatía acianógena, un defecto grave se asocia clínicamente con un soplo _____.","back":"Leve."},{"front":"¿Cuál es la localización más frecuente de la comunicación interauricular (CIA)?","back":"Ostium secundum."},{"front":"¿Qué hallazgo característico se encuentra en la auscultación del segundo ruido en una CIA?","back":"Desdoblamiento fijo del segundo ruido."},{"front":"¿Cuál es la característica del soplo en una comunicación interauricular?","back":"Mesosistólico eyectivo de baja intensidad en foco pulmonar."},{"front":"¿En qué rango de edad se recomienda el cierre quirúrgico de una CIA si el defecto es > 7 mm?","back":"Entre los 3 y 6 años."},{"front":"¿Cuál es la localización más frecuente de la comunicación interventricular (CIV)?","back":"Perimembranosa."},{"front":"¿Cómo se describe el soplo característico de una comunicación interventricular (CIV)?","back":"Soplo en barra (pansistólico), no irradiado y con frémito palpable."},{"front":"¿En qué situación está contraindicado el cierre de una comunicación interventricular?","back":"En pacientes con Síndrome de Eisenmenger."},{"front":"¿Qué infección congénita se asocia frecuentemente con la persistencia del conducto arterioso (PCA)?","back":"Rubéola."},{"front":"¿Cómo se denomina el soplo característico de la persistencia del conducto arterioso?","back":"Soplo en maquinaria de Gibson."},{"front":"¿Hacia dónde se irradia típicamente el soplo de la persistencia del conducto arterioso?","back":"Hacia la espalda o el cuello."},{"front":"¿Cuál es el tratamiento farmacológico de elección para el PCA en recién nacidos prematuros?","back":"Indometacina o Ibuprofeno."},{"front":"¿Con qué síndrome genético se asocia frecuentemente la coartación de la aorta?","back":"Síndrome de Turner."},{"front":"¿Qué valvulopatía se asocia comúnmente a la coartación de la aorta?","back":"Válvula aórtica bicúspide."},{"front":"¿Cuál es el signo físico clave para sospechar coartación de la aorta?","back":"Diferencia de presiones en extremidades superiores e inferiores de más de 20 mmHg."},{"front":"¿Cuál es la localización anatómica más común de la coartación aórtica?","back":"Yuxtaductal."},{"front":"¿Cómo se llama el signo radiológico característico de la coartación de la aorta?","back":"Signo del 3 (Signo de Roesler)."},{"front":"¿Qué sucede fisiopatológicamente en el Síndrome de Eisenmenger?","back":"Inversión del cortocircuito de izquierda-derecha a derecha-izquierda por aumento de presiones pulmonares."},{"front":"¿Hacia dónde se dirige el cortocircuito en las cardiopatías cianógenas?","back":"De derecha a izquierda."},{"front":"Mencione dos ejemplos de cardiopatías cianógenas con flujo pulmonar aumentado.","back":"Tronco arterioso común y transposición de grandes vasos."},{"front":"Mencione dos ejemplos de cardiopatías cianógenas con flujo pulmonar normal o disminuido.","back":"Tetralogía de Fallot y atresia tricuspídea."},{"front":"¿Cuáles son los cuatro componentes de la Tetralogía de Fallot?","back":"Cabalgamiento de la aorta, CIV, estenosis pulmonar e hipertrofia del ventrículo derecho."},{"front":"¿Cuál es el componente más importante para el pronóstico en la Tetralogía de Fallot?","back":"Etenosis de la arteria pulmonar."},{"front":"¿Cuál es la cardiopatía cianógena más frecuente después del primer año de vida?","back":"Tetralogía de Fallot."},{"front":"¿Qué hallazgo se observa en la radiografía de tórax de un paciente con Tetralogía de Fallot?","back":"Corazón en bota o en zapato sueco."},{"front":"La tríada de la crisis de Fallot incluye: taquipnea, hipoxemia y _____.","back":"Disminución del tono muscular."},{"front":"¿Qué fármaco se utiliza para la prevención de las crisis de hipoxia en la Tetralogía de Fallot?","back":"Propranolol."},{"front":"¿Cuál es el tratamiento quirúrgico paliativo clásico para la Tetralogía de Fallot?","back":"Fístula sistémico-pulmonar de Blalock-Taussig."},{"front":"¿Cuál es la cardiopatía cianógena más frecuente al nacimiento?","back":"Transposición de grandes vasos (TGV)."},{"front":"¿Qué fármaco se administra inicialmente en la TGV para mantener el conducto arterioso permeable?","back":"Prostaglandina E1."},{"front":"¿Cómo se llama el procedimiento con balón para mantener abierto el foramen oval en la TGV?","back":"Septostomía de Rashkind."},{"front":"¿Cuál es la cirugía definitiva de elección para la transposición de grandes vasos?","back":"Cirugía de Jatene (Switch arterial)."},{"front":"¿Qué imagen radiológica es característica de la transposición de grandes vasos?","back":"Corazón en huevo o en un hilo."},{"front":"¿Con qué síndrome genético se asocia frecuentemente el tronco arterioso común?","back":"Síndrome de DiGeorge."},{"front":"¿Cuál es el tratamiento quirúrgico de elección para el tronco arterioso común?","back":"Cirugía de Rastelli."},{"front":"¿En qué anomalía la válvula tricúspide se inserta en una posición más baja de lo normal?","back":"Anomalía de Ebstein."},{"front":"¿Qué síndrome de preexcitación se asocia frecuentemente con la anomalía de Ebstein?","back":"Síndrome de Wolff-Parkinson-White."},{"front":"¿Cuál es el signo radiológico característico de la anomalía de Ebstein?","back":"Corazón en caja o en garrafa."},{"front":"¿Qué técnica quirúrgica se utiliza en la anomalía de Ebstein?","back":"Técnica de Fontan."},{"front":"¿Qué imagen radiológica se observa en el drenaje venoso pulmonar anómalo total?","back":"Signo del muñeco de nieve."},{"front":"¿Por qué se produce el bloqueo de rama derecha en las cardiopatías acianógenas?","back":"Debido a un aumento del flujo de la arteria pulmonar."},{"front":"¿Qué fármaco está contraindicado en pacientes con cardiopatías congénitas según el material?","back":"Salbutamol."},{"front":"¿Qué hallazgo electrocardiográfico define al Síndrome de Jervell Lange-Nielsen?","back":"Intervalos QT largos."},{"front":"¿Qué cardiopatía acianógena puede presentarse como una obstrucción del flujo sistólico sin cianosis?","back":"Coartación aórtica."},{"front":"¿A qué se le denomina 'maquinaria de vapor' en la auscultación cardíaca?","back":"Soplo continuo de la persistencia del conducto arterioso."},{"front":"¿En qué tipo de coartación aórtica es más común encontrar el signo de Roesler en adultos?","back":"Coartación postductal."},{"front":"El tipo de tronco arterioso común más frecuente según Collet y Edwards es el Tipo _____.","back":"I"},{"front":"¿Qué maniobra no farmacológica ayuda a disminuir los precipitantes en una crisis de Fallot?","back":"Posición genupectoral (rodillas al pecho)."},{"front":"¿Cuál es la localización más frecuente de la comunicación interventricular?","back":"Porción perimembranosa."},{"front":"¿Qué nombre recibe el signo radiológico de las muescas costales en la coartación aórtica?","back":"Signo de Roesler."},{"front":"En la anomalía de Ebstein, la inserción baja de la tricúspide provoca la formación de una _____.","back":"Comunicación interauricular (CIA)."},{"front":"Ante un paciente con cianosis intensa al nacimiento y flujo pulmonar aumentado, se debe sospechar en _____.","back":"Transposición de grandes vasos."},{"front":"¿Cuál es la causa del soplo sistólico en el foco pulmonar en la CIA?","back":"Hiperflujo a través de la válvula pulmonar (no por el defecto en sí)."}]},"26":{"num":26,"name":"ESPECIALIDADES PEDIA PARTE 1","cards":[{"front":"¿De qué estructura embrionaria derivan los neuroblastomas?","back":"De la cresta neural."},{"front":"¿Cuál es el tumor sólido maligno más frecuente durante la infancia?","back":"El neuroblastoma."},{"front":"¿En qué sitio anatómico se originan con mayor frecuencia los neuroblastomas?","back":"En la médula adrenal."},{"front":"Mencione los tres genes principales asociados al desarrollo del neuroblastoma.","back":"ALK, PHOX2B y GEN N-MYC."},{"front":"¿Qué porcentaje de los neuroblastomas abdominales cruza la línea media?","back":"El 70%."},{"front":"¿Cuál es el hallazgo patognomónico en la histología de un neuroblastoma?","back":"Pseudorosetas de Homer Wright."},{"front":"¿Qué sustancia es responsable de la diarrea secretora en los síndromes neoplásicos del neuroblastoma?","back":"El Péptido Intestinal Vasoactivo (PIV)."},{"front":"¿En qué consiste el Síndrome de Pepper asociado al neuroblastoma?","back":"Compromiso masivo del hígado en la enfermedad metastásica."},{"front":"¿Cuál es la tríada clínica característica del síndrome opsoclonus-mioclonus?","back":"Ataxia, sacudidas mioclónicas e hipertensión arterial."},{"front":"En el diagnóstico inicial de neuroblastoma, ¿cuál es la característica radiológica típica de la masa abdominal?","back":"Masa abdominal calcificada."},{"front":"¿Cuál es el tumor renal más frecuente en la población pediátrica?","back":"El nefroblastoma (Tumor de Wilms)."},{"front":"¿Cuál es el rango de edad en el que se presenta la máxima incidencia del tumor de Wilms?","back":"Entre los dos y cuatro años de edad."},{"front":"¿A qué alteración cromosómica se asocia frecuentemente el nefroblastoma?","back":"Mutaciones del cromosoma 11p."},{"front":"¿Qué característica diferencia clínicamente la masa del tumor de Wilms de la del neuroblastoma?","back":"La masa del tumor de Wilms no cruza la línea media."},{"front":"¿Cuál es el sitio más frecuente de metástasis en el nefroblastoma?","back":"El pulmón."},{"front":"Mencione los tres componentes histológicos que conforman el nefroblastoma.","back":"Epitelio, blastema y estroma."},{"front":"¿Qué hallazgo ocular no ocular puede asociarse específicamente al tumor de Wilms?","back":"Aniridia."},{"front":"¿Cuál es la piedra angular del tratamiento para el nefroblastoma?","back":"Resección quirúrgica (Nefroureterectomía)."},{"front":"¿Cuál es la neoplasia maligna del sistema nervioso central más frecuente en la infancia después de los tumores embrionarios?","back":"El astrocitoma."},{"front":"¿Qué hallazgo histológico es característico del astrocitoma pilocítico juvenil?","back":"Fibras de Rosenthal."},{"front":"¿Qué diferencia existe en la captación de contraste por resonancia magnética entre el astrocitoma pilocítico y el fibrilar de bajo grado?","back":"El pilocítico capta contraste y el fibrilar no."},{"front":"Mencione dos enfermedades hereditarias asociadas al desarrollo de astrocitomas.","back":"Síndrome de Li-Fraumeni y Neurofibromatosis."},{"front":"¿Cuál es el fármaco quimioterapéutico estándar para los tumores del sistema nervioso central según el material?","back":"Temozolomida."},{"front":"¿Cuál es el tipo de hipersensibilidad implicado en la dermatitis atópica?","back":"Tipo I (mediada por IgE)."},{"front":"¿Qué mutación genética se asocia a la alteración de la barrera cutánea en la dermatitis atópica?","back":"Mutación del gen de la proteína filagrina."},{"front":"En lactantes, ¿cuál es la localización típica de las lesiones por dermatitis atópica?","back":"En la cara (respetando el triángulo nasogeniano) y superficies extensoras."},{"front":"¿Cuál es la localización característica de la dermatitis atópica durante la infancia (niños mayores)?","back":"Pliegues flexores (antecubital y poplíteo)."},{"front":"¿Qué síntoma es indispensable para el diagnóstico de dermatitis atópica?","back":"Prurito."},{"front":"¿Cuál es el nombre de los criterios diagnósticos confirmatorios para la dermatitis atópica?","back":"Criterios de Hanifin y Rajka."},{"front":"¿Cuál es el tratamiento de elección (primera línea farmacológica) para los brotes de dermatitis atópica?","back":"Esteroides tópicos (Hidrocortisona o Fluocinolona)."},{"front":"Mencione un inhibidor de la calcineurina utilizado como segunda línea en dermatitis atópica.","back":"Tacrolimus."},{"front":"¿Qué microorganismo es el principal responsable de la impetiginización en pacientes con dermatitis atópica?","back":"Staphylococcus aureus."},{"front":"¿Cómo se define la hipersensibilidad de Tipo 3?","back":"Formación de inmunocomplejos (Ag-Ac) que precipitan en tejidos."},{"front":"¿Cuál es el agente causal de la dermatitis seborreica relacionado con la inflamación cutánea?","back":"Malassezia furfur (o Candida)."},{"front":"¿Cuál es el tratamiento tópico de elección para la dermatitis seborreica?","back":"Ketoconazol al 2% (gel o crema)."},{"front":"En la dermatitis del pañal, ¿cuál es el factor de riesgo más importante para la alteración del estrato córneo?","back":"La sobrehidratación del área."},{"front":"¿Cuál es la complicación infecciosa más frecuente de la dermatitis del pañal?","back":"Candidosis (infección por Candida)."},{"front":"¿Qué patrón morfológico y topográfico caracteriza a la dermatitis del pañal?","back":"Disposición en W."},{"front":"¿Cuál es el agente etiológico del molusco contagioso?","back":"Molluscipoxvirus (Poxvirus)."},{"front":"Mencione la característica clínica distintiva de las pápulas en el molusco contagioso.","back":"Son pápulas umbilicadas."},{"front":"¿Qué hallazgo histopatológico es considerado el estándar de oro para el diagnóstico de molusco contagioso?","back":"Cuerpos de Henderson-Petterson."},{"front":"¿Cuál es el tratamiento de primera línea para el molusco contagioso?","back":"Imiquimod."},{"front":"¿Qué toxina de Staphylococcus aureus es responsable del Síndrome de Piel Escaldada?","back":"Toxina estafilocócica exfoliativa (ETA o ETB)."},{"front":"¿Qué signo clínico, caracterizado por el desprendimiento de la epidermis al tocar la piel, es positivo en el Síndrome de Ritter?","back":"Signo de Nikolsky."},{"front":"¿Cuál es el tratamiento antibiótico de elección para el Síndrome de Shock Tóxico estafilocócico?","back":"Dicloxacilina (o Vancomicina en caso de resistencia) más Clindamicina."},{"front":"¿Qué característica dermatológica en palmas y plantas es común en el Síndrome de Shock Tóxico?","back":"Exantema maculopapular difuso con afectación palmoplantar."},{"front":"En el manejo de la dermatitis atópica, ¿qué intervención se considera la piedra angular para restaurar la barrera cutánea?","back":"El uso de emolientes."},{"front":"El Síndrome de Shock Tóxico estreptocócico es causado principalmente por qué microorganismo?","back":"Streptococcus pyogenes (Grupo A)."},{"front":"¿A partir de qué edad se recomienda iniciar la ablactación para prevenir atopias según el material?","back":"A partir de los 6 meses de edad."},{"front":"¿Qué tipo de inmunidad caracteriza a la hipersensibilidad de Tipo 4?","back":"Inmunidad celular (mediada por células T)."},{"front":"¿Cuál es la supervivencia del neuroblastoma después del diagnóstico?","back":"Superior al 90%."},{"front":"¿Qué estudio de imagen es la prueba de elección para el diagnóstico de astrocitomas?","back":"Resonancia Magnética (RM)."},{"front":"En la dermatitis seborreica, ¿cómo se le denomina comúnmente a las placas amarillentas y oleosas en el cuero cabelludo?","back":"Costra de lácteo."},{"front":"¿Qué medicamento se utiliza para tratar la dermatitis refractaria según las complicaciones mencionadas?","back":"Ciclosporina."},{"front":"¿Cuál es el periodo de incubación típico del molusco contagioso?","back":"De 2 a 8 semanas."}]},"27":{"num":27,"name":"ESPECIALIDADES PEDIA PARTE 2","cards":[{"front":"¿Cuál es el segundo cáncer de hueso más común en la población pediátrica?","back":"Sarcoma de Ewing."},{"front":"¿En qué grupo étnico y rango de edad es más frecuente el Sarcoma de Ewing?","back":"Caucásicos entre los 10 y 15 años."},{"front":"¿Cuál es la localización anatómica más frecuente del Sarcoma de Ewing?","back":"Diáfisis del fémur."},{"front":"¿Qué traslocación cromosómica es característica del Sarcoma de Ewing?","back":"Traslocación (11;22)."},{"front":"En el Sarcoma de Ewing, el dolor loco-regional suele exacerbarse con el _____.","back":"Ejercicio."},{"front":"¿Cómo se describe el hallazgo radiográfico clásico en el Sarcoma de Ewing?","back":"Imagen en capas de cebolla."},{"front":"¿Qué estudio es de elección para la evaluación local de la extensión de un tumor de Ewing?","back":"Resonancia Magnética (RM)."},{"front":"¿Cuál es el esquema de quimioterapia para el Sarcoma de Ewing de bajo riesgo?","back":"Vincristina, ifosfamida, doxorrubicina y etopósido."},{"front":"¿Cuál es la neoplasia ósea más frecuente en pediatría?","back":"Osteosarcoma."},{"front":"¿En qué rango de edad se presenta típicamente el osteosarcoma?","back":"10 a 25 años."},{"front":"¿Cuál es la localización más común del osteosarcoma?","back":"Tercio distal del fémur y tibia proximal."},{"front":"¿En qué parte anatómica del hueso se origina siempre el osteosarcoma?","back":"Metáfisis ósea."},{"front":"¿Qué hallazgo radiográfico es patognomónico del osteosarcoma?","back":"Imagen en sol naciente."},{"front":"¿Cuál es el método diagnóstico definitivo para el osteosarcoma?","back":"Biopsia a cielo abierto."},{"front":"A diferencia del Sarcoma de Ewing, el dolor en el osteosarcoma se presenta durante el _____.","back":"Descanso y la noche."},{"front":"¿Cuál es el pilar del tratamiento para el osteosarcoma dado que no es sensible a radioterapia?","back":"Quimioterapia neoadyuvante más cirugía más quimioterapia adyuvante."},{"front":"¿Cuál es el agente causal más importante en la artritis séptica (75% de los casos)?","back":"Staphylococcus aureus."},{"front":"¿Cuál es la articulación más frecuentemente afectada por la artritis séptica?","back":"Rodillas (40% de los casos)."},{"front":"¿Cuál es el factor de riesgo más importante para artritis séptica en pacientes pediátricos?","back":"Compromiso inmune."},{"front":"En neonatos y lactantes con sospecha de artritis séptica, se debe buscar intencionadamente la _____.","back":"Posición antiálgica."},{"front":"¿Cuál es el Gold Standard para el diagnóstico de artritis séptica?","back":"Cultivo de aspiración articular."},{"front":"¿Qué hallazgos se observan en la radiografía inicial de una artritis séptica?","back":"Aumento del espacio articular y de los tejidos blandos."},{"front":"¿Cuál es la dosis de dicloxacilina para el tratamiento de artritis séptica en niños < 40\\text{ kg}?","back":"200\\text{ mg/kg/día} en 14 dosis."},{"front":"¿Cuál es la definición de Displasia de Cadera (DDC)?","back":"Anormalidades anatómicas que afectan la articulación coxofemoral, incluyendo el borde acetabular y la posición de la cabeza femoral."},{"front":"¿Qué características definen a un paciente de alto riesgo para Displasia de Cadera?","back":"Sexo femenino, presentación pélvica e historia familiar."},{"front":"¿Cuál es la localización más común de la Displasia de Cadera?","back":"Lado izquierdo."},{"front":"¿Qué signo de exploración física busca luxar la cadera en menores de 3 meses?","back":"Signo de Barlow."},{"front":"¿Qué signo de exploración física busca reducir una cadera luxada en menores de 3 meses?","back":"Signo de Ortolani."},{"front":"¿Qué signo clínico es característico de la DDC en pacientes mayores de 3 meses?","back":"Signo de Galeazzi."},{"front":"¿Qué hallazgo en la marcha se asocia con la displasia de cadera en la etapa de deambulación?","back":"Signo de Trendelenburg."},{"front":"¿En qué momento se recomienda realizar el tamizaje para Displasia de Cadera?","back":"En la primera semana de vida."},{"front":"¿En qué periodo de vida es ideal realizar un ultrasonido de cadera como diagnóstico temprano?","back":"Entre la 4^{\\text{a}} y 6^{\\text{a}} semana."},{"front":"¿A partir de qué edad se recomiendan las proyecciones radiográficas para el diagnóstico de DDC?","back":"Después de los 4 meses."},{"front":"¿Cuál es el tratamiento de primera elección para DDC en menores de 6 meses?","back":"Arnés de Pavlik."},{"front":"¿Qué intervención se indica para DDC en niños de 6 a 24 meses?","back":"Reducción cerrada."},{"front":"¿Qué define al pie plano flexible?","back":"Arco plantar ausente con apoyo, pero presente al estar sin apoyo sobre el medio pie."},{"front":"¿Qué prueba se utiliza para evaluar la flexibilidad del arco en el pie plano?","back":"Prueba de Jack."},{"front":"¿Cuál es el tratamiento para el pie plano flexible asintomático?","back":"No se requiere tratamiento."},{"front":"¿Cuál es la causa del pie plano rígido en menos del 1% de los casos?","back":"Coalición tarsiana o astrágalo vertical."},{"front":"¿Qué síntoma caracteriza al pie plano flexible con tendón de Aquiles corto?","back":"Limitación de la dorsiflexión del tobillo y dolor en la pantorrilla."},{"front":"¿Cuál es el tratamiento inicial para el pie plano flexible con tendón de Aquiles corto?","back":"Ejercicios de estiramiento para relajar la musculatura y plantillas."},{"front":"¿Qué es la Púrpura de Henoch-Schönlein?","back":"Vasculitis de pequeños vasos asociada a inmunocomplejos IgA, siendo la vasculitis sistémica más común en niños."},{"front":"¿Cuál es la tríada clínica clásica de la Púrpura de Henoch-Schönlein?","back":"Artritis, dolor abdominal tipo cólico y exantema purpúrico palpable."},{"front":"¿Cuál es el antecedente clínico común en pacientes con Púrpura de Henoch-Schönlein?","back":"Infecciones previas con desarrollo de febrícula."},{"front":"¿Cuál es el diagnóstico definitivo para la Púrpura de Henoch-Schönlein?","back":"Biopsia que demuestre depósitos de IgA en piel o riñón."},{"front":"¿Qué complicación renal puede ocasionar la Púrpura de Henoch-Schönlein?","back":"Síndrome Nefrítico (glomerulonefritis)."},{"front":"En la Púrpura de Henoch-Schönlein, los _____ aceleran la resolución de los síntomas inflamatorios.","back":"Corticoesteroides."},{"front":"¿Qué caracteriza a la Púrpura Trombocitopénica (PTI) desde el punto de vista fisiopatológico?","back":"Producción de autoanticuerpos antiplaquetarios que aceleran su destrucción."},{"front":"¿Cuál es el cuadro clínico característico de la Púrpura Trombocitopénica?","back":"Petequias, púrpura y hemorragias de mucosas (gingivorragia)."},{"front":"En una biometría hemática de un paciente con PTI, se reportará trombopenia con menos de _____ plaquetas.","back":"150,000."},{"front":"¿Cuál es el tratamiento farmacológico estándar para la Púrpura Trombocitopénica?","back":"Prednisona 1-2\\text{ mg/kg} vía oral por 2-3 semanas."},{"front":"¿Qué tratamiento de primera línea se debe considerar específicamente en lactantes con PTI?","back":"Inmunoglobulina Intravenosa (IgG IV)."}]},"28":{"num":28,"name":"CROMOSOMOPATIAS VIH EN EL BINOMIO","cards":[{"front":"¿Cuál es la prevalencia de anormalidades cromosómicas en la pérdida de embarazos tempranos?","back":"Representan el 50% de los casos."},{"front":"¿Cuál es la cromosomopatía más frecuente y causa principal de retraso mental?","back":"El síndrome de Down (trisomía 21)."},{"front":"¿Cuál es el objetivo primordial del tamizaje de cromosomopatías en el control prenatal?","back":"La detección y manejo oportunos del feto para mejorar supervivencia y calidad de vida."},{"front":"¿A partir de qué edad materna se considera un factor de riesgo para el tamizaje de cromosomopatías?","back":"Igual o mayor a 35 años."},{"front":"¿A partir de qué edad paterna se considera un factor de riesgo para el tamizaje de cromosomopatías?","back":"Igual o mayor a 45 años."},{"front":"En el ultrasonido del primer trimestre, ¿cuál es el marcador de mayor importancia para la detección de cromosomopatías?","back":"La translucencia nucal."},{"front":"¿Qué hallazgo en el hueso nasal sugiere una cromosomopatía durante el tamizaje?","back":"Su ausencia o hipoplasia."},{"front":"En el segundo trimestre, ¿cuál es el marcador ecográfico más sensible para la detección de cromosomopatías?","back":"La hipoplasia nasal."},{"front":"¿Qué medida del pliegue nucal se considera anormal en el tamizaje ecográfico?","back":"Un valor mayor a 6 mm."},{"front":"¿En qué consiste el 'Duo Test' realizado durante el primer trimestre?","back":"En la medición de \\beta-HCG (elevada) y PAPP-A (disminuida)."},{"front":"¿Qué parámetros componen el 'Cuádruple Test' del segundo trimestre?","back":"\\beta-HCG, estriol, alfafetoproteína e inhibina."},{"front":"¿Cuál es el periodo gestacional recomendado para realizar una biopsia corial?","back":"Entre la semana 9 a 13 de gestación."},{"front":"¿Cuál es el periodo gestacional para realizar una amniocentesis según la GPC?","back":"De la semana 16 a la 20."},{"front":"¿A partir de qué semana de gestación se puede realizar la cordocentesis?","back":"A partir de la semana 20."},{"front":"¿Cuál técnica invasiva de diagnóstico prenatal tiene el mayor riesgo de aborto?","back":"La biopsia corial."},{"front":"¿Qué técnica invasiva permite medir la maduración pulmonar a las 32 semanas de gestación?","back":"La amniocentesis."},{"front":"En el síndrome de Down, ¿cuál es el dato clínico más frecuente?","back":"El perfil facial plano."},{"front":"¿Cómo se denominan los criterios utilizados para el diagnóstico clínico del síndrome de Down?","back":"Criterios de Hall."},{"front":"¿Cuál es la cardiopatía congénita más frecuentemente asociada al síndrome de Down?","back":"Defectos del canal auriculoventricular (CIA/CIV)."},{"front":"¿Qué patología hematológica requiere seguimiento intencionado en pacientes con síndrome de Down?","back":"Leucemias."},{"front":"Defina el mosaicismo en el contexto del síndrome de Down.","back":"Es la presencia de la trisomía en algunas células, mientras otras son normales (46,XX/47,XX,+21)."},{"front":"¿Qué alteración cromosómica define al síndrome de Edwards?","back":"La presencia de un cromosoma 18 extra (47,XX/XY, +18)."},{"front":"¿Cuál es la segunda trisomía autosómica más frecuente después del síndrome de Down?","back":"El síndrome de Edwards."},{"front":"¿Qué característica de las manos es típica del síndrome de Edwards?","back":"Manos con dedos superpuestos."},{"front":"¿Cómo se describe la malformación de los pies característica del síndrome de Edwards?","back":"Pies en mecedora."},{"front":"¿Cuál es el pronóstico de supervivencia para un neonato con síndrome de Edwards?","back":"Alta mortalidad temprana, generalmente dentro del primer año de vida."},{"front":"¿Qué trisomía se caracteriza por la presencia de un cromosoma 13 extra?","back":"El síndrome de Patau."},{"front":"¿Qué malformación del sistema nervioso central, consistente en el fallo de separación de los hemisferios, es común en el síndrome de Patau?","back":"Holoprosencefalia."},{"front":"En el síndrome de Patau, ¿qué anomalías faciales graves pueden presentarse en casos severos?","back":"Hipotelorismo o ciclopía."},{"front":"¿Cuál es el cariotipo clásico del síndrome de Klinefelter?","back":"47, XXY."},{"front":"¿Cuál es el fenotipo físico característico de un paciente con síndrome de Klinefelter respecto a su talla?","back":"Talla alta con extremidades largas."},{"front":"¿Qué hallazgos se esperan en el perfil hormonal de un paciente con síndrome de Klinefelter?","back":"Testosterona baja con gonadotropinas (FSH, LH) elevadas."},{"front":"¿Cuál es el pilar del tratamiento farmacológico en el síndrome de Klinefelter para mejorar la masa ósea y caracteres sexuales?","back":"Reemplazo con testosterona."},{"front":"¿Qué gen y en qué cromosoma se encuentra mutado en el síndrome de Marfan?","back":"Gen de la fibrilina-1 (FBN1) en el cromosoma 15."},{"front":"¿Cuál es el patrón de herencia del síndrome de Marfan?","back":"Autosómica dominante."},{"front":"En el síndrome de Marfan, ¿qué término describe la presencia de dedos desproporcionadamente largos y delgados?","back":"Aracnodactilia."},{"front":"¿Hacia dónde suele ocurrir la subluxación del cristalino en el síndrome de Marfan?","back":"Hacia arriba y afuera."},{"front":"¿Cuál es la principal causa de morbimortalidad en pacientes con síndrome de Marfan?","back":"Aneurisma o disección de la raíz aortica."},{"front":"¿Qué criterios diagnósticos se utilizan para el síndrome de Marfan?","back":"Criterios de Ghent."},{"front":"¿A partir de qué diámetro de la raíz aórtica dilatada se indica la cirugía en el síndrome de Marfan?","back":"Mayor a 50 mm."},{"front":"¿Qué porcentaje de probabilidad de transmisión vertical de VIH existe en una madre sin tratamiento antirretroviral?","back":"Del 15 al 40%."},{"front":"¿Cuál es el momento de mayor frecuencia para la transmisión del VIH de madre a hijo?","back":"El periodo periparto (alrededor del 70% de los casos)."},{"front":"¿En qué porcentaje incrementa la lactancia materna el riesgo de transmisión de VIH?","back":"Hasta en un 22%."},{"front":"¿Qué cifra de linfocitos CD4 se considera un factor de riesgo para la transmisión vertical de VIH?","back":"Un recuento menor a 200 células/mm^{3}."},{"front":"Si una paciente embarazada con factores de riesgo resulta negativa en su prueba rápida de VIH, ¿cuál es la conducta a seguir?","back":"Repetir la prueba inmediatamente; si sale negativa, repetir en 3 meses."},{"front":"¿Cuáles son los estudios confirmatorios que se realizan tras una prueba rápida de VIH positiva en el embarazo?","back":"ELISA seguido de Western Blot."},{"front":"¿Cuál es el esquema de tratamiento para una embarazada con VIH que nunca ha recibido TARV y tiene una carga viral < 100,000?","back":"Zidovudina + Lamivudina + Lopinavir/Ritonavir."},{"front":"¿Qué fármaco antirretroviral debe evitarse durante las primeras 8 semanas de embarazo debido a la organogénesis?","back":"Efavirenz."},{"front":"¿Bajo qué condiciones se indica el parto vaginal en una paciente con VIH?","back":"Carga viral menor a 50 copias, tratamiento con triple ARV y buen control."},{"front":"¿En qué momento debe iniciarse la Zidovudina IV en una embarazada programada para cesárea por VIH?","back":"Tres horas antes de la incisión."},{"front":"¿Por qué no se debe realizar ELISA o Western Blot para el diagnóstico de VIH en neonatos menores de 18 meses?","back":"Debido a que los anticuerpos maternos cruzan la barrera placentaria y pueden dar falsos positivos."},{"front":"¿Cómo se excluye definitivamente la infección por VIH en un niño menor de 18 meses?","back":"Con dos o más estudios virológicos negativos a los 6 meses de vida (sin lactancia materna)."},{"front":"¿Cuál es la profilaxis posnatal para un recién nacido de madre con TARV y supresión viral efectiva?","back":"Zidovudina durante 4 semanas."},{"front":"¿Qué esquema de profilaxis recibe el neonato si la madre solo recibió TARV intraparto?","back":"Zidovudina por 6 semanas más 3 dosis de Nevirapina."},{"front":"¿Cuál es el manejo para un recién nacido de madre que no recibió TARV en ningún momento?","back":"Zidovudina (6 sem) + Nevirapina (dosis única) + Lamivudina (1 sem)."},{"front":"¿Qué fármacos componen el tratamiento del lactante en caso de confirmarse la infección por VIH?","back":"Abacavir + Lamivudina + Dolutegravir."},{"front":"¿En qué semana de gestación se debe realizar la cesárea programada en pacientes con VIH y carga viral > 50 copias?","back":"En la semana 38 de gestación."},{"front":"En el síndrome de Down, ¿qué alteración de los pabellones auriculares es común?","back":"Implantación baja."},{"front":"¿Qué marcador ecográfico del segundo trimestre se asocia a síndrome de Down pero tiene baja especificidad de forma aislada?","back":"Foco ecogénico intracardiaco."},{"front":"En el síndrome de Edwards, ¿qué nombre recibe la prominencia de la parte posterior del cráneo?","back":"Occipucio prominente."}]}},"medicina":{"1":{"num":1,"name":"INTRODUCCION A MI","cards":[{"front":"¿Cuál es el mecanismo de acción de las tetraciclinas?","back":"Bloquean la síntesis de proteínas uniéndose a la subunidad 30S ribosomal."},{"front":"Mencione tres efectos secundarios importantes de las tetraciclinas.","back":"Efecto disulfiram, neutropenia y neuropatía periférica."},{"front":"¿Cómo inhiben la síntesis proteica los aminoglucósidos?","back":"Se unen a la subunidad 30S ribosomal."},{"front":"¿Cuáles son los dos efectos adversos más característicos de los aminoglucósidos?","back":"Nefrotoxicidad y ototoxicidad."},{"front":"Verdadero o Falso: Los aminoglucósidos deben emplearse habitualmente en monoterapia.","back":"Falso; no se deben emplear en monoterapia."},{"front":"¿Cuál es el mecanismo de acción de los macrólidos (ej. Eritromicina)?","back":"Bloquean la síntesis de proteínas uniéndose a la subunidad 50S ribosomal."},{"front":"¿Qué efectos secundarios se asocian al uso de macrólidos?","back":"Diplopía y hepatotoxicidad."},{"front":"¿Cuál es el principal efecto secundario de las lincosamidas como la clindamicina?","back":"Colitis por C. difficile."},{"front":"El síndrome del niño gris y la anemia aplásica son efectos secundarios de _____.","back":"Cloranfenicol"},{"front":"¿Cómo actúan las fluoroquinolonas en las bacterias Gram negativas?","back":"Inhiben la síntesis de ácidos nucleicos mediante el bloqueo de la girasa."},{"front":"¿Qué estructuras anatómicas pueden verse afectadas gravemente por el uso de fluoroquinolonas?","back":"Los tendones (riesgo de tendinitis y ruptura de tendones)."},{"front":"¿Qué alteración en el electrocardiograma pueden causar las fluoroquinolonas?","back":"Prolongación del intervalo QT."},{"front":"¿Cuál es el mecanismo de acción de los glucopéptidos como la vancomicina?","back":"Inhiben la incorporación de mureína al peptidoglicano de la pared celular."},{"front":"Concepto: Síndrome de hombre rojo","back":"Definición: Reacción adversa característica de los glucopéptidos (vancomicina) por infusión rápida."},{"front":"¿Cuál es el mecanismo de acción de los nitroimidazoles (ej. Metronidazol)?","back":"Efecto citotóxico mediado por la formación de radicales libres."},{"front":"¿Cómo interfieren las sulfamidas en el metabolismo bacteriano?","back":"Interfieren en la síntesis de ácido fólico."},{"front":"Mencione una complicación cutánea grave asociada a las sulfamidas.","back":"Síndrome de Stevens-Johnson."},{"front":"¿Cuáles son los criterios de temperatura para el Síndrome de Respuesta Inflamatoria Sistémica (SRIS)?","back":">38 \\, ^{\\circ}C o <36 \\, ^{\\circ}C."},{"front":"¿Qué valor de frecuencia respiratoria (FR) se requiere para cumplir un criterio de SRIS?","back":"FR > 20 \\, rpm."},{"front":"¿Qué niveles de leucocitos definen un criterio de SRIS?","back":">12,000 o <4,000."},{"front":"¿Cómo se define la Sepsis según el material?","back":"Presencia de SRIS más la sospecha de un foco infeccioso."},{"front":"¿Qué diferencia a la Sepsis Grave de la Sepsis convencional?","back":"La Sepsis Grave incluye disfunción orgánica o anormalidades de la perfusión."},{"front":"¿Qué caracteriza al Choque Séptico?","back":"Sepsis grave con hipotensión que no responde a la administración de líquidos."},{"front":"Concepto: Choque Séptico Refractario","back":"Definición: Choque que dura más de 1 hora y no responde a vasopresores."},{"front":"¿Cuántos puntos debe aumentar la escala de SOFA para definir Disfunción Orgánica Múltiple?","back":"Un aumento mayor de 2 puntos."},{"front":"¿Cuál es la utilidad clínica principal de la escala SOFA?","back":"Determinar el pronóstico del paciente."},{"front":"¿Cuáles son los tres criterios que componen la escala qSOFA?","back":"Alteración de la conciencia, taquipnea e hipotensión."},{"front":"¿Qué puntaje en la Escala de Glasgow se considera criterio en el qSOFA?","back":"Glasgow \\leq 13 puntos."},{"front":"¿Cuál es el punto de corte de la frecuencia respiratoria en el qSOFA?","back":"\\geq 22 \\, rpm."},{"front":"¿Qué valor de tensión arterial sistólica es criterio para qSOFA?","back":"\\leq 100 \\, mmHg."},{"front":"¿Cuál es la meta de Presión Arterial Media (PAM) en la reanimación de sepsis?","back":"\\geq 65 \\, mmHg."},{"front":"Mencione la fórmula para calcular la Presión Arterial Media (PAM).","back":"PAM = \\frac{(2 \\times \\text{Diastólica}) + \\text{Sistólica}}{3}"},{"front":"¿Cuál es la meta de gasto urinario (GU) en el tratamiento de sepsis?","back":"0.5 \\, mL/kg/hr."},{"front":"¿Qué reactante de fase aguda tiene un valor pronóstico específico en sepsis y se eleva tras 6 horas?","back":"Procalcitonina."},{"front":"¿En qué lapso de tiempo se debe iniciar el antibiótico en sepsis (Hora Dorada)?","back":"Dentro de la primera hora del diagnóstico."},{"front":"¿Qué cantidad de cristaloides se recomienda infundir inicialmente y en cuánto tiempo?","back":"1000 \\, cc en un lapso de 30 minutos."},{"front":"¿Cuál es el umbral de hemoglobina (Hb) para iniciar una transfusión de concentrados eritrocitarios en sepsis?","back":"Hb < 7 \\, g/dL."},{"front":"¿Cuándo está indicada la transfusión de plaquetas en un paciente con sepsis?","back":"Cuando están <5,000 o si hay presencia de sangrado activo."},{"front":"¿Cuáles son los vasopresores de elección mencionados para mantener la meta de PAM?","back":"Dopamina o Norepinefrina."},{"front":"¿En qué situación clínica se debe emplear Dobutamina en sepsis?","back":"Cuando existe evidencia de disfunción miocárdica."},{"front":"¿Cuándo se indica el uso de Hidrocortisona en el manejo del choque?","back":"En casos de hipotensión persistente."},{"front":"¿Qué fármacos esteroides están contraindicados específicamente en el manejo de sepsis según el material?","back":"Dexametasona y Metilprednisolona."},{"front":"¿Cómo se define la Fiebre de Origen Desconocido (FOD) en adultos?","back":"Temperatura >38.5 \\, ^{\\circ}C por más de 3 semanas sin diagnóstico tras estudios básicos."},{"front":"¿Cuál es la definición de FOD en pacientes pediátricos?","back":"Temperatura persistente por más de 2 semanas sin diagnóstico."},{"front":"¿Qué sospecha diagnóstica principal se debe tener en un lactante con fiebre sin foco?","back":"Infección de Vías Urinarias (IVU)."},{"front":"¿Cuál es la principal sospecha de FOD en la población pediátrica general?","back":"Neoplasias, específicamente leucemias."},{"front":"¿Cuál es la causa infecciosa más común de FOD en adultos?","back":"Tuberculosis."},{"front":"¿Qué patologías se deben sospechar primordialmente en pacientes geriátricos con FOD?","back":"Cáncer colorrectal o tumores sólidos intestinales."},{"front":"¿Cuál es el abordaje inicial recomendado para descartar causas de FOD?","back":"Historia clínica, examen físico, descartar presentaciones atípicas y pruebas de imagen (Rx o TAC)."},{"front":"¿En qué casos se recomienda realizar una biopsia de médula ósea en el estudio de FOD?","back":"Principalmente en niños."},{"front":"¿Qué estudio de imagen funcional se menciona como complemento en el abordaje de FOD?","back":"PET o gammagrafía de leucocitos marcados con In^{111}."},{"front":"Mencione las tres categorías generales de causas de FOD.","back":"Infecciones, neoplasias y vasculitis (enfermedades reumatológicas)."},{"front":"¿Qué detecta y cuantifica la prueba ELISA?","back":"Anticuerpos o antígenos en una muestra sanguínea."},{"front":"¿Para qué se utiliza comúnmente la prueba Western Blot?","back":"Para confirmar resultados positivos de ELISA, especialmente en VIH."},{"front":"Definición: Inmunofluorescencia","back":"Uso de anticuerpos marcados con tintes fluorescentes para detectar antígenos o anticuerpos."},{"front":"¿En qué principio biológico se basan las pruebas de aglutinación?","back":"En la aglomeración de partículas recubiertas de antígeno o anticuerpo al reaccionar con la muestra."},{"front":"¿Qué gasometría es típica encontrar en la sepsis y qué indica?","back":"Hipocapnia, a menudo asociada a un índice PaO2/FiO2 < 300 \\, mmHg."},{"front":"¿Qué estudio de laboratorio se debe realizar cada 24 horas para vigilar la falla renal en sepsis?","back":"Creatinina sérica."},{"front":"¿Cuál es la recomendación sobre el inicio de antibióticos en FOD?","back":"No instaurar tratamiento antibiótico sin un foco infeccioso claro."},{"front":"En el contexto de FOD, ¿cuál es el sitio de biopsia preferido en adultos si el abordaje inicial falla?","back":"Hígado."},{"front":"¿Qué valor de ácido láctico (lactato) se busca monitorizar en sepsis como marcador de gravedad?","back":"Lactato elevado (asociado a hipoperfusión tisular)."},{"front":"¿Qué profilaxis farmacológica se menciona como parte del soporte en sepsis?","back":"Profilaxis para Trombosis Venosa Profunda (TVP) e inhibidores de la bomba de protones (IBP)."},{"front":"¿Cuál es la posición recomendada de la cabeza del paciente en ventilación mecánica por sepsis?","back":"Elevada entre 30 y 45 grados."}]},"2":{"num":2,"name":"TUBERCULOSIS","cards":[{"front":"¿Cuál es el agente causal principal de la tuberculosis?","back":"Complejo Mycobacterium\\ tuberculosis"},{"front":"Mencione tres especies, además de M.\\ tuberculosis, que integran el complejo causante de la tuberculosis.","back":"M.\\ bovis, M.\\ microti y M.\\ africanum"},{"front":"¿Qué porcentaje de los casos de tuberculosis suelen ser de localización pulmonar?","back":"84%"},{"front":"¿Cuáles son los tres estados de México con mayor afectación por tuberculosis?","back":"Baja California, Sinaloa y Sonora"},{"front":"¿Cuál es la principal característica de tinción del bacilo de la tuberculosis?","back":"Bacilo ácido-alcohol resistente (BAAR)"},{"front":"¿Cuánto tiempo suele tardar el inicio de la replicación de las micobacterias tras la inhalación de partículas?","back":"De 14 a 21 días"},{"front":"¿Cuál es la comorbilidad asociada más frecuente en pacientes con tuberculosis en México?","back":"Diabetes (20%)"},{"front":"¿Qué porcentaje de pacientes con tuberculosis en México presenta desnutrición como comorbilidad?","back":"13%"},{"front":"¿Qué porcentaje de los contactos de un caso activo desarrollarán tuberculosis latente?","back":"30-40%"},{"front":"¿Cuál es la forma más frecuente de tuberculosis extrapulmonar?","back":"Adenitis tuberculosa (linfadenitis)"},{"front":"¿Cuál es el síntoma respiratorio cardinal de la tuberculosis pulmonar?","back":"Tos productiva por más de 2 semanas"},{"front":"¿Cuál es el rango típico de pérdida de peso en un paciente con clínica de tuberculosis?","back":"De 2 a 8 kg"},{"front":"¿Cuál es el signo clínico característico de tuberculosis en niños?","back":"Falta de crecimiento"},{"front":"¿A cuántos microgramos equivale la carga infectante necesaria para desarrollar tuberculosis?","back":"50 a 200 \\mu g inhalados"},{"front":"¿Cuál es la manifestación cutánea más frecuente de la tuberculosis?","back":"Lupus vulgar"},{"front":"¿Con qué frecuencia se debe realizar la notificación de un caso de tuberculosis pulmonar?","back":"Semanal"},{"front":"¿Con qué frecuencia se debe realizar la notificación de un caso de tuberculosis meníngea?","back":"Inmediata"},{"front":"¿Qué hallazgo auscultatorio es típico del síndrome cavitario en tuberculosis?","back":"Soplo anfórico"},{"front":"¿Qué hallazgo se espera a la percusión en un paciente con síndrome cavitario?","back":"Matidez"},{"front":"¿Cuál es la principal causa de Fiebre de Origen Desconocido (FOD) según el material?","back":"Tuberculosis"},{"front":"¿En qué porcentaje previene la vacuna BCG la tuberculosis pulmonar?","back":"50%"},{"front":"¿Cuántos días de incapacidad se requieren típicamente para esta patología?","back":"30 días"},{"front":"¿Cuál es la causa más frecuente de insuficiencia suprarrenal (enfermedad de Addison) en México?","back":"Tuberculosis"},{"front":"¿Cuál es el estudio de elección inicial para el diagnóstico y seguimiento de tuberculosis pulmonar?","back":"Baciloscopía (BAAR) en serie de 3 muestras"},{"front":"¿Qué tinción se utiliza específicamente para la baciloscopía en tuberculosis?","back":"Tinción de Ziehl-Neelsen"},{"front":"Si la primera baciloscopía es negativa pero hay sospecha clínica, ¿cuándo se debe realizar la prueba adicional?","back":"1 a 3 semanas después"},{"front":"¿Cuál es el estándar de oro (gold standard) para el diagnóstico de tuberculosis?","back":"Cultivo de Löwenstein-Jensen"},{"front":"¿Cuál es el tiempo promedio para obtener resultados de un cultivo de Löwenstein-Jensen?","back":"4 a 6 semanas"},{"front":"¿En qué tipo de tuberculosis es de elección realizar un cultivo?","back":"Tuberculosis extrapulmonar"},{"front":"¿Cuál es la prueba diagnóstica con mayor sensibilidad y rapidez para tuberculosis pulmonar?","back":"PCR (Reacción en Cadena de la Polimerasa)"},{"front":"¿Qué fármacos componen la fase intensiva del tratamiento primario?","back":"Isoniazida, Rifampicina, Pirazinamida y Etambutol"},{"front":"¿Cuál es la duración y el número de dosis de la fase intensiva del tratamiento primario?","back":"2 meses (60 dosis)"},{"front":"¿Qué fármacos se utilizan en la fase de sostén del tratamiento primario?","back":"Isoniazida y Rifampicina"},{"front":"¿Cuál es la duración y el número de dosis de la fase de sostén del tratamiento primario?","back":"4 meses (45 dosis)"},{"front":"¿Con qué frecuencia se administran las dosis en la fase de sostén del tratamiento?","back":"3 días a la semana"},{"front":"Mencione tres fármacos considerados de segunda línea para tuberculosis resistente.","back":"Amikacina, Levofloxacino y Cicloserina"},{"front":"¿En qué mes de tratamiento una baciloscopía positiva obliga a solicitar pruebas de resistencia?","back":"Al segundo o tercer mes"},{"front":"¿Cuál es la duración total del tratamiento para tuberculosis ósea?","back":"9 meses"},{"front":"¿Cuál es la duración total del tratamiento para tuberculosis meníngea o miliar?","back":"12 meses"},{"front":"¿Cuál es el esquema de tratamiento indicado para pacientes embarazadas o en lactancia?","back":"Isoniazida y Rifampicina por 9 meses"},{"front":"¿Cuál es el nombre del fármaco que combina el esquema RIPE en un solo comprimido?","back":"Dotbal"},{"front":"¿Con qué frecuencia se deben realizar las baciloscopías de seguimiento durante el tratamiento?","back":"Mensual"},{"front":"¿Cuáles son los tres principales efectos adversos de la Rifampicina?","back":"Hepatotoxicidad, síndrome pseudogripal y color anaranjado de fluidos"},{"front":"¿Qué interacción farmacológica importante tiene la Rifampicina con las mujeres en edad fértil?","back":"Inhibe la acción de los anticonceptivos orales"},{"front":"¿Cuál es el mecanismo de acción de la Rifampicina?","back":"Inhibe la RNA polimerasa"},{"front":"¿Cuál es el efecto adverso no hepático más importante de la Isoniazida?","back":"Neuritis periférica"},{"front":"¿Qué suplemento vitamínico se debe administrar junto con la Isoniazida para prevenir la neuritis?","back":"Piridoxina (B_{6})"},{"front":"¿Cuál es el mecanismo de acción de la Isoniazida?","back":"Inhibe la síntesis de ácidos micólicos"},{"front":"¿Qué trastorno metabólico puede causar la Pirazinamida?","back":"Hiperuricemia (puede desencadenar gota)"},{"front":"¿Cuál es el mecanismo de acción de la Pirazinamida a nivel celular?","back":"Acidifica el interior del macrófago"},{"front":"¿Cuál es el efecto adverso característico del Etambutol?","back":"Neuritis óptica (disminución de agudeza visual)"},{"front":"¿Cuál es el principal efecto adverso de la Estreptomicina?","back":"Afectación del VIII par craneal (ototoxicidad)"},{"front":"¿Por qué está contraindicada la Estreptomicina durante el embarazo?","back":"Por riesgo de ototoxicidad fetal"},{"front":"¿Cuál es el diagnóstico de elección para la tuberculosis latente?","back":"Prueba de tuberculina (Intradermorreacción de Mantoux)"},{"front":"¿Dónde se aplica anatómicamente la prueba de PPD?","back":"Unión del tercio distal y proximal en la cara posterolateral del antebrazo"},{"front":"¿Cuál es el punto de corte en milímetros para considerar PPD positivo en un paciente con VIH?","back":"> 5 mm"},{"front":"¿Cuál es el punto de corte en milímetros para considerar PPD positivo en la población general?","back":"> 10 mm"},{"front":"Tras una prueba de PPD positiva, ¿cuál es el siguiente paso antes de iniciar quimioprofilaxis?","back":"Realizar radiografía de tórax para descartar tuberculosis activa"},{"front":"¿Cuál es el tratamiento de elección para la tuberculosis latente?","back":"Isoniazida por 6 meses"},{"front":"¿Cuál es la duración del tratamiento de tuberculosis latente en pacientes inmunocomprometidos?","back":"9 meses"},{"front":"Mencione un esquema alternativo para tuberculosis latente además de la monoterapia con Isoniazida.","back":"Isoniazida con Rifampicina por 4 meses"},{"front":"¿En qué grupo de edad se indica quimioprofilaxis a todos los contactos, sin importar el estado de vacunación?","back":"Menores de 5 años"},{"front":"¿Cómo se define la tuberculosis latente?","back":"Infección por micobacterias sin presentar signos o síntomas de la enfermedad"},{"front":"¿Cuál es el término médico para la linfadenitis tuberculosa cervical?","back":"Escrófula"},{"front":"¿Cuál es el método diagnóstico de elección para la linfadenitis tuberculosa?","back":"Biopsia"},{"front":"¿Cuál es la tríada clínica clásica de la tuberculosis genitourinaria en el examen de orina?","back":"Piuria estéril, orina ácida y hematuria"},{"front":"¿Qué órgano se afecta con mayor frecuencia en la tuberculosis genitourinaria masculina?","back":"Epidídimo"},{"front":"¿Cuál es la complicación más grave de la tuberculosis en las trompas de Falopio?","back":"Esterilidad"},{"front":"¿Qué nombre recibe la tuberculosis ósea que afecta la columna dorsal?","back":"Mal de Pott"},{"front":"¿Cuáles son las tres consecuencias físicas del Mal de Pott?","back":"Destrucción de cuerpos vertebrales, dolor y xifosis"},{"front":"¿Qué porción del tracto digestivo se ve afectada con mayor frecuencia en la tuberculosis abdominal?","back":"Íleon terminal"},{"front":"¿Qué fármaco se debe agregar al tratamiento en casos de tuberculosis abdominal o meníngea?","back":"Esteroides"},{"front":"¿A qué se debe la tuberculosis miliar?","back":"Diseminación sanguínea (hematógena) de las micobacterias"},{"front":"¿Cuál es el dato patognomónico de la tuberculosis miliar observable en el examen físico?","back":"Tubérculos en la coroides del fondo de ojo"},{"front":"¿Cuál es la forma más letal de tuberculosis extrapulmonar?","back":"Tuberculosis meníngea"},{"front":"¿Cuáles son las tres características bioquímicas del Líquido Cefalorraquídeo (LCR) en la tuberculosis meníngea?","back":"Linfocitosis, hipoglucorraquia e hiperproteinorraquia"},{"front":"¿Qué porcentaje de pacientes con tuberculosis meníngea presentan secuelas?","back":"Hasta el 25%"},{"front":"¿Cuál es la causa más común de fracaso al tratamiento primario?","back":"Incumplimiento terapéutico"}]},"3":{"num":3,"name":"VIH","cards":[]},"4":{"num":4,"name":"ENFERMEDADES TRANSMITIDAS POR VECTOR","cards":[{"front":"¿A qué género pertenece el virus del Dengue?","back":"Pertenece al género Flavivirus."},{"front":"¿Cuáles son los serotipos existentes del virus del Dengue (DENV)?","back":"Existen 4 serotipos, del DENV-1 al DENV-4."},{"front":"¿Qué especie de mosquito es el vector más importante del Dengue en México?","back":"El Aedes aegypti."},{"front":"¿Cuáles son las tres proteínas estructurales del virus del Dengue?","back":"Son las proteínas P, M y E."},{"front":"¿Cuál es el periodo de incubación promedio del Dengue?","back":"El periodo de incubación es de 4 a 7 días (rango de 3 a 14 días)."},{"front":"¿Cuál es el principal factor de riesgo para desarrollar Dengue grave?","back":"El antecedente de una infección previa por Dengue."},{"front":"¿Qué característica dermatológica típica aparece en la fase febril del Dengue?","back":"Eritema con apariencia de \"islas blancas en un mar rojo\"."},{"front":"¿En qué fase del Dengue ocurre la fuga plasmática?","back":"Ocurre en la fase de defervescencia o fase crítica."},{"front":"Definición: Dengue sin datos de alarma","back":"Paciente en fase febril con al menos 2 síntomas (náusea, exantema, cefalea, dolor retroocular o artralgias)."},{"front":"Definición: Dengue grave","back":"Presencia de choque, hemorragia grave o afectación orgánica severa (hepática, encefalitis)."},{"front":"¿Qué dato clínico caracteriza al Dengue con datos de alarma respecto al abdomen?","back":"Dolor abdominal intenso y vómitos persistentes."},{"front":"¿Cuál es la prueba confirmatoria diagnóstica de Dengue durante los primeros 5 días de fiebre?","back":"La detección del antígeno NS1 en suero."},{"front":"¿A partir de qué día se debe solicitar la detección de anticuerpos IgM para Dengue?","back":"A partir del sexto día de iniciada la fiebre."},{"front":"¿Cuál es el Gold Standard para el diagnóstico de Dengue?","back":"La prueba de PCR en tiempo real."},{"front":"¿Qué hallazgo hace que la prueba de torniquete se considere positiva?","back":"La presencia de 20 o más petequias en un área de 2.5 \\text{ cm}^2."},{"front":"¿Cuál es el fármaco de elección para el control térmico en el Dengue?","back":"El paracetamol."},{"front":"¿Qué analgésicos están estrictamente contraindicados en el Dengue?","back":"ASA (aspirina), metamizol y AINEs."},{"front":"¿Cuál es el vector principal del virus Zika en regiones tropicales?","back":"El mosquito Aedes aegypti."},{"front":"¿Cuál es el hospedero principal del virus Zika?","back":"Los primates."},{"front":"¿En qué ventana de tiempo es útil la RT-PCR en sangre para diagnosticar Zika?","back":"Dentro de los primeros 8 días de iniciados los síntomas."},{"front":"¿Hasta qué día es detectable el virus Zika mediante RT-PCR en orina?","back":"Dentro de los primeros 14 días."},{"front":"¿Qué complicación neurológica autoinmune se asocia a la infección por Zika?","back":"El Síndrome de Guillain-Barré."},{"front":"¿Qué hallazgo craneal es característico del Zika congénito?","back":"La microcefalia."},{"front":"¿A qué familia de virus pertenece el Chikungunya?","back":"Pertenece a la familia Togaviridae (tipo Alfavirus)."},{"front":"¿Cómo se describe la artralgia en la fase aguda de Chikungunya?","back":"Se describe como artralgias severas e incapacitantes."},{"front":"¿Cuánto tiempo dura la fase crónica de la fiebre Chikungunya?","back":"Dura desde los 3 meses hasta los 3 años."},{"front":"¿Qué tipo de inmunidad desarrolla el humano tras infectarse por Chikungunya?","back":"Desarrolla inmunidad permanente."},{"front":"¿Qué estado de México es el único reportado como libre de Paludismo?","back":"El estado de Tlaxcala."},{"front":"¿Cuál es la especie de Plasmodium más frecuente en México?","back":"Plasmodium vivax."},{"front":"¿Cuál es la especie de Plasmodium asociada a mayor letalidad?","back":"Plasmodium falciparum."},{"front":"¿Cuál es el vector transmisor del Paludismo?","back":"El mosquito del género Anopheles."},{"front":"¿Cuál es el estudio parasitoscópico de elección para el diagnóstico de Paludismo?","back":"El frotis de sangre periférica por gota gruesa."},{"front":"¿Qué tinciones se utilizan para observar Plasmodium al microscopio?","back":"Las tinciones de Giemsa o Wright."},{"front":"¿Cuál es el esquema de tratamiento de elección para Paludismo?","back":"La combinación de Cloroquina y Primaquina."},{"front":"¿Qué efecto adverso puede causar la Primaquina en pacientes con déficit de glucosa 6 fosfato?","back":"Puede producir anemia hemolítica."},{"front":"¿Cuál es el agente etiológico de la Tripanosomiasis americana (Chagas)?","back":"El protozoario flagelado Trypanosoma cruzi."},{"front":"¿Cómo se le conoce comúnmente al vector de la enfermedad de Chagas en México?","back":"Chinche besucona (Triatoma)."},{"front":"¿Qué nombre recibe el complejo oftalmo-ganglionar típico de la fase aguda de Chagas?","back":"Signo de Romaña-Mazza."},{"front":"¿Qué porcentaje de pacientes en fase crónica de Chagas desarrollan lesiones cardíacas?","back":"Aproximadamente el 27%."},{"front":"¿Cuál es la causa de cardiomiopatía infecciosa más frecuente en el mundo?","back":"La enfermedad de Chagas."},{"front":"¿Qué tipo de anticuerpos predominan en la fase crónica de la Tripanosomiasis?","back":"Los niveles altos de IgG."},{"front":"¿Cuál es el tratamiento de elección para la enfermedad de Chagas en fase aguda?","back":"El Benznidazol durante 60 días."},{"front":"¿Cuál es la segunda opción de tratamiento para Chagas si el Benznidazol no está disponible?","back":"El Nifurtimox."},{"front":"Concepto: Promastigote","back":"Definición: Es la forma infectante y móvil del género Leishmania."},{"front":"Concepto: Amastigote","back":"Definición: Es la forma replicativa de Leishmania dentro del hospedero."},{"front":"¿Cómo se conoce popularmente a la úlcera cutánea única por Leishmania en México?","back":"Úlcera de los chicleros."},{"front":"¿Qué especies de Leishmania causan principalmente la forma cutánea?","back":"L. mexicana y L. braziliensis."},{"front":"¿Qué órganos presentan megalias masivas en la Leishmaniasis visceral?","back":"El hígado (hepatomegalia) y el bazo (esplenomegalia)."},{"front":"¿Qué nombre recibe la hiperpigmentación distal en fases avanzadas de Leishmaniasis visceral?","back":"Fiebre negra (Kala-azar)."},{"front":"¿Cuál es el nombre de la prueba inmunológica de hipersensibilidad tardía para Leishmaniasis?","back":"Antígeno de Montenegro o Leishmanina."},{"front":"¿Cuál es el tratamiento de elección para la Leishmaniasis visceral?","back":"Anfotericina B liposomal por vía intravenosa."},{"front":"¿Qué fármaco se utiliza de forma intralesional para la Leishmaniasis cutánea localizada?","back":"Antimoniato de meglumina."},{"front":"¿En qué fase del Dengue se debe vigilar estrechamente la elevación de enzimas hepáticas y trombocitopenia?","back":"En la fase de defervescencia (crítica)."},{"front":"La fase subaguda de Chikungunya se caracteriza por poliartritis distal y _____ hipertrófica.","back":"Tenosinovitis"},{"front":"En el Paludismo, el acceso palúdico clásico incluye fiebre irregular, escalofríos y _____ no dolorosa.","back":"Esplenomegalia"},{"front":"¿Qué fármaco profiláctico se utiliza para el Paludismo?","back":"La Cloroquina."},{"front":"¿Cuál es el porcentaje de efectividad del tratamiento antiparasitario en la fase crónica de Chagas?","back":"Tiene una efectividad del 10% al 25%."},{"front":"¿Cuál es el periodo de incubación de la Leishmaniasis cutánea?","back":"Puede ser entre 2 y 6 semanas."},{"front":"¿Qué fármaco adyuvante se puede dar en casos graves de Leishmaniasis cutánea?","back":"La Pentoxifilina."},{"front":"¿Qué síntoma prodrómico diferencia al Zika por su intensidad?","back":"El exantema maculopapular muy pruriginoso."},{"front":"¿Cuál es el signo dermatológico inicial de la Leishmaniasis cutánea tras la picadura?","back":"Un granuloma dérmico."},{"front":"¿Qué alteración hematológica completa define la pancitopenia en la Leishmaniasis visceral?","back":"Disminución de glóbulos rojos, blancos y plaquetas."},{"front":"¿Cuál es el vector de la Leishmaniasis?","back":"El mosquito del género Lutzomyia (flebótomo)."},{"front":"¿Cuál es la mortalidad de la fiebre Chikungunya?","back":"Tiene una mortalidad baja."},{"front":"¿Cuál es el primer paso en el manejo del Dengue sin datos de alarma?","back":"Hidratación con Vida Suero Oral (VSO) y reposo."}]},"5":{"num":5,"name":"ZOONOSIS Y MICOSIS","cards":[{"front":"¿Cuál es el agente etiológico de la Brucelosis?","back":"Género Brucella (principalmente B. melitensis), un coco Gram negativo aerobio."},{"front":"¿Cuál es la principal causa de muerte en pacientes con Brucelosis?","back":"Endocarditis."},{"front":"Tipo de fiebre característica que presenta un paciente con Brucelosis.","back":"Fiebre continua ondulante."},{"front":"¿Cuál es el medio de cultivo específico (Gold Standard) para el diagnóstico de Brucelosis?","back":"Medio de Ruiz-Castañeda (hemocultivo o aspirado de médula ósea)."},{"front":"¿Qué prueba se utiliza para el diagnóstico presuntivo de Brucelosis?","back":"Aglutinación Rosa de Bengala."},{"front":"Tratamiento de primera línea para Brucelosis no complicada.","back":"Doxiciclina + Estreptomicina (o Gentamicina)."},{"front":"Esquema de tratamiento para Brucelosis en mujeres embarazadas y ancianos.","back":"Rifampicina + TMP/SMX (Trimetoprima/Sulfametoxazol)."},{"front":"Tratamiento de elección para Brucelosis cuando existe complicación por endocarditis.","back":"Doxiciclina + Rifampicina + TMP/SMX."},{"front":"Fisiopatología de la Rickettsiosis: Invade células _____ de los vasos sanguíneos causando vasculitis.","back":"Endoteliales"},{"front":"Agente causal de la Fiebre Manchada de las Montañas Rocosas.","back":"Rickettsia rickettsii."},{"front":"Vector principal de la Rickettsiosis en México.","back":"Garrapata (Rhipicephalus sanguineus o Ixodes scapularis)."},{"front":"Descripción del exantema característico en Rickettsiosis.","back":"Exantema macular petequial de distribución centrípeta."},{"front":"¿Cuál es el Gold Standard para el diagnóstico de Rickettsiosis?","back":"Detección de anticuerpos mediante Inmunofluorescencia Indirecta (IFI)."},{"front":"Tratamiento antibiótico de elección para Rickettsiosis.","back":"Doxiciclina (vía oral o IV si el caso es crítico)."},{"front":"Agente causal de la Enfermedad de Lyme.","back":"Borrelia burgdorferi (una espiroqueta)."},{"front":"Manifestación cutánea patognomónica de la etapa inicial de la Enfermedad de Lyme.","back":"Eritema migratorio (mácula con palidez central)."},{"front":"Complicaciones características de la infección inicial diseminada en Lyme.","back":"Meningorradiculitis linfocítica, lesiones de nervios craneales y arritmias."},{"front":"Tratamiento farmacológico de elección para la Enfermedad de Lyme.","back":"Tetraciclinas o Ceftriaxona."},{"front":"¿Cuál es el agente causal del Carbunco (Ántrax)?","back":"Bacillus anthracis."},{"front":"Características microbiológicas del Bacillus anthracis.","back":"Bacilo Gram positivo inmóvil, aerobio o anaerobio facultativo, formador de esporas."},{"front":"Forma clínica más frecuente del Carbunco.","back":"Carbunco cutáneo."},{"front":"Descripción de la lesión en el Carbunco cutáneo.","back":"Úlcera con escara necrótica negruzca e indolora."},{"front":"Tratamiento de elección para cepas de Bacillus anthracis asociadas a bioterrorismo.","back":"Ciprofloxacino o Levofloxacino."},{"front":"Agente etiológico de la Tularemia.","back":"Francisella tularensis."},{"front":"Reservorios animales comúnmente asociados a la transmisión de Tularemia.","back":"Liebres y conejos."},{"front":"Descripción de la lesión cutánea por inoculación en Tularemia.","back":"Pápula inflamada que progresa a úlcera en sacabocados."},{"front":"Tratamiento de primera línea para la Tularemia.","back":"Estreptomicina (por 7 a 10 días)."},{"front":"Especie de Aspergillus responsable del 90% de los casos de Aspergilosis.","back":"Aspergillus fumigatus."},{"front":"Cuadro clínico: Esfera fúngica que coloniza una cavidad pulmonar preexistente (ej. por TB).","back":"Aspergiloma."},{"front":"¿Qué signo radiológico caracteriza al Aspergiloma?","back":"Signo de cascabel."},{"front":"¿Qué signo radiológico caracteriza a la Aspergilosis pulmonar invasora?","back":"Signo del halo."},{"front":"Ángulo de ramificación característico de las hifas de Aspergillus en cortes histológicos.","back":"45^{\\circ}"},{"front":"Tratamiento de primera elección para la Aspergilosis invasora.","back":"Voriconazol IV."},{"front":"¿Cuál es la principal causa de meningitis fúngica en pacientes con VIH?","back":"Cryptococcus neoformans."},{"front":"Conteo de linfocitos T CD4 usualmente asociado a criptococosis en pacientes con VIH.","back":"< 100 cel/mL."},{"front":"Método de tinción clásica para visualizar la cápsula de Cryptococcus en LCR.","back":"Tinta China."},{"front":"Hallazgos típicos en el LCR de un paciente con meningitis por Cryptococcus.","back":"Hipoglucorraquia, hiperproteinemia y pleocitosis de predominio mononuclear."},{"front":"Tratamiento de inducción para meningitis por Cryptococcus en pacientes con VIH.","back":"Anfotericina B."},{"front":"Tratamiento de mantenimiento para Criptococosis en pacientes con VIH.","back":"Fluconazol 200 mg por 12 meses."},{"front":"Micosis asociada a la exposición a murciélagos en cuevas o excremento de aves.","back":"Histoplasmosis (H. capsulatum)."},{"front":"¿Con qué enfermedad endocrina se asocia la Histoplasmosis diseminada en un 44% de los casos?","back":"Enfermedad de Addison."},{"front":"Método diagnóstico para Histoplasmosis en su forma diseminada.","back":"Aspiración de médula ósea."},{"front":"Tratamiento para Histoplasmosis diseminada.","back":"Anfotericina B + Glucocorticoides (por 2 semanas)."},{"front":"Mecanismo de transmisión de la Coccidioidomicosis.","back":"Inhalación de artroesporas."},{"front":"¿Qué estructuras se observan en el examen directo para diagnosticar Coccidioidomicosis?","back":"Endoesporas."},{"front":"Tratamiento de elección para casos leves a moderados de Coccidioidomicosis.","back":"Fluconazol o Itraconazol."},{"front":"Micosis con hifas en aspecto de \"timón de barco\" en el frotis o biopsia.","back":"Paracoccidioidomicosis (P. brasilensis)."},{"front":"Tratamiento de elección para Blastomicosis y Paracoccidioidomicosis.","back":"Anfotericina B."},{"front":"Factor de riesgo principal para desarrollar Mucormicosis (Zigomicosis).","back":"Diabetes mellitus descompensada (cetoacidosis)."},{"front":"Características clínicas de la Mucormicosis rinocerebral.","back":"Necrosis facial, úlceras necróticas en paladar duro y destrucción ósea."},{"front":"Hallazgo histológico característico de la Mucormicosis.","back":"Hifas gruesas no tabicadas con invasión de vasos sanguíneos (angio-invasión)."},{"front":"¿Cuál es la micosis subcutánea más frecuente en México?","back":"Micetoma."},{"front":"Agente causal más frecuente del Micetoma en México (90% de los casos).","back":"Nocardia brasiliensis."},{"front":"Tratamiento de elección para el Micetoma cutáneo por Nocardia.","back":"TMP/SMX + Diaminofenilsulfona por 2 meses."},{"front":"Signo clínico del Micetoma: inflamación crónica con abscesos que drenan _____.","back":"Gránulos de material purulento"},{"front":"Tratamiento para Tularemia si el paciente presenta meningitis.","back":"Cloranfenicol (por 14 a 21 días)."},{"front":"Principal reservorio animal de la Brucelosis por B. melitensis.","back":"Cabras (caprinos)."},{"front":"Vía de transmisión más común de la Brucelosis al humano.","back":"Ingesta de lácteos no pasteurizados de animales enfermos."},{"front":"Manifestación de la infección tardía persistente en la Enfermedad de Lyme.","back":"Artritis franca oligoarticular y acrodermatitis crónica atrófica."},{"front":"Tratamiento de la Aspergilosis broncopulmonar alérgica.","back":"Voriconazol + Esteroides (por la hiperreactividad bronquial)."},{"front":"Especie de Cryptococcus asociada a árboles como el eucalipto.","back":"Cryptococcus gattii."}]},"6":{"num":6,"name":"TETANOS, BOTULISMO Y RABIA","cards":[{"front":"¿Qué agente etiológico es un bacilo anaerobio productor de la exotoxina causante del tétanos?","back":"Clostridium tetani."},{"front":"¿Cuáles son las dos toxinas principales producidas por el bacilo del tétanos?","back":"Tetanolisina y tetanospasmina."},{"front":"¿Cuál es el período de incubación típico del tétanos según el material?","back":"De 5 a 7 días."},{"front":"¿Qué condición es necesaria en el tejido para que las esporas de C. tetani germinen y produzcan toxinas?","back":"Presencia de necrosis."},{"front":"¿En qué sitio específico de la médula espinal actúa la toxina tetánica bloqueando la inhibición?","back":"En el asta anterior."},{"front":"¿Qué neurotransmisor inhibidor es bloqueado por la toxina tetánica, resultando en hipertonía?","back":"GABA (ácido gamma-aminobutírico)."},{"front":"¿Cómo se define la \"risa sardónica\" en el contexto del tétanos?","back":"Es una contractura involuntaria de los músculos faciales que asemeja una sonrisa fija."},{"front":"¿Cuál es el signo clínico del tétanos caracterizado por espasmo de los músculos masticatorios?","back":"Trismo (trismus)."},{"front":"¿Qué término médico describe la postura de hiperextensión del cuerpo debido a espasmos musculares intensos en el tétanos?","back":"Opistótonos."},{"front":"¿Cuál es el estándar de oro para el diagnóstico del tétanos?","back":"El diagnóstico es puramente clínico."},{"front":"¿Qué tipo de entorno de hospitalización requiere un paciente con tétanos para evitar estímulos?","back":"Unidad de Cuidados Intensivos (UCI) sin estímulos visuales ni auditivos."},{"front":"¿Cuáles son los dos antibióticos de elección indicados para el tratamiento farmacológico del tétanos?","back":"Penicilina G y metronidazol."},{"front":"¿Qué grupo farmacológico se utiliza para el manejo de la hipertonía muscular en el tétanos?","back":"Benzodiacepinas."},{"front":"En adultos, ¿cuál es la dosis estándar de inmunoglobulina antitetánica?","back":"500 UI."},{"front":"¿Cuál es la dosis de inmunoglobulina antitetánica indicada para pacientes pediátricos?","back":"250 UI."},{"front":"¿En qué sitio debe aplicarse la inmunoglobulina antitetánica con respecto al lugar de la vacuna?","back":"En un sitio anatómico distinto al lugar de la vacunación."},{"front":"¿Cuál es el esquema de refuerzo de la vacuna Td en adultos con esquema previo completo?","back":"Una dosis cada 10 años."},{"front":"¿Cuál es el intervalo de aplicación para la segunda dosis de Td en un paciente de 15 años nunca vacunado?","back":"4 semanas después de la primera dosis."},{"front":"En un paciente no vacunado, ¿cuándo se aplica la tercera dosis del esquema Td?","back":"12 meses después de la primera dosis."},{"front":"¿A partir de qué semana de gestación se debe aplicar la vacuna Tdpa en embarazadas con esquema previo completo?","back":"A partir de la semana 20 de gestación."},{"front":"¿Qué manejo profiláctico requiere una herida limpia en un paciente con esquema de vacunación desconocido?","back":"Vacunación únicamente."},{"front":"¿Qué manejo profiláctico requiere una herida sucia en un paciente con menos de 3 dosis de vacuna antitetánica?","back":"Vacunación e inmunoglobulina antitetánica."},{"front":"Ante una herida limpia, ¿después de cuántos años de la última dosis de vacuna se considera necesario volver a vacunar?","back":"Más de 10 años."},{"front":"Ante una herida sucia, ¿después de cuántos años de la última dosis de vacuna se considera necesario volver a vacunar?","back":"Más de 5 años."},{"front":"¿Qué microorganismo causa el botulismo?","back":"Clostridium botulinum."},{"front":"¿Cuál es la característica microbiológica de Clostridium botulinum respecto al oxígeno?","back":"Es un bacilo anaerobio (Gram+)."},{"front":"¿A qué nivel del sistema nervioso actúa la toxina botulínica?","back":"A nivel presináptico."},{"front":"¿Qué neurotransmisor cuya liberación es inhibida por la toxina botulínica provoca parálisis?","back":"Acetilcolina."},{"front":"¿Cuál es la principal vía de exposición al botulismo en adultos mencionada en el texto?","back":"Ingesta (miel, conservas, embutidos) o por herida."},{"front":"¿Cuál de los 8 tipos de toxina botulínica se considera la más grave?","back":"Toxina tipo A."},{"front":"¿Cuál es el rango de tiempo habitual para el inicio de síntomas de botulismo tras la ingestión?","back":"De 18 a 36 horas."},{"front":"¿Cuál es la principal causa de muerte en pacientes con botulismo?","back":"Falla respiratoria."},{"front":"¿Qué signos oculares son característicos en el cuadro clínico del botulismo?","back":"Diplopía y midriasis."},{"front":"¿Cómo se confirma el diagnóstico de botulismo laboratorialmente?","back":"Aislamiento de esporas y toxinas en heces mediante cultivos anaeróbicos."},{"front":"¿Cuál es el tratamiento específico para el botulismo en adultos?","back":"Antitoxina botulínica de origen equino."},{"front":"¿Qué tratamiento específico se utiliza para el botulismo en niños?","back":"Inmunoglobulina humana IV."},{"front":"¿Qué medida se debe tomar para reducir la absorción de la toxina en botulismo alimentario?","back":"Acelerar el tránsito intestinal."},{"front":"¿Qué familia de virus causa la rabia?","back":"Rhabdoviridae."},{"front":"¿A qué género pertenece el virus de la rabia?","back":"Lyssavirus."},{"front":"¿Cuál es el principal reservorio animal que transmite la rabia al hombre por saliva?","back":"El perro."},{"front":"¿Cuál es el rango del período de incubación de la rabia humana?","back":"De 1 a 3 meses."},{"front":"¿Cuál es la velocidad de migración del virus de la rabia por los axones hacia el SNC?","back":"De 5 a 100 mm por día."},{"front":"¿Cómo se llama el tipo de transporte neuronal que utiliza el virus de la rabia para llegar a la raíz dorsal?","back":"Transporte retrógrado."},{"front":"¿Cuáles son los síntomas de la fase prodrómica de la rabia?","back":"Dolor en el sitio de la lesión y cefalea."},{"front":"¿Qué síntomas caracterizan la fase de encefalitis aguda en la rabia?","back":"Desorientación, delirio y convulsiones."},{"front":"¿Qué tríada de síntomas indica afectación del tronco del encéfalo en la rabia?","back":"Paresias, hidrofobia y fotofobia."},{"front":"¿Cuánto tiempo de vida le queda aproximadamente a un paciente una vez que inicia la encefalitis rábica?","back":"7 días."},{"front":"¿Cuál es el hallazgo histopatológico considerado el Gold Standard para el diagnóstico de rabia?","back":"Cuerpos de Negri."},{"front":"¿Qué prueba diagnóstica permite la confirmación del virus de la rabia mediante inmunofluorescencia directa?","back":"PCR."},{"front":"¿Cuál es el primer paso en el manejo de cualquier exposición al virus de la rabia (categoría \"Sin Riesgo\")?","back":"Lavar con agua y jabón por 10 minutos y desinfectar con agua oxigenada."},{"front":"¿Qué animales se consideran los tres principales transmisores de rabia en orden de frecuencia?","back":"1. Perro, 2. Gato, 3. Murciélago."},{"front":"¿Por qué no se recomienda suturar las heridas por mordedura de animales sospechosos de rabia?","back":"Para evitar la inoculación profunda del virus (solo suturar si es estrictamente necesario)."},{"front":"En la clasificación de riesgo de rabia, ¿qué situación define un \"Riesgo Leve\"?","back":"Lamedura en piel erosionada o mordedura superficial en tronco o miembros inferiores."},{"front":"¿Qué esquema de vacunación antirrábica se utiliza en pacientes con Riesgo Leve?","back":"Esquema Essen (días 0, 3, 7 y 14)."},{"front":"¿Qué define un \"Riesgo Grave\" en cuanto a la localización de la mordedura?","back":"Mordeduras en cabeza, cuello, miembros superiores o genitales."},{"front":"En caso de Riesgo Grave por rabia, ¿cuál es la dosis de inmunoglobulina antirrábica indicada?","back":"20 UI por kg."},{"front":"Si un paciente con Riesgo Grave ya tiene antecedente de vacunación previa contra la rabia, ¿qué componente del tratamiento se omite?","back":"La inmunoglobulina antirrábica (solo se aplica refuerzo de vacuna)."},{"front":"¿Cuál es el esquema de vacunación post-exposición (PEP) para un paciente ya vacunado previamente contra la rabia?","back":"Dos dosis los días 0 y 3."},{"front":"¿Por cuánto tiempo se debe observar a un perro o gato agresor si tiene vacunación vigente y no muestra signos de rabia?","back":"10 días."},{"front":"Ante una agresión por un animal silvestre o un animal rábico confirmado, ¿qué categoría de riesgo se asigna?","back":"Riesgo Grave."},{"front":"¿Qué manejo se indica para lameduras en mucosas (ojo, nariz, boca)?","back":"Tratamiento para Riesgo Grave (vacunación + inmunoglobulina)."},{"front":"¿Cuál es el manejo si el animal agresor no es localizado y hubo contacto de saliva con piel lesionada?","back":"Iniciar profilaxis para Riesgo Grave."},{"front":"¿Qué mamíferos se mencionan específicamente como no infectantes para la rabia?","back":"Los roedores."}]},"7":{"num":7,"name":"EPOC Y CANCER DE PULMON","cards":[{"front":"¿Cuál es la cuarta causa de muerte a nivel mundial según el material proporcionado?","back":"La Enfermedad Pulmonar Obstructiva Crónica (EPOC)."},{"front":"¿Qué hallazgo es el más frecuente durante la exploración física de un paciente con EPOC?","back":"Las sibilancias espiratorias."},{"front":"¿Cuál es el principal factor de riesgo para el desarrollo de EPOC?","back":"El tabaquismo."},{"front":"En pacientes menores de 45 años con EPOC, ¿qué deficiencia enzimática se debe investigar?","back":"Deficiencia de \\alpha-1 antitripsina."},{"front":"Concepto: Enfisema Pulmonar","back":"Destrucción y ensanchamiento alveolar sin fibrosis, caracterizado por el fenotipo de \"rosado soplador\"."},{"front":"Concepto: Bronquitis Crónica","back":"Presencia de tos productiva por al menos 3 meses durante 2 años consecutivos, con fenotipo \"azul abotagado\"."},{"front":"¿Qué hallazgo radiológico en el corazón es característico del enfisema?","back":"Corazón disminuido de tamaño (en gota)."},{"front":"¿Qué alteración histológica pulmonar es característica de la bronquitis crónica?","back":"Hiperplasia de células caliciformes."},{"front":"¿Cómo se define la limitación del flujo aéreo en la espirometría confirmatoria para EPOC?","back":"Relación FEV_1/FVC < 0.7 postbroncodilatador."},{"front":"Fórmula: Índice Tabáquico","back":"(\\text{Cigarrillos al día} \\times \\text{Años fumando}) / 20."},{"front":"¿A partir de qué valor de índice tabáquico se considera riesgo alto para patología pulmonar?","back":"Mayor a 41."},{"front":"¿Cuál es el síntoma más importante y frecuente de la EPOC?","back":"La disnea de esfuerzo progresiva."},{"front":"Mencione los componentes de la tríada cardinal de la EPOC.","back":"Disnea de esfuerzo, tos y producción de esputo."},{"front":"¿Qué grado de severidad GOLD corresponde a un FEV_1 postbroncodilatador de entre 50% y 79%?","back":"GOLD 2 (Moderado)."},{"front":"¿Qué grado de severidad GOLD se asigna a un paciente con FEV_1 < 30%?","back":"GOLD 4 (Muy severo)."},{"front":"¿Qué escala se utiliza específicamente para predecir hospitalizaciones y exacerbaciones mediante la disnea?","back":"La escala mMRC (Modified Medical Research Council)."},{"front":"¿Qué herramienta mide el impacto de la EPOC en la calidad de vida y sus cambios en el tiempo?","back":"El Test CAT (COPD Assessment Test)."},{"front":"¿Cuál es la utilidad principal del índice BODEx?","back":"Determinar el pronóstico y el riesgo de muerte en el paciente con EPOC."},{"front":"Mencione tres hallazgos típicos en la radiografía de tórax de un paciente con EPOC.","back":"Hiperinsuflación, aplanamiento del diafragma e hiperlucidez pulmonar."},{"front":"¿Cuál es el tratamiento inicial indicado para un paciente con EPOC Grupo A?","back":"Un broncodilatador (puede ser de acción corta o larga)."},{"front":"¿Cuál es el tratamiento de elección para pacientes con EPOC Grupo B?","back":"Broncodilatadores de acción larga (LAMA o LABA)."},{"front":"¿En qué condición se debe agregar un glucocorticoide inhalado al tratamiento del Grupo C o D?","back":"Cuando el conteo de eosinófilos es mayor o igual a 300 células/\\muL."},{"front":"Ejemplo de fármaco: LAMA","back":"Tiotropio."},{"front":"Ejemplo de fármacos: LABA","back":"Salmeterol o Formoterol."},{"front":"¿A partir de qué saturación de oxígeno (SatO_2) se indica oxigenoterapia domiciliaria?","back":"Saturación menor al 88%."},{"front":"¿Cuántas horas al día debe usarse el oxígeno para evitar la hipertensión pulmonar en EPOC?","back":"Más de 15 horas al día."},{"front":"¿Qué vacunas deben recibir todos los pacientes diagnosticados con EPOC?","back":"Vacunas contra Neumococo e Influenza."},{"front":"¿Cuál es el tratamiento definitivo para la EPOC en estadios terminales?","back":"Trasplante pulmonar."},{"front":"¿Qué define a una exacerbación de EPOC?","back":"Empeoramiento agudo de síntomas respiratorios que requiere un cambio en el tratamiento farmacológico."},{"front":"¿Cuál es la causa bacteriana más frecuente de exacerbación en EPOC?","back":"Haemophilus influenzae."},{"front":"¿Qué agente viral se detecta con mayor frecuencia en las exacerbaciones de EPOC?","back":"Picornavirus."},{"front":"¿Cuál es la causa más común de muerte intrahospitalaria en pacientes con exacerbación de EPOC?","back":"Falla cardíaca (37%)."},{"front":"¿Cuál es el tratamiento farmacológico para una exacerbación leve de EPOC?","back":"SABA (Salbutamol) y/o SAMA (Ipratropio) a demanda."},{"front":"¿Cuál es el esquema de esteroides sistémicos recomendado en una exacerbación moderada?","back":"Prednisona 40 mg al día por 5 a 7 días."},{"front":"¿Cuál es el objetivo de saturación de oxígeno durante el manejo de una exacerbación aguda?","back":"Entre 88% y 92%."},{"front":"Mencione una contraindicación para la ventilación mecánica no invasiva (indicación de intubación).","back":"Escala de Glasgow menor a 10."},{"front":"¿Cuál es el porcentaje de casos de cáncer de pulmón que corresponden al tipo microcítico (células pequeñas)?","back":"Aproximadamente el 20\\% - 25%."},{"front":"¿Cuál es el factor de riesgo más importante para cáncer de pulmón, presente en el 90% de los casos?","back":"El tabaquismo."},{"front":"¿Qué estudio se recomienda para el tamizaje de cáncer de pulmón en pacientes de alto riesgo?","back":"TAC de tórax a dosis bajas."},{"front":"¿A qué edad y con qué índice tabáquico se inicia el tamizaje para cáncer de pulmón?","back":"Entre 55-74 años con índice >30 paquetes/año o >20 con factores de riesgo adicionales."},{"front":"¿Cuál es el indicador pronóstico más importante para evaluar la extensión del cáncer pulmonar?","back":"El sistema TNM."},{"front":"¿Cuál es el tipo histológico de cáncer de pulmón más frecuente en general y en no fumadores?","back":"Adenocarcinoma."},{"front":"¿Qué tipo de cáncer pulmonar se localiza típicamente de forma periférica?","back":"Adenocarcinoma (y el carcinoma de células grandes)."},{"front":"¿Qué tipos histológicos de cáncer pulmonar suelen tener una localización central?","back":"Carcinoma de células escamosas (epidermoide) y carcinoma de células pequeñas."},{"front":"Concepto: Carcinoma de Células Pequeñas","back":"Tumor neuroendocrino altamente agresivo, asociado a tabaquismo y localización central."},{"front":"¿Qué síntomas son característicos de los tumores pulmonares centrales?","back":"Tos, disnea, atelectasia, neumonía postobstructiva y hemoptisis."},{"front":"¿Cuál es el síntoma inicial más común en el cáncer de pulmón?","back":"La tos."},{"front":"¿Qué estudio de imagen es el paso inicial ante la sospecha de cáncer pulmonar?","back":"Radiografía de tórax."},{"front":"¿A partir de qué tamaño de nódulo detectado en Rx se debe solicitar una TAC de alta resolución?","back":"Mayor a 8 mm."},{"front":"¿Cuál es el estudio de elección para evaluar metástasis al sistema nervioso central (SNC)?","back":"Resonancia Magnética (o TAC de cráneo según disponibilidad)."},{"front":"¿Cuál es el estándar de oro (Gold Standard) para el diagnóstico de extensión en el mediastino?","back":"Mediastinoscopía."},{"front":"¿Qué técnica diagnóstica es útil específicamente para lesiones centrales de forma no invasiva?","back":"Citología de esputo."},{"front":"¿Qué descripción histopatológica se asocia clásicamente al carcinoma de células pequeñas?","back":"Biopsia en \"sal y pimienta\"."},{"front":"¿Cuál es el tratamiento de elección para los estadios I y II del cáncer pulmonar de células no pequeñas?","back":"Resección quirúrgica."},{"front":"¿Qué fármacos constituyen la base de la quimioterapia en cáncer de pulmón?","back":"Cisplatino o Carboplatino."},{"front":"¿Cuál es el manejo indicado para el estadio IV de cáncer de pulmón?","back":"Cuidados paliativos."},{"front":"Concepto: Tumor de Pancoast","back":"Tumor apical que invade el plexo braquial y estructuras de la pared torácica, causando dolor de hombro."},{"front":"¿Qué estructuras suele invadir el tumor de Pancoast además del plexo braquial?","back":"Vasos subclavios, médula espinal o la primera costilla."},{"front":"¿Qué tríada clínica caracteriza al Síndrome de Claude-Bernard-Horner?","back":"Ptosis, miosis y anhidrosis ipsilateral."},{"front":"¿Qué ganglio se ve afectado para producir el Síndrome de Horner en cáncer de pulmón?","back":"El ganglio estrellado."},{"front":"¿Cuáles son los signos clínicos del Síndrome de Vena Cava Superior?","back":"Edema facial, cianosis facial y circulación colateral torácica."},{"front":"¿Qué síndrome paraneoplásico se asocia frecuentemente al Adenocarcinoma?","back":"Osteoartropatía hipertrófica pulmonar (acropatía)."},{"front":"Mencione dos síndromes paraneoplásicos asociados al carcinoma microcítico.","back":"SIADH (hormona antidiurética) y Síndrome de Cushing (ACTH)."},{"front":"¿Qué tipo de cáncer pulmonar se asocia más frecuentemente al tumor de Pancoast?","back":"Carcinoma epidermoide (escamoso)."},{"front":"¿En qué etapa de la EPOC se recomienda iniciar la rehabilitación respiratoria?","back":"A partir del estadio B."},{"front":"¿Qué hallazgo en la TAC sugiere malignidad en un nódulo pulmonar?","back":"Márgenes espiculados o retracción pleural."},{"front":"¿Qué hallazgo en la TAC sugiere invasión vascular por un tumor pulmonar?","back":"Signo de captación vascular de contraste."},{"front":"¿Qué porcentaje de pacientes con cáncer de pulmón sobrevive a los 5 años del diagnóstico?","back":"Solo el 18%."},{"front":"Según el material, ¿qué suplementos NO se recomiendan para prevenir el cáncer de pulmón?","back":"\\beta-carotenos, Vitamina E y Retinoides."},{"front":"¿Cuál es la cirugía indicada para tumores sólidos mayores de 2 cm?","back":"Lobectomía."},{"front":"¿Qué escala clasifica la falta de aire como \"Tengo que parar a respirar cuando camino 100 metros\"?","back":"Grado 3 de la escala mMRC."},{"front":"¿Qué cambio en el esputo sugiere la necesidad de iniciar antibióticos en una exacerbación?","back":"Incremento en la purulencia del esputo."},{"front":"¿Qué mutación genética se asocia específicamente con factores de riesgo en el carcinoma de células no pequeñas?","back":"Mutación del gen EGFR."},{"front":"En el índice BODEx, ¿qué puntaje se asigna a un paciente con un IMC \\le 21 \\text{ kg/m}^2?","back":"1 punto."},{"front":"¿Qué porcentaje de supervivencia a los 52 meses tiene un paciente con un índice de BODE de 7-10?","back":"25%."}]},"8":{"num":8,"name":"NEUMONIAS INTERSTICIALES Y DERRAME PLEURAL","cards":[{"front":"¿Qué procesos patológicos afectan el parénquima pulmonar de forma difusa en las neumonías intersticiales?","back":"Inflamación y fibrosis intersticial."},{"front":"¿Cuáles son los fármacos comúnmente asociados al desarrollo de neumonía intersticial?","back":"Nitrofurantoína y sulfas."},{"front":"¿Cuál es el síntoma respiratorio paroxístico característico de las neumonías intersticiales?","back":"Tos paroxística no productiva."},{"front":"¿Qué patrón se observa típicamente en la espirometría de un paciente con enfermedad pulmonar intersticial?","back":"Patrón restrictivo."},{"front":"¿Qué hallazgos citológicos caracterizan el remodelado en las neumonías intersticiales?","back":"Fibrosis e hiperplasia de las células epiteliales."},{"front":"¿Cuál es la dosis inicial recomendada de prednisona para el tratamiento de neumonías intersticiales?","back":"20-40 mg."},{"front":"¿Qué fármaco se añade al tratamiento cuando existe enfermedad pulmonar intersticial extensa?","back":"Hidroxicloroquina."},{"front":"¿Qué sustancia sustituye al tejido pulmonar funcional en la fisiopatología de las neumoconiosis?","back":"Colágeno."},{"front":"¿Qué porcentaje de las enfermedades ocupacionales en el país representan las neumoconiosis?","back":"10%."},{"front":"¿Cuál es el estudio confirmatorio de elección para las neumoconiosis?","back":"Biopsia con broncoscopía."},{"front":"¿Qué tipo de polvo mineral causa la bisinosis?","back":"Polvo de algodón."},{"front":"¿En qué sector industrial es más prevalente la bisinosis?","back":"Industria del vestido o textil."},{"front":"¿Qué término clínico describe el empeoramiento de los síntomas de la bisinosis el primer día después del descanso?","back":"Opresión torácica del lunes."},{"front":"¿Qué patología respiratoria produce el tabaquismo cuando se asocia a la bisinosis?","back":"Bronquitis crónica."},{"front":"¿Qué otras fibras vegetales pueden causar síndromes similares a la bisinosis pero más leves?","back":"Lino, cáñamo y yute."},{"front":"¿Qué agente etiológico específico causa la silicosis?","back":"Sílice cristalina (dióxido de silicio)."},{"front":"¿Cuál es el tamaño en micras de las partículas de sílice con mayor capacidad de generar daño?","back":"0.5-5 micras."},{"front":"¿Qué hallazgo radiológico clásico se observa en las adenopatías hiliares de la silicosis?","back":"Calcificaciones en cáscara de huevo."},{"front":"¿Qué complicación infecciosa es la más frecuente en pacientes con silicosis?","back":"Infección por tuberculosis."},{"front":"¿Por qué están contraindicados los esteroides en el tratamiento de la silicosis?","back":"Por la predisposición aumentada a desarrollar tuberculosis."},{"front":"¿A qué enfermedades reumatológicas se asocia frecuentemente la silicosis?","back":"Esclerodermia y artritis reumatoide."},{"front":"¿Cuál es el periodo de latencia típico de la asbestosis tras una exposición prolongada?","back":"10-20 años."},{"front":"¿En qué región pulmonar se localizan predominantemente los crepitantes y las opacidades en la asbestosis?","back":"Zona basal y lateral."},{"front":"¿Cuál es el Gold Standard para el diagnóstico de asbestosis?","back":"Biopsia (detección de fibras de asbesto en macrófagos)."},{"front":"¿Cuál es la principal neoplasia maligna asociada a la exposición por asbesto?","back":"Mesotelioma."},{"front":"¿Qué otro nombre recibe la neumoconiosis de los mineros de carbón?","back":"Antracosis."},{"front":"¿Qué síndrome se define por la asociación de nódulos pulmonares y artritis reumatoide en mineros de carbón?","back":"Síndrome de Caplan."},{"front":"¿Cuál es el hallazgo característico en la biopsia pulmonar de un paciente con antracosis?","back":"Gránulos negros en el parénquima pulmonar."},{"front":"¿Qué tipo de granulomas caracterizan histológicamente a la sarcoidosis?","back":"Granulomas no caseificantes."},{"front":"¿Cuál es el grupo epidemiológico más afectado por la sarcoidosis?","back":"Mujeres entre 20-40 años."},{"front":"¿Qué tipo de linfocito es el responsable de la formación de granulomas en la sarcoidosis?","back":"Linfocitos LT-CD4."},{"front":"¿Qué hallazgo radiológico hiliar es típico en la sarcoidosis?","back":"Adenopatía hiliar bilateral."},{"front":"¿Qué sustancia se acumula de forma anormal en los alvéolos en la proteinosis alveolar?","back":"Constituyentes del surfactante."},{"front":"¿Qué proceso autoinmunitario subyace a la mayoría de los casos de proteinosis alveolar?","back":"Anticuerpos contra el factor estimulante de colonias de monocito-macrófagos."},{"front":"¿Cómo se reporta la tinción del líquido de lavado broncoalveolar en la proteinosis alveolar?","back":"PAS positivo (PAS+)."},{"front":"¿Cuál es el tratamiento de elección para los casos graves de proteinosis alveolar?","back":"Lavado pulmonar completo."},{"front":"¿Qué volumen de líquido se considera normal en el espacio pleural?","back":"10-15 ml."},{"front":"¿Cuál es la causa número uno de derrame pleural según la estadística presentada?","back":"Enfermedades infecciosas (52.2%)."},{"front":"¿Qué hallazgo físico en la percusión sugiere la presencia de derrame pleural?","back":"Matidez."},{"front":"¿Cuál es el estudio de imagen de primera elección ante la sospecha de derrame pleural?","back":"Radiografía de tórax (AP y lateral)."},{"front":"¿Qué volumen mínimo de líquido pleural suele causar el borramiento del ángulo costo-diafragmático?","back":"50-75 ml."},{"front":"¿Qué signo radiológico se forma cuando el líquido pleural comienza a ascender por las paredes laterales?","back":"Signo del menisco."},{"front":"¿A partir de qué volumen se observa el borramiento de los ángulos cardiofrénico y costodiafragmático?","back":"> 200 ml."},{"front":"¿En qué dirección se desplaza el mediastino en un derrame pleural masivo?","back":"Hacia el lado opuesto al derrame."},{"front":"¿Qué criterios se utilizan para diferenciar entre un exudado y un trasudado pleural?","back":"Criterios de Light."},{"front":"¿Cuál es el punto de corte de la relación proteínas pleural/suero para clasificar un exudado?","back":"> 0.5."},{"front":"¿Cuál es el punto de corte de la relación LDH pleural/suero para clasificar un exudado?","back":"> 0.6."},{"front":"¿Qué valor de LDH en líquido pleural comparado con el límite superior plasmático define un exudado?","back":"> 2/3 del límite superior normal."},{"front":"¿Qué patologías sistémicas suelen causar trasudados pleurales?","back":"Insuficiencia cardíaca, cirrosis hepática e hipoalbuminemia."},{"front":"¿Qué valor de Adenosina Desaminasa (ADA) es indicativo de tuberculosis pleural?","back":"> 35 U/L."},{"front":"¿Qué volumen total de líquido pleural se recomienda extraer en una toracocentesis diagnóstica?","back":"50 ml."},{"front":"¿Qué cantidad de líquido pleural debe enviarse específicamente a bacteriología?","back":"5 ml."},{"front":"¿Cuál es el tratamiento antibiótico de primera elección para el derrame paraneumónico?","back":"Penicilina con inhibidor de \\beta-lactamasas o cefalosporinas de 3ra generación."},{"front":"¿Qué nivel de pH pleural indica la necesidad de drenaje torácico?","back":"< 7.2."},{"front":"¿Qué nivel de glucosa en líquido pleural es criterio para colocar una sonda de drenaje?","back":"< 60 mg/dL."},{"front":"¿Qué valor de LDH pleural en un derrame tabicado obliga al uso de drenaje torácico?","back":"> 1000 U/L."},{"front":"¿Cuándo está indicado realizar una toracocentesis terapéutica?","back":"En pacientes con disnea moderada/severa o derrame masivo."},{"front":"¿Cuál es la función biológica de la Alfa-1-Antitripsina?","back":"Inhibir la elastasa de los neutrófilos."},{"front":"¿Qué dos órganos se ven principalmente afectados por la deficiencia de Alfa-1-Antitripsina?","back":"Pulmones (enfisema/EPOC) e hígado (cirrosis)."},{"front":"¿En qué grupo de edad se debe sospechar inicialmente la deficiencia de Alfa-1-Antitripsina?","back":"Pacientes menores de 45 años con datos de EPOC."},{"front":"¿Cuál es el rango de valores normales de Alfa-1-Antitripsina en suero?","back":"80-220 mg/dL."},{"front":"¿Qué hallazgo en la radiografía de tórax es característico de la proteinosis alveolar?","back":"Consolidación bilateral y perihiliar."},{"front":"¿Qué complicación pulmonar se asocia a los trabajadores de la industria automotriz y demoledores?","back":"Asbestosis."},{"front":"¿Qué trabajadores presentan mayor riesgo de desarrollar silicosis?","back":"Mineros, cortadores de piedra y sopladores de cristal."},{"front":"En la espirometría de un paciente con bisinosis, el patrón esperado es de tipo _____.","back":"Restrictivo."},{"front":"El gradiente sérico pleural de albúmina en un trasudado es _____ a 1.2.","back":"Mayor (>)."},{"front":"El colesterol en el líquido pleural es mayor a 43 mg/dL en el caso de un _____.","back":"Exudado."},{"front":"La tríada clínica del derrame pleural incluye disnea, dolor pleurítico y _____.","back":"Tos seca."},{"front":"Para el diagnóstico de mesotelioma, el principal factor de riesgo es la exposición a _____.","back":"Asbesto."},{"front":"¿Qué tamaño de sonda (Fr) se recomienda para el drenaje de colecciones pleurales?","back":"10-14 Fr."},{"front":"¿En qué etapa de la inspiración son más audibles los crepitantes de la proteinosis alveolar?","back":"Teleinspiratorios (al final de la inspiración)."},{"front":"¿Qué tratamiento quirúrgico se indica si no hay expansión pulmonar tras el drenaje de un empiema?","back":"Toracotomía."},{"front":"La relación LDH pleural/suero menor a _____ es característica de un trasudado.","back":"0.6."},{"front":"¿Qué antibióticos se deben iniciar si se sospecha de S. aureus meticilino resistente en un derrame pleural?","back":"Vancomicina o Linezolid."},{"front":"¿Por qué los aminoglucósidos no están indicados en el tratamiento del derrame pleural?","back":"Debido a su escasa penetración pleural."}]},"9":{"num":9,"name":"PATOLOGIA TIROIDEA","cards":[{"front":"¿Cuál es el valor normal de la Hormona Estimulante de Tiroides (TSH)?","back":"0.4 – 4.0 mU/L."},{"front":"¿Cuál es la prueba más sensible para detectar alteraciones tiroideas?","back":"La medición de TSH."},{"front":"¿Por qué aumenta la T_{4} total durante el embarazo?","back":"Por el incremento de la globulina fijadora de tiroxina (TBG)."},{"front":"¿Qué estudio es más útil que la T_{4} total ante alteraciones de proteínas plasmáticas?","back":"La T_{4} libre (T_{4}L)."},{"front":"¿Qué hormona aumenta más rápido en casos de hipertiroidismo?","back":"La T_{3} total."},{"front":"¿En qué situación clínica es útil medir la T_{3} libre (T_{3}L)?","back":"En casos de hipertiroidismo con TSH suprimida y T_{4}L normal (T_{3} toxicosis)."},{"front":"¿Qué anticuerpos resultan positivos en la tiroiditis autoinmune (Hashimoto y Graves)?","back":"Anticuerpos anti-TPO."},{"front":"¿Qué anticuerpos son específicos para la Enfermedad de Graves?","back":"Anticuerpos anti-receptor de TSH (TRAB)."},{"front":"En el hipertiroidismo primario, la TSH se encuentra _____ y la T_{4}L se encuentra _____.","back":"Disminuida; elevada."},{"front":"¿Cómo se define la tirotoxicosis?","back":"Síndrome clínico de hipermetabolismo por hormonas tiroideas elevadas sin afectación directa de la glándula tiroides."},{"front":"¿Qué genes HLA se relacionan con la Enfermedad de Graves?","back":"HLA DR3 y B8."},{"front":"¿Cuáles son los tres componentes diagnósticos de la Enfermedad de Graves?","back":"Hipertiroidismo, bocio y oftalmopatía."},{"front":"¿Cuál es la causa más común de hipertiroidismo en el embarazo?","back":"La Enfermedad de Graves."},{"front":"Concepto: Bocio multinodular tóxico","back":"Hiperplasia funcional de varios nódulos tiroideos que secretan hormonas en exceso."},{"front":"¿Cuál es la diferencia fisiopatológica entre el adenoma tóxico y el bocio multinodular?","back":"El adenoma tóxico presenta un solo nódulo funcional autónomo."},{"front":"¿Qué estudio se utiliza para distinguir las causas de hipertiroidismo según su patrón de captación?","back":"Captación de yodo radiactivo."},{"front":"¿Qué alteraciones en el metabolismo del calcio se asocian al hipertiroidismo?","back":"Hipercalciuria e hipercalcemia."},{"front":"¿Cuál es el fármaco de elección inicial para el hipertiroidismo?","back":"Metimazol (10–20 mg diarios)."},{"front":"¿En qué casos específicos se prefiere el uso de propiltiouracilo (PTU)?","back":"Primer trimestre de embarazo y tormenta tiroidea."},{"front":"¿Cuál es la función del propranolol en el tratamiento del hipertiroidismo?","back":"Disminuir la frecuencia cardíaca, la tensión arterial sistólica y la intolerancia al ejercicio."},{"front":"¿Cuál es la contraindicación principal para el uso de propranolol?","back":"Pacientes con asma."},{"front":"¿Bajo qué condiciones se inicia tratamiento en hipertiroidismo subclínico?","back":"TSH < 0.1, riesgo cardiovascular u osteopenia."},{"front":"¿Cuál es el efecto adverso más grave de las tionamidas?","back":"Agranulocitosis (inhibición de la mielopoyesis)."},{"front":"¿Cómo se describe el bocio en la Enfermedad de Graves?","back":"Difuso, simétrico y con presencia de soplo o frémito."},{"front":"¿Cuál es la causa de la oftalmopatía en la Enfermedad de Graves?","back":"Acumulación de glucosaminoglicanos e hipertrofia del tejido adiposo."},{"front":"¿Cuál es el patrón de captación en la gammagrafía para un adenoma tóxico?","back":"Captación focal (nódulo caliente)."},{"front":"¿Cuál es el signo de Pemberton?","back":"Plétora facial por obstrucción del flujo venoso yugular debida a una masa en el cuello."},{"front":"¿Qué porcentaje de los nódulos tiroideos suelen ser benignos?","back":"Hasta el 95%."},{"front":"¿En qué grupos de edad se debe sospechar malignidad ante un nódulo tiroideo?","back":"Varones menores de 15 años o mayores de 60 años."},{"front":"¿Cuáles son los dos estudios iniciales ante el hallazgo de un nódulo tiroideo?","back":"Medición de TSH y ultrasonido (USG) de tiroides."},{"front":"Mencione dos hallazgos ecográficos sugerentes de malignidad en un nódulo tiroideo.","back":"Microcalcificaciones y márgenes espiculados."},{"front":"¿A partir de qué tamaño se indica una Biopsia por Aspiración con Aguja Fina (BAAF) en un nódulo tiroideo?","back":"Nódulos mayores de 1 cm."},{"front":"¿Cuál es la sospecha diagnóstica ante síntomas tiroideos que inician una semana después de una infección respiratoria superior?","back":"Tiroiditis de Quervain (subaguda)."},{"front":"¿Cuál es el hallazgo característico a la exploración física en la tiroiditis de Quervain?","back":"Dolor a la palpación en una tiroides de gran tamaño y nodular."},{"front":"¿Qué escala se utiliza para evaluar la gravedad de una tormenta tiroidea?","back":"Criterios de Burch-Wartofsky."},{"front":"¿Qué fármaco se utiliza para disminuir la conversión de T_{4} a T_{3} en una tormenta tiroidea?","back":"Beta-bloqueadores."},{"front":"¿Cuál es el porcentaje de casos de hipotiroidismo que son de origen primario?","back":"99%."},{"front":"El hipotiroidismo primario se caracteriza por TSH _____ y T_{4}L _____.","back":"Elevada; disminuida."},{"front":"¿Cuál es la causa más frecuente de hipotiroidismo a nivel mundial?","back":"Deficiencia de yodo."},{"front":"¿Qué anticuerpos son positivos en la tiroiditis de Hashimoto?","back":"Anti-TPO y anti-tiroglobulina."},{"front":"Defina hipotiroidismo subclínico.","back":"Aumento leve de TSH con niveles de T_{4} normal y ausencia de síntomas."},{"front":"¿A qué edad se recomienda realizar el tamizaje de hipotiroidismo en mujeres con TSH?","back":"A los 60 años."},{"front":"¿Cuál es la dosis estándar de levotiroxina para el tratamiento del hipotiroidismo?","back":"1.6–1.8 \\mu g/kg/día basado en el peso actual."},{"front":"¿Cuál es la dosis inicial de levotiroxina recomendada en adultos mayores?","back":"12–25 \\mu g/día."},{"front":"¿Cuál es la meta terapéutica de TSH en pacientes con hipotiroidismo?","back":"0.45 – 4.12 mU/L."},{"front":"¿Qué ajuste de dosis de levotiroxina se requiere en pacientes embarazadas?","back":"Aumentar la dosis en un 30%."},{"front":"¿Cuándo se debe iniciar tratamiento en un hipotiroidismo subclínico?","back":"Cuando la TSH > 10, o ante embarazo, infertilidad o bocio."},{"front":"¿Qué fármaco debe administrarse empíricamente antes de la hormona tiroidea en el coma mixedematoso?","back":"Glucocorticoides (restitución suprarrenal)."},{"front":"¿Cuáles son los tres tipos histológicos principales del cáncer de tiroides?","back":"Epiteliales (Papilar y Folicular), Medulares y Anaplásicos."},{"front":"¿Cuál es el tipo de cáncer de tiroides más frecuente y de mejor pronóstico?","back":"Carcinoma Papilar."},{"front":"¿Qué hallazgo histológico es característico del carcinoma papilar de tiroides?","back":"Cuerpos de psamoma."},{"front":"¿Qué marcador tumoral se utiliza para el seguimiento vitalicio del cáncer epitelial de tiroides?","back":"Tiroglobulina."},{"front":"¿De qué células se origina el carcinoma medular de tiroides?","back":"Células C parafoliculares."},{"front":"¿Cuál es el marcador diagnóstico característico del carcinoma medular de tiroides?","back":"Calcitonina."},{"front":"¿Cuál es el tipo de cáncer de tiroides más agresivo y común en pacientes mayores?","back":"Carcinoma anaplásico."},{"front":"¿Qué fármaco se utiliza para el control de los síntomas (bochornos y diarrea) en el cáncer medular?","back":"Octreótida."},{"front":"¿En qué tipo de cáncer de tiroides se encuentran las células de Hurthle?","back":"Carcinoma folicular."},{"front":"¿Cuál es el tratamiento de elección para el cáncer papilar con tumor residual?","back":"Tiroidectomía total más radioterapia con yodo."}]},"10":{"num":10,"name":"SINDROME METABOLICO","cards":[]},"11":{"num":11,"name":"DIABETES MELLITUS","cards":[]},"12":{"num":12,"name":"COMPLICACIONES DE DIABETES","cards":[{"front":"¿Cuáles son los tres componentes que caracterizan a la Cetoacidosis Diabética (CAD)?","back":"Acidosis metabólica, hipercetonemia e hiperglucemia."},{"front":"¿En qué tipo de pacientes es más común la presentación de Cetoacidosis Diabética?","back":"Pacientes con Diabetes Mellitus tipo 1."},{"front":"¿Cuál es el principal factor desencadenante de la Cetoacidosis Diabética?","back":"Las infecciones."},{"front":"¿Cuál es la principal causa de muerte en niños que presentan Cetoacidosis Diabética?","back":"El edema cerebral."},{"front":"¿Cuál es el valor de glucosa típicamente observado en los tres niveles de severidad de la CAD?","back":">250 mg/dl."},{"front":"En la CAD leve, ¿cuál es el rango esperado de pH arterial?","back":"De 7.25 a 7.3."},{"front":"En la CAD moderada, ¿cuál es el rango esperado de pH arterial?","back":"De 7.24 a 7.0."},{"front":"En la CAD severa, ¿cuál es el valor de pH arterial?","back":"<7.0."},{"front":"¿Cuál es el rango de bicarbonato (HCO_{3}) en una CAD leve?","back":"15 a 18 mEq/l."},{"front":"¿Cuál es el rango de bicarbonato (HCO_{3}) en una CAD moderada?","back":"10 a 15 mEq/l."},{"front":"¿Cuál es el nivel de bicarbonato (HCO_{3}) en una CAD severa?","back":"<10 mEq/l."},{"front":"¿Cuál es el estado mental típico de un paciente con CAD severa?","back":"Estupor o coma."},{"front":"¿Cuál es el estándar de oro para el diagnóstico de Cetoacidosis Diabética?","back":"Medición de \\beta-hidroxibutirato."},{"front":"¿Con qué frecuencia se deben realizar las mediciones de pH, HCO_{3} y electrolitos séricos en el manejo de CAD?","back":"Cada 4 a 6 horas."},{"front":"¿Cuál es el manejo inicial de líquidos en la primera hora de tratamiento de la CAD?","back":"Administración IV de 1000 cc de solución salina al 0.9%."},{"front":"Si el potasio (K) es <3.3 mEq/l en un paciente con CAD, ¿qué acción debe tomarse respecto a la insulina?","back":"No administrar insulina hasta reponer el potasio."},{"front":"¿Bajo qué condición de pH se recomienda administrar bicarbonato en CAD?","back":"Cuando el pH es <6.9."},{"front":"¿Cuál es la dosis de infusión continua de insulina regular recomendada en el tratamiento de CAD?","back":"0.1 unidades/kg/hora."},{"front":"¿Cuál es la meta de disminución de glucosa plasmática por hora en el manejo de CAD?","back":"50 a 75 mg/dl por hora."},{"front":"¿Qué solución debe añadirse cuando la glucosa es <250 mg/dl en el tratamiento de CAD?","back":"Solución glucosada al 5% o 10%."},{"front":"¿Cuáles son los criterios de resolución de la Cetoacidosis Diabética?","back":"Glucosa <200, bicarbonato >18, brecha aniónica <12 y pH venoso >7.3."},{"front":"¿Qué caracteriza al Estado Hiperglucémico Hiperosmolar (EHH)?","back":"Hiperglucemia severa, hiperosmolaridad y deshidratación sin cetosis significativa."},{"front":"¿En qué tipo de pacientes es más prevalente el Estado Hiperglucémico Hiperosmolar?","back":"Pacientes con Diabetes Mellitus tipo 2."},{"front":"¿Cuál es la tríada clínica del Estado Hiperglucémico Hiperosmolar?","back":"Hiperglucemia severa, hiperosmolaridad y deshidratación sin cetosis."},{"front":"¿Cuál es el nivel de glucosa diagnóstico para el Estado Hiperglucémico Hiperosmolar?","back":">600 mg/dl."},{"front":"¿Cuál es el umbral de osmolaridad sérica para diagnosticar EHH?","back":">320 mOsm/kg."},{"front":"¿Cómo se calcula el sodio corregido en hiperglucemia?","back":"Na + 1.6 mEq por cada 100 mg/dl de glucosa por arriba de 100."},{"front":"¿Cuál es la fórmula para calcular la osmolaridad efectiva?","back":"2 \\times Na + \\text{Glucosa}/18."},{"front":"¿Cuál es el rango recomendado para reducir la osmolaridad en EHH?","back":"De 3 a 8 mOsm/kg/hora."},{"front":"¿Cuáles son los criterios de resolución del Estado Hiperglucémico Hiperosmolar?","back":"Osmolaridad <310 mOsm, glucosa sérica <250 mg/dl y recuperación del estado de alerta."},{"front":"¿Cómo se define el pie diabético?","back":"Alteración anatómica y funcional del pie por hiperglucemia sostenida, con daño neuropático y vascular."},{"front":"¿Cuál es la causa más frecuente de amputación no traumática?","back":"Pie diabético."},{"front":"¿Cuál es la supervivencia a 5 años de un paciente diabético tras presentar una úlcera?","back":"Del 50% al 60%."},{"front":"¿Qué prueba se utiliza para el tamizaje de neuropatía en el pie diabético?","back":"Prueba de Semmes-Weinstein (monofilamento)."},{"front":"¿Cuántos puntos de sensibilidad detectados en la prueba de monofilamento indican alteración?","back":"4 de 10 puntos."},{"front":"¿Qué herramienta se utiliza para valorar la enfermedad arterial periférica en pacientes con pie diabético?","back":"Índice Tobillo-Brazo."},{"front":"¿Cuál es la altura recomendada del tacón para el calzado de un paciente diabético?","back":"Entre 2 y 3 cm."},{"front":"¿Cuál es el estudio de imagen inicial para evaluar el pie diabético?","back":"Radiografía (RX) en dos proyecciones."},{"front":"¿Cuál es el estándar de oro para el diagnóstico de complicaciones en pie diabético?","back":"Resonancia Magnética (RM)."},{"front":"Según la clasificación de Wagner, ¿qué grado corresponde a una úlcera profunda que llega a tendones y articulaciones?","back":"Grado 2."},{"front":"Según la clasificación de Wagner, ¿qué grado representa gangrena en todo el pie?","back":"Grado 5."},{"front":"En la clasificación de la Universidad de Texas, ¿qué estadio indica la presencia de infección e isquemia?","back":"Estadio D."},{"front":"¿Cuál es la meta de glucemia en un paciente con pie diabético?","back":"<140 mg/dl."},{"front":"¿Cuál es el tratamiento antibiótico de elección para un eritema perilesional <2 cm en pie diabético?","back":"Cefalexina o Ceftriaxona."},{"front":"¿Qué esquema antibiótico se recomienda para el tratamiento de osteomielitis en pie diabético?","back":"Clindamicina + Rifampicina + Quinolonas por 6 semanas."},{"front":"En gasometría, ¿qué valores definen una acidemia?","back":"pH < 7.35."},{"front":"¿Cuál es el rango normal de PaCO_{2} en un adulto?","back":"35 a 45 mmHg."},{"front":"¿Cuál es el rango normal de bicarbonato (HCO_{3}) en un adulto?","back":"22 a 26 mEq/l."},{"front":"En trastornos metabólicos, ¿en qué dirección se mueven el pH y el HCO_{3}?","back":"En la misma dirección."},{"front":"¿Qué fórmula se utiliza para predecir el PaCO_{2} esperado en una acidosis metabólica?","back":"Fórmula de Winter: PaCO_{2} = (1.5 \\times HCO_{3}) + 8 \\pm 2."},{"front":"¿Cuál es el primer paso para interpretar una gasometría arterial?","back":"Determinar si existe acidosis o alcalosis mediante el pH."},{"front":"En una acidosis respiratoria aguda, ¿cuánto aumenta el HCO_{3} por cada +10 mmHg de CO_{2}?","back":"+1 mEq/l."},{"front":"En una acidosis respiratoria crónica, ¿cuánto aumenta el HCO_{3} por cada +10 mmHg de CO_{2}?","back":"+3.5 a +4 mEq/l."},{"front":"¿Qué indica el exceso de base (EB/BE) en una gasometría?","back":"El estado global del medio interno (normal -2 a +2 mEq/l)."},{"front":"¿Con qué frecuencia se recomienda la inspección de pies en un paciente de alto riesgo?","back":"Cada 1 a 3 meses."}]},"13":{"num":13,"name":"PATOLOGIA CENTRAL Y SUPRARRENAL","cards":[{"front":"¿Cómo se define analíticamente la hiperprolactinemia?","back":"Como la elevación persistente de los niveles circulantes de prolactina por encima de 20-25\\text{ ng/ml}."},{"front":"¿Cuál es la función principal de la prolactina en el organismo?","back":"El crecimiento de las glándulas mamarias y la producción láctea."},{"front":"¿Cuál es la causa fisiológica más común de hiperprolactinemia?","back":"El embarazo."},{"front":"En una mujer con amenorrea e hiperprolactinemia, ¿qué es lo primero que se debe descartar?","back":"El embarazo."},{"front":"¿Cuál es la causa patológica más frecuente de hiperprolactinemia?","back":"Los prolactinomas (específicamente microadenomas)."},{"front":"Mencione tres fármacos que frecuentemente inducen hiperprolactinemia.","back":"Metoclopramida, risperidona e inhibidores selectivos de la recaptación de serotonina (IRSS)."},{"front":"¿Qué porcentaje de los tumores secretores de hormonas hipofisiarias corresponden a prolactinomas?","back":"Aproximadamente el 40%."},{"front":"¿Cuál es el punto de corte en tamaño para distinguir un microadenoma de un macroadenoma hipofisario?","back":"1\\text{ cm}."},{"front":"¿En qué población son más frecuentes los macroadenomas prolactínicos según el material?","back":"En hombres y niños."},{"front":"¿Cuál es el síntoma visual característico causado por la compresión del quiasma óptico por un macroadenoma?","back":"Hemianopsia bitemporal."},{"front":"¿Cuáles son los síntomas típicos de hiperprolactinemia en mujeres?","back":"Alteraciones menstruales, galactorrea e infertilidad."},{"front":"¿Qué síntomas predominan en hombres con hiperprolactinemia?","back":"Disminución de la libido y disfunción eréctil."},{"front":"¿Qué nivel de prolactina sérica sugiere una probabilidad del 100% de que la causa sea un prolactinoma?","back":"Niveles superiores a 200\\text{ ng/ml}."},{"front":"¿Qué niveles de prolactina se asocian habitualmente con la presencia de macroadenomas?","back":"Niveles superiores a 1000\\text{ ng/ml}."},{"front":"¿Cuál es el estudio de imagen de elección para el abordaje de la patología hipofisaria?","back":"Resonancia Magnética (RM)."},{"front":"¿Cuál es el Gold Standard para el diagnóstico de hiperprolactinemia?","back":"Cromatografía de filtración en gel."},{"front":"¿Cuál es el tratamiento de primera línea para los prolactinomas (tanto micro como macro)?","back":"Agonistas de la dopamina (cabergolina o bromocriptina)."},{"front":"¿Cómo se define el Síndrome de Secreción Inadecuada de Hormona Antidiurética (SIADH)?","back":"Como un trastorno de disminución de excreción de agua por incapacidad de suprimir la secreción de ADH."},{"front":"¿Cuál es el tipo de trastorno hidroelectrolítico característico del SIADH?","back":"Hiponatremia por retención de agua libre."},{"front":"Mencione la causa ectópica principal de SIADH.","back":"Carcinoma microcítico de pulmón."},{"front":"¿Cuál es el estado de hidratación clínica típico en un paciente con SIADH?","back":"Normovolémico o levemente hipervolémico (sin edema)."},{"front":"En el SIADH, ¿cómo se encuentran la osmolaridad plasmática y la urinaria?","back":"Osmolaridad plasmática disminuida (<275\\text{ mOsm/kg}) y urinaria aumentada (>100\\text{ mOsm/kg})."},{"front":"¿Cuál es el nivel de sodio urinario esperado en el SIADH?","back":"Aumentado, generalmente >20-40\\text{ mEq/L}."},{"front":"¿Cuál es el pilar del tratamiento inicial en el SIADH?","back":"Restricción de agua libre."},{"front":"¿Qué fármaco antagonista de la ADH puede emplearse en casos seleccionados de SIADH?","back":"Tolvaptán."},{"front":"¿Cómo se define la Diabetes Insípida (DI)?","back":"Como un trastorno de la homeostasis del agua caracterizado por un aumento en la excreción de agua (poliuria diluida)."},{"front":"¿Cuál es la diferencia fisiopatológica entre la DI central y la nefrogénica?","back":"La central es por deficiencia absoluta de ADH y la nefrogénica por resistencia renal a su acción."},{"front":"¿Qué fármaco es una causa común de Diabetes Insípida nefrogénica adquirida?","back":"Litio."},{"front":"¿Cuáles son los síntomas cardinales de la Diabetes Insípida?","back":"Poliuria (>3\\text{ L/día}), sed excesiva y polidipsia."},{"front":"¿Cómo se encuentran el sodio y la osmolaridad plasmática en la Diabetes Insípida?","back":"Sodio aumentado (>145\\text{ mEq/L}) y osmolaridad plasmática aumentada (>295\\text{ mOsm/kg})."},{"front":"¿Cuál es el valor de osmolaridad urinaria que define una orina hipotónica en DI?","back":"Menor de 300\\text{ mOsm/kg}."},{"front":"¿Qué prueba permite diferenciar entre las distintas etiologías de Diabetes Insípida?","back":"La prueba de privación de agua (H_{2}O)."},{"front":"¿Cómo se diferencia la DI central de la nefrogénica tras administrar desmopresina?","back":"La DI central responde aumentando la osmolaridad urinaria; la nefrogénica no responde."},{"front":"¿Cuál es el tratamiento de elección para la Diabetes Insípida central?","back":"Desmopresina."},{"front":"¿Cuál es el tratamiento farmacológico inicial para la Diabetes Insípida nefrogénica?","back":"Restricción de sodio y diuréticos tiazídicos."},{"front":"¿Qué hormona estimula la liberación de ACTH en la hipófisis anterior?","back":"La hormona liberadora de corticotropina (CRH) del hipotálamo."},{"front":"¿De qué molécula precursora deriva la ACTH?","back":"Proopiomelanocortina (POMC)."},{"front":"¿Cómo se define el Síndrome de Cushing?","back":"Como cualquier entidad que curse con un exceso de producción o administración de glucocorticoides (cortisol)."},{"front":"¿Cuál es la causa más frecuente de Síndrome de Cushing en general?","back":"Cushing iatrogénico (por administración de esteroides exógenos)."},{"front":"¿Qué diferencia al Síndrome de Cushing de la Enfermedad de Cushing?","back":"La Enfermedad de Cushing se debe específicamente a un microadenoma hipofisario productor de ACTH."},{"front":"¿Cuáles son los signos clínicos más frecuentes del Síndrome de Cushing según su porcentaje de aparición?","back":"Obesidad troncal (97%), plétora facial (95%) y facies de luna llena (90%)."},{"front":"¿Cuál es el estudio de primera elección para el diagnóstico de Síndrome de Cushing?","back":"Cortisoluria de 24 horas (positiva si es >100-140)."},{"front":"¿En qué consiste el Test de Nugent?","back":"Administración de dexametasona la noche anterior y determinación de cortisol sérico a la mañana siguiente."},{"front":"¿Qué estudio de imagen se utiliza para diagnosticar la Enfermedad de Cushing?","back":"Resonancia Magnética (RM) con gadolinio."},{"front":"¿Cuál es el tratamiento de elección para la Enfermedad de Cushing?","back":"Resección transesfenoidal del adenoma."},{"front":"¿Qué gammagrafía se utiliza para localizar un foco de Cushing ectópico?","back":"Gammagrafía con ^{111}\\text{In-octreótide}."},{"front":"¿Cómo se conoce a la insuficiencia suprarrenal primaria?","back":"Enfermedad de Addison."},{"front":"¿Cuál es la causa más frecuente de insuficiencia suprarrenal primaria en México?","back":"Tuberculosis."},{"front":"¿Cuál es la causa más común de insuficiencia suprarrenal primaria a nivel mundial?","back":"Autoinmune."},{"front":"¿Qué porcentaje de la corteza suprarrenal debe destruirse para que se manifieste la Enfermedad de Addison?","back":"Más del 90%."},{"front":"¿Cuál es el síntoma cutáneo distintivo de la insuficiencia suprarrenal primaria?","back":"Hiperpigmentación."},{"front":"¿Qué valor de cortisol sérico basal prácticamente descarta insuficiencia suprarrenal?","back":"Valores superiores a 18\\text{ mcg/dl}."},{"front":"¿Cuál es el Gold Standard para diagnosticar insuficiencia suprarrenal?","back":"Prueba de estimulación con cosintropina (ACTH sintética)."},{"front":"¿Qué alteraciones electrolíticas son características de la insuficiencia suprarrenal primaria?","back":"Hiponatremia e hiperkalemia (hiperpotasemia)."},{"front":"¿Cuál es el tratamiento de reemplazo estándar para la insuficiencia suprarrenal?","back":"Hidrocortisona y fludrocortisona."},{"front":"¿Cuál es la causa más frecuente de una crisis adrenal aguda?","back":"Suspensión brusca del tratamiento corticoideo prolongado."},{"front":"¿Cuál es la presentación clínica de un paciente en crisis adrenal?","back":"Fiebre elevada, deshidratación, vómitos e hipotensión (choque refractario a aminas)."},{"front":"¿Qué prueba diagnóstica se realiza en México ante la sospecha de insuficiencia suprarrenal secundaria?","back":"Prueba de hipoglucemia inducida con insulina."},{"front":"¿Qué es un feocromocitoma?","back":"Un tumor de células cromafines que secreta catecolaminas, principalmente norepinefrina."},{"front":"Mencione dos componentes de la 'regla de los 10' del feocromocitoma.","back":"10% bilaterales, 10% malignos, 10% extraadrenales o 10% familiares."},{"front":"¿Cuáles son las '5 H' que conforman la clínica del feocromocitoma?","back":"Hipertensión, Hiperhidrosis, Hot flashes (bochornos), Headache (cefalea) e Hiperadrenérgico."},{"front":"¿Cuál es el método diagnóstico inicial para feocromocitoma?","back":"Determinación de metanefrinas en plasma o en orina de 24 horas."},{"front":"¿Cuál es el tratamiento definitivo del feocromocitoma?","back":"Escisión quirúrgica del tumor."},{"front":"¿Qué fármaco de primera línea se usa para el bloqueo alfa previo a la cirugía de feocromocitoma?","back":"Fenoxibenzamina."},{"front":"¿Qué fármaco se utiliza en las emergencias hipertensivas por feocromocitoma?","back":"Fentolamina."},{"front":"¿Cómo se conoce también al hiperaldosteronismo primario?","back":"Síndrome de Conn."},{"front":"¿Cuál es la tríada clínica o analítica sugerente de Síndrome de Conn?","back":"Hipertensión arterial de difícil control, hipopotasemia y renina baja."},{"front":"¿Qué valor de aldosterona plasmática orienta al diagnóstico inicial de hiperaldosteronismo primario?","back":"Valores superiores a 15\\text{ pg/ml}."},{"front":"¿Cuál es el Gold Standard confirmatorio para el hiperaldosteronismo primario?","back":"Prueba de carga oral de sodio."},{"front":"¿Cuál es el tratamiento de elección para un adenoma secretor de aldosterona?","back":"Resección laparoscópica."},{"front":"¿Qué efecto tiene el cortisol sobre los niveles de glucosa y la presión arterial?","back":"Aumenta tanto la glucosa como la presión arterial."},{"front":"¿Qué hallazgo en el EKG se puede observar en la insuficiencia suprarrenal?","back":"Reducción y lentitud de las ondas."},{"front":"¿Cuál es la localización extraadrenal más frecuente de un feocromocitoma?","back":"El área paraaórtica."}]},"14":{"num":14,"name":"PERLAS DE ENDOCRINOLOGIA","cards":[{"front":"¿Cuál es el rango normal del pH arterial en un adulto?","back":"El rango normal es de 7.35 a 7.45."},{"front":"¿Cuál es el valor normal de la PaCO_2 en una gasometría arterial?","back":"El valor normal es de 35 a 45 mmHg."},{"front":"¿Cuál es el rango normal del bicarbonato (HCO_3^-) en el adulto?","back":"El rango normal es de 22 a 26 mEq/L."},{"front":"¿Cuál es el valor normal de la PaO_2 con una FiO_2 al 21 %?","back":"El valor normal es de 80 a 100 mmHg."},{"front":"¿Qué parámetro gasométrico indica el \"Exceso de Base\" global del medio interno?","back":"El parámetro es el EB o BE, con valor normal de -2 a +2 mEq/L."},{"front":"Si el pH es menor a 7.35, el estado ácido-base se define como _____.","back":"Acidemia"},{"front":"Si el pH es mayor a 7.45, el estado ácido-base se define como _____.","back":"Alcalemia"},{"front":"¿Cómo se comporta la PaCO_2 respecto al pH en un trastorno respiratorio primario?","back":"Se mueve en sentido inverso al pH."},{"front":"¿Cómo se comporta el HCO_3^- respecto al pH en un trastorno metabólico primario?","back":"Se mueve en el mismo sentido que el pH."},{"front":"¿Qué trastorno primario se sospecha si hay acidemia y la PaCO_2 está elevada?","back":"Acidosis respiratoria."},{"front":"¿Qué trastorno primario se sospecha si hay acidemia y el HCO_3^- está disminuido?","back":"Acidosis metabólica."},{"front":"¿Qué trastorno primario se sospecha si hay alcalemia y la PaCO_2 está disminuida?","back":"Alcalosis respiratoria."},{"front":"¿Qué trastorno primario se sospecha si hay alcalemia y el HCO_3^- está aumentado?","back":"Alcalosis metabólica."},{"front":"¿Cuál es la fórmula de Winter para calcular la PaCO_2 esperada en la acidosis metabólica?","back":"PaCO_2 = 1.5 \\times HCO_3^- + 8 \\pm 2"},{"front":"¿Cómo se calcula la compensación de la PaCO_2 en una alcalosis metabólica?","back":"\\% \\Delta PaCO_2 \\approx 0.6 \\times \\Delta HCO_3^-"},{"front":"En la acidosis respiratoria aguda, ¿cuánto aumenta el HCO_3^- por cada +10 mmHg de PaCO_2?","back":"Aumenta +1 mEq/L."},{"front":"En la acidosis respiratoria crónica, ¿cuánto aumenta el HCO_3^- por cada +10 mmHg de PaCO_2?","back":"Aumenta de +3 a +3.5 mEq/L."},{"front":"En la alcalosis respiratoria aguda, ¿cuánto disminuye el HCO_3^- por cada -10 mmHg de PaCO_2?","back":"Disminuye -2 mEq/L."},{"front":"En la alcalosis respiratoria crónica, ¿cuánto disminuye el HCO_3^- por cada -10 mmHg de PaCO_2?","back":"Disminuye -5 mEq/L."},{"front":"¿Cuánto disminuye el pH por cada +10 de PaCO_2 en una acidosis respiratoria aguda?","back":"Disminuye 0.08."},{"front":"¿Cuánto disminuye el pH por cada +10 de PaCO_2 en una acidosis respiratoria crónica?","back":"Disminuye 0.03."},{"front":"¿Cuánto tiempo debe transcurrir para considerar un trastorno respiratorio como crónico?","back":"Debe transcurrir un tiempo mayor o igual a 48 horas."},{"front":"¿Cuál es la causa más frecuente de hipercalcemia en la población general?","back":"El hiperparatiroidismo primario."},{"front":"¿Cuál es la causa etiológica principal del hiperparatiroidismo primario en el 80-85 % de los casos?","back":"Un adenoma único paratiroideo."},{"front":"¿Cuáles son los síntomas gastrointestinales comunes de la hipercalcemia leve?","back":"Estreñimiento, anorexia, náuseas, vómito y dolor abdominal."},{"front":"¿Qué alteración en el intervalo del EKG se asocia a la hipercalcemia grave?","back":"Acortamiento del intervalo QTc."},{"front":"¿A partir de qué nivel de calcio sérico se debe sospechar de una etiología por malignidad?","back":"Calcio mayor a 14 mg/dL."},{"front":"¿Cuál es el tratamiento inicial para disminuir los niveles de calcio en una crisis aguda?","back":"Administración de líquidos intravenosos para aumentar el volumen."},{"front":"¿En qué pacientes con hiperparatiroidismo primario se indica el tratamiento quirúrgico?","back":"En pacientes sintomáticos o con calcio sérico >1 mg/dL sobre el límite normal."},{"front":"¿Qué alteraciones bioquímicas caracterizan al hipoparatiroidismo?","back":"Hipocalcemia asociada a hiperfosfatemia."},{"front":"¿Cuál es la causa más común de hipoparatiroidismo?","back":"La extirpación quirúrgica de las glándulas paratiroides."},{"front":"¿En qué consiste el signo de Chvostek?","back":"Contracción de los músculos faciales al golpear el nervio facial."},{"front":"¿En qué consiste el signo de Trousseau?","back":"Espasmo carpopedal tras inflar el manguito del esfigmomanómetro."},{"front":"¿Cuáles son los síntomas neurológicos graves que puede causar la hipocalcemia?","back":"Tetania, laringoespasmo o convulsiones generalizadas."},{"front":"¿Cuál es el parámetro de laboratorio de elección para el diagnóstico de hipoparatiroidismo?","back":"La medición del calcio ionizado."},{"front":"¿Cuál es el tratamiento de urgencia para un paciente con tetania por hipocalcemia?","back":"Gluconato de calcio intravenoso."},{"front":"¿Qué tratamiento se indica para el manejo de la hipocalcemia crónica?","back":"Calcio y Vitamina D por vía oral."},{"front":"¿A qué alteración hormonal se debe la acromegalia?","back":"A un aumento de la secreción de hormona somatotropa (hormona del crecimiento)."},{"front":"¿Cuál es la causa más frecuente de acromegalia?","back":"Adenomas hipofisarios."},{"front":"¿A qué edad promedio suele presentarse la acromegalia?","back":"Entre los 40 y 45 años."},{"front":"¿Qué hallazgo físico se refiere al crecimiento excesivo de la mandíbula en la acromegalia?","back":"Prognatismo"},{"front":"¿Qué complicación respiratoria se asocia a la macroglosia en pacientes acromegálicos?","back":"Síndrome de Apnea Obstructiva del Sueño (SAOS)."},{"front":"¿Qué defecto visual es característico de un macroadenoma hipofisario?","back":"Hemianopsia bitemporal."},{"front":"¿Cuál es el estudio diagnóstico inicial de elección en la sospecha de acromegalia?","back":"Medición del factor de crecimiento similar a la insulina tipo 1 (IGF-1)."},{"front":"¿Cuál es la prueba confirmatoria para el diagnóstico de acromegalia?","back":"Prueba de supresión de hormona del crecimiento con glucosa oral."},{"front":"¿Qué fármaco análogo de la somatostatina se utiliza para el tratamiento sintomático de la acromegalia?","back":"Octreótide"},{"front":"¿Qué efecto secundario biliar es común con el uso prolongado de octreótide?","back":"Litiasis vesicular."},{"front":"¿Cuál es el tratamiento quirúrgico de elección para el adenoma hipofisario en acromegalia?","back":"Cirugía transesfenoidal."},{"front":"En trastornos metabólicos, el pH y el HCO_3^- se mueven en _____ dirección.","back":"la misma"},{"front":"En trastornos respiratorios, el pH y la PaCO_2 se mueven en direcciones _____.","back":"opuestas"},{"front":"¿Cuál es la presentación clínica más común del hiperparatiroidismo primario?","back":"Asintomático o con hipercalcemia leve."},{"front":"¿Qué síntoma cutáneo/sensorial es el más frecuente en el hipoparatiroidismo postoperatorio?","back":"Parestesias en espalda y piernas."},{"front":"¿Cómo se encuentra la excitabilidad neuromuscular en un paciente con hipoparatiroidismo?","back":"Se encuentra aumentada debido a la hipocalcemia."},{"front":"La tríada bioquímica del hipoparatiroidismo es: hipocalcemia, hiperfosfatemia y niveles _____ de paratohormona.","back":"bajos (o deficientes)"},{"front":"El signo de _____ se busca percutiendo el nervio facial por delante del conducto auditivo externo.","back":"Chvostek"}]},"15":{"num":15,"name":"INTRODUCCION A HEMATOLOGIA","cards":[{"front":"¿Cuáles son los valores normales de hemoglobina en hombres según el material?","back":"13-17 g/dL"},{"front":"¿Cuáles son los valores normales de hemoglobina en mujeres según el material?","back":"12-15 g/dL"},{"front":"Rango normal del Volumen Corpuscular Medio (VCM):","back":"80-100 fL"},{"front":"Rango normal de la Hemoglobina Corpuscular Media (HCM):","back":"27-33 pg"},{"front":"Rango normal del Ancho de Distribución Eritrocitaria (ADE o RDW):","back":"11-15%"},{"front":"¿Cuál es el porcentaje normal de reticulocitos en sangre periférica?","back":"2-3%"},{"front":"Rango normal de leucocitos totales:","back":"4,000-12,000 /\\mu L"},{"front":"Rango normal de plaquetas:","back":"150,000-450,000 /\\mu L"},{"front":"¿Cómo se define la anemia en hombres según el hematocrito?","back":"Menor a 41%"},{"front":"¿Cómo se define la anemia en mujeres según el nivel de hemoglobina?","back":"Menor a 12 g/dL"},{"front":"¿Cuál es la causa más común de anemia a nivel mundial?","back":"Deficiencia de hierro"},{"front":"Mencione las dos causas principales de deficiencia de hierro:","back":"Déficit de aporte y hemorragias"},{"front":"¿Qué término se utiliza para describir la clínica de anemia cuando aún no se cuenta con resultados de laboratorio?","back":"Síndrome anémico"},{"front":"¿Qué estudio permite observar el tamaño, forma e inclusiones de los eritrocitos?","back":"Frotis de sangre periférica"},{"front":"¿En qué célula precursora se encuentra hemoglobina por primera vez?","back":"Proeritroblasto"},{"front":"¿Cuál es el primer sitio de hematopoyesis en el feto?","back":"Saco vitelino"},{"front":"¿Cuál es el segundo sitio de formación de sangre en el feto?","back":"Hígado"},{"front":"¿Cuál es el tercer sitio donde se forma sangre en el feto?","back":"Bazo"},{"front":"¿Para qué sirve el recuento de reticulocitos en el abordaje de las anemias?","back":"Para distinguir entre anemias regenerativas y arregenerativas"},{"front":"Una anemia con menos del 2% de reticulocitos se clasifica como:","back":"Arregenerativa"},{"front":"Una anemia con más del 3% de reticulocitos se clasifica como:","back":"Regenerativa"},{"front":"¿Qué vía metabólica del eritrocito produce ATP para energía?","back":"Vía glucolítica de Embden-Meyerhof"},{"front":"¿Qué produce la vía de la hexosa-monofosfato en el eritrocito?","back":"NADPH"},{"front":"¿Cuál es la función principal del NADPH en el metabolismo del eritrocito?","back":"Protección contra radicales libres"},{"front":"¿Cuál es la causa más frecuente de macrocitosis sin anemia?","back":"Alcoholismo"},{"front":"¿Cuál es la causa más frecuente de anemia macrocítica no megaloblástica?","back":"Hepatopatías"},{"front":"¿En qué parte del tubo digestivo se absorbe el hierro?","back":"Duodeno"},{"front":"¿En qué parte del tubo digestivo se absorbe el ácido fólico?","back":"Yeyuno"},{"front":"¿En qué parte del tubo digestivo se absorbe la vitamina B_{12}?","back":"Íleon terminal"},{"front":"Mencione tres grupos de riesgo para padecer anemia:","back":"Niños 0-5 años, mujeres en edad reproductiva y adultos mayores"},{"front":"Morfología clásica de la anemia ferropénica:","back":"Microcítica e hipocrómica"},{"front":"¿A qué se asocia la deficiencia de hierro en hombres?","back":"Sangrado digestivo"},{"front":"¿A qué se asocia la deficiencia de hierro en mujeres?","back":"Menstruación"},{"front":"¿Qué evaluación se recomienda semestralmente en adultos mayores para prevenir la anemia ferropénica?","back":"Evaluación odontológica"},{"front":"¿Cuál es la profilaxis de hierro indicada en embarazadas a partir de la semana 20?","back":"60 mg diarios"},{"front":"¿Cuál es la dosis de hierro profiláctico para niños de madres con deficiencia de hierro?","back":"2 mg/kg/día durante 6 meses"},{"front":"Síntomas que integran el síndrome anémico:","back":"Fatiga, taquicardia, palpitaciones y disnea"},{"front":"Definición de pica (pagofagia):","back":"Deseo irresistible de comer hielo"},{"front":"Triada del síndrome de Plummer-Vinson:","back":"Anemia ferropénica, membranas esofágicas y queilitis angular"},{"front":"¿Qué proteína saca el hierro del enterocito hacia la sangre?","back":"Ferroportina"},{"front":"¿Qué proteína transporta el hierro en el torrente sanguíneo?","back":"Transferrina"},{"front":"Forma de almacenamiento del hierro en los macrófagos del hígado:","back":"Ferritina"},{"front":"¿Cuál es el primer cambio analítico en la cinética de hierro ante una deficiencia?","back":"Disminución de la ferritina"},{"front":"¿Cuál es la mejor prueba diagnóstica para evaluar la deficiencia de hierro?","back":"Ferritina"},{"front":"Estándar de oro (Gold Standard) para el diagnóstico de anemia ferropénica:","back":"Biopsia de médula ósea con tinción de Perls (Azul de Prusia)"},{"front":"¿Cuál es la primera línea de tratamiento para la anemia ferropénica?","back":"Hierro oral (Sulfato o Gluconato ferroso)"},{"front":"¿Qué sustancia mejora la absorción del hierro oral?","back":"Vitamina C (ácidos)"},{"front":"Dosis de hierro elemental recomendada en adultos para tratamiento:","back":"180 mg/día dividido en 3 dosis"},{"front":"¿Cuánto tiempo debe durar el tratamiento con hierro según la GPC?","back":"El doble del tiempo que tardó en normalizarse la hemoglobina"},{"front":"¿Cuál es el parámetro hematológico que se corrige primero (a los 10 días) tras iniciar hierro?","back":"Reticulocitos"},{"front":"¿Cuánto tiempo tarda la hemoglobina en normalizarse con tratamiento adecuado?","back":"2 meses"},{"front":"¿Cuánto tiempo tarda en normalizarse la ferritina con tratamiento?","back":"3-6 meses"},{"front":"¿Cuál es la principal indicación para el uso de hierro parenteral?","back":"Intolerancia grave al hierro oral"},{"front":"¿Qué cantidad de oxígeno transporta 1 gramo de hemoglobina saturada al 100%?","back":"1.34 mL"},{"front":"¿Qué tipo de anemia producen las deficiencias de ácido fólico y vitamina B_{12}?","back":"Anemia megaloblástica"},{"front":"Valor de VCM característico en anemias megaloblásticas:","back":"Mayor a 100 fL (típicamente >115 fL)"},{"front":"¿Cuánto tiempo duran las reservas corporales de ácido fólico?","back":"2-3 meses"},{"front":"Mencione tres fármacos que pueden causar deficiencia de ácido fólico:","back":"Fenitoína, TMP-SMX y sulfadiazina"},{"front":"¿Qué síntoma clínico diferencia la deficiencia de B_{12} de la de ácido fólico?","back":"Alteraciones neurológicas (parestesias, demencia)"},{"front":"Perfil bioquímico de la deficiencia de ácido fólico (Ácido fólico, Homocisteína, Ácido Metilmalónico):","back":"Fólico bajo, homocisteína alta, metilmalónico normal"},{"front":"¿Cuánto tiempo duran las reservas corporales de vitamina B_{12}?","back":"2-3 años"},{"front":"Causa más frecuente de deficiencia de vitamina B_{12} para términos ENARM:","back":"Anemia perniciosa"},{"front":"Hallazgo característico en el frotis de sangre de un paciente con deficiencia de B_{12}:","back":"Neutrófilos hipersegmentados"},{"front":"Perfil bioquímico de la deficiencia de vitamina B_{12} (B12, Homocisteína, Ácido Metilmalónico):","back":"B_{12} baja, homocisteína alta, metilmalónico alto"},{"front":"¿Cuál es la fisiopatología de la anemia perniciosa?","back":"Gastritis atrófica autoinmune que causa déficit de factor intrínseco"},{"front":"¿Qué anticuerpo es el más específico para el diagnóstico de anemia perniciosa?","back":"Antifactor intrínseco"},{"front":"¿Qué anticuerpo es el más sensible para el diagnóstico de anemia perniciosa?","back":"Anti-células parietales"},{"front":"¿Con qué neoplasia maligna se asocia el 10% de los pacientes con anemia perniciosa?","back":"Adenocarcinoma gástrico"},{"front":"¿Cuál es el tratamiento de por vida para la anemia perniciosa?","back":"Vitamina B_{12} intramuscular"},{"front":"¿Qué mediadores inflamatorios reducen la absorción de hierro en la anemia por enfermedad crónica?","back":"Hepcidina e IL-6"},{"front":"¿Cuál es el segundo tipo de anemia más frecuente en general?","back":"Anemia por enfermedad crónica (inflamatoria)"},{"front":"Perfil de hierro en anemia por enfermedad crónica (Hierro, Ferritina, Transferrina):","back":"Hierro disminuido, ferritina elevada o normal, transferrina aumentada"},{"front":"¿Cuál es el umbral de hemoglobina para transfundir a un paciente con anemia inflamatoria?","back":"Menor a 7 g/dL"},{"front":"¿Qué hallazgo clínico obliga a descartar aplasia medular si hay afectación de las 3 líneas celulares?","back":"Ausencia de esplenomegalia"},{"front":"¿Qué criterios se utilizan para estadificar la aplasia medular?","back":"Criterios de Camitta"},{"front":"¿Cuál es el tratamiento de elección para la anemia aplásica?","back":"Trasplante alogénico"},{"front":"¿Qué tipo de herencia tiene la anemia de Fanconi?","back":"Autosómica recesiva"},{"front":"Mencione tres signos físicos de la anemia de Fanconi:","back":"Manchas café con leche, hipoplasia del pulgar y malformaciones renales"},{"front":"¿Qué tipo de hemólisis se asocia clásicamente con anticuerpos fríos?","back":"Intravascular"},{"front":"¿Qué tipo de hemólisis se asocia clásicamente con anticuerpos calientes?","back":"Extravascular"}]},"16":{"num":16,"name":"ANEMIA HEMOLITICA","cards":[{"front":"¿Cuál es el rango de referencia normal del Volumen Corpuscular Medio (\\text{VCM})?","back":"80-100 \\text{fL}."},{"front":"¿Cuál es el valor normal de la Concentración Media de Hemoglobina Corpuscular (\\text{CMHC})?","back":"33-35 \\text{g/dL}."},{"front":"¿Cuál es el rango normal de reticulocitos en una biometría hemática convencional?","back":"2-3 \\%."},{"front":"¿Cómo se define la anemia hemolítica en función de la producción de reticulocitos?","back":"Es una anemia regenerativa con reticulocitos elevados."},{"front":"¿Qué otro nombre recibe la esferocitosis hereditaria?","back":"Enfermedad de Minkowski-Chauffard."},{"front":"¿Cuál es la proteína del citoesqueleto del eritrocito que se pierde con mayor frecuencia en la esferocitosis hereditaria?","back":"Anquirina."},{"front":"Mencione las tres proteínas (además de la anquirina) que pueden estar defectuosas en la esferocitosis hereditaria.","back":"\\alpha y \\beta espectrina, banda 3 y palidina."},{"front":"¿Cuál es el patrón de herencia más común en la esferocitosis hereditaria?","back":"Autosómico dominante."},{"front":"¿Cuál es la anemia hemolítica hereditaria más común en México?","back":"Esferocitosis hereditaria."},{"front":"¿Qué valor de la Concentración Media de Hemoglobina Corpuscular (\\text{CMHC}) sugiere esferocitosis hereditaria?","back":"Un valor mayor a 36 \\text{g/dL}."},{"front":"¿Cuál es el estudio de laboratorio estándar de oro (\\text{Gold Standard}) para el diagnóstico de esferocitosis hereditaria?","back":"Prueba de fragilidad osmótica."},{"front":"¿Cómo se encuentra típicamente el resultado de la prueba de Coombs en un paciente con esferocitosis hereditaria?","back":"Coombs directo negativo."},{"front":"¿Cuál es el tratamiento farmacológico indicado durante las exacerbaciones de esferocitosis hereditaria con reticulocitosis muy elevada?","back":"Prednisona."},{"front":"¿A qué edad se recomienda realizar la esplenectomía en pacientes con esferocitosis hereditaria moderada o grave?","back":"A los 6 años."},{"front":"¿Contra qué microorganismos encapsulados se debe vacunar obligatoriamente a un paciente antes de una esplenectomía?","back":"Neumococo, Meningococo y H. \\text{ influenzae}."},{"front":"¿Qué complicación biliar es frecuente en pacientes con esferocitosis hereditaria debido a la hemólisis crónica?","back":"Litiasis vesicular (litos pigmentados)."},{"front":"¿Cuál es el patrón de herencia de la deficiencia de glucosa-6-fosfato deshidrogenasa (\\text{G6PD})?","back":"Herencia ligada al cromosoma X."},{"front":"¿Cuál es el mecanismo fisiopatológico principal de la hemólisis en la deficiencia de \\text{G6PD}?","back":"Disminución de glutatión reducido para proteger al eritrocito de agentes oxidantes."},{"front":"¿Qué alimento desencadena clásicamente las crisis hemolíticas en la deficiencia de \\text{G6PD}?","back":"Habas (favismo)."},{"front":"Mencione tres fármacos que pueden precipitar una crisis hemolítica en un paciente con deficiencia de \\text{G6PD}.","back":"Nitrofurantoína, sulfas y primaquina."},{"front":"¿Qué hallazgos característicos se observan en el frotis de sangre periférica durante una crisis de deficiencia de \\text{G6PD}?","back":"Cuerpos de Heinz y células mordidas."},{"front":"¿Cuál es el tratamiento principal para la deficiencia de \\text{G6PD}?","back":"Evitar la ingesta de alimentos (habas) y fármacos precipitantes."},{"front":"¿Qué tipo de defecto estructural de la hemoglobina caracteriza a las talasemias?","back":"Defecto cuantitativo en la síntesis de las cadenas de globina."},{"front":"¿En qué cromosoma se localiza el defecto genético de la \\alpha-talasemia?","back":"Cromosoma 16."},{"front":"¿En qué cromosoma se localiza el defecto genético de la \\beta-talasemia?","back":"Cromosoma 11."},{"front":"¿Cuál es la causa más común de talasemia a nivel mundial?","back":"\\beta-talasemia."},{"front":"¿A qué edad suele manifestarse clínicamente la \\beta-talasemia mayor?","back":"A partir de los 6 meses de vida."},{"front":"¿Qué hallazgos radiológicos craneales y faciales son típicos de la expansión de la médula ósea en la talasemia mayor?","back":"Cráneo en cepillo y facies de ardilla."},{"front":"¿Cómo se encuentran típicamente el Ancho de Distribución Eritrocitaria (\\text{ADE}) y la ferritina en la talasemia menor?","back":"\\text{ADE} menor a 11 y ferritina normal."},{"front":"¿Cuál es el estudio de elección para el diagnóstico definitivo de las talasemias?","back":"Electroforesis de hemoglobina."},{"front":"¿Qué fármaco quelante de hierro se utiliza en pacientes con talasemia mayor sometidos a transfusiones frecuentes?","back":"Desferroxamina."},{"front":"¿Cuál es el tratamiento definitivo para la talasemia mayor?","back":"Trasplante alogénico de médula ósea."},{"front":"¿Cuál es la composición de cadenas de la Hemoglobina A (del adulto)?","back":"\\alpha_2\\beta_2."},{"front":"¿Cuál es la composición de cadenas de la Hemoglobina Fetal (\\text{HbF})?","back":"\\alpha_2\\gamma_2."},{"front":"¿Qué mutación molecular específica da origen a la Hemoglobina S en la anemia falciforme?","back":"Sustitución de ácido glutámico por valina en la posición 6 de la cadena \\beta."},{"front":"¿Cuál es el patrón de herencia de la anemia falciforme (drepanocitosis)?","back":"Autosómico recesivo."},{"front":"¿Cuál es la causa más frecuente de muerte en pacientes con anemia falciforme?","back":"Sepsis neumocócica."},{"front":"¿Qué virus se asocia frecuentemente con el desencadenamiento de crisis aplásicas en pacientes con anemia falciforme?","back":"Parvovirus B19."},{"front":"¿Qué forma característica adoptan los eritrocitos en el frotis periférico de un paciente con drepanocitosis?","back":"Eritrocitos en forma de hoz o media luna (drepanocitos)."},{"front":"¿Qué porcentaje aproximado de Hemoglobina S (\\text{HbS}) se espera encontrar en la electroforesis de un paciente con anemia falciforme?","back":"85-95 \\%."},{"front":"¿Cuál es el pilar del tratamiento inicial durante una crisis dolorosa en la anemia falciforme?","back":"Rehidratación agresiva y analgesia."},{"front":"¿Qué fármaco se utiliza para aumentar la Hemoglobina Fetal y reducir la frecuencia de crisis en la anemia falciforme?","back":"Hidroxiurea."},{"front":"¿De qué enfermedad infecciosa confiere protección el rasgo falciforme?","back":"Malaria (paludismo)."},{"front":"¿Cuál es el isotipo de anticuerpo principal involucrado en la Anemia Hemolítica Autoinmune (\\text{AHAI}) por anticuerpos calientes?","back":"\\text{IgG}."},{"front":"¿Cuál es el isotipo de anticuerpo involucrado en la \\text{AHAI} por anticuerpos fríos?","back":"\\text{IgM}."},{"front":"¿A qué temperatura ocurre la aglutinación óptima en la \\text{AHAI} por anticuerpos calientes?","back":"37 ^{\\circ}\\text{C}."},{"front":"¿A qué temperatura ocurre la aglutinación en la enfermedad por crioaglutininas?","back":"22 ^{\\circ}\\text{C} (o menores)."},{"front":"¿Cuál es el sitio predominante de hemólisis en la \\text{AHAI} por anticuerpos calientes?","back":"Extravascular (en el bazo)."},{"front":"¿Qué microorganismo se asocia frecuentemente con la aparición de anticuerpos fríos (\\text{IgM})?","back":"Mycoplasma \\text{ pneumoniae} o Virus de Epstein-Barr."},{"front":"¿Cuál es el tratamiento de elección inicial para la \\text{AHAI} por anticuerpos calientes?","back":"Esteroides (Prednisona o Metilprednisolona)."},{"front":"¿Cuál es la medida terapéutica más importante en la \\text{AHAI} por anticuerpos fríos?","back":"Evitar la exposición al frío (medidas térmicas)."},{"front":"¿Cuál es el mecanismo fisiopatológico de la Hemoglobinuria Paroxística Nocturna (\\text{HPN})?","back":"Mutación somática adquirida en el gen \\text{PIGA} que causa déficit de anclaje \\text{GPI}."},{"front":"¿Qué proteínas reguladoras del complemento faltan en la membrana de los eritrocitos en la \\text{HPN}?","back":"\\text{CD55} (DAF) y \\text{CD59} (MIRL)."},{"front":"¿Cuál es la tríada clínica clásica de la Hemoglobinuria Paroxística Nocturna?","back":"Hemólisis intravascular crónica, pancitopenia y trombosis venosa atípica."},{"front":"¿Cuál es el estándar de oro para el diagnóstico de \\text{HPN}?","back":"Citometría de flujo (detecta ausencia de \\text{CD55}/\\text{CD59})."},{"front":"¿Cuál es el anticuerpo monoclonal indicado para el tratamiento de la \\text{HPN}?","back":"Eculizumab."},{"front":"¿Qué tipo de anemia se caracteriza por pancitopenia y médula ósea hipocelular?","back":"Anemia aplásica."},{"front":"¿Qué criterios se utilizan para estadificar la gravedad de la anemia aplásica?","back":"Criterios de Camitta."},{"front":"¿Cuál es la tríada de hallazgos en la anemia de Fanconi?","back":"Pancitopenia congénita, malformaciones renales/esqueléticas y manchas café con leche."},{"front":"¿Qué malformación en las extremidades superiores es típica de la Anemia de Fanconi?","back":"Hipoplasia del pulgar."},{"front":"¿Cuál es el tratamiento de elección para la anemia aplásica grave en pacientes jóvenes?","back":"Trasplante alogénico de células progenitoras."},{"front":"¿Qué tipo de hemólisis (intra o extravascular) predomina en la \\text{AHAI} por anticuerpos fríos?","back":"Intravascular (vía \\text{MAC})."},{"front":"En la electroforesis de hemoglobina de un adulto sano, ¿qué porcentaje aproximado representa la \\text{HbA}?","back":"96-98 \\%."},{"front":"¿Qué hallazgo en el frotis sugiere una hemólisis de tipo intravascular?","back":"Esquistocitos."},{"front":"¿Qué hallazgo en el frotis sugiere una hemólisis de tipo extravascular?","back":"Esferocitos."},{"front":"¿Cómo se clasifica una esferocitosis hereditaria con hemoglobina de 8-12 \\text{g/dL} y reticulocitos > 6 \\%?","back":"Esferocitosis moderada."},{"front":"Concepto: Prueba de Coombs Directo.","back":"Detecta anticuerpos o complemento adheridos directamente a la membrana del eritrocito del paciente."},{"front":"¿Por qué los pacientes con \\text{HPN} presentan crisis de hemoglobinuria clásicamente por la mañana?","back":"La acidosis respiratoria leve durante el sueño actúa como gatillo para el complemento."},{"front":"¿Qué fármacos anticonvulsivos se asocian al desarrollo de anemia aplásica?","back":"Fentoína o carbamazepina (según contexto de riesgo por fármacos)."},{"front":"¿Cuál es la causa de muerte por sobrecarga de hierro en pacientes con talasemia mayor?","back":"Falla cardíaca o toxicidad orgánica por hemosiderosis."},{"front":"¿Qué suplementación vitamínica es fundamental como soporte en casi todas las anemias hemolíticas crónicas?","back":"Ácido fólico."},{"front":"¿Cuál es la afinidad por el oxígeno de la Hemoglobina Fetal en comparación con la Hemoglobina A?","back":"La \\text{HbF} tiene una afinidad mucho mayor por el oxígeno."},{"front":"En la anemia falciforme, ¿qué fenómeno físico ocurre con la desoxi-hemoglobina que daña al eritrocito?","back":"Polimerización de la hemoglobina \\text{S}."},{"front":"¿Cuál es la composición de cadenas de la Hemoglobina A_2?","back":"\\alpha_2\\delta_2."},{"front":"¿Cómo se encuentra el nivel de haptoglobina en una hemólisis intravascular?","back":"Haptoglobina ausente o muy disminuida."},{"front":"¿Cuál es el tratamiento definitivo para la Hemoglobinuria Paroxística Nocturna?","back":"Trasplante de médula ósea."}]},"17":{"num":17,"name":"LEUCEMIAS","cards":[{"front":"¿A partir de qué tipo celular específico se origina el Linfoma de Hodgkin?","back":"Se origina en los linfocitos B maduros localizados en el centro germinal de los ganglios linfáticos."},{"front":"¿Qué células gigantes multinucleadas son características, aunque no patognomónicas, del Linfoma de Hodgkin?","back":"Las células de Reed-Sternberg."},{"front":"¿Con qué agente viral se ha encontrado una asociación etiológica frecuente en el Linfoma de Hodgkin?","back":"Virus de Epstein-Barr (VEB)."},{"front":"¿Qué incremento de riesgo para Linfoma de Hodgkin presentan los pacientes con VIH/SIDA?","back":"Presentan un riesgo 8 veces mayor que la población general."},{"front":"Mencione los tres marcadores inmunofenotípicos característicos del Linfoma de Hodgkin.","back":"Los marcadores son CD15, CD30 y Ki-1."},{"front":"¿Qué criterio numérico define a una adenopatía como \"enfermedad voluminosa\" o masa \"Bulky\"?","back":"La presencia de una masa con un diámetro mayor a 10 cm."},{"front":"¿Cuál es la localización más común de las adenopatías periféricas en el Linfoma de Hodgkin?","back":"La región cervical."},{"front":"¿Qué síntoma típico del Linfoma de Hodgkin se desencadena específicamente tras la ingesta de alcohol?","back":"Dolor en las adenopatías periféricas."},{"front":"¿Qué porcentaje de pacientes con Linfoma de Hodgkin presenta los denominados \"síntomas B\"?","back":"El 40% de los pacientes."},{"front":"¿Cuál es el síntoma dermatológico típico asociado al Linfoma de Hodgkin?","back":"El prurito."},{"front":"¿Cuál es la principal vía de diseminación del Linfoma de Hodgkin?","back":"La vía linfática."},{"front":"¿Qué variante histológica del Linfoma de Hodgkin presenta el mejor pronóstico?","back":"La variante linfocítico nodular."},{"front":"¿En qué variante del Linfoma de Hodgkin las células neoplásicas tienen apariencia de \"palomita de maíz\"?","back":"En la variante linfocítico nodular."},{"front":"¿Cuál es la variante de Linfoma de Hodgkin más frecuente en Estados Unidos y Europa?","back":"La variante de esclerosis nodular."},{"front":"¿Qué morfología celular de Reed-Sternberg es característica de la variante de esclerosis nodular?","back":"La morfología lacunar."},{"front":"¿Cuál es el estadio clínico más frecuente al momento del diagnóstico en la esclerosis nodular?","back":"El Estadio II."},{"front":"¿Qué variante de Linfoma de Hodgkin es común en pacientes con VIH/SIDA y tiene una edad media de presentación de 38 años?","back":"La variante de celularidad mixta."},{"front":"¿Qué caracteriza la arquitectura celular de la variante de celularidad mixta en el LH?","back":"Células de Reed-Sternberg distribuidas en un medio difuso sin fibrosis esclerosante."},{"front":"¿Cuál es la variante histológica más rara del Linfoma de Hodgkin?","back":"La variante de depleción linfocitaria."},{"front":"¿En qué localización anatómica suele presentarse la variante de depleción linfocitaria?","back":"En los ganglios retroperitoneales."},{"front":"¿Qué variante del Linfoma de Hodgkin se asocia con el peor pronóstico clínico?","back":"La variante de depleción linfocitaria."},{"front":"Según la estadificación de Ann Arbor, ¿qué define al Estadio I?","back":"Afectación de una sola región ganglionar o un solo sitio extralinfático localizado."},{"front":"Según la estadificación de Ann Arbor, ¿qué define al Estadio II?","back":"Afectación de dos o más regiones ganglionares del mismo lado del diafragma."},{"front":"Según la estadificación de Ann Arbor, ¿qué define al Estadio III?","back":"Afectación de regiones ganglionares a ambos lados del diafragma."},{"front":"Según la estadificación de Ann Arbor, ¿qué define al Estadio IV?","back":"Infiltración difusa o diseminada de uno o más órganos extranodales, con o sin involucro ganglionar."},{"front":"¿A qué se refiere la letra \"B\" en la estadificación de los linfomas?","back":"A la presencia de síntomas sistémicos como fiebre mayor a 38^{\\circ}C, diaforesis nocturna o pérdida de peso."},{"front":"¿Qué porcentaje de pérdida de peso en los últimos 6 meses se considera un síntoma B?","back":"Una pérdida de peso mayor al 10%."},{"front":"¿Cómo se define una masa mediastinal voluminosa (X) en la radiografía de tórax?","back":"Cuando el tumor es mayor a una tercera parte del diámetro interno del tórax medido entre T5 y T6."},{"front":"¿Cuál es el estándar de oro para el diagnóstico definitivo del Linfoma de Hodgkin?","back":"La biopsia excisional de ganglio linfático."},{"front":"¿Qué fármacos integran el esquema de quimioterapia ABVD?","back":"Adriamicina, Bleomicina, Vinblastina y Dacarbacina."},{"front":"¿Cuántos ciclos de ABVD se administran típicamente en el tratamiento del Linfoma de Hodgkin?","back":"Se administran 4 ciclos."},{"front":"¿Cuál es la dosis estándar de radioterapia utilizada en el Linfoma de Hodgkin?","back":"Dosis de 20 a 30 Gy."},{"front":"¿Cuáles son los dos tipos más frecuentes de Linfoma No Hodgkin?","back":"El difuso de células B grandes y el folicular."},{"front":"¿Qué agente infeccioso se asocia específicamente al linfoma gástrico tipo MALT?","back":"La bacteria H. pylori."},{"front":"¿En qué linaje celular es más común el Linfoma No Hodgkin en adultos?","back":"En las células B."},{"front":"¿Qué translocación citogenética es característica del Linfoma de Burkitt?","back":"La translocación t(8;14)."},{"front":"¿Qué translocación citogenética se asocia al Linfoma Folicular?","back":"La translocación t(14;18)."},{"front":"¿Qué translocación citogenética se asocia al Linfoma de células del manto?","back":"La translocación t(11;14)."},{"front":"¿Cómo suele ser la linfadenopatía característica del Linfoma No Hodgkin?","back":"Es una linfadenopatía generalizada y no dolorosa."},{"front":"¿Qué hallazgo clínico abdominal es típico del Linfoma de Burkitt?","back":"Una masa abdominal mayor a 10 cm."},{"front":"¿Cuál es el linfoma considerado más agresivo debido al rápido crecimiento de los ganglios?","back":"El Linfoma de Burkitt."},{"front":"¿En qué localización anatómica suelen presentarse las neoplasias de células T originadas en el timo?","back":"En el mediastino y el cuello."},{"front":"Según el material, ¿qué complicación vascular puede presentarse en neoplasias de células T del mediastino?","back":"El síndrome de la vena cava inferior."},{"front":"¿Qué patrón histológico es el estándar de oro diagnóstico para el Linfoma de Burkitt?","back":"El patrón en \"cielo estrellado\"."},{"front":"¿Qué fármacos componen el esquema de quimioterapia CHOP para Linfoma No Hodgkin?","back":"Ciclofosfamida, Doxorrubicina, Vincristina y Prednisona."},{"front":"¿Cuántos ciclos del esquema CHOP se administran habitualmente en el LNH?","back":"Se administran 3 ciclos."},{"front":"¿Cuál es la dosis de radioterapia recomendada en el tratamiento del Linfoma No Hodgkin?","back":"Dosis de 30 a 36 Gy."},{"front":"¿Cómo se encuentra típicamente el hemograma en un paciente con Linfoma de Hodgkin?","back":"Se encuentra normal, ya que típicamente \"no leucemiza\"."},{"front":"¿Cuál es el orden de frecuencia de las adenopatías periféricas en el Linfoma de Hodgkin?","back":"Primero las cervicales y en segundo lugar las mediastínicas."},{"front":"¿Qué designación se utiliza en Ann Arbor para la infiltración localizada de un solo órgano extralinfático?","back":"Se utiliza el sufijo \"E\" (Estadio IE, IIE o IIIE)."}]},"18":{"num":18,"name":"ONCOHEMATOLOGIA","cards":[{"front":"¿De qué células específicas se origina el linfoma de Hodgkin?","back":"De los linfocitos B maduros localizados en el centro germinal de los ganglios linfáticos."},{"front":"¿Cuál es la célula gigante multinucleada característica, aunque no patognomónica, del linfoma de Hodgkin?","back":"La célula de Reed-Sternberg."},{"front":"Menciona los tres marcadores inmunohistoquímicos característicos del linfoma de Hodgkin.","back":"CD15, CD30 y Ki-1."},{"front":"¿Con qué agente viral se asocia frecuentemente la patogenia del linfoma de Hodgkin?","back":"El virus de Epstein-Barr (VEB)."},{"front":"¿Cuántas veces es mayor el riesgo de padecer linfoma de Hodgkin en pacientes con VIH/SIDA?","back":"8 veces mayor."},{"front":"En el linfoma de Hodgkin, ¿cuál es el sitio más frecuente de aparición de adenopatías periféricas?","back":"La región cervical."},{"front":"¿Qué síntoma cutáneo se considera típico y distintivo del linfoma de Hodgkin?","back":"El prurito."},{"front":"¿Qué fenómeno clínico ocurre en los ganglios de algunos pacientes con linfoma de Hodgkin tras consumir alcohol?","back":"Dolor en las adenopatías."},{"front":"¿Cuál es la principal vía de diseminación del linfoma de Hodgkin?","back":"La vía linfática."},{"front":"Define el concepto de 'enfermedad voluminosa' o 'masa bulky' en linfomas según el diámetro.","back":"Una masa que mide más de 10 cm."},{"front":"Según la clasificación de Ann Arbor, ¿qué define al Estadio I?","back":"Afectación de una sola región ganglionar o un solo sitio extralinfático localizado."},{"front":"Según la clasificación de Ann Arbor, ¿qué define al Estadio II?","back":"Afectación de dos o más regiones ganglionares del mismo lado del diafragma."},{"front":"¿Qué hallazgo define al Estadio III en la escala de Ann Arbor?","back":"Afectación de regiones ganglionares a ambos lados del diafragma."},{"front":"Describe el Estadio IV de la estadificación de Ann Arbor.","back":"Infiltración difusa o diseminada de uno o más órganos extranodales, con o sin involucro ganglionar."},{"front":"¿Cuáles son los tres 'síntomas B' específicos utilizados en la estadificación de linfomas?","back":"Fiebre > 38^{\\circ}C, diaforesis nocturna y pérdida de peso > 10% en los últimos 6 meses."},{"front":"En la estadificación de Ann Arbor, ¿qué significa el sufijo 'A'?","back":"Ausencia de síntomas sistémicos (síntomas B)."},{"front":"En radiografía de tórax, ¿cuándo se considera que un tumor mediastinal es 'masa bulky' (X)?","back":"Cuando el diámetro del tumor es mayor a un tercio del diámetro interno del tórax medido entre T5/T6."},{"front":"¿Cuál es el estudio 'gold estándar' para el diagnóstico definitivo del linfoma de Hodgkin?","back":"La biopsia excisional de ganglio linfático."},{"front":"¿Cuál es el hallazgo típico en un hemograma de un paciente con linfoma de Hodgkin?","back":"Hemograma normal (se dice que 'no leucemiza')."},{"front":"¿Qué variante histológica del linfoma de Hodgkin tiene el mejor pronóstico?","back":"El predominio linfocítico nodular."},{"front":"¿Qué morfología celular característica presentan las células neoplásicas en la variante de predominio linfocítico nodular?","back":"Células en 'palomita de maíz' (popcorn cells)."},{"front":"¿Cuál es la variante histológica más frecuente del linfoma de Hodgkin en EE.UU. y Europa?","back":"La esclerosis nodular."},{"front":"¿Qué tipo de células de Reed-Sternberg son características de la variante esclerosis nodular?","back":"Células lacunares."},{"front":"¿Cuál es el rango de edad más frecuente para la presentación de la variante esclerosis nodular?","back":"Entre 15 y 34 años."},{"front":"¿Qué variante histológica es la más común en pacientes con VIH/SIDA y tiene una edad media de presentación de 38 años?","back":"La celularidad mixta."},{"front":"¿Qué variante del linfoma de Hodgkin tiene el peor pronóstico y se asocia a ganglios retroperitoneales?","back":"La depleción linfocitaria."},{"front":"¿Qué fármacos componen el esquema de quimioterapia ABVD?","back":"Adriamicina (Doxorrubicina), Bleomicina, Vinblastina y Dacarbacina."},{"front":"¿Cuántos ciclos de ABVD se recomiendan usualmente seguidos de radioterapia?","back":"4 ciclos."},{"front":"¿Cuál es el rango de dosis de radioterapia (en Grays) utilizado típicamente en el linfoma de Hodgkin?","back":"20-30 Gy."},{"front":"¿Cuál es el origen celular más frecuente en los linfomas no Hodgkin (LNH)?","back":"Las células B."},{"front":"¿Cómo varía la frecuencia relativa de linfomas B frente a linfomas T en la población pediátrica comparada con los adultos?","back":"En pediatría la frecuencia se invierte, siendo más comunes los linfomas T."},{"front":"¿Qué dos subtipos de linfoma no Hodgkin son los más frecuentes en adultos?","back":"El difuso de células B grandes y el folicular."},{"front":"¿Qué agente infeccioso se asocia específicamente al linfoma gástrico tipo MALT?","back":"\\textit{Helicobacter pylori}."},{"front":"¿Qué translocación cromosómica es característica del linfoma de Burkitt?","back":"t(8;14)."},{"front":"¿Qué translocación cromosómica se asocia al linfoma folicular en adultos menores de 65 años?","back":"t(14;18)."},{"front":"¿Qué translocación cromosómica es típica del linfoma de manto?","back":"t(11;14)."},{"front":"¿Cuál es la característica clínica principal de la linfadenopatía en el linfoma no Hodgkin?","back":"Linfadenopatía generalizada no dolorosa."},{"front":"¿Qué porcentaje de pacientes con linfoma no Hodgkin presentan síntomas B?","back":"40%."},{"front":"¿En qué localización anatómica suele presentarse el linfoma de Burkitt en niños?","back":"Como una masa abdominal mayor a 10 cm."},{"front":"¿Cuál es la localización anatómica predominante de las neoplasias de células T (timo)?","back":"Mediastino y cuello."},{"front":"¿Qué complicación vascular puede presentarse en linfomas T de localización mediastinal?","back":"Síndrome de vena cava superior (aunque el material menciona inferior, clínicamente en mediastino es superior)."},{"front":"¿Qué patrón histológico es el hallazgo clásico en la biopsia del linfoma de Burkitt?","back":"Patrón en 'cielo estrellado'."},{"front":"¿Qué fármacos integran el esquema de quimioterapia CHOP?","back":"Ciclofosfamida, Doxorrubicina (Adriamicina), Vincristina y Prednisona."},{"front":"¿Cuántos ciclos del esquema CHOP se administran típicamente en el linfoma no Hodgkin?","back":"3 ciclos."},{"front":"¿Cuál es la dosis de radioterapia recomendada para el tratamiento del linfoma no Hodgkin?","back":"30-36 Gy."},{"front":"En el contexto de linfomas, ¿qué significan las siglas 'L y H'?","back":"Variedad linfocítica y/o histocítica."},{"front":"¿Cuál es el segundo sitio más frecuente de adenopatías en el linfoma de Hodgkin tras el cuello?","back":"La región mediastínica."},{"front":"Según la clasificación de Cotswolds, ¿qué indica el sufijo 'E'?","back":"Infiltración localizada de un solo órgano o sitio extralinfático."},{"front":"¿Qué variante de linfoma de Hodgkin se presenta con abundantes células de Hodgkin y Reed-Sternberg en un fondo con pocos linfocitos?","back":"La depleción linfocitaria."},{"front":"¿Cuál es el linfoma considerado más agresivo debido al rápido crecimiento de sus ganglios?","back":"El linfoma de Burkitt."},{"front":"La tríada de fiebre, pérdida de peso y diaforesis se conoce colectivamente como _____.","back":"Síntomas B."},{"front":"El esquema de tratamiento estándar para el linfoma de Hodgkin es el _____, mientras que para el linfoma no Hodgkin es el _____.","back":"ABVD / CHOP"},{"front":"La translocación t(8;14) involucra al protooncogén MYC y es típica del linfoma de _____.","back":"Burkitt"},{"front":"En la variante de _____ del linfoma de Hodgkin, el tejido linfoide es reemplazado por bandas de colágeno que circundan nódulos tumorales.","back":"Esclerosis nodular"},{"front":"Concepto: Células L y H","back":"Definición: Células neoplásicas con núcleo multilobulado (en palomita de maíz) características del linfoma de Hodgkin de predominio linfocítico nodular."},{"front":"Concepto: Clasificación de Ann Arbor Estadio IIE","back":"Definición: Afectación de dos o más regiones ganglionares del mismo lado del diafragma junto con infiltración localizada de un sitio extralinfático."}]},"19":{"num":19,"name":"ANORMALIDADES DE LA HEMOSTASIA","cards":[{"front":"¿Cuál es el trastorno hemorrágico hereditario más frecuente?","back":"Enfermedad de Von Willebrand."},{"front":"¿Qué glicoproteína se encarga de unir el colágeno subendotelial con el receptor plaquetario GPIb?","back":"Factor Von Willebrand (FVW)."},{"front":"Además de la adhesión plaquetaria, ¿qué factor de la coagulación estabiliza el FVW prolongando su vida media?","back":"Factor VIII."},{"front":"¿Qué tipo de herencia predomina en la Enfermedad de Von Willebrand?","back":"Autosómica dominante."},{"front":"La deficiencia cuantitativa parcial del FVW define a la Enfermedad de Von Willebrand tipo _____.","back":"1"},{"front":"¿Qué porcentaje de los casos de Enfermedad de Von Willebrand corresponden al tipo 1?","back":"75-85%."},{"front":"¿En qué consiste la alteración de la Enfermedad de Von Willebrand tipo 2?","back":"Deficiencia cualitativa del FVW."},{"front":"¿Qué tipo de deficiencia y herencia presenta la Enfermedad de Von Willebrand tipo 3?","back":"Deficiencia cuantitativa total con herencia autosómica recesiva."},{"front":"¿Cuál es la localización más frecuente del sangrado en la Enfermedad de Von Willebrand?","back":"Mucosas."},{"front":"¿Qué prueba de laboratorio se considera el estándar de confirmación para la Enfermedad de Von Willebrand?","back":"Cofactor de Ristocetina."},{"front":"¿A partir de qué nivel de actividad del FVW se genera riesgo de hemorragia?","back":"Menor a 30\\ UI/dL."},{"front":"¿Cuál es el tratamiento de elección para favorecer la liberación de FVW desde las células endoteliales?","back":"Desmopresina (DDAVP)."},{"front":"¿Qué opciones terapéuticas se recomiendan para el manejo de la menorragia en mujeres con Enfermedad de Von Willebrand?","back":"Anticonceptivos orales o DIU hormonal."},{"front":"En una embarazada con EvW tipo 1, el parto puede manejarse sin tratamiento si el nivel de cofactor de ristocetina es superior a _____.","back":"50\\ UI/dL."},{"front":"¿En qué condición obstétrica se debe evitar específicamente el uso de desmopresina (DDAVP)?","back":"Preeclampsia."},{"front":"¿Qué factor de la coagulación es deficiente en la Hemofilia A?","back":"Factor VIII."},{"front":"¿Qué tipo de herencia presentan tanto la Hemofilia A como la Hemofilia B?","back":"Ligada al cromosoma X."},{"front":"¿Cuál es la principal causa de muerte en pacientes con Hemofilia?","back":"Hemorragia por traumatismo craneoencefálico (TCE)."},{"front":"¿Qué manifestación clínica se considera patognomónica de la Hemofilia?","back":"Hemartrosis (hemorragia articular)."},{"front":"¿Cuál es la articulación más frecuentemente afectada por hemartrosis en adultos con hemofilia?","back":"Rodilla."},{"front":"¿Qué articulación es el sitio más frecuente de hemartrosis en pacientes pediátricos y adolescentes con hemofilia?","back":"Tobillo."},{"front":"¿Qué hallazgo se observa en los tiempos de coagulación de un paciente con Hemofilia A?","back":"TTP alargado con TP normal."},{"front":"La Hemofilia B también es conocida como enfermedad de _____.","back":"Christmas"},{"front":"¿Qué factor de la coagulación está ausente en la Hemofilia B?","back":"Factor IX."},{"front":"¿Cuál es la manifestación clínica típica de la Hemofilia B durante la infancia temprana?","back":"Gingivorragia durante la erupción dentaria."},{"front":"¿Cómo se clasifica la severidad de la hemofilia si la actividad del factor es menor al 1%?","back":"Hemofilia grave."},{"front":"¿Qué rango de actividad del factor define a la hemofilia moderada?","back":"1-5%."},{"front":"¿A partir de qué porcentaje de actividad se clasifica la hemofilia como leve?","back":"Mayor al 5% (pero menor al normal)."},{"front":"¿Qué vía de la coagulación evalúa el Tiempo Parcial de Tromboplastina (TTP)?","back":"Vía intrínseca."},{"front":"¿Qué vía de la coagulación evalúa el Tiempo de Protrombina (TP)?","back":"Vía extrínseca y vía común."},{"front":"¿Cuál es la utilidad del INR en la práctica clínica?","back":"Estandarizar los resultados del TP en pacientes que toman antagonistas de la vitamina K."},{"front":"¿Qué caracteriza biológicamente a los Síndromes Mielodisplásicos?","back":"Citopenias progresivas y dishematopoyesis."},{"front":"¿Qué porcentaje de los Síndromes Mielodisplásicos se asocian a causas secundarias como quimioterapia o radiación?","back":"20%."},{"front":"Mencione dos fármacos antineoplásicos comúnmente asociados al desarrollo de Síndrome Mielodisplásico secundario.","back":"Alquilantes y antraciclinas."},{"front":"¿Qué hallazgo en el frotis de sangre periférica sugiere un Síndrome Mielodisplásico?","back":"Neutrófilos (PMN) hipogranulares."},{"front":"¿Cuál es el límite máximo de porcentaje de blastos en médula ósea para el diagnóstico de Síndrome Mielodisplásico?","back":"Menos del 20%."},{"front":"¿Qué nivel de hemoglobina se busca mantener mediante apoyo transfusional en pacientes con SMD?","back":"8-10\\ g/dL."},{"front":"¿Cuándo se indica el uso de quelantes de hierro como la desferroxamina en pacientes con SMD?","back":"Más de 20 transfusiones o ferritina mayor a 1000\\ ng/mL."},{"front":"Mencione dos fármacos específicos utilizados en el tratamiento de los Síndromes Mielodisplásicos.","back":"Lenalidomida y Azacitidina."},{"front":"¿Qué tríada clínica caracteriza el estado de hiperviscosidad en la Policitemia Vera?","back":"Hipertensión, visión borrosa y dolor abdominal."},{"front":"¿Qué síntoma cutáneo es característico de la Policitemia Vera tras la exposición al agua caliente?","back":"Prurito."},{"front":"¿Cuál es el criterio de hemoglobina para el diagnóstico de Policitemia Vera en hombres?","back":"Mayor a 18.5\\ g/dL."},{"front":"¿Cuál es el criterio de hemoglobina para el diagnóstico de Policitemia Vera en mujeres?","back":"Mayor a 16.5\\ g/dL."},{"front":"¿Cómo se encuentran los niveles de eritropoyetina en la Policitemia Vera?","back":"Disminuidos."},{"front":"¿Qué mutación genética está presente en la mayoría de los pacientes con Policitemia Vera?","back":"JAK2."},{"front":"¿Cuál es el pilar del tratamiento inicial para reducir el hematocrito en Policitemia Vera?","back":"Flebotomía."},{"front":"¿Qué cifra de plaquetas define a la Trombocitemia Esencial?","back":"Mayor a 450,000/\\mu L."},{"front":"¿Qué hallazgo es característico en la biopsia de médula ósea de un paciente con Trombocitemia Esencial?","back":"Megacariocitos con núcleos hiperlobulados."},{"front":"¿Qué fármaco se utiliza en Trombocitemia Esencial para reducir el conteo plaquetario si hay riesgo elevado?","back":"Hidroxiurea."},{"front":"¿Qué proceso fisiopatológico define a la Mielofibrosis Primaria?","back":"Mieloproliferación clonal con fibrosis medular reactiva."},{"front":"¿Cuál es el hallazgo físico más prominente en la Mielofibrosis Primaria debido a la hematopoyesis extramedular?","back":"Hepatoesplenomegalia masiva."},{"front":"¿Cuál es el único tratamiento curativo para la Mielofibrosis Primaria?","back":"Trasplante de células progenitoras hematopoyéticas (TCHP) alogénico."},{"front":"¿Qué mecanismo fisiopatológico causa la Púrpura Trombocitopénica Inmune (PTI)?","back":"Autoanticuerpos antiplaquetarios que aceleran su destrucción."},{"front":"¿Qué antecedente clínico es común encontrar en niños antes de la aparición de PTI?","back":"Infección viral previa."},{"front":"¿Cuál es el síntoma inicial más común de la PTI?","back":"Aparición abrupta de petequias y púrpura."},{"front":"¿Qué nivel de plaquetas define la trombocitopenia en la PTI?","back":"Menor a 150,000."},{"front":"¿Cuál es el tratamiento de primera línea con corticoides para la PTI?","back":"Prednisona 1-2\\ mg/kg/día."},{"front":"¿Cuál es la recomendación de manejo para niños con PTI de reciente diagnóstico y hemorragia leve?","back":"Observación cuidadosa sin tratamiento farmacológico."},{"front":"¿Qué tratamiento de primera línea se considera específicamente para lactantes con PTI?","back":"Inmunoglobulina intravenosa (IgIV)."}]},"20":{"num":20,"name":"INTRODUCCION A CARDIOLOGIA","cards":[{"front":"¿Cuál es la función del nodo sinoatrial (SA) en el sistema de conducción cardíaco?","back":"Actuar como el marcapasos principal generando impulsos eléctricos automáticamente."},{"front":"¿En qué espacio intercostal se localiza el foco aórtico?","back":"Segundo espacio intercostal derecho, línea paraesternal."},{"front":"¿Dónde se sitúa el foco pulmonar para la auscultación cardíaca?","back":"Segundo espacio intercostal izquierdo, línea paraesternal."},{"front":"¿En qué localización se ausculta el foco tricuspídeo?","back":"Cuarto espacio intercostal izquierdo, línea paraesternal."},{"front":"¿Cuál es la ubicación exacta del foco mitral?","back":"Quinto espacio intercostal izquierdo, línea medio-clavicular."},{"front":"¿Qué área del corazón representa el foco de Erb?","back":"El tercer espacio intercostal izquierdo, funcionando como área general del corazón."},{"front":"¿Qué evento mecánico produce el primer ruido cardíaco (R_{1})?","back":"El cierre de las válvulas auriculoventriculares (mitral y tricúspide)."},{"front":"¿En qué foco se escucha con mayor intensidad el primer ruido cardíaco (R_{1})?","back":"En el foco mitral."},{"front":"¿Qué fase del ciclo cardíaco ocurre entre los ruidos R_{1} y R_{2}?","back":"La sístole."},{"front":"¿Qué fenómeno valvular genera el segundo ruido cardíaco (R_{2})?","back":"El cierre de las válvulas semilunares (aórtica y pulmonar)."},{"front":"¿En qué focos se ausculta mejor el segundo ruido cardíaco (R_{2})?","back":"En los focos aórtico y pulmonar."},{"front":"¿Qué fase del ciclo cardíaco sucede entre los ruidos R_{2} y el siguiente R_{1}?","back":"La diástole."},{"front":"¿A qué proceso fisiológico corresponde el tercer ruido cardíaco (R_{3})?","back":"Al llenado ventricular rápido."},{"front":"Mencione una patología asociada a la presencia de un tercer ruido cardíaco (R_{3}).","back":"Insuficiencia cardíaca o dilatación ventricular."},{"front":"¿Qué mecanismo produce el cuarto ruido cardíaco (R_{4})?","back":"La contracción auricular forzada contra un ventrículo rígido."},{"front":"¿Con qué condición estructural se asocia comúnmente el cuarto ruido cardíaco (R_{4})?","back":"Hipertrofia ventricular o cardiopatía isquémica."},{"front":"¿En qué momento del ciclo respiratorio ocurre el desdoblamiento fisiológico del segundo ruido?","back":"Durante la inspiración."},{"front":"¿Por qué ocurre el desdoblamiento fisiológico del segundo ruido durante la inspiración?","back":"Debido a un retraso en el cierre de la válvula pulmonar."},{"front":"¿Qué alteración eléctrica se asocia con un desdoblamiento amplio del segundo ruido?","back":"Bloqueo de rama derecha."},{"front":"¿Cuándo se considera que un desdoblamiento del segundo ruido es paradójico?","back":"Cuando los ruidos se separan durante la espiración."},{"front":"¿Qué patología eléctrica causa un desdoblamiento paradójico del segundo ruido?","back":"Bloqueo de rama izquierda."},{"front":"Definición: Automatismo cardíaco.","back":"Capacidad de generar impulsos eléctricos automáticamente, principalmente por el nodo SA."},{"front":"¿Qué efecto tiene el aumento del automatismo en la frecuencia cardíaca?","back":"Produce una taquicardia sinusal."},{"front":"Definición: Inotropismo.","back":"Capacidad de contracción del músculo cardíaco en respuesta a un estímulo."},{"front":"¿Qué trastorno clínico resulta de una disminución severa del inotropismo por daño miocárdico?","back":"Insuficiencia cardíaca o shock cardiogénico."},{"front":"Definición: Cronotropismo.","back":"Capacidad del corazón para regular la frecuencia cardíaca."},{"front":"¿Qué neurotransmisor media el cronotropismo positivo a través de receptores \\beta_{1}?","back":"Noradrenalina (y adrenalina en estrés)."},{"front":"¿Qué sistema nervioso y neurotransmisor regulan el cronotropismo negativo?","back":"Sistema parasimpático (vagal) mediante la acetilcolina."},{"front":"¿En qué receptores actúa la acetilcolina para disminuir la frecuencia cardíaca?","back":"Receptores muscarínicos M_{2}."},{"front":"Definición: Dromotropismo.","back":"Propiedad del corazón para la propagación del impulso eléctrico."},{"front":"¿Qué estructura es responsable de retrasar el impulso para permitir la contracción auricular previa a la ventricular?","back":"El nodo auriculoventricular (AV)."},{"front":"¿Qué hallazgo en el EKG es característico de la preexcitación en el Síndrome de Wolff-Parkinson-White?","back":"Presencia de la onda delta."},{"front":"Definición: Batmotropismo.","back":"Capacidad del corazón de responder a estímulos eléctricos (excitabilidad)."},{"front":"¿Qué trastorno electrolítico puede alterar el potencial de reposo afectando el batmotropismo?","back":"Hiperkalemia o hipokalemia."},{"front":"¿Qué sucede durante la Fase 0 del potencial de acción ventricular?","back":"Ingreso masivo de Na^{+} por canales rápidos, provocando despolarización rápida."},{"front":"¿Cuál es el cambio de voltaje aproximado durante la Fase 0 del potencial de acción?","back":"De -90\\text{ mV} a +20\\text{ mV}."},{"front":"¿Qué eventos iónicos caracterizan la Fase 1 del potencial de acción?","back":"Salida breve de K^{+} por canales transitorios, resultando en repolarización inicial."},{"front":"¿Qué ocurre durante la Fase 2 (meseta) del potencial de acción?","back":"Entrada lenta de Ca^{2+} compensada por salida de K^{+}, manteniendo la contracción."},{"front":"¿Por qué es importante la Fase 2 del potencial de acción para la función cardíaca?","back":"Permite una contracción prolongada para el bombeo y asegura el periodo refractario absoluto."},{"front":"¿Qué fenómeno iónico define la Fase 3 del potencial de acción?","back":"Cierre de canales de Ca^{2+} y salida masiva de K^{+}, causando repolarización rápida."},{"front":"¿Cómo se restablece el equilibrio iónico durante la Fase 4 del potencial de acción?","back":"Mediante la bomba sodio-potasio (3Na^{+} hacia afuera, 2K^{+} hacia adentro)."},{"front":"¿Cuál es el potencial de membrana en reposo aproximado en la Fase 4?","back":"-90\\text{ mV}."},{"front":"¿En qué fase del potencial de acción actúan los fármacos Clase I (como lidocaína)?","back":"Fase 0 (bloqueo de canales de Na^{+})."},{"front":"¿En qué fase del potencial de acción actúan los betabloqueadores (Clase II)?","back":"Fase 4 (disminuyen el automatismo)."},{"front":"¿Cuál es el mecanismo de acción de la Amiodarona (Clase III)?","back":"Bloqueo de canales de K^{+} prolongando la Fase 3 y el intervalo QT."},{"front":"¿Sobre qué fase actúan el Verapamilo y el Diltiazem (Clase IV)?","back":"Fase 2 (bloqueo de canales de Ca^{2+})."},{"front":"¿Qué evento eléctrico representa la onda P en el EKG?","back":"Despolarización auricular o contracción de las aurículas."},{"front":"¿Cuál es la duración normal de la onda P?","back":"Menor a 0.12\\text{ s}."},{"front":"¿Qué representa el intervalo PR en el EKG?","back":"El tiempo que tarda el impulso en viajar desde el nodo SA hasta el nodo AV."},{"front":"¿Cuál es el rango de duración normal para el intervalo PR?","back":"0.12 a 0.20\\text{ s}."},{"front":"¿Qué proceso fisiológico representa el complejo QRS?","back":"Despolarización ventricular."},{"front":"¿Cuál es la duración normal de un complejo QRS estrecho?","back":"Menor a 0.12\\text{ s}."},{"front":"¿Qué representa el segmento ST en el trazado electrocardiográfico?","back":"El intervalo entre la despolarización y la repolarización ventricular."},{"front":"¿Qué evento eléctrico corresponde a la onda T?","back":"Repolarización ventricular."},{"front":"¿Cuándo inicia y termina la sístole eléctrica en el EKG?","back":"Inicia con el complejo QRS y termina con la onda T."},{"front":"¿Cómo se define la bradicardia sinusal?","back":"Frecuencia cardíaca menor a 60\\text{ lpm} con ondas P y QRS normales."},{"front":"¿Qué caracteriza a la taquicardia sinusal?","back":"Frecuencia cardíaca mayor a 100\\text{ lpm} con ondas P y QRS normales."},{"front":"Mencione dos causas no patológicas de bradicardia sinusal.","back":"Sueño profundo y condición de atleta."},{"front":"¿Qué arritmia se caracteriza por la ausencia de ondas P y un ritmo irregular?","back":"Fibrilación auricular."},{"front":"¿Qué hallazgo patognomónico presenta el Flutter auricular en el EKG?","back":"Ondas en \"dientes de sierra\" (F) a una frecuencia de 300\\text{ lpm}."},{"front":"¿Qué indica un complejo QRS ancho (>0.12\\text{ s})?","back":"Que el impulso se genera en los ventrículos o hay un retraso en la conducción (bloqueo)."},{"front":"¿Qué emergencia médica se caracteriza por actividad eléctrica desorganizada y ausencia de QRS identificable?","back":"Fibrilación ventricular (Paro cardíaco)."},{"front":"¿Qué alteración electrocardiográfica sugiere un Bloqueo AV de primer grado?","back":"Prolongación del intervalo PR mayor a 0.20\\text{ s}."},{"front":"¿Qué sugiere una elevación del segmento ST?","back":"Infarto transmural por oclusión total de una arteria coronaria."},{"front":"¿Qué indica la depresión del segmento ST en el contexto de dolor torácico?","back":"Isquemia subendocárdica o angina de esfuerzo."},{"front":"¿Cuál es el significado clínico de una onda T picuda?","back":"Hiperpotasemia (hiperkalemia)."},{"front":"¿Qué patología puede causar una onda T invertida?","back":"Isquemia miocárdica subepicárdica o hipertrofia ventricular."},{"front":"La capacidad del corazón para responder a estímulos se conoce como ____.","back":"Batmotropismo"},{"front":"¿Qué vía accesoria es responsable del acortamiento del PR en el síndrome de WPW?","back":"El Haz de Kent."},{"front":"¿Qué efecto tiene el aumento del tono vagal sobre el cronotropismo?","back":"Cronotropismo negativo (disminución de la frecuencia cardíaca)."},{"front":"¿Qué fármacos se utilizan para bloquear los canales de sodio en la fase 0?","back":"Fármacos antiarrítmicos Clase I (ej. Lidocaína, Propafenona)."},{"front":"¿Qué representa el área general de auscultación llamada Foco de Erb?","back":"El tercer espacio intercostal izquierdo."},{"front":"¿En qué fase del potencial de acción se abren los canales lentos de calcio tipo L?","back":"Fase 2 (Meseta)."},{"front":"¿Qué cambio electrolítico ocurre típicamente en la Fase 3 del potencial de acción?","back":"Salida masiva de potasio (K^{+})."},{"front":"¿Cuál es la duración máxima normal del complejo QRS?","back":"0.11\\text{ s} (debe ser <0.12\\text{ s})."},{"front":"¿Cómo se llama la propiedad de propagar el impulso eléctrico?","back":"Dromotropismo."},{"front":"En el EKG, ¿qué indica la presencia de una onda delta?","back":"Preexcitación ventricular, característica del síndrome de Wolff-Parkinson-White."},{"front":"¿A qué frecuencia cardíaca suele presentarse el Flutter auricular?","back":"Aproximadamente 300\\text{ lpm} en las aurículas."},{"front":"¿Qué ruido cardíaco se asocia con el galope auricular?","back":"Cuarto ruido cardíaco (R_{4})."},{"front":"¿Cuál es la causa del desdoblamiento amplio del segundo ruido?","back":"Bloqueo de rama derecha."},{"front":"Concepto: Taquicardia supraventricular.","back":"Frecuencia de 150-250\\text{ lpm} con QRS estrecho, generalmente por reentrada en el nodo AV."}]},"21":{"num":21,"name":"INSUFICIENCIA CARDIACA","cards":[{"front":"¿Cómo se define la insuficiencia cardíaca aguda (ICA) según el inicio de los síntomas?","back":"Como el inicio súbito de signos y síntomas relacionados con el aumento de la presión telediastólica del ventrículo izquierdo."},{"front":"¿Cuál es la principal consecuencia fisiopatológica de la ICA sobre los órganos principales?","back":"La disminución de la perfusión tisular."},{"front":"En México, ¿cuál es el porcentaje aproximado de defunciones relacionadas con problemas cardíacos?","back":"El 90% de las defunciones."},{"front":"¿Qué estados de México se mencionan como los más afectados por problemas cardíacos?","back":"Veracruz, Morelos y San Luis Potosí."},{"front":"Menciona tres etiologías comunes de la insuficiencia cardíaca aguda.","back":"Síndromes coronarios agudos, valvulopatías y emergencias hipertensivas."},{"front":"¿Cuál es la fórmula para calcular la fracción de eyección (FEVI)?","back":"FEVI = (Volumen \\: sistólico / Volumen \\: telediastólico) \\times 100."},{"front":"¿Cuál es el rango considerado normal para la fracción de eyección?","back":"Entre el 50% y el 75%."},{"front":"¿Qué síntomas se asocian directamente con la disminución del gasto cardíaco en la insuficiencia cardíaca?","back":"Fatiga y debilidad."},{"front":"¿Qué valor de FEVI define a la insuficiencia cardíaca con fracción de eyección reducida (ICFER)?","back":"FEVI \\le 40%."},{"front":"¿Qué rango de FEVI caracteriza a la insuficiencia cardíaca con fracción de eyección media?","back":"Entre 41% y 49%."},{"front":"¿A partir de qué porcentaje se considera insuficiencia cardíaca con fracción de eyección preservada?","back":"FEVI \\ge 50%."},{"front":"Menciona dos causas frecuentes de insuficiencia cardíaca con fracción de eyección reducida.","back":"Miocardiopatía isquémica y miocardiopatía dilatada."},{"front":"¿Qué tipo de miocardiopatías suelen presentar una FEVI \\ge 50%?","back":"Miocardiopatía restrictiva, hipertrófica y no compactada."},{"front":"¿Cuáles son las causas principales de la disfunción del ventrículo derecho?","back":"Hipertensión pulmonar, infarto del ventrículo derecho o miocardiopatía arritmogénica."},{"front":"¿Qué nivel de péptido natriurético tipo B (BNP) descarta el diagnóstico de ICA?","back":"Niveles menores de 100 \\: pg/mL."},{"front":"¿Qué nivel de NT-proBNP permite descartar la insuficiencia cardíaca aguda?","back":"Niveles menores de 300 \\: pg/mL."},{"front":"¿Qué valor de MR-pro-ANP se utiliza para descartar el diagnóstico de ICA?","back":"Valores menores a 120 \\: pmol/L."},{"front":"En el contexto de ICA, ¿cuándo se recomienda realizar un ecocardiograma?","back":"En cuanto el recurso esté disponible tras la sospecha clínica."},{"front":"¿En qué condición específica de la ICA se puede considerar la ventilación mecánica no invasiva?","back":"En el edema pulmonar cardiogénico."},{"front":"¿Qué representa el perfil hemodinámico 'Caliente y Seco' (A)?","back":"Representa la insuficiencia cardíaca compensada."},{"front":"¿Cuál es el patrón hemodinámico más común en pacientes con ICA?","back":"Caliente y Húmedo (B)."},{"front":"¿Cuál es el tratamiento de primera línea para el perfil hemodinámico 'Caliente y Húmedo'?","back":"Diuréticos de asa intravenosos, como la furosemida."},{"front":"¿Qué fármaco se puede agregar si persiste la congestión a pesar del uso de diuréticos de asa?","back":"Acetazolamida."},{"front":"¿Cuál es la indicación para la ultrafiltración en un paciente con ICA?","back":"Cuando existe fracaso al tratamiento farmacológico."},{"front":"¿Cuál es el manejo inicial para un paciente con perfil 'Frío y Seco' (L)?","back":"Administración de líquidos intravenosos y, transitoriamente, inotrópicos."},{"front":"¿Cuál es la prioridad terapéutica en el perfil hemodinámico 'Frío y Húmedo' (C)?","back":"Tratar la causa adyacente."},{"front":"Menciona tres síntomas típicos de la insuficiencia cardíaca.","back":"Ortopnea, disnea paroxística nocturna y tolerancia reducida al ejercicio."},{"front":"¿Qué signo específico se describe como 'ritmo de galope'?","back":"La presencia de un tercer sonido cardíaco."},{"front":"Menciona tres signos específicos de la insuficiencia cardíaca.","back":"Presión venosa yugular elevada, reflujo hepatoyugular e impulso apical desplazado lateralmente."},{"front":"¿Qué síntoma atípico se define como disnea al inclinarse hacia adelante?","back":"Bendopnea."},{"front":"Según los criterios de Framingham, ¿qué hallazgo radiológico es un criterio mayor?","back":"La cardiomegalia."},{"front":"¿Qué valor de presión venosa yugular se considera criterio mayor de Framingham?","back":"> 16 \\: mmH_{2}O."},{"front":"Menciona tres criterios menores de Framingham.","back":"Edema de miembros pélvicos, tos nocturna y hepatomegalia."},{"front":"¿En qué consiste el 'criterio mixto' de Framingham?","back":"Pérdida de peso de 4.5 \\: kg en 5 días tras iniciar el tratamiento."},{"front":"¿Cuántos criterios de Framingham se requieren para diagnosticar insuficiencia cardíaca?","back":"Dos criterios mayores o un criterio mayor más dos menores."},{"front":"¿Cómo se define la Clase I de la clasificación funcional NYHA?","back":"Pacientes sin limitación de la actividad física habitual que realizan \\ge 7 METs."},{"front":"¿Qué caracteriza a la Clase II de la NYHA en términos de limitación física?","back":"Ligera limitación de la actividad física ordinaria, realizando \\ge 5 METs."},{"front":"¿Qué caracteriza a la Clase III de la NYHA?","back":"Marcada limitación de la actividad física ordinaria, realizando \\ge 2 METs."},{"front":"¿Cómo se define la Clase IV de la NYHA?","back":"Incapacidad para realizar cualquier actividad física sin molestias o síntomas en reposo."},{"front":"¿Cuál es el tratamiento farmacológico inicial para un paciente con ICFER en clase funcional NYHA I?","back":"IECA y betabloqueadores."},{"front":"En pacientes con NYHA II-IV e ICFER, ¿qué fármaco se añade si los síntomas persisten tras IECA y betabloqueadores?","back":"Espironolactona (antagonista de mineralocorticoides)."},{"front":"¿Qué alternativa terapéutica se indica ante la intolerancia a IECA o ARA II?","back":"Hidralazina e isosorbida."},{"front":"¿Bajo qué condiciones se indica el uso de Ivabradina en insuficiencia cardíaca?","back":"FEVI < 35%, frecuencia cardíaca > 70 \\: lpm o refractariedad a betabloqueadores."},{"front":"Menciona dos indicaciones para el uso de digoxina en la insuficiencia cardíaca crónica.","back":"Persistencia de FEVI < 45% o presencia de fibrilación auricular."},{"front":"¿Qué parámetros de laboratorio se deben vigilar periódicamente en todos los pacientes con tratamiento para IC?","back":"Creatinina, urea, sodio y tiempos de coagulación (TP + INR)."},{"front":"El edema agudo de pulmón y la distensión venosa yugular son criterios _____ de Framingham.","back":"Mayores"},{"front":"La taquicardia y el derrame pleural son criterios _____ de Framingham.","back":"Menores"},{"front":"¿Cuál es la principal causa de insuficiencia cardíaca con fracción de eyección reducida mencionada en la etiología?","back":"Infarto agudo al miocardio."},{"front":"¿Qué enfermedad infecciosa se asocia con la miocardiopatía dilatada y FEVI < 40% en el material?","back":"Enfermedad de Chagas."},{"front":"¿Qué condición sistémica se asocia con la miocardiopatía infiltrativa y FEVI de 40-50%?","back":"Amiloidosis."}]},"22":{"num":22,"name":"VALVULOPATIAS","cards":[{"front":"¿Qué término describe el estrechamiento valvular que impide el paso normal de la sangre?","back":"Estenosis"},{"front":"¿Cómo se define la insuficiencia valvular en términos de flujo sanguíneo?","back":"Regurgitación de sangre debido a un cierre valvular defectuoso."},{"front":"¿Cuál es la valvulopatía más frecuente en países desarrollados y en pacientes geriátricos?","back":"Estenosis Aórtica"},{"front":"¿Cuál es la causa principal de estenosis aórtica en pacientes mayores de 70 años?","back":"Degeneración y calcificación senil."},{"front":"En pacientes de entre 30 y 70 años, ¿cuál es la etiología congénita más común de la estenosis aórtica?","back":"Válvula Bicúspide"},{"front":"¿Qué defecto valvular es la causa más probable de estenosis aórtica en un paciente de 0 a 30 años?","back":"Válvula Unicúspide"},{"front":"Mencione los tres componentes de la tríada clásica de la estenosis aórtica.","back":"Angina, síncope e insuficiencia cardíaca."},{"front":"Tras la aparición de síncope en un paciente con estenosis aórtica, ¿cuál es la sobrevida estimada?","back":"2 a 3 años."},{"front":"¿Cuál es el hallazgo característico en el electrocardiograma de un paciente con estenosis aórtica?","back":"Hipertrofia ventricular izquierda."},{"front":"¿Cómo se describe el soplo característico de la estenosis aórtica?","back":"Soplo sistólico romboidal en foco aórtico."},{"front":"¿Hacia qué estructura anatómica se irradia típicamente el soplo de la estenosis aórtica?","back":"Arterias carótidas"},{"front":"¿Qué nombre recibe el fenómeno donde el soplo de la estenosis aórtica se percibe en el foco accesorio?","back":"Fenómeno de Gallavardin"},{"front":"¿Cómo se describe el pulso arterial en un paciente con estenosis aórtica?","back":"Parvus et tardus"},{"front":"¿Cuál es el estándar de oro para el diagnóstico de las valvulopatías?","back":"Ecocardiograma"},{"front":"¿Cuál es el área valvular que define una estenosis aórtica como severa?","back":"Menor a 1\\text{ cm}^2"},{"front":"¿Qué valor de Fracción de Eyección del Ventrículo Izquierdo (FEVI) es indicación de reemplazo valvular en estenosis aórtica?","back":"Menor al 50%"},{"front":"Mencione tres causas comunes de insuficiencia aórtica aguda o crónica.","back":"Endocarditis, disección aórtica y fiebre reumática."},{"front":"¿Cuáles son los síntomas iniciales más frecuentes en la insuficiencia aórtica?","back":"Disnea de esfuerzo progresiva y dolor torácico."},{"front":"¿En qué foco y fase del ciclo cardíaco se ausculta el soplo de la insuficiencia aórtica?","back":"Soplo diastólico en el foco aórtico (2do espacio intercostal derecho)."},{"front":"¿Qué nombres recibe el pulso amplio y saltón característico de la insuficiencia aórtica crónica?","back":"Pulso Magnus, de Corrigan o Celere et Altus."},{"front":"¿Qué nombre recibe el soplo de regurgitación mitral funcional causado por el chorro de insuficiencia aórtica?","back":"Soplo de Austin-Flint"},{"front":"¿Cuál es el tratamiento farmacológico de elección para la insuficiencia aórtica aguda?","back":"Dobutamina y Nitroprusiato."},{"front":"¿A partir de qué valor de FEVI se indica cirugía en un paciente con insuficiencia aórtica severa?","back":"Menor al 55%"},{"front":"¿Cuál es la etiología responsable del 90% de los casos de estenosis mitral?","back":"Fiebre Reumática"},{"front":"¿Cuál es el síntoma más frecuente en la estenosis mitral?","back":"Disnea"},{"front":"¿Qué complicación arrítmica es común en pacientes con estenosis mitral de larga evolución?","back":"Fibrilación Auricular"},{"front":"Según el área valvular, ¿cómo se clasifica la estenosis mitral moderada?","back":"Mayor a 1.5\\text{ cm}"},{"front":"¿Cuál es el área valvular característica de una estenosis mitral severa?","back":"Menor a 1.5\\text{ cm}"},{"front":"¿En qué foco y fase cardíaca se percibe el soplo de la estenosis mitral?","back":"Soplo diastólico en foco mitral (5to espacio intercostal)."},{"front":"¿Qué hallazgos componen el soplo de Duroziez en la estenosis mitral?","back":"Primer ruido intenso y segundo ruido desdoblado."},{"front":"¿Qué signo radiológico sugiere congestión pulmonar en la estenosis mitral?","back":"Líneas B de Kerley"},{"front":"¿Qué microorganismo debe tratarse si un paciente con estenosis mitral presenta faringitis?","back":"Streptococcus pyogenes"},{"front":"¿En qué grado de la clasificación NYHA se indica tratamiento quirúrgico para estenosis mitral?","back":"Clase III-IV"},{"front":"¿Cuál es la segunda cardiopatía valvular más frecuente en la actualidad?","back":"Insuficiencia Mitral"},{"front":"¿Qué evento isquémico agudo puede causar insuficiencia mitral por ruptura de cuerdas tendinosas?","back":"Infarto Agudo al Miocardio (IAM) de cara inferior."},{"front":"Cite dos causas crónicas de insuficiencia mitral.","back":"Fiebre reumática y endocarditis."},{"front":"¿Cuál es el cuadro clínico de la insuficiencia mitral aguda?","back":"Edema agudo pulmonar, disnea de esfuerzo y paroxística nocturna."},{"front":"¿Hacia dónde se irradia el soplo sistólico de la insuficiencia mitral?","back":"Hacia la axila"},{"front":"¿Qué indica la presencia de un tercer ruido cardíaco en la insuficiencia mitral?","back":"Insuficiencia cardíaca"},{"front":"En insuficiencia mitral con fibrilación auricular, ¿qué fármacos se añaden al tratamiento crónico?","back":"Antiarrítmicos y anticoagulantes."},{"front":"¿Cuál es la causa más frecuente de estenosis tricuspídea?","back":"Etiología Reumática"},{"front":"Mencione tres signos de insuficiencia cardíaca derecha presentes en la estenosis tricuspídea.","back":"Edema, distensión yugular y reflujo hepatojugular."},{"front":"¿Qué nombre recibe el soplo diastólico tricuspídeo que aumenta con la inspiración?","back":"Soplo de Rivero-Carvallo"},{"front":"¿Cuál es la maniobra que hace aumentar la intensidad del soplo de Rivero-Carvallo?","back":"Inspiración profunda"},{"front":"¿Cuál es la causa funcional más común de la insuficiencia tricuspídea?","back":"Hipertensión Pulmonar"},{"front":"¿Cuáles son las dos causas orgánicas principales de la insuficiencia tricuspídea?","back":"Endocarditis o fiebre reumática."},{"front":"¿Cuál es el tratamiento quirúrgico opcional para la insuficiencia tricuspídea?","back":"Valvuloplastía"},{"front":"Concepto: Fenómeno de Gallavardin","back":"Disociación del soplo de estenosis aórtica, donde el componente rudo se oye en el foco aórtico y el musical en el ápex."},{"front":"¿Qué valvulopatía se asocia con el síntoma de 'cianosis acra'?","back":"Estenosis Mitral"},{"front":"¿En qué casos de estenosis aórtica se prefiere el tratamiento con balón percutáneo?","back":"Pacientes geriátricos"},{"front":"El soplo sistólico en foco tricuspídeo es característico de la _____.","back":"Insuficiencia Tricuspídea"},{"front":"La tríada de angina, síncope y disnea es patognomónica de la _____.","back":"Estenosis Aórtica"},{"front":"El pulso parvus et tardus es a la estenosis aórtica lo que el pulso de Corrigan es a la _____.","back":"Insuficiencia Aórtica"},{"front":"¿Qué fármacos se utilizan para el control crónico de la insuficiencia mitral?","back":"Diuréticos y betabloqueadores."},{"front":"En la estenosis mitral, el área valvular mayor de 2\\text{ cm} se considera _____.","back":"Leve"},{"front":"¿Cuál es el manejo inicial para un paciente con estenosis aórtica asintomática?","back":"Observación"},{"front":"En la insuficiencia tricuspídea, el paciente suele presentar disnea, fatiga y datos de _____.","back":"Insuficiencia cardíaca derecha"},{"front":"¿Qué tratamiento médico es común para reducir la precarga en casi todas las insuficiencias valvulares sintomáticas?","back":"Diuréticos"},{"front":"¿Qué valvulopatía presenta un soplo sistólico que se irradia a la axila?","back":"Insuficiencia Mitral"},{"front":"La estenosis mitral se asocia frecuentemente a la aparición de _____ sistémicos por fibrilación auricular.","back":"Embolismos"},{"front":"¿Cuál es el agente etiológico de la Fiebre Reumática?","back":"Estreptococo beta hemolítico del grupo A (EBHGA) o S. pyogenes."},{"front":"La Fiebre Reumática es la causa más frecuente de _____ y doble lesión mitral.","back":"estenosis mitral"},{"front":"¿En qué rango de edad suele aparecer la Fiebre Reumática tras una infección faríngea?","back":"Entre los 2 y 5 años de edad."},{"front":"Mnemotecnia \"CANCER\" para Criterios Mayores de Jones: C (Carditis), A (Artritis), N (Nódulos subcutáneos), C (Corea de Sydenham) y _____.","back":"Eritema marginado"},{"front":"Mnemotecnia \"FIERA\" para Criterios Menores de Jones: F (Fiebre), I (Intervalo PR prolongado), E (Enfermedad cardíaca reumática previa), R (Reactantes de fase aguda) y _____.","back":"Artralgias"},{"front":"¿Cuál es el requisito para establecer el diagnóstico clínico de Fiebre Reumática según los criterios de Jones?","back":"Al menos dos criterios mayores o uno mayor y dos menores."},{"front":"¿Qué estudio de imagen confirma el diagnóstico de carditis en Fiebre Reumática?","back":"Ecocardiograma."},{"front":"¿Cuál es la manifestación clínica más habitual (75%) de la Fiebre Reumática?","back":"Artritis (poliartritis migratoria)."},{"front":"Signo clínico de la Corea de Sydenham caracterizado por movimientos irregulares al apretar las manos del explorador:","back":"Signo de la lechera."},{"front":"¿Cuál es el antibiótico de elección para el tratamiento de Fiebre Reumática?","back":"Penicilina."},{"front":"¿Qué fármaco se administra en pacientes con Fiebre Reumática alérgicos a la penicilina?","back":"Eritromicina."},{"front":"¿Cuál es el antiinflamatorio más empleado para la artritis en Fiebre Reumática?","back":"Ácido acetilsalicílico (Aspirina)."},{"front":"¿Cuál es el tratamiento de elección para el control de la carditis en Fiebre Reumática?","back":"Prednisona."},{"front":"¿Cuánto tiempo debe durar la profilaxis con penicilina benzatina en un paciente con Fiebre Reumática sin afectación cardíaca?","back":"5 años tras el último episodio o hasta cumplir los 18 años."},{"front":"¿Cuál es la causa más común de Pericarditis Aguda para términos del examen ENARM?","back":"Virus Coxsackie A y B."},{"front":"¿Qué maniobra postural disminuye el dolor torácico en la Pericarditis Aguda?","back":"Inclinarse hacia adelante."},{"front":"¿Qué hallazgo característico se observa en la radiografía de tórax de un paciente con derrame pericárdico importante?","back":"Corazón en forma de garrafa (o cantimplora)."},{"front":"En el EKG de la Pericarditis Aguda, se observa una elevación difusa del segmento ST con morfología _____.","back":"cóncava"},{"front":"¿Cuál es el cambio en el intervalo PR característico de la Pericarditis Aguda en el EKG?","back":"Descenso del intervalo PR."},{"front":"¿Cuál es el tratamiento inicial para el primer brote de Pericarditis Aguda?","back":"AINES (como Ibuprofeno)."},{"front":"¿Qué fármaco se agrega al tratamiento de Pericarditis Aguda en caso de gravedad o recurrencia?","back":"Colchicina."},{"front":"¿Cuál es el agente infeccioso viral más frecuentemente asociado a la Miocarditis?","back":"Virus Coxsackie B."},{"front":"¿Cuál es el método más usado para establecer el diagnóstico definitivo de Miocarditis?","back":"Biopsia endomiocárdica."},{"front":"¿Cómo se denominan los criterios histológicos utilizados para el diagnóstico de Miocarditis?","back":"Criterios de Dallas."},{"front":"¿Qué sospecha diagnóstica se debe tener ante una muerte súbita en atletas jóvenes previamente sanos?","back":"Miocarditis (o miocardiopatía hipertrófica)."},{"front":"¿Cuál es la lesión anatomopatológica más característica de la Endocarditis Infecciosa?","back":"Vegetaciones."},{"front":"¿Cuál es el microorganismo de mayor incidencia global en la Endocarditis Infecciosa?","back":"Staphylococcus aureus."},{"front":"¿Qué agente etiológico se asocia a Endocarditis Infecciosa en pacientes con cáncer de colon?","back":"Streptococcus bovis."},{"front":"¿Cuál es el microorganismo más frecuente en Endocarditis sobre prótesis valvular temprana (antes de 12 meses)?","back":"Staphylococcus epidermidis."},{"front":"Las máculas hemorrágicas no dolorosas en palmas y plantas por fenómenos embólicos en la Endocarditis se llaman _____.","back":"Lesiones de Janeway"},{"front":"Las hemorragias retinianas con centro pálido por fenómenos inmunológicos en la Endocarditis se llaman _____.","back":"Manchas de Roth"},{"front":"¿Cuál es el mejor método diagnóstico para identificar el microorganismo causal en la Endocarditis Infecciosa?","back":"Hemocultivo central."},{"front":"¿Qué estudio diagnóstico tiene mayor sensibilidad para identificar vegetaciones en Endocarditis?","back":"Ecocardiograma transesofágico."},{"front":"¿Cuál es el esquema antibiótico empírico para Endocarditis en válvula nativa?","back":"Ampicilina + Aminoglucósido."},{"front":"¿Qué triple terapia antibiótica se recomienda para Endocarditis en válvula protésica precoz?","back":"Vancomicina + Aminoglucósido + Rifampicina."},{"front":"¿Cuál es la complicación más frecuente que indica tratamiento quirúrgico en la Endocarditis Infecciosa?","back":"Insuficiencia cardíaca congestiva por rotura valvular."},{"front":"¿Qué enzima escinde el angiotensinógeno para convertirlo en angiotensina I?","back":"Renina."},{"front":"¿En qué órgano se localiza principalmente la Enzima Convertidora de Angiotensina (ECA)?","back":"Pulmón (aproximadamente 70%)."},{"front":"¿Qué efecto tiene la Aldosterona sobre el potasio (K^{+}) y los hidrogeniones (H^{+})?","back":"Promueve su excreción en la nefrona distal."},{"front":"¿Cuál es el efecto hemodinámico directo de los IECA al disminuir la Angiotensina II y aumentar la bradicinina?","back":"Vasodilatación y disminución de la resistencia periférica sistémica."},{"front":"¿Cuál es el efecto adverso más común de los IECA relacionado con la acumulación de bradicinina?","back":"Tos (o angioedema)."},{"front":"¿Cuál es la localización más frecuente de los tumores cardíacos primarios?","back":"Aurícula izquierda."},{"front":"¿Cuál es el tumor cardíaco primario benigno más frecuente en adultos?","back":"Mixoma."},{"front":"¿Qué tumor cardíaco suele afectar principalmente las válvulas (aórtica y mitral)?","back":"Fibroelastoma papilar."},{"front":"¿Cuál es el estudio inicial de elección ante la sospecha de un tumor cardíaco?","back":"Ecocardiograma transtorácico."},{"front":"¿Cuál es el sitio principal de hipertrofia en la Cardiomiopatía Hipertrófica?","back":"Septum interventricular."},{"front":"¿Qué sucede con la intensidad del soplo sistólico en la Cardiomiopatía Hipertrófica durante la maniobra de Valsalva?","back":"Aumenta."},{"front":"¿Qué agentes etiológicos se asocian clásicamente con la Cardiomiopatía Dilatada?","back":"Alcoholismo y Enfermedad de Chagas."},{"front":"¿Qué patología infiltrativa es la causa común de Cardiomiopatía Restrictiva en pacientes geriátricos?","back":"Amiloideosis."},{"front":"¿Qué signo clínico venoso es característico de la Cardiomiopatía Restrictiva?","back":"Signo de Kussmaul."},{"front":"¿Cuál es el evento fisiopatológico principal que inicia una Disección Aórtica?","back":"Desgarro de la íntima."},{"front":"¿Cuál es la localización anatómica más frecuente del desgarro en la Disección Aórtica?","back":"Aorta ascendente (65%)."},{"front":"Según la clasificación de Stanford, una disección que involucra la aorta ascendente es de tipo _____.","back":"A"},{"front":"¿Cuál es el síntoma cardinal de la Disección Aórtica?","back":"Dolor súbito penetrante (transfictivo) en tórax, abdomen o espalda."},{"front":"¿Qué hallazgo se busca en la radiografía de tórax inicial ante sospecha de Disección Aórtica?","back":"Ensanchamiento del mediastino."},{"front":"¿Cuál es el estudio de imagen confirmatorio (de elección por rapidez) para Disección Aórtica?","back":"Angio-TAC."},{"front":"¿Cuál es el estándar de oro (Gold Standard) para el diagnóstico de Disección Aórtica?","back":"Ecocardiograma transesofágico."},{"front":"¿Cuáles son las metas hemodinámicas de tensión arterial sistólica (TAS) y frecuencia cardíaca (FC) en la Disección Aórtica?","back":"TAS < 120 mmHg y FC < 60 lpm."},{"front":"¿En cuánto tiempo se deben lograr las metas hemodinámicas en una emergencia por Disección Aórtica?","back":"20 minutos."},{"front":"¿Qué combinación de fármacos antihipertensivos se utiliza típicamente en la fase aguda de la Disección Aórtica?","back":"Esmolol (o Labetalol) + Nitroprusiato de sodio."}]},"23":{"num":23,"name":"SINDROMES CORONARIOS","cards":[{"front":"¿A qué se refiere el término de Infarto Agudo de Miocardio (IAM)?","back":"A la evidencia de daño miocárdico con elevación de troponinas cardíacas mayor al percentil 99 del límite superior de referencia."},{"front":"¿Cuál es la fisiopatología más común del Infarto Agudo de Miocardio?","back":"Obstrucción por aterotrombosis secundaria a la rotura o erosión de una placa de aterosclerosis."},{"front":"¿Cómo se define el IAM con elevación del segmento ST (IAM CEST)?","back":"Paciente con elevación de troponinas y elevación del segmento ST en al menos dos derivaciones contiguas."},{"front":"¿Qué caracteriza a la angina inestable en comparación con el IAM?","back":"Presenta clínica de infarto pero sin elevación de troponinas mayor al percentil 99 ni alteraciones en el electrocardiograma."},{"front":"¿Cuál es la duración típica de la clínica en una angina inestable?","back":"Mayor a 20 minutos."},{"front":"¿Qué factores alivian el dolor en una angina estable?","back":"El reposo o la administración de nitroglicerina."},{"front":"¿Cuál es la duración del dolor en una angina estable?","back":"De 3 a 5 minutos."},{"front":"Según la cuarta definición universal, ¿qué criterio electrocardiográfico (además de las troponinas) permite diagnosticar un IAM?","back":"Cambios isquémicos nuevos o el desarrollo de nuevas ondas Q patológicas."},{"front":"Clasificación Universal: ¿Qué mecanismo define al IAM tipo 1?","back":"Ruptura o erosión de placa aterosclerótica."},{"front":"Clasificación Universal: ¿A qué se debe un IAM tipo 2?","back":"A un desequilibrio entre la demanda y el aporte de oxígeno."},{"front":"Clasificación Universal: ¿Qué define al IAM tipo 3?","back":"Muerte cardíaca súbita que ocurre antes de poder determinar el IAM mediante biomarcadores."},{"front":"Clasificación Universal: ¿Qué evento causa un IAM tipo 4b?","back":"Trombosis del stent."},{"front":"Clasificación Universal: ¿En qué contexto ocurre un IAM tipo 5?","back":"Secundario a una cirugía de revascularización coronaria."},{"front":"¿Cuál es el principal factor de riesgo para enfermedad coronaria?","back":"Hipertensión arterial sistémica (presente en el 60% de los casos)."},{"front":"¿Qué sustancia es una causa principal de infarto en personas jóvenes sin factores de riesgo tradicionales?","back":"Cocaína."},{"front":"¿Cuál es la principal causa de muerte intrahospitalaria en pacientes con infarto?","back":"Choque cardiogénico."},{"front":"¿Cuál es la principal causa de muerte extrahospitalaria en pacientes con infarto?","back":"Fibrilación ventricular."},{"front":"¿En qué grupos de pacientes son más frecuentes los síntomas atípicos de isquemia?","back":"Mujeres, pacientes diabéticos y pacientes geriátricos."},{"front":"¿Cuáles son los sitios de irradiación o localización del dolor considerados síntomas atípicos?","back":"Cuello, tórax posterior y epigastrio."},{"front":"¿Cuál es el tiempo meta para realizar un EKG de 12 derivaciones tras la llegada del paciente?","back":"Primeros 10 minutos."},{"front":"¿En qué momento se debe repetir el ecocardiograma tras un IAM para valorar la necesidad de un DAI?","back":"A las 6 a 12 semanas después del evento agudo."},{"front":"¿Cuál es el biomarcador cardíaco que se eleva primero tras un infarto?","back":"Mioglobina (1 a 2 horas)."},{"front":"¿Cuál es el biomarcador cardíaco con mayor especificidad diagnóstica?","back":"Troponina I."},{"front":"¿Qué biomarcador cardíaco permanece elevado por más tiempo?","back":"Troponina T."},{"front":"¿Cuál es la cinética de elevación y persistencia de la CPK-MB?","back":"Se eleva de 3 a 6 horas y persiste hasta por 3 días."},{"front":"¿Qué derivaciones adicionales deben solicitarse ante la sospecha de un infarto posterior?","back":"V_{7}, V_{8} y V_{9}."},{"front":"¿Qué derivaciones se utilizan para diagnosticar un infarto del ventrículo derecho?","back":"V_{3}R y V_{4}R."},{"front":"¿Qué derivaciones del EKG corresponden a la cara septal del corazón?","back":"V_{1} y V_{2}."},{"front":"¿Qué derivaciones del EKG evalúan la cara anterior del corazón?","back":"V_{3} y V_{4}."},{"front":"¿Qué derivaciones del EKG corresponden a la cara lateral alta y baja?","back":"DI, aVL, V_{5} y V_{6}."},{"front":"¿Qué derivaciones del EKG evalúan la cara inferior del corazón?","back":"DII, DIII y aVF."},{"front":"¿Qué arteria coronaria suele estar afectada en un infarto de la cara anterior (V_{1} a V_{6})?","back":"Arteria descendente anterior."},{"front":"¿Qué arteria coronaria se asocia típicamente a un infarto de la cara lateral?","back":"Arteria circunfleja."},{"front":"¿Cuál es la arteria afectada en el 85% de los infartos de cara inferior?","back":"Arteria coronaria derecha."},{"front":"En el contexto de isquemia, ¿qué hallazgo en la onda T indica afección subendocárdica?","back":"Onda T picuda."},{"front":"En el contexto de isquemia, ¿qué hallazgo en la onda T indica afección subepicárdica?","back":"Onda T negativa."},{"front":"En el contexto de lesión, ¿qué cambio en el segmento ST indica afección subendocárdica?","back":"Infradesnivel del segmento ST."},{"front":"En el contexto de lesión, ¿qué cambio en el segmento ST indica afección subepicárdica?","back":"Supradesnivel del segmento ST."},{"front":"¿Cuál es la dosis de carga inicial recomendada de ácido acetilsalicílico en un SCACEST?","back":"150 a 300 mg."},{"front":"¿Bajo qué condiciones está indicada la administración de oxígeno en un IAM?","back":"Saturación < 90% o PaO_{2} < 60 mmHg."},{"front":"¿Cuál es la complicación más severa asociada al uso de morfina como analgésico en el IAM?","back":"Hipotensión."},{"front":"¿Cuál es el objetivo principal del uso de IECAs en las primeras 24 horas del IAM?","back":"Evitar el remodelado ventricular."},{"front":"¿Qué fármaco se administra para disminuir la posibilidad de fibrilación ventricular en el IAM?","back":"Beta-bloqueadores."},{"front":"¿Cuál es la meta de colesterol LDL en la prevención secundaria post-infarto?","back":"Menor a 55 mg/dL."},{"front":"¿Cuál es el tiempo meta 'puerta-balón' para una intervención coronaria percutánea (ICP)?","back":"90 minutos."},{"front":"¿Cuál es el tiempo meta 'puerta-aguja' para el inicio de la terapia fibrinolítica?","back":"30 minutos."},{"front":"¿En qué situación está indicada la trombólisis como estrategia de reperfusión inicial?","back":"Cuando no puede realizarse una angioplastia primaria en las primeras 2 horas."},{"front":"¿Cuál es el fármaco fibrinolítico de elección por su administración en bolo único?","back":"Tenecteplasa."},{"front":"¿Qué niveles de presión arterial contraindican absolutamente la terapia fibrinolítica?","back":"PAS > 180 mmHg o PAD > 110 mmHg."},{"front":"¿Qué porcentaje de resolución del segmento ST a los 60-90 minutos indica una reperfusión exitosa?","back":"50% de elevación inicial."},{"front":"¿Qué escalas se utilizan para estadificar el riesgo en un SCASEST?","back":"TIMI y GRACE."},{"front":"¿En qué plazo debe realizarse la angiografía en un paciente con SCASEST de riesgo muy alto (choque o arritmias)?","back":"Primeras 2 horas."},{"front":"¿Qué variables integra la escala de GRACE para riesgo en SCASEST?","back":"Edad, PAS, FC, Creatinina, biomarcadores, cambios ST, paro cardíaco al ingreso y clasificación Killip."},{"front":"Término: Angina de Prinzmetal","back":"Definición: Angina vasoespástica brusca, nocturna y en reposo, con elevación transitoria del ST. Tratamiento: Calcioantagonistas y nitratos."},{"front":"¿Qué fármacos están contraindicados en un IAM con insuficiencia cardíaca aguda sintomática?","back":"Beta-bloqueadores, verapamilo, diltiazem y nifedipino."},{"front":"¿Cuál es la tríada clásica del infarto del ventrículo derecho?","back":"Hipotensión, ingurgitación yugular y auscultación pulmonar normal."},{"front":"Término: Síndrome de Dressler","back":"Definición: Pericarditis que ocurre semanas después de un IAM agudo."},{"front":"¿Cuál es la meta de colesterol total en la prevención secundaria?","back":"Menor a 180 mg/dL."},{"front":"¿Qué tipo de dieta se recomienda para pacientes con enfermedad coronaria?","back":"Dieta mediterránea."},{"front":"¿Qué escala se utiliza para estadificar la severidad de la falla cardíaca en el contexto de IAM y predecir mortalidad?","back":"Escala de Killip-Kimball."},{"front":"¿Qué complicación mecánica es característica de los infartos de cara inferior?","back":"Rotura del músculo papilar."},{"front":"¿Cuál es la complicación eléctrica más frecuente post-IAM?","back":"Taquiarrítmias supraventriculares."},{"front":"¿Qué marcador inflamatorio predice el riesgo de aterosclerosis?","back":"Proteína C Reactiva (PCR)."},{"front":"¿Cuál es la recomendación de ejercicio (gasto calórico) para pacientes con cardiopatía?","back":"Consumir 2200 kcal por semana (3 a 5 veces por semana)."},{"front":"¿Qué sustancias nocivas se producen durante la reperfusión cardíaca?","back":"Especies reactivas de oxígeno (HO)."}]},"24":{"num":24,"name":"ACLS Y BLS","cards":[{"front":"¿Cuál es el primer eslabón de la cadena de supervivencia intrahospitalaria?","back":"Reconocimiento y prevención tempranos."},{"front":"¿Cuál es el segundo eslabón de la cadena de supervivencia intrahospitalaria?","back":"Activación de la respuesta a emergencias."},{"front":"¿Cuál es el tercer eslabón de la cadena de supervivencia intrahospitalaria?","back":"RCP de alta calidad."},{"front":"¿Cuál es el cuarto eslabón de la cadena de supervivencia intrahospitalaria?","back":"Desfibrilación."},{"front":"¿Cuál es el quinto eslabón de la cadena de supervivencia intrahospitalaria?","back":"Cuidados posparo cardíaco."},{"front":"¿Cuál es el sexto eslabón de la cadena de supervivencia intrahospitalaria?","back":"Recuperación."},{"front":"¿Cuál es el primer eslabón de la cadena de supervivencia extrahospitalaria?","back":"Activación de la respuesta a emergencias."},{"front":"¿Cuál es el segundo eslabón de la cadena de supervivencia extrahospitalaria?","back":"RCP de alta calidad."},{"front":"¿Cuál es el tercer eslabón de la cadena de supervivencia extrahospitalaria?","back":"Desfibrilación."},{"front":"¿Cuál es el cuarto eslabón de la cadena de supervivencia extrahospitalaria?","back":"Soporte vital avanzado."},{"front":"¿Cuál es el quinto eslabón de la cadena de supervivencia extrahospitalaria?","back":"Cuidados posparo cardíaco."},{"front":"¿Cuál es el sexto eslabón de la cadena de supervivencia extrahospitalaria?","back":"Recuperación."},{"front":"En el algoritmo BLS, ¿qué acción es prioritaria antes de acercarse a la víctima?","back":"Verificar si la escena es segura."},{"front":"Si la víctima no responde tras el estímulo inicial, ¿qué debe hacer el reanimador de inmediato?","back":"Pedir ayuda en voz alta."},{"front":"Acción simultánea a la activación del sistema de emergencias en el algoritmo BLS:","back":"Obtener un DEA y equipo para emergencias."},{"front":"¿Cuál es el tiempo máximo permitido para comprobar la respiración y el pulso simultáneamente?","back":"10 segundos o menos."},{"front":"¿Cuál es la conducta a seguir si el paciente tiene pulso pero no respira?","back":"Proporcionar ventilación de rescate."},{"front":"¿Cuál es la frecuencia de la ventilación de rescate en un adulto con pulso?","back":"1 ventilación cada 6 segundos (o 10 ventilaciones por minuto)."},{"front":"En un paciente con ventilación de rescate, ¿cada cuánto tiempo se debe reevaluar el pulso?","back":"Cada 2 minutos."},{"front":"Fármaco indicado en caso de sospecha de sobredosis por opioides durante la reanimación:","back":"Naloxona."},{"front":"¿Bajo qué condiciones específicas se deben iniciar ciclos de 30 compresiones y 2 ventilaciones?","back":"Si la víctima no respira (o solo jadea/boquea) y no tiene pulso."},{"front":"¿Cuál es la profundidad mínima recomendada para las compresiones torácicas en adultos?","back":"Al menos 5\\text{ cm}."},{"front":"¿Cuál es la frecuencia recomendada de compresiones torácicas por minuto?","back":"100-120\\text{ cpm}."},{"front":"¿Cada cuánto tiempo se debe cambiar al reanimador que realiza las compresiones?","back":"Cada 2 minutos (o antes si está cansado)."},{"front":"En capnografía cuantitativa, ¿qué valor de \\text{PETCO}_2 indica la necesidad de mejorar la calidad de las compresiones?","back":"Menor a 10\\text{ mmHg}."},{"front":"¿Cuál es el valor objetivo de \\text{PETCO}_2 durante una RCP de alta calidad?","back":"Mayor a 20\\text{ mmHg}."},{"front":"Si se utiliza monitoreo de presión intraarterial, ¿qué valor de presión diastólica obliga a mejorar la RCP?","back":"Menor a 20\\text{ mmHg}."},{"front":"Menciona los dos ritmos clasificados como desfibrilables:","back":"Fibrilación Ventricular (FV) y Taquicardia Ventricular sin pulso (TVSP)."},{"front":"Menciona los dos ritmos clasificados como no desfibrilables:","back":"Asistolia y Actividad Eléctrica Sin Pulso (AESP)."},{"front":"¿Cuál es la carga de energía recomendada para una descarga monofásica?","back":"360\\text{ J}."},{"front":"¿Cómo se determina la energía de descarga en un desfibrilador bifásico?","back":"Según la recomendación del fabricante (o el valor máximo disponible si se desconoce)."},{"front":"¿Cuál es la dosis estándar de Adrenalina en el algoritmo ACLS?","back":"1\\text{ mg} cada 3-5 minutos."},{"front":"¿En qué momento se administra la primera dosis de Adrenalina en un ritmo desfibrilable?","back":"Después de la segunda descarga."},{"front":"¿En qué momento se administra la Adrenalina en ritmos no desfibrilables (Asistolia/AESP)?","back":"De manera temprana (lo antes posible)."},{"front":"¿Cuál es la primera dosis de Amiodarona indicada en ritmos desfibrilables refractarios?","back":"Bolo de 300\\text{ mg}."},{"front":"¿Cuál es la segunda dosis de Amiodarona si persiste el ritmo desfibrilable?","back":"150\\text{ mg}."},{"front":"¿Cuál es el rango de la primera dosis de Lidocaína en ACLS?","back":"1-1.5\\text{ mg/kg}."},{"front":"¿Cuál es el rango de la segunda dosis de Lidocaína en ACLS?","back":"0.5-0.75\\text{ mg/kg}."},{"front":"¿Cuál es la frecuencia ventilatoria una vez colocado un dispositivo avanzado para la vía aérea?","back":"1 ventilación cada 6 segundos con compresiones continuas."},{"front":"Método recomendado para confirmar y monitorizar la colocación del tubo endotraqueal:","back":"Capnografía."},{"front":"¿Qué hallazgo en la capnografía sugiere el Retorno de la Circulación Espontánea (RCE)?","back":"Aumento abrupto y sostenido del \\text{PETCO}_2 mayor a 40\\text{ mmHg}."},{"front":"Menciona las 5 causas reversibles conocidas como las \"H\":","back":"Hipovolemia, Hipoxia, Hidrogeniones (acidosis), Hipo-hiperpotasemia e Hipotermia."},{"front":"Menciona las 5 causas reversibles conocidas como las \"T\":","back":"Tensión (neumotórax), Taponamiento cardíaco, Toxinas, Trombosis pulmonar y Trombosis coronaria."},{"front":"En el algoritmo BLS, ¿qué debe hacerse inmediatamente después de administrar una descarga con el DEA?","back":"Reanudar la RCP inmediatamente por 2 minutos."},{"front":"¿Qué acción se debe evitar rigurosamente durante la ventilación para no comprometer el retorno venoso?","back":"Ventilación excesiva."},{"front":"¿Qué indica la presencia de ondas de presión intraarterial espontánea en un paciente monitorizado?","back":"Retorno de la Circulación Espontánea (RCE)."},{"front":"En el algoritmo de ritmos no desfibrilables, ¿cuál es el siguiente paso tras 2 minutos de RCP y administración de Adrenalina?","back":"Verificar si el ritmo es desfibrilable."},{"front":"¿Cuándo se considera el manejo avanzado de la vía aérea y la capnografía en el algoritmo de FV/TVSP?","back":"Después de la segunda descarga y administración de Adrenalina."},{"front":"Causa reversible: ¿A qué entidad clínica se refiere el término 'Tensión'?","back":"Neumotórax a tensión."},{"front":"Causa reversible: ¿A qué entidad clínica se refiere el término 'Hidrogeniones'?","back":"Acidosis."},{"front":"¿Cuál es el objetivo principal de reducir al mínimo las interrupciones en las compresiones?","back":"Mantener la presión de perfusión coronaria y cerebral."}]},"25":{"num":25,"name":"TRASTORNOS DEL RITMO","cards":[{"front":"¿Qué evento electrofisiológico representa la onda P en el electrocardiograma?","back":"La despolarización auricular."},{"front":"¿Cuál es la duración normal de la onda P según las generalidades del material?","back":"< 0.12 \\ s."},{"front":"¿Cuál es el rango de tiempo normal para el segmento PR?","back":"0.12 a 0.20 \\ segundos."},{"front":"¿Qué evento electrofisiológico representa el complejo QRS?","back":"La despolarización ventricular."},{"front":"¿Cuál es la duración normal de un complejo QRS?","back":"< 0.12 \\ s."},{"front":"¿Qué evento electrofisiológico representa la onda T?","back":"La repolarización ventricular."},{"front":"¿Con qué hallazgo en el electrocardiograma inicia la sístole?","back":"Con el complejo QRS."},{"front":"¿En qué punto del electrocardiograma inicia la diástole y en cuál finaliza?","back":"Inicia con el segmento ST y finaliza con la onda P."},{"front":"Concepto: Automatismo cardiaco","back":"Es el mecanismo de generación del impulso nervioso."},{"front":"Concepto: Dromotropismo cardiaco","back":"Es el mecanismo de propagación del impulso nervioso."},{"front":"¿Cuál es la conducta a seguir ante un paciente con frecuencia cardiaca < 50 \\ lpm pero asintomático?","back":"Únicamente vigilancia."},{"front":"¿Cuál es la dosis inicial recomendada de Atropina IV en el tratamiento de bradicardias sintomáticas?","back":"1 \\ mg en bolo."},{"front":"¿Cuál es la frecuencia de administración y la dosis máxima total de Atropina en bradicardias?","back":"Repetir cada 3 a 5 \\ minutos hasta un máximo de 3 \\ mg."},{"front":"¿Qué fármacos se pueden utilizar en bradiarritmias si la Atropina resulta inefectiva?","back":"Infusión de Dopamina o Adrenalina."},{"front":"¿Cuál es el rango de dosis habitual para la infusión de Dopamina en bradicardias?","back":"5 a 20 \\ mcg/kg por minuto."},{"front":"¿Cuál es el rango de dosis para la infusión de Adrenalina en bradicardias?","back":"2 a 10 \\ mcg por minuto."},{"front":"¿Qué caracteriza al bloqueo AV de primer grado en el electrocardiograma?","back":"Intervalo PR alargado (> 200 \\ ms) de forma constante."},{"front":"¿Qué hallazgo define al bloqueo AV de segundo grado tipo Mobitz I (Wenckebach)?","back":"Intervalos PR que se alargan progresivamente hasta que una onda P no conduce."},{"front":"¿Qué caracteriza al bloqueo AV de segundo grado tipo Mobitz II?","back":"Intervalo PR constante con la aparición repentina de una onda P que no conduce."},{"front":"¿Qué define al bloqueo AV de tercer grado (disociación AV)?","back":"Ausencia de relación entre ondas P y complejos QRS, con presencia de más ondas P que QRS."},{"front":"¿Cuál es la causa más frecuente de implante de marcapasos definitivo en el medio descrito?","back":"Los bloqueos auriculoventriculares (AV)."},{"front":"¿Cuáles son las dos etiologías principales de los bloqueos AV en pacientes geriátricos?","back":"Causas idiopáticas y fármacos frenadores."},{"front":"¿Con qué tipo de infarto agudo al miocardio se asocian frecuentemente los bloqueos AV?","back":"Infarto inferior."},{"front":"¿En qué situaciones se indica marcapasos en bloqueos de primer grado o segundo grado tipo I?","back":"Solo en caso de sintomatología, como síncopes."},{"front":"¿Para qué tipos de bloqueos AV está indicado el marcapasos independientemente de los síntomas iniciales?","back":"Bloqueo de segundo grado tipo II y bloqueo de tercer grado."},{"front":"¿Qué define al síndrome del nodo sinusal enfermo en términos de frecuencia cardiaca relativa?","back":"Frecuencia cardiaca menor del 80% de acuerdo a la edad."},{"front":"¿Cuál es la manifestación clínica característica del síndrome de bradicardia-taquicardia?","back":"Periodos de bradicardia extrema que se alternan con periodos de taquicardia."},{"front":"¿Qué estudio diagnóstico se utiliza si el paciente con sospecha de enfermedad del nodo sinusal presenta síntomas poco frecuentes?","back":"Holter subcutáneo."},{"front":"¿Cuál es el hallazgo diagnóstico en el tiempo de conducción sinoauricular en pacientes con enfermedad del nodo sinusal?","back":"El tiempo de conducción está alargado."},{"front":"¿En qué fase del potencial de acción cardiaco actúan los antiarrítmicos de Clase I?","back":"Fase 0 y Fase 1."},{"front":"¿Cuál es el mecanismo de acción principal de los fármacos antiarrítmicos de Clase II?","back":"Disminuyen el automatismo."},{"front":"Mecanismo de acción de la Clase III de antiarrítmicos: Bloquean canales de K^{+} y prolongan la repolarización, lo que causa el alargamiento del _____.","back":"Intervalo QT."},{"front":"¿En qué fase del potencial de acción actúan los calcioantagonistas (Clase IV)?","back":"Fase 2."},{"front":"Fármacos ejemplo: Clase 1A, 1B y 1C de Vaughan Williams","back":"1A Procainamida, 1B Lidocaína/Fenitoína, 1C Propafenona."},{"front":"¿Cuál es el fármaco prototipo de los antiarrítmicos de Clase III?","back":"Amiodarona."},{"front":"¿Qué define a una taquicardia sinusal en términos de frecuencia y morfología?","back":"Ritmo sinusal > 100 \\ lpm con onda P idéntica a la sinusal."},{"front":"¿Cuál es el manejo terapéutico principal de la taquicardia sinusal?","back":"Tratar la causa responsable (estrés, anemia, fiebre, etc.)."},{"front":"¿Qué fármacos pueden emplearse para controlar la frecuencia en una taquicardia sinusal persistente?","back":"Beta-bloqueantes, calcioantagonistas o ivabradina."},{"front":"¿Cuál es la arritmia crónica sostenida más frecuente en la práctica clínica?","back":"Fibrilación auricular."},{"front":"¿Qué hallazgo en el electrocardiograma sustituye a las ondas P en la fibrilación auricular?","back":"Ondas f (minúsculas) de 350 a 600 \\ lpm."},{"front":"¿Cuál es el factor predisponente más frecuente para el desarrollo de fibrilación auricular?","back":"Hipertensión arterial."},{"front":"¿Qué porcentaje de los eventos trombóticos es causado por la fibrilación auricular?","back":"El 20% de los eventos."},{"front":"¿Cuál es el estándar de oro para el diagnóstico de fibrilación auricular?","back":"Electrocardiograma de 12 derivaciones."},{"front":"En la escala CHA2DS2-VASc, ¿cuántos puntos se otorgan por el criterio de edad \\ge 75 \\ años?","back":"2 \\ puntos."},{"front":"¿Qué puntuación en la escala CHA2DS2-VASc indica la necesidad de anticoagulación en hombres y mujeres respectivamente?","back":"1 o más puntos en hombres; 2 o más puntos en mujeres."},{"front":"¿Cuál es el fármaco de primera elección para la anticoagulación en fibrilación auricular por su menor riesgo de EVC hemorrágica?","back":"Warfarina (antagonista de vitamina K)."},{"front":"¿Cuál es el rango de INR óptimo buscado en pacientes con fibrilación auricular bajo tratamiento con Warfarina?","back":"2 a 3."},{"front":"¿Cuál es la meta de frecuencia cardiaca en reposo para el control de la frecuencia en fibrilación auricular?","back":"< 110 \\ lpm."},{"front":"¿En qué pacientes con fibrilación auricular se puede realizar cardioversión sin anticoagulación previa de 3 semanas?","back":"En aquellos con evolución < 48 \\ horas."},{"front":"¿Qué fármaco es el más eficaz para prevenir las recurrencias de fibrilación auricular?","back":"Amiodarona."},{"front":"¿Qué mecanismo electrofisiológico produce el flutter auricular típico?","back":"Una macrorreentrada en torno al anillo tricuspídeo."},{"front":"¿Qué patrón electrocardiográfico es característico del flutter auricular?","back":"Ondas en dientes de sierra (ondas F mayúsculas)."},{"front":"¿A qué patología pulmonar se asocia frecuentemente el flutter auricular?","back":"EPOC (Enfermedad Pulmonar Obstructiva Crónica)."},{"front":"¿Cuál es el tratamiento definitivo para prevenir el flutter auricular común?","back":"Ablación con catéter del istmo cavotricuspídeo."},{"front":"¿Qué estructura anatómica anómala comunica las aurículas con los ventrículos en el síndrome de Wolff-Parkinson-White?","back":"El Haz de Kent."},{"front":"¿Qué tríada electrocardiográfica caracteriza al síndrome de Wolff-Parkinson-White?","back":"Intervalo PR corto (< 0.12 \\ s), onda delta y QRS ancho."},{"front":"¿Qué anomalía congénita se asocia con mayor frecuencia al síndrome de Wolff-Parkinson-White?","back":"Enfermedad de Ebstein."},{"front":"¿Cuál es la definición de taquicardia ventricular en términos de latidos consecutivos?","back":"Presencia de tres o más latidos consecutivos con QRS ancho (> 0.12 \\ s)."},{"front":"¿Cuál es la causa más frecuente (80%) de taquicardia ventricular?","back":"Cardiopatía isquémica (reentrada sobre cicatriz de infarto previo)."},{"front":"¿Cuánto tiempo debe durar una taquicardia ventricular para ser considerada 'sostenida'?","back":"> 30 \\ segundos (o producir colapso circulatorio)."},{"front":"¿Cuál es el tratamiento de elección para una taquicardia ventricular polimorfa (Torsade de Pointes)?","back":"Sulfato de Magnesio."},{"front":"¿Qué hallazgo electrocardiográfico define a la fibrilación ventricular?","back":"Ondulaciones irregulares sin complejos QRS ni ondas T distinguibles."},{"front":"¿Cuál es el único tratamiento eficaz para la fibrilación ventricular?","back":"Desfibrilación eléctrica."},{"front":"¿Cómo se clasifican la Fibrilación Ventricular y la Taquicardia Ventricular sin pulso en el algoritmo de paro?","back":"Ritmos desfibrilables."},{"front":"¿Cómo se clasifican la Asistolia y la Actividad Eléctrica Sin Pulso (AESP) en el algoritmo de paro?","back":"Ritmos no desfibrilables."},{"front":"¿Qué carga de energía se recomienda para la cardioversión de una taquicardia de QRS ancho regular inestable?","back":"100 \\ J."},{"front":"¿Qué carga de energía se recomienda para la cardioversión de una taquicardia de QRS ancho irregular (desfibrilación)?","back":"200 \\ J."},{"front":"¿Qué maniobra inicial se recomienda en una taquicardia estable de QRS estrecho regular?","back":"Maniobras vagales."},{"front":"¿Cuál es la causa más frecuente de Síndrome de QT Largo (SQTL) adquirido?","back":"Uso de fármacos que interfieren con las corrientes iónicas repolarizantes."},{"front":"¿Qué dato clínico sugiere endocarditis infecciosa en un usuario de drogas IV?","back":"Falla cardiaca izquierda y máculas en palmas y plantas."},{"front":"¿Qué agente infeccioso se asocia típicamente a la miocarditis?","back":"Virus Coxsackie B."},{"front":"¿Qué característica del dolor orienta al diagnóstico de pericarditis aguda?","back":"Dolor pleurítico que aumenta al toser y disminuye al inclinarse hacia adelante."},{"front":"¿Qué hallazgo en el EKG es típico de la pericarditis aguda?","back":"Elevación difusa del segmento ST en casi todas las derivaciones."},{"front":"¿Qué tríada clínica sugiere miocardiopatía hipertrófica?","back":"Síncope, angina y soplo sistólico que aumenta con la maniobra de Valsalva."},{"front":"¿Qué hallazgo en la angioplastia caracteriza a la Angina de Prinzmetal?","back":"Ausencia de trombos (vasoconstricción primaria)."},{"front":"¿Qué antecedente epidemiológico se asocia a la miocardiopatía dilatada en el contexto de bajo gasto cardiaco?","back":"Enfermedad de Chagas."}]},"26":{"num":26,"name":"HIPERTENSION ARTERIAL SISTEMICA","cards":[{"front":"¿Cómo se define la Hipertensión Arterial Sistémica (HAS) según las cifras de presión arterial en el consultorio?","back":"Como la elevación persistente de la presión arterial \\ge 140/90 mmHg tras exámenes repetidos."},{"front":"Fisiológicamente, la presión arterial es el producto del gasto cardíaco por la _____.","back":"Resistencia vascular sistémica"},{"front":"¿Cuál es la prevalencia aproximada de la hipertensión arterial en la población adulta de México?","back":"32.3\\%"},{"front":"¿Qué porcentaje de pacientes hipertensos en México se encuentra bajo un control adecuado?","back":"15\\%"},{"front":"¿A partir de qué edad se considera que el riesgo de desarrollar HAS aumenta significativamente como factor de riesgo?","back":"40 años"},{"front":"¿Cuántas veces es más común la HAS en individuos que tienen un padre hipertenso?","back":"2 veces"},{"front":"¿Cuál es el límite máximo recomendado de ingesta diaria de sodio para prevenir la HAS?","back":"2000 mg (equivalente a 5 g de sal)"},{"front":"Para la prevención de HAS, se recomienda realizar ejercicio aeróbico moderado o intenso durante al menos _____ minutos, 5 a 7 días por semana.","back":"30 a 45 minutos"},{"front":"¿Qué porcentaje de los casos de hipertensión arterial corresponde a la forma primaria o esencial?","back":"95\\%"},{"front":"¿Cuál es la causa más común de hipertensión arterial secundaria?","back":"Enfermedad Renal Crónica"},{"front":"¿Con qué frecuencia deben someterse a tamizaje los adultos de 18 a 39 años con presión normal (<130/80 mmHg) y sin factores de riesgo?","back":"Cada 3 a 5 años"},{"front":"¿Con qué frecuencia debe realizarse la detección de HAS en adultos mayores de 40 años con factores de riesgo?","back":"Anualmente"},{"front":"¿Cuáles son las dimensiones estándar (ancho y largo) del manguito de presión recomendado para la medición?","back":"12-13 cm de ancho y 35 cm de largo"},{"front":"¿Cuántos minutos de reposo debe tener el paciente antes de iniciar la medición de la presión arterial?","back":"5 minutos"},{"front":"Según la clasificación, ¿cuáles son las cifras de presión arterial para el Nivel Óptimo?","back":"<120 mmHg de sistólica y <80 mmHg de diastólica"},{"front":"¿Qué rango de presión arterial sistólica define a la HAS Estadio 1?","back":"140 a 159 mmHg"},{"front":"¿Qué rango de presión arterial diastólica define a la HAS Estadio 2?","back":"100 a 109 mmHg"},{"front":"La HAS Estadio 3 se define por una presión sistólica \\ge 180 mmHg o una diastólica \\ge _____ mmHg.","back":"110 mmHg"},{"front":"¿Cuál es el criterio diagnóstico de HAS mediante el monitoreo domiciliario (AMPA/MDPA)?","back":"Cifras \\ge 135/85 mmHg"},{"front":"¿Cuál es el criterio diagnóstico de HAS mediante MAPA en el periodo diurno?","back":"Cifras \\ge 135/85 mmHg"},{"front":"¿Cuál es el criterio diagnóstico de HAS mediante MAPA en el periodo nocturno?","back":"Cifras >120/75 mmHg"},{"front":"La HAS de bata blanca se sospecha en adultos con una presión sistólica mayor a 130 mmHg pero menor a _____ mmHg en el consultorio.","back":"160 mmHg"},{"front":"¿Qué condición se define como presión arterial <140/90 mmHg en consultorio pero >140/90 mmHg en casa?","back":"Hipertensión enmascarada"},{"front":"¿Cuál es el método de elección para confirmar el diagnóstico de hipertensión arterial?","back":"MAPA (Monitorización Ambulatoria de la Presión Arterial) de 24 horas"},{"front":"¿Cuántas mediciones y visitas médicas se requieren para el diagnóstico inicial 'tradicional' de HAS?","back":"2-3 mediciones en al menos 2 visitas médicas"},{"front":"¿Cuánto puede reducir la presión arterial sistólica la implementación de dietas como la DASH o Mediterránea?","back":"Hasta 11 mmHg"},{"front":"¿En qué grupo de pacientes está contraindicada la suplementación de potasio?","back":"Pacientes con Enfermedad Renal Crónica (ERC)"},{"front":"¿Qué tipo de carne se prefiere consumir en el tratamiento no farmacológico de la HAS?","back":"Carne blanca (pescado o pollo)"},{"front":"¿Qué hallazgo en un paciente joven con HAS debe hacer sospechar de estenosis de la arteria renal tras iniciar tratamiento?","back":"Incremento de creatinina mayor a 0.7 mg/dl o más del 30\\%"},{"front":"¿Cuál es el manejo inicial recomendado para un paciente con HAS sistólica de 140 mmHg?","back":"Inicio de tratamiento farmacológico para disminuir riesgo de muerte y EVC"},{"front":"¿Cuál es la estrategia farmacológica inicial recomendada para la mayoría de los pacientes con HAS?","back":"Terapia dual a dosis estándar combinando fármacos de primera línea"},{"front":"¿En qué pacientes se sugiere iniciar con monoterapia en lugar de terapia dual?","back":"Pacientes con fragilidad o edad >80 años"},{"front":"¿Con qué cifras de presión arterial se debe iniciar tratamiento farmacológico en pacientes de alto riesgo cardiovascular (>10%)?","back":">130/80 mmHg"},{"front":"¿Cuáles son las dos combinaciones posibles para la terapia dual inicial?","back":"IECA o BRA + Calcioantagonista (BCC) o IECA o BRA + Diurético"},{"front":"¿Qué tipo de terapia dual se prefiere en pacientes con síndrome metabólico, obesidad o DM2?","back":"Combinación que incluya un Calcioantagonista (BCC)"},{"front":"¿Qué tipo de diurético se sugiere utilizar si el aclaramiento de creatinina es <30 ml/min?","back":"Diurético de asa"},{"front":"¿Qué fármacos componen la terapia triple para el tratamiento de la HAS?","back":"IECA o BRA + Calcioantagonista + Diurético"},{"front":"¿Qué fármaco se añade a la terapia triple en casos de hipertensión arterial resistente?","back":"Espironolactona"},{"front":"¿Qué alternativa farmacológica se prefiere en HAS resistente con aclaramiento de creatinina <30 ml/min en lugar de espironolactona?","back":"Bloqueadores alfa, betabloqueadores o simpaticolíticos"},{"front":"¿Cuál es la meta de presión arterial sistólica a corto plazo en adultos menores de 80 años?","back":"<140 mmHg (pero nunca menos de 65 mmHg)"},{"front":"¿Cuál es la meta de presión arterial en pacientes con diabetes mellitus e hipertensión?","back":"<130/80 mmHg"},{"front":"¿Cuál es la meta de presión arterial en pacientes hipertensos con aterosclerosis carotídea mayores de 80 años?","back":"<150/90 mmHg"},{"front":"¿Cuál es la contraindicación absoluta para el uso de diuréticos de tipo tiazida?","back":"Gota"},{"front":"Menciona dos contraindicaciones para el uso de IECAs.","back":"Embarazo y estenosis renal bilateral"},{"front":"¿En qué condiciones respiratorias y cardíacas están contraindicados los betabloqueadores?","back":"Asma y bloqueo auriculoventricular (AV)"},{"front":"¿Qué condición define a la hipertensión sistólica aislada?","back":"Cifras >140/<90 mmHg"},{"front":"¿Qué fenómeno clínico se caracteriza por náuseas y visión borrosa 1-2 horas después de comer en pacientes geriátricos?","back":"Hipotensión posprandial"},{"front":"¿Cuál es la causa principal de hipotensión ortostática en pacientes geriátricos?","back":"Causas farmacológicas"},{"front":"El signo de _____ consiste en la palpación de la arteria radial tras la desaparición del pulso al inflar el manguito.","back":"Osler"},{"front":"¿Por qué se recomienda tomar la presión arterial en ambos brazos durante la primera consulta?","back":"Porque una diferencia >15 mmHg indica enfermedad ateromatosa y mayor riesgo CV"},{"front":"¿Cómo se define la hipertensión arterial maligna?","back":"Elevación de la TA asociada a edema de papila"},{"front":"¿Qué fármaco se debe administrar en caso de hipertensión perioperatoria con cifras >160/90 mmHg?","back":"Esmolol o Nitroglicerina"},{"front":"¿Cuál es el criterio de presión arterial para posponer una cirugía programada?","back":">180/110 mmHg"},{"front":"¿Cuál es la cifra de presión arterial sistólica mínima recomendada en pacientes con insuficiencia cardíaca con FEVI conservada?","back":"No menor a 130 mmHg"},{"front":"¿Qué estudios básicos de laboratorio se recomiendan para el abordaje inicial de la HAS?","back":"Biometría hemática, creatinina, urea, electrolitos séricos, examen de orina y perfil de lípidos"},{"front":"¿Cuál es la definición general de crisis hipertensiva?","back":"Elevación aguda de la TA con sistólica >180 mmHg y/o diastólica >120 mmHg"},{"front":"¿Qué característica distingue a la urgencia hipertensiva de la emergencia?","back":"La ausencia de daño agudo a órgano diana"},{"front":"¿Cuál es la vía de administración preferida para el tratamiento de una urgencia hipertensiva?","back":"Vía oral (manejo ambulatorio)"},{"front":"¿Cuál es el porcentaje de crisis hipertensivas que corresponden a emergencias?","back":"24\\%"},{"front":"¿Cuál es el fármaco de primera línea de forma general para la emergencia hipertensiva por su inicio rápido?","back":"Nitroprusiato de sodio"},{"front":"¿Cuál es el esquema de tratamiento de primera línea para una disección aórtica aguda?","back":"Esmolol o Labetalol + Nitroprusiato"},{"front":"¿Cuál es la meta de presión sistólica y frecuencia cardíaca en la disección aórtica en los primeros 20 minutos?","back":"Sistólica <120 mmHg y FC <80 lpm"},{"front":"¿Cuál es la meta de reducción de la TAM en las primeras 24 horas para un EVC isquémico no candidato a trombólisis?","back":"Disminución del 15\\%"},{"front":"¿Cuál es la meta de presión arterial para iniciar trombólisis en un EVC isquémico?","back":"<185/110 mmHg"},{"front":"¿Qué fármacos se recomiendan para el control de la TA en un síndrome coronario agudo?","back":"Nitroglicerina, Labetalol o Esmolol"},{"front":"¿Cuál es la meta de presión sistólica en una hemorragia cerebral aguda según la guía?","back":"<220 mmHg"},{"front":"¿Cuál es el objetivo de reducción de la TAM en la primera hora de una encefalopatía hipertensiva?","back":"Reducción del 20 a 25\\%"},{"front":"¿Qué combinación de fármacos es de primera línea para el edema agudo pulmonar hipertensivo?","back":"Nitroprusiato + Diuréticos de asa"},{"front":"¿Cuál es el manejo inicial para la hipertensión causada por consumo de cocaína o anfetaminas?","back":"Benzodiacepinas (y Fentolamina si es necesario)"},{"front":"¿En qué consiste el tratamiento de primera línea para la hipertensión maligna?","back":"Labetalol (primera opción) o Nitroprusiato"},{"front":"Term/Definition: AMPA","back":"Automedida de la Presión Arterial; realizada por el paciente en su entorno habitual."},{"front":"Term/Definition: MAPA","back":"Monitorización Ambulatoria de la Presión Arterial; registro automático durante 24 horas."},{"front":"¿Qué estudio de gabinete es específico para sospecha de disección aórtica en una crisis hipertensiva?","back":"Angiotomografía de tórax y/o abdomen"},{"front":"¿Qué síntoma neurológico es característico de la encefalopatía hipertensiva?","back":"Cefalea intensa y pérdida del estado de alerta"},{"front":"¿Cuál es el objetivo de presión sistólica en un síndrome coronario agudo?","back":"<140 mmHg"}]},"27":{"num":27,"name":"PERLAS DE CARDIOLOGIA","cards":[{"front":"¿En qué espacio intercostal y línea se localiza el foco aórtico?","back":"Segundo espacio intercostal derecho, línea paraesternal."},{"front":"¿Dónde se sitúa exactamente el foco pulmonar para la auscultación?","back":"Segundo espacio intercostal izquierdo, línea paraesternal."},{"front":"Localización del foco tricuspídeo:","back":"Cuarto espacio intercostal izquierdo, línea paraesternal."},{"front":"¿En qué punto anatómico se ausculta mejor el foco mitral?","back":"Quinto espacio intercostal izquierdo, línea medio-clavicular."},{"front":"¿Cuál es la ubicación del foco de Erb (área general del corazón)?","back":"Tercer espacio intercostal izquierdo."},{"front":"¿Qué evento mecánico produce el primer ruido cardíaco (R_1)?","back":"El cierre de las válvulas auriculoventriculares (mitral y tricuspídea)."},{"front":"¿En qué foco auscultatorio se escucha con mayor intensidad el ruido R_1?","back":"Foco mitral."},{"front":"¿Qué fase del ciclo cardíaco ocurre entre los ruidos R_1 y R_2?","back":"La sístole."},{"front":"¿Qué fenómeno fisiológico genera el segundo ruido cardíaco (R_2)?","back":"El cierre de las válvulas semilunares (aórtica y pulmonar)."},{"front":"¿Qué fase del ciclo cardíaco sucede entre los ruidos R_2 y R_1?","back":"La diástole."},{"front":"¿A qué fenómeno fisiopatológico se asocia la presencia de un tercer ruido (R_3)?","back":"Llenado ventricular rápido, común en insuficiencia cardíaca o dilatación ventricular."},{"front":"¿Qué indica la presencia de un cuarto ruido cardíaco (R_4)?","back":"Contracción auricular forzada contra un ventrículo rígido (hipertrofia o isquemia)."},{"front":"¿En qué momento de la respiración ocurre el desdoblamiento fisiológico del segundo ruido?","back":"Durante la inspiración."},{"front":"El desdoblamiento amplio del segundo ruido cardíaco se asocia patológicamente con el _____.","back":"Bloqueo de rama derecha"},{"front":"¿Qué trastorno eléctrico se sospecha ante un desdoblamiento paradójico (en espiración) del segundo ruido?","back":"Bloqueo de rama izquierda."},{"front":"Propiedad cardíaca: Automatismo","back":"Definición: Capacidad del nodo SA para generar impulsos eléctricos automáticamente."},{"front":"Propiedad cardíaca: Inotropismo","back":"Definición: Capacidad de contracción del músculo cardíaco."},{"front":"Propiedad cardíaca: Cronotropismo","back":"Definición: Capacidad de regulación de la frecuencia cardíaca."},{"front":"Propiedad cardíaca: Dromotropismo","back":"Definición: Propiedad para la propagación del impulso eléctrico."},{"front":"Propiedad cardíaca: Batmotropismo","back":"Definición: Capacidad del corazón de responder a estímulos eléctricos (excitabilidad)."},{"front":"¿Qué neurotransmisor y receptor median el cronotropismo positivo (simpático)?","back":"Noradrenalina actuando en receptores \\beta-1."},{"front":"¿Qué neurotransmisor y receptor median el cronotropismo negativo (parasimpático)?","back":"Acetilcolina actuando en receptores muscarínicos M_2."},{"front":"¿Qué estructura anatómica regula el dromotropismo retrasando el impulso para permitir el llenado ventricular?","back":"El nodo auriculoventricular (AV)."},{"front":"Potencial de acción: Fase 0","back":"Evento: Despolarización rápida por ingreso masivo de Na^+ a través de canales rápidos."},{"front":"¿Cuál es el cambio de voltaje aproximado durante la Fase 0 del potencial de acción?","back":"De -90 mV a +20 mV."},{"front":"Potencial de acción: Fase 1","back":"Evento: Repolarización inicial por salida breve de K^+ a través de canales transitorios."},{"front":"Potencial de acción: Fase 2 (Meseta)","back":"Evento: Entrada lenta de Ca^{2+} (canales tipo L) y salida simultánea de K^+."},{"front":"Potencial de acción: Fase 3","back":"Evento: Repolarización rápida por cierre de canales de Ca^{2+} y salida masiva de K^+."},{"front":"¿Cuál es la función principal de la bomba Na^+/K^+ durante la Fase 4?","back":"Restablecer los electrolitos sacando 3 Na^+ y metiendo 2 K^+ para mantener el potencial de reposo."},{"front":"Clasificación de Vaughan Williams: Clase I","back":"Mecanismo: Bloquean canales de Na^+ y actúan en la Fase 0 (ej. Lidocaína, Propafenona)."},{"front":"Clasificación de Vaughan Williams: Clase II","back":"Mecanismo: Betabloqueadores que disminuyen el automatismo actuando en la Fase 4."},{"front":"Clasificación de Vaughan Williams: Clase III","back":"Mecanismo: Bloquean canales de K^+, prolongan la repolarización y el QT (ej. Amiodarona)."},{"front":"Clasificación de Vaughan Williams: Clase IV","back":"Mecanismo: Bloquean canales de Ca^{2+} y actúan en la Fase 2 (ej. Verapamilo, Diltiazem)."},{"front":"¿Qué evento eléctrico representa la onda P en el EKG?","back":"La despolarización auricular (contracción de las aurículas)."},{"front":"¿Cuál es la duración normal del intervalo PR?","back":"0.12 a 0.20 segundos."},{"front":"¿Qué representa el complejo QRS y cuál es su duración normal?","back":"Representa la despolarización ventricular y dura menos de 0.12 segundos."},{"front":"¿Qué evento eléctrico se manifiesta como la onda T en el EKG?","back":"La repolarización ventricular."},{"front":"¿Cómo se define la bradicardia sinusal según la frecuencia cardíaca?","back":"Frecuencia cardíaca menor a 60 latidos por minuto (LPM)."},{"front":"¿Qué hallazgo en el intervalo PR es característico del Síndrome de Wolff-Parkinson-White?","back":"Acortamiento del PR (menor a 0.12 s) debido a una vía accesoria."},{"front":"En el EKG, un intervalo PR mayor a 0.20 segundos es diagnóstico de _____.","back":"Bloqueo auriculoventricular (AV)"},{"front":"¿Qué indica un complejo QRS ancho (mayor a 0.12 s) en un paciente con taquicardia?","back":"Que el impulso se genera en los ventrículos (ej. taquicardia ventricular) o hay un bloqueo de rama."},{"front":"¿Qué patología coronaria se asocia con una elevación del segmento ST?","back":"Infarto transmural por oclusión total de una arteria coronaria."},{"front":"¿Qué sugiere una depresión del segmento ST en el EKG?","back":"Isquemia subendocárdica o angina de esfuerzo."},{"front":"¿Cuál es la alteración electrolítica clásica que produce ondas T picudas?","back":"Hiperpotasemia (hiperkalemia)."},{"front":"¿Qué hallazgo en la onda T sugiere isquemia miocárdica subepicárdica?","back":"Onda T invertida."},{"front":"Hallazgo EKG: Ausencia de ondas P y ritmo irregular.","back":"Fibrilación auricular."},{"front":"¿Qué arritmia se caracteriza por ondas en 'dientes de sierra'?","back":"Flutter auricular."},{"front":"¿Qué evento eléctrico fatal presenta una actividad desorganizada sin complejos QRS identificables?","back":"Fibrilación ventricular."},{"front":"¿Qué caracteriza a la taquicardia supraventricular en términos de frecuencia y QRS?","back":"Frecuencia de 150-250 LPM y complejo QRS estrecho."},{"front":"¿Qué componente del EKG marca el inicio de la sístole ventricular?","back":"El complejo QRS."},{"front":"¿En qué fase del potencial de acción actúan los fármacos de Clase III como la Amiodarona?","back":"Fase 3 (repolarización rápida)."},{"front":"¿Cuál es la causa fisiológica del retraso del impulso en el nodo AV?","back":"Permitir que las aurículas se contraigan y vacíen su sangre en los ventrículos antes de la sístole ventricular."},{"front":"¿Qué representa la onda delta en el EKG?","back":"Preexcitación ventricular, característica del síndrome de Wolff-Parkinson-White."},{"front":"¿Qué alteración del potasio puede alterar el potencial de reposo y afectar la excitabilidad (batmotropismo)?","back":"Tanto la hiperkalemia como la hipokalemia."},{"front":"¿Qué fármacos se utilizan típicamente en la Fase 4 del potencial de acción (Clase II)?","back":"Betabloqueadores como el Metoprolol o Propanolol."}]},"28":{"num":28,"name":"ENFERMEDAD VASCULAR CEREBRAL","cards":[{"front":"En México, ¿qué lugar ocupa la enfermedad vascular cerebral como causa de muerte?","back":"Séptimo lugar."},{"front":"¿Cuál es la incidencia aproximada de EVC en México por cada 100,000 habitantes al año?","back":"Cercana a los 250 casos."},{"front":"¿Cuál es la primera causa de discapacidad en adultos en México?","back":"La enfermedad vascular cerebral (EVC)."},{"front":"De acuerdo con el material, ¿qué porcentaje de los EVC son de tipo isquémico?","back":"Entre el 75-80% (o 87% según la definición técnica)."},{"front":"¿Cuál es el principal factor de riesgo **no modifiable** para padecer un EVC?","back":"La edad."},{"front":"¿Cuál es el principal factor de riesgo **modifiable** para padecer un EVC?","back":"La hipertensión arterial."},{"front":"¿Cuál es el segundo factor de riesgo modificado más importante mencionado?","back":"Diabetes Mellitus."},{"front":"En menores de 50 años, ¿cuál es la causa más frecuente de EVC?","back":"Cardiopatía reumática."},{"front":"¿Cuáles son las tres categorías de la clasificación etiológica del EVC isquémico?","back":"Cardioembolismo, aterosclerosis de grandes vasos y lacunar."},{"front":"¿Qué condiciones se asocian frecuentemente al cardioembolismo como causa de EVC?","back":"Fibrilación auricular, trombos murales y cardiomiopatía dilatada."},{"front":"¿Cuál es la meta de presión arterial para la población general como prevención de EVC?","back":"<140/90 mmHg."},{"front":"¿Cuál es la meta de presión arterial para pacientes con Diabetes Mellitus?","back":"<130/80 mmHg."},{"front":"En el control glucémico preventivo, ¿cuál es el objetivo de HbA1c?","back":"<7%."},{"front":"En la prevención de EVC, ¿cuál es el nivel meta de LDL en pacientes con dislipidemia?","back":"<100 mg/dL."},{"front":"¿Cómo se define la Isquemia Cerebral Transitoria (ICT) en términos de duración?","back":"Déficit neurológico con una duración menor de 24 horas (usualmente menor de una hora)."},{"front":"Un criterio esencial de la Isquemia Cerebral Transitoria es la ausencia de _____ en la neuroimagen.","back":"Infarto agudo (lesión orgánica)."},{"front":"¿Cuál es la arteria cerebral que se afecta con mayor frecuencia en el EVC isquémico?","back":"Arteria cerebral media."},{"front":"¿Qué signo se observa en la TAC simple ante la oclusión de la arteria cerebral media?","back":"Signo de la cuerda."},{"front":"Un cuadro con afasia, alexia, agrafia y hemiparesia facio-braquial contralateral sugiere afección de la arteria _____.","back":"Cerebral media."},{"front":"¿Hacia qué lado ocurre la desviación de la mirada horizontal en una lesión de la arteria cerebral media?","back":"Hacia el lado de la lesión."},{"front":"La tríada de hemiparesia de predominio crural, apraxia de la marcha e incontinencia urinaria indica afección de la arteria _____.","back":"Cerebral anterior."},{"front":"La presencia de alexia sin afasia ni paresia sugiere una lesión en la arteria _____.","back":"Cerebral posterior."},{"front":"¿Qué síntoma visual es típico de la afección distal de la arteria cerebral posterior?","back":"Hemianopsia o cuadrantanopsia."},{"front":"¿Qué síntoma ocular transitorio sugiere afección de la carótida interna?","back":"Amaurosis fugax."},{"front":"Para identificar candidatos a trombólisis mediante la escala de Cincinnati, ¿qué tres signos se evalúan?","back":"Parálisis facial, caída del brazo y habla anormal."},{"front":"¿Qué instrucción se le da al paciente para evaluar la parálisis facial en la escala de Cincinnati?","back":"Que sonría y muestre los dientes."},{"front":"¿Cuánto tiempo debe el paciente mantener los brazos extendidos para evaluar la caída del brazo?","back":"10 segundos."},{"front":"¿Cuál es la frase que se le pide repetir al paciente para evaluar el habla anormal?","back":"\"No se le puede enseñar trucos nuevos a un perro viejo\"."},{"front":"¿Qué condición metabólica debe descartarse siempre al inicio del abordaje de un posible EVC?","back":"Hipoglucemia."},{"front":"¿Cuál es la escala de primera línea para el diagnóstico prehospitalario de EVC?","back":"Escala FAST."},{"front":"¿Cuál es la escala diagnóstica prehospitalaria considerada como la más sensible?","back":"Escala FAST."},{"front":"¿Cuál es la escala diagnóstica prehospitalaria considerada como la más específica?","back":"Escala de Los Ángeles."},{"front":"¿Para qué sirve la escala ABCD2?","back":"Para evaluar el riesgo tras un ataque isquémico transitorio y la necesidad de hospitalización."},{"front":"En la escala ABCD2, ¿qué significa la letra 'B'?","back":"Blood Pressure (Presión arterial) >140/90 mmHg."},{"front":"En la escala ABCD2, ¿cuántos puntos otorga la debilidad unilateral?","back":"2 puntos."},{"front":"Según la escala ABCD2, ¿qué rango de puntos define una ICT de alto riesgo?","back":"2 a 4 puntos."},{"front":"Tras la llegada a urgencias, ¿en cuántos minutos debe realizarse la evaluación física inicial?","back":"En los primeros 10 minutos."},{"front":"Tras la llegada a urgencias, ¿en cuántos minutos debe realizarse la tomografía?","back":"En los primeros 25 minutos."},{"front":"Tras la llegada a urgencias, ¿en cuántos minutos debe estar interpretada la tomografía?","back":"En los primeros 45 minutos."},{"front":"¿Cuál es el tiempo meta ('door-to-needle') para iniciar la trombólisis desde la llegada del paciente?","back":"En los primeros 60 minutos."},{"front":"¿En cuánto tiempo debe ser transferido el paciente a un área apropiada para su cuidado?","back":"En las primeras 3 horas."},{"front":"¿Qué escala se utiliza para evaluar el grado de severidad y afectación neurológica inicial?","back":"Escala de NIHSS."},{"front":"Un puntaje de NIHSS entre 5 y 20 puntos se clasifica como _____.","back":"EVC Moderado."},{"front":"Un puntaje de NIHSS entre 21 y 42 puntos se clasifica como _____.","back":"EVC Grave."},{"front":"¿Qué escala se utiliza ante síntomas vestibulares que sugieren afectación de la circulación posterior?","back":"Escala DEFENSIVE."},{"front":"¿Cuál es el estudio de imagen de primera elección para detectar cambios isquémicos tempranos (3-30 min)?","back":"Resonancia Magnética (RM)."},{"front":"Si no hay RM disponible, la TAC simple detecta cambios isquémicos en un rango de _____ horas.","back":"6 a 24 horas."},{"front":"¿Para qué sirve la escala de ASPECTS en la valoración del EVC por TAC?","back":"Para valorar la extensión de la isquemia en el territorio de la arteria cerebral media."},{"front":"En la escala ASPECTS, un puntaje menor o igual a 7 indica que está afectado más de _____ del territorio de la ACM.","back":"Un tercio."},{"front":"¿Cuál es la solución intravenosa recomendada para el manejo inicial y corrección de volumen?","back":"Solución salina al 0.9%."},{"front":"¿Cuál es el objetivo de saturación de oxígeno en el manejo inicial del EVC?","back":"94%."},{"front":"En una emergencia hipertensiva durante un EVC, ¿en qué porcentaje máximo se debe reducir la TA?","back":"No más del 10-20%."},{"front":"¿Qué estudio de control se debe realizar 24 horas después de la trombólisis?","back":"TAC o RM de control."},{"front":"¿Cuál es el fármaco trombolítico de primera línea y su dosis estándar?","back":"Alteplasa (rt-PA) a 0.9 mg/kg."},{"front":"¿Cuál es la dosis máxima permitida de Alteplasa en el tratamiento del EVC?","back":"90 mg."},{"front":"¿Cuál es la ventana de tiempo estándar para el inicio de la terapia fibrinolítica venosa?","back":"<4.5 horas desde el inicio de los síntomas."},{"front":"¿Qué puntaje de ASPECTS es necesario para ser candidato a trombólisis?","back":"Mayor a 6 (>6)."},{"front":"¿Cuál es el rango de edad mencionado como criterio para la trombólisis estándar?","back":"Mayor o igual a 18 años y menores de 80 años."},{"front":"¿Qué cifra de presión arterial es un criterio de exclusión absoluto para trombólisis?","back":"Presión arterial mayor de 185/110 mmHg."},{"front":"¿Qué fármacos se utilizan para bajar la TA por debajo de 185/110 mmHg antes de trombolizar?","back":"Labetalol o Nicardipino."},{"front":"¿Cuál es el tiempo límite para realizar una trombectomía mecánica (tratamiento endovascular)?","back":"6 horas desde el inicio de los síntomas."},{"front":"¿En qué casos está indicada la craneotomía descompresiva temprana (primeras 48 h)?","back":"Cuando hay afectación extensa de la arteria cerebral media."},{"front":"Concepto: Hemorragia Subaracnoidea (HSA)","back":"Presencia de sangre en el espacio subaracnoideo o en el sistema ventricular."},{"front":"¿Cuál es la causa más frecuente (80%) de hemorragia subaracnoidea espontánea?","back":"Ruptura de aneurismas saculares."},{"front":"¿En qué arteria se localizan con mayor frecuencia los aneurismas causantes de HSA?","back":"Arteria comunicante anterior."},{"front":"¿Cuál es el cuadro clínico típico de una hemorragia subaracnoidea?","back":"Cefalea súbita de gran intensidad (\"la peor de la vida\"), rigidez de nuca, náusea y fotofobia."},{"front":"¿Qué estudio de imagen es la primera elección para el diagnóstico de HSA?","back":"Tomografía Computarizada (TAC)."},{"front":"¿Cuál es el estándar de oro (Gold Standard) para el diagnóstico de HSA?","back":"Angiografía cerebral selectiva."},{"front":"¿Qué prueba es la más sensible para HSA en caso de que la TAC sea normal o haya duda diagnóstica?","back":"Punción lumbar."},{"front":"¿Qué escala se utiliza para valorar el pronóstico clínico de pacientes con HSA?","back":"Escala de Hunt y Hess."},{"front":"¿Qué evalúa la escala de Fisher en el contexto de la HSA?","back":"El riesgo de presentar vasoespasmo según los hallazgos en TAC."},{"front":"¿Cuál es el tratamiento quirúrgico de elección para aneurismas de la comunicante anterior?","back":"Clipaje quirúrgico."},{"front":"¿Qué procedimiento se prefiere para aneurismas en la circulación posterior?","back":"Embolización."},{"front":"¿Cuál es la principal causa de morbimortalidad en la HSA y en qué días aparece?","back":"Vasoespasmo, aparece entre los días 4 y 12."},{"front":"¿Qué fármaco se utiliza para la prevención del vasoespasmo en la HSA?","back":"Nimodipino."},{"front":"¿Cuál es el objetivo de Presión Arterial Media (PAM) en el manejo de la HSA?","back":"65 mmHg."},{"front":"¿Qué fármaco se utiliza para el control de convulsiones en la HSA?","back":"Fenitoína."},{"front":"Concepto: Hemorragia Intraparenquimatosa","back":"Hemorragia producida dentro del encéfalo por ruptura de un vaso profundo (arterial o venoso)."},{"front":"¿Cuáles son las cuatro localizaciones más frecuentes de la hemorragia intraparenquimatosa hipertensiva?","back":"Putamen, tálamo, protuberancia y cerebelo."},{"front":"¿Cuál es el factor de riesgo modifiable más importante para la hemorragia intraparenquimatosa?","back":"La hipertensión arterial."},{"front":"¿Qué estudio es el de mayor sensibilidad para detectar hemorragia intraparenquimatosa en etapa aguda?","back":"Tomografía Computarizada (TAC)."},{"front":"¿Qué fármacos se recomiendan para el control de la TA en hemorragia intraparenquimatosa?","back":"Labetalol o Hidralazina."},{"front":"¿Qué manejo se utiliza para evitar o reducir el edema cerebral?","back":"Manitol o soluciones hipertónicas."},{"front":"¿Bajo qué condición se indica intervención quirúrgica en una hemorragia intraparenquimatosa?","back":"Si existe efecto de masa."},{"front":"¿Cuál es la dosis de Alteplasa que se administra inicialmente como bolo?","back":"10% de la dosis total calculada."},{"front":"En el algoritmo de tratamiento, ¿a qué nivel de glucosa capilar se debe tratar la hipoglucemia?","back":"\\\\le 60 mg/dL."}]},"29":{"num":29,"name":"TRASTORNOS DEL MOVIMIENTO","cards":[{"front":"¿Qué término define a las oscilaciones rítmicas de una parte del cuerpo por contracciones musculares alternas?","back":"Temblor."},{"front":"El temblor que ocurre en ausencia de actividad muscular voluntaria se clasifica como temblor de _____.","back":"reposo"},{"front":"¿Cómo se divide el temblor de acción según la contracción muscular voluntaria?","back":"En temblor postural y temblor cinético."},{"front":"¿Qué tipo de temblor aparece al mantener una posición específica contra la gravedad?","back":"Temblor postural."},{"front":"El temblor que interfiere con la realización de movimientos voluntarios precisos se denomina temblor _____.","back":"cinético"},{"front":"¿Cuál es la característica clínica inicial del temblor en la enfermedad de Parkinson?","back":"Es un temblor de reposo, grosero, lento y habitualmente unilateral."},{"front":"¿Qué patología se asocia típicamente con un temblor cinético que interfiere con el movimiento terminal?","back":"Patología cerebelosa o del tronco encefálico."},{"front":"¿Cuál es la fisiopatología del temblor fisiológico exacerbado?","back":"Incremento de la actividad periférica \\beta-adrenérgica por aumento de catecolaminas."},{"front":"¿Qué fármacos son el tratamiento de elección para el temblor fisiológico exacerbado?","back":"Betabloqueantes."},{"front":"¿Cuál es el trastorno del movimiento más prevalente y de herencia autosómica dominante?","back":"Temblor esencial benigno."},{"front":"¿Qué sustancia suele disminuir la intensidad del temblor esencial benigno?","back":"El alcohol."},{"front":"¿Cuáles son los medicamentos de primera línea para el tratamiento del temblor esencial?","back":"Propanolol o primidona."},{"front":"¿Qué neurotransmisor se encuentra disminuido en la sustancia negra en la enfermedad de Parkinson?","back":"Dopamina."},{"front":"¿Cuál es el hallazgo histopatológico característico en el cerebro de pacientes con Parkinson?","back":"Cuerpos de Lewy."},{"front":"¿Qué mutaciones genéticas se asocian con la enfermedad de Parkinson?","back":"Mutaciones en los genes \\text{PARK1} y \\text{PARK4}."},{"front":"¿Cuál es el factor de riesgo más importante para desarrollar Parkinson después de la edad?","back":"Antecedente familiar."},{"front":"La enfermedad de Parkinson es la _____ causa más frecuente de enfermedad degenerativa a nivel mundial.","back":"segunda"},{"front":"¿Por qué se considera que las mujeres tienen cierta protección contra el Parkinson?","back":"Por la presencia de estrógenos."},{"front":"¿Cómo se describe el temblor típico de las manos en el paciente con Parkinson?","back":"Temblor en reposo con inicio en \"cuenta de monedas\"."},{"front":"¿Qué término médico describe la lentitud de movimientos característica del Parkinson?","back":"Bradicinesia."},{"front":"¿Cuál es el síntoma no motor (psicológico) más frecuente en la enfermedad de Parkinson?","back":"Depresión."},{"front":"¿Qué escala se utiliza para evaluar el grado de discapacidad en un paciente con Parkinson?","back":"Clasificación de Hoehn y Yahr."},{"front":"¿Cuál es el Gold Standard diagnóstico para la enfermedad de Parkinson?","back":"Evaluación clínica sumada a los Criterios del Banco de Cerebros."},{"front":"¿Cuál es el rango de frecuencia típico del temblor parkinsoniano?","back":"4-6\\text{ Hz}."},{"front":"¿Qué fármacos se prefieren para pacientes jóvenes (menores de 65 años) con Parkinson leve?","back":"Inhibidores de la MAO-B (Selegilina, Rasagilina) o agonistas dopaminérgicos."},{"front":"¿Cuál es el tratamiento de elección para el Parkinson en estadios moderados a graves?","back":"Levodopa combinada con Carbidopa."},{"front":"¿Cuál es la función de la Carbidopa cuando se administra con Levodopa?","back":"Actuar como inhibidor de la dopa-descarboxilasa periférica."},{"front":"¿Qué efecto secundario importante se asocia al tratamiento farmacológico crónico del Parkinson?","back":"Síndromes psiquiátricos."},{"front":"¿Cuál es el tratamiento quirúrgico de elección para el Parkinson?","back":"Estimulación cerebral profunda del subnúcleo talámico bilateral."},{"front":"¿En qué cromosoma se encuentra el defecto genético de la enfermedad de Huntington?","back":"En el brazo corto del cromosoma 4."},{"front":"¿Qué región anatómica del cerebro sufre atrofia característica en la enfermedad de Huntington?","back":"El núcleo caudado."},{"front":"La tríada clínica de la enfermedad de Huntington incluye trastornos del movimiento, deterioro cognitivo y _____.","back":"trastornos psiquiátricos"},{"front":"¿Cuál es el trastorno del movimiento más característico de la enfermedad de Huntington?","back":"Corea."},{"front":"¿Qué repetición de tripletes de nucleótidos se busca para el diagnóstico definitivo de Huntington?","back":"Tripletes \\text{CAG}."},{"front":"¿Cuál es la causa más frecuente de muerte en pacientes con enfermedad de Huntington?","back":"Neumonía e infecciones."},{"front":"¿Qué hallazgo se observa típicamente en una TAC de un paciente con Huntington?","back":"Atrofia de la cabeza del núcleo caudado."},{"front":"¿Cuál es la primera causa de demencia a nivel mundial?","back":"Enfermedad de Alzheimer."},{"front":"¿Qué alelo de la apolipoproteína se considera un factor de riesgo para el Alzheimer?","back":"Alelo \\text{E4}."},{"front":"¿Qué estructuras patológicas extracelulares se forman en el hipocampo en el Alzheimer?","back":"Placas \\beta-amiloides."},{"front":"¿Qué proceso sufre la proteína Tau para formar ovillos neurofibrilares intracelulares?","back":"Hiperfosforilación."},{"front":"¿Cuál es el síntoma clínico inicial predominante en la enfermedad de Alzheimer?","back":"Pérdida de memoria a corto plazo."},{"front":"¿Qué puntaje en el Minimental State Evaluation (MMSE) es sugestivo de demencia?","back":"Menor a 24 puntos."},{"front":"¿Cuál es el Gold Standard para el diagnóstico de la enfermedad de Alzheimer?","back":"La autopsia (presencia de placas y ovillos)."},{"front":"Menciona los tres inhibidores de la acetilcolinesterasa usados en Alzheimer leve-moderado.","back":"Galantamina, Rivastigmina y Donepecilo."},{"front":"¿Cuál es el mecanismo de acción de la Memantina?","back":"Agonista parcial de los receptores \\text{NMDA}."},{"front":"¿Qué fármaco se utiliza como monoterapia en la enfermedad de Alzheimer grave?","back":"Memantina."},{"front":"¿Cuál es el tratamiento de elección para la psicosis con agitación aguda en Alzheimer?","back":"Haloperidol."},{"front":"¿Cómo se define la Esclerosis Lateral Amiotrófica (ELA)?","back":"Trastorno neurodegenerativo progresivo de la motoneurona."},{"front":"¿Cuál es la media de supervivencia tras el diagnóstico de ELA?","back":"3 años."},{"front":"¿Qué signos clínicos indican afectación de la primera motoneurona?","back":"Espasticidad, hiperreflexia y signo de Babinski."},{"front":"¿Qué signos clínicos indican afectación de la segunda motoneurona?","back":"Debilidad, amiotrofia y fasciculaciones."},{"front":"¿Cuál es el único fármaco disponible que modifica la progresión de la ELA?","back":"Riluzol."},{"front":"¿Qué enfermedad es la causa más frecuente de discapacidad neurológica en jóvenes?","back":"Esclerosis Múltiple."},{"front":"¿Cuál es el dato clínico de inicio más frecuente en la Esclerosis Múltiple?","back":"Alteración de la sensibilidad (hipoestesia o parestesia)."},{"front":"¿Qué hallazgo en el LCR es característico de la Esclerosis Múltiple?","back":"Bandas oligoclonales."},{"front":"¿Cuál es el tratamiento de elección para un brote agudo de Esclerosis Múltiple?","back":"Corticoides intravenosos por 3 a 5 días."},{"front":"¿Cómo se define el Síndrome de Guillain-Barré?","back":"Polirradiculoneuropatía aguda autoinmune desmielinizante."},{"front":"¿Cuál es la causa más frecuente de parálisis flácida a nivel mundial?","back":"Síndrome de Guillain-Barré."},{"front":"¿Qué agente infeccioso se asocia con mayor frecuencia al inicio del Guillain-Barré?","back":"\\textit{Campylobacter jejuni}."},{"front":"¿Cuál es el patrón característico de la debilidad muscular en el Guillain-Barré?","back":"Simétrica y ascendente."},{"front":"¿Qué hallazgo en el LCR define la disociación albúmino-citológica en Guillain-Barré?","back":"Aumento de proteínas con recuento celular normal."},{"front":"¿Cuál es la escala utilizada para evaluar la discapacidad funcional en Guillain-Barré?","back":"Escala de Hughes."},{"front":"¿Cuál es el tratamiento de primera línea para el Síndrome de Guillain-Barré?","back":"Inmunoglobulina intravenosa (2\\text{ g/kg})."},{"front":"¿Qué componente de la unión neuromuscular es atacado en la Miastenia Gravis clásica?","back":"Receptor nicotínico de acetilcolina."},{"front":"¿Cuál es la característica principal de la debilidad muscular en la Miastenia Gravis?","back":"Fluctuante: empeora con la actividad y mejora con el reposo."},{"front":"¿Qué prueba de anticuerpos es el Gold Standard para diagnosticar Miastenia Gravis?","back":"Anticuerpos antireceptor de acetilcolina."},{"front":"¿Cuál es el fármaco anticolinesterásico de primera elección en Miastenia Gravis?","back":"Piridostigmina."},{"front":"¿Qué procedimiento quirúrgico puede mejorar el pronóstico de la Miastenia Gravis?","back":"Timectomía."},{"front":"¿Qué fármaco es útil para el tratamiento de la rigidez en rueda dentada del Parkinson?","back":"Biperideno o Trihexifenidilo."},{"front":"En la Esclerosis Múltiple, las placas desmielinizantes crónicas presentan un infiltrado predominante de linfocitos _____.","back":"\\text{CD8}"}]},"30":{"num":30,"name":"CEFALEAS","cards":[]},"31":{"num":31,"name":"DEMENCIAS","cards":[{"front":"¿Cómo se define la demencia según el material de estudio?","back":"Como un deterioro de las funciones cognitivas lo suficientemente severo para incapacitar al paciente."},{"front":"Mencione los cuatro dominios principales que se ven afectados en el deterioro cognitivo.","back":"Memoria, lenguaje, conducta y orientación."},{"front":"¿Cuáles son los dos principales diagnósticos diferenciales del deterioro cognitivo?","back":"Demencia y depresión."},{"front":"¿Qué porcentaje de prevalencia de demencia se observa a los 60 años?","back":"1%."},{"front":"¿Qué porcentaje de prevalencia de demencia se observa a los 80 años?","back":"13%."},{"front":"¿Qué porcentaje de prevalencia de demencia se observa a los 90 años?","back":"32%."},{"front":"¿Cuál es la causa número uno de demencia a nivel mundial y en México?","back":"Enfermedad de Alzheimer."},{"front":"¿Cuál es el síntoma neuropsiquiátrico más frecuente en pacientes con demencia?","back":"Apatía."},{"front":"¿Cuál es la herramienta de primera elección para el cribado inicial de deterioro cognitivo?","back":"Minimental de Folstein (MMSE)."},{"front":"En el Minimental de Folstein, un puntaje menor a 14 puntos indica deterioro _____.","back":"Severo"},{"front":"En el Minimental de Folstein, un puntaje entre 14 y 18 puntos indica deterioro _____.","back":"Moderado"},{"front":"En el Minimental de Folstein, un puntaje entre 19 y 23 puntos indica deterioro _____.","back":"Leve"},{"front":"En el Minimental de Folstein, ¿qué puntaje se considera como 'sin deterioro'?","back":"24 puntos o más."},{"front":"¿Qué estudios de imagen se deben realizar en todos los pacientes con sospecha de demencia?","back":"Resonancia Magnética o Tomografía Computarizada (TAC)."},{"front":"¿Cuál es la principal causa de muerte en pacientes con Alzheimer?","back":"Neumonía por aspiración."},{"front":"¿Cuál es el factor de riesgo más importante para desarrollar Alzheimer?","back":"Edad avanzada."},{"front":"Etiología del Alzheimer: Formación de placas de _____.","back":"\\beta-amiloide"},{"front":"Etiología del Alzheimer: Formación de ovillos neurofibrilares por alteración de la proteína _____.","back":"Tau"},{"front":"¿Cuál es el síntoma cardinal inicial en la enfermedad de Alzheimer?","back":"Pérdida de memoria a corto plazo."},{"front":"¿Qué ocurre con la marcha en las etapas iniciales de la enfermedad de Alzheimer?","back":"La marcha está conservada."},{"front":"¿Cuál es el 'Gold Standard' diagnóstico para la enfermedad de Alzheimer?","back":"Autopsia (identificación de ovillos neurofibrilares)."},{"front":"¿Qué criterios se recomiendan para el diagnóstico clínico de Alzheimer?","back":"Criterios de NINCDS-ADRDA."},{"front":"¿Qué escala se utiliza específicamente para evaluar la progresión o mejoría en Alzheimer?","back":"Escala de Deterioro Global (GDS)."},{"front":"¿Qué escala se recomienda para el diagnóstico de depresión en pacientes con Alzheimer?","back":"Escala de Yesavage."},{"front":"¿Cuál es el tratamiento farmacológico de elección para el Alzheimer en fase leve-moderada?","back":"Inhibidores de la acetilcolinesterasa (Rivastigmina, Galantamina)."},{"front":"¿Qué fármaco es de elección para el Alzheimer en fase moderada-severa?","back":"Memantina."},{"front":"¿Cuál es el mecanismo de acción de la Memantina?","back":"Antagonista de los receptores NMDA."},{"front":"¿Qué suplementos o fármacos NO deben usarse para prevenir o tratar la demencia según la guía?","back":"Ginkgo biloba, Complejo B, ácido fólico, pentoxifilina o piracetam."},{"front":"¿Cuál es la segunda causa más común de demencia?","back":"Demencia Vascular."},{"front":"¿Cuál es el tiempo de supervivencia promedio tras el diagnóstico de demencia vascular?","back":"3.5 años."},{"front":"¿Cómo es el patrón de progresión clínica característico de la demencia vascular?","back":"Escalonado (aparición abrupta de síntomas en diferentes momentos)."},{"front":"¿Qué escala se utiliza para diferenciar la demencia vascular del Alzheimer?","back":"Escala de Isquemia de Hachinski."},{"front":"En la escala de Hachinski, un puntaje mayor a 7 sugiere _____.","back":"Demencia Vascular"},{"front":"En la escala de Hachinski, un puntaje menor a 4 sugiere _____.","back":"Enfermedad de Alzheimer"},{"front":"¿Qué instrumento se prefiere para evaluar la función ejecutiva en la demencia vascular?","back":"Evaluación Cognitiva Montreal (MoCA)."},{"front":"Concepto: Enfermedad de Pick","back":"Definición: Demencia frontotemporal caracterizada por atrofia de lóbulos frontales y temporales con presencia de neuronas de Pick."},{"front":"¿Cuál es el rango de edad más frecuente para la presentación de la Enfermedad de Pick?","back":"45 a 65 años."},{"front":"¿A qué mutación cromosómica se asocia la demencia frontotemporal?","back":"Cromosoma 17."},{"front":"¿Cuáles son los síntomas iniciales predominantes en la Enfermedad de Pick?","back":"Cambios conductuales graves (desinhibición, pérdida de empatía) y alteraciones del lenguaje."},{"front":"¿Qué es el 'fenómeno de alien' en la demencia frontotemporal?","back":"Es cuando una mano actúa de forma involuntaria (mano ajena)."},{"front":"A diferencia del Alzheimer, la Enfermedad de Pick suele cursar inicialmente sin _____.","back":"Amnesia, apraxia o agnosia."},{"front":"¿Qué fármacos se utilizan para tratar los síntomas psicóticos en la Enfermedad de Pick?","back":"ISRS y Quetiapina."},{"front":"¿Qué proteína forma las inclusiones citoplasmáticas en la Demencia por Cuerpos de Lewy?","back":"\\alpha-sinucleína."},{"front":"¿Cuál es la característica clínica clave de las alucinaciones en Cuerpos de Lewy?","back":"Son visuales, recurrentes y bien formadas."},{"front":"¿Qué síntomas extrapiramidales presentan los pacientes con Demencia por Cuerpos de Lewy?","back":"Bradicinesia, rigidez y temblor en reposo."},{"front":"¿A qué clase de fármacos presentan una sensibilidad extrema los pacientes con Cuerpos de Lewy?","back":"Neurolépticos (antipsicóticos)."},{"front":"¿Qué trastorno del sueño es característico de la Demencia por Cuerpos de Lewy?","back":"Trastorno del sueño REM (conducta violenta al soñar)."},{"front":"Termino: Síndrome de Capgras","back":"Definición: Delirio en el que el paciente cree que un ser querido ha sido reemplazado por un impostor."},{"front":"¿Qué hallazgo en la Resonancia Magnética sugiere Cuerpos de Lewy frente a Alzheimer?","back":"Atrofia occipital y temporal menos severa."},{"front":"¿Cuál es el tratamiento de elección para el parkinsonismo en la Demencia por Cuerpos de Lewy?","back":"Levodopa/Carbidopa."},{"front":"Paciente de 50 años con demencia, hipersexualidad y fenómeno de alien. Diagnóstico más probable:","back":"Demencia Frontotemporal (Enfermedad de Pick)."},{"front":"Paciente con parkinsonismo que desarrolla alucinaciones visuales y fluctuaciones cognitivas. Diagnóstico más probable:","back":"Demencia por Cuerpos de Lewy."},{"front":"Paciente con antecedente de EVC que presenta deterioro cognitivo de inicio abrupto. Diagnóstico más probable:","back":"Demencia Vascular."},{"front":"¿Cuáles son los componentes de la tríada clásica de la Demencia por Cuerpos de Lewy?","back":"Alucinaciones visuales, fluctuaciones cognitivas y parkinsonismo."},{"front":"La tríada de afasia, apraxia o agnosia es característica de la clínica de _____.","back":"Demencia (general)"},{"front":"Según la escala de Hachinski, un puntaje de 5-6 indica _____.","back":"Coexistencia de demencia vascular y Alzheimer."},{"front":"¿Cuál es la supervivencia promedio tras el diagnóstico de Alzheimer?","back":"5 a 10 años."},{"front":"¿Qué prueba cognitiva evalúa específicamente la capacidad de dibujar un círculo y colocar números?","back":"Prueba del Reloj."}]},"32":{"num":32,"name":"DERMATOLOGIA","cards":[{"front":"¿Qué son las dermatofitosis?","back":"Micosis superficiales causadas por hongos parásitos de la queratina."},{"front":"¿Cuáles son los tres géneros principales de dermatofitos?","back":"Trichophyton, Microsporum y Epidermophyton."},{"front":"¿Qué factores ambientales favorecen la aparición de dermatofitosis?","back":"Humedad y calor."},{"front":"¿Cuál es la dermatofitosis más común a nivel mundial?","back":"Tiña capitis."},{"front":"¿Qué porcentaje de las onicopatías corresponde a la onicomicosis?","back":"Del 18% al 40%."},{"front":"Agente causal más frecuente de la tiña capitis con lesión en escopetazo:","back":"T. tonsurans."},{"front":"Agente causal de la tiña capitis que suele presentarse como una lesión única:","back":"M. canis."},{"front":"¿Qué hallazgo clínico caracteriza a la tiña capitis?","back":"Zonas de alopecia y costras."},{"front":"¿Cuál es el estudio inicial para el diagnóstico de tiña capitis?","back":"Estudio microscópico directo con hidróxido de potasio al 20%."},{"front":"Tratamiento de primera elección para la tiña capitis:","back":"Terbinafina."},{"front":"Agentes causales frecuentes de la tiña de la barba (tiña barbae):","back":"T. mentagrophytes o T. verrucosum."},{"front":"Agente etiológico principal de la tiña corporis:","back":"T. rubrum."},{"front":"Descripción clínica de las lesiones en la tiña corporis:","back":"Placas eritemato-escamosas con borde activo y crecimiento excéntrico."},{"front":"Tratamiento de primera elección para la tiña corporis:","back":"Terbinafina en crema."},{"front":"Tratamiento de segunda elección para la tiña corporis:","back":"Miconazol."},{"front":"Agente etiológico principal de la tiña pedis (pie de atleta):","back":"T. rubrum."},{"front":"Tratamiento estándar de la onicomicosis:","back":"Terbinafina 250 mg durante 16 semanas."},{"front":"¿Qué es el Querión de Celso?","back":"Forma inflamatoria de tiña capitis con pústulas y costras melicéricas."},{"front":"¿Qué signo clínico es característico del Querión de Celso?","back":"Signo de la espumadera."},{"front":"Fisiopatología del Querión de Celso:","back":"Reacción de hipersensibilidad por inmunidad celular."},{"front":"Tratamiento adyuvante para disminuir la inflamación en el Querión de Celso:","back":"Prednisona (0.3-0.5 mg/kg/día)."},{"front":"Agente causal del Favus:","back":"T. schoenleinii."},{"front":"Hallazgo clínico patognomónico del Favus:","back":"Cazoleta fávica con costras amarillas (escútulas)."},{"front":"¿Qué es el granuloma tricofítico de Majocchi?","back":"Infección inflamatoria profunda en piel con pocos folículos, común tras depilación."},{"front":"¿Qué virus causa el Herpes Zóster?","back":"Virus de la Varicela-Zóster (Tipo 3)."},{"front":"¿Dónde permanece latente el virus del Herpes Zóster?","back":"Ganglios de los nervios craneales y del neuroeje."},{"front":"¿A qué edad se incrementa significativamente el riesgo de Herpes Zóster?","back":"A los 40 años."},{"front":"¿Cuál es la duración de la protección de la vacuna contra el Herpes Zóster?","back":"3 años."},{"front":"¿Qué caracteriza al Síndrome de Ramsay Hunt?","back":"Afectación del ganglio geniculado con vesículas auriculares y parálisis facial."},{"front":"Dermatoma más frecuentemente afectado por el Herpes Zóster:","back":"Zona toracolumbar (T3-L2)."},{"front":"Manifestación cutánea del Herpes Zóster:","back":"Exantema con vesículas y costras limitado al trayecto de un nervio."},{"front":"Tiempo límite ideal para iniciar antivirales en Herpes Zóster:","back":"Antes de las 72 horas de aparición del exantema."},{"front":"Contraindicación para la vacuna de Herpes Zóster:","back":"Pacientes inmunodeprimidos o embarazo."},{"front":"Fármacos de primera línea para el dolor en neuropatía postherpética (paso 1):","back":"Paracetamol 500-1000 mg cada 6-8 horas."},{"front":"Agente causal más frecuente de pediculosis:","back":"Pediculus capitis."},{"front":"Localización predilecta de las liendres en la cabeza:","back":"Región occipital y retroauricular."},{"front":"Tratamiento tópico de primera línea para la pediculosis capitis:","back":"Permetrina al 1%."},{"front":"Dosis de ivermectina oral para infestaciones masivas de piojos:","back":"200 \\mug/kg."},{"front":"Agente bacteriano causante del acné:","back":"Propionibacterium acnes."},{"front":"Mecanismo patogénico del acné:","back":"Obstrucción de glándulas sebáceas por queratinización anormal."},{"front":"Lesión inicial y elemental del acné leve:","back":"Comedones."},{"front":"Lesiones características del acné moderado:","back":"Pápulas y pústulas."},{"front":"Complicación más común del acné:","back":"Cicatrices."},{"front":"Tratamiento tópico de elección para acné leve:","back":"Tretinoína + peróxido de benzoilo."},{"front":"Tratamiento sistémico de elección para acné moderado:","back":"Tetraciclinas orales (Doxiciclina)."},{"front":"Tratamiento estándar de oro para el acné severo:","back":"Isotretinoína oral."},{"front":"Efecto adverso más común de la isotretinoína:","back":"Xerosis cutaneomucosa."},{"front":"Criterio de referencia inmediata a dermatología en acné:","back":"Acné fulminante o riesgo de cicatrices permanentes."},{"front":"Agente causal más común de la pitiriasis versicolor:","back":"Malassezia globosa."},{"front":"Variante clínica más frecuente de la pitiriasis versicolor:","back":"Lesiones hipocrómicas."},{"front":"¿En qué consiste el signo de la uñada en pitiriasis versicolor?","back":"Desprendimiento de escama fina al realizar rascado de la lesión."},{"front":"Hallazgo en la lámpara de Wood para pitiriasis versicolor:","back":"Fluorescencia amarillo-anaranjada."},{"front":"Imagen característica del KOH en pitiriasis versicolor:","back":"Hifas cortas y esporas (imagen de espagueti y albóndigas)."},{"front":"Tratamiento oral para pitiriasis versicolor extensa:","back":"Ketoconazol 200 mg por 10 días."},{"front":"¿Qué tipo de hipersensibilidad media la urticaria?","back":"Hipersensibilidad tipo I."},{"front":"Lesión elemental de la urticaria:","back":"Habón o roncha pruriginosa."},{"front":"Prueba diagnóstica de elección para urticaria física por frío:","back":"Prueba del cubo de hielo."},{"front":"Tratamiento de primera línea para la urticaria:","back":"Antihistamínicos de segunda generación (Loratadina o Cetirizina)."},{"front":"¿Cuándo se debe sospechar de vasculitis urticariana?","back":"Cuando las lesiones duran más de 24 horas y son ardorosas."},{"front":"¿Qué es el dermatografismo?","back":"Aparición de habones tras el rascado o presión firme de la piel."}]},"33":{"num":33,"name":"DERMATOLOGIA ONCOLOGICA","cards":[{"front":"¿De qué estructura específica surge el carcinoma basocelular (CBC)?","back":"De la capa basal de la epidermis y sus apéndices."},{"front":"¿Cuáles son los agentes etiológicos más importantes para el desarrollo de CBC?","back":"La exposición a rayos UV y las quemaduras solares."},{"front":"El carcinoma basocelular representa el _____% de los casos de cáncer de piel.","back":"74%"},{"front":"¿Cuál es la estirpe histológica más común del carcinoma basocelular a nivel global?","back":"La variante nodular."},{"front":"¿Qué velocidad de crecimiento anual suele presentar el carcinoma basocelular?","back":"0.5 cm por año."},{"front":"¿En qué región anatómica se localiza el 82% de los carcinomas basocelulares?","back":"En el rostro, específicamente en la nariz."},{"front":"Concepto: Carcinoma basocelular superficial.","back":"Definición: Placa eritematosa localizada comúnmente en el tronco y la cara."},{"front":"¿Qué característica clínica define al carcinoma basocelular morfeiforme?","back":"Su capacidad para infiltrar los nervios cutáneos."},{"front":"¿Cuál es la descripción clínica típica de una lesión por CBC nodular?","back":"Pápula rosa de brillo perlado con telangiectasias y posible depresión central."},{"front":"¿Qué hallazgos dermatoscópicos son característicos del carcinoma basocelular?","back":"Presencia de estructuras en hojas de arce y ruedas de carro."},{"front":"¿Cuál es el estándar de oro para el diagnóstico del carcinoma basocelular?","back":"Biopsia escisional con estudio histopatológico."},{"front":"¿Qué hallazgo histopatológico es patognomónico del CBC?","back":"Células basaloides dispuestas en empalizada."},{"front":"¿Cuál es el tratamiento de primera línea para el carcinoma basocelular?","back":"Extirpación quirúrgica."},{"front":"¿En qué casos de carcinoma basocelular se indica la cirugía de Mohs?","back":"En lesiones clasificadas como de alto riesgo de recurrencia."},{"front":"¿Qué opciones terapéuticas existen para un paciente con CBC que no es candidato quirúrgico?","back":"Uso de imiquimod o radioterapia."},{"front":"¿Cuál es el esquema de seguimiento post-tratamiento para el carcinoma basocelular?","back":"Revisiones a los 3, 6 y 12 meses, seguidas de citas anuales por 5 años."},{"front":"¿Qué tamaño define a un CBC nodular como de 'bajo riesgo' en una zona de riesgo bajo?","back":"Menor a 2 cm."},{"front":"El carcinoma basocelular tipo tumor de _____ se clasifica siempre como de bajo riesgo.","back":"Pinkus"},{"front":"¿A partir de qué tamaño un CBC nodular en topografía de riesgo alto se considera de 'alto riesgo'?","back":"Cualquier tamaño mayor a 1 cm."},{"front":"¿Cuál es el origen celular del carcinoma espinocelular (CEC)?","back":"Los queratinocitos epidérmicos."},{"front":"¿Cuál es la lesión precursora más frecuente del carcinoma espinocelular?","back":"La queratosis actínica."},{"front":"¿Qué porcentaje de carcinomas espinocelulares se localizan en la cara?","back":"60%"},{"front":"¿Qué característica clínica diferencia al CEC del CBC respecto a los vasos sanguíneos?","back":"El carcinoma espinocelular presenta ausencia de telangiectasias."},{"front":"¿Qué forma clínica peculiar puede adoptar el CEC en el 20% de los casos?","back":"Presentación en forma de cuerno cutáneo."},{"front":"¿Qué hallazgo histológico es característico del carcinoma espinocelular bien diferenciado?","back":"Perlas de queratina."},{"front":"¿Qué estudios de imagen se solicitan ante la sospecha de metástasis por CEC?","back":"Tomografía Computarizada (TAC) y Resonancia Magnética (RM)."},{"front":"¿Cuáles son los sitios más frecuentes de metástasis del carcinoma espinocelular?","back":"Pulmón, hígado y cerebro."},{"front":"¿Qué factores de riesgo no solares se asocian al carcinoma espinocelular?","back":"Tabaquismo, infección por VPH, úlceras crónicas e inmunosupresión."},{"front":"¿Cuál es el tratamiento quirúrgico para un CEC de bajo riesgo?","back":"Curetaje o electrocauterización."},{"front":"¿Qué esquema de quimioterapia se utiliza en el CEC con metástasis?","back":"5-fluorouracilo combinado con cetuximab."},{"front":"¿Cuál es la recomendación de reaplicación del fotoprotector solar?","back":"Cada 3 horas."},{"front":"¿De qué células deriva el melanoma?","back":"De los melanocitos."},{"front":"¿Qué lugar ocupa el melanoma en frecuencia entre las neoplasias cutáneas en México?","back":"Tercer lugar."},{"front":"¿Cuál es la variante clínica de melanoma más frecuente en la población mexicana?","back":"Melanoma nodular."},{"front":"¿Qué gen es el principal responsable de la susceptibilidad oncogénica en el melanoma?","back":"El gen CDKN2A (P16^{INK4})."},{"front":"En la regla ABCDE del melanoma, ¿qué significa la letra 'A'?","back":"Asimetría de la lesión."},{"front":"En la regla ABCDE del melanoma, ¿qué significa la letra 'B'?","back":"Bordes irregulares o \"con picos\"."},{"front":"En la regla ABCDE del melanoma, ¿qué significa la letra 'C'?","back":"Color no homogéneo (variaciones del marrón claro al negro)."},{"front":"En la regla ABCDE del melanoma, ¿qué punto de corte en el diámetro ('D') sugiere malignidad?","back":"Mayor a 6 mm."},{"front":"En la regla ABCDE del melanoma, ¿qué evalúa la letra 'E'?","back":"Evolución o cambios en la lesión en los últimos 1 a 2 meses."},{"front":"¿Qué cantidad de nevos comunes aumenta significativamente el riesgo de melanoma?","back":"Más de 100 nevos comunes."},{"front":"¿Qué fototipos de Fitzpatrick tienen mayor riesgo de desarrollar melanoma?","back":"Fototipos I y II."},{"front":"¿Qué antecedente de tratamiento para psoriasis se asocia con riesgo de melanoma?","back":"Más de 250 tratamientos con PUVA (luz UV con psoralenos)."},{"front":"¿Cuál es el margen de tejido celular subcutáneo recomendado en una biopsia escisional por melanoma?","back":"De 1 a 3 mm."},{"front":"¿Bajo qué criterio de espesor se debe buscar el ganglio centinela en melanoma?","back":"Cuando el índice de Breslow es mayor a 1 mm."},{"front":"Concepto: Melanoma de diseminación superficial.","back":"Características: Representa el 70% mundial; común en espalda (hombres) y piernas (mujeres)."},{"front":"¿Qué signo clínico es característico del melanoma lentiginoso acral en el lecho ungueal?","back":"Signo de Hutchinson."},{"front":"¿Cuál es el pronóstico general del melanoma lentiginoso acral?","back":"Mal pronóstico."},{"front":"¿Cuál es la principal neoplasia intraocular derivada de la capa pigmentada?","back":"Melanoma uveal."},{"front":"¿Cuál es el primer paso ante un paciente con una lesión sospechosa según el sistema ABCDE?","back":"Referencia inmediata a dermatología para biopsia."},{"front":"¿Cuál es el objetivo de realizar una biopsia incisional en lugar de escisional en melanoma?","back":"Se reserva para lesiones muy grandes donde no es posible el cierre directo inicial."},{"front":"¿Qué estudio diagnóstico se indica si el ganglio centinela resulta positivo en melanoma?","back":"Extensión mediante TAC, RM y PET."},{"front":"¿Cuál es la frecuencia de seguimiento recomendada para pacientes de alto riesgo de melanoma?","back":"Cada 6 meses."}]},"34":{"num":34,"name":"PATOLOGIA DERMATOLOGICA","cards":[{"front":"¿Qué patología dermatológica se define por la hipopigmentación de la piel asociada a componentes autoinmunes?","back":"Vitíligo"},{"front":"Menciona tres patologías autoinmunes asociadas frecuentemente al vitíligo.","back":"Anemia perniciosa, diabetes tipo 1 y tiroiditis."},{"front":"Descripción morfológica de las lesiones típicas del vitíligo.","back":"Lesiones hipopigmentarias (acrómicas) rodeadas de un anillo hipercrómico."},{"front":"¿En qué zonas faciales suele ubicarse preferentemente el vitíligo?","back":"Ojos, boca y narinas."},{"front":"¿En qué zonas extrafaciales suele ubicarse preferentemente el vitíligo?","back":"Manos, pies, superficies flexoras y genitales."},{"front":"Definición de vitíligo localizado.","back":"Afectación de un solo segmento corporal."},{"front":"¿Qué porcentaje de superficie corporal define al vitíligo diseminado?","back":"Menos del 75%."},{"front":"Definición de vitíligo generalizado.","back":"Afectación de más del 75% de la superficie corporal."},{"front":"Tratamiento de primera línea para el vitíligo localizado.","back":"Esteroides tópicos e inhibidores de calcineurina."},{"front":"Tratamiento de elección para el vitíligo generalizado.","back":"Láser Excimer."},{"front":"¿De qué tipo de cáncer tienen mayor riesgo los pacientes con vitíligo?","back":"Melanoma."},{"front":"¿Cuál es el trastorno despigmentario más común en dermatología?","back":"Vitíligo."},{"front":"¿A qué grupo de edad afecta principalmente la rosácea?","back":"Personas de mediana edad."},{"front":"¿Cuál es la característica clínica cardinal de la rosácea?","back":"Rubor o flushing en la región facial (periocular, nasal, malar)."},{"front":"Menciona dos microorganismos asociados a la etiología de la rosácea.","back":"Demodex\\ folliculorum y H.\\ pylori."},{"front":"¿Qué lesiones elementales provocan el rubor en la rosácea?","back":"Pápulas, pústulas y telangiectasias."},{"front":"Menciona dos trastornos oftálmicos que pueden aparecer en la rosácea crónica.","back":"Blefaritis y conjuntivitis."},{"front":"Concepto: Rinofima.","back":"Engrosamiento y deformidad de la nariz como dato pivote de rosácea crónica."},{"front":"Tratamiento tópico de elección para la rosácea.","back":"Metronidazol tópico o ácido azelaico."},{"front":"Fármaco oral utilizado en casos severos de rosácea.","back":"Isotretinoína."},{"front":"¿Qué estructura celular se ve afectada en el pénfigo vulgar?","back":"Los desmosomas."},{"front":"¿Qué estructura celular se ve afectada en el penfigoide bulloso?","back":"Los hemidesmosomas."},{"front":"¿Qué tipo de reacción de hipersensibilidad e inmunoglobulina median el pénfigo vulgar?","back":"Hipersensibilidad tipo 2 mediada por IgG."},{"front":"Características de las ampollas en el pénfigo vulgar.","back":"Ampollas flácidas."},{"front":"Características de las ampollas en el penfigoide bulloso.","back":"Ampollas tensas."},{"front":"¿Cuál es la diferencia de afectación de la mucosa oral entre pénfigo vulgar y penfigoide bulloso?","back":"El pénfigo vulgar afecta la mucosa oral, mientras que el penfigoide bulloso no."},{"front":"¿Cuál es el resultado del signo de Nikolsky en el pénfigo vulgar?","back":"Positivo."},{"front":"¿Cuál es el resultado del signo de Nikolsky en el penfigoide bulloso?","back":"Negativo."},{"front":"Estándar de oro para el diagnóstico de patologías ampollosas como el pénfigo.","back":"Biopsia con inmunofluorescencia."},{"front":"Tratamiento sistémico de elección para el pénfigo vulgar.","back":"Esteroides sistémicos (Prednisona)."},{"front":"Mecanismo patogénico de la psoriasis.","back":"Proliferación excesiva de queratinocitos (hiperqueratosis) que aumenta el grosor epidérmico."},{"front":"¿Qué subpoblación de linfocitos se propone como causante del ataque en la psoriasis?","back":"Linfocitos Th1."},{"front":"Menciona tres alelos HLA asociados a una mayor incidencia de psoriasis.","back":"HLA-Cw6, HLA-B12 y HLA-Bw57."},{"front":"¿Qué porcentaje de herencia de la psoriasis se atribuye al gen PSORS1?","back":"Entre el 35% y el 50%."},{"front":"¿Qué porcentaje de pacientes con psoriasis desarrolla artritis psoriásica?","back":"Al menos un 30%."},{"front":"Menciona tres fármacos asociados con la exacerbación de la psoriasis.","back":"Litio, beta-bloqueadores y AINES."},{"front":"Localización clásica de las lesiones en la psoriasis vulgar.","back":"Áreas extensoras (codos, rodillas, glúteos)."},{"front":"Descripción de las placas en la psoriasis vulgar.","back":"Placas eritematosas con descamación plateada y bordes bien definidos."},{"front":"¿Qué tipo de psoriasis se caracteriza por brotes de pequeñas pápulas tras una infección faríngea estreptocócica?","back":"Psoriasis en gota (guttata)."},{"front":"Características clínicas de la psoriasis pustular.","back":"Múltiples pústulas superficiales que tienden a coalescer, acompañadas de fiebre."},{"front":"¿Qué áreas corporales se ven afectadas en la psoriasis inversa?","back":"Áreas flexoras (axilar, inguinal, submamario, genitales)."},{"front":"Definición de eritrodermia psoriásica.","back":"Afectación de más del 90% de la superficie corporal con predominio de eritema."},{"front":"Hallazgos clínicos típicos de la psoriasis ungueal.","back":"Onicodistrofia con hiperqueratosis distal y manchas en 'aceite'."},{"front":"Concepto: Fenómeno de Koebner.","back":"Aparición de lesiones psoriásicas en zonas de traumatismo cutáneo."},{"front":"Concepto: Signo de Auspitz.","back":"Aparición de pequeñas gotas de sangre tras el levantamiento de la escama (rocío sangriento)."},{"front":"¿Qué es el Halo de Woronoff?","back":"Anillo de hipocromía que rodea a una placa de psoriasis."},{"front":"¿En qué consiste el raspado metódico de Brocq?","back":"Raspar la superficie de la lesión con un objeto romo para observar signos clínicos."},{"front":"Tratamiento tópico inicial recomendado (inducción) para psoriasis.","back":"Combinación de análogos de Vitamina D3 + esteroides (Clobetasol) + retinoide tópico."},{"front":"Tratamiento sistémico oral de primera línea para psoriasis.","back":"Ciclosporina o Metotrexato."},{"front":"Tratamiento de elección para psoriasis en pacientes embarazadas.","back":"Tratamiento tópico únicamente."},{"front":"¿Qué debe descartarse antes de iniciar tratamiento sistémico biológico en psoriasis?","back":"Tuberculosis latente o activa."},{"front":"¿Cuáles son las características de las escamas en la dermatitis seborreica?","back":"Escamas grasas de color amarillo-grisáceo sobre placas de eritema."},{"front":"Menciona los dos hongos asociados a la dermatitis seborreica.","back":"Cándida y Malassezia."},{"front":"Epidemiología de la dermatitis seborreica infantil.","back":"Se presenta en los primeros 3 meses de vida y suele resolverse al año."},{"front":"Zonas de predilección de la dermatitis seborreica.","back":"Áreas ricas en glándulas sebáceas (cuero cabelludo, cara, pliegues retroauriculares)."},{"front":"¿Qué prueba diagnóstica se utiliza en adultos para confirmar dermatitis seborreica?","back":"Prueba de cinta e hidróxido de potasio (KOH)."},{"front":"Antifúngico tópico de elección para dermatitis seborreica.","back":"Ketoconazol al 2%."},{"front":"¿Qué agente queratolítico se recomienda para la dermatitis seborreica en cuero cabelludo?","back":"Ácido salicílico."},{"front":"Agentes etiológicos de la pitiriasis versicolor.","back":"Malassezia\\ furfur o M.\\ globosa."},{"front":"Factores ambientales que predisponen a la pitiriasis versicolor.","back":"Calor y humedad."},{"front":"¿Cuál es la variante clínica más frecuente de la pitiriasis versicolor?","back":"Lesiones hipocrómicas."},{"front":"Concepto: Signo de la uñada.","back":"Desprendimiento de una escama fina tras el rascado de la lesión en pitiriasis versicolor."},{"front":"Tratamiento de elección para casos extensos o recurrentes de pitiriasis versicolor.","back":"Ketoconazol oral (200\\ mg por 10 días)."},{"front":"¿Qué color de fluorescencia emite la pitiriasis versicolor bajo la lámpara de Wood?","back":"Amarillo-anaranjado."},{"front":"Descripción de la imagen microscópica clásica en KOH para pitiriasis versicolor.","back":"Hifas cortas no septadas y esporas (imagen de 'espagueti y albóndigas')."},{"front":"Etiología propuesta para la pitiriasis rosada de Gilbert.","back":"Idiopática, frecuentemente asociada al virus herpes simple 6 (VHS-6)."},{"front":"Descripción de la lesión inicial en la pitiriasis rosada de Gilbert.","back":"Medallón heráldico de 3-6\\ cm, circular, color asalmonado o hiperpigmentado."},{"front":"Patrón de distribución secundaria característico de la pitiriasis rosada.","back":"Signo de 'árbol de Navidad' en el tronco."},{"front":"¿Cuál es la duración promedio de la pitiriasis rosada de Gilbert?","back":"Se autolimita en 4-8 semanas."},{"front":"Menciona tres grupos de fármacos asociados frecuentemente al Síndrome de Stevens-Johnson (SSJ).","back":"Sulfas, antiepilépticos y alopurinol."},{"front":"Definición de Síndrome de Stevens-Johnson según la extensión de superficie corporal.","back":"Desprendimiento epidérmico en menos del 10% de la superficie corporal."},{"front":"Definición de Necrólisis Epidérmica Tóxica (NET) según la extensión de superficie corporal.","back":"Desprendimiento epidérmico en más del 30% de la superficie corporal."},{"front":"¿Cuál es el rango de superficie corporal para la transición SSJ-NET?","back":"Entre el 10% y el 30%."},{"front":"Resultado del signo de Nikolsky en SSJ y NET.","back":"Positivo."},{"front":"Tratamiento farmacológico de elección (fines ENARM) para SSJ/NET.","back":"Inmunoglobulina intravenosa y enoxaparina."},{"front":"¿Cuál es el manejo de los esteroides en el tratamiento del SSJ/NET?","back":"Están contraindicados."},{"front":"¿Qué mortalidad se asocia a la Necrólisis Epidérmica Tóxica?","back":"Mayor al 30%."},{"front":"Menciona tres factores de riesgo para desarrollar NET.","back":"Edad avanzada, infección por VIH y HLA-B12."},{"front":"Hallazgo patognomónico del eritema multiforme.","back":"Lesiones en diana (o en blanco de tiro)."},{"front":"Infección viral más comúnmente relacionada con el eritema multiforme.","back":"Herpes simple."},{"front":"Descripción clínica de las pápulas en el liquen plano.","back":"Pápulas planas, poligonales, rojo-violáceas y muy pruriginosas."},{"front":"Localización típica del liquen plano.","back":"Cara flexora de muñecas, antebrazos, tobillos y región lumbosacra."},{"front":"¿Cómo se manifiestan las lesiones de liquen plano en las mucosas?","back":"Lesiones reticuladas blanquecinas (Estrías de Wickham)."},{"front":"¿Qué porcentaje de pacientes con liquen plano presenta afectación en mucosas?","back":"Entre el 60% y el 70%."},{"front":"¿Cuál es el tratamiento inicial para la psoriasis ungueal?","back":"Se sigue el esquema general de tratamiento tópico o sistémico según la gravedad."}]},"35":{"num":35,"name":"REUMATOLOGIA","cards":[{"front":"¿Cuáles son los alelos del complejo mayor de histocompatibilidad asociados principalmente con la Artritis Reumatoide?","back":"Son el HLA-DR4 y el HLA-DR1."},{"front":"¿Cuál es el principal factor de riesgo ambiental relacionado con la Artritis Reumatoide?","back":"El tabaquismo."},{"front":"Mencione tres agentes infecciosos asociados a la Artritis Reumatoide.","back":"Mycoplasma, Parvovirus B19 y Virus de Epstein-Barr (VEB)."},{"front":"¿Cuál es la proporción de afectación por sexo en la Artritis Reumatoide?","back":"Es más frecuente en mujeres, con una relación de 3:1 respecto a los hombres."},{"front":"¿A qué edad suele presentarse inicialmente la Artritis Reumatoide?","back":"Alrededor de los 40 años (\\pm 10 años)."},{"front":"¿Qué tipo de cáncer tiene una incidencia aumentada en pacientes con Artritis Reumatoide?","back":"El Linfoma No Hodgkin."},{"front":"¿Cuál es el órgano blanco primordial en la fisiopatología de la Artritis Reumatoide?","back":"La membrana sinovial."},{"front":"¿Cómo se define la inflamación articular característica de la Artritis Reumatoide?","back":"Es una inflamación poliarticular y simétrica de pequeñas y grandes articulaciones."},{"front":"¿Cuál es la duración mínima de la rigidez matutina para sugerir Artritis Reumatoide?","back":"Más de 30 minutos."},{"front":"En la exploración de Artritis Reumatoide, el signo de _____ consiste en ejercer presión suave en los bordes de la mano o pie para provocar dolor.","back":"Morton"},{"front":"¿Cuáles son las articulaciones más frecuentemente afectadas en la fase temprana de la Artritis Reumatoide?","back":"Las metacarpofalángicas."},{"front":"Mencione tres articulaciones afectadas típicamente en la Artritis Reumatoide de larga evolución.","back":"Tobillos, rodillas y codos."},{"front":"¿Qué estructura patológica se forma por la degeneración del líquido sinovial en la Artritis Reumatoide?","back":"El pannus."},{"front":"¿Cuáles son las tres zonas histológicas de un nódulo reumatoide?","back":"Zona central (necrosis), zona intermedia (macrófagos) y zona externa (tejido de granulación)."},{"front":"¿Cuál es la manifestación ocular más común en pacientes con Artritis Reumatoide?","back":"La queratoconjuntivitis seca derivada del Síndrome de Sjögren."},{"front":"¿Cuál es la manifestación pleuropulmonar más frecuente en la Artritis Reumatoide?","back":"La pleuritis."},{"front":"¿Cuál es la manifestación cardíaca más común en la Artritis Reumatoide?","back":"La pericarditis."},{"front":"¿Qué fármaco se considera el modificador de la enfermedad (FARME) de primera elección en Artritis Reumatoide?","back":"El Metotrexato."},{"front":"En el tratamiento de Artritis Reumatoide, ¿cuál es el manejo inicial recomendado si existen factores de mal pronóstico?","back":"Esquema combinado de Metotrexato + Sulfasalazina."},{"front":"¿Qué valor del índice DAS28 indica remisión en la Artritis Reumatoide?","back":"Un valor menor a 2.4."},{"front":"¿Cuál es la articulación más frecuentemente afectada en la Osteoartritis?","back":"La interfalángica distal."},{"front":"¿Cómo se denominan los nódulos óseos en las interfalángicas distales típicos de la Osteoartritis?","back":"Nódulos de Heberden."},{"front":"¿Cómo se denominan los nódulos óseos en las interfalángicas proximales típicos de la Osteoartritis?","back":"Nódulos de Bouchard."},{"front":"Mencione dos hallazgos radiográficos característicos de la Osteoartritis según la escala de Kellgren.","back":"Disminución del espacio interarticular y presencia de osteofitos."},{"front":"¿Cuál es el fármaco de elección inicial para el manejo del dolor en la Osteoartritis?","back":"El Paracetamol."},{"front":"¿A partir de qué edad se recomienda generalmente la artroplastia de rodilla en casos de Osteoartritis refractaria?","back":"En pacientes mayores de 55 años."},{"front":"¿Cuál es el criterio clínico de dolor para el diagnóstico de Fibromialgia?","back":"Dolor generalizado en los 4 cuadrantes del cuerpo por al menos 3 meses."},{"front":"¿Cuántos 'puntos gatillo' deben ser dolorosos a la palpación digital para diagnosticar Fibromialgia?","back":"Al menos 11 de los 18 puntos existentes."},{"front":"¿Qué fármaco antidepresivo se recomienda en Fibromialgia para mejorar los trastornos del sueño?","back":"La Amitriptilina."},{"front":"¿Cuál es el mecanismo de hipersensibilidad implicado en el Lupus Eritematoso Sistémico (LES)?","back":"Hipersensibilidad Tipo III."},{"front":"¿Cuál es la principal causa de muerte en pacientes con Lupus Eritematoso Sistémico?","back":"La nefritis lúpica."},{"front":"¿Qué alelos del sistema HLA se asocian con un mayor riesgo de LES?","back":"HLA-DR2, HLA-DR3 y HLA-B8."},{"front":"¿Cómo se describe el eritema malar característico del Lupus Cutáneo Agudo?","back":"Eritema en 'alas de mariposa' que respeta el surco nasogeniano."},{"front":"¿Cuál es la manifestación cardíaca más común en el Lupus Eritematoso Sistémico?","back":"La pericarditis."},{"front":"¿Qué tipo de glomerulonefritis es la más frecuente en la nefritis lúpica?","back":"La glomerulonefritis segmentaria difusa (afecta al 50% de los pacientes)."},{"front":"Según los criterios SLICC 2012 para LES, ¿cuántos criterios se requieren para el diagnóstico?","back":"Al menos 4 criterios, incluyendo al menos 1 clínico y 1 inmunológico."},{"front":"¿Qué anticuerpo es el más sensible para el diagnóstico de Lupus Eritematoso Sistémico?","back":"Los anticuerpos antinucleares (ANA), presentes en el 75% al 95% de los casos."},{"front":"¿Qué anticuerpos son los más específicos para el diagnóstico de LES?","back":"Los anticuerpos Anti-Smith (Anti-Sm)."},{"front":"¿Para qué se utilizan clínicamente los anticuerpos Anti-dsDNA en el Lupus?","back":"Para identificar riesgo de nefritis lúpica y monitorizar la actividad de la enfermedad."},{"front":"¿Qué anticuerpos se asocian con el desarrollo de Lupus Neonatal?","back":"Los anticuerpos Anti-Ro y Anti-La."},{"front":"¿Cuál es el fármaco de base que debe prescribirse a todos los pacientes con Lupus para prevenir exacerbaciones?","back":"La Hidroxicloroquina (HCQ)."},{"front":"¿Cuál es el esquema de inducción recomendado para LES con daño a órgano blanco (ej. nefritis grave)?","back":"Bolos de Metilprednisolona + Ciclofosfamida."},{"front":"Las espondiloartropatías se caracterizan por la ausencia de _____ y nódulos reumatoides.","back":"Factor reumatoide"},{"front":"¿Qué antígeno de histocompatibilidad es común en las espondiloartropatías?","back":"El HLA-B27."},{"front":"Definición: Entesitis","back":"Es la inflamación en el sitio de inserción del tendón o ligamento en el hueso."},{"front":"¿Cómo es el patrón de dolor lumbar en la Espondilitis Anquilosante?","back":"De comienzo insidioso, dura >3 meses, no mejora con reposo pero sí con el ejercicio."},{"front":"¿Qué prueba clínica valora la limitación de la movilidad lumbar en la Espondilitis Anquilosante?","back":"El Test de Schöber."},{"front":"¿Cuál es el hallazgo radiológico definitivo según los criterios de Nueva York para Espondilitis Anquilosante?","back":"La sacroileítis grado \\ge 2 bilateral o grado 3-4 unilateral."},{"front":"¿Cuál es la manifestación extraarticular más común de la Espondilitis Anquilosante?","back":"La uveítis anterior aguda (suele ser unilateral)."},{"front":"¿Qué imagen radiográfica es característica de la Artritis Psoriásica avanzada?","back":"Imagen de 'lápiz-copa' (pencil-in-cup) por reabsorción de falanges distales."},{"front":"¿Cuál es la tríada clásica del Síndrome de Reiter (Artritis Reactiva)?","back":"Uretritis/Cervicitis, conjuntivitis/uveítis y oligoartritis."},{"front":"¿Cuál es el tiempo de latencia típico entre la infección previa y la aparición de Artritis Reactiva?","back":"No superior a un mes."},{"front":"Mencione dos agentes bacterianos gastrointestinales asociados a la Artritis Reactiva.","back":"Shigella y Salmonella."},{"front":"¿Qué marcador serológico es el 'Gold Standard' para la Granulomatosis de Wegener?","back":"Los anticuerpos c-ANCA (contra proteinasa 3)."},{"front":"¿Qué hallazgo histopatológico define a la Granulomatosis de Wegener?","back":"Vasculitis con granulomas no caseificantes."},{"front":"El Test de Schirmer se considera positivo para xeroftalmía si el lagrimeo es menor a _____ en 5 minutos.","back":"5 mm"},{"front":"¿Qué linfocitos infiltran las glándulas exocrinas en el Síndrome de Sjögren?","back":"Linfocitos CD4."},{"front":"¿Cuál es la complicación maligna más grave asociada al Síndrome de Sjögren?","back":"El Linfoma No Hodgkin."},{"front":"¿Qué fármaco secretagogo se utiliza para tratar la xerostomía en el Síndrome de Sjögren?","back":"La Pilocarpina (5 mg cada 6 horas)."},{"front":"¿Con qué infección viral se asocia frecuentemente la Poliarteritis Nodosa (PAN)?","back":"Con la Hepatitis B (VHB)."},{"front":"¿Qué vasos sanguíneos afecta primordialmente la Poliarteritis Nodosa?","back":"Vasos de mediano y pequeño calibre, respetando arteriolas, capilares y vénulas."},{"front":"¿Cuál es la manifestación neurológica más común en la Poliarteritis Nodosa?","back":"La mononeuritis múltiple."},{"front":"¿Cuál es la primera línea de tratamiento para PAN no asociada a VHB?","back":"Corticoesteroides."},{"front":"¿Qué grandes vasos afecta principalmente la Arteritis de Takayasu?","back":"La aorta y sus ramas principales."},{"front":"¿Cuál es el criterio de edad obligatorio para sospechar Arteritis de Takayasu según Ishikawa?","back":"Tener menos de 40 años."},{"front":"¿Qué síntoma vascular es característico de la fase crónica de la Arteritis de Takayasu?","back":"Ausencia de pulsos o diferencia de presión entre brazos >10 mmHg."}]}}};